-- ============================================================
-- Migration 00010: Questions table for Banco de Preguntas
-- ============================================================
-- Creates the questions table and loads 3,000 PNP exam questions.
-- Execute this migration in Supabase SQL Editor AFTER 00008.
-- ============================================================

-- Drop table if exists (clean slate)
DROP TABLE IF EXISTS public.questions;

-- Create questions table
CREATE TABLE public.questions (
  id              INTEGER PRIMARY KEY,
  topic           TEXT NOT NULL,
  text            TEXT NOT NULL,
  option_a        TEXT NOT NULL,
  option_b        TEXT NOT NULL,
  option_c        TEXT,
  option_d        TEXT,
  option_e        TEXT,
  option_f        TEXT,
  correct_option  CHAR(1) NOT NULL,
  explanation     TEXT,
  ubicacion       TEXT,
  codigo          TEXT,
  created_at      TIMESTAMPTZ DEFAULT NOW()
);

-- Enable RLS
ALTER TABLE public.questions ENABLE ROW LEVEL SECURITY;

-- RLS Policies: authenticated users can read, admins can manage
CREATE POLICY "Authenticated users can read questions"
  ON public.questions FOR SELECT
  USING (auth.role() = 'authenticated');

CREATE POLICY "Admins can insert questions"
  ON public.questions FOR INSERT
  WITH CHECK (public.is_admin());

CREATE POLICY "Admins can update questions"
  ON public.questions FOR UPDATE
  USING (public.is_admin());

CREATE POLICY "Admins can delete questions"
  ON public.questions FOR DELETE
  USING (public.is_admin());

-- Indexes for efficient querying
CREATE INDEX IF NOT EXISTS idx_questions_topic ON public.questions(topic);
CREATE INDEX IF NOT EXISTS idx_questions_correct_option ON public.questions(correct_option);

