(699, 'Decreto Legislativo 1291?.', 'SEGÚN EL ARTÍCULO 17 DEL DECRETO LEGISLATIVO 1291, INDIQUE USTED, LA ESPECIALIDAD QUE SE IMPLEMENTA DENTRO DE LA CARRERA DE LA POLICÍA NACIONAL DEL PERÚ:.', 'ESPECIALIDAD DE CONTROL INTERNO.', 'ESPECIALIDAD DE CONTROL.', 'ESPECIALIDAD DE CONTROL ADMINISTRATIVO DISCIPLINARIO.', 'ESPECIALIDAD DE CONTROL DE PROCEDIMIENTOS ADMINISTRATIVOS DISCIPLINARIOS.', 'ESPECIALIDAD DE INVESTIGACIÓN ADMINISTRATIVO DISCIPLINARIO.', NULL, 'c', 'ESPECIALIDAD DE CONTROL ADMINISTRATIVO DISCIPLINARIO.', '(ART: 17) (item: 50)** [TITULO V]', '181661'),
(700, 'Decreto Legislativo 1291?.', 'LA APLICACIÓN DE LA PRUEBA DE CONTROL Y CONFIANZA SE REALIZA CON LA UTILIZACIÓN DE:.', 'SOPORTES BÁSICOS.', 'SOPORTES INFORMÁTICOS.', 'SOPORTES TECNOLÓGICOS.', 'SOPORTES DE TELEMÁTICA EXTERNA.', 'SOPORTES DE LA PLATAFORMA INFORMÁTICA DE LA DIRREHUM.', NULL, 'c', 'SOPORTES TECNOLÓGICOS.', '(ART: 13) (item: 49)** [TITULO II]  [CAPITULO II]', '181662'),
