(705, 'Decreto Legislativo 1291?.', 'CUANDO EN EL DECRETO SUPREMO 013-2017-IN, SE MENCIONE SIN ESPECIFICAR LAS PALABRAS; SECTOR, MINISTERIO, POLICÍA NACIONAL DEL PERÚ Y SISTEMA, NOS ESTAMOS REFIRIENDO A:.', 'SIGLAS.', 'RESUMEN.', 'NOMENCLATURA.', 'HERRAMIENTAS.', 'ABREVIATURAS.', NULL, 'c', 'NOMENCLATURA.', '(ART: 2) (item: 49)** [TITULO I]', '181667'),
(706, 'Decreto Legislativo 1291?.', 'SEGÚN LAS RESTRICCIONES Y RESERVAS SEÑALADAS EN LA PRESENTE NORMA, EL PERSONAL DE LOS DIFERENTES ÓRGANOS Y UNIDADES ORGÁNICAS DEL SECTOR INTERIOR, INCLUYENDO A LA POLICÍA NACIONAL DEL PERÚ, ESTA OBLIGADO A MANTENER:.', 'ESTRICTA CONFIDENCIALIDAD DE TODA LA DOCUMENTACIÓN OBTENIDA.', 'ESTRICTA RESERVADO Y CONFIDENCIALIDAD EN PARTE DE LA INFORMACIÓN OBTENIDA.', 'ESTRICTA RESERVA Y CONFIDENCIALIDAD DE TODA LA INFORMACIÓN OBTENIDA.', 'ESTRICTA CONFIDENCIALIDAD Y SECRETO DE TODA LA INFORMACIÓN OBTENIDA.', 'ESTRICTO SECRETO Y CONFIDENCIALIDAD DE TODA LA INFORMACIÓN OBTENIDA.', NULL, 'c', 'ESTRICTA RESERVA Y CONFIDENCIALIDAD DE TODA LA INFORMACIÓN OBTENIDA.', '(ART: 3) (item: 49)** [TITULO I]', '181668'),
