(708, 'Decreto Legislativo 1291?.', '¿QUE OFICINA VERIFICARÁ LA INFORMACIÓN CONTENIDA EN LAS DECLARACIONES JURADAS DE BIENES Y RENTAS DEL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ?:.', 'LA OFICINA DE GESTIÓN INSTITUCIONAL DE LA POLICÍA NACIONAL DEL PERÚ.', 'LA OFICINA DE DISCIPLINA DE LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ.', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL.', 'LA OFICINA GENERAL DE INTEGRACIÓN INSTITUCIONAL.', 'LA OFICINA ANTICORRUPCIÓN DEL MININTER.', NULL, 'c', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL.', '(ART: 6) (item: 50)** [TITULO II]', '181671'),
(709, 'Decreto Legislativo 1291?.', 'LA PRUEBA DE INTEGRIDAD BUSCA DETERMINAR SI EL PERSONAL POLICIAL EN ACTIVIDAD O SERVIDOR CIVIL DEL SECTOR INTERIOR TIENE UNA CONDUCTA:.', 'ÍNTEGRA.', 'DISCIPLINADA.', 'ÉTICA.', 'INTACHABLE.', 'HONESTA.', NULL, 'a', 'ÍNTEGRA.', '(ART: 12) (item: 50)** [TITULO IV]', '181672'),
(710, 'Decreto Legislativo 1291?.', 'LA RENDICIÓN DE CUENTAS ESTARÁ REFERIDA AL INCREMENTO O DISMINUCIÓN DE LA CRIMINALIDAD DENTRO DE LA JURISDICCIÓN, ASÍ COMO A LAS DIFICULTADES CON QUE PUEDA HABERSE ENCONTRADO .................... EN LA EJECUCIÓN DE SUS ACTIVIDADES: MARQUE LA RESPUESTA.:', 'PARA EL CUMPLIMIENTO DE SU MISIÓN.', 'LA POLICÍA NACIONAL DEL PERÚ.', 'LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ.', 'EL COMISARIO DE LA JURISDICCIÓN.', 'EL JEFE DE LA REGIÓN POLICIAL.', NULL, 'b', 'LA POLICÍA NACIONAL DEL PERÚ.', '(ART: 24) (item: 49)** [TITULO II]  [CAPITULO III]', '181673'),
(711, 'Decreto Legislativo 1291?.', 'A QUIEN LE CORRESPONDE ELABORAR LAS DIRECTIVAS QUE ESTABLEZCAN LOS PROTOCOLOS, PROCEDIMIENTOS, METAS, OBJETIVOS Y PLAZOS PARA LA APLICACIÓN DE LAS PRUEBAS: MARQUE LA RESPUESTA CORRECTA:.', 'A LA OFICINA DE INTEGRIDAD.', 'AL COMISIONADO DE INTEGRIDAD.', 'A LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA.', 'A LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ.', 'A LA DIRECCIÓN ANTICORRUPCIÓN DE LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'c', 'A LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA.', '(ART: 20) (item: 49)** [TITULO II]  [CAPITULO II]', '181674'),
(712, 'Decreto Legislativo 1291?.', '¿INDIQUE USTED UNA CARACTERÍSTICA DE LA PRUEBA DE INTEGRIDAD, SEGÚN EL DECRETO LEGISLATIVO 1291?.', 'EL PERSONAL QUE NO APRUEBA SERÁ DESTACADO A OTRA UNIDAD DE LA POLICÍA NACIONAL DEL PERÚ Y SE GUARDARÁ', 'EL RESULTADO DE LA PRUEBA SI PRESENTA UNA CONDUCTA TIPIFICADA COMO INFRACCIÓN DISCIPLINARIA O ILÍCITO', 'EL RESULTADO DE LA PRUEBA SERÁ REGISTRADO EN SU LEGAJO PERSONAL Y PERFIL ESTADÍSTICO DE LA DIRECCIÓN DE', 'EL COMISIONADO DE INTEGRIDAD ACTUARÁ SIN PROVOCAR SITUACIONES COMPROMETEDORAS QUE INDUZCAN A LA', 'EL RESULTADO DE LA PRUEBA TIENE CARÁCTER DE INFORMACIÓN CONFIDENCIAL.', NULL, 'd', 'EL COMISIONADO DE INTEGRIDAD ACTUARÁ SIN PROVOCAR SITUACIONES COMPROMETEDORAS QUE', '(ART: 16) (item: 50)** [TITULO IV]', '181675'),
(713, 'Decreto Legislativo 1291?.', 'LA PRUEBA DE INTEGRIDAD ES LA EVALUACIÓN REALIZADA AL PERSONAL CIVIL:.', 'DEL SECTOR DEFENSA.', 'DEL SECTOR PÚBLICO.', 'DEL SECTOR INTERIOR.', 'DE LA POLICÍA NACIONAL DEL PERÚ.', 'DEL ESTADO.', NULL, 'c', 'DEL SECTOR INTERIOR.', '(ART: 11) (item: 50)** [TITULO IV]', '181676'),
(714, 'Decreto Legislativo 1291?.', 'CONTENIDO DE LA PRUEBA.- NO PODRÁN CONSTITUIR ACTOS MANIFIESTAMENTE PROVOCADORES QUE SIGNIFIQUEN HECHOS INDUCTIVOS O INSTIGADORES PARA LA COMISIÓN DE UNA CONDUCTA FUNCIONAL IRREGULAR. CORRESPONDE A:.', 'ACCIONES QUE SIGNIFIQUEN HECHOS TRASCENDENTES.', 'ACCIONES MANIPULADAS.', 'ACCIONES O HECHOS CONTRARIOS AL RÉGIMEN DISCIPLINARIO.', 'ACCIONES QUE CONSTITUYAN RETARDO EN LA ADMINISTRACIÓN.', 'LAS ACCIONES SIMULADAS.', NULL, 'e', 'LAS ACCIONES SIMULADAS.', '(ART: 30) (item: 49)** [TITULO II]  [CAPITULO IV]', '181677'),
(715, 'Decreto Legislativo 1291?.', 'ES AQUELLA MEDIANTE LA CUAL SE VERIFICA LA REACCIÓN PSICOFISIOLÓGICA DEL EVALUADO ANTE LA APLICACIÓN DE UN CUESTIONARIO A FIN DE ESTABLECER LA VERACIDAD DE LA INFORMACIÓN PROPORCIONADA, NOS REFERIMOS A:.', 'LA EVALUACIÓN MEDIANTE LA UTILIZACIÓN DE POLÍGRAFO O INSTRUMENTOS SIMILARES.', 'LA EVALUACIÓN MEDIANTE LA UTILIZACIÓN DE INSTRUMENTOS DIVERSOS.', 'LA EVALUACIÓN MEDIANTE LA NO UTILIZACIÓN DE POLÍGRAFO O INSTRUMENTOS SIMILARES.', 'EL EXAMEN MEDIANTE EL USO DEL POLÍGRAFO O INSTRUMENTOS TECNOLÓGICOS.', 'EVALUACIÓN DE CONFIABILIDAD.', NULL, 'a', 'LA EVALUACIÓN MEDIANTE LA UTILIZACIÓN DE POLÍGRAFO O INSTRUMENTOS SIMILARES.', '(ART: 17) (item: 49)** [TITULO II]  [CAPITULO II]', '181680'),
(716, 'Decreto Legislativo 1291?.', 'DENTRO DE LAS RESTRICCIONES Y RESERVAS. LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA, ASÍ COMO EL PERSONAL POLICIAL, PERICIAL O TÉCNICO QUE PARTICIPE EN LA PRUEBA, SE ENCUENTRA OBLIGADO A MANTENER ESTRICTA CONFIDENCIALIDAD RESPECTO DE.........: MARQUE LA RESPUESTA CORRECTA:.', 'LA INFORMACIÓN RESERVADA DE LAS PRUEBAS DE CONTROL, SEGURIDAD Y CONFIANZA.', 'LA INFORMACIÓN RESERVADA OBTENIDA CON LAS PRUEBAS DE CONFIANZA Y SEGURIDAD.', 'LA INFORMACIÓN RESERVADA DE LAS PRUEBAS DE CONTROL Y SEGURIDAD.', 'LA INFORMACIÓN OBTENIDA CON LAS PRUEBAS DE CONTROL Y CONFIANZA.', 'LA INFORMACIÓN RESERVADA OBTENIDA POR EL COMISIONADO DE INTEGRIDAD.', NULL, 'd', 'LA INFORMACIÓN OBTENIDA CON LAS PRUEBAS DE CONTROL Y CONFIANZA.', '(ART: 22) (item: 49)** [TITULO II]  [CAPITULO II]', '181681'),
(717, 'Decreto Legislativo 1291?.', 'EN EL CASO DE LA PRUEBA DEL POLÍGRAFO, SE INCORPORAN ADICIONALMENTE LAS AUTORIZACIONES DE SOMETIMIENTO A DICHAS PRUEBAS O:.', 'RECHAZO A LA APLICACIÓN.', 'SU NEGATIVA DE SER EL CASO.', 'SU ACEPTACIÓN LUEGO DEL EXAMEN', 'RECLAMO ANTE DICHA APLICACIÓN.', 'ACEPTACIÓN DE LA INDAGACIÓN.', NULL, 'b', 'SU NEGATIVA DE SER EL CASO.', '(ART: 4) (item: 49)** [TITULO I]', '181682'),
(718, 'Decreto Legislativo 1291?.', 'ES OBJETIVO QUE LOS ÓRGANOS Y UNIDADES ORGÁNICAS DEL SISTEMA DISCIPLINARIO POLICIAL CUENTEN CON PERSONAL POLICIAL ALTAMENTE CALIFICADO Y CON EL PERFIL IDÓNEO QUE PERMITA REALIZAR UNA LABOR PROFESIONAL Y EFECTIVA PARA:.', 'EL CONTROL DEL MAL USO DE LOS RECURSOS ASIGNADOS POR EL ESTADO, ASÍ COMO LA CONSERVACIÓN DE LOS', 'EL CONTROL DEL BUEN USO DE LOS RECURSOS ASIGNADOS POR EL ESTADO, ASÍ COMO LA PRESERVACIÓN DE LOS', 'PERMANECER EN LA ESPECIALIDAD HASTA EL TERMINO DE SU DESTAQUE EN LA UNIDAD POLICIAL DONDE PRESTA', 'EL CONTROL DEL BUEN USO DE LOS RECURSOS LOGÍSTICOS Y ECONOMICOS ASIGNADOS POR EL ESTADO.', 'ELEVAR EL NIVEL DE LOS COMISIONADOS DE INTEGRIDAD EN CUMPLIMIENTO DE SU FUNCIÓN POLICIAL.', NULL, 'b', 'EL CONTROL DEL BUEN USO DE LOS RECURSOS ASIGNADOS POR EL ESTADO, ASÍ COMO LA PRESERVACIÓN', '(ART: 18) (item: 50)** [TITULO V]', '181683'),
(719, 'Decreto Legislativo 1291?.', 'DENTRO DE LAS FUNCIONES DE LA OFICINA DE CONTROL, CUMPLIMIENTO Y CONFIANZA, ES DICTAR LOS LINEAMIENTOS PARA GARANTIZAR: MARQUE LA QUE CORRESPONDA:.', 'LA RESERVA DE LA INFORMACIÓN A LAS DECLARACIONES JURADAS DE INGRESOS BIENES Y RENTAS REGISTRADAS EN EL', 'EL CARÁCTER SECRETO Y DE CONFIDENCIALIDAD DE LA INFORMACIÓN A LAS DECLARACIONES JURADAS DE BIENES Y', 'LA CONFIDENCIALIDAD Y RESERVA DE LA INFORMACIÓN A LAS DECLARACIONES JURADAS DE INGRESOS, BIENES Y', 'EL CARÁCTER RESERVADO DE LA INFORMACIÓN A LAS DECLARACIONES JURADAS DE INGRESOS BIENES Y RENTAS', 'LA CONFIDENCIALIDAD Y RESERVA DE LA INFORMACIÓN A LAS DECLARACIONES JURADAS DE BIENES Y RENTAS', NULL, 'c', 'LA CONFIDENCIALIDAD Y RESERVA DE LA INFORMACIÓN A LAS DECLARACIONES JURADAS DE INGRESOS,', '(ART: 10) (item: 49)** [TITULO II]  [CAPITULO I]', '181685'),
(720, 'Decreto Legislativo 1291?.', 'DE CONFORMIDAD AL DECRETO LEGISLATIVO 1291 ES RESPONSABILIDAD DE LOS JEFES DE LOS FRENTES POLICIALES:.', 'CONTROLAR LAS RENDICIONES DE CUENTAS.', 'SUPERVISAR EL CUMPLIMIENTO DE LAS RENDICIONES DE CUENTAS.', 'SUPERVISAR QUE LAS DDJJ SEAN PRESENTADAS A TIEMPO.', 'SUPERVISAR LA REFORMULACIÓN DE LAS RENDICIONES DE CUENTAS.', 'ANALIZAR EL CUMPLIMIENTO DE LAS RENDICIONES DE CUENTAS ECONÓMICAS.', NULL, 'b', 'SUPERVISAR EL CUMPLIMIENTO DE LAS RENDICIONES DE CUENTAS.', '(ART: 10) (item: 50)** [TITULO IV]', '181687'),
(721, 'Decreto Legislativo 1291?.', 'SEÑALE EL ENUNCIADO QUE CORRESPONDA A UN INCENTIVO DE LA ESPECIALIDAD DE CONTROL ADMINISTRATIVO DISCIPLINARIO:.', 'UN INCENTIVO ECONÓMICO POR LA LABOR QUE DESEMPEÑA.', 'CAPACITACIÓN EN EL EXTRANJERO.', 'FELICITACIÓN.', 'CAPACITACIÓN PERMANENTE EN EL PAÍS Y EN EXTRANJERO POR CADA GRADO.', 'CAPACITACIÓN PERMANENTE EN EL COEM Y MAESTRÍA EN SU GRADO.', NULL, 'd', 'CAPACITACIÓN PERMANENTE EN EL PAÍS Y EN EXTRANJERO POR CADA GRADO.', '(ART: 19) (item: 50)** [TITULO V]', '181688'),
(722, 'Decreto Legislativo 1291?.', 'EL CONTENIDO DE LA DECLARACIÓN JURADA DE INGRESOS, BIENES Y RENTAS:.', 'DEBE SER SUPERVISADA POR LA DIRREHUM DE LA POLICÍA NACIONAL DEL PERÚ.', 'OBLIGA A LA PRESENTACIÓN DE DOCUMENTOS QUE SUSTENTEN SU CONTENIDO.', 'OBLIGA A LA PRESENTACIÓN DEL EXPEDIENTE ADMINISTRATIVO.', 'NO OBLIGA A LA PRESENTACIÓN DE DOCUMENTOS QUE SUSTENTEN SU CONTENIDO.', 'DEBE SER APROBADA POR LA CONTRALORÍA GENERAL DE LA REPÚBLICA.', NULL, 'd', 'NO OBLIGA A LA PRESENTACIÓN DE DOCUMENTOS QUE SUSTENTEN SU CONTENIDO.', '(ART: 9) (item: 49)** [TITULO II]  [CAPITULO I]', '181690'),
(723, 'Decreto Legislativo 1291?.', 'LA PRUEBA DE CONTROL Y CONFIANZA SE APLICA AL PERSONAL CIVIL Y POLICIAL DEL SECTOR INTERIOR Y TIENE COMO OBJETIVO FORTALECER LOS NIVELES DE CONFIABILIDAD Y SEGURIDAD, MEDIANTE LA IDENTIFICACIÓN DE PERSONAL: MARQUE LA RESPUESTA CORRECTA:.', 'CUYOS  PRINCIPIOS Y VALORES PODRÍAN ESTAR ACORDES A LAS METAS INSTITUCIONALES.', 'CUYAS CONDUCTAS, PRINCIPIOS Y VALORES SEAN ACORDES A LOS INSTITUCIONALES.', 'CUYAS CONDUCTAS NO SEAN ACORDES A LOS INSTITUCIONALES.', 'CUYOS VALORES SEAN ACORDES A LAS METAS INSTITUCIONALES.', 'CUYO COMPORTAMIENTO NO AFECTE LOS BIENES JURÍDICOS DE LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'b', 'CUYAS CONDUCTAS, PRINCIPIOS Y VALORES SEAN ACORDES A LOS INSTITUCIONALES.', '(ART: 13) (item: 49)** [TITULO II]  [CAPITULO II]', '181698'),
