(731, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'ES EL RESPONSABLE DE EJERCER AUTORIDAD EN TODO LUGAR Y CIRCUNSTANCIA, ASÍ COMO MANTENER LA DISCIPLINA MEDIANTE LA INSTRUCCIÓN, EL MANDO JUSTO, EL BUEN EJEMPLO Y LA IMPARCIALIDAD:', 'EL ADMINISTRADO.', 'EL SUPERIOR.', 'EL PRESUNTO INFRACTOR.', 'EL ÓRGANO DISCIPLINARIO.', 'EL ÓRGANO DE INVESTIGACIÓN.', NULL, 'b', 'EL SUPERIOR.', '(texto: 8)** [TITULO I]  [CAPITULO III]', '177928'),
