(835, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'RESPECTO A LA SUBORDINACIÓN SELECCIONE LA RESPUESTA CORRECTA:', 'EXISTE SUBORDINACIÓN HACIA EL SUPERIOR EN RAZÓN DEL GRADO, ANTIGÜEDAD O CARGO.', 'EXISTE SUBORDINACIÓN HACIA EL SUPERIOR EN RAZÓN DEL GRADO, ANTIGÜEDAD, CARGO O EMPLEO.', 'EXISTE SUBORDINACIÓN HACIA EL SUPERIOR EN RAZÓN DEL GRADO Y ANTIGÜEDAD.', 'EXISTE SUBORDINACIÓN HACIA EL SUPERIOR EN RAZÓN DEL GRADO, CARGO O EMPLEO.', 'EXISTE SUBORDINACIÓN HACIA EL SUPERIOR EN RAZÓN DEL GRADO, ANTIGÜEDAD, JERARQUÍA, CARGO O EMPLEO.', NULL, 'a', 'EXISTE SUBORDINACIÓN HACIA EL SUPERIOR EN RAZÓN DEL GRADO, ANTIGÜEDAD O CARGO.', '(texto: 16)** [TITULO I]  [CAPITULO V]', '178038'),
(836, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ DEBE MANTENER CORDIALES RELACIONES CON LOS FUNCIONARIOS PÚBLICOS Y CON LOS REPRESENTANTES DE LAS INSTITUCIONES PRIVADAS. EL ENUNCIADO CORRESPONDE A ...:', 'TRATO DEBIDO.', 'EJERCICIO DEL COMANDO.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'NORMAS DE CONDUCTA.', 'EJERCICIO DEL MANDO.', NULL, 'c', 'SIGNOS Y EXPRESIONES DE RESPETO.', '(texto: 15)** [TITULO I]  [CAPITULO IV]', '178039'),
(837, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LOS JEFES DE LAS UNIDADES POLICIALES AL ASUMIR EL CARGO, PRESENTARÁN SU SALUDO EN FORMA PERSONAL O POR ESCRITO, A LAS AUTORIDADES QUE CORRESPONDAN. EL ENUNCIADO CORRESPONDE A ...:', 'TRATO DEBIDO.', 'HONORES Y PREMINENCIAS.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'NORMAS DE CONDUCTA.', 'SUBORDINACIÓN, MANDO Y COMANDO.', NULL, 'c', 'SIGNOS Y EXPRESIONES DE RESPETO.', '(texto: 15)** [TITULO I]  [CAPITULO IV]', '178040'),
(838, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LA PRESENTACIÓN Y RECONOCIMIENTO PARA EL EJERCICIO DEL COMANDO O DESEMPEÑO DEL CARGO SON OBLIGATORIOS, Y SE EJECUTARÁN EN CEREMONIA CONFORME A LO DISPUESTO EN EL REGLAMENTO RESPECTIVO. EL ENUNCIADO CORRESPONDE A ...:', 'TRATO DEBIDO.', 'HONORES Y PREEMINENCIAS.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'NORMAS DE CONDUCTA.', 'LA DISCIPLINA.', NULL, 'c', 'SIGNOS Y EXPRESIONES DE RESPETO.', '(texto: 15)** [TITULO I]  [CAPITULO IV]', '178041'),
(839, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LA MANERA DE PRESENTARSE AL SUPERIOR DEBE SER CON PULCRITUD EN EL VESTIR Y BUENOS MODALES. EL PERSONAL ESTÁ OBLIGADO A USAR EL UNIFORME O EL TRAJE DE CIVIL CON SOBRIEDAD, DECORO, ASEO Y CORRECCIÓN. EL ENUNCIADO CORRESPONDE A ...:', 'TRATO DEBIDO.', 'HONORES Y PREEMINENCIAS.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'NORMAS DE CONDUCTA.', 'LA DISCIPLINA.', NULL, 'c', 'SIGNOS Y EXPRESIONES DE RESPETO.', '(texto: 15)** [TITULO I]  [CAPITULO IV]', '178042'),
(840, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL SALUDO REGLAMENTARIO AL SUPERIOR ES OBLIGATORIO EN TODO LUGAR O CIRCUNSTANCIA, ESTE TIENE EL DEBER DE CONTESTARLO. EL SUBORDINADO ANTE LA PRESENCIA DEL SUPERIOR DEBE PONERSE DE PIE Y ADOPTAR LA POSICIÓN DE ATENCIÓN. ENTRE PERSONAL DE IGUAL GRADO, EL MENOS ANTIGUO ESTÁ OBLIGADO A SALUDAR REGLAMENTARIAMENTE; EN CASO DE DUDA, CUALQUIERA DE ELLOS PUEDE ANTICIPARSE, DEMOSTRANDO ASÍ SU CORTESÍA, DISCIPLINA Y EDUCACIÓN. EL ENUNCIADO CORRESPONDE A ...:', 'TRATO DEBIDO.', 'HONORES Y PREMINENCIAS.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'NORMAS DE CONDUCTA.', 'LA DISCIPLINA.', NULL, 'c', 'SIGNOS Y EXPRESIONES DE RESPETO.', '(texto: 15)** [TITULO I]  [CAPITULO IV]', '178043'),
(841, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'SON AQUELLOS QUE NORMAN LAS RELACIONES INTERNAS Y EXTERNAS ENTRE LOS MIEMBROS DE LA INSTITUCIÓN Y DEMÁS AUTORIDADES, Y CON LA CIUDADANÍA EN GENERAL:', 'TRATO DEBIDO.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'NORMAS DE CONDUCTA.', 'LA DISCIPLINA.', 'NORMAS DE CORTESÍA.', NULL, 'b', 'SIGNOS Y EXPRESIONES DE RESPETO.', '(texto: 15)** [TITULO I]  [CAPITULO IV]', '178044'),
(842, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ SANCIONADO CON RESOLUCIÓN FIRME POR LA COMISIÓN DE INFRACCIÓN GRAVE O MUY GRAVE QUE AFECTE LA FUNCIÓN QUE VENÍA DESEMPEÑANDO, NO PODRÁ CONTINUAR NI VOLVER A SER ASIGNADO AL CARGO QUE OCUPABA AL MOMENTO DE COMETER LA INFRACCIÓN O EN FUNCIONES ANÁLOGAS EN OTRA UNIDAD, POR UN PERÍODO DE ...:', '4 AÑOS.', '5 AÑOS.', '3 AÑOS.', '10 AÑOS.', '2 AÑOS.', NULL, 'b', '5 AÑOS.', '(texto: 13)** [TITULO I]  [CAPITULO III]', '178045'),
(843, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PERSONAL POLICIAL BRINDA UN TRATO CORTÉS Y RESPETUOSO AL CIUDADANO:', 'TRATO DEBIDO.', 'NORMAS DE CONDUCTA.', 'NORMAS DE CORTESÍA.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'LA DISCIPLINA.', NULL, 'a', 'TRATO DEBIDO.', '(texto: 7)** [TITULO I]  [CAPITULO III]', '178046'),
(844, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'SON LOS MANDATOS O REGLAS DE CUMPLIMIENTO OBLIGATORIO DEL PERSONAL POLICIAL DENTRO Y FUERA DEL SERVICIO, GARANTIZA EL RESPETO DE LOS BIENES JURÍDICOS PROTEGIDOS:', 'TRATO DEBIDO.', 'NORMAS DE CONDUCTA.', 'SIGNOS Y EXPRESIONES DE RESPETO.', 'LA DISCIPLINA.', 'LAS ÓRDENES.', NULL, 'b', 'NORMAS DE CONDUCTA.', '(texto: 6)** [TITULO I]  [CAPITULO III]', '178047'),
(845, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'ES EL CONJUNTO DE ACTIVIDADES QUE EJECUTA EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE ACTIVIDAD PARA EL CUMPLIMIENTO DE LA MISIÓN Y FUNCIONES INSTITUCIONALES, DE ACUERDO A LO ESTIPULADO EN LA CONSTITUCIÓN POLÍTICA DEL PERÚ, LAS LEYES Y REGLAMENTOS.', 'DISCIPLINA POLICIAL.', 'SERVICIO POLICIAL.', 'IMAGEN INSTITUCIONAL.', 'MÍSTICA POLICIAL.', 'ÉTICA POLICIAL.', NULL, 'b', 'SERVICIO POLICIAL.', '(texto: 5)** [TITULO I]  [CAPITULO II]', '178048'),
(846, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'SU OBSERVANCIA GENERA CONFIANZA Y RESPETO EN LAS PERSONAS, LA SOCIEDAD, LA PATRIA Y LA INSTITUCIÓN:', 'DISCIPLINA POLICIAL.', 'SERVICIO POLICIAL.', 'IMAGEN INSTITUCIONAL.', 'MÍSTICA POLICIAL.', 'ÉTICA POLICIAL.', NULL, 'e', 'ÉTICA POLICIAL.', '(texto: 5)** [TITULO I]  [CAPITULO II]', '178049'),
(847, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'TAMBIÉN SE APLICARÁ AL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE RETIRO, SIEMPRE QUE LAS PRESUNTAS INFRACCIONES SE HAYAN COMETIDO MIENTRAS SE ENCONTRABA EN SITUACIÓN DE ACTIVIDAD O DISPONIBILIDAD. NOS REFERIMOS A ...:', 'EL ALCANCE DE LA LEY 30714.', 'LA NATURALEZA DE LA LEY 30714.', 'EL OBJETO DE LA LEY 30714.', 'EL CONTENIDO DE LA LEY 30714.', 'LA FINALIDAD DE LA LEY 30714.', NULL, 'a', 'EL ALCANCE DE LA LEY 30714.', '(texto: 4)** [TITULO I]  [CAPITULO I]', '178050'),
(848, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'COMPRENDE AL PERSONAL POLICIAL EN SITUACIÓN DE ACTIVIDAD Y DISPONIBILIDAD. NOS REFERIMOS A ...:', 'EL ALCANCE DE LA LEY 30714.', 'LA NATURALEZA DE LA LEY 30714.', 'EL OBJETO DE LA LEY 30714.', 'EL CONTENIDO DE LA LEY 30714.', 'LA FINALIDAD DE LA LEY 30714.', NULL, 'a', 'EL ALCANCE DE LA LEY 30714.', '(texto: 4)** [TITULO I]  [CAPITULO I]', '178051'),
(849, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'ESTABLECER LAS NORMAS Y PROCEDIMIENTOS ADMINISTRATIVO-DISCIPLINARIOS DESTINADOS A PREVENIR, REGULAR Y SANCIONAR LAS INFRACCIONES COMETIDAS POR EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, CONSTITUYE:', 'EL ALCANCE DE LA LEY 30714.', 'LA NATURALEZA DE LA LEY 30714.', 'EL OBJETO DE LA LEY 30714.', 'EL CONTENIDO DE LA LEY 30714.', 'LA FINALIDAD DE LA LEY 30714.', NULL, 'c', 'EL OBJETO DE LA LEY 30714.', '(texto: 2)** [TITULO I]  [CAPITULO I]', '178052'),
(850, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'SON APLICABLES LAS DISPOSICIONES SANCIONADORAS VIGENTES EN EL MOMENTO DE INCURRIR EL INFRACTOR EN LA CONDUCTA A SANCIONAR, SALVO QUE LAS POSTERIORES LE SEAN MÁS FAVORABLES. CORRESPONDE AL PRINCIPIO DE:', 'RETROACTIVIDAD.', 'LEGALIDAD.', 'LICITUD.', 'IRRETROACTIVIDAD.', 'ILICITUD.', NULL, 'd', 'IRRETROACTIVIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178053'),
(851, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'MEDIANTE EL CUAL NADIE DEBE SER DISCRIMINADO POR MOTIVO DE ORIGEN, RAZA, SEXO, IDIOMA, RELIGIÓN, OPINIÓN, CONDICIÓN ECONÓMICA O DE CUALQUIERA OTRA ÍNDOLE. CORRESPONDE AL PRINCIPIO DE:', 'IMPARCIALIDAD.', 'NO DISCRIMINACIÓN.', 'DEBIDO PROCEDIMIENTO.', 'AUTONOMÍA DE LA RESPONSABILIDAD ADMINISTRATIVA.', 'IGUALDAD.', NULL, 'e', 'IGUALDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178054'),
(852, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LA RESPONSABILIDAD DEBE RECAER EN QUIEN REALIZA LA CONDUCTA OMISIVA O ACTIVA CONSTITUTIVA DE INFRACCIÓN SANCIONABLE. CORRESPONDE AL PRINCIPIO DE:', 'CASUALIDAD.', 'CAUSALIDAD.', 'CAUSA - EFECTO.', 'LICITUD.', 'TIPICIDAD.', NULL, 'b', 'CAUSALIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178055'),
(853, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LAS ENTIDADES DEBEN PRESUMIR QUE LOS ADMINISTRADOS HAN ACTUADO APEGADOS A SUS DEBERES MIENTRAS NO CUENTEN CON EVIDENCIA EN CONTRARIO. CORRESPONDE AL PRINCIPIO DE:', 'PRESUNCIÓN DE INOCENCIA.', 'PRESUNCIÓN DE ILICITUD.', 'PRESUNCIÓN DE LICITUD.', 'LEGALIDAD.', 'RAZONABILIDAD.', NULL, 'c', 'PRESUNCIÓN DE LICITUD.', '(texto: 1)** [TITULO PRELIMINAR]', '178056'),
(854, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL SUPERIOR Y LOS ÓRGANOS DISCIPLINARIOS DEBEN CUMPLIR SU ACTUACIÓN DENTRO DE LOS PLAZOS ESTABLECIDOS, EVITANDO ACTUACIONES INNECESARIAS QUE DIFICULTEN SU DESENVOLVIMIENTO. CORRESPONDE AL PRINCIPIO DE:', 'IMPULSO DE OFICIO.', 'DEBIDO PROCESO.', 'DEBIDO PROCEDIMIENTO ADMINISTRATIVO.', 'CELERIDAD.', 'PRINCIPIO DE INMEDIATEZ.', NULL, 'd', 'CELERIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178057'),
(855, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LA RESPONSABILIDAD ADMINISTRATIVA ES SUBJETIVA, SALVO LOS CASOS EN QUE POR LEY SE DISPONGA LA RESPONSABILIDAD ADMINISTRATIVA OBJETIVA. CORRESPONDE AL PRINCIPIO DE:', 'IGUALDAD.', 'LICITUD.', 'TIPICIDAD.', 'CULPABILIDAD.', 'SUBJETIVIDAD.', NULL, 'd', 'CULPABILIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178058'),
(856, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL SUPERIOR Y LOS ÓRGANOS DISCIPLINARIOS ACTÚAN SIN NINGUNA CLASE DE DISCRIMINACIÓN O FAVORITISMO ENTRE EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ OTORGÁNDOLES TRATAMIENTO OBJETIVO Y TUTELA IGUALITARIA FRENTE AL PROCEDIMIENTO, EN ATENCIÓN A LOS BIENES JURÍDICOS PROTEGIDOS POR LA PRESENTE NORMA. CORRESPONDE AL PRINCIPIO DE:', 'IMPARCIALIDAD.', 'RAZONABILIDAD.', 'TIPICIDAD.', 'IGUALDAD.', 'DEBIDO PROCEDIMIENTO.', NULL, 'a', 'IMPARCIALIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178059'),
(857, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'ADECUACIÓN DE LA CONDUCTA A LA INFRACCIÓN DESCRITA Y SANCIONADA POR LA NORMA SIN ADMITIR INTERPRETACIÓN EXTENSIVA O POR ANALOGÍA. CORRESPONDE AL PRINCIPIO DE:', 'TIPICIDAD.', 'RAZONABILIDAD.', 'CAUSALIDAD.', 'CULPABILIDAD.', 'PROPORCIONALIDAD.', NULL, 'a', 'TIPICIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178060'),
(858, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PERSONAL QUE CONOZCA DE UNA INVESTIGACIÓN ADMINISTRATIVO-DISCIPLINARIA O SEA PARTE DE LA MISMA, ESTÁ OBLIGADO A MANTENER RESERVA DEL CONTENIDO DEL PROCEDIMIENTO HASTA SU CULMINACIÓN. CORRESPONDE AL PRINCIPIO DE:', 'INFIDENCIA.', 'CONFIDENCIALIDAD.', 'RESERVA.', 'CAUSALIDAD.', 'LICITUD.', NULL, 'c', 'RESERVA.', '(texto: 1)** [TITULO PRELIMINAR]', '178061'),
(859, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL CONOCIMIENTO DE LA COMISIÓN DE UNA INFRACCIÓN OBLIGA EL INICIO INMEDIATO DEL PROCEDIMIENTO ADMINISTRATIVO-DISCIPLINARIO CORRESPONDIENTE Y COMPROMETE LA RESPONSABILIDAD DEL SUPERIOR. NOS REFERIMOS AL ...:', 'PRINCIPIO DE PROPORCIONALIDAD.', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', 'PRINCIPIO DE LEGALIDAD.', 'PRINCIPIO DE INMEDIATEZ.', 'PRINCIPIO DE LA AUTONOMÍA DE LA RESPONSABILIDAD ADMINISTRATIVA.', NULL, 'd', 'PRINCIPIO DE INMEDIATEZ.', '(texto: 1)** [TITULO PRELIMINAR]', '178062'),
(860, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL DERECHO A SER NOTIFICADO, CORRESPONDE AL:', 'PRINCIPIO DE LEGALIDAD.', 'PRINCIPIO DE IGUALDAD.', 'PRINCIPIO DE CONTRADICCIÓN.', 'PRESUNCIÓN DE LICITUD.', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', NULL, 'e', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', '(texto: 1)** [TITULO PRELIMINAR]', '178063'),
(861, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'ACCEDER AL EXPEDIENTE, CORRESPONDE AL:', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO', 'PRINCIPIO DE LEGALIDAD.', 'PRINCIPIO DEL DEBIDO PROCESO.', 'PRINCIPIO DE CONTRADICCIÓN.', 'PRESUNCIÓN DE LICITUD.', NULL, 'a', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO', '(texto: 1)** [TITULO PRELIMINAR]', '178064'),
(862, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PROCEDIMIENTO DISCIPLINARIO SANCIONADOR ES INDEPENDIENTE Y DISTINTO DE LOS PROCESOS JURISDICCIONALES CIVILES, PENALES U OTROS; Y ESTÁ ORIENTADA A ESTABLECER LA RESPONSABILIDAD ADMINISTRATIVO-DISCIPLINARIA EN LAS QUE INCURRE EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ. NOS REFERIMOS AL:', 'PRINCIPIO DE LEGALIDAD.', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', 'PRINCIPIO DE INDEPENDENCIA.', 'PRINCIPIO DE INMEDIATEZ.', 'PRINCIPIO DE LA AUTONOMÍA DE LA RESPONSABILIDAD ADMINISTRATIVA.', NULL, 'e', 'PRINCIPIO DE LA AUTONOMÍA DE LA RESPONSABILIDAD ADMINISTRATIVA.', '(texto: 1)** [TITULO PRELIMINAR]', '178065'),
(863, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, ESTÁ PROHIBIDO DE:', 'PARTICIPAR EN REUNIONES PÚBLICAS DE ASOCIACIONES SIN FINES DE LUCRO.', 'PARTICIPAR EN MANIFESTACIONES PÚBLICAS.', 'PARTICIPAR EN ACTUACIONES PROTOCOLARES DE LA POLICÍA NACIONAL DEL PERÚ.', 'REUNIRSE PÚBLICAMENTE EN FORMA PACÍFICA.', 'PERTENECER A AGRUPACIONES U OTRAS ORGANIZACIONES SIN FINES DE LUCRO.', NULL, 'b', 'PARTICIPAR EN MANIFESTACIONES PÚBLICAS.', '(texto: 12)** [TITULO I]  [CAPITULO III]', '178066'),
(864, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'PARA SER DESIGNADO MIEMBRO DEL TRIBUNAL DE DISCIPLINA POLICIAL SE REQUIERE:', 'CONTAR CON TÍTULO PROFESIONAL EN LA ESPECIALIDAD DE CONTROL ADMINISTRATIVO-DISCIPLINARIO, Y COLEGIATURA', 'TENER ESTUDIOS DE ESPECIALIZACIÓN, YA SEA EN GESTIÓN PÚBLICA, DERECHO CONSTITUCIONAL, ADMINISTRATIVO,', 'NO HABER SIDO CONDENADO POR DELITO CULPOSO.', 'HABER SIDO SANCIONADO CON DESTITUCIÓN O DESPIDO POR FALTA GRAVE. EN EL CASO DEL PERSONAL DE LA POLICÍA', 'TENER CONDUCTA INTACHABLE Y RECONOCIDA SOLVENCIA E IDONEIDAD MORAL Y ECONÓMICA.', NULL, 'b', 'TENER ESTUDIOS DE ESPECIALIZACIÓN, YA SEA EN GESTIÓN PÚBLICA, DERECHO CONSTITUCIONAL,', '(texto: 44)** [TITULO III]  [CAPITULO III]', '178067'),
(865, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'PARA SER DESIGNADO MIEMBRO DEL TRIBUNAL DE DISCIPLINA POLICIAL SE REQUIERE SER OFICIAL GENERAL U OFICIAL SUPERIOR DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE RETIRO CON LA ESPECIALIDAD DE:', 'INVESTIGACIÓN CRIMINAL.', 'CONTROL ADMINISTRATIVO-DISCIPLINARIO.', 'PROCEDIMIENTO SANCIONADOR.', 'DERECHO ADMINISTRATIVO.', 'ADMINISTRACIÓN.', NULL, 'b', 'CONTROL ADMINISTRATIVO-DISCIPLINARIO.', '(texto: 44)** [TITULO III]  [CAPITULO III]', '178068'),
(866, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'PARA SER DESIGNADO MIEMBRO DEL TRIBUNAL DE DISCIPLINA POLICIAL SE REQUIERE TENER COMPROBADA DOCENCIA UNIVERSITARIA POR EL PERÍODO NO MENOR DE:', '10 AÑOS.', '15 AÑOS.', '20 AÑOS.', '12 AÑOS.', '7 AÑOS.', NULL, 'a', '10 AÑOS.', '(texto: 44)** [TITULO III]  [CAPITULO III]', '178069'),
