(901, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'CONSTITUYE UN ÓRGANO DE DECISIÓN EN PRIMERA INSTANCIA POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES:', 'LA INSPECTORÍA MACRO REGIONAL COMPETENTE.', 'EL TRIBUNAL DE DISCIPLINA POLICIAL.', 'EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ.', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL, A TRAVÉS DE LA OFICINA DE ASUNTOS INTERNOS.', 'LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, A TRAVÉS DE LAS OFICINAS DE DISCIPLINA.', NULL, 'c', 'EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ.', '(texto: 39)** [TITULO III]  [CAPITULO II]', '178105'),
(902, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', '¿QUÉ SUCEDE CUANDO DENTRO DE UNA INVESTIGACIÓN POR INFRACCIONES GRAVES O MUY GRAVES SE IDENTIFICAN HECHOS QUE PUEDAN SER CONSIDERADOS COMO UNA INFRACCIÓN LEVE?', 'LAS INFRACCIONES LEVES NO FORMARAN PARTE DE LA INVESTIGACIÓN, YA QUE SE INVESTIGAN INFRACCIONES DE', 'EL ÓRGANO DE INVESTIGACIÓN A CARGO, APERTURA UNA NUEVA INVESTIGACIÓN, DONDE SE INCLUIRÁ LA INFRACCIÓN', 'EL ÓRGANO DE INVESTIGACIÓN A CARGO, EXCLUIRÁ LA INFRACCIÓN LEVE DEL PROCEDIMIENTO DE INVESTIGACIÓN,', 'SE NOTIFICA INMEDIATAMENTE AL PRESUNTO INFRACTOR, Y SE LE IMPONE LA SANCIÓN CORRESPONDIENTE A LA', 'EL ÓRGANO DE INVESTIGACIÓN A CARGO LA INCLUIRÁ EN EL PROCEDIMIENTO DE INVESTIGACIÓN, SOLICITANDO LOS', NULL, 'e', 'EL ÓRGANO DE INVESTIGACIÓN A CARGO LA INCLUIRÁ EN EL PROCEDIMIENTO DE INVESTIGACIÓN,', '(texto: 38)** [TITULO III]  [CAPITULO II]', '178106'),
(903, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', '¿DE QUIÉN ESTARÁ A CARGO LA OFICINA DE ASUNTOS INTERNOS?', 'ESTARÁ A CARGO DE UN PROFESIONAL CIVIL.', 'ESTARÁ A CARGO DE UN GENERAL DE ARMAS EN SITUACIÓN DE ACTIVIDAD.', 'ESTARÁ A CARGO DE UN GENERAL DE ARMAS EN SITUACIÓN DE RETIRO.', 'ESTARÁ A CARGO DE UN GENERAL DE SERVICIOS ABOGADO EN SITUACIÓN DE ACTIVIDAD.', 'ESTARÁ A CARGO DE UN GENERAL DE SERVICIOS ABOGADO EN SITUACIÓN DE RETIRO.', NULL, 'a', 'ESTARÁ A CARGO DE UN PROFESIONAL CIVIL.', '(texto: 38)** [TITULO III]  [CAPITULO II]', '178107'),
(904, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'REALIZA INVESTIGACIONES EXTRAORDINARIAS DE OFICIO O POR DISPOSICIÓN DEL MINISTRO POR LA COMISIÓN DE INFRACCIONES GRAVES O MUY GRAVES, PREVIA EVALUACIÓN DE LA TRASCENDENCIA O GRAVEDAD DE LOS HECHOS A INVESTIGAR:', 'LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ, A TRAVÉS DE LAS OFICINAS DE DISCIPLINA.', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL, A TRAVÉS DE LA OFICINA DE ASUNTOS INTERNOS.', 'EL INSPECTOR GENERAL DE LA POLICÍA NACIONAL DEL PERÚ PARA EL CASO DE INFRACCIONES GRAVES Y MUY GRAVES.', 'LAS INSPECTORÍAS MACRO REGIONALES.', 'LA INSPECTORÍA DESCENTRALIZADA COMPETENTE POR LA COMISIÓN DE INFRACCIONES GRAVES Y MUY GRAVES.', NULL, 'b', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL, A TRAVÉS DE LA OFICINA DE ASUNTOS INTERNOS.', '(texto: 38)** [TITULO III]  [CAPITULO II]', '178108'),
