(972, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LAS SANCIONES PREVISTAS EN LA PRESENTE NORMA SE GRADÚAN EN ATENCIÓN A LA GRAVEDAD, NATURALEZA O TRASCENDENCIA DEL HECHO, ASÍ COMO LAS REFERENCIAS ADMINISTRATIVAS DISCIPLINARIAS DEL INFRACTOR. CORRESPONDE LA PRINCIPIO DE:', 'CAUSALIDAD.', 'RAZONABILIDAD.', 'LICITUD.', 'PROPORCIONALIDAD.', 'LEGALIDAD.', NULL, 'b', 'RAZONABILIDAD.', '(texto: 1)** [TITULO PRELIMINAR]', '178176'),
(973, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL DERECHO A LA DEFENSA, CORRESPONDE AL:', 'PRINCIPIO DE LEGALIDAD.', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', 'PRESUNCIÓN DE LICITUD.', 'PRINCIPIO DE CONTRADICCIÓN.', 'PRINCIPIO DE IGUALDAD.', NULL, 'b', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', '(texto: 1)** [TITULO PRELIMINAR]', '178178'),
(974, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LAS INFRACCIONES SON SANCIONADAS CON SUJECIÓN A LOS PROCEDIMIENTOS ESTABLECIDOS EN LA PRESENTE NORMA, RESPETÁNDOSE LAS GARANTÍAS Y DERECHOS DEL DEBIDO PROCEDIMIENTO. NOS REFERIMOS AL:', 'PRINCIPIO DE LEGALIDAD.', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', 'PRINCIPIO DE TIPICIDAD.', 'CAUSALIDAD.', 'PRINCIPIO DE IGUALDAD.', NULL, 'b', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO.', '(texto: 1)** [TITULO PRELIMINAR]', '178179'),
