(976, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'PARA CASOS COMPLEJOS, LA ETAPA DE INVESTIGACIÓN PARA LAS INFRACCIONES MUY GRAVES SERÁ DE ...:', '35 DÍAS HÁBILES.', '60 DÍAS HÁBILES.', '120 DÍAS HÁBILES.', '100 DÍAS HÁBILES.', '50 DÍAS HÁBILES.', NULL, 'e', '50 DÍAS HÁBILES.', '(texto: 66)** [TITULO IV]  [CAPITULO III]', '178181'),
(977, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LA ETAPA DE INVESTIGACIÓN EN EL PROCEDIMIENTO ADMINISTRATIVO DISCIPLINARIO SUMARIO TIENE UN PLAZO MÁXIMO DE ...:', 'CINCO DÍAS HÁBILES.', 'DIEZ DÍAS HÁBILES.', 'QUINCE DÍAS HÁBILES.', 'VEINTE DÍAS HÁBILES.', 'OCHO DÍAS HÁBILES.', NULL, 'b', 'DIEZ DÍAS HÁBILES.', '(texto: 67)** [TITULO IV]  [CAPITULO IV]', '178182'),
(978, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'ES COMPETENTE A NIVEL NACIONAL PARA REALIZAR INVESTIGACIONES EXTRAORDINARIAS POR LA COMISIÓN DE INFRACCIONES DISCIPLINARIAS GRAVES O MUY GRAVES:', 'LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ.', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL A TRAVÉS DE LA OFICINA DE ASUNTOS INTERNOS.', 'LAS OFICINAS DE DISCIPLINA.', 'INSPECTORÍA DESCENTRALIZADA COMPETENTE.', 'EL TRIBUNAL DISCIPLINARIO NACIONAL.', NULL, 'b', 'LA OFICINA GENERAL DE INTEGRIDAD INSTITUCIONAL A TRAVÉS DE LA OFICINA DE ASUNTOS INTERNOS.', '(texto: 45)** [TITULO III]  [CAPITULO IV]', '178183'),
(979, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ NO PODRÁ AUSENTARSE DEL ÁMBITO DE LA DEMARCACIÓN POLICIAL ...:', 'CUANDO LO CONSIDERE NECESARIO', 'CON CONOCIMIENTO PREVIO DE SU COMANDO.', 'SIN CONOCIMIENTO PREVIO DE SU COMANDO.', 'EN NINGUNA CIRCUNSTANCIA.', 'EN CUALQUIER MOMENTO.', NULL, 'c', 'SIN CONOCIMIENTO PREVIO DE SU COMANDO.', '(texto: 14)** [TITULO I]  [CAPITULO III]', '178184'),
(980, 'Ley Nº 30714 - Ley De Régimen Disciplinario De La Policia Nacional Del Perú', 'LA RECOPILACIÓN DE LAS INFORMACIONES QUE PERMITAN EL ESCLARECIMIENTO DE LOS HECHOS; CONSTITUYE:', 'UNA DE LAS ACCIONES PRELIMINARES QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-', 'UNA DE LAS ACCIONES PREVIAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-', 'UNA DE LAS ACCIONES PREVENTIVAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-', 'UNA DE LAS ACCIONES PREPARATORIAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO', 'UNO DE LOS ACTOS DE INVESTIGACIÓN QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO-', NULL, 'b', 'UNA DE LAS ACCIONES PREVIAS QUE PUEDEN REALIZARSE PARA EL INICIO DEL PROCEDIMIENTO', '(texto: 50)** [TITULO IV]  [CAPITULO I]', '178185'),
