(988, 'Decreto Legislativo N° 1318 - Ley Que Regula La Formación Profesional De La Poli', 'NO PUEDE RESTRINGIRSE O RETIRARSE LA CONDICIÓN DE ESTUDIANTE POR HECHOS VINCULADOS A:.', 'MEDIDA DISCIPLINARIA', 'ACTOS INDECOROSOS', 'MÉRITOS ALCANZADOS', 'PATERNIDAD', 'VIOLENCIA FAMILIAR', NULL, 'd', 'PATERNIDAD', '(ART: 11) [TITULO II]  [CAPITULO II]', '181511'),
