(1076, 'Decreto Supremo N° 021-2019-Jus Ley De Transparencia Y De Acceso A La Informació', 'RESPECTO A LA DENEGATORIA DE ACCESO A LA INFORMACIÓN PÚBLICA; SI EL REQUERIMIENTO DE INFORMACIÓN NO HUBIERE SIDO SATISFECHO, LA RESPUESTA HUBIERE SIDO AMBIGUA, O NO SE HUBIEREN CUMPLIDO LAS EXIGENCIAS PRECEDENTES, SE CONSIDERARÁ QUE EXISTIÓ:', 'NEGLIGENCIA EN BRINDARLA.', 'NEGATIVA EN BRINDARLA.', 'IMPEDIMENTO EN BRINDARLA.', 'DENEGATORIA EN BRINDARLA.', 'VOLUNTAD MANIFIESTA EN DENEGARLA.', NULL, 'b', 'NEGATIVA EN BRINDARLA.', '(texto: 13)** [TITULO III]', '186296'),
(1077, 'Decreto Supremo N° 021-2019-Jus Ley De Transparencia Y De Acceso A La Informació', 'RESPECTO A LA DENEGATORIA DE ACCESO A LA INFORMACIÓN PÚBLICA; NO SE PODRÁ NEGAR INFORMACIÓN CUANDO SE SOLICITE QUE ESTA SEA ENTREGADA EN UNA DETERMINADA FORMA O MEDIO, SIEMPRE QUE:', 'LA ENTIDAD ASUMA EL COSTO QUE SUPONGA EL PEDIDO.', 'SE TENGA LA LOGÍSTICA NECESARIA PARA ATENDER EL PEDIDO.', 'EL SOLICITANTE ASUMA EL COSTO QUE SUPONGA EL PEDIDO.', 'EL PEDIDO NO REPRESENTE NINGÚN COSTO.', 'EL SOLICITANTE SEA OTRA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA.', NULL, 'c', 'EL SOLICITANTE ASUMA EL COSTO QUE SUPONGA EL PEDIDO.', '(texto: 13)** [TITULO III]', '186297'),
(1078, 'Decreto Supremo N° 021-2019-Jus Ley De Transparencia Y De Acceso A La Informació', '"SE APLICA A TODAS LAS INSTITUCIONES INTEGRANTES DEL SISTEMA DE JUSTICIA: PODER JUDICIAL, MINISTERIO PÚBLICO, JUNTA NACIONAL DE JUSTICIA, TRIBUNAL CONSTITUCIONAL Y ACADEMIA DE LA MAGISTRATURA". EL PÁRRAFO ANTERIOR SE REFIERE A:', 'ÁMBITO DE APLICACIÓN DEL RÉGIMEN LEGAL DE TRANSPARENCIA', 'TRANSPARENCIA EN LOS PODERES DEL ESTADO.', 'TRANSPARENCIA EN EL PODER JUDICIAL.', 'ÁMBITO DE APLICACIÓN DE TRANSPARENCIA EN EL PODER JUDICIAL.', 'RÉGIMEN DE TRANSPARENCIA EN EL SISTEMA JUDICIAL.', NULL, 'a', 'ÁMBITO DE APLICACIÓN DEL RÉGIMEN LEGAL DE TRANSPARENCIA', '(texto: 38)** [TITULO VI]', '186298'),
