(1129, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EXCEPCIONES AL EJERCICIO DEL DERECHO DE INFORMACIÓN.- LA INFORMACIÓN QUE POR RAZONES DE SEGURIDAD NACIONAL EN EL ÁMBITO DEL ORDEN INTERNO, CUYA REVELACIÓN ORIGINARÍA UN RIESGO A LA INTEGRIDAD TERRITORIAL Y/O LA SUBSISTENCIA DEL SISTEMA DEMOCRÁTICO. ES CONSIDERADA INFORMACIÓN CLASIFICADA COMO:', 'ESTRICTAMENTE SECRETA.', 'ESTRICTAMENTE RESERVADA.', 'SECRETA.', 'CONFIDENCIAL.', 'RESERVADA.', NULL, 'e', 'RESERVADA.', '(texto: 16)** [TITULO III]', '186352'),
(1130, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL FUNCIONARIO PÚBLICO RESPONSABLE DE DAR INFORMACIÓN, QUE DE MODO ARBITRARIO OBSTRUYA EL ACCESO DEL SOLICITANTE A LA INFORMACIÓN REQUERIDA, SERÁ SANCIONADO POR:', 'LA COMISIÓN DE UNA FALTA GRAVE.', 'LA COMISIÓN DE UN DELITO GRAVE.', 'LA COMISIÓN DE DELITO DE CORRUPCIÓN DE FUNCIONARIOS.', 'LA COMISIÓN DE DELITO CONTRA LA FE PÚBLICA.', 'LA COMISIÓN DE UNA FALTA MUY GRAVE.', NULL, 'a', 'LA COMISIÓN DE UNA FALTA GRAVE.', '(texto: 4)** [TITULO I]', '186353'),
(1131, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'REGULACIÓN DE LAS EXCEPCIONES.- EL EJERCICIO DE ESTAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA SE ENMARCA DENTRO DE LAS LIMITACIONES QUE SEÑALA:', 'LA LEY DE TRANSPARENCIA Y ACCESO A LA INFORMACIÓN PÚBLICA.', 'LA CONSTITUCIÓN POLÍTICA DEL PERÚ.', 'EL CÓDIGO PENAL.', 'EL DERECHO INTERNACIONAL.', 'LA LEY DE PROCEDIMIENTOS ADMINISTRATIVOS.', NULL, 'b', 'LA CONSTITUCIÓN POLÍTICA DEL PERÚ.', '(texto: 18)** [TITULO III]', '186354'),
(1132, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'TODAS LAS ENTIDADES DE LA ADMINISTRACIÓN PÚBLICA QUEDAN OBLIGADAS A CUMPLIR LO ESTIPULADO EN LA PRESENTE NORMA; ESTE ENUNCIADO SE ENCUENTRA CONSIDERADO EN:', 'OBLIGACIONES Y FUNCIONES.', 'ATRIBUCIONES Y MEDIDAS CORRECTIVAS.', 'RESPONSABILIDADES Y SANCIONES.', 'OBJETO DE LA NORMA.', 'CUMPLIMIENTO DE FUNCIONES.', NULL, 'c', 'RESPONSABILIDADES Y SANCIONES.', '(texto: 4)**', '186355'),
(1133, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EXCEPCIONES AL EJERCICIO DEL DERECHO.- QUE CLASIFICACIÓN CORRESPONDE A LA INFORMACIÓN QUE CONTENGA CONSEJOS PRODUCIDOS COMO PARTE DEL PROCESO DELIBERATIVO Y CONSULTIVO PREVIO A LA TOMA DE UNA DECISIÓN DE GOBIERNO, SALVO QUE DICHA INFORMACIÓN SEA PÚBLICA:', 'INFORMACIÓN PÚBLICA.', 'INFORMACIÓN PRIVADA.', 'INFORMACIÓN SECRETA.', 'INFORMACIÓN RESERVADA.', 'INFORMACIÓN CONFIDENCIAL.', NULL, 'e', 'INFORMACIÓN CONFIDENCIAL.', '(texto: 17)** [TITULO III]', '186356'),
(1134, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'TASA APLICABLE.- EL SOLICITANTE QUE REQUIERA LA INFORMACIÓN DEBERÁ ABONAR SOLAMENTE EL IMPORTE CORRESPONDIENTE A LOS COSTOS DE REPRODUCCIÓN DE LA INFORMACIÓN:', 'ACCESIBLE.', 'REQUERIDA.', 'ARCHIVADA.', 'SOLICITADA.', 'DISPONIBLE.', NULL, 'b', 'REQUERIDA.', '(texto: 20)** [TITULO III]', '186357'),
(1135, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL DERECHO DE ACCESO A LA INFORMACIÓN PÚBLICA NO PODRÁ SER EJERCIDO RESPECTO DE LA INFORMACIÓN CLASIFICADA COMO RESERVADA. EN CONSECUENCIA LA EXCEPCIÓN COMPRENDE EL SIGUIENTE SUPUESTO:', 'INFORMACIÓN DEL ÁMBITO EXTERNO.', 'ÓRDENES DE OPERACIONES SECRETAS.', 'CUANDO ES CONFIDENCIAL.', 'EL ARMAMENTO Y MATERIAL LOGÍSTICO COMPROMETIDO EN OPERACIONES ESPECIALES.', 'LA INTEGRIDAD TERRITORIAL.', NULL, 'd', 'EL ARMAMENTO Y MATERIAL LOGÍSTICO COMPROMETIDO EN OPERACIONES ESPECIALES.', '(texto: 16)** [TITULO III]', '186358'),
(1136, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'BAJO RESPONSABILIDAD DE SU MÁXIMO REPRESENTANTE, LAS ENTIDADES OBLIGADAS A BRINDAR INFORMACIÓN IDENTIFICARÁN AL FUNCIONARIO RESPONSABLE DE BRINDAR LA INFORMACIÓN SOLICITADA EN VIRTUD DE LA PRESENTE LEY. EN CASO DE QUE ÉSTE NO HUBIERA SIDO DESIGNADO LAS RESPONSABILIDADES ADMINISTRATIVAS Y PENALES RECAERÁN EN:', 'EL SUPERIOR DEL SECRETARIO GENERAL.', 'EL JEFE DE ADMINISTRACIÓN DE LA ENTIDAD O QUIEN HAGA SUS VECES.', 'EL JEFE DE ARCHIVO DE LA ENTIDAD O QUIEN HAGA SUS VECES.', 'EL JEFE DE LA MESA DE PARTES DE INSTITUCIÓN O QUIEN HAGA SUS VECES.', 'EL SECRETARIO GENERAL DE LA INSTITUCIÓN O QUIEN HAGA SUS VECES.', NULL, 'e', 'EL SECRETARIO GENERAL DE LA INSTITUCIÓN O QUIEN HAGA SUS VECES.', '(texto: 8)** [TITULO III]', '186359'),
