(1140, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '¿TRANSCURRIDO QUÉ PLAZO, EL ARCHIVO NACIONAL PODRÁ DESTRUIR INFORMACIÓN QUE NO TENGA UTILIDAD PÚBLICA?', 'SIETE AÑOS.', 'DIEZ AÑOS.', 'CINCO AÑOS.', 'PRUDENCIAL.', 'RAZONABLE', NULL, 'e', 'RAZONABLE', '(texto: 21)** [TITULO III]', '186363'),
(1141, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EXCEPCIONES AL EJERCICIO DEL DERECHO.- QUÉ CLASIFICACIÓN CORRESPONDE A LA INFORMACIÓN QUE AL SER DIVULGADA OFICIALMENTE POR EL MINISTERIO DE RELACIONES EXTERIORES PUDIERA AFECTAR NEGATIVAMENTE LAS RELACIONES DIPLOMÁTICAS CON OTROS PAÍSES:', 'SECRETA.', 'CONFIDENCIAL.', 'ESTRICTAMENTE SECRETA.', 'RESERVADA.', 'PÚBLICA.', NULL, 'd', 'RESERVADA.', '(texto: 16)** [TITULO III]', '186364'),
