(1190, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"LOS OFICIALES Y SUBOFICIALES TIENEN LOS MISMOS DERECHOS Y OPORTUNIDADES PARA LOS ASCENSOS EN SUS RESPECTIVOS GRADOS Y CATEGORÍAS, POR LO QUE QUEDA PROSCRITA TODA PRÁCTICA DE DISCRIMINACIÓN, PRIVILEGIO O PREFERENCIA". EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DE IGUALDAD', 'PRINCIPIO DE NO DISCRIMINACIÓN', 'PRINCIPIO DE MERITOCRACIA', 'PRINCIPIO DE OBJETIVIDAD', 'PRINCIPIO DE PROPORCIONALIDAD', NULL, 'a', 'PRINCIPIO DE IGUALDAD', '(texto: UNICO)** [TITULO PRELIMINAR]', '186706'),
(1191, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"LOS PROCESOS DE ASCENSOS ESTÁN EXENTOS DE INTERÉS AJENO AL INSTITUCIONAL, POR LO QUE SE LLEVAN A CABO DE MANERA IMPARCIAL. LAS JUNTAS EVALUADORA, SELECTORA O REVISORA NO DEBEN TENER INTERÉS EN LOS RESULTADOS QUE SE ORIGINEN COMO CONSECUENCIA DE LOS PROCESOS DE ASCENSOS.". EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DE MERITOCRACIA', 'PRINCIPIO DE IMPARCIALIDAD', 'PRINCIPIO DE OBJETIVIDAD', 'PRINCIPIO DE TRANSPARENCIA', 'PRINCIPIO DE JUSTICIA', NULL, 'b', 'PRINCIPIO DE IMPARCIALIDAD', '(texto: UNICO)** [TITULO PRELIMINAR]', '186707'),
(1192, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"LOS ASCENSOS EN LA CARRERA POLICIAL SE FUNDAMENTAN EN LOS MÉRITOS Y EN LAS CAPACIDADES PERSONALES, PROFESIONALES Y TÉCNICAS DEL PERSONAL CONSIGNADAS EN LA PRESENTE LEY." . EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DE EFICIENCIA Y EFICACIA', 'PRINCIPIO DE PRESUNCIÓN DE LICITUD', 'PRINCIPIO DE MERITOCRACIA.', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO', 'PRINCIPIO DE PERTENENCIA INSTITUCIONAL', NULL, 'c', 'PRINCIPIO DE MERITOCRACIA.', '(texto: UNICO)** [TITULO PRELIMINAR]', '186708'),
(1193, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"LA APLICACIÓN DE LAS NORMAS ESTABLECIDAS SE REALIZA A TRAVÉS DE FACTORES, SUBFACTORES Y ELEMENTOS CLARAMENTE DEFINIDOS PARA LA EVALUACIÓN DE LAS APTITUDES PROFESIONALES, TÉCNICAS, DISCIPLINARIAS Y PSICOSOMÁTICAS". EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DE MERITOCRACIA', 'PRINCIPIO DE OBJETIVIDAD', 'PRINCIPIO DE EFICIENCIA Y EFICACIA', 'PRINCIPIO DE INTEGRIDAD', 'PRINCIPIO DE PROPORCIONALIDAD', NULL, 'b', 'PRINCIPIO DE OBJETIVIDAD', '(texto: UNICO)** [TITULO PRELIMINAR]', '186709'),
(1194, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"SE FUNDAMENTA EN LA PUBLICACIÓN DE TODAS LAS ETAPAS DE LOS PROCESOS DE ASCENSOS. LOS RESULTADOS SE PUBLICAN DESPUÉS DE CADA EVALUACIÓN EN LA PÁGINA WEB Y MEDIANTE LOS CANALES O PLATAFORMAS DE COMUNICACIÓN DE LA POLICÍA NACIONAL DEL PERÚ (PNP)". EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DE PUBLICIDAD', 'PRINCIPIO DE RENDICIÓN DE CUENTAS', 'PRINCIPIO DE EFICIENCIA Y EFICACIA', 'PRINCIPIO DE LEGALIDAD', 'PRINCIPIO DE TRANSPARENCIA', NULL, 'e', 'PRINCIPIO DE TRANSPARENCIA', '(texto: UNICO)** [TITULO PRELIMINAR]', '186710'),
(1195, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"LOS PROCESOS DE ASCENSOS SE LLEVAN A CABO EN CUMPLIMIENTO DE LAS NORMAS CONSTITUCIONALES, LAS DISPOSICIONES CONTENIDAS EN LA PRESENTE LEY Y OTRAS NORMAS LEGALES Y REGLAMENTARIAS SOBRE LA MATERIA". EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DE PRESUNCIÓN DE LICITUD', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO', 'PRINCIPIO DE JUSTICIA', 'PRINCIPIO DE LEGALIDAD', 'PRINCIPIO DE PRIMACÍA DE LA PERSONA HUMANA Y SUS DERECHOS FUNDAMENTALES', NULL, 'd', 'PRINCIPIO DE LEGALIDAD', '(texto: UNICO)** [TITULO PRELIMINAR]', '186711'),
(1196, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '"LOS CANDIDATOS E INTEGRANTES DE LAS JUNTAS QUE PARTICIPAN EN LOS PROCESOS DE ASCENSOS OBSERVAN LAS NORMAS ÉTICAS Y DE CONDUCTA, DEMOSTRANDO EN TODO MOMENTO HONESTIDAD, RESPETO Y TRANSPARENCIA EN LAS INTERACCIONES PERSONALES". EL ENUNCIADO CORRESPONDE A:', 'PRINCIPIO DEL DEBIDO PROCEDIMIENTO', 'PRINCIPIO DE PROBIDAD', 'PRINCIPIO DE TRANSPARENCIA', 'PRINCIPIO DE JUSTICIA', 'PRINCIPIO DE INTEGRIDAD', NULL, 'e', 'PRINCIPIO DE INTEGRIDAD', '(texto: UNICO)** [TITULO PRELIMINAR]', '186712'),
(1197, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ESTABLECER LOS PRINCIPIOS, ETAPAS, REQUISITOS, APTITUDES Y PROCEDIMIENTOS PARA MATERIALIZAR LA ORGANIZACIÓN, EJECUCIÓN, CONTROL Y EVALUACIÓN DE LOS PROCESOS DE ASCENSOS DE LOS OFICIALES Y', 'EL OBJETO DE LA LEY 31873', 'LA FINALIDAD DE LA LEY 31873', 'LA NATURALEZA DE LA LEY 31873', 'EL OBJETIVO DE LA LEY 31873', 'EL ALCANCE DE LA LEY 31873', NULL, 'a', 'EL OBJETO DE LA LEY 31873', '(texto: 1)** [TITULO I]  [CAPITULO UNICO]', '186713'),
(1198, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'GARANTIZAR UNA LÍNEA DE CARRERA POLICIAL AL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ (PNP) SUSTENTADA EN UN SISTEMA DE EVALUACIÓN DE MANERA MERITOCRÁTICA, EN CONSIDERACIÓN A SUS CAPACIDADES, CONOCIMIENTOS, HABILIDADES, DESEMPEÑO PROFESIONAL Y APTITUDES, EN ESTRICTA OBSERVANCIA DEL ORDENAMIENTO LEGAL VIGENTE; CONSTITUYE:', 'EL OBJETO DE LA LEY 31873', 'LA FINALIDAD DE LA LEY 31873', 'LA NATURALEZA DE LA LEY 31873', 'EL OBJETIVO DE LA LEY 31873', 'EL ALCANCE DE LA LEY 31873', NULL, 'b', 'LA FINALIDAD DE LA LEY 31873', '(texto: 2)** [TITULO I]  [CAPITULO UNICO]', '186714'),
(1199, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ESTABLECER UN PROCEDIMIENTO OBJETIVO PARA CUANTIFICAR LOS FACTORES DE LA CARRERA POLICIAL, PARA LA PROMOCIÓN DE LOS OFICIALES Y SUBOFICIALES MÁS CALIFICADOS E IDÓNEOS AL GRADO INMEDIATO SUPERIOR EN LA POLICÍA NACIONAL DEL PERÚ (PNP); CONSTITUYE:', 'EL OBJETO DE LA LEY 31873', 'LA FINALIDAD DE LA LEY 31873', 'LA NATURALEZA DE LA LEY 31873', 'EL OBJETIVO DE LA LEY 31873', 'EL ALCANCE DE LA LEY 31873', NULL, 'b', 'LA FINALIDAD DE LA LEY 31873', '(texto: 2)** [TITULO I]  [CAPITULO UNICO]', '186715'),
