(1248, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '¿CUÁL ES EL ÓRGANO COMPETENTE PARA APROBAR LAS VACANTES ANUALES EN EL GRADO DE OFICIALES GENERALES SEGÚN LA NORMATIVA DE LA LEY 31873?', 'LA COMANDANCIA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ', 'LA PRESIDENCIA DEL CONSEJO DE MINISTROS', 'LA DIRECCIÓN DE RECURSOS HUMANOS', 'EL PRESIDENTE DE LA REPÚBLICA MEDIANTE RESOLUCIÓN SUPREMA', 'EL MINISTERIO DEL INTERIOR MEDIANTE RESOLUCIÓN MINISTERIAL', NULL, 'd', 'EL PRESIDENTE DE LA REPÚBLICA MEDIANTE RESOLUCIÓN SUPREMA', '(texto: (ART: 44)**  Articulo 44.- Vacantes)**', '186776'),
(1249, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CONSIDERANDO LA DIFUSIÓN DE LAS RESOLUCIONES QUE APRUEBAN VACANTES, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA?', 'TODAS LAS RESOLUCIONES DEBEN PUBLICARSE ÚNICAMENTE EN EL SISTEMA INTEGRADO DE GESTIÓN DE LA CARRERA', 'LAS RESOLUCIONES SUPREMAS Y MINISTERIALES SE PUBLICAN TANTO EN EL SISTEMA INTEGRADO DE GESTIÓN DE LA', 'LAS RESOLUCIONES DE LA DIRECCIÓN DE RECURSOS HUMANOS SE PUBLICAN SOLO EN EL DIARIO OFICIAL EL PERUANO.', 'LAS RESOLUCIONES DE LA COMANDANCIA GENERAL REQUIEREN PUBLICACIÓN EN LA GACETA INTERNA DE LA POLICÍA.', 'NINGUNA RESOLUCIÓN REQUIERE PUBLICACIÓN PARA SER VÁLIDA.', NULL, 'b', 'LAS RESOLUCIONES SUPREMAS Y MINISTERIALES SE PUBLICAN TANTO EN EL SISTEMA INTEGRADO DE', '(texto: (ART: 44)**  Articulo 44.- Vacantes)**', '186778'),
(1250, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ENTRE LAS CAUSALES QUE GENERAN PLAZAS VACANTES ANUALES SEGÚN LA LEY 31873, ¿CUÁL DE LAS SIGUIENTES NO ESTÁ EXPRESAMENTE SEÑALADA EN EL ARTÍCULO 44 COMO CAUSAL DIRECTA?', 'ASCENSOS DENTRO DE LA ESPECIALIDAD', 'FALLECIMIENTO', 'RENUNCIA VOLUNTARIA SIN CAUSA JUSTIFICADA', 'PASES A LA SITUACIÓN DE RETIRO', 'CAMBIOS DERIVADOS EN LA ORGANIZACIÓN', NULL, 'c', 'RENUNCIA VOLUNTARIA SIN CAUSA JUSTIFICADA', '(texto: (ART: 44)**  Articulo 44.- Vacantes)**', '186779'),
