(1287, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRECISE USTED QUÉ RESPONSABILIDAD GENERA EL INCUMPLIMIENTO INJUSTIFICADO DE LOS PLAZOS PREVISTOS PARA LAS ACTUACIONES DE LAS ENTIDADES.', 'RESPONSABILIDAD PENAL PARA LA AUTORIDAD OBLIGADA.', 'RESPONSABILIDAD JUDICIAL PARA LA AUTORIDAD OBLIGADA.', 'RESPONSABILIDAD ADMINISTRATIVA Y PENAL.', 'RESPONSABILIDAD PENAL Y CIVIL.', 'RESPONSABILIDAD DISCIPLINARIA PARA LA AUTORIDAD OBLIGADA.', NULL, 'e', 'RESPONSABILIDAD DISCIPLINARIA PARA LA AUTORIDAD OBLIGADA.', '(ART: 143)** [TITULO II]  [CAPITULO IV]', '181860'),
(1288, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRECISE USTED EN ATENCIÓN A QUE RAZONES, LA AUTORIDAD A CARGO DEL PROCEDIMIENTO, PUEDE REDUCIR PLAZOS O ANTICIPAR LOS TÉRMINOS:', 'OPORTUNIDAD Y CONVIVENCIA.', 'CELERIDAD Y PRONTITUD.', 'OPORTUNIDAD O CONVENIENCIA.', 'OPORTUNIDAD Y CELERIDAD.', 'PRONTITUD Y CELERIDAD.', NULL, 'c', 'OPORTUNIDAD O CONVENIENCIA.', '(ART: 141)** [TITULO II]  [CAPITULO IV]', '181861'),
(1289, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. IV - PRINCIPIOS DEL PROCEDIMIENTO ADMINISTRATIVO.- PRINCIPIO DE PRESUNCIÓN DE VERACIDAD.- EN LA TRAMITACIÓN DEL PROCEDIMIENTO ADMINISTRATIVO, SE PRESUME QUE LOS DOCUMENTOS Y DECLARACIONES FORMULADOS POR LOS ADMINISTRADOS EN LA FORMA PRESCRITA POR ESTA LEY, RESPONDEN:', 'A LA VERDAD DE LOS HECHOS QUE ELLOS AFIRMAN', 'NO NECESARIAMENTE A LA VERDAD.', 'A LA VERDAD Y NO TIENEN QUE SER VERIFICADAS EN NINGÚN MOMENTO.', 'A UNA PRESUNCIÓN DE VERDAD.', 'CATEGORICAMENTE A UNA VERDAD.', NULL, 'a', 'A LA VERDAD DE LOS HECHOS QUE ELLOS AFIRMAN', '(ART: IV)** [TITULO PRELIMINAR]', '181862'),
(1290, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN EL CASO DE NO ENCONTRAR AL ADMINISTRADO U OTRA PERSONA EN EL DOMICILIO SEÑALADO EN EL PROCEDIMIENTO, EL NOTIFICADOR DEBERÁ :', 'REGRESAR OTRO DÍA.', 'COLOCAR UN AVISO EN DICHO DOMICILIO INDICANDO LA NUEVA FECHA EN QUE SE HARÁ EFECTIVA LA SIGUIENTE', 'DAR POR NOTIFICADO AL ADMINISTRADO.', 'REGRESAR A LA ADMINISTRACIÓN DANDO POR NOTIFICADO AL ADMINISTRADO.', 'DEJAR LA NOTIFICACIÓN AL VECINO MÁS CERCANO.', NULL, 'b', 'COLOCAR UN AVISO EN DICHO DOMICILIO INDICANDO LA NUEVA FECHA EN QUE SE HARÁ EFECTIVA LA', '(ART: 21)** [TITULO I]  [CAPITULO III]', '181863'),
(1291, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL SIGUIENTE ENUNCIADO: QUIENES PARTICIPAN EN EL PROCEDIMIENTO DEBEN AJUSTAR SU ACTUACIÓN DE TAL MODO QUE SE DOTE AL TRÁMITE DE LA MÁXIMA DINÁMICA POSIBLE, EVITANDO ACTUACIONES PROCESALES QUE DIFICULTEN SU DESENVOLVIMIENTO O CONSTITUYAN MEROS FORMALISMOS, A FIN DE ALCANZAR UNA DECISIÓN EN TIEMPO RAZONABLE, SIN QUE ELLO RELEVE A LAS AUTORIDADES DEL RESPETO AL DEBIDO PROCEDIMIENTO O VULNERE EL ORDENAMIENTO...CORRESPONDE AL PRINCIPIO DE:', 'IMPARCIALIDAD.', 'IMPULSO DE OFICIO.', 'VERDAD MATERIAL.', 'EFICACIA.', 'CELERIDAD.', NULL, 'e', 'CELERIDAD.', '(ART: IV)** [TITULO PRELIMINAR]', '181864'),
(1292, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'RECIBIDA LA SOLICITUD O LA DISPOSICIÓN DE AUTORIDAD SUPERIOR, SEGÚN EL CASO, PARA INICIAR UN PROCEDIMIENTO, LAS AUTORIDADES DE OFICIO DEBEN ASEGURARSE DE SU PROPIA COMPETENCIA PARA PROSEGUIR CON EL NORMAL DESARROLLO DEL PROCEDIMIENTO, SIGUIENDO LOS CRITERIOS APLICABLES AL CASO DE LA MATERIA : (SEÑALE LA CORRECTA)', 'EL TERRITORIO, EL TIEMPO, EL GRADO O LA CUANTÍA.', 'EL TERRITORIO, EL TIEMPO, EL VALOR APLICABLE.', 'EL TERRITORIO, EL ESPACIO Y LA CUANTÍA.', 'EL TIEMPO, EL ESPACIO, EL VALOR APLICABLE Y LA CUANTÍA.', 'EL TIEMPO, EL ESPACIO, Y LA AUTORIDAD QUE LE CORRESPONDA DE ACUERDO A DONDE SE HALLAN SUCEDIDO LOS', NULL, 'a', 'EL TERRITORIO, EL TIEMPO, EL GRADO O LA CUANTÍA.', '(ART: 80)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO IV]', '181865'),
(1293, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LUEGO DE RESUELTO EL CONFLICTO DE COMPETENCIA, EL ÓRGANO QUE RESULTE COMPETENTE PARA CONOCER EL ASUNTO CONTINUA EL PROCEDIMIENTO SEGÚN SU ESTADO Y CONSERVA TODO LO ACTUADO, SALVO AQUELLO:', 'QUE NO ESTE TÉCNICAMENTE DESCRITO.', 'QUE NO SE HAYA EFECTUADO EN SU TIEMPO Y TERRITORIO.', 'QUE NO SEA JURÍDICAMENTE POSIBLE.', 'QUE NO ESTÉ RESUELTO POR EL ÓRGANO COMPETENTE.', 'QUE NO ESTÉ DE ACUERDO AL CRITERIO DEL ÓRGANO QUE RESULTE COMPETENTE.', NULL, 'c', 'QUE NO SEA JURÍDICAMENTE POSIBLE.', '(ART: 87)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO IV]', '181866'),
(1294, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'INDIQUE USTED DE LOS SIGUIENTES ENUNCIADOS, CUÁL CORRESPONDE AL PRINCIPIO DE IMPARCIALIDAD.', 'LAS NORMAS DE PROCEDIMIENTO DEBEN SER INTERPRETADAS EN FORMA FAVORABLE A LA ADMISIÓN Y DECISIÓN FINAL', 'EN LA TRAMITACIÓN DEL PROCEDIMIENTO ADMINISTRATIVO, SE PRESUME QUE LOS DOCUMENTOS Y DECLARACIONES', 'LAS AUTORIDADES ADMINISTRATIVAS ACTÚAN SIN NINGUNA CLASE DE DISCRIMINACIÓN ENTRE LOS ADMINISTRADOS,', 'LAS AUTORIDADES ADMINISTRATIVAS DEBEN ACTUAR CON RESPETO A LA CONSTITUCIÓN, LA LEY Y AL DERECHO,', 'QUIENES PARTICIPAN EN EL PROCEDIMIENTO DEBEN AJUSTAR SU ACTUACIÓN DE TAL MODO QUE SE DOTE AL TRÁMITE', NULL, 'c', 'LAS AUTORIDADES ADMINISTRATIVAS ACTÚAN SIN NINGUNA CLASE DE DISCRIMINACIÓN ENTRE LOS', '(ART: IV)** [TITULO PRELIMINAR]', '181867'),
(1295, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL PRINCIPIO DE IMPULSO DE OFICIO CONSIDERA QUE:', 'LAS AUTORIDADES DEBEN DIRIGIR E IMPULSAR DE OFICIO EL PROCEDIMIENTO Y ORDENAR LA REALIZACIÓN O PRÁCTICA', 'LA TRAMITACIÓN DE LOS PROCEDIMIENTOS ADMINISTRATIVOS SE SUSTENTARÁ EN LA APLICACIÓN DE LA FISCALIZACIÓN', 'LA AUTORIDAD ADMINISTRATIVA DEBERÁ BRINDAR A LOS ADMINISTRADOS O SUS REPRESENTANTES INFORMACIÓN', 'LA AUTORIDAD ADMINISTRATIVA DEBERÁ ESTABLECER REQUISITOS SIMILARES PARA TRÁMITES SIMILARES,', 'NINGUNO.', NULL, 'a', 'LAS AUTORIDADES DEBEN DIRIGIR E IMPULSAR DE OFICIO EL PROCEDIMIENTO Y ORDENAR LA REALIZACIÓN O', '(ART: IV)** [TITULO PRELIMINAR]', '181868'),
(1296, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 191.- PRECISE USTED CUÁL ES LA FORMA EN QUE LA AUTORIDAD ADMINISTRATIVA PODRÁ DECLARAR EL ABANDONO DEL PROCEDIMIENTO INICIADO A SOLICITUD DEL ADMINISTRADO:', 'DE OFICIO.', 'A SOLICITUD DEL ADMINISTRADO.', 'DE OFICIO O A SOLICITUD DEL ADMINISTRADO..', 'DE OFICIO Y A SOLICITUD DEL ADMINISTRADO.', 'A SOLICITUD DEL ADMINISTRADOR.', NULL, 'c', 'DE OFICIO O A SOLICITUD DEL ADMINISTRADO..', '(ART: 191)** [TITULO II]  [CAPITULO VIII]', '181869'),
(1297, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'INTEGRA UN SISTEMA ORGÁNICO QUE TIENE AUTONOMÍA RESPECTO DE OTRAS RAMAS DEL DERECHO:', 'LAS RONDAS CAMPESINAS.', 'LOS PODERES DEL ESTADO.', 'LA JUSTICIA CIVIL MILITAR.', 'EL ORDENAMIENTO JERÁRQUICO ADMINISTRATIVO.', 'EL ORDENAMIENTO JURÍDICO ADMINISTRATIVO.', NULL, 'e', 'EL ORDENAMIENTO JURÍDICO ADMINISTRATIVO.', '(ART: V)** [TITULO PRELIMINAR]', '181870'),
(1298, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 12 - EFECTOS DE LA DECLARACIÓN DE NULIDAD.- LA DECLARACIÓN DE NULIDAD TENDRÁ EFECTO DECLARATIVO Y RETROACTIVO A LA FECHA DEL ACTO, SALVO :', 'DERECHOS ADQUIRIDOS POR LOS ADMINISTRADOS, EN CUYO CASO OPERARÁ CONFORME A LEY.', 'DERECHOS ADQUIRIDOS DE BUENA FE POR TERCEROS, EN CUYO CASO OPERARÁ A FUTURO.', 'OBLIGACIONES ADQUIRIDOS DE BUENA FE POR LOS ADMINISTRADOS, EN CUYO CASO OPERARÁ A FUTURO.', 'DERECHOS CONCEDIDOS DE BUENA FE A TERCEROS, EN CUYO CASO OPERARÁ A FUTURO.', 'DERECHOS ADQUIRIDOS DE BUENA FE POR TERCEROS, EN CUYO CASO OPERARÁ DE INMEDIATO CONFORME A LEY.', NULL, 'b', 'DERECHOS ADQUIRIDOS DE BUENA FE POR TERCEROS, EN CUYO CASO OPERARÁ A FUTURO.', '(ART: 12)** [TITULO I]  [CAPITULO II]', '181871'),
(1299, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SON FUENTES DEL PROCEDIMIENTO ADMINISTRATIVO, SEÑALE EL CORRECTO:', 'LA LEGALIDAD.', 'EL DEBIDO PROCEDIMIENTO.', 'LA RAZONABILIDAD.', 'LAS DISPOSICIONES CONSTITUCIONALES.', 'LA IMPARCIALIDAD.', NULL, 'd', 'LAS DISPOSICIONES CONSTITUCIONALES.', '(ART: V)** [TITULO PRELIMINAR]', '181872'),
(1300, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL SIGUIENTE ENUNCIADO : LAS NORMAS DE PROCEDIMIENTO DEBEN SER INTERPRETADAS EN FORMA FAVORABLE A LA ADMISIÓN Y DECISIÓN FINAL DE LAS PRETENSIONES DE LOS ADMINISTRADOS, DE MODO QUE SUS DERECHOS E INTERESES NO SEAN AFECTADOS POR LA EXIGENCIA DE ASPECTOS FORMALES QUE PUEDAN SER SUBSANADOS DENTRO DEL PROCEDIMIENTO, SIEMPRE QUE DICHA EXCUSA NO AFECTE DERECHOS DE TERCEROS O EL INTERÉS PÚBLICO....CORRESPONDE AL PRINCIPIO DE:', 'RAZONABILIDAD.', 'IMPARCIALIDAD.', 'INFORMALISMO.', 'EFICACIA.', 'LEGALIDAD.', NULL, 'c', 'INFORMALISMO.', '(ART: IV)** [TITULO PRELIMINAR]', '181873'),
(1301, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 211 - REQUISITOS DEL RECURSO.- EL ESCRITO DEL RECURSO A PARTE DE SER AUTORIZADO POR LETRADO, DEBE CUMPLIR CON LOS REQUISITOS PREVISTOS EN EL ARTÍCULO 113 : (SEÑALE EL REQUISITO INCORRECTO).', 'NOMBRES Y APELLIDOS COMPLETOS, DOMICILIO Y DNI O CARNE DE EXTRANJERÍA DEL ADMINISTRADO.', 'EXPRESIÓN CONCRETA DE LO PEDIDO.', 'LUGAR, FECHA, FIRMA O HUELLA DIGITAL, EN CASO DE NO SABER FIRMAR O ESTAR IMPEDIDO.', 'NOMBRES Y APELLIDOS COMPLETOS DE SU CÓNYUGE, PADRES E HIJOS COMO FILIACIÓN.', 'LA INDICACIÓN DEL ÓRGANO, LA ENTIDAD O LA AUTORIDAD A LA CUÁL ES DIRIGIDO.', NULL, 'd', 'NOMBRES Y APELLIDOS COMPLETOS DE SU CÓNYUGE, PADRES E HIJOS COMO FILIACIÓN.', '(ART: 113)** [TITULO II]  [CAPITULO III]', '181874'),
(1302, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SON ACTOS ADMINISTRATIVOS: (SEÑALE LA RESPUESTA CORRECTA) .', 'LAS DECLARACIONES DE LAS ENTIDADES QUE, EN EL MARCO DE LAS NORMAS DE DERECHO PÚBLICO ESTÉN DESTINADAS', 'LOS ACTOS DE ADMINISTRACIÓN INTERNA DE LAS ENTIDADES DESTINADAS A ORGANIZAR O HACER FUNCIONAR SUS', 'LOS COMPORTAMIENTOS Y ACTIVIDADES MATERIALES DE LAS ENTIDADES.', 'LOS COMPORTAMIENTOS Y ACTIVIDADES SUBJETIVAS DE LAS ENTIDADES.', 'LOS ACTOS DE ADMINISTRACIÓN EXTERNA DE LAS ENTIDADES.', NULL, 'a', 'LAS DECLARACIONES DE LAS ENTIDADES QUE, EN EL MARCO DE LAS NORMAS DE DERECHO PÚBLICO ESTÉN', '(ART: 1)** [TITULO I]  [CAPITULO I]', '181875'),
(1303, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA COPIA DE CUALQUIER DOCUMENTO PÚBLICO, SIEMPRE QUE EXISTA CONSTANCIA DE QUE ES AUTÉNTICA, SEÑALE LA RESPUESTA CORRECTA:', 'GOZA DE LA MISMA VALIDEZ Y EFICACIA QUE ÉSTOS.', 'SÓLO GOZA DE EFICACIA.', 'SÓLO GOZA DE VALIDEZ.', 'NO ES VÁLIDA.', 'GOZA DE PRIORIDAD EN SU ATENCIÓN.', NULL, 'a', 'GOZA DE LA MISMA VALIDEZ Y EFICACIA QUE ÉSTOS.', '(ART: 43)** [TITULO II]  [CAPITULO I]', '181876'),
(1304, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CUÁNDO EL ERROR EN LA CALIFICACIÓN DEL RECURSO POR PARTE DEL RECURRENTE NO SERÁ OBSTÁCULO PARA SU TRAMITACIÓN? : MARCA LA CORRECTA', 'SI EL ESCRITO ESTÁ CORREGIDO POR EL ABOGADO DEFENSOR.', 'SI SOLICITA VERBALMENTE QUE SE ACEPTE SU RECURSO.', 'SI DEL ESCRITO SE DEDUZCA SU VERDADERO CARÁCTER.', 'SI EL ESCRITO SE PRESENTÓ A MANUSCRITO.', 'NO PUEDE ARTICULARLOS.', NULL, 'c', 'SI DEL ESCRITO SE DEDUZCA SU VERDADERO CARÁCTER.', '(ART: 213)** [TITULO III]  [CAPITULO II]', '181877'),
(1305, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SE DECLARA ABANDONO DEL PROCEDIMIENTO, CUANDO EL ADMINISTRADO INCUMPLA ALGÚN TRÁMITE QUE SE HUBIERA SIDO REQUERIDO QUE PRODUZCA PARALIZACIÓN POR : MARCA EL CORRECTO:', '10 DÍAS.', '30 DÍAS.', '07 DÍAS.', '15 DÍAS.', '20 DÍAS.', NULL, 'b', '30 DÍAS.', '(ART: 191)** [TITULO II]  [CAPITULO VIII]', '181878'),
(1306, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA INTERPOSICIÓN DE CUALQUIER RECURSO, EXCEPTO LOS CASOS EN QUE UNA NORMA LEGAL ESTABLEZCA LO CONTRARIO, NO SUSPENDERÁ LA EJECUCIÓN DEL ACTO IMPUGNADO; NO OBSTANTE LO DISPUESTO EN EL NUMERAL ANTERIOR, LA AUTORIDAD A QUIEN COMPETA RESOLVER EL RECURSO SUSPENDE DE OFICIO O A PETICIÓN DE PARTE LA EJECUCIÓN DEL ACTO RECURRIDO CUANDO CONCURRA ALGUNA DE LAS SIGUIENTES CIRCUNSTANCIAS:', 'QUE LA EJECUCIÓN NO CAUSE PERJUICIOS DE IMPOSIBLE REPARACIÓN.', 'QUE SE APRECIE OBJETIVAMENTE LA EXISTENCIA DE UN VICIO DE NULIDAD TRASCENDENTE.', 'QUE SE APRECIE OBJETIVAMENTE LA EXISTENCIA DE UN VICIO DE NULIDAD INTRASCENDENTE.', 'QUE LA EJECUCIÓN NO CAUSE PERJUICIOS DE DIFÍCIL REPARACIÓN.', 'QUE EL DAÑO CAUSADO SEA TRASCENDENTE.', NULL, 'b', 'QUE SE APRECIE OBJETIVAMENTE LA EXISTENCIA DE UN VICIO DE NULIDAD TRASCENDENTE.', '(ART: 216)** [TITULO III]  [CAPITULO II]', '181879'),
(1307, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL PLAZO MÁXIMO PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER ES :', '02 DÍAS.', '07 DÍAS.', '05 DÍAS.', '03 DÍAS.', 'EN EL DÍA.', NULL, 'd', '03 DÍAS.', '(ART: 132)** [TITULO II]  [CAPITULO IV]', '181880'),
(1308, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL RÉGIMEN DE LA NOTIFICACIÓN CONSISTE EN : MARCA LA INCORRECTA', 'NOTIFICAR EN EL ÚLTIMO DOMICILIO QUE LA PERSONA, A QUIÉN DEBA NOTIFICAR, HAYA SEÑALADO ANTE EL ÓRGANO', 'EN CASO NO HAYA SEÑALADO DOMICILIO, SE DEBE AGOTAR SU BÚSQUEDA MEDIANTE LOS MEDIOS QUE SE ENCUENTREN', 'NOTIFICAR EN EL DOMICILIO QUE CONSTA EN EL EXPEDIENTE.', 'SI NO SE ENCUENTRA LA PERSONA, SE ENTREGA AL VECINO.', 'EN EL ACTO DE NOTIFICACIÓN DEBE ENTREGARSE COPIA DEL ACTO DE NOTIFICACIÓN.', NULL, 'd', 'SI NO SE ENCUENTRA LA PERSONA, SE ENTREGA AL VECINO.', '(ART: 21)** [TITULO I]  [CAPITULO III]', '181881'),
(1309, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA LEY 27444 SEÑALA QUE, LOS ACTOS ADMINISTRATIVOS QUE AGOTEN LA VIA ADMINISTRATIVA PODRÁN SER:', 'IMPUGNADOS ANTE EL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO.', 'IMPUGNADOS ANTE EL SUPERIOR JERÁRQUICO DEL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO.', 'IMPUGNADOS ANTE EL PODER JUDICIAL.', 'APELADOS ANTE EL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO.', 'APELADOS ANTE EL SUPERIOR JERÁRQUICO DEL MISMO ÓRGANO QUE DICTO EL ACTO RESOLUTIVO.', NULL, 'c', 'IMPUGNADOS ANTE EL PODER JUDICIAL.', '(ART: 218)** [TITULO III]  [CAPITULO II]', '181882'),
(1310, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 50 - SUJETOS DEL PROCEDIMIENTO.- LA AUTORIDAD ADMINISTRATIVA ES EL AGENTE DE LAS ENTIDADES QUE, BAJO CUALQUIER RÉGIMEN JURÍDICO Y EJERCIENDO POTESTADES PÚBLICAS CONDUCEN: ( COMPLETE LO CORRECTO)', 'EL INICIO, LA INSTRUCCIÓN, LA SUSTANCIACIÓN, LA RESOLUCIÓN, LA EJECUCIÓN, O QUE DE OTRO MODO PARTICIPAN EN', 'LA INVESTIGACIÓN, LA INSTRUCCIÓN Y EL JUICIO, O QUE DE OTRO MODO PARTICIPAN EN LA GESTIÓN DE LOS', 'EL INICIO, LA FINALIZACIÓN, LA RESOLUCIÓN, LA EJECUCIÓN, O QUE DE OTRO MODO PARTICIPAN EN LA GESTIÓN DE LOS', 'EL TRÁMITE, LA REPRESENTACIÓN PROCESAL, LA RESOLUCIÓN, LA EJECUCIÓN, O QUE DE OTRO MODO PARTICIPAN EN LA', 'EL INICIO, LA INSTRUCCIÓN, LA SUSTANCIACIÓN, LA ADMINISTRACIÓN, LA GESTIÓN, O QUE DE OTRO MODO PARTICIPAN EN', NULL, 'a', 'EL INICIO, LA INSTRUCCIÓN, LA SUSTANCIACIÓN, LA RESOLUCIÓN, LA EJECUCIÓN, O QUE DE OTRO MODO', '(ART: 50)** [TITULO II]  [CAPITULO II]', '181883'),
(1311, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'MARQUE LA INCORRECTA: EL CITATORIO SE RIGE POR EL RÉGIMEN COMÚN DE LA NOTIFICACIÓN, HACIENDO CONSTAR EN ELLA LO SIGUIENTE:', 'LA DISPOSICIÓN LEGAL QUE FACULTA AL ÓRGANO A REALIZAR ESTA CITACIÓN.', 'EL DESAGRAVIO, EN CASO DE INASISTENCIA AL REQUERIMIENTO.', 'LOS NOMBRES Y APELLIDOS DEL CITADO.', 'EL NOMBRE Y LA DIRECCIÓN DEL ÓRGANO QUE CITA, CON INDICACIÓN DE LA AUTOPRIDAD REQUIRIENTE.', 'EL OBJETO Y ASUNTO DE LA COMPARECENCIA.', NULL, 'b', 'EL DESAGRAVIO, EN CASO DE INASISTENCIA AL REQUERIMIENTO.', '(ART: 59)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO I]', '181884'),
(1312, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LAS AUTORIDADES ADMINISTRATIVAS NO PODRÁN DEJAR DE RESOLVER LAS CUESTIONES QUE SE LES PROPONGA, POR DEFICIENCIA DE SUS FUENTES; EN TALES CASOS, ACUDIRÁN A:', 'EL PRINCIPIO DE IGUALDAD PROCESAL.', 'EL PRINCIPIO DE LA DOBLE INSTANCIA.', 'LOS PRINCIPIOS DEL DERECHO ADMINISTRATIVO.', 'LOS PRINCIPIOS DEL DERECHO PENAL.', 'LOS PRINCIPIOS DEL DERECHO LABORAL.', NULL, 'c', 'LOS PRINCIPIOS DEL DERECHO ADMINISTRATIVO.', '(ART: VIII)** [TITULO PRELIMINAR]', '181885'),
(1313, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'INDIQUE CUÁL ES EL ENUNCIADO CORRECTO QUE CORRESPONDE A LA COPIA DE LOS ESCRITOS:', 'EL ESCRITO ES PRESENTADO EN PAPEL MEMBRETADO.', 'EL ESCRITO ES PRESENTADO EN ORIGINAL SIN COPIA.', 'EL ESCRITO ES PRESENTADO EN ORIGINAL ACOMPAÑADO DE COPIA ILEGIBLE.', 'EL CARGO ASÍ EXPEDIDO TIENE EL MISMO VALOR LEGAL QUE EL ORIGINAL.', 'LA COPIA DEL ESCRITO ES DEVUELTA AL ADMINISTRADO CON EL SELLO DE RECEPCIÓN Y SIN FIRMA DE LA AUTORIDAD.', NULL, 'd', 'EL CARGO ASÍ EXPEDIDO TIENE EL MISMO VALOR LEGAL QUE EL ORIGINAL.', '(ART: 114)** [TITULO II]  [CAPITULO III]', '181886'),
(1314, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SE ENTIENDE POR PROCEDIMIENTO ADMINISTRATIVO AL (........................) TRAMITADOS EN LAS ENTIDADES, CONDUCENTES A LA EMISIÓN DE UN ACTO ADMINISTRATIVO QUE CONDUZCA EFECTOS JURÍDICOS INDIVIDUALES O INDIVIDUALIZABLES SOBRE INTERESES, OBLIGACIONES O DERECHOS DE LOS ADMINISTRADOS. (SEÑALE LA FRASE CORRECTA)', 'CONJUNTO DECISIONES.', 'CONJUNTO DE NORMAS.', 'CONJUNTO DE DISPOSICIONES LEGALES.', 'CONJUNTO DE ACTOS Y DILIGENCIAS.', 'TEMA DE DECISIÓN.', NULL, 'd', 'CONJUNTO DE ACTOS Y DILIGENCIAS.', '(ART: 29)** [TITULO II]  [CAPITULO I]', '181887'),
(1315, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 13 - ALCANCES DE LA NULIDAD.- LA NULIDAD PARCIAL DEL ACTO ADMINISTRATIVO NO ALCANZA A LAS OTRAS PARTES DEL ACTO QUE RESULTEN (...................... ) DE LA PARTE NULA, SALVO QUE SEA SU CONSECUENCIA, NI IMPIDE LA PRODUCCIÓN DE EFECTOS PARA LOS CUALES NO OBSTANTE, EL ACTO PUEDA SER IDÓNEO, SALVO DISPOSICIÓN LEGAL EN CONTRARIO. ( SEÑALE LO CORRECTO)', 'CONSECUENCIA.', 'INDEPENDIENTES.', 'DEPENDIENTES.', 'PROCEDENCIA.', 'ACTUACIONES.', NULL, 'b', 'INDEPENDIENTES.', '(ART: 13)** [TITULO I]  [CAPITULO II]', '181888'),
(1316, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 52 - CAPACIDAD PROCESAL.- TIENEN CAPACIDAD PROCESAL ANTE LAS ENTIDADES LAS PERSONAS QUE GOZAN DE (...................... ) CONFORME A LAS LEYES. (COMPLETE LO CORRECTO)', 'SUFRAGIO.', 'LA ACTUACIÓN.', 'CAPACIDAD JURÍDICA.', 'CAPACIDAD ECONÓMICA.', 'PLACER.', NULL, 'c', 'CAPACIDAD JURÍDICA.', '(ART: 52)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO I]', '181889'),
(1317, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 132.- A FALTA DE PLAZO ESTABLECIDO POR LEY EXPRESA, LAS ACTUACIONES DEBEN PRODUCIRSE DENTRO DE LO SIGUIENTE: (MARQUE EL ENUNCIADO CORRECTO).', 'PARA LA RECEPCIÓN Y DERIVACIÓN DE UN ESCRITO A LA UNIDAD COMPETENTE: AL TERCER DÍA DE SU PRESENTACIÓN.', 'PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER: EN SEIS DÍAS.', 'PARA EMISIÓN DE DICTÁMENES EN: TRES DÍAS.', 'PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER: EN TRES DÍAS.', 'PARA ACTO DE REVISIÓN DE EXPEDIENTE: CINCO DÍAS.', NULL, 'd', 'PARA ACTOS DE MERO TRÁMITE Y DECIDIR PETICIONES DE ESE CARÁCTER: EN TRES DÍAS.', '(ART: 132)** [TITULO II]  [CAPITULO IV]', '181890'),
(1318, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'COMPARECENCIA PERSONAL.- LAS ENTIDADES PUEDEN CONVOCAR LA COMPARECENCIA PERSONAL A SU SEDE, DE LOS ADMINISTRADOS SÓLO.............. (SEÑALE LA RESPUESTA CORRECTA).', 'CUANDO NO HA SIDO FACULTADO EXPRESAMENTE POR LEY.', 'CUANDO ASÍ LE HAYA SIDO FACULTADO EXPRESAMENTE POR LEY.', 'NO PUEDEN COMPARECER ASISTIDOS POR SUS ASESORES.', 'PUEDEN COMPARECER CON SUS ASESORES SÓLO PARA PRESENCIAR SU TESTIMONIO.', 'PUEDEN COMPARECER ASISTIDOS POR SU SEGURIDAD PERSONAL.', NULL, 'b', 'CUANDO ASÍ LE HAYA SIDO FACULTADO EXPRESAMENTE POR LEY.', '(ART: 58)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO I]', '181891'),
(1319, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRECISE USTED CUÁL DE LOS SIGUIENTES ENUNCIADOS ES EL CORRECTO:', 'EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN NO SE SUSTENTE EN DIFERENTE', 'EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN IGUAL INTERPRETACIÓN DE', 'EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN DIFERENTE INTERPRETACIÓN', 'EL RECURSO DE APELACIÓN NO SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN DIFERENTE', 'EL TÉRMINO PARA INTERPONER RECURSOS ES DE TRES DÍAS.', NULL, 'c', 'EL RECURSO DE APELACIÓN SE INTERPONDRÁ CUANDO LA IMPUGNACIÓN SE SUSTENTE EN DIFERENTE', '(ART: 209)** [TITULO III]  [CAPITULO II]', '181892'),
(1320, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DE LOS SIGUIENTES ENUNCIADOS RELATIVOS A LA ACUMULACIÓN DE SOLICITUDES, SEÑALE USTED EL QUE ES CORRECTO:', 'LA ACUMULACIÓN DE PETICIONES O SOLICITUDES TIENE EL PROPÓSITO QUE SE LES TRAMITE EN UN MISMO EXPEDIENTE', 'PUEDE ACUMULARSE EN UN SOLO ESCRITO MÁS DE UNA PETICIÓN AÚN CUANDO NO SE TRATE DE ASUNTOS CONEXOS.', 'LAS PRETENSIONES NO CONEXAS OBJETIVAMENTE PUEDEN SER ACUMULADAS CUANDO PROVENGAN DEL MISMO', 'NO PROCEDE LA DENEGACIÓN DE LA ACUMULACIÓN CUANDO VARIAS PRETENSIONES SON PROPUESTAS PARA QUE LA', 'DENEGADA LA ACUMULACIÓN, LA AUTORIDAD NO DEBE REQUERIR AL ADMINISTRADO PARA QUE PRESENTE SUS', NULL, 'a', 'LA ACUMULACIÓN DE PETICIONES O SOLICITUDES TIENE EL PROPÓSITO QUE SE LES TRAMITE EN UN MISMO', '(ART: 116)** [TITULO II]  [CAPITULO III]', '181893'),
(1321, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRINCIPIO DE PRESUNCIÓN DE VERACIDAD.- EN LA TRAMITACIÓN DEL PROCEDIMIENTO ADMINISTRATIVO, SE PRESUME QUE LOS DOCUMENTOS Y DECLARACIONES FORMULADOS POR LOS ADMINISTRADOS EN LA FORMA PRESCRITA POR ESTA LEY, RESPONDEN A LA VERDAD DE LOS HECHOS QUE ELLOS AFIRMAN. ESTA PRESUNCIÓN...:', 'SE APLICA SOBRE TODO DOCUMENTO QUE HAYA SIDO DEBIDAMENTE VERIFICADO POR LA ENTIDAD.', 'NO ADMITE PRUEBA EN CONTRARIO.', 'ADMITE PRUEBA EN CONTRARIO.', 'NO ES DE ALCANCE PARA LAS DECLARACIONES JURADAS.', 'NO ES DE ALCANDE PARA LOS PROCEDIMIENTOS DISCIPLINARIOS.', NULL, 'c', 'ADMITE PRUEBA EN CONTRARIO.', '(ART: IV)** [TITULO PRELIMINAR]', '181894'),
(1322, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ART. 143 - RESPONSABILIDAD POR INCUMPLIMIENTO DE PLAZOS.- EL INCUMPLIMIENTO INJUSTIFICADO DE LOS PLAZOS PREVISTOS PARA LAS ACTUACIONES DE LAS ENTIDADES GENERA RESPONSABILIDAD (.........) PARA LA AUTORIDAD OBLIGADA, SIN PERJUICIO DE LA RESPONSABILIDAD CIVIL POR LOS DAÑOS Y PERJUICIOS QUE PUDIERA HABER ACASIONADO: (SEÑALE LA RESPUESTA CORRECTA).', 'PENAL.', 'ECONÓMICA.', 'DISCIPLINARIA.', 'PATRIMONIAL.', 'COMPARTIDA.', NULL, 'c', 'DISCIPLINARIA.', '(ART: 143)** [TITULO II]  [CAPITULO IV]', '181895'),
(1323, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'TODA NOTIFICACIÓN DEBERÁ PRACTICARSE A MÁS TARDAR DENTRO DEL PLAZO DE 5 DÍAS A PARTIR DE LA EXPEDICIÓN DEL ACTO QUE SE NOTIFIQUE Y DEBERÁ CONTENER:(SEÑALE LO INCORRECTO).', 'EL TEXTO ÍNTEGRO DEL ACTO ADMINISTRATIVO, INCLUYENDO SU MOTIVACIÓN.', 'LA IDENTIFICACIÓN DEL PROCEDIMIENTO DENTRO DEL CUÁL HAYA SIDO DICTADO.', 'LA AUTORIDAD E INSTITUCIÓN DE LA CUÁL PROCEDE EL ACTO Y SU DIRECCIÓN.', 'LA FECHA DE VIGENCIA DEL ACTO NOTIFICADO, Y CON LA MENCIÓN DE SI AGOTARE LA VÍA ADMINISTRATIVA.', 'LA EXPRESIÓN DE LOS RECURSOS QUE NO PROCEDEN Y LA ENTIDAD ANTE LA CUÁL DEBE PRESENTARSE LA', NULL, 'e', 'LA EXPRESIÓN DE LOS RECURSOS QUE NO PROCEDEN Y LA ENTIDAD ANTE LA CUÁL DEBE PRESENTARSE LA', '(ART: 24)** [TITULO I]  [CAPITULO III]', '181896'),
(1324, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRECISE USTED CUÁL ES EL ENUNCIADO CORRECTO QUE ESTABLECE UNO DE LOS DEBERES GENERALES DE LOS ADMINISTRADOS EN EL PROCEDIMIENTO:', 'COMPROBAR PREVIAMENTE A SU PRESENTACIÓN ANTE LA ENTIDAD, LA FALSIFICACIÓN Y AUTENCIDAD DE LA', 'FORMULAR PRETENSIONES O ARTICULACIONES ILEGALES, DE DECLARAR HECHOS CONTRARIOS A LA VERDAD O NO', 'PRESTAR SU COLABORACIÓN PARA EL PERTINENTE ESCLARECIMIENTO DE LOS HECHOS.', 'PROPORCIONAR A LA AUTORIDAD SÓLO LA INFORMACIÓN DIRIGIDA A NO IDENTIFICAR A OTROS ADMINISTRADOS NO', 'EVITAR PRESTAR CUALQUIER TIPO DE INFORMACIÓN Y COLABORACIÓN PARA EL ESCLARECIENTO DE LOS HECHOS.', NULL, 'c', 'PRESTAR SU COLABORACIÓN PARA EL PERTINENTE ESCLARECIMIENTO DE LOS HECHOS.', '(ART: 56)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO I]', '181897'),
(1325, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ORIENTAN AL ADMINISTRADO EN LA PRESENTACIÓN DE SUS SOLICITUDES Y FORMULARIOS, QUEDANDO OBLIGADAS A RECIBIRLOS Y DARLES INGRESO PARA INICIAR O IMPULSAR LOS PROCEDIMIENTOS, SIN QUE EN NINGÚN CASO PUEDA CALIFICAR, NEGAR O DIFERIR SU ADMISIÓN:', 'LAS UNIDADES DE RECEPCIÓN DOCUMENTAL.', 'EL SUPERIOR JERÁRQUICO.', 'LOS ABOGADOS DE OFICIO.', 'LOS ABOGADOS DE LA ADMINISTRACIÓN PÚBLICA.', 'LAS PROCURADURIAS PÚBLICAS.', NULL, 'a', 'LAS UNIDADES DE RECEPCIÓN DOCUMENTAL.', '(ART: 124)** [TITULO II]  [CAPITULO III]', '181898'),
