(1329, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRECISE CUÁL DE LOS ENUNCIADOS QUE SE ENUMERA A CONTINUACIÓN, CONSTITUYE UN RECURSO ADMINISTRATIVO QUE RECONOCE COMO TAL LA LEY 27444.', 'RECURSOS DE IMPUGNACIÓN.', 'RECURSOS DE SOBRESEIMIENTO.', 'RECURSO DE CONTRADICCIÓN.', 'RECURSO DE APELACIÓN.', 'RECURSO DE LA DOBLE INSTANCIA.', NULL, 'd', 'RECURSO DE APELACIÓN.', '(ART: 209)** [TITULO III]  [CAPITULO II]', '181902'),
(1330, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PARA MANTENER REUNIDAS TODAS LAS ACTUACIONES PARA RESOLVER, CUÁNTOS EXPEDIENTES PUEDEN ORGANIZARSE PARA LA SOLUCIÓN DE UN MISMO CASO? MARCA LA CORRECTA:', 'SÓLO UN EXPEDIENTE.', 'LOS EXPEDIENTES NECESARIOS Y SOLICITADOS POR EL ADMINISTRADO.', 'DOS EXPEDIENTES.', 'TRES EXPEDIENTES.', 'LOS EXPEDIENTES NECESARIOS DISPUESTO POR LA ADMINISTRACIÓN.', NULL, 'a', 'SÓLO UN EXPEDIENTE.', '(ART: 150)** [TITULO II]  [CAPITULO V]', '181903'),
(1331, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'INDIQUE, DE LOS ENUNCIADOS SIGUIENTES, RESPECTO A REQUISITOS DE LOS ESCRITOS.- CUÁL ES EL INCORRECTO:', 'LUGAR, FECHA, FIRMA O HUELLA DIGITAL, EN CASO DE NO SABER FIRMAR O ESTAR IMPEDIDO.', 'NOMBRES Y APELLIDOS COMPLETOS, DOMICILIO Y NÚMERO DE DOCUMENTO NACIONAL DE IDENTIDAD O CARNÉ DE', 'LA EXPRESIÓN CONCRETA DE LO PEDIDO, LOS FUNDAMENTOS DE HECHO QUE LO APOYE Y CUANDO LE SEA POSIBLE, LOS', 'LA INDICACIÓN DEL ÓRGANO, LA ENTIDAD O LA AUTORIDAD A LA CUÁL ES DIRIGIDA.', 'CERTIFICADOS DE ESTUDIO', NULL, 'e', 'CERTIFICADOS DE ESTUDIO', '(ART: 113)** [TITULO II]  [CAPITULO III]', '181904'),
(1332, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DERECHO DE PETICIÓN ADMINISTRATIVA.- CUALQUIER ADMINISTRADO, INDIVIDUAL O COLECTIVAMENTE, PUEDE PROMOVER POR ESCRITO EL INICIO DEL PROCEDIMIENTO ADMINISTRATIVO ANTE TODAS Y CUALQUIERA DE LAS ENTIDADES, EJERCIENDO EL DERECHO DE PETICIÓN, RECONOCIDO EN EL ...:', 'ART. 2 INCISO 20.- DE LA CONSTITUCIÓN POLÍTICA DEL ESTADO.', 'ART. 2 INCISO 6.- DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ.', 'ART. 102 DE LA LEY 27444 - LEY DE PROCEDIMIENTO ADMINISTRATIVO GENERAL.', 'ART. 6 DE LA LEY 27584 QUE REGULA EL PROCESO CONTENCIOSO ADMINISTRATIVO.', 'ART. 60 DE LA LEY 27444 - LEY DE PROCEDIMIENTO ADMINISTRATIVO GENERAL.', NULL, 'a', 'ART. 2 INCISO 20.- DE LA CONSTITUCIÓN POLÍTICA DEL ESTADO.', '(ART: 106)** [TITULO II]  [CAPITULO III]', '181905'),
