(1334, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN EL ACTO DE NOTIFICACIÓN : MARCA EL CORRECTO', 'SE CONDUCE AL NOTIFICADO ANTE LA AUTORIDAD SOLICITANTE.', 'SE ENTREGA COPIA DEL ACTO NOTIFICADO.', 'SE LE COMUNICA SU DETENCIÓN.', 'SE PROCEDE A RECABAR SUS GENERALES DE LEY.', 'SE CONDUCE AL NOTIFICADO AL MINISTERIO PÚBLICO.', NULL, 'b', 'SE ENTREGA COPIA DEL ACTO NOTIFICADO.', '(ART: 21)** [TITULO I]  [CAPITULO III]', '181907'),
(1335, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA AUTORIDAD ORDENARÁ QUE SE REHAGA LA NOTIFICACIÓN, EN EL SIGUIENTE CASO: MARCA LA CORRECTA.', 'QUE SE DEMUESTRE QUE LA NOTIFICACIÓN SE HA REALIZADO SIN LAS FORMALIDADES Y REQUISITOS LEGALES.', 'POR CONVENIR AL ADMINISTRADO.', 'CUANDO EXISTAN NUEVAS PRUEBAS.', 'CUANDO SE SOLICITA LA NULIDAD DEL PROCESO.', 'NO SE PUEDE REHACER LA NOTIFICACIÓN.', NULL, 'a', 'QUE SE DEMUESTRE QUE LA NOTIFICACIÓN SE HA REALIZADO SIN LAS FORMALIDADES Y REQUISITOS', '(ART: 26)** [TITULO I]  [CAPITULO III]', '181908'),
(1336, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EFICACIA DEL ACTO ADMINISTRATIVO.- EL ACTO ADMINISTRATIVO QUE OTORGA BENEFICIO AL ADMINISTRADO SE ENTIENDE EFICAZ DESDE LA FECHA DE SU EMISIÓN, SALVO: (SEÑALE LA RESPUESTA CORRECTA).', 'DISPOSICIÓN DEL RECURRENTE.', 'DISPOSICIÓN DIFERENTE DEL MISMO ACTO.', 'DISPOSICIÓN IGUAL DEL MISMO ACTO.', 'DISPOSICIÓN TRANSITORIA DEL ACTO.', 'DISPOSICIÓN EXPRESA DE LA MESA DIRECTIVA.', NULL, 'b', 'DISPOSICIÓN DIFERENTE DEL MISMO ACTO.', '(ART: 16)** [TITULO I]  [CAPITULO III]', '181909'),
(1337, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'VIGENCIA DE LAS NOTIFICACIONES.- LAS NOTIFICACIONES SURTIRÁN EFECTO CONFORME A LAS SIGUIENTES REGLAS: (SEÑALE EL INCORRECTO)', 'LAS NOTIFICACIONES PERSONALES: EL DÍA QUE HUBIEREN SIDO REALIZADOS.', 'LAS CURSADAS MEDIANTE CORREO CERTIFICADO, OFICIO, CORREO ELECTRÓNICO Y ANÁLOGOS: EL DÍA QUE CONSTE', 'LAS NOTIFICACIONES TELEFÓNICAS: EL MISMO DÍA.', 'LAS NOTIFICACIONES POR PUBLICACIONES: A PARTIR DEL DÍA DE LA ÚLTIMA PUBLICACIÓN EN EL DIARIO OFICIAL.', 'CUANDO POR DISPOSICIÓN LEGAL EXPRESA, UN ACTO ADMINISTRATIVO DEBE SER A LA VEZ NOTIFICADO', NULL, 'c', 'LAS NOTIFICACIONES TELEFÓNICAS: EL MISMO DÍA.', '(ART: 25)** [TITULO I]  [CAPITULO III]', '181910'),
(1338, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'NOTIFICACIONES DEFECTUOSAS.- LA DESESTIMACIÓN DEL CUESTIONAMIENTO A LA VALIDEZ DE UNA NOTIFICACIÓN, CAUSA QUE DICHA NOTIFICACIÓN: ( SEÑALE LO CORRECTO)', 'INVALIDE EL PROCEDIMIENTO ADMINISTRATIVO.', 'SE HAGA CONSTAR ASÍ EN ACTA O RESOLUCIÓN.', 'OPERE DESDE LA FECHA EN QUE FUE REALIZADA.', 'TENGA VALIDEZ DESDE EL DÍA HÁBIL SIGUIENTE EN QUE FUE REALIZADA.', 'OPERE DESDE EL DÍA EN QUE LA AUTORIDAD ADMINISTRATIVA IMPARTIÓ LA ORDEN DE NOTIFICACIÓN.', NULL, 'c', 'OPERE DESDE LA FECHA EN QUE FUE REALIZADA.', '(ART: 26)** [TITULO I]  [CAPITULO III]', '181911'),
(1339, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'INDEPENDENCIA DE LOS VICIOS DEL ACTO ADMINISTRATIVO.- LOS VICIOS INCURRIDOS EN LA EJECUCIÓN DE UN ACTO ADMINISTRATIVO O EN SU MODIFICACIÓN A LOS ADMINISTRADOS SON:', 'INDEPENDIENTES DE SU VALIDEZ.', 'DEPENDIENTES DE SU VALIDEZ.', 'SON INDEPENDIENTES Y DEPENDIENTES DE SU VALIDEZ.', 'SON VÁLIDOS A PESAR DEL VICIO INCURRIDO.', 'NO SON VÁLIDOS.', NULL, 'a', 'INDEPENDIENTES DE SU VALIDEZ.', '(ART: 15)** [TITULO I]  [CAPITULO II]', '181912'),
(1340, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'RECURSO DE RECONSIDERACION.- EN LOS CASOS DE ACTOS ADMINISTRATIVOS, EMITIDOS POR ÓRGANOS QUE CONSTITUYEN ÚNICA INSTANCIA: (INDIQUE LA RESPUESTA CORRECTA).', 'SE REQUIERE NECESARIAMENTE DE NUEVA PRUEBA.', 'NO SE REQUIERE NUEVA PRUEBA.', 'SE REQUIERE DE NUEVOS TESTIMONIOS OBLIGATORIAMENTE.', 'SE REQUIERE DE NUEVO TESTIMONIO.', 'NO SE REQUIERE DE RECURSO DE RECONSIDERACIÓN.', NULL, 'b', 'NO SE REQUIERE NUEVA PRUEBA.', '(ART: 208)** [TITULO III]  [CAPITULO II]', '181913'),
(1341, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '(................), ESTIMARÁ EN TODO O EN PARTE O DESESTIMARÁ LAS PRETENSIONES FORMULADAS EN EL MISMO, O DECLARARÁ SU INADMISIÓN.', 'EL CONTENIDO DEL RECURSO.', 'LA RESOLUCIÓN DEL RECURSO.', 'EL PROVEÍDO DEL RECURSO.', 'LOS ANEXOS DEL RECURSO.', 'LA RESOLUCIÓN PLANTEADA EN LOS ANEXOS.', NULL, 'b', 'LA RESOLUCIÓN DEL RECURSO.', '(ART: 217)** [TITULO III]  [CAPITULO II]', '181914'),
(1342, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CONSERVACIÓN DEL ACTO.- SON ACTOS ADMINISTRATIVOS AFECTADOS POR VICIOS NO TRASCENDENTES LOS SIGUIENTES: (SEÑALE LA INCORRECTA)', 'EL ACTO CUYO CONTENIDO SEA IMPRECISO O INCONGRUENTE CON LAS CUESTIONES SURGIDAS EN LA MOTIVACIÓN.', 'EL ACTO EMITIDO CON INFRACCIÓN A LAS FORMALIDADES NO ESENCIALES DEL PROCEDIMIENTO.', 'EL ACTO EMITIDO CON UNA MOTIVACIÓN INSUFICIENTE O PARCIAL.', 'LA CONTRAVENCIÓN A LA CONSTITUCIÓN, A LAS LEYES O A LAS NORMAS REGLAMENTARIAS.', 'AQUELLOS EMITIDOS CON OMISIÓN DE DOCUMENTACIÓN NO ESENCIAL.', NULL, 'd', 'LA CONTRAVENCIÓN A LA CONSTITUCIÓN, A LAS LEYES O A LAS NORMAS REGLAMENTARIAS.', '(ART: 14)** [TITULO I]  [CAPITULO II]', '181915'),
(1343, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LOS PRINCIPIOS DEL PROCEDIMIENTO ADMINISTRATIVO:', 'SON DE NATURALEZA ANALOGA', 'NO SON DE NATURALEZA ANALOGA', 'TIENEN CARÁCTER TAXATIVO', 'NO TIENEN CARÁCTER TAXATIVO', 'NO SIRVEN DE CRITERIO INTERPRETATIVO PARA RESOLVER LAS CUESTIONES QUE PUEDAN SUSCITARSE EN LA', NULL, 'd', 'NO TIENEN CARÁCTER TAXATIVO', '(ART: IV)** [TITULO PRELIMINAR]', '181916'),
(1344, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA CARGA DE LA PRUEBA SE RIGE POR EL PRINCIPIO DE (....) ESTABLECIDO EN LA PRESENTE LEY.', 'CELERIDAD.', 'LEGALIDAD.', 'IMPULSO DE OFICIO.', 'INFORMALISMO.', 'EFICIENCIA.', NULL, 'c', 'IMPULSO DE OFICIO.', '(ART: 162)** [TITULO II]  [CAPITULO VI]', '181919'),
(1345, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DE ACUERDO CON EL ARTÍCULO 174 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL, ¿CUÁL ES UNA DE LAS ALTERNATIVAS QUE TIENE LA AUTORIDAD ANTE LA OMISIÓN DEL INFORME DENTRO DEL PLAZO SEÑALADO?', 'ORDENAR LA DESTITUCIÓN INMEDIATA DEL FUNCIONARIO OMISO SIN PROCESO PREVIO.', 'EXTENDER EL PLAZO PARA LA PRESENTACIÓN DEL INFORME SIN COMUNICACIÓN AL ADMINISTRADO.', 'PRESCINDIR DEL INFORME, DEPENDIENDO DE LAS CIRCUNSTANCIAS DEL CASO Y LA RELACIÓN ADMINISTRATIVA CON EL', 'SOLICITAR OBLIGATORIAMENTE EL INFORME POR VÍA JUDICIAL ANTES DE CONTINUAR EL PROCEDIMIENTO.', 'SANCIONAR DE INMEDIATO AL ADMINISTRADO POR FALTA DE COLABORACIÓN.', NULL, 'c', 'PRESCINDIR DEL INFORME, DEPENDIENDO DE LAS CIRCUNSTANCIAS DEL CASO Y LA RELACIÓN', '(ART: 174)** [TITULO II]  [CAPITULO VI]', '181921'),
(1346, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '¿QUIEN TIENE LA CARGA DE LA COMPARECENCIA DE LOS TESTIGOS EN EL LUGAR, FECHA Y HORA FIJADOS?', 'LA ADMINISTRACIÓN.', 'EL PROPONENTE DE LA PRUEBA DE TESTIGOS.', 'EL ADMINISTRADO.', 'EL TITULAR DE LA ENTIDAD.', 'EL TITULAR DEL PROCESO ADMINISTRATIVO COMPETENCIAL.', NULL, 'b', 'EL PROPONENTE DE LA PRUEBA DE TESTIGOS.', '(ART: 175)** [TITULO II]  [CAPITULO VI]', '181922'),
(1347, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN EL MARCO DEL ARTÍCULO 176 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL, ¿CUÁL ES EL PROCEDIMIENTO CORRECTO PARA QUE LOS ADMINISTRADOS PROPONGAN LA INTERVENCIÓN DE PERITOS DURANTE UN PROCEDIMIENTO ADMINISTRATIVO?', 'LOS ADMINISTRADOS PUEDEN PROPONER LA DESIGNACIÓN DE PERITOS A DISCRECIÓN DEL ÓRGANO ADMINISTRATIVO,', 'LOS ADMINISTRADOS PUEDEN PROPONER LA DESIGNACIÓN DE PERITOS A COSTA DEL ESTADO, JUSTIFICANDO', 'LOS ADMINISTRADOS PUEDEN PROPONER LA DESIGNACIÓN DE PERITOS A SU COSTA, DEBIENDO EN EL MISMO MOMENTO', 'LA ADMINISTRACIÓN DESIGNA PERITOS OBLIGATORIAMENTE SI LOS ADMINISTRADOS ASÍ LO SOLICITAN, SIN REQUERIRSE', 'SÓLO LOS ADMINISTRADOS QUE ACREDITEN UN INTERÉS DIRECTO PUEDEN PROPONER PERITOS, Y LA ADMINISTRACIÓN', NULL, 'c', 'LOS ADMINISTRADOS PUEDEN PROPONER LA DESIGNACIÓN DE PERITOS A SU COSTA, DEBIENDO EN EL MISMO', '(ART: 176)** [TITULO II]  [CAPITULO VI]', '181923'),
(1348, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN RELACIÓN AL DEBER DE LOS TERCEROS DE COLABORAR EN ACTUACIONES PROBATORIAS EN EL PROCEDIMIENTO ADMINISTRATIVO, SEGÚN EL ARTÍCULO 179, EL CUMPLIMIENTO DE ESTE DEBER:', 'SIEMPRE PREVALECE SOBRE LOS DERECHOS FUNDAMENTALES DE LOS TERCEROS, DADO EL INTERÉS PÚBLICO', 'SE ENCUENTRA SUPEDITADO AL RESPETO DE LOS DERECHOS CONSTITUCIONALES DE LOS TERCEROS INVOLUCRADOS.', 'PUEDE SER EXIGIDO POR LA ADMINISTRACIÓN SIN NECESIDAD DE GARANTIZAR NINGÚN TIPO DE PROTECCIÓN A LOS', 'SOLAMENTE OPERA CUANDO LOS TERCEROS HAN SIDO PARTE FORMAL DEL PROCEDIMIENTO ADMINISTRATIVO', 'IMPLICA QUE LOS TERCEROS DEBEN SOMETERSE A LAS ACTUACIONES PROBATORIAS SIN POSIBILIDAD DE OBJETAR POR', NULL, 'b', 'SE ENCUENTRA SUPEDITADO AL RESPETO DE LOS DERECHOS CONSTITUCIONALES DE LOS TERCEROS', '(ART: 179)** [TITULO II]  [CAPITULO VI]', '181924'),
(1349, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LOS ERRORES MATERIAL O ARITMÉTICO EN LOS ACTOS ADMINISTRATIVOS (...........), EN CUALQUIER MOMENTO, DE OFICIO O A INSTANCIA DE LOS ADMINISTRADOS, SIEMPRE QUE NO SE ALTERE LO SUSTANCIAL DE SU CONTENIDO NI EL SENTIDO DE LA DECISIÓN.', 'PUEDEN SER RECTIFICADOS SIN EFECTO RETROACTIVO.', 'NO PUEDEN SER RECTIFICADOS CON EFECTO RETROACTIVO.', 'PUEDEN SER RECTIFICADOS CON EFECTO RETROACTIVO.', 'PUEDEN SER RECTIFICADOS CON EFECTO DEVOLUTIVO.', 'NO PUEDEN SER RECTIFICADOS CON EFECTO DEVOLUTIVO.', NULL, 'c', 'PUEDEN SER RECTIFICADOS CON EFECTO RETROACTIVO.', '(ART: 201)** [TITULO III]  [CAPITULO I]', '181925'),
(1350, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'RECURSOS ADMINISTRATIVOS.- CONSTATADA LA EXISTENCIA DE UNA CAUSAL DE NULIDAD, LA AUTORIDAD, ADEMÁS DE LA DECLARACIÓN DE NULIDAD, RESOLVERÁ SOBRE EL FONDO DEL ASUNTO, DE CONTARSE CON LOS ELEMENTOS SUFICIENTES PARA ELLO. CUANDO NO SEA POSIBLE PRONUNCIARSE SOBRE EL FONDO DEL ASUNTO, SE DISPONDRÁ:', 'SU PROCEDENCIA.', 'SU ADMISIÓN.', 'SU INADMISIÓN.', 'SU IMPROCEDENCIA.', 'LA REPOSICIÓN DEL PROCEDIMIENTO AL MOMENTO EN QUE EL VICIO SE PRODUJO.', NULL, 'e', 'LA REPOSICIÓN DEL PROCEDIMIENTO AL MOMENTO EN QUE EL VICIO SE PRODUJO.', '(ART: 217)** [TITULO III]  [CAPITULO II]', '181926'),
(1351, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN LA RESOLUCIÓN QUE PONGA FIN AL PROCEDIMIENTO SANCIONADOR NO SE PODRÁN ACEPTAR HECHOS DISTINTOS DE LOS DETERMINADOS EN EL CURSO DEL PROCEDIMIENTO, CON INDEPENDENCIA DE SU DIFERENTE VALORACIÓN JURÍDICA. LA RESOLUCIÓN SERÁ EJECUTIVA CUANDO:', 'LA SUSCRIBE EL TITULAR DEL PLIEGO.', 'PONGA FIN A LA VÍA ADMINISTRATIVA.', 'SE RESUELVA EN SEGUNDA INSTANCIA.', 'SE RESUELVA EN ÚLTIMA INSTANCIA.', 'SE RESUELVA EN INSTANCIA ÚNICA.', NULL, 'b', 'PONGA FIN A LA VÍA ADMINISTRATIVA.', '(ART: 237)** [TITULO IV]  [CAPITULO II]  [SUBCAPITULO II]', '181927'),
(1352, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'RESPECTO A LAS RESPONSABILIDADES DE LA ADMINISTRACIÓN PÚBLICA SEÑALE LA RESPUESTA CORRECTA:', 'LAS ENTIDADES NO SON PATRIMONIALMENTE RESPONSABLES FRENTE A LOS ADMINISTRADOS POR LOS DAÑOS', 'LAS ENTIDADES NO SON PATRIMONIALMENTE RESPONSABLES FRENTE A LOS ADMINISTRADOS POR LOS DAÑOS', 'HAY LUGAR A LA REPARACIÓN POR PARTE DE LA ADMINISTRACIÓN, CUANDO EL DAÑO FUERA CONSECUENCIA DE CASO', 'HAY LUGAR A REPARACIÓN POR PARTE DE LA ADMINISTRACIÓN, CUANDO LA ENTIDAD HUBIERE ACTUADO RAZONABLE Y', 'LA DECLARATORIA DE NULIDAD DE UN ACTO ADMINISTRATIVO EN SEDE ADMINISTRATIVA O POR RESOLUCIÓN JUDICIAL NO', NULL, 'e', 'LA DECLARATORIA DE NULIDAD DE UN ACTO ADMINISTRATIVO EN SEDE ADMINISTRATIVA O POR RESOLUCIÓN', '(ART: 238)** [TITULO V]  [CAPITULO I]', '181928'),
(1353, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DE ACUERDO CON EL ARTÍCULO 124 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL, RESPECTO A LAS FUNCIONES DE LAS UNIDADES DE RECEPCIÓN DOCUMENTAL, ¿CUÁL ES LA LIMITACIÓN MÁS RELEVANTE IMPUESTA A DICHAS UNIDADES EN EL MARCO DE LA ADMISIÓN DE SOLICITUDES PRESENTADAS POR LOS ADMINISTRADOS?', 'SOLO PUEDEN ORIENTAR SOBRE CÓMO LLENAR CORRECTAMENTE LOS FORMULARIOS, PERO TIENEN COMPETENCIA', 'PUEDEN DENEGAR LA ADMISIÓN DE UN DOCUMENTO SI CONSIDERAN QUE NO CUMPLE CON LOS REQUISITOS', 'ESTÁN OBLIGADAS A RECIBIR Y DAR INGRESO A LAS SOLICITUDES, SIN PODER CALIFICAR, NEGAR O DIFERIR SU ADMISIÓN', 'SOLO PUEDEN RECHAZAR LOS DOCUMENTOS CUANDO NO SE ADJUNTAN COPIAS CERTIFICADAS DE LA DOCUMENTACIÓN', 'PUEDEN POSTERGAR EL INGRESO DE SOLICITUDES SI EL ADMINISTRADO NO JUSTIFICA LA URGENCIA DEL TRÁMITE.', NULL, 'c', 'ESTÁN OBLIGADAS A RECIBIR Y DAR INGRESO A LAS SOLICITUDES, SIN PODER CALIFICAR, NEGAR O DIFERIR', '(ART: 124)** [TITULO II]  [CAPITULO III]', '181929'),
(1354, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'INICIACIÓN DEL PROCEDIMIENTO.- CUANDO SEA INGRESADA UNA SOLICITUD QUE SE ESTIMA COMPETENCIA DE OTRA ENTIDAD, LA ENTIDAD RECEPTORA DEBE REMITIRLA, EN EL (.....), A AQUELLA QUE CONSIDERE COMPETENTE, COMUNICANDO DICHA DECISIÓN AL ADMINISTRADO.', 'PLAZO DE DOS DÍAS HÁBILES.', 'TÉRMINO DE LA DISTANCIA.', 'PLAZO DE TRES DÍAS HÁBILES.', 'PLAZO DE CUATRO DÍAS HÁBILES.', 'PLAZO DE CINCO DÍAS HÁBILES.', NULL, 'b', 'TÉRMINO DE LA DISTANCIA.', '(ART: 130)** [TITULO II]  [CAPITULO III]', '181930'),
(1355, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DEL PROCEDIMIENTO ADMINISTRATIVO.- AL VENCIMIENTO DE UN (....) PARA REALIZAR UNA ACTUACIÓN O EJERCER UNA FACULTAD PROCESAL, PREVIO APERCIBIMIENTO, LA ENTIDAD DECLARA DECAÍDO EL DERECHO AL CORRESPONDIENTE ACTO, NOTIFICANDO LA DECISIÓN.', 'PLAZO APLAZABLE.', 'PLAZO PERENTORIO.', 'PLAZO IMPRORROGABLE.', 'PLAZO NO MAYOR DE 15 DÍAS.', 'PLAZO NO MAYOR DE 30 DÍAS.', NULL, 'c', 'PLAZO IMPRORROGABLE.', '(ART: 140)** [TITULO II]  [CAPITULO IV]', '181931'),
(1356, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DE ACUERDO AL ARTÍCULO 140 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL, ¿CUÁNDO SE CONSIDERA VENCIDO UN PLAZO FIJADO PARA LA REALIZACIÓN DE UNA ACTUACIÓN ADMINISTRATIVA?', 'EL PLAZO SE VENCE EXACTAMENTE CUANDO LA ACTUACIÓN ES NOTIFICADA A LAS PARTES, SIN CONSIDERAR SI FUE', 'EL PLAZO SE VENCE IRRESTRICTAMENTE A LA MEDIANOCHE DEL DÍA ANTERIOR AL SEÑALADO, INDEPENDIENTEMENTE DE', 'EL PLAZO VENCE AL ÚLTIMO MOMENTO DEL DÍA HÁBIL SEÑALADO, O ANTICIPADAMENTE SI LA ACTUACIÓN PARA LA QUE', 'EL PLAZO SIEMPRE VENCE A LAS 18:00 HORAS DEL DÍA FIJADO, CONFORME A LA PRÁCTICA ADMINISTRATIVA GENERAL.', 'EL PLAZO SOLO VENCE CUANDO LA AUTORIDAD ADMINISTRATIVA LO DECLARA EXPRESAMENTE MEDIANTE RESOLUCIÓN', NULL, 'c', 'EL PLAZO VENCE AL ÚLTIMO MOMENTO DEL DÍA HÁBIL SEÑALADO, O ANTICIPADAMENTE SI LA ACTUACIÓN', '(ART: 140)** [TITULO II]  [CAPITULO IV]', '181932'),
(1357, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DEL PROCEDIMIENTO ADMINISTRATIVO.- RESPECTO AL IMPULSO DEL PROCEDIMIENTO, SEÑALE LA RESPUESTA CORRECTA:', 'LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE PROMOVER TODA ACTUACIÓN QUE FUESE NECESARIA', 'LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE SUPERAR CUALQUIER OBSTÁCULO QUE SE OPONGA A', 'LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE DETERMINAR LA NORMA APLICABLE AL CASO AUN', 'LA AUTORIDAD COMPETENTE, PREVIO PEDIDO DE PARTE, DEBE EVITAR EL ENTORPECIMIENTO O DEMORA A CAUSA DE', 'LA AUTORIDAD COMPETENTE DEBE ADOPTAR LAS MEDIDAS OPORTUNAS PARA ELIMINAR CUALQUIER IRREGULARIDAD', NULL, 'e', 'LA AUTORIDAD COMPETENTE DEBE ADOPTAR LAS MEDIDAS OPORTUNAS PARA ELIMINAR CUALQUIER', '(ART: 145)** [TITULO II]  [CAPITULO V]', '181933'),
(1358, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SEGÚN EL ARTÍCULO 146 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL (LEY 27444), ¿EN CUÁL DE LOS SIGUIENTES ESCENARIOS UNA MEDIDA CAUTELAR DICTADA EN UN PROCEDIMIENTO ADMINISTRATIVO CADUCA DE PLENO DERECHO?', 'CUANDO SE EMITE LA RESOLUCIÓN QUE PONE FIN AL PROCEDIMIENTO ADMINISTRATIVO.', 'CUANDO TRANSCURRE EL PLAZO FIJADO PARA LA EJECUCIÓN DE LA MEDIDA CAUTELAR.', 'CUANDO EL ADMINISTRADO SOLICITA EXPRESAMENTE LA CADUCIDAD DE LA MEDIDA Y ESTO ES ACEPTADO POR LA', 'CUANDO LA ENTIDAD ADMINISTRATIVA DECIDE EN CUALQUIER MOMENTO REVOCAR LA MEDIDA SIN MOTIVACIÓN ALGUNA.', 'CUANDO SE INTERPONEN RECURSOS ADMINISTRATIVOS CONTRA LA MEDIDA CAUTELAR Y ESTOS NO SON RESUELTOS EN', NULL, 'a', 'CUANDO SE EMITE LA RESOLUCIÓN QUE PONE FIN AL PROCEDIMIENTO ADMINISTRATIVO.', '(ART: 146)** [TITULO II]  [CAPITULO V]', '181934'),
(1359, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN UNA SOLA DECISIÓN SE DISPONDRÁ EL CUMPLIMIENTO DE TODOS LOS TRÁMITES NECESARIOS QUE POR SU NATURALEZA CORRESPONDA, SIEMPRE Y CUANDO NO SE ENCUENTREN ENTRE SÍ SUCESIVAMENTE SUBORDINADOS EN SU CUMPLIMIENTO, Y SE CONCENTRARÁN EN UN MISMO ACTO TODAS LAS DILIGENCIAS Y ACTUACIONES DE PRUEBAS POSIBLES, PROCURANDO QUE EL DESARROLLO DEL PROCEDIMIENTO SE REALICE EN EL MENOR NÚMERO DE ACTOS PROCESALES. EL REFERIDO PÁRRAFO CONSTITUYE UNA REGLA PARA ASEGURAR EL CUMPLIMIENTO DEL PRINCIPIO DE:', 'CELERIDAD.', 'EFICIENCIA.', 'IMPULSO DE OFICIO.', 'LEGALIDAD.', 'INFORMALISMO.', NULL, 'a', 'CELERIDAD.', '(ART: 148)** [TITULO II]  [CAPITULO V]', '181935'),
(1360, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN EL IMPULSO Y TRAMITACIÓN DE CASOS DE UNA MISMA NATURALEZA, SE SIGUE RIGUROSAMENTE EL ORDEN DE INGRESO, Y SE RESUELVEN CONFORME LO VAYA PERMITIENDO SU ESTADO, DANDO CUENTA AL SUPERIOR DE LOS MOTIVOS DE DEMORA EN EL CUMPLIMIENTO DE LOS PLAZOS DE LEY, QUE NO PUEDAN SER REMOVIDOS DE OFICIO. EL REFERIDO PÁRRAFO CONSTITUYE UNA REGLA PARA ASEGURAR EL CUMPLIMIENTO DEL PRINCIPIO DE:', 'LEGALIDAD.', 'EFICIENCIA.', 'IMPULSO DE OFICIO.', 'CELERIDAD.', 'INFORMALISMO.', NULL, 'd', 'CELERIDAD.', '(ART: 148)** [TITULO II]  [CAPITULO V]', '181936'),
(1361, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN NINGÚN CASO LA AUTORIDAD PODRÁ ALEGAR DEFICIENCIAS DEL ADMINISTRADO NO ADVERTIDAS A LA PRESENTACIÓN DE LA SOLICITUD, COMO FUNDAMENTO PARA DENEGAR SU PRETENSIÓN. EL REFERIDO PÁRRAFO CONSTITUYE UNA REGLA PARA ASEGURAR EL CUMPLIMIENTO DEL PRINCIPIO DE:', 'LEGALIDAD.', 'EFICIENCIA.', 'IMPULSO DE OFICIO.', 'CELERIDAD.', 'INFORMALISMO.', NULL, 'd', 'CELERIDAD.', '(ART: 148)** [TITULO II]  [CAPITULO V]', '181937'),
(1362, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DEL PROCEDIMIENTO ADMINISTRATIVO.- LOS EXPEDIENTES SON COMPAGINADOS SIGUIENDO EL ORDEN REGULAR DE LOS DOCUMENTOS QUE LO INTEGRAN, FORMANDO CUERPOS CORRELATIVOS QUE NO EXCEDAN DE (......), SALVO CUANDO TAL LÍMITE OBLIGARA A DIVIDIR ESCRITOS O DOCUMENTOS QUE CONSTITUYAN UN SOLO TEXTO, EN CUYO CASO SE MANTENDRÁ SU UNIDAD.', 'TRESCIENTOS FOLIOS.', 'QUINIENTOS FOLIOS.', 'CIEN FOLIOS.', 'DOSCIENTOS FOLIOS.', 'CINCUENTA FOLIOS.', NULL, 'd', 'DOSCIENTOS FOLIOS.', '(ART: 152)** [TITULO II]  [CAPITULO V]', '181938'),
(1363, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '¿EN QUÉ MOMENTO, LOS ADMINISTRADOS PUEDEN FORMULAR QUEJA CONTRA LOS DEFECTOS DE TRAMITACIÓN Y, EN ESPECIAL, LOS QUE SUPONGAN PARALIZACIÓN, INFRACCIÓN DE LOS PLAZOS ESTABLECIDOS LEGALMENTE, INCUMPLIMIENTO DE LOS DEBERES FUNCIONALES U OMISIÓN DE TRÁMITES QUE DEBEN SER SUBSANADOS?', 'EN CUALQUIER MOMENTO.', 'ANTES DEL INICIO DEL PROCEDIMIENTO.', 'ANTES DE LA RESOLUCIÓN DEFINITIVA DEL ASUNTO EN LA INSTANCIA RESPECTIVA.', 'ANTES DE LA APORTACIÓN DE PRUEBAS.', 'ANTES DE LA APELACIÓN.', NULL, 'a', 'EN CUALQUIER MOMENTO.', '(ART: 158)** [TITULO II]  [CAPITULO V]', '181939'),
(1364, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CONTINUACIÓN DEL PROCEDIMIENTO.- LUEGO DE RESUELTO EL CONFLICTO DE COMPETENCIA, EL ÓRGANO QUE RESULTE COMPETENTE PARA CONOCER EL ASUNTO CONTINÚA EL PROCEDIMIENTO SEGÚN SU ESTADO Y CONSERVA TODO LO ACTUADO, SALVO AQUELLO QUE NO SEA (.......).', 'UN PROCEDIMIENTO ADMINISTRATIVO.', 'JURÍDICAMENTE POSIBLE.', 'UN ACTO ADMINISTRATIVO.', 'NECESARIO.', 'DIFUSO.', NULL, 'b', 'JURÍDICAMENTE POSIBLE.', '(ART: 87)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO IV]', '181940'),
(1365, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'AUTORIDADES DE LOS ÓRGANOS COLEGIADOS.- ¿QUIEN TIENE A CARGO ASEGURAR LA REGULARIDAD DE LAS DELIBERACIONES Y EJECUTAR SUS ACUERDOS.?', 'EL SECRETARIO DEL ÓRGANO COLEGIADO.', 'EL DIRECTOR DEL ÓRGANO COLEGIADO.', 'EL PRESIDENTE DEL ÓRGANO COLEGIADO.', 'EL DECANO DEL ÓRGANO COLEGIADO.', 'EL TITULAR DEL ÓRGANO COLEGIADO.', NULL, 'c', 'EL PRESIDENTE DEL ÓRGANO COLEGIADO.', '(ART: 96)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO V]', '181941'),
(1366, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'AUTORIDADES DE LOS ÓRGANOS COLEGIADOS.- CADA ÓRGANO COLEGIADO DE LAS ENTIDADES ES REPRESENTADO POR UN (...............), A CARGO DE ASEGURAR LA REGULARIDAD DE LAS DELIBERACIONES Y EJECUTAR SUS ACUERDOS, Y CUENTA CON UN SECRETARIO, A CARGO DE PREPARAR LA AGENDA, LLEVAR, ACTUALIZAR Y CONSERVAR LAS ACTAS DE LAS SESIONES, COMUNICAR LOS ACUERDOS, OTORGAR COPIAS Y DEMÁS ACTOS PROPIOS DE LA NATURALEZA DEL CARGO.', 'SECRETARIO.', 'PRESIDENTE.', 'DIRECTOR.', 'DECANO.', 'TITULAR.', NULL, 'b', 'PRESIDENTE.', '(ART: 96)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO V]', '181942'),
(1367, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', '(.....), ES PROMOVIDO DE OFICIO POR EL ÓRGANO COMPETENTE O INSTANCIA DEL ADMINISTRADO, SALVO QUE POR DISPOSICIÓN LEGAL O POR SU FINALIDAD CORRESPONDA SER INICIADO EXCLUSIVAMENTE DE OFICIO O A INSTANCIA DEL INTERESADO.', 'LOS PROCEDIMIENTOS DE LA ADMINISTRACIÓN.', 'LOS ACTOS ADMINISTRATIVOS.', 'EL PROCEDIMIENTO ADMINISTRATIVO.', 'LOS ACTOS DE LA ADMINISTRACIÓN.', 'LOS DOCUMENTOS ADMINISTRATIVOS.', NULL, 'c', 'EL PROCEDIMIENTO ADMINISTRATIVO.', '(ART: 103)** [TITULO II]  [CAPITULO III]', '181943'),
(1368, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'FRENTE A UN ACTO QUE SUPONE QUE VIOLA, AFECTA, DESCONOCE O LESIONA UN DERECHO O UN INTERÉS LEGÍTIMO, PROCEDE (....) EN LA VÍA ADMINISTRATIVA EN LA FORMA PREVISTA EN ESTA LEY, PARA QUE SEA REVOCADO, MODIFICADO, ANULADO O SEAN SUSPENDIDOS SUS EFECTOS.', 'QUEJA.', 'SU CONTRADICCIÓN.', 'DENUNCIA PENAL.', 'SU REVISIÓN.', 'SU OBSERVACIÓN ADMINISTRATIVA.', NULL, 'b', 'SU CONTRADICCIÓN.', '(ART: 109)** [TITULO II]  [CAPITULO III]', '181944'),
(1369, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN RELACIÓN AL ARTÍCULO 61 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL (LEY 27444), RESPECTO A LA FUENTE DE LA COMPETENCIA DE LAS ENTIDADES ADMINISTRATIVAS, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DESCRIBE CORRECTAMENTE EL ORIGEN Y REGULACIÓN DE DICHA COMPETENCIA?', 'LA COMPETENCIA DE LAS ENTIDADES ADMINISTRATIVAS PUEDE ESTABLECERSE VÁLIDAMENTE MEDIANTE ACUERDOS', 'LA COMPETENCIA DE LAS ENTIDADES TIENE SU ORIGEN DIRECTO EN LA PRÁCTICA ADMINISTRATIVA Y LA COSTUMBRE, Y', 'LA COMPETENCIA DE LAS ENTIDADES DEVIENE ÚNICAMENTE DE LA CONSTITUCIÓN Y LA LEY, Y ES REGLAMENTADA POR', 'LAS ENTIDADES ADQUIEREN COMPETENCIA PRINCIPALMENTE DE LOS TRATADOS INTERNACIONALES RATIFICADOS POR EL', 'EL EJERCICIO DE COMPETENCIA DEVIENE VÁLIDO SIEMPRE QUE PROVENGA DE UNA NORMA REGLAMENTARIA EMITIDA', NULL, 'c', 'LA COMPETENCIA DE LAS ENTIDADES DEVIENE ÚNICAMENTE DE LA CONSTITUCIÓN Y LA LEY, Y ES', '(ART: 61)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO II]', '181945'),
(1370, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'DE ACUERDO CON EL ARTÍCULO 73 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL (LEY 27444), RESPECTO A LA SUPLENCIA DE LOS TITULARES DE ÓRGANOS ADMINISTRATIVOS, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA SOBRE EL PROCESO DE SUPLENCIA TEMPORAL EN CASO DE VACANCIA O AUSENCIA JUSTIFICADA?', 'LA SUPLENCIA SOLO PROCEDE ANTE LA AUSENCIA DEL TITULAR, EXCLUYENDO CASOS DE VACANCIA DEFINITIVA.', 'LA SUPLENCIA TEMPORAL ES AUTOMÁTICAMENTE EJERCIDA POR EL SERVIDOR CON MAYOR ANTIGÜEDAD EN LA ENTIDAD,', 'LA SUPLENCIA TEMPORAL CORRESPONDE ÚNICAMENTE AL SUBALTERNO INMEDIATO DEL TITULAR, SIGUIENDO EL ORDEN', 'LA SUPLENCIA DE LOS TITULARES DE ÓRGANOS ADMINISTRATIVOS, EN CASO DE VACANCIA O AUSENCIA JUSTIFICADA,', 'LA SUPLENCIA SOLO PUEDE DISPONERSE SI LA VACANCIA ES PRODUCTO DE UNA SANCIÓN ADMINISTRATIVA VIGENTE.', NULL, 'd', 'LA SUPLENCIA DE LOS TITULARES DE ÓRGANOS ADMINISTRATIVOS, EN CASO DE VACANCIA O AUSENCIA', '(ART: 73)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO II]', '181946'),
(1371, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SEGÚN EL ARTÍCULO 79 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL, ¿CUÁL ES LA CONSECUENCIA PRINCIPAL RESPECTO DE LAS COSTAS CUANDO UNA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA SOLICITA LA COLABORACIÓN DE OTRA ENTIDAD?', 'LA ENTIDAD QUE SOLICITA LA COLABORACIÓN DEBE ASUMIR LOS COSTOS ADMINISTRATIVOS Y TASAS QUE ELLO', 'LA ENTIDAD QUE RECIBE LA SOLICITUD PUEDE EXIGIR EL PAGO DE DERECHOS ADMINISTRATIVOS SI ASÍ LO CONSIDERA', 'LA SOLICITUD DE COLABORACIÓN SÍ PUEDE GENERAR EL PAGO DE TASAS, PERO ÚNICAMENTE SI EXISTE UNA', 'NO SE GENERA EL PAGO DE TASAS, DERECHOS ADMINISTRATIVOS O DE CUALQUIER OTRO CONCEPTO QUE IMPLIQUE', 'EL PAGO DE CUALQUIER CONCEPTO QUEDARÁ A DISCRECIÓN DEL ÓRGANO ADMINISTRATIVO SUPERIOR A AMBAS', NULL, 'd', 'NO SE GENERA EL PAGO DE TASAS, DERECHOS ADMINISTRATIVOS O DE CUALQUIER OTRO CONCEPTO QUE', '(ART: 79)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO III]', '181947'),
(1372, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN TODO CONFLICTO DE COMPETENCIA, EL ÓRGANO A QUIEN SE REMITE EL EXPEDIENTE DICTA RESOLUCIÓN IRRECURRIBLE DENTRO DEL PLAZO DE (....).', 'TRES DÍAS.', 'CUATRO DÍAS.', 'DOS DÍAS.', 'CINCO DÍAS.', 'DIEZ DÍAZ.', NULL, 'b', 'CUATRO DÍAS.', '(ART: 85)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO IV]', '181948'),
(1373, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SEGÚN EL ARTÍCULO 86 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL, ¿QUIÉN ES COMPETENTE PARA RESOLVER LOS CONFLICTOS POSITIVOS O NEGATIVOS DE COMPETENCIA DENTRO DE UNA MISMA ENTIDAD ADMINISTRATIVA CUANDO EXISTEN DIVERSAS AUTORIDADES INVOLUCRADAS?', 'EL SUPERIOR JERÁRQUICO COMÚN DE LAS AUTORIDADES EN CONFLICTO.', 'EL PRESIDENTE DEL CONSEJO DE MINISTROS, POR DELEGACIÓN EXPRESA DEL TITULAR DE LA ENTIDAD.', 'EL TRIBUNAL CONSTITUCIONAL, POR VÍA DE CONSULTA ADMINISTRATIVA.', 'LA DEFENSORÍA DEL PUEBLO, COMO ÓRGANO IMPARCIAL EXTERNO A LA ENTIDAD.', 'EL JUEZ DE LO CONTENCIOSO ADMINISTRATIVO DESIGNADO PARA LA CIRCUNSCRIPCIÓN TERRITORIAL', NULL, 'a', 'EL SUPERIOR JERÁRQUICO COMÚN DE LAS AUTORIDADES EN CONFLICTO.', '(ART: 86)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO IV]', '181949'),
(1374, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SI DEBIERA NOTIFICARSE A MÁS DE (...) PERSONAS QUE HAN PLANTEADO UNA SOLA SOLICITUD CON DERECHO COMÚN, LA NOTIFICACIÓN SE HARÁ CON QUIEN ENCABEZA EL ESCRITO INICIAL, INDICÁNDOLE QUE TRASMITA LA DECISIÓN A SUS COINTERESADOS.', 'CINCO.', 'DIEZ.', 'OCHO.', 'QUINCE.', 'VEINTE.', NULL, 'b', 'DIEZ.', '(ART: 22)** [TITULO I]  [CAPITULO III]', '181950'),
(1375, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SEGÚN EL ARTÍCULO 51 DE LA LEY DEL PROCEDIMIENTO ADMINISTRATIVO GENERAL (LEY 27444), ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DEFINE CORRECTAMENTE QUIÉNES SON CONSIDERADOS ADMINISTRADOS RESPECTO DE UN PROCEDIMIENTO ADMINISTRATIVO CONCRETO?', 'SOLAMENTE QUIENES INICIAN UN PROCEDIMIENTO ADMINISTRATIVO PUEDEN SER CONSIDERADOS ADMINISTRADOS, SIN', 'SOLO LAS PERSONAS JURÍDICAS, YA QUE SOLO ELLAS PUEDEN OSTENTAR DERECHOS COLECTIVOS ANTE LA', 'LOS QUE PROMUEVEN EL PROCEDIMIENTO Y ADEMÁS QUIENES, AUN SIN INICIARLO, POSEAN DERECHOS O INTERESES', 'CUALQUIER PERSONA NATURAL O JURÍDICA, INDEPENDIENTEMENTE DE ESTAR INVOLUCRADOS EN EL PROCEDIMIENTO O', 'SOLAMENTE TITULARES DE DERECHOS PATRIMONIALES INDIVIDUALES PUEDEN SER ADMINISTRADOS EN EL', NULL, 'c', 'LOS QUE PROMUEVEN EL PROCEDIMIENTO Y ADEMÁS QUIENES, AUN SIN INICIARLO, POSEAN DERECHOS O', '(ART: 51)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO I]', '181951'),
(1376, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LOS ACTOS ADMINISTRATIVOS DEBERÁN EXPRESARSE POR ESCRITO, SALVO QUE POR LA NATURALEZA Y CIRCUNSTANCIA DEL CASO, EL ORDENAMIENTO JURÍDICO HAYA PREVISTO OTRA FORMA, SIEMPRE QUE PERMITA TENER CONSTANCIA DE SU EXISTENCIA, SE REFIERE A UNA:', 'OBJETO O CONTENIDO DEL ACTO ADMINISTRATIVO.', 'FORMA DE LOS ACTOS ADMINISTRATIVOS.', 'MOTIVACIÓN DEL ACTO ADMINISTRATIVO.', 'REQUISITOS DE VALIDEZ DEL ACTO ADMINISTRATIVO.', 'RÉGIMEN DE LOS ACTOS DE LA ADMNISTRACIÓN INTERNA.', NULL, 'b', 'FORMA DE LOS ACTOS ADMINISTRATIVOS.', '(ART: 4)** [TITULO I]  [CAPITULO I]', '181952'),
(1377, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'ES VÁLIDO EL ACTO ADMNINISTRATIVO DICTADO CONFORME AL ORDENAMIENTO JURÍDICO; SE REFIERE A:', 'VALIDEZ DEL ACTO ADMINISTRATIVO.', 'PRESUNCIÓN DE VALIDEZ.', 'CAUSALES DE NULIDAD.', 'INSTANCIA COMPETENTE PARA DECLARAR LA NULIDAD.', 'ALCANCES DE LA NULIDAD.', NULL, 'a', 'VALIDEZ DEL ACTO ADMINISTRATIVO.', '(ART: 8)** [TITULO I]  [CAPITULO II]', '181953'),
(1378, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA NULIDAD DE UN ACTO SÓLO IMPLICA LA DE LOS SUCESIVOS EN EL PROCEDIMIENTO CUANDO ESTÉN VINCULADOS A ÉL; SE REFIERE A:', 'CONSERVACIÓN DEL ACTO.', 'INDEPENDENCIA DE LOS VICIOS DEL ACTO ADMINISTRATIVO.', 'INSTANCIA COMPETENTE PARA DECLARAR LA NULIDAD.', 'CAUSALES DE NULIDAD.', 'ALCANCES DE LA NULIDAD.', NULL, 'e', 'ALCANCES DE LA NULIDAD.', '(ART: 13)** [TITULO I]  [CAPITULO II]', '181954'),
(1379, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA AUTORIDAD PODRÁ DISPONER EN EL MISMO ACTO ADMINISTRATIVO QUE TENGA EFICACIA ANTICIPADA A SU EMISIÓN, SÓLO SI FUERA MÁS FAVORABLE A LOS ADMINISTRADOS, Y SIEMPRE QUE NO LESIONE DERECHOS FUNDAMENTALES O INTERESES DE BUENA FE LEGALMENTE PROTEGIDOS A TERCEROS Y QUE EXISTIERA EN LA FECHA A LA QUE PRETENDA RETROTRAERSE LA EFICACIA DEL ACTO EL SUPUESTO DE HECHO JUSTIFICATIVO PARA SU ADOPCIÓN; SE REFIERE A LA:', 'EFICACIA ANTICIPADA DEL ACTO ADMINISTRATIVO.', 'OBLIGACIÓN DE NOTIFICAR.', 'DISPENSA DE NOTIFICACIÓN.', 'MODALIDADES DE NOTIFICACIÓN.', 'EFICACIA DEL ACTO ADMINISTRATIVO.', NULL, 'a', 'EFICACIA ANTICIPADA DEL ACTO ADMINISTRATIVO.', '(ART: 17)** [TITULO I]  [CAPITULO III]', '181955'),
(1380, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SE HARÁ EN EL DOMICILIO QUE CONSTE EN EL EXPEDIENTE, O EN EL ÚLTIMO DOMICILIO QUE LA PERSONA A QUIÉN DEBA NOTIFICAR HAYA SEÑALADO ANTE EL ÓRGANO ADMNINISTRATIVO EN OTRO PROCEDIMIENTO ANÁLOGO EN LA PROPIA ENTIDAD DENTRO DEL ÚLTIMO AÑO; SE REFIERE A:', 'LA NOTIFICACIÓN PERSONAL.', 'EL ACTO DE NOTIFICACIÓN.', 'NOTIFICACIÓN A PLURALIDAD DE INTERESADOS.', 'MODALIDADES DE NOTIFICACIÓN.', 'DISPENSA DE NOTIFICACIÓN.', NULL, 'a', 'LA NOTIFICACIÓN PERSONAL.', '(ART: 21)** [TITULO I]  [CAPITULO III]', '181956'),
(1381, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CONJUNTO DE ACTOS Y DILIGENCIAS TRÁMITADOS EN LAS ENTIDADES, CONDUCENTES A LA EMISIÓN DE UN ACTO ADMINISTRATIVO QUE PRODUZCA EFECTOS JURÍDICOS INDIVIDUALES O INDIVIDUALIZABLES SOBRE INTERESES, OBLIGACIONES O DERECHOS DE LOS ADMINISTRADOS; SE REFIERE A:', 'PROCEDIMIENTOS ADMINISTRATIVOS.', 'CALIFICACIÓN DE LOS PROCEDIMIENTOS ADMINISTRATIVOS.', 'FISCALIZACIÓN POSTERIOR.', 'RÉGIMEN DE PROCEDIMIENTO DE APROBACIÓN AUTOMÁTICA.', 'LEGALIDAD DEL PROCEDIMIENTO.', NULL, 'a', 'PROCEDIMIENTOS ADMINISTRATIVOS.', '(ART: 29)** [TITULO II]  [CAPITULO I]', '181957'),
(1382, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL PLAZO QUE TRANSCURRA DESDE EL INICIO DE UN PROCEDIMEINTO ADMINISTRATIVO DE EVALUACIÓN PREVIA HASTA QUE SEA DICTADA LA RESOLUCIÓN RESPECTIVA, NO PUEDE EXCEDER DE:', 'VEINTE (20) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO', 'VEINTICINCO (25) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS', 'TREINTA (30) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO', 'TRES (3) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO', 'CINCO (5) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN PROCEDIMIENTOS CUYO', NULL, 'c', 'TREINTA (30) DÍAS HÁBILES, SALVO QUE POR LEY O DECRETO LEGISLATIVO SE ESTABLEZCAN', '(ART: 35)** [TITULO II]  [CAPITULO I]', '181958'),
(1383, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SOLAMENTE SERÁN INCLUIDOS COMO REQUISITOS EXIGIDOS PARA LA REALIZACIÓN DE CADA PROCEDIMIENTO ADMINISTRATIVO AQUELLOS QUE RAZONABLEMENTE SEAN INDISPENSABLES PARA OBTENER EL PRONUNCIAMIENTO CORRESPONDIENTE, ATENDIENDO ADEMÁS A SUS COSTOS Y BENEFICIOS; SE REFIERE A:', 'CONSIDERACIONES PARA ESTRUCTURAR EL PROCEDIMIENTO.', 'DOCUMENTACIÓN PROHIBIDA DE SOLICITAR.', 'DOCUMENTOS.', 'APROBACIÓN DEL TEXTO ÚNICO DE PROCEDIMIENTOS ADMINSITRATIVOS.', 'CONTENIDO DEL TEXTO ÚNICO DE PROCEDIMIENTOS ADMINSITRATIVOS.', NULL, 'a', 'CONSIDERACIONES PARA ESTRUCTURAR EL PROCEDIMIENTO.', '(ART: 39)** [TITULO II]  [CAPITULO I]', '181959'),
(1384, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'SON CONSIDERADOS DOCUMENTOS PÚBLICOS AQUELLOS EMITIDOS:', 'VÁLIDAMENTE POR LOS ÓRGANOS DE LAS ENTIDADES.', 'VÁLIDAMENTE POR LOS ÓRGANOS DE LAS ENTIDADES POR CREARSE.', 'VÁLIDAMENTE POR LAS ONG.', 'VÁLIDAMENTE POR LAS ASOCIACIONES SINDICALES.', 'VÁLIDAMENTE POR LOS ORGANISMOS INTERNACIONALES.', NULL, 'a', 'VÁLIDAMENTE POR LOS ÓRGANOS DE LAS ENTIDADES.', '(ART: 43)** [TITULO II]  [CAPITULO I]', '181960'),
(1385, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EL CITATORIO SE RIGE POR EL RÉGIMEN COMÚN DE LA NOTIFICACIÓN; ES UNA:', 'FORMALIDAD DE LA COMPARECENCIA.', 'COMPARECENCIA PERSONAL.', 'FORMALIDAD DE TERCEROS ADMINISTRADOS.', 'ACCIÓN DE SUMINISTRO DE INFORMACIÓN A LAS ENTIDADES.', 'FORMA DE DEBERES GENERALES DE LOS ADMINISTRADOS EN EL PROCEDIMIENTO.', NULL, 'a', 'FORMALIDAD DE LA COMPARECENCIA.', '(ART: 59)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO I]', '181961'),
(1386, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA REALIZACIÓN DE ACTIVIDADES CON CARÁCTER MATERIAL, TÉCNICO O DE SERVICIOS DE COMPETENCIA DE UN ÓRGANO PUEDE SER ENCARGADA A OTROS ÓRGANOS O ENTIDADES POR RAZONES DE EFICACIA, O CUANDO LA ENCARGADA POSEA LOS MEDIOS IDÓNEOS PARA SU DESEMPEÑO POR SÍ MISMA; SE REFIERE A:', 'DELEGACIÓN DE COMPETENCIA.', 'DEBER DE VIGILANCIA DEL DELEGANTE.', 'ENCARGO DE GESTIÓN.', 'AVOCACIÓN DE COMPETENCIA.', 'DELEGACIÓN DE FIRMA.', NULL, 'c', 'ENCARGO DE GESTIÓN.', '(ART: 71)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO II]', '181962'),
