(1401, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN CASO DE SUSCITARSE CONFLICTO NEGATIVO DE COMPETENCIA, EL EXPEDIENTE ES ELEVADO AL ÓRGANO INMEDIATO SUPERIOR PARA QUE SE RESUELVA EL CONFLICTO; SE REFIERE A:', 'CONFLICTO NEGATIVO DE COMPETENCIA.', 'CONFLICTO POSITIVO DE COMPETENCIA.', 'RESOLUCIÓN DE CONFLICTO DE COMPETENCIA.', 'COMPETENCIA PARA RESOLVER CONFLICTOS.', 'CONTINUACIÓN DEL PROCEDIMIENTO.', NULL, 'a', 'CONFLICTO NEGATIVO DE COMPETENCIA.', '(ART: 83)** [TITULO II]  [CAPITULO II]  [SUBCAPITULO IV]', '181977'),
