(1410, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CUANDO EL ACTO ADMINISTRATIVO ES PRODUCIDO POR MEDIO DE SISTEMAS AUTOMATIZADOS, DEBE GARANTIZARSE AL ADMINISTRADO:', 'CONOCER EL NOMBRE Y CARGO DE LA AUTORIDAD QUE LO EXPIDE.', 'CONOCER LA CONTRASEÑA Y EL PROGRAMA EN QUE ES PRODUCIDO', 'CONOCER EL NOMBRE, CARGO Y DOMICILIO DE LA AUTORIDAD QUE LO EXPIDE.', 'CONOCER EL NOMBRE DE LA EMPRESA QUE PROVEE EL SISTEMA.', 'CONOCER EL NOMBRE Y CARGO DE LA AUTORIDAD QUE LO EXPIDE, ASÍ COMO EL NOMBRE DE LA EMPRESA QUE PROVEE', NULL, 'a', 'CONOCER EL NOMBRE Y CARGO DE LA AUTORIDAD QUE LO EXPIDE.', '(ART: 4)** [TITULO I]  [CAPITULO I]', '181986'),
(1411, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN EL ACTO DE NOTIFICACIÓN DEBE ENTREGARSE COPIA DEL ACTO NOTIFICADO Y SEÑALAR LA FECHA Y HORA EN QUE ES EFECTUADA, RECABANDO EL NOMBRE Y FIRMA DE LA PERSONA CON QUIÉN SE ENTIENDA LA DILIGENCIA. SI ÉSTA SE NIEGA SE:', 'PROCEDERA A SU DETENCIÓN', 'INVALIDA EL PROCEDIMIENTO', 'SE HARÁ CONSTAR ASÍ EN EL ACTA.', 'SE DECLARA NULO EL PROCESO ADMINISTRATIVO', 'OBTENDRÁ ORDEN DEL JUEZ PARA CONDUCIRLO DE GRADO O FUERZA.', NULL, 'c', 'SE HARÁ CONSTAR ASÍ EN EL ACTA.', '(ART: 21)** [TITULO I]  [CAPITULO III]', '181987'),
(1412, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CUANDO PODRÁN ADOPTARSE LAS MEDIDAS QUE SEAN NECESARIAS PARA ASEGURAR LA PROTECCIÓN DEL INTERÉS PÚBLICO O LOS DERECHOS DE TERCEROS Y LA EFICACIA DE LA RESOLUCIÓN IMPUGNADA?', 'CUANDO SE DISPONE LA SUSPENSIÓN DE LA EJECUCIÓN DEL ACTO ADMINISTRATIVO', 'CUANDO SE CUSTODIA EL INTERÉS PÚBLICO Y PRIVADO', 'CUANDO SE PROTEGE LOS DERECHOS DE LOS ADMINISTRADOS', 'CUANDO SE PROTEGE LA EFICACIA INMEDIATA DEL ACTO', 'EN EL ACTO JURÍDICO', NULL, 'a', 'CUANDO SE DISPONE LA SUSPENSIÓN DE LA EJECUCIÓN DEL ACTO ADMINISTRATIVO', '(ART: 216)** [TITULO III]  [CAPITULO II]', '181988'),
