(1454, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'CUANDO DEBAN EMITIRSE VARIOS ACTOS ADMINISTRATIVOS DE LA MISMA NATURALEZA PODRÁ SER EMPLEADA FIRMA (...................... ) O INTEGRARSE EN UN SÓLO DOCUMENTO BAJO UNA MISMA MOTIVACIÓN, SIEMPRE QUE SE INDIVIDUALICE A LOS ADMINISTRADOS SOBRE LOS QUE RECAE LOS EFECTOS DEL ACTO. SEÑALE LO CORRECTO:', 'MECÁNICA', 'AUTOMATIZADA', 'REFRENDADA POR ABOGADO', 'SISTEMATIZADA', 'LEGALIZADA.', NULL, 'a', 'MECÁNICA', '(ART: 4)** [TITULO I]  [CAPITULO I]', '182030'),
(1455, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LOS ACTOS ADMINISTRATIVOS DEBEN EXPRESAR SU RESPECTIVO OBJETO, DE TAL MODO QUE PUEDA DETERMINARSE INEQUÍVOCAMENTE SUS EFECTOS JURÍDICOS. SU CONTENIDO SE AJUSTARÁ A LO DISPUESTO EN EL ORDENAMIENTO JURÍDICO, DEBIENDO SER LÍCITO, PRECISO, POSIBLE FÍSICA Y JURÍDICAMENTE, Y COMPRENDER LAS CUESTIONES SURGIDAS DE LA MOTIVACIÓN, ES UN REQUISITO DE VALIDEZ DE LOS ACTOS ADMINISTRATIVOS CONOCIDO COMO:', 'COMPETENCIA', 'OBJETO O CONTENIDO', 'FINALIDAD PÚBLICA', 'MOTIVACIÓN', 'PROCEDIMIENTO REGULAR', NULL, 'b', 'OBJETO O CONTENIDO', '(ART: 3)** [TITULO I]  [CAPITULO I]', '182031'),
(1456, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LAS AUTORIDADES ADMINISTRATIVAS NO PODRÁN DEJAR DE RESOLVER LAS CUESTIONES QUE SE LE PROPONGAN, POR DEFICIENCIAS DE SUS FUENTES; EN TALES CASOS ACUDIRÁN A:', 'PRINCIPIOS JERÁRQUICOS PRECEDENTES ADMINISTRATIVOS', 'PRINCIPIOS DE PROCEDIMIENTOS ADMINISTRATIVO PREVISTOS EN LA LEY NÚMERO 27444', 'PRINCIPIOS ELEMENTALES DE LA FUNCIÓN PÚBLICA', 'PRINCIPIOS DE PRIVILEGIO EN LA ATENCIÓN', 'PRINCIPIOS FUNDAMENTALES DE LA FUNCIÓN PÚBLICA', NULL, 'b', 'PRINCIPIOS DE PROCEDIMIENTOS ADMINISTRATIVO PREVISTOS EN LA LEY NÚMERO 27444', '(ART: VIII)** [TITULO PRELIMINAR]', '182032'),
(1457, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PRECISE CUÁL ES EL EFECTO QUE SE ORIGINA CUANDO EL RECURRENTE CALIFICA ERRÓNEAMENTE EL RECURSO:', 'SE DEVUELVE EL RECURSO PARA SU CORRECCIÓN', 'NO ES POSIBLE DAR TRÁMITE A DICHO RECURSO.', 'ES UN OBSTÁCULO PARA SU TRAMITACIÓN.', 'NO SERÁ OBSTÁCULO PARA SU TRAMITACIÓN.', 'PERDERÁ EL DERECHO A ARTICULARLOS.', NULL, 'd', 'NO SERÁ OBSTÁCULO PARA SU TRAMITACIÓN.', '(ART: 213)** [TITULO III]  [CAPITULO II]', '182033'),
(1458, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'EN CASO DE DUDA SOBRE LA AUTENTICIDAD DE LA FIRMA DEL ADMINISTRADO, LA AUTORIDAD PUEDE NOTIFICARLO PARA QUE RATIFIQUE LA FIRMA SIN PERJUICIO DE LA CONTINUACIÓN DEL PROCEDIMIENTO EN UN PLAZO DE:', 'AL DÍA SIGUIENTE DE RECIBIDO EL ESCRITO', 'DENTRO DE SIETE DÍAS HÁBILES', 'DENTRO DE TRES DÍAS HÁBILES', 'DENTRO DE UN PLAZO PRUDENCIAL', 'DENTRO DE LOS 30 DÍAS DE RECIBIDO EL ESCRITO', NULL, 'd', 'DENTRO DE UN PLAZO PRUDENCIAL', '(ART: 129)** [TITULO II]  [CAPITULO III]', '182034'),
(1459, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'PLAZOS MÁXIMOS PARA REALIZAR ACTOS PROCEDIMENTALES.- EN EL PLAZO MÁXIMO PARA LA EMISIÓN DE DICTÁMENES PERITAJES, INFORMES Y SIMILARES SERÁ DENTRO DE (..................) DÍAS DESPUÉS DE SOLICITADOS, PUDIENDO SER PRORROGADO A TRES DÍAS MÁS SI LA DILIGENCIA REQUIERE EL TRASLADO FUERA DE SU SEDE O LA ASISTENCIA DE TERCEROS: (SEÑALE LA RESPUESTA CORRECTA).', 'SIETE DÍAS.', 'TRES DÍAS', 'CUATRO DÍAS.', 'OCHO DÍAS.', 'QUINCE DÍAS.', NULL, 'a', 'SIETE DÍAS.', '(ART: 132)** [TITULO II]  [CAPITULO IV]', '182035'),
