(1497, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'TODA NOTIFICACIÓN DEBERÁ PRACTICARSE A MÁS TARDAR DENTRO DEL PLAZO DE 5 DÍAS, A PARTIR DE LA EXPEDICIÓN DEL ACTO QUE SE NOTIFIQUE, Y DEBERÁ CONTENER; MARQUE LA RESPUESTA CORRECTA:', 'LA EXPRESIÓN DE LOS LINEAMIENTOS QUE PROCEDEN, EL ÓRGANO ANTE EL CUÁL DEBEN SOLICITAR LOS RECURSOS Y', 'LA SOLICITUD DE LOS RECURSOS QUE PROCEDEN, EL ÓRGANO ANTE EL CUÁL NO DEBEN PRESENTARSE LOS RECURSOS', 'LA DOCUMENTACIÓN DE LOS RECURSOS QUE INTERPONEN, EL ÓRGANO ANTE EL CUÁL DEBEN PRESENTARSE LOS', 'LA EXPRESIÓN DE LOS RECURSOS QUE PROCEDEN, EL ÓRGANO ANTE EL CUÁL DEBEN PRESENTARSE LOS RECURSOS Y', 'LA EXPRESIÓN DE LOS PETITORIOS QUE PROCEDEN, ANTE EL CUÁL DEBEN PRESENTARSE LOS RECURSOS Y EL PLAZO', NULL, 'd', 'LA EXPRESIÓN DE LOS RECURSOS QUE PROCEDEN, EL ÓRGANO ANTE EL CUÁL DEBEN PRESENTARSE LOS', '(ART: 24)** [TITULO I]  [CAPITULO III]', '182076'),
(1498, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'TODA NOTIFICACIÓN DEBERÁ PRACTICARSE A MÁS TARDAR DENTRO DEL PLAZO DE 5 DÍAS, A PARTIR DE LA EXPEDICIÓN DEL ACTO QUE SE NOTIFIQUE, Y DEBERÁ CONTENER:', 'LA CONDICIÓN DEL PROCEDIMIENTO DENTRO DEL CUÁL HAYA SIDO VERIFICADO.', 'LA IDENTIFICACIÓN DEL PROCEDIMIENTO DENTRO DEL CUÁL HAYA SIDO DICTADO.', 'LA VERIFICACIÓN DEL PROCESO DENTRO DEL CUÁL HAYA SIDO SOLUCIONADO.', 'LA IDENTIDAD DE LA RESOLUCIÓN DENTRO DEL CUÁL HAYA SIDO SOLICITADO.', 'LA SOLICITUD DEL PROCEDIMIENTO FUERA DE LA CUÁL HAYA SIDO DICTADO.', NULL, 'b', 'LA IDENTIFICACIÓN DEL PROCEDIMIENTO DENTRO DEL CUÁL HAYA SIDO DICTADO.', '(ART: 24)** [TITULO I]  [CAPITULO III]', '182077'),
