(1500, 'Ley De Presupuesto Del Sector Público, De Conformidad Con Los Clasificadores De ', 'LA DECLARATORIA DE NULIDAD Y LOS ACTOS QUE SE DICTEN EN ENMIENDA, TAMBIÉN TIENEN EFICACIA :', 'ANTICIPADA.', 'CORRELACIONADA.', 'POSTERIOR.', 'DIFERENTE.', 'PARTICIPATIVA.', NULL, 'a', 'ANTICIPADA.', '(ART: 17)** [TITULO I]  [CAPITULO III]', '182079');
