(1501, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA POLICÍA PODRÁ INFORMAR A LOS MEDIOS DE COMUNICACIÓN SOCIAL ACERCA DE LA IDENTIDAD DE LOS IMPUTADOS. CUANDO SE TRATE DE LA VÍCTIMA, REQUERIRÁ:.', 'PREVIA AUTORIZACIÓN DEL FISCAL', 'PREVIA AUTORIZACIÓN DEL JUEZ PENAL', 'AUTORIZACIÓN PREVIA DEL JUEZ DE LA INVESTIGACIÓN PREPARATORIA', 'AUTORIZACIÓN PREVIA DE LA POLICÍA NACIONAL DEL PERÚ', 'PREVIA AUTORIZACIÓN DEL DEFENSOR DEL PUEBLO', NULL, 'a', 'PREVIA AUTORIZACIÓN DEL FISCAL', '(ART: 70) [LIBRO PRIMERO]  [SECCION IV]  [TITULO I]  [CAPITULO II]', '184330'),
(1502, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿A TRAVÉS DE QUIÉN EL IMPUTADO PUEDE HACER VALER LOS DERECHOS QUE LA CONSTITUCIÓN Y LAS LEYES LA CONCEDEN?', 'SU REPRESENTANTE LEGAL', 'EL DEFENSOR DEL PUEBLO', 'DE SU ABOGADO DEFENSOR', 'LA CORTE INTERAMERICANA DE DERECHOS HUMANOS', 'EL JUEZ PENAL', NULL, 'c', 'DE SU ABOGADO DEFENSOR', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184331'),
(1503, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CONOCER LOS CARGOS FORMULADOS EN SU CONTRA Y, EN CASO DE DETENCIÓN, A QUE SE LE EXPRESE LA CAUSA O MOTIVO DE DICHA MEDIDA, ES UN:', 'DERECHO DEL IMPUTADO', 'POTESTAD DEL PROCESADO', 'DERECHO DEL ENCAUSADO', 'DERECHO DEL PROCESADO', 'DERECHO DEL DETENIDO', NULL, 'a', 'DERECHO DEL IMPUTADO', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184332'),
(1504, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO EL IMPUTADO CONSIDERE QUE DURANTE LAS DILIGENCIAS PRELIMINARES O EN LA INVESTIGACIÓN PREPARATORIA NO SE HAN DADO CUMPLIMIENTO A ESTAS DISPOSICIONES, O QUE SUS DERECHOS NO SON RESPETADOS O QUE ES OBJETO DE MEDIDAS LIMITATIVAS DE DERECHOS INDEBIDAS O DE REQUERIMIENTOS ILEGALES; PUEDE ACUDIR:', 'AL JUEZ RESPECTIVO QUE LLEVA LA INVESTIGACIÓN', 'A SU ABOGADO DEFENSOR, PARA QUE HAGA PREVALECER SUS DERECHOS', 'EN VÍA DE CONSULTA AL JUEZ DE LA INVESTIGACIÓN INTERMEDIA', 'AL FISCAL QUE SE ENCUENTRA DIRIGIENDO LA INVESTIGACIÓN', 'EN VÍA DE TUTELA AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA', NULL, 'e', 'EN VÍA DE TUTELA AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA', '(ART: 71)** [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184333'),
(1505, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUIÉN DEBE SER ASISTIDO DESDE LOS ACTOS INICIALES DE INVESTIGACIÓN POR UN ABOGADO DEFENSOR?', 'EL IMPUTADO', 'LA VÍCTIMA', 'LOS TESTIGOS', 'PERSONAS VINCULADAS AL HECHO PUNIBLE', 'LOS FAMILIARES', NULL, 'a', 'EL IMPUTADO', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184334'),
(1506, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL IMPUTADO TIENE DERECHO A ABSTENERSE DE DECLARAR; Y, SI ACEPTA HACERLO, A QUE SU ABOGADO DEFENSOR ESTÉ PRESENTE EN SU DECLARACIÓN Y EN TODAS LAS DILIGENCIAS EN QUE:', 'SE SOLICITE SU AUSENCIA', 'SE REQUIERE SU PRESENCIA', 'SE SOLICITE SU PARTICIPACIÓN DURANTE LA INVESTIGACIÓN', 'SE REQUIERA DE SU INTERVENCIÓN PARA EL ESCLARECIMIENTO', 'SE LE NOTIFIQUE PARA DECLARAR RESPECTO AL HECHO DELICTUOSO COMETIDO', NULL, 'b', 'SE REQUIERE SU PRESENCIA', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184335'),
(1507, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL IMPUTADO TIENE DERECHO A QUE NO SE EMPLEE EN SU CONTRA MEDIOS COACTIVOS, INTIMIDATORIOS O CONTRARIOS A SU DIGNIDAD, NI A SER SOMETIDO A TÉCNICAS O MÉTODOS QUE INDUZCAN O ALTEREN:', 'LAS PREMINENCIAS RESPECTO A SU DETENCIÓN', 'SUS DECLARACIONES RELACIONADAS AL HECHO', 'SU LIBRE VOLUNTAD O A SUFRIR UNA RESTRICCIÓN NO AUTORIZADA', 'LOS MEDIOS DE PRUEBA OFRECIDOS EN SU MOMENTO', 'LOS MECANISMOS DE DEFENSA POR PARTE DE SU ABOGADO DEFENSOR', NULL, 'c', 'SU LIBRE VOLUNTAD O A SUFRIR UNA RESTRICCIÓN NO AUTORIZADA', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184336'),
(1508, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL IMPUTADO CUANDO SU ESTADO DE SALUD ASÍ LO REQUIERA, TIENE DERECHO A SER EXAMINADO POR MÉDICO LEGISTA O EN SU DEFECTO POR:', 'UN NEURÓLOGO DE SER EL CASO', 'UN TÉCNICO DE SALUD MÁS PRÓXIMO', 'UN MÉDICO GENERAL', 'OTRO PROFESIONAL DE LA SALUD', 'OTRO MÉDICO DE LA ESPECIALIDAD QUE EN EL MOMENTO SE NECESITE', NULL, 'd', 'OTRO PROFESIONAL DE LA SALUD', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184337'),
(1509, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUIÉNES FIRMAN EN EL ACTA SOBRE EL CUMPLIMIENTO DE LOS DERECHOS DEL IMPUTADO?', 'EL IMPUTADO, EL ABOGADO Y LA POLICÍA NACIONAL', 'EL ABOGADO DEFENSOR Y EL MINISTERIO PÚBLICO', 'EL DEFENSOR DEL PUEBLO', 'LOS FAMILIARES', 'EL IMPUTADO Y LA AUTORIDAD CORRESPONDIENTE', NULL, 'e', 'EL IMPUTADO Y LA AUTORIDAD CORRESPONDIENTE', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184338'),
(1510, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ DEBERÁ DE REALIZARSE, SI EL IMPUTADO SE REHÚSA A FIRMAR EN ACTA?', 'SE HARÁ CONSTAR LA ABSTENCIÓN, Y SE CONSIGNARÁ EL MOTIVO SI LO EXPRESARE.', 'NO SE HARÁ CONSTAR LA ABSTENCIÓN, SI ASÍ LO EXPRESARE.', 'SE HARÁ CONSTATAR LA DECISIÓN, Y SE CONSIGNARÁ EL MOTIVO SI LO EXPRESARE.', 'NO SE HARÁ CONSTAR DICHA OBSERVACIÓN, SIN CONSIGNAR EL MOTIVO SI ASÍ LO EXPRESARE.', 'NO SE HARÁ CONSTAR LA DECISIÓN.', NULL, 'a', 'SE HARÁ CONSTAR LA ABSTENCIÓN, Y SE CONSIGNARÁ EL MOTIVO SI LO EXPRESARE.', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184339'),
(1511, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUIÉN PUEDE ACUDIR EN VÍA DE TUTELA AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA, PARA QUE SUBSANE LA OMISIÓN, O DICTE LA MEDIDA DE CORRECCIÓN O DE PROTECCIÓN QUE CORRESPONDA?', 'EL IMPUTADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS', 'EL PROCESADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS', 'EL SENTENCIADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS', 'EL INVESTIGADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS', 'EL INTERVENIDO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE MEDIDAS', NULL, 'a', 'EL IMPUTADO CUANDO CONSIDERE QUE SUS DERECHOS NO SON RESPETADOS, O QUE ES OBJETO DE', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184340'),
(1512, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUIÉN SERÁ IDENTIFICADO POR SU NOMBRE, DATOS PERSONALES, SEÑAS PARTICULARES Y, CUANDO CORRESPONDA, POR SUS IMPRESIONES DIGITALES A TRAVÉS DE LA OFICINA TÉCNICA RESPECTIVA?', 'EL PROCESADO', 'EL IMPUTADO', 'EL INVESTIGADO', 'EL DETENIDO', 'EL AUTOR', NULL, 'b', 'EL IMPUTADO', '(ART: 72) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184341'),
(1513, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ SE DEBERÁ REALIZAR SI EL IMPUTADO SE ABSTIENE DE PROPORCIONAR DATOS QUE LO IDENTIFICAN O LO HAGA FALSAMENTE?', 'SE LE IDENTIFICARÁ POR MEDIO DE LOS IMPUTADOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD', 'SE LE IDENTIFICARÁ POR LOS PERITOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD', 'SE LE IDENTIFICARÁ POR TESTIGOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD', 'SE LE IDENTIFICARÁ POR PERITOS O POR OTROS MEDIOS ÚTILES, AUN SEA VOLUNTARIO', 'SE LE IDENTIFICARÁ POR LOS AGRAVIADOS O POR OTROS MEDIOS CIENTÍFICOS, AUN CONTRA SU VOLUNTAD', NULL, 'c', 'SE LE IDENTIFICARÁ POR TESTIGOS O POR OTROS MEDIOS ÚTILES, AUN CONTRA SU VOLUNTAD', '(ART: 72)** [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184342'),
(1514, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ SUCEDERÁ SI HUBIERA DUDA SOBRE LOS DATOS OBTENIDOS EN LA IDENTIFICACIÓN DEL IMPUTADO?.', 'ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER CORREGIDOS EN', 'ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS NO PODRÁN SER CORREGIDOS', 'ALTERARÁ EL CURSO DE LAS ACTUACIONES JUDICIALES Y LOS ERRORES SOBRE ELLOS NO PODRÁN SER CORREGIDOS', 'NO ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER CORREGIDOS', 'ALTERARÁ EL CURSO DE LAS INVESTIGACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS NO PODRÁN SER', NULL, 'd', 'NO ALTERARÁ EL CURSO DE LAS ACTUACIONES PROCESALES Y LOS ERRORES SOBRE ELLOS PODRÁN SER', '(ART: 72) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184343'),
(1515, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LOS JUECES, LOS FISCALES O LA POLICÍA NACIONAL DEBEN HACER SABER AL IMPUTADO DE MANERA INMEDIATA Y COMPRENSIBLE, QUE TIENE DERECHO A:', 'SER ASISTIDO POR UN JURISTA EN LA MATERIA QUE DIO LUGAR A SU DETENCIÓN', 'SER ASISTIDO POR UN ABOGADO DE OFICIO, CUANDO NO CUENTE CON LOS MEDIOS ECONÓMICOS SUFICIENTES', 'SER ASISTIDO POR UN ABOGADO DE LA DEFENSORÍA DEL PUEBLO', 'SER ASISTIDO DESDE LOS ACTOS INICIALES POR UN ABOGADO DEFENSOR', 'SER ASISTIDO POR UN ASESOR LEGAL DEL PODER JUDICIAL', NULL, 'd', 'SER ASISTIDO DESDE LOS ACTOS INICIALES POR UN ABOGADO DEFENSOR', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184344'),
(1516, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LOS JUECES, LOS FISCALES O LA POLICÍA NACIONAL DEBEN HACER SABER AL IMPUTADO DE MANERA INMEDIATA Y COMPRENSIBLE, QUE TIENE DERECHO A:', 'NEGARSE A MANIFESTAR RESPECTO A LOS MOTIVOS QUE DIO ORIGEN A SU DETENCIÓN', 'ABSTENERSE DE DECLARAR; Y, SI ACEPTA HACERLO, A QUE SU ABOGADO DEFENSOR ESTÉ PRESENTE', 'ABSTENERSE DE BRINDAR ENTREVISTAS; Y, SI ASÍ LO QUISIERA, DEBERÁ ESTAR PRESENTE SU ABOGADO DEFENSOR', 'ABSTENERSE DE EFECTUAR COMENTARIOS ADVERSOS A LA INVESTIGACIÓN DE LA POLICÍA NACIONAL', 'ABSTENERSE DE EFECTUAR COMENTARIOS ADVERSOS A LA INVESTIGACIÓN DEL MINISTERIO PÚBLICO', NULL, 'b', 'ABSTENERSE DE DECLARAR; Y, SI ACEPTA HACERLO, A QUE SU ABOGADO DEFENSOR ESTÉ PRESENTE', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184345'),
(1517, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LOS JUECES, LOS FISCALES O LA POLICÍA NACIONAL DEBEN HACER SABER AL IMPUTADO DE MANERA INMEDIATA Y COMPRENSIBLE QUE TIENE DERECHO A:', 'QUE NO SE LE VIOLENTE FÍSICA NI PSICOLÓGICAMENTE', 'SER RESPETADO EN TODO MOMENTO, BRINDÁNDOSELE ALIMENTACIÓN COMPLETA Y ABRIGO', 'PODER ENTABLAR DIÁLOGO CON ALGÚN REPRESENTANTE DE LA CRUZ ROJA INTERNACIONAL', 'EXPRESAR SU MALESTAR A LA DEFENSORÍA DEL PUEBLO, SOBRE SU DETENCIÓN', 'QUE NO SE EMPLEE EN SU CONTRA MEDIOS COACTIVOS, INTIMIDATORIOS O CONTRARIOS A SU DIGNIDAD', NULL, 'e', 'QUE NO SE EMPLEE EN SU CONTRA MEDIOS COACTIVOS, INTIMIDATORIOS O CONTRARIOS A SU DIGNIDAD', '(ART: 71) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184346'),
(1518, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'AL PROCESADO QUE ALTERE EL ORDEN EN UN ACTO PROCESAL, SE LE APERCIBIRÁ CON LA SUSPENSIÓN DE LA DILIGENCIA Y DE CONTINUARLA.', 'CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y DEMÁS SUJETOS PROCESALES', 'CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y SIN LA PARTICIPACIÓN DE LOS SUJETOS PROCESALES', 'CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y UN REPRESENTANTE LEGAL', 'CON LA SOLA INTERVENCIÓN DE UN TESTIGO Y DEMÁS SUJETOS PROCESALES', 'CON LA SOLA INTERVENCIÓN DEL AGRAVIADO Y DEMÁS SUJETOS PROCESALES', NULL, 'a', 'CON LA SOLA INTERVENCIÓN DE SU ABOGADO DEFENSOR Y DEMÁS SUJETOS PROCESALES', '(ART: 73) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184347'),
(1519, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ SUCEDERÍA SI EL ABOGADO DEFENSOR SE SOLIDARIZA Y ABANDONA LA DILIGENCIA?', 'SERÁ SUSTITUIDO POR UNO NOMBRADO DE PARTE', 'SERÁ SUSTITUIDO POR UNO NOMBRADO DE OFICIO', 'NO SERÁ SUSTITUIDO Y CONTINUARÁ EL ABOGADO DE OFICIO', 'NO SERÁ SUSTITUIDO POR UNO NOMBRADO POR EL MINISTERIO PÚBLICO', 'SERÁ SUSTITUIDO INMEDIATAMENTE.', NULL, 'b', 'SERÁ SUSTITUIDO POR UNO NOMBRADO DE OFICIO', '(ART: 73)** [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184348'),
(1520, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO SE ESTABLEZCA LA MINORÍA DE EDAD DEL IMPUTADO, ¿QUIÉN PUEDE SOLICITAR AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA, CORTE LA SECUELA DEL PROCESO Y PONGA AL ADOLESCENTE A DISPOSICIÓN DEL FISCAL DE FAMILIA?', 'EL ABOGADO DEFENSOR', 'LOS FAMILIARES', 'EL FISCAL O CUALQUIERA DE LAS PARTES', 'EL REPRESENTANTE DE LA DEFENSORÍA DEL PUEBLO', 'EL JUEZ DE MENORES', NULL, 'c', 'EL FISCAL O CUALQUIERA DE LAS PARTES', '(ART: 74) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184349'),
(1521, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ ACCIONES DICTARÁ EL JUEZ CUANDO SE ACREDITA LA MINORÍA DE EDAD EN LA ETAPA INTERMEDIA O EN EL JUICIO ORAL, PREVIA AUDIENCIA Y CON LA INTERVENCIÓN DE LAS PARTES?', 'DICTARÁ LOS PROVEÍDOS NECESARIOS', 'CONSULTARÁ SOBRE LA RESOLUCIÓN CORRESPONDIENTE', 'IMPARTIRÁ LAS DISPOSICIONES PERTINENTES', 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE', 'NO DICTARÁ NINGUNA RESOLUCIÓN', NULL, 'd', 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE', '(ART: 74) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184350'),
(1522, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO SE ESTABLEZCA LA MINORÍA DE EDAD DEL IMPUTADO, EN TODOS LOS CASOS:', 'SOLAMENTE EN ESTE CASO NO SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN OTRA', 'EN TODOS ESTOS CASOS SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN CUALQUIER', 'EN NINGÚN CASO EL ACTOR CIVIL TIENE DERECHO PARA QUE LO HAGA VALER EN LA VÍA PERTINENTE.', 'NO SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA PREVALECER EN LA ETAPA INTERMEDIA.', 'SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN LA VÍA PERTINENTE.', NULL, 'e', 'SE DEJARÁ A SALVO EL DERECHO DEL ACTOR CIVIL PARA QUE LO HAGA VALER EN LA VÍA PERTINENTE.', '(ART: 74) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184351'),
(1523, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ, A REQUERIMIENTO DEL FISCAL O DE LAS DEMÁS PARTES, PREVIA CONSTATACIÓN, DECLARARÁ CONTUMAZ AL IMPUTADO CUANDO:', 'NO OBEDEZCA, PESE A DESCONOCER DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN', 'OBEDEZCA, AL TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN', 'DESACATE, PESE A TENER CONOCIMIENTO DE SU INDUCCIÓN, UNA ORDEN EN SU CONTRA O PRISIÓN', 'DESOBEDEZCA, PESE A SER CONSCIENTE DE SU EMISIÓN, UNA PAPELETA DE DETENCIÓN O PRIVATIVA DE LIBERTAD', 'NO OBEDEZCA, PESE A TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN.', NULL, 'e', 'NO OBEDEZCA, PESE A TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN.', '(ART: 79) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184352'),
(1524, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN CASO DE INIMPUTABILIDAD DEL PROCESADO, ¿CUÁNDO DISPONDRÁ EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA LA PRÁCTICA DE UN EXAMEN POR UN PERITO ESPECIALIZADO?.', 'SEGÚN EL ESTADO DE LA CAUSA, SOLAMENTE DISPONDRÁ A PEDIDO DE PARTE', 'SEGÚN EL ESTADO DE LA CAUSA, DISPONDRÁ, DE OFICIO O A PEDIDO DE PARTE', 'SEGÚN EL ESTADO DE SOBRESEIMIENTO, SOLAMENTE DISPONDRÁ DE OFICIO', 'SEGÚN EL ESTADO DE SOBRESEIMIENTO, SOLAMENTE DISPONDRÁ A PEDIDO DE PARTE', 'SEGÚN EL CASO DEL JUICIO', NULL, 'b', 'SEGÚN EL ESTADO DE LA CAUSA, DISPONDRÁ, DE OFICIO O A PEDIDO DE PARTE', '(ART: 75) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184353'),
(1525, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'RECIBIDO EL INFORME PERICIAL, PREVIA AUDIENCIA, CON INTERVENCIÓN DE LAS PARTES Y DEL PERITO, SI EL JUEZ CONSIDERA SI EXISTEN INDICIOS SUFICIENTES PARA ESTIMAR ACREDITADO EL ESTADO DE INIMPUTABILIDAD DEL PROCESADO:', 'NO DICTARÁ RESOLUCIÓN NI PROCEDIMIENTO DE SEGURIDAD', 'DICTARÁ LA RESOLUCIÓN SOBRE EL RESULTADO DEL EXAMEN MÉDICO, INSTANDO LA INCOACIÓN DEL PROCEDIMIENTO', 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE INSTANDO LA INCOACIÓN DEL PROCEDIMIENTO DE SEGURIDAD', 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE INSTANDO LA COACCIÓN DEL INICIO DEL PROCEDIMIENTO', 'DICTARÁ LA RESOLUCIÓN PERTINENTE INSTANDO LA PLANIFICACIÓN DEL PROCEDIMIENTO DE SEGURIDAD', NULL, 'c', 'DICTARÁ LA RESOLUCIÓN CORRESPONDIENTE INSTANDO LA INCOACIÓN DEL PROCEDIMIENTO DE SEGURIDAD', '(ART: 75) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184354'),
(1526, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿EN QUÉ CONSISTE LA ANOMALÍA PSÍQUICA SOBREVENIDA?', 'ANTES DE COMETER EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO', 'DURANTE LA REALIZACIÓN DEL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO', 'CUANDO DESPUÉS DE COMETIDO EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO', 'CUANDO DESPUÉS DE COMETIDO LA INFRACCIÓN LE SOBREVIENE ANOMALÍA PSÍQUICA AL PROCESADO', 'CUANDO DESPUÉS DE COMETIDO EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL AGRAVIADO', NULL, 'c', 'CUANDO DESPUÉS DE COMETIDO EL DELITO LE SOBREVIENE ANOMALÍA PSÍQUICA GRAVE AL IMPUTADO', '(ART: 76) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184355'),
(1527, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ANOMALÍA PSÍQUICA SOBREVENIDA.- SI DEL ANÁLISIS DE LO ACTUADO, EL ÓRGANO JURISDICCIONAL ADVIERTE QUE EL IMPUTADO PRESENTA ANOMALÍA PSÍQUICA GRAVE QUE LE IMPIDE CONTINUAR CON LA CAUSA:', 'CONSULTARÁ LA SUSPENSIÓN DEL PROCESO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA HAGA POSIBLE REINICIARLO', 'DISPONDRÁ LA SUSPENSIÓN DEL PROCESADO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA SEA POSIBLE INICIARLO', 'NO DISPONDRÁ LA SUSPENSIÓN DEL PROCESO Y CONTINUARÁ CON EL TRATAMIENTO DE LA DOLENCIA', 'DISPONDRÁ LA SUSPENSIÓN DEL PROCESO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA HAGA POSIBLE REINICIARLO', 'DISPONDRÁ EL TRATAMIENTO HASTA QUE EL IMPUTADO SUPERE SU DOLENCIA', NULL, 'd', 'DISPONDRÁ LA SUSPENSIÓN DEL PROCESO HASTA QUE EL TRATAMIENTO DE LA DOLENCIA HAGA POSIBLE', '(ART: 76) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184356'),
(1528, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ANOMALÍA PSÍQUICA SOBREVENIDA.- ¿CUÁNDO SE IMPEDIRÁ LA DECLARACIÓN DEL IMPUTADO O EL JUICIO?', 'CUANDO LO DISPONGA EL JUEZ DURANTE EL PROCESO SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL', 'CUANDO LO DISPONGA EL FISCAL DURANTE EL PROCESO SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL', 'CUANDO LO ORDENE EL FISCAL EN EL PROCESO SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO', 'SE SUSPENDE A SOLICITUD DE PARTE', 'CUANDO SE SUSPENDA EL PROCESO, SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO', NULL, 'e', 'CUANDO SE SUSPENDA EL PROCESO, SIN PERJUICIO DE QUE SE PROSIGA CON LA INVESTIGACIÓN DEL HECHO', '(ART: 76) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184357'),
(1529, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ DISPONDRÁ EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA CUANDO EL IMPUTADO ENFERMARA DURANTE LA PRIVACIÓN DE SU LIBERTAD?', 'DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO LEGISTA O, EN SU DEFECTO, DEL PERITO MÉDICO QUE', 'DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO CIRUJANO O, EN SU DEFECTO, DEL PERITO', 'DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO CIRUJANO O, EN SU DEFECTO, POR UNA JUNTA MÉDICA', 'DISPONDRÁ SU EVALUACIÓN POR PARTE DEL MÉDICO LEGISTA O, EN SU DEFECTO, DEL PERITO MÉDICO QUE DESIGNE EL', 'DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO FORENSE O, EN SU DEFECTO, DEL PERITO MÉDICO QUE', NULL, 'a', 'DISPONDRÁ SU INMEDIATA EVALUACIÓN POR PARTE DEL MÉDICO LEGISTA O, EN SU DEFECTO, DEL PERITO', '(ART: 77) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184358'),
(1530, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ENFERMEDAD DEL IMPUTADO.- EVACUADO EL DICTAMEN, SE PODRÁ ORDENAR, SI FUERE NECESARIO:', 'EL INGRESO DEL IMPUTADO A UN CENTRO HOSPITALARIO', 'EL INGRESO DEL AGRAVIADO A UN CENTRO HOSPITALARIO', 'EL INGRESO DEL IMPUTADO A UNA CENTRO MÉDICO PRIVADO', 'QUE EL PROCESADO VISITE UNA CLÍNICA PRIVADA', 'EL INGRESO DEL TESTIGO A UN CENTRO HOSPITALARIO ESTATAL', NULL, 'a', 'EL INGRESO DEL IMPUTADO A UN CENTRO HOSPITALARIO', '(ART: 77) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184359'),
(1531, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ENFERMEDAD DEL IMPUTADO.- CUANDO SE REQUIERA DE INFRAESTRUCTURA Y ATENCIÓN MÉDICA ESPECIALIZADA QUE NO EXISTA EN UN CENTRO HOSPITALARIO ESTATAL.', 'EN CUALQUIER CASO, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA', 'EN CASOS EXCEPCIONALES, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA', 'CUANDO LO REQUIERA LA FAMILIA, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA', 'CUANDO LA FAMILIA TENGA RECURSOS SUFICIENTES PARA SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA', 'EL ABOGADO DEFENSOR PODRÁ CONDUCIRLO A UNA CLÍNICA PRIVADA', NULL, 'b', 'EN CASOS EXCEPCIONALES, SE PODRÁ AUTORIZAR SU INTERNAMIENTO EN UNA CLÍNICA PRIVADA', '(ART: 77) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184360'),
(1532, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL DIRECTOR DEL CENTRO HOSPITALARIO EN DONDE EL PROCESADO RECIBA ASISTENCIA MÉDICA O PSIQUIÁTRICA, DEBERÁ:', 'INFORMAR BIMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE', 'INFORMAR SEMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE', 'INFORMAR TRIMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE', 'INFORMAR BIMESTRALMENTE AL ABOGADO DEFENSOR Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE', 'INFORMAR SEMESTRALMENTE SOLAMENTE AL FISCAL ACERCA DEL ESTADO DE SALUD DEL PACIENTE', NULL, 'c', 'INFORMAR TRIMESTRALMENTE AL FISCAL Y AL JUEZ ACERCA DEL ESTADO DE SALUD DEL PACIENTE', '(ART: 78) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184361'),
(1533, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA JUSTICIA PENAL ES GRATUITA, SALVO EL:', 'PAGO DEL ARANCEL JUDICIAL', 'PAGO DE LAS COSTAS PROCESALES', 'COSTO DE LOS HONORARIOS DEL ABOGADO DEFENSOR', 'PAGO DEL IMPORTE PROCESAL', 'COSTO DEL PROCESO PROPIAMENTE DICHO', NULL, 'b', 'PAGO DE LAS COSTAS PROCESALES', '(ART: I) [TITULO PRELIMINAR]', '184362'),
(1534, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UN JUICIO PREVIO, ORAL, PÚBLICO Y CONTRADICTORIO, ES UN DERECHO QUE LE CORRESPONDE:', 'AL IMPUTADO', 'AL PROCESADO', 'AL INVESTIGADO', 'A TODA PERSONA', 'AL AUTOR', NULL, 'd', 'A TODA PERSONA', '(ART: I) [TITULO PRELIMINAR]', '184363'),
(1535, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CONSTITUCIÓN Y ESTE CÓDIGO, PREVÉN QUE:', 'LOS AUTORES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y', 'LOS IMPLICADOS INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y', 'LAS PARTES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y DERECHOS', 'LOS INVESTIGADOS INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y', 'LOS CÓMPLICES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y', NULL, 'c', 'LAS PARTES INTERVENDRÁN EN EL PROCESO CON IGUALES POSIBILIDADES DE EJERCER LAS FACULTADES Y', '(ART: I) [TITULO PRELIMINAR]', '184364'),
(1536, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUIÉNES PRESERVARÁN EL PRINCIPIO DE IGUALDAD PROCESAL?', 'LOS FISCALES', 'LOS JUECES', 'LA POLICÍA NACIONAL', 'EL ÓRGANO JURISDICCIONAL', 'LOS REPRESENTANTES DEL MINISTERIO PÚBLICO', NULL, 'b', 'LOS JUECES', '(ART: I) [TITULO PRELIMINAR]', '184365'),
(1537, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL ESTADO, ES QUIEN GARANTIZA LA:', 'REPARACIÓN POR LOS ERRORES PROCESALES', 'MOTIVACIÓN DE UN JUICIO JUSTO', 'INDEMNIZACIÓN POR LOS ERRORES JUDICIALES', 'DEBIDA OBSERVANCIA DEL PROCESO', 'CANCELACIÓN POR LOS ERRORES JUDICIALES', NULL, 'c', 'INDEMNIZACIÓN POR LOS ERRORES JUDICIALES', '(ART: I) [TITULO PRELIMINAR]', '184366'),
(1538, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LAS RESOLUCIONES SON RECURRIBLES, EN:', 'EL RECURSO DE APELACIÓN', 'EN EL DESARROLLO DEL PROCESO', 'EL MODO COMO LO SOLICITE EL ABOGADO DEFENSOR', 'LA FORMA Y CIRCUNSTANCIAS ESTABLECIDAS', 'LOS CASOS Y MODOS PREVISTOS POR LEY', NULL, 'e', 'LOS CASOS Y MODOS PREVISTOS POR LEY', '(ART: I) [TITULO PRELIMINAR]', '184367'),
(1539, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿A QUIÉNES SE CONSIDERA INOCENTE?', 'AL IMPLICADO EN LA COMISIÓN DE UN HECHO DELICTUOSO, Y DEBE SER TRATADO COMO AL AUTOR, MIENTRAS SE', 'A TODA PERSONA IMPUTADA DE LA COMISIÓN DE UN HECHO PUNIBLE Y DEBE SER TRATADA COMO TAL, MIENTRAS NO SE', 'AL INVESTIGADO POR DELITO FLAGRANTE, Y DEBE SER TRATADA COMO TAL, MIENTRAS NO SE DEMUESTRE LO', 'AL PROCESADO QUE NO PUEDA DEMOSTRAR FEHACIENTEMENTE SU INOCENCIA', 'AL IMPUTADO DE DELITOS GRAVES, CONVICTO Y CONFESO, CUANDO SE DEMUESTRE SU AUTORÍA', NULL, 'b', 'A TODA PERSONA IMPUTADA DE LA COMISIÓN DE UN HECHO PUNIBLE Y DEBE SER TRATADA COMO TAL,', '(ART: II) [TITULO PRELIMINAR]', '184368'),
(1540, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'NINGÚN FUNCIONARIO O AUTORIDAD PÚBLICA PUEDE PRESENTAR A UNA PERSONA COMO:', 'AUTOR DE UN HECHO DELICTUOSO, HASTA QUE SE DECLARE SU INOCENCIA', 'INVESTIGADO DE UN DELITO GRAVE, HASTA QUE LO DISPONGA EL JUEZ', 'IMPUTADO DE UN HECHO PENAL, HASTA QUE SE DESARROLLE EL PROCESO JUDICIAL', 'CULPABLE O BRINDAR INFORMACIÓN EN TAL SENTIDO', 'IMPLICADO EN UN HECHO PUNIBLE, HASTA CONFIRMAR SU AUTORÍA', NULL, 'd', 'CULPABLE O BRINDAR INFORMACIÓN EN TAL SENTIDO', '(ART: II) [TITULO PRELIMINAR]', '184369'),
(1541, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿EN QUÉ CASO PROCEDERÁ EL ARRESTO CIUDADANO?', 'ANTES DE LAS 72 HORAS DE COMETIDO EL HECHO DELICTUOSO', 'EN ESTADO DE FLAGRANCIA DELICTIVA', 'DESPUÉS DE LAS 72 HORAS DE COMETIDO EL HECHO DELICTUOSO', 'EL AGENTE COMETIÓ EL HECHO DELICTIVO, HABIENDO TRANSCURRIDO LAS CUARENTA Y OCHO (48) HORAS', 'EL AGENTE ES ENCONTRADO DESPUÉS DE VEINTICUATRO (24) HORAS DESPUÉS DE LA PERPETRACIÓN DEL DELITO', NULL, 'b', 'EN ESTADO DE FLAGRANCIA DELICTIVA', '(ART: 260) [LIBRO SEGUNDO]  [SECCION III]  [TITULO II]', '184370'),
(1542, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL MINISTERIO PÚBLICO ES EL TITULAR DEL EJERCICIO PÚBLICO DE LA ACCIÓN PENAL EN LOS DELITOS Y TIENE EL DEBER DE:', 'LA CARGA DE LA PRUEBA', 'INVESTIGAR PRELIMINARMENTE', 'LA CARGA PROCESAL', 'DAR LOS LINEAMIENTOS DE ACCIÓN A LA POLICÍA NACIONAL', 'ESTABLECER LA AUTORÍA DEL IMPLICADO', NULL, 'a', 'LA CARGA DE LA PRUEBA', '(ART: IV) [TITULO PRELIMINAR]', '184371'),
(1543, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DEBE RESOLVERSE A FAVOR DEL IMPUTADO EN CASO DE:', 'INTERRUPCIÓN DE LAS INVESTIGACIONES', 'FALLECIMIENTO DEL IMPUTADO', 'DUDA SOBRE LA RESPONSABILIDAD PENAL', 'ANOMALÍA PSÍQUICA COMPROBADA', 'MINORÍA DE EDAD DEL IMPUTADO', NULL, 'c', 'DUDA SOBRE LA RESPONSABILIDAD PENAL', '(ART: II) [TITULO PRELIMINAR]', '184372'),
(1544, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL AGRAVIADO TIENE DERECHO A SER INFORMADO DEL RESULTADO DEL PROCEDIMIENTO, AUN CUANDO NO HAYA INTERVENIDO EN ÉL:', 'SIEMPRE QUE LO SOLICITE', 'PREVIA CONSULTA AL FISCAL', 'CUANDO EL JUEZ PENAL LO AUTORICE', 'SIN NECESIDAD DE SOLICITARLO', 'A TRAVÉS DEL DEFENSOR DEL PUEBLO', NULL, 'a', 'SIEMPRE QUE LO SOLICITE', '(ART: 95) [LIBRO PRIMERO]  [SECCION IV]  [TITULO IV]  [CAPITULO I]', '184373'),
(1545, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'INTERDICCIÓN DE LA PERSECUCIÓN PENAL MÚLTIPLE, SE REFIERE A:', 'QUE SE PROCESE A UNA O MÁS PERSONAS POR UN MISMO HECHO', 'QUE EL INCULPADO PIDA SU SEPARACIÓN DEL PROCESO', 'QUE EL AUTOR SOLICITE LA PRESCRIPCIÓN DE SU CASO', 'QUE EL INVESTIGADO EXIJA LA PRESENCIA DEL FISCAL', 'QUE NADIE PODRÁ SER PROCESADO NI SANCIONADO MÁS DE UNA VEZ POR UN MISMO HECHO', NULL, 'e', 'QUE NADIE PODRÁ SER PROCESADO NI SANCIONADO MÁS DE UNA VEZ POR UN MISMO HECHO', '(ART: III) [TITULO PRELIMINAR]', '184374'),
(1546, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿LA POLICÍA QUÉ DOCUMENTO REDACTARÁ DONDE SE HAGA CONSTAR LA ENTREGA Y LAS DEMÁS CIRCUNSTANCIAS DE LA INTERVENCIÓN?', 'UN INFORME', 'UN OFICIO', 'UN PARTE', 'UN ACTA', 'UN ATESTADO', NULL, 'd', 'UN ACTA', '(ART: 260) [LIBRO SEGUNDO]  [SECCION III]  [TITULO II]', '184375'),
(1547, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ES UNO DE LOS DERECHOS DEL AGRAVIADO, A SER ESCUCHADO ANTES DE CADA DECISIÓN QUE:', 'EXPLIQUE LA HABILITACIÓN O SUSPENSIÓN DE LA ACCIÓN PENAL', 'IMPLIQUE LA EXTINCIÓN O SUSPENSIÓN DE LA ACCIÓN PENAL', 'IMPLIQUE LA ACCIÓN O EXTENSIÓN DE LA ACCIÓN PENAL', 'EXPLIQUE LA EXTINCIÓN O INCLUSIÓN DE LA ACCIÓN PENAL', 'IMPLIQUE LA CONCLUSIÓN DE LA ACCIÓN PENAL', NULL, 'b', 'IMPLIQUE LA EXTINCIÓN O SUSPENSIÓN DE LA ACCIÓN PENAL', '(ART: 95) [LIBRO PRIMERO]  [SECCION IV]  [TITULO IV]  [CAPITULO I]', '184376'),
(1548, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SALVO LAS EXCEPCIONES PREVISTAS EN LA CONSTITUCIÓN, SOLO PODRÁN DICTARSE POR LA AUTORIDAD JUDICIAL:', 'LAS RESOLUCIONES QUE LIMITAN DERECHOS FUNDAMENTALES', 'LAS DIRECTIVAS QUE LIMITAN DERECHOS FUNDAMENTALES', 'LAS CAUSAS QUE LIMITAN DERECHOS FUNDAMENTALES', 'LAS MEDIDAS QUE LIMITAN DERECHOS FUNDAMENTALES', 'LAS MOTIVACIONES QUE LIMITAN DERECHOS FUNDAMENTALES', NULL, 'd', 'LAS MEDIDAS QUE LIMITAN DERECHOS FUNDAMENTALES', '(ART: VI) [TITULO PRELIMINAR]', '184377'),
(1549, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL AGRAVIADO TIENE DERECHO A RECIBIR UN TRATO DIGNO Y RESPETUOSO POR PARTE DE LAS AUTORIDADES COMPETENTES, Y A LA PROTECCIÓN DE SU INTEGRIDAD, INCLUYENDO LA DE SU FAMILIA. EN LOS PROCESOS POR DELITOS CONTRA LA LIBERTAD SEXUAL SE:', 'CONSERVARÁ SU IDENTIDAD PREVIA CONSULTA AL FISCAL', 'PRESERVARÁ SU IDENTIDAD', 'CONSERVARÁ SU IDENTIDAD', 'CONSERVARÁ SU IDENTIDAD CON AUTORIZACIÓN DEL JUEZ PENAL', 'OCULTARÁ SU IDENTIDAD', NULL, 'b', 'PRESERVARÁ SU IDENTIDAD', '(ART: 95) [LIBRO PRIMERO]  [SECCION IV]  [TITULO IV]  [CAPITULO I]', '184378'),
(1550, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SERÁ INTERPRETADA RESTRICTIVAMENTE:', 'LA NORMA QUE OTORGUE BENEFICIOS AL IMPUTADO', 'LA LEY MÁS FAVORABLE AL IMPUTADO', 'LA LEY QUE COACTE LA LIBERTAD O EL EJERCICIO DE LOS DERECHOS PROCESALES', 'LA NORMA QUE GENERA EL INICIO DEL PROCESO', 'LA NORMA QUE FAVOREZCA A LOS CÓMPLICES', NULL, 'c', 'LA LEY QUE COACTE LA LIBERTAD O EL EJERCICIO DE LOS DERECHOS PROCESALES', '(ART: VII) [TITULO PRELIMINAR]', '184379'),
(1551, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LAS PRUEBAS OBTENIDAS, DIRECTA O INDIRECTAMENTE, CON VIOLACIÓN DEL CONTENIDO ESENCIAL DE LOS DERECHOS FUNDAMENTALES DE LA PERSONA:', 'TAMBIÉN SON VÁLIDAS, MIENTRAS NO DIGA LO CONTRARIO EL FISCAL', 'CARECEN DE EFECTO LEGAL', 'NO ESTÁN PERMITIDAS EN EL PROCESO', 'SE VAN DESCARTANDO DURANTE LA INVESTIGACIÓN POLICIAL', 'SE ADMITEN SI SON NECESARIAS EN LA INVESTIGACIÓN', NULL, 'b', 'CARECEN DE EFECTO LEGAL', '(ART: VIII) [TITULO PRELIMINAR]', '184380'),
(1552, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL MINISTERIO PÚBLICO ES TITULAR DEL EJERCICIO DE LA ACCIÓN PENAL EN LOS DELITOS Y TIENE EL DEBER DE LA CARGA DE LA PRUEBA, ADEMÁS:', 'COORDINA CON EL JUEZ PARA EL INICIO DEL PROCESO', 'VERIFICAR LA SALUD FÍSICA Y MENTAL DEL IMPUTADO', 'RECIBE LOS LINEAMIENTOS DEL JUEZ DEL CASO', 'ASUME LA CONDUCCIÓN DE LA INVESTIGACIÓN', 'PLANTEA LOS ALEGATOS DURANTE LA FASE PRELIMINAR', NULL, 'd', 'ASUME LA CONDUCCIÓN DE LA INVESTIGACIÓN', '(ART: IV) [TITULO PRELIMINAR]', '184381'),
(1553, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CONTRA SÍ MISMO, CONTRA SU CÓNYUGE, O SUS PARIENTES DENTRO DEL CUARTO GRADO DE CONSANGUINIDAD O SEGUNDO DE AFINIDAD:', 'NADIE PUEDE SER OBLIGADO O INDUCIDO A DECLARAR O A RECONOCER CULPABILIDAD', 'EL IMPUTADO ESTA OBLIGADO A RECONOCER SU PARTICIPACIÓN', 'EL AUTOR PUEDE DECLARAR SU CULPABILIDAD EN CASO DE FLAGRANCIA', 'EL IMPLICADO SI ES QUE ASÍ LO DESEA PUEDE RECONOCER SU AUTORÍA', 'EL PROCESADO A TRAVÉS DE SU ABOGADO DEFENSOR, PUEDE MANIFESTAR LO CONVENIENTE PARA ÉL', NULL, 'a', 'NADIE PUEDE SER OBLIGADO O INDUCIDO A DECLARAR O A RECONOCER CULPABILIDAD', '(ART: IX) [TITULO PRELIMINAR]', '184382'),
(1554, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿POR QUÉ EL AGRAVIADO PUEDE IMPUGNAR EL SOBRESEIMIENTO Y LA SENTENCIA ABSOLUTORIA?', 'POR SER UN PEDIDO DEL FISCAL', 'PORQUE NO ESTAR DE ACUERDO', 'PORQUE ES UN DERECHO', 'PORQUE ES UN UN DEBER', 'POR SER UNA DISPOSICIÓN JUDICIAL', NULL, 'c', 'PORQUE ES UN DERECHO', '(ART: 95) [LIBRO PRIMERO]  [SECCION IV]  [TITULO IV]  [CAPITULO I]', '184383'),
(1555, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿CUÁNDO SERÁ INFORMADO EL AGRAVIADO SOBRE SUS DERECHOS?', 'DESPUÉS DE INTERPONER LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU PRIMERA INTERVENCIÓN EN LA', 'CUANDO INTERPONGA UN RECURSO DE QUEJA, POSTERIOR A SU DECLARACIÓN O EN SU PRIMERA INTERVENCIÓN EN LA', 'CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU SEGUNDA INTERVENCIÓN EN LA CAUSA', 'CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU PRIMERA INTERVENCIÓN EN LA CAUSA', 'CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O POSTERIOR A SU PRIMERA INTERVENCIÓN EN', NULL, 'd', 'CUANDO INTERPONGA LA DENUNCIA, AL DECLARAR PREVENTIVAMENTE O EN SU PRIMERA INTERVENCIÓN EN', '(ART: 95) [LIBRO PRIMERO]  [SECCION IV]  [TITULO IV]  [CAPITULO I]', '184385'),
(1556, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CITACIÓN AL IMPUTADO CON DOMICILIO CONOCIDO Y PROCESAL, SERÁ REQUERIDO PARA SU CONCURRENCIA AL JUICIO BAJO APERCIBIMIENTO DE:', 'SER ABSUELTO', 'SER SENTENCIADO EN AUSENCIA', 'SER DECLARADO CONTUMAZ', 'SER DECLARADO REO AUSENTE', 'SER CONDENADO', NULL, 'c', 'SER DECLARADO CONTUMAZ', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184386'),
(1557, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI UN SOLO ACUSADO O SIENDO VARIOS NINGUNO CONCURRE A LA APERTURA DE LA AUDIENCIA, SIN JUSTIFICAR SU INASISTENCIA, SE:', 'SERA SENTENCIADO COMO REO - CONTUMAZ', 'CITADO PARA UNA FECHA, SIN PERJUICIO DE DECLARAR CONTUMAZ', 'SEÑALARÁ NUEVO DÍA Y HORA, SIN PERJUICIO DE DECLARARLOS CONTUMACES', 'NO SERA CITADO PARA UN NUEVO DÍA Y HORA', 'SERA DECLARADO CONTUMAZ', NULL, 'c', 'SEÑALARÁ NUEVO DÍA Y HORA, SIN PERJUICIO DE DECLARARLOS CONTUMACES', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184387'),
(1558, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LAS MEDIDAS QUE LIMITAN DERECHOS FUNDAMENTALES, SE IMPONDRÁN MEDIANTE RESOLUCIÓN MOTIVADA, A INSTANCIA DE:', 'LA PARTE PROCESAL LEGITIMADA', 'LA SOLITUD DEL AGRAVIADO', 'DEL ABOGADO DEFENSOR DEL IMPUTADO', 'DEL FISCAL DE LA INVESTIGACIÓN PREPARATORIA', 'DEL JUEZ DE LA ETAPA PRELIMINAR', NULL, 'a', 'LA PARTE PROCESAL LEGITIMADA', '(ART: VI) [TITULO PRELIMINAR]', '184388'),
(1559, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN QUE CASOS NO PODRÁ REALIZARSE LA AUDIENCIA:', 'CUANDO NO CONCURRE EL ACUSADO', 'SIN PRESENCIA DEL ACUSADO Y SU DEFENSOR', 'CUANDO NO CONCURRE EL ABOGADO DEFENSOR', 'CUANDO NO CONCURRE EL FISCAL PROVINCIAL', 'CUANDO CONCURRE EL ACUSADO Y SU DEFENSOR', NULL, 'b', 'SIN PRESENCIA DEL ACUSADO Y SU DEFENSOR', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184389'),
(1560, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL SUPERIOR JERÁRQUICO DE UN FISCAL, DE OFICIO O A INSTANCIA DEL AFECTADO, PODRÁ REEMPLAZARLO CUANDO NO CUMPLE ADECUADAMENTE CON SUS FUNCIONES O INCURRE EN IRREGULARIDADES. TAMBIÉN PODRÁ HACERLO PREVIA LAS INDAGACIONES QUE CONSIDERE CONVENIENTE, CUANDO:', 'SE HAYAN DETECTADO ACTOS DE CORRUPCIÓN', 'ESTÉ INCURSO EN LAS CAUSALES DE RECUSACIÓN ESTABLECIDAS', 'SE COMPRUEBE UNA CONDUCTA INDECOROSA', 'FALTE A SU CÓDIGO DE ÉTICA PROFESIONAL', 'SE LE SORPRENDA EN FLAGRANCIA DEL DELITO DE EXTORSIÓN', NULL, 'b', 'ESTÉ INCURSO EN LAS CAUSALES DE RECUSACIÓN ESTABLECIDAS', '(ART: 62) [LIBRO PRIMERO]  [SECCION IV]  [TITULO I]  [CAPITULO I]', '184390'),
(1561, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DE CONFORMIDAD CON LA LEY, AL FISCAL DE LA NACIÓN LE CORRESPONDE ESTABLECER LA:', 'ENTREGA DE LOS LINEAMIENTOS DE ACCIÓN A LOS FISCALES', 'EFICACIA DE LAS FACULTADES A LOS REPRESENTANTES DEL MINISTERIO PÚBLICO', 'DISTRIBUCIÓN DE FUNCIONES DE LOS MIEMBROS DEL MINISTERIO PÚBLICO', 'CREACIÓN LAS DIRECTRICES PARA EL DESARROLLO DE LA INVESTIGACIÓN PRELIMINAR', 'EJECUCIÓN DE LAS POLÍTICAS DE TRABAJO PARA LOS FISCALES', NULL, 'c', 'DISTRIBUCIÓN DE FUNCIONES DE LOS MIEMBROS DEL MINISTERIO PÚBLICO', '(ART: 63) [LIBRO PRIMERO]  [SECCION IV]  [TITULO I]  [CAPITULO I]', '184391'),
(1562, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TODO MEDIO DE PRUEBA SERÁ VALORADO SÓLO SI HA SIDO OBTENIDO E INCORPORADO AL PROCESO POR UN PROCEDIMIENTO:', 'INVESTIGATIVO PRELIMINAR', 'CON PARTICIPACIÓN DE LA POLICÍA NACIONAL', 'REGULAR CON PARTICIPACIÓN DEL FISCAL', 'CONSTITUCIONALMENTE LEGÍTIMO', 'QUE LE FAVOREZCA AL IMPUTADO', NULL, 'd', 'CONSTITUCIONALMENTE LEGÍTIMO', '(ART: VIII) [TITULO PRELIMINAR]', '184392'),
(1563, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO SON VARIOS LOS ACUSADOS, Y ALGUNO DE ELLOS NO CONCURRA, LA AUDIENCIA SE:', 'SE SUSPENDERÁ LA AUDIENCIA', 'INICIARÁ CON LOS ASISTENTES', 'INICIARÁ CUANDO CONCURRAN TODOS LOS ASISTENTES', 'NO SE INICIARÁ LA AUDIENCIA', 'SE REPROGRAMARÁ LA AUDIENCIA', NULL, 'b', 'INICIARÁ CON LOS ASISTENTES', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184393'),
(1564, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TODA PERSONA TIENE DERECHO INVIOLABLE E IRRESTRICTO, A QUE SE LE CONCEDA UN TIEMPO RAZONABLE PARA:', 'MEDITAR SOBRE SU CASO Y DECLARAR VOLUNTARIAMENTE', 'QUE PUEDA RECONOCER SU CULPA', 'QUE COORDINE CON SU ABOGADO DEFENSOR', 'QUE PREPARE SU DEFENSA', 'QUE HAGA LAS CONSULTAS PERTINENTES', NULL, 'd', 'QUE PREPARE SU DEFENSA', '(ART: IX) [TITULO PRELIMINAR]', '184394'),
(1565, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TODA PERSONA TIENE DERECHO INVIOLABLE E IRRESTRICTO, A:', 'QUE HAGA LAS CONSULTAS PERTINENTES', 'QUE COORDINE CON SU ABOGADO DEFENSOR', 'QUE PUEDA RECONOCER SU CULPA', 'MEDITAR SOBRE SU CASO Y DECLARAR VOLUNTARIAMENTE', 'EJERCER SU AUTODEFENSA MATERIAL', NULL, 'e', 'EJERCER SU AUTODEFENSA MATERIAL', '(ART: IX) [TITULO PRELIMINAR]', '184395'),
(1566, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TODA PERSONA TIENE DERECHO INVIOLABLE E IRRESTRICTO, A:', 'INTERVENIR, EN PLENA IGUALDAD, EN LA ACTIVIDAD PROBATORIA', 'OBJETAR LAS CUESTIONES QUE NO TIENEN QUE VER CON SU CASO', 'MEDITAR SOBRE SU CASO Y DECLARAR VOLUNTARIAMENTE', 'QUE PUEDA RECONOCER SU PARTICIPACIÓN EN EL HECHO DELICTUOSO QUE SE LE IMPUTA', 'QUE COORDINE CON SU ABOGADO DEFENSOR PARA DARLE MAYORES APORTES', NULL, 'a', 'INTERVENIR, EN PLENA IGUALDAD, EN LA ACTIVIDAD PROBATORIA', '(ART: IX) [TITULO PRELIMINAR]', '184396'),
(1567, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN QUÉ CASO AL ACUSADO AUSENTE O CONTUMAZ, SE LE INCORPORARÁ A LA AUDIENCIA:', 'CUANDO ES NO HABIDO', 'CUANDO SEA CAPTURADO', 'CUANDO SEA CITADO FORMALMENTE', 'CUANDO ACEPTA SU RESPONSABILIDAD', 'CUANDO NO ACEPTA SU RESPONSABILIDAD', NULL, 'b', 'CUANDO SEA CAPTURADO', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184397'),
(1568, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TODA PERSONA TIENE DERECHO INVIOLABLE E IRRESTRICTO, A:', 'MEDITAR SOBRE SU CASO Y DECLARAR VOLUNTARIAMENTE', 'UTILIZAR LOS MEDIOS DE PRUEBA PERTINENTES', 'QUE PUEDA RECONOCER SU PARTICIPACIÓN EN EL HECHO DELICTUOSO QUE SE LE IMPUTA', 'QUE COORDINE CON SU ABOGADO DEFENSOR PARA DARLE MAYORES APORTES', 'OBJETAR LAS CUESTIONES QUE NO TIENEN QUE VER CON SU CASO', NULL, 'b', 'UTILIZAR LOS MEDIOS DE PRUEBA PERTINENTES', '(ART: IX) [TITULO PRELIMINAR]', '184398'),
(1569, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN QUÉ CASO AL ACUSADO AUSENTE O CONTUMAZ, SE LE INCORPORARÁ A LA AUDIENCIA:', 'CUANDO NO SE PRESENTE VOLUNTARIAMENTE', 'CUANDO SE PRESENTE VOLUNTARIAMENTE', 'CUANDO SEA CITADO FORMALMENTE', 'CUANDO SEA POSIBLE SU UBICACIÓN', 'CUANDO SE TIENE CONOCIMIENTO DE SU PARADERO', NULL, 'b', 'CUANDO SE PRESENTE VOLUNTARIAMENTE', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184399'),
(1570, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CÓMO COMPARECERÁ EL IMPUTADO PRESO PREVENTIVO, EN TODO EL CURSO DEL JUICIO:', 'CON LIGADURAS Y PRISIONES, A FIN DE EVITAR SU FUGA', 'SIN LIGADURAS NI PRISIONES, ACOMPAÑADO DE EFECTIVOS POLICIALES', 'ACOMPAÑADO POR SU ABOFADO DEFENSOR', 'CON GRILLETES Y CADENA DE SEGURIDAD, ACOMPAÑADO DE EFECTIVOS POLICIALES', 'CON SU ABOGADO DEFENSOR', NULL, 'b', 'SIN LIGADURAS NI PRISIONES, ACOMPAÑADO DE EFECTIVOS POLICIALES', '(ART: 367) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184400'),
(1571, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL PROCESO PENAL GARANTIZA, TAMBIÉN, EL EJERCICIO DE LOS DERECHOS DE INFORMACIÓN Y DE PARTICIPACIÓN PROCESAL A LA PERSONA AGRAVIADA O:', 'AL IMPUTADO AGRAVIADO EN EL PROCESO', 'A LOS IMPLICADOS EN EL HECHO PUNIBLE', 'PERJUDICADA POR EL DELITO', 'A LOS AUTORES Y PRESUNTOS AUTORES, CONFIRMADOS DENTRO DEL PROCESO', 'AL PROCESADO QUE SE LE DECLARE INIMPUTABLE', NULL, 'c', 'PERJUDICADA POR EL DELITO', '(ART: IX) [TITULO PRELIMINAR]', '184401'),
(1572, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'PRECISE EN QUÉ LUGAR SE REALIZARÁ EL JUZGAMIENTO:', 'LA SALA DE AUDIENCIAS', 'EN LOS CENTROS DE RECLUSIÓN', 'EN LOS CENTROS PENITENCIARIOS', 'EN LOS JUZGADOS RESPECTIVOS', 'EN LOS JUZGADOS DEL CRIMEN ORGANIZADO', NULL, 'a', 'LA SALA DE AUDIENCIAS', '(ART: 368) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184402'),
(1573, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL MINISTERIO PÚBLICO, FORMULARÁ SUS DISPOSICIONES, REQUERIMIENTOS Y CONCLUSIONES EN FORMA MOTIVADA Y LA ESPECÍFICA, DE MANERA QUE SE BASTEN A SÍ MISMOS, SIN REMITIRSE A LAS DECISIONES DEL:', 'FISCAL DE LA NACIÓN', 'ÓRGANO JURISDICCIONAL', 'JUEZ QUE EMITIRÁ LA SENTENCIA', 'JUEZ', 'ABOGADO DEFENSOR', NULL, 'd', 'JUEZ', '(ART: 64) [LIBRO PRIMERO]  [SECCION IV]  [TITULO I]  [CAPITULO I]', '184403'),
(1574, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'QUÉ AUTORIDAD DESIGNA LA SALA DE AUDIENCIAS PARA EL JUZGAMIENTO:', 'EL VOCAL SUPERIOR', 'EL FISCAL DE LA INVESTIGACIÓN PREPARATORIA', 'EL JUZGADO PENAL', 'EL FISCAL PROVINCIAL', 'EL PRESIDENTE DE LA CORTE SUPREMA DE JUSTICIA', NULL, 'c', 'EL JUZGADO PENAL', '(ART: 368) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184404'),
(1575, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO EL ACUSADO POR RAZONES DE ENFERMEDAD U OTRA CAUSAL JUSTIFICADA SEA IMPOSIBLE SU CONCURRENCIA A LA SALA DE AUDIENCIAS, DÓNDE PODRÁ REALIZARSE EL JUZGAMIENTO:', 'EN EL LUGAR DONDE SEÑALA SU ABOGADO DEFENSOR', 'EN EL LUGAR DONDE ÉSTE SE ENCUENTRE', 'EN EL LUGAR DONDE INDIQUE SU MÉDICO TRATANTE', 'EN EL LUGAR DONDE SEÑALA SU DEFENSA TÉCNICA', 'EN EL LUGAR DONDE SEÑALA EL DIRECTOR DEL ESTABLECIMIENTO PENITENCIARIO', NULL, 'b', 'EN EL LUGAR DONDE ÉSTE SE ENCUENTRE', '(ART: 368) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184405'),
(1576, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'QUE SUJETO PROCESAL, VERIFICARÁ LA CORRECTA CITACIÓN A LAS PARTES, ASÍ COMO LA EFECTIVA CONCURRENCIA DE LOS TESTIGOS Y PERITOS EMPLAZADOS:', 'EL ABOGADO DEFENSOR', 'EL FISCAL DE LA INVESTIGACIÓN PREPARATORIA', 'EL JUEZ PENAL', 'EL FISCAL', 'EL AUXILIAR DE JUSTICIA', NULL, 'c', 'EL JUEZ PENAL', '(ART: 369) [LIBRO TERCERO]  [SECCION III]  [TITULO II]', '184406'),
(1577, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUIÉN PODRÁ DISPONER LA CONDUCCIÓN COMPULSIVA DEL OMISO POR LA POLICÍA NACIONAL, EN CASO DE INCONCURRENCIA A UNA CITACIÓN DEBIDAMENTE NOTIFICADA BAJO APERCIBIMIENTO?', 'LA POLICÍA NACIONAL', 'EL JUEZ DE LA ETAPA INTERMEDIA', 'EL JUEZ ESPECIALIZADO EN LO PENAL', 'EL MINISTERIO PÚBLICO', 'EL JUEZ DESIGNADO PARA EL CASO', NULL, 'd', 'EL MINISTERIO PÚBLICO', '(ART: 66) [LIBRO PRIMERO]  [SECCION IV]  [TITULO I]  [CAPITULO I]', '184407'),
(1578, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'RECIBIR LAS DENUNCIAS ESCRITAS O SENTAR EL ACTA DE LAS VERBALES, ASÍ COMO TOMAR DECLARACIONES A LOS DENUNCIANTES, ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'e', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO A', '184408'),
(1579, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'AISLAR, PROTEGER Y VIGILAR EL LUGAR DE LOS HECHOS A FIN DE QUE NO SEAN SUSTRAÍDOS, ALTERADOS Y CONTAMINADOS LOS INDICIOS Y EVIDENCIAS DEL DELITO. ES UNA:', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'a', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO B', '184409'),
(1580, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'PRACTICAR EL REGISTRO DE LAS PERSONAS, ASÍ COMO PRESTAR EL AUXILIO QUE REQUIERAN LAS VÍCTIMAS DEL DELITO. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'c', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO C', '184410'),
