(1582, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'PRACTICAR LAS DILIGENCIAS ORIENTADAS A LA IDENTIFICACIÓN FÍSICA DE LOS AUTORES Y PARTÍCIPES DEL DELITO Y LAS FALTAS. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'b', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO E', '184412'),
(1583, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'REALIZAR ENTREVISTAS E IDENTIFICAR A POSIBLES TESTIGOS QUE HAYAN PRESENCIADO LA COMISIÓN DE LOS HECHOS. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'd', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO F', '184413'),
(1584, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LEVANTAR PLANOS, TOMAR FOTOGRAFÍAS, REALIZAR GRABACIONES EN VIDEO Y DEMÁS OPERACIONES TÉCNICAS O CIENTÍFICAS. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'c', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO G', '184414'),
(1585, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'INTERVENIR Y DETENER A LOS PRESUNTOS AUTORES Y PARTÍCIPES EN CASO DE FLAGRANCIA, INFORMÁNDOLES DE INMEDIATO SOBRE SUS DERECHOS. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'b', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO H', '184415'),
(1586, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ASEGURAR LOS DOCUMENTOS PRIVADOS, E INSTRUMENTOS DE TELECOMUNICACIONES QUE PUEDAN SERVIR A LA INVESTIGACIÓN. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'c', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO I', '184416'),
(1587, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ALLANAR LOCALES DE USO PÚBLICO O ABIERTOS AL PÚBLICO, MEDIANTE OPERATIVOS DEBIDAMENTE PLANIFICADOS, HACIENDO USO RACIONAL DE LA FUERZA CONFORME CON LA NORMATIVA DE LA MATERIA. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'd', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO J', '184417'),
(1588, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EFECTUAR, BAJO INVENTARIO, LOS SECUESTROS E INCAUTACIONES NECESARIOS EN LOS CASOS DE DELITOS FLAGRANTES O DE PELIGRO INMINENTE DE SU PERPETRACIÓN. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'c', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO K', '184418'),
(1589, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'RECIBIR LA MANIFESTACIÓN DE LOS PRESUNTOS AUTORES O PARTÍCIPES DE DELITOS, CON PRESENCIA OBLIGATORIA DEL ABOGADO DEFENSOR DE SU ELECCIÓN O DEL DEFENSOR PÚBLICO QUE CORRESPONDA, DEBIÉNDOSE REGISTRAR LAS DECLARACIONES EN DISPOSITIVOS O EQUIPOS AUDIOVISUALES. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'c', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO L', '184419'),
(1590, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'REUNIR CUANTA INFORMACIÓN ADICIONAL DE URGENCIA PERMITA LA CRIMINALÍSTICA PARA PONERLA A DISPOSICIÓN DEL FISCAL. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'b', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO M', '184420'),
(1591, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LAS DEMÁS DILIGENCIAS Y PROCEDIMIENTOS DE INVESTIGACIÓN NECESARIOS PARA EL MEJOR ESCLARECIMIENTO DE LOS HECHOS INVESTIGADOS. ES UNA:', 'FACULTAD DE LA POLICÍA NACIONAL DEL PERÚ', 'DERECHO DE LA POLICÍA NACIONAL DEL PERÚ', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'UN DEBER DE LA POLICÍA NACIONAL DEL PERÚ', 'OBLIGACIÓN DE LA POLICÍA NACIONAL DEL PERÚ', NULL, 'c', 'ATRIBUCIÓN DE LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO N° 68. NUMERAL 1. INCISO N', '184421'),
(1592, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'QUIÉN, ESCUCHANDO A LAS PARTES, DECIDIRÁ EL ORDEN EN QUE DEBEN ACTUARSE LAS DECLARACIONES DE LOS IMPUTADOS, SI FUERAN VARIOS:', 'EL FISCAL Y EL ACUSADO', 'FISCAL PROVINCIAL PENAL', 'EL FISCAL', 'JUEZ PENAL', 'FISCAL DE LA INVESTIGACIÓN PREPARATORIA', NULL, 'd', 'JUEZ PENAL', '(ART: 375) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184423'),
(1593, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'A QUIÉN LE CORRESPONDE EL INTERROGATORIO DIRECTO DE LOS ÓRGANOS DE PRUEBA:', 'AL ABOGADO DEFENSOR', 'AL JUEZ PENAL', 'AL FISCAL', 'AL FISCAL Y A LOS ABOGADOS DE LAS PARTES', 'A LOS ABOGADOS DE LAS PARTES', NULL, 'd', 'AL FISCAL Y A LOS ABOGADOS DE LAS PARTES', '(ART: 375) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184424'),
(1594, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN EL DEBATE PROBATORIO, EN QUÉ ORDEN SE ENCUENTRA EL EXAMEN DEL ACUSADO:', 'SEGUNDO ORDEN', 'PRIMER ORDEN', 'TERCER ORDEN', 'CUARTO ORDEN', 'QUINTO ORDEN', NULL, 'b', 'PRIMER ORDEN', '(ART: 375) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184425'),
(1595, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN EL DEBATE PROBATORIO, EN QUÉ ORDEN SE ENCUENTRA LA ACTUACIÓN DE LOS MEDIOS DE PRUEBA ADMITIDOS:', 'SEGUNDO ORDEN', 'PRIMER ORDEN', 'TERCER ORDEN', 'CUARTO ORDEN', 'QUINTO ORDEN', NULL, 'a', 'SEGUNDO ORDEN', '(ART: 375) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184426'),
(1596, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN EL DEBATE PROBATORIO, EN QUÉ ORDEN SE ENCUENTRA LA ORALIZACIÓN DE LOS MEDIOS PROBATORIOS:', 'SEGUNDO ORDEN', 'PRIMER ORDEN', 'TERCER ORDEN', 'CUARTO ORDEN', 'QUINTO ORDEN', NULL, 'c', 'TERCER ORDEN', '(ART: 375) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184427'),
(1597, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'PRESTAR ASESORAMIENTO DESDE QUE SU PATROCINADO FUERE CITADO O DETENIDO POR LA AUTORIDAD POLICIAL; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'MÉDICO LEGISTA', 'JUEZ', 'ABOGADO DEFENSOR', NULL, 'e', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 1', '184428'),
(1598, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'INTERROGAR DIRECTAMENTE A SU DEFENDIDO, ASÍ COMO A LOS DEMÁS PROCESADOS, TESTIGOS Y PERITOS; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'MÉDICO LEGISTA', 'ABOGADO DEFENSOR', 'JUEZ', NULL, 'd', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 2', '184429'),
(1599, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'RECURRIR A LA ASISTENCIA RESERVADA DE UN EXPERTO EN CIENCIA, TÉCNICA O ARTE DURANTE EL DESARROLLO DE UNA DILIGENCIA, SIEMPRE QUE SUS CONOCIMIENTOS SEAN REQUERIDOS PARA MEJOR DEFENDER. EL ASISTENTE DEBERÁ ABSTENERSE DE INTERVENIR DE MANERA DIRECTA; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'ABOGADO DEFENSOR', 'MÉDICO LEGISTA', 'JUEZ', NULL, 'c', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 3', '184430'),
(1600, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'PARTICIPAR EN TODAS LAS DILIGENCIAS, EXCEPTO EN LA DECLARACIÓN PRESTADA DURANTE LA ETAPA DE INVESTIGACIÓN POR EL IMPUTADO QUE NO DEFIENDA; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'MÉDICO LEGISTA', 'ABOGADO DEFENSOR', 'JUEZ', NULL, 'd', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 4', '184431'),
(1601, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'APORTAR LOS MEDIOS DE INVESTIGACIÓN Y DE PRUEBA QUE ESTIME PERTINENTES;', 'PERITO DE OFICIO', 'FISCAL', 'MÉDICO LEGISTA', 'ABOGADO DEFENSOR', 'JUEZ', NULL, 'd', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 5', '184432'),
(1602, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'PRESENTAR PETICIONES ORALES O ESCRITAS PARA ASUNTOS DE SIMPLE TRÁMITE; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'ABOGADO DEFENSOR', 'MÉDICO LEGISTA', 'JUEZ', NULL, 'c', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 6', '184433'),
(1603, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TENER ACCESO EN TODO EL DESARROLLO DEL PROCESO A LOS DOCUMENTOS DE ÁMBITO POLICIAL Y A LOS EXPEDIENTES DE ÁMBITO FISCAL Y JUDICIAL PARA INFORMARSE DEL PROCESO, SIN MÁS LIMITACIÓN QUE LA PREVISTA EN LA LEY, ASÍ COMO A OBTENER COPIA SIMPLE DE LAS ACTUACIONES EN CUALQUIER ESTADO O GRADO DEL PROCEDIMIENTO;', 'PERITO DE OFICIO', 'ABOGADO DEFENSOR', 'FISCAL', 'MÉDICO LEGISTA', 'JUEZ', NULL, 'b', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 7', '184434'),
(1604, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'INGRESAR A LOS ESTABLECIMIENTOS PENALES Y DEPENDENCIAS POLICIALES, PREVIA IDENTIFICACIÓN, PARA ENTREVISTARSE CON SU PATROCINADO; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'MÉDICO LEGISTA', 'ABOGADO DEFENSOR', 'JUEZ', NULL, 'd', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 8', '184435'),
(1605, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EXPRESARSE CON AMPLIA LIBERTAD EN EL CURSO DE LA DEFENSA, ORALMENTE Y POR ESCRITO, SIEMPRE QUE NO SE OFENDA EL HONOR DE LAS PERSONAS, YA SEAN NATURALES O JURÍDICAS; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'FISCAL', 'ABOGADO DEFENSOR', 'MÉDICO LEGISTA', 'JUEZ', NULL, 'c', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 9', '184436'),
(1606, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'INTERPONER CUESTIONES PREVIAS, CUESTIONES PREJUDICIALES, EXCEPCIONES, RECURSOS IMPUGNATORIOS Y LOS DEMÁS MEDIOS DE DEFENSA PERMITIDOS POR LA LEY; ES UN DERECHO Y UN DEBER DEL:', 'PERITO DE OFICIO', 'ABOGADO DEFENSOR', 'FISCAL', 'MÉDICO LEGISTA', 'JUEZ', NULL, 'b', 'ABOGADO DEFENSOR', 'ARTÍCULO 84°. NUMERAL 10', '184437'),
(1607, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ, DESPUÉS DE IDENTIFICARLOS ADECUADAMENTE, A QUIÉN, DISPONDRÁ QUE PRESTE JURAMENTO O PROMESA DE DECIR LA VERDAD:', 'EL PROCESADO', 'EL SENTENCIADO', 'EL AGRAVIADO', 'TESTIGO O PERITO', 'EL ACUSADO', NULL, 'd', 'TESTIGO O PERITO', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184438'),
(1608, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO EL IMPUTADO NO OBEDEZCA, PESE A TENER CONOCIMIENTO DE SU EMISIÓN, UNA ORDEN DE DETENCIÓN O PRISIÓN; EL JUEZ, A REQUERIMIENTO DEL FISCAL O DE LAS DEMÁS PARTES, PREVIA CONSTATACIÓN LO DECLARARÁ, COMO:', 'PROCESADO', 'INVESTIGADO', 'CONTUMAZ', 'AUSENTE', 'IMPLICADO', NULL, 'c', 'CONTUMAZ', '(ART: 79) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184439'),
(1609, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO EL IMPUTADO SE AUSENTE, SIN AUTORIZACIÓN DEL FISCAL O DEL JUEZ, DEL LUGAR DE SU RESIDENCIA O DEL ASIGNADO PARA RESIDIR; EL JUEZ, A REQUERIMIENTO DEL FISCAL O DE LAS DEMÁS PARTES, PREVIA CONSTATACIÓN LO DECLARARÁ, COMO:', 'IMPLICADO', 'PROCESADO', 'INVESTIGADO', 'CONTUMAZ', 'IMPUTADO', NULL, 'd', 'CONTUMAZ', '(ART: 79) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184440'),
(1610, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'NO SE SUSPENDE LA INVESTIGACIÓN PREPARATORIA NI LA ETAPA INTERMEDIA RESPECTO DEL CONTUMAZ O AUSENTE, POR LA:', 'AUSENCIA DEL ABOGADO DEFENSOR', 'INASISTENCIA DE LOS TESTIGOS AL PROCESO', 'FALTA DE ELEMENTOS DE PRUEBA OFRECIDAS POR EL FISCAL', 'DECLARACIÓN DE CONTUMACIA O AUSENCIA', 'SITUACIÓN DE SALUD FÍSICA O MENTAL DEL IMPUTADO', NULL, 'd', 'DECLARACIÓN DE CONTUMACIA O AUSENCIA', '(ART: 79) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO I]', '184441'),
(1611, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL TEXTO: EL SERVICIO NACIONAL DE LA DEFENSA DE OFICIO, A CARGO DEL MINISTERIO DE JUSTICIA, PROVEERÁ LA DEFENSA GRATUITA A TODOS AQUELLOS QUE DENTRO DEL PROCESO PENAL, POR SUS ESCASOS RECURSOS NO PUEDAN DESIGNAR UN ABOGADO, SE REFIERE A:', 'UN ABOGADO DE OFICIO', 'UN ABOGADO DEFENSOR', 'QUE NO SE VULNERE LOS DERECHOS DEL IMPUTADO', 'UN PROCESO PENAL JUSTO', 'DERECHO A LA DEFENSA TÉCNICA', NULL, 'e', 'DERECHO A LA DEFENSA TÉCNICA', '(ART: 80) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO II]', '184442'),
(1612, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN EL EXAMEN DE TESTIGOS, QUIÉN CONDUCIRÁ EL EXAMEN AL TESTIGO MENOR DE DIECISÉIS AÑOS DE EDAD:', 'EL FISCAL DE LA FAMILIA', 'EL ABOGADO DEFENSOR', 'EL FISCAL', 'EL JUEZ', 'FISCAL DE INVESTIGACIÓN PREPARATORIA', NULL, 'd', 'EL JUEZ', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184443'),
(1613, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL EXAMEN AL TESTIGO MENOR DE DIECISÉIS AÑOS DE EDAD SERÁ CONDUCIDO POR EL JUEZ EN BASE A LAS PREGUNTAS Y CONTRAINTERROGATORIOS PRESENTADOS POR:', 'EL JUEZ', 'EL FISCAL Y LAS DEMÁS PARTES', 'LA POLICÍA', 'LA FISCAL DE LA FAMILIA', 'EL FISCAL DE INVESTIGACIÓN PREPARATORIA', NULL, 'b', 'EL FISCAL Y LAS DEMÁS PARTES', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184444'),
(1614, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CÓMO SE INICIA EL EXAMEN DE LOS PERITOS:', 'CON SU PRESENTACIÓN, DETALLANDO SU HOJA DE VIDA', 'CON LA EXPOSICIÓN BREVE DEL CONTENIDO Y CONCLUSIONES DEL DICTAMEN PERICIAL', 'CON LA EXPOSICIÓN BREVE DE SU CARRERA', 'CON LA EXPOSICIÓN BREVE DEL CASO', 'CON LA EXPOSICIÓN DEL MÉTODO EMPLEADO', NULL, 'b', 'CON LA EXPOSICIÓN BREVE DEL CONTENIDO Y CONCLUSIONES DEL DICTAMEN PERICIAL', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184445'),
(1615, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI UN TESTIGO O PERITO DECLARA QUE YA NO SE ACUERDA DE UN HECHO, QUÉ PROCEDIMIENTO SE UTILIZA:.', 'SE LE ENTREGARÁ SU DECLARACIÓN O PERITAJE, SEGÚN CORRESPONDA, A FIN DE QUE RECUERDE', 'SE DARÁ POR CONCLUIDA SU PARTICIPACIÓN Y SE DISPONDRÁ SU SALIDA DE LA SALA', 'SE PUEDE LEER LA PARTE CORRESPONDIENTE DEL ACTO SOBRE SU INTERROGATORIO ANTERIOR PARA HACER MEMORIA', 'SE PRESCINDIRÁ SU PARTICIPACIÓN Y SE NOMBRARÁ UN PERITO JUDICIAL', 'SERÁ SUSPENDIDO DEL REGISTRO RESPECTIVO Y NO SE LE TOMARÁ EN CUENTA PARA OTRAS DILIGENCIAS', NULL, 'c', 'SE PUEDE LEER LA PARTE CORRESPONDIENTE DEL ACTO SOBRE SU INTERROGATORIO ANTERIOR PARA', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184446'),
(1616, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'QUIÉNES ESTÁN AUTORIZADOS PARA CONSULTAR DOCUMENTOS, NOTAS ESCRITAS Y PUBLICACIONES DURANTE SU INTERROGATORIO:', 'EL ABOGADO DEFENSOR', 'LOS PERITOS', 'LOS TESTIGOS', 'LOS AGRAVIADOS', 'EL FISCAL', NULL, 'b', 'LOS PERITOS', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184447'),
(1617, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DURANTE EL CONTRAINTERROGATORIO, QUIÉNES PODRÁN CONFRONTAR AL PERITO O TESTIGO CON SUS PROPIOS DICHOS U OTRAS VERSIONES DE LOS HECHOS PRESENTADAS EN EL JUICIO:', 'EL ABOGADO DEFENSOR Y EL ACUSADO', 'EL FISCAL Y EL ABOGADO DEFENSOR', 'LAS PARTES', 'EL ABOGADO DEFENSOR Y EL SENTENCIADO', 'EL O LOS AGRAVIADOS', NULL, 'c', 'LAS PARTES', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184448'),
(1618, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'A SOLICITUD DE QUIÉN, EL JUEZ PODRÁ AUTORIZAR UN NUEVO INTERROGATORIO DE LOS TESTIGOS O PERITOS QUE YA HUBIERAN DECLARADO EN LA AUDIENCIA:', 'EL FISCAL PROVINCIAL', 'DEL FISCAL DE INVESTIGACIÓN PREPARATORIA', 'DEL ABOGADO DEFENSOR', 'DE ALGUNA DE LAS PARTES', 'DEL FISCAL', NULL, 'd', 'DE ALGUNA DE LAS PARTES', '(ART: 378) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184449'),
(1619, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'QUÉ ACCIÓN ADOPTA EL JUEZ, CUANDO EL TESTIGO O PERITO, OPORTUNAMENTE CITADO, NO HAYA COMPARECIDO AL JUICIO ORAL:', 'ORDENARÁ QUE SU JEFE INMEDIATO ADOPTE LAS ACCIONES RESPECTIVAS', 'ORDENARÁ QUE SEA CITADO NUEVAMENTE', 'ORDENARÁ QUE SEA CONDUCIDO COMPULSIVAMENTE', 'ORDENARÁ QUE SEA SANCIONADO', 'ORDENARÁ QUE SEA MULTADO', NULL, 'c', 'ORDENARÁ QUE SEA CONDUCIDO COMPULSIVAMENTE', '(ART: 379) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184450'),
(1620, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'QUÉ SUCEDE CON EL JUICIO, SI EL TESTIGO O PERITO NO PUEDE SER LOCALIZADO PARA SU CONDUCCIÓN COMPULSIVA:', 'SE REANUDARÁ CUANDO ES UBICADO Y CITADO', 'CONTINUARÁ CON PRESCINDENCIA DE ESA PRUEBA', 'CONTINUARÁ CUANDO ES UBICADO Y CONDUCIDO COMPULSIVAMENTE', 'SE SUSPENDERÁ', 'CULMINARÁ CON LA SENTENCIA ÚNICA', NULL, 'b', 'CONTINUARÁ CON PRESCINDENCIA DE ESA PRUEBA', '(ART: 379) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184451'),
(1621, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN QUE CASO, EL JUEZ, DE OFICIO O A SOLICITUD DE PARTE, PUEDE ORDENAR QUE EL ACUSADO NO ESTÉ PRESENTE EN LA AUDIENCIA DURANTE UN INTERROGATORIO.', 'SI ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO DIRÁ LA VERDAD', 'SI ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO NO DIRÁ LA VERDAD EN SU PRESENCIA', 'NO ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO DIRÁ LA VERDAD', 'SI ES DE TEMER QUE EL AGRAVIADO DIRÁ LA VERDAD', 'SI ES DE PRESUMIR QUE OTRO AGRAVIADO DIRÁ LA VERDAD', NULL, 'b', 'SI ES DE TEMER QUE OTRO PROCESADO, UN TESTIGO O UN PERITO NO DIRÁ LA VERDAD EN SU PRESENCIA', '(ART: 380) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184452'),
(1622, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LOS TESTIGOS Y PERITOS QUE NO PUEDAN CONCURRIR A LA SALA DE AUDIENCIAS POR UN IMPEDIMENTO JUSTIFICADO, DONDE SERÁN EXAMINADOS POR EL JUEZ:', 'YA NO LOS EXAMINARÁ', 'EN EL LUGAR DONDE TRABAJAN', 'EN EL LUGAR DONDE SE HALLEN', 'EN EL LUGAR DONDE SEÑALE EL JUEZ', 'EN EL LUGAR DONDE LOS SOLICITAN', NULL, 'c', 'EN EL LUGAR DONDE SE HALLEN', '(ART: 381) [LIBRO TERCERO]  [SECCION III]  [TITULO IV]', '184453'),
