(1725, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO CORRESPONDE LA PREVIA AUTORIZACIÓN DEL CONGRESO O DE OTRO ÓRGANO PÚBLICO PARA EL EJERCICIO DE LA ACCIÓN PENAL, SE OBSERVARÁ EL PROCEDIMIENTO PREVISTO POR LA LEY PARA DEJAR EXPEDITA LA:', 'CONTINUACIÓN DEL PROCESO', 'ETAPA DE INVESTIGACIÓN PRELIMINAR', 'DEFENSA LEGAL', 'MOTIVACIÓN QUE DIO ORIGEN AL PROCESO', 'PROMOCIÓN DE LA ACCIÓN PENAL', NULL, 'e', 'PROMOCIÓN DE LA ACCIÓN PENAL', '(ART: 1) [LIBRO PRIMERO]  [SECCION I]', '184561'),
(1726, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿EN QUÉ CASO EL MINISTERIO PÚBLICO, DE OFICIO O A PEDIDO DEL IMPUTADO Y CON SU CONSENTIMIENTO, PODRÁ ABSTENERSE DE EJERCITAR LA ACCIÓN PENAL?', 'CUANDO EL AGENTE HAYA SIDO AFECTADO GRAVEMENTE POR LAS CONSECUENCIAS DE SU DELITO', 'CUANDO EL AGENTE SEA MENOR DE EDAD', 'CUANDO EL AGENTE PADEZCA DE ALGUNA ANOMALÍA PSÍQUICA', 'CUANDO EL AGENTE SEA INIMPUTABLE', 'CUANDO SE TRATE DE LOS CÓMPLICES', NULL, 'a', 'CUANDO EL AGENTE HAYA SIDO AFECTADO GRAVEMENTE POR LAS CONSECUENCIAS DE SU DELITO', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184562'),
(1727, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿EN QUÉ CASO EL MINISTERIO PÚBLICO, DE OFICIO O A PEDIDO DEL IMPUTADO Y CON SU CONSENTIMIENTO, PODRÁ ABSTENERSE DE EJERCITAR LA ACCIÓN PENAL?', 'CUANDO EL AGENTE SEA INIMPUTABLE', 'CUANDO SE TRATE DE DELITOS QUE NO AFECTEN GRAVEMENTE EL INTERÉS PÚBLICO', 'CUANDO SE TRATE DE LOS CÓMPLICES', 'CUANDO EL AGENTE SEA MENOR DE EDAD', 'CUANDO EL AGENTE PADEZCA DE ALGUNA ANOMALÍA PSÍQUICA', NULL, 'b', 'CUANDO SE TRATE DE DELITOS QUE NO AFECTEN GRAVEMENTE EL INTERÉS PÚBLICO', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184563'),
(1728, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿EN QUÉ CASO EL MINISTERIO PÚBLICO, DE OFICIO O A PEDIDO DEL IMPUTADO Y CON SU CONSENTIMIENTO, PODRÁ ABSTENERSE DE EJERCITAR LA ACCIÓN PENAL?', 'CUANDO EL AGENTE SEA MENOR DE EDAD', 'CUANDO EL AGENTE PADEZCA DE ALGUNA ANOMALÍA PSÍQUICA', 'CUANDO SE ADVIERTA QUE NO EXISTE NINGÚN INTERÉS PÚBLICO GRAVEMENTE COMPROMETIDO EN SU PERSECUCIÓN', 'CUANDO SE TRATE DE LOS CÓMPLICES', 'CUANDO EL AGENTE SEA INIMPUTABLE', NULL, 'c', 'CUANDO SE ADVIERTA QUE NO EXISTE NINGÚN INTERÉS PÚBLICO GRAVEMENTE COMPROMETIDO EN SU', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184564'),
(1729, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ PODRÁ DETERMINAR EL FISCAL, EN CASO DE INASISTENCIA DEL AGRAVIADO?', 'LA CONTINUACIÓN DEL PROCESO', 'LA PRESENCIA DE SU ABOGADO DEFENSOR', 'LA REPROGRAMACIÓN DE LA DILIGENCIA', 'EL MONTO DE LA REPARACIÓN CIVIL QUE CORRESPONDA', 'LA SUSPENSIÓN DE LA INVESTIGACIÓN PREPARATORIA', NULL, 'd', 'EL MONTO DE LA REPARACIÓN CIVIL QUE CORRESPONDA', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184565'),
(1730, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI NO SE LLEGA A UN ACUERDO SOBRE EL PLAZO PARA EL PAGO DE LA REPARACIÓN CIVIL, EL FISCAL LO FIJARÁ SIN QUE ÉSTE EXCEDA DE:', 'DOS MESES', 'TRES MESES', 'CUATRO MESES', 'CINCO MESES', 'NUEVE MESES', NULL, 'e', 'NUEVE MESES', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184566'),
(1731, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'NO SERÁ NECESARIA LA DILIGENCIA DE DETERMINACIÓN DE LA REPARACIÓN CIVIL, SI EL IMPUTADO Y LA VÍCTIMA LLEGAN A UN ACUERDO Y ÉSTE CONSTA EN:', 'INSTRUMENTO PÚBLICO O DOCUMENTO PRIVADO LEGALIZADO NOTARIALMENTE', 'EL ACTA CORRESPONDIENTE REFRENDADO POR LAS PARTES', 'EL INFORME EMITIDO POR EL FISCAL', 'EL DOCUMENTO DE ACCIÓN NECESARIO PARA ESTE FIN', 'EL MISMO ACTO DE PAGO DE REPARACIÓN CIVIL', NULL, 'a', 'INSTRUMENTO PÚBLICO O DOCUMENTO PRIVADO LEGALIZADO NOTARIALMENTE', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184567'),
(1732, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'HABIENDO LLEGADO A UN ACUERDO EL IMPUTADO Y LA VÍCTIMA, Y SATISFECHA LA REPARACIÓN CIVIL, EL FISCAL EXPEDIRÁ:', 'UNA CONSTANCIA DE TAL ACTO A CADA UNO DE ELLOS', 'UNA DISPOSICIÓN DE ABSTENCIÓN', 'EL ACTA CORRESPONDIENTE, INDICANDO EL CUMPLIMIENTO DE TAL DILIGENCIA', 'EL INFORME AL RESPECTO, HACIENDO MENCIÓN DE LO ACTUADO', 'LAS RESPECTIVAS NOTIFICACIONES A LAS PARTES', NULL, 'b', 'UNA DISPOSICIÓN DE ABSTENCIÓN', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184568'),
(1733, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DE EXISTIR UN PLAZO PARA EL PAGO DE LA REPARACIÓN CIVIL, SE SUSPENDERÁN LOS EFECTOS DE DICHA DECISIÓN HASTA:', 'QUE EL IMPUTADO CUENTE CON LOS MEDIOS ECONÓMICOS', 'QUE EL IMPUTADO Y LA VÍCTIMA SE PONGAN DE ACUERDO', 'SU EFECTIVO CUMPLIMIENTO', 'LA INVESTIGACIÓN PREPARATORIA', 'LA ETAPA DE JUZGAMIENTO', NULL, 'c', 'SU EFECTIVO CUMPLIMIENTO', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184569'),
(1734, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DE NO PRODUCIRSE EL PAGO DE LA REPARACIÓN CIVIL, SE DICTARÁ DISPOSICIÓN PARA LA PROMOCIÓN DE LA ACCIÓN PENAL, LA CUAL:', 'SERÁ APELABLE', 'PODRÁ SER CUESTIONADA POR EL ABOGADO DEFENSOR', 'SERÁ INAPELABLE', 'NO SERÁ IMPUGNABLE', 'CONSTARÁ EN ACTAS', NULL, 'd', 'NO SERÁ IMPUGNABLE', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184570'),
(1735, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SEGÚN EL PRINCIPIO DE OPORTUNIDAD, ¿QUÉ PROPONDRÁ EL FISCAL DE OFICIO O A PEDIDO DEL IMPUTADO O DE LA VÍCTIMA?', 'UN PLAZO PERENTORIO', 'UN PAGO JUSTO QUE BENEFICIE A LA VÍCTIMA', 'QUE NO SE AFECTE CONSIDERABLEMENTE LA ECONOMÍA DEL IMPUTADO', 'UN ACUERDO REPARATORIO', 'EL INCREMENTO DEL PAGO DE LA REPARACIÓN CIVIL', NULL, 'd', 'UN ACUERDO REPARATORIO', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184571'),
(1736, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿QUÉ ACCIÓN ADOPTARÁ EL FISCAL, SI EL IMPUTADO NO CONCURRE A LA SEGUNDA CITACIÓN O SE IGNORA SU DOMICILIO O PARADERO?', 'LO DECLARARÁ REO AUSENTE', 'CONTINUARÁ LA INVESTIGACIÓN PREPARATORIA', 'DARÁ CUENTA DEL HECHO AL JUEZ', 'PROMOVERÁ LA ACCIÓN PENAL', 'LO NOTIFICARÁ POR TERCERA VEZ', NULL, 'd', 'PROMOVERÁ LA ACCIÓN PENAL', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184572'),
(1737, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI LA ACCIÓN PENAL HUBIERA SIDO PROMOVIDA, PREVIA AUDIENCIA, A PETICIÓN DEL MINISTERIO PÚBLICO, CON LA APROBACIÓN DEL IMPUTADO Y CITACIÓN DEL AGRAVIADO, EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA PODRÁ:.', 'PROSEGUIR CON EL PROCESO', 'NOTIFICAR A LAS PARTES', 'DICTAR AUTO DE SOBRESEIMIENTO', 'PREPARAR EL JUICIO ORAL', 'SUSPENDER EL PROCESO', NULL, 'c', 'DICTAR AUTO DE SOBRESEIMIENTO', '(ART: 2) [LIBRO PRIMERO]  [SECCION I]', '184573'),
(1738, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL MINISTERIO PÚBLICO COMUNICARÁ AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA SU DECISIÓN FORMAL DE CONTINUAR CON LAS:', 'DILIGENCIAS PRELIMINARES', 'ACCIONES TENDIENTES AL ESCLARECIMIENTO DEL HECHO', 'RECOPILACIONES DE ELEMENTOS PROBATORIOS', 'MEDIDAS PERTINENTES PARA ESTABLECER RESPONSABILIDAD PENAL', 'INVESTIGACIONES PREPARATORIAS', NULL, 'e', 'INVESTIGACIONES PREPARATORIAS', '(ART: 3) [LIBRO PRIMERO]  [SECCION I]', '184574'),
