(1740, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN LA CUESTIÓN PREVIA, LA INVESTIGACIÓN PREPARATORIA PODRÁ REINICIARSE LUEGO QUE EL REQUISITO OMITIDO SEA:', 'SATISFECHO', 'SUBSANADO', 'CORREGIDO', 'INCORPORADO', 'VALORADO', NULL, 'a', 'SATISFECHO', '(ART: 4) [LIBRO PRIMERO]  [SECCION I]', '184576'),
(1741, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CUESTIÓN PREJUDICIAL PROCEDE CUANDO EL FISCAL DECIDE CONTINUAR CON LA INVESTIGACIÓN PREPARATORIA, PESE A QUE FUERE NECESARIA EN VÍA EXTRA-PENAL UNA DECLARACIÓN VINCULADA AL CARÁCTER DELICTUOSO DEL:', 'HECHO INCRIMINADO', 'PROCESO PENAL', 'IMPUTADO', 'PROCESADO', 'AUTOR', NULL, 'a', 'HECHO INCRIMINADO', '(ART: 5) [LIBRO PRIMERO]  [SECCION I]', '184577'),
(1742, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI SE DECLARA FUNDADA, LA INVESTIGACIÓN PREPARATORIA SE SUSPENDE HASTA QUE EN LA OTRA VÍA RECAIGA:', 'LO DESCRITO EN EL DICTAMEN PERICIAL', 'RESOLUCIÓN FIRME', 'DICTAMEN OPORTUNO', 'DISPOSICIÓN PENAL', 'AUTO DE APERTURA', NULL, 'b', 'RESOLUCIÓN FIRME', '(ART: 5) [LIBRO PRIMERO]  [SECCION I]', '184578'),
(1743, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN CASO DE QUE EL PROCESO EXTRA-PENAL NO HAYA SIDO PROMOVIDO POR LA PERSONA LEGITIMADA PARA HACERLO, SE LE NOTIFICARÁ Y REQUERIRÁ PARA QUE LO HAGA EN EL PLAZO DE:', 'TRES DÍAS.', 'SIETE DÍAS.', 'TREINTA DÍAS.', 'OCHO DÍAS.', 'QUINCE DÍAS.', NULL, 'c', 'TREINTA DÍAS.', '(ART: 5) [LIBRO PRIMERO]  [SECCION I]', '184579'),
(1744, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SEGÚN LA CUESTIÓN PREJUDICIAL, EL FISCAL ESTÁ AUTORIZADO PARA INTERVENIR Y CONTINUAR EL PROCESO HASTA SU TERMINACIÓN, ASÍ COMO SUSTITUIR AL TITULAR DE LA ACCIÓN SI ÉSTE:', 'NO SE PRESENTA AL INICIO DEL PROCESO', 'NO LO PROSIGUE', 'NO SE INTERESA EN SU CASO', 'ENFERMARA Y LE FUERA IMPOSIBLE PRESENTARSE AL PROCESO', 'VIAJA AL EXTRANJERO', NULL, 'b', 'NO LO PROSIGUE', '(ART: 5) [LIBRO PRIMERO]  [SECCION I]', '184580'),
(1745, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿DE QUÉ DEPENDE LA PROSECUCIÓN O EL SOBRESEIMIENTO DEFINITIVO DE LA CAUSA?', 'DE LAS INVESTIGACIONES PREPARATORIAS', 'DE LOS ELEMENTOS PROBATORIOS', 'DEL DICTAMEN PERICIAL', 'DE LO RESUELTO EN LA VÍA EXTRA-PENAL', 'DE LAS DECLARACIONES DE LAS PARTES', NULL, 'd', 'DE LO RESUELTO EN LA VÍA EXTRA-PENAL', '(ART: 5) [LIBRO PRIMERO]  [SECCION I]', '184581'),
(1746, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UNA DE LAS EXCEPCIONES QUE PUEDE DEDUCIRSE, ES LA SIGUIENTE:', 'NATURALEZA DEL PROCESO, CUANDO SE HA DADO AL PROCESO UNA CONNOTACIÓN SIMILAR A LA PREVISTA EN LA', 'NATURALEZA DE JUICIO, CUANDO SE HA DADO AL PROCESO UNA PERSPECTIVA DISTINTA A LA PREVISTA EN EL MISMO', 'NATURALEZA DE JUICIO, CUANDO SE HA DADO AL PROCESO UNA VALORACIÓN ACORDE A LA PREVISTA EN LA', 'NATURALEZA DE JUICIO, CUANDO SE HA DADO AL PROCESO UNA SUSTANCIACIÓN DISTINTA A LA PREVISTA EN LA LEY', 'NATURALEZA DE OPINIÓN, CUANDO SE HA DADO AL PROCESO UNA RELEVANCIA DISTINTA A LA PREVISTA EN LA NORMA', NULL, 'd', 'NATURALEZA DE JUICIO, CUANDO SE HA DADO AL PROCESO UNA SUSTANCIACIÓN DISTINTA A LA PREVISTA EN', '(ART: 6) [LIBRO PRIMERO]  [SECCION I]', '184582'),
(1747, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UNA DE LAS EXCEPCIONES QUE PUEDE DEDUCIRSE, ES LA SIGUIENTE:', 'PROCEDENCIA DE ACCIÓN, CUANDO EL HECHO NO CONSTITUYE DELITO O NO ES JUSTICIABLE PENALMENTE', 'PROCEDENCIA DE ACCIÓN, CUANDO EL HECHO CONSTITUYE DELITO O ES JUSTICIABLE PENALMENTE', 'IMPROCEDENCIA DE ACCIÓN, CUANDO EL HECHO NO CONSTITUYE FALTA O NO ES PUNIBLE', 'IMPROCEDENCIA DE LA INVESTIGACIÓN PREPARATORIA, CUANDO EL HECHO NO CONSTITUYE DELITO O NO ES', 'IMPROCEDENCIA DE ACCIÓN, CUANDO EL HECHO NO CONSTITUYE DELITO O NO ES JUSTICIABLE PENALMENTE', NULL, 'e', 'IMPROCEDENCIA DE ACCIÓN, CUANDO EL HECHO NO CONSTITUYE DELITO O NO ES JUSTICIABLE PENALMENTE', '(ART: 6) [LIBRO PRIMERO]  [SECCION I]', '184583'),
(1748, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UNA DE LAS EXCEPCIONES QUE PUEDE DEDUCIRSE, ES LA SIGUIENTE:', 'COSA JUZGADA, CUANDO EL HECHO PUNIBLE HA SIDO OBJETO DE UNA RESOLUCIÓN FIRME', 'CASO CERRADO, CUANDO EL HECHO INVESTIGADO HA SIDO OBJETO DE UNA RESOLUCIÓN FIRME', 'COSA JUZGADA, CUANDO EL HECHO PUNIBLE HA SIDO OBJETO DE UNA RESOLUCIÓN SUSPENDIDA', 'COSA PROCESADA, CUANDO EL HECHO PUNIBLE HA SIDO OBJETO DE UNA RESOLUCIÓN DE SOBRESEIMIENTO', 'COSA PROCESADA, CUANDO EL HECHO PUNIBLE HA SIDO OBJETADO CON UNA RESOLUCIÓN FIRME', NULL, 'a', 'COSA JUZGADA, CUANDO EL HECHO PUNIBLE HA SIDO OBJETO DE UNA RESOLUCIÓN FIRME', '(ART: 6) [LIBRO PRIMERO]  [SECCION I]', '184584'),
(1749, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UNA DE LAS EXCEPCIONES QUE PUEDE DEDUCIRSE, ES LA SIGUIENTE:', 'PERDÓN', 'AMNISTÍA', 'INDULTO', 'GRACIA', 'CONDONACIÓN', NULL, 'b', 'AMNISTÍA', '(ART: 6) [LIBRO PRIMERO]  [SECCION I]', '184585'),
(1750, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UNA DE LAS EXCEPCIONES QUE PUEDE DEDUCIRSE, ES LA SIGUIENTE:', 'CONDONACIÓN', 'GRACIA', 'PRESCRIPCIÓN', 'PERDÓN', 'INDULTO', NULL, 'c', 'PRESCRIPCIÓN', '(ART: 6) [LIBRO PRIMERO]  [SECCION I]', '184586'),
(1751, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN CASO QUE SE DECLARE FUNDADA LA EXCEPCIÓN DE NATURALEZA DE JUICIO, EL PROCESO SE ADECUARÁ AL TRÁMITE RECONOCIDO EN EL:', 'AUTO APERTORIO', 'PROCESO MISMO', 'DESARROLLO DEL JUICIO', 'AUTO QUE LA RESUELVA', 'AUTO DE SOBRESEIMIENTO', NULL, 'd', 'AUTO QUE LA RESUELVA', '(ART: 6) [LIBRO PRIMERO]  [SECCION I]', '184587'),
(1752, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CUESTIÓN PREVIA, CUESTIÓN PREJUDICIAL Y LAS EXCEPCIONES SE PLANTEAN UNA VEZ QUE EL FISCAL HAYA DECIDIDO CONTINUAR CON LAS INVESTIGACIONES PREPARATORIAS O:', 'UNA VEZ QUE LAS PARTES HAYAN ACORDADO LO MÁS CONVENIENTE', 'AL EMPEZAR LAS DILIGENCIAS DE INVESTIGACIÓN', 'UNA VEZ SE HAGA DE CONOCIMIENTO DEL HECHO AL JUEZ', 'AL CONTESTAR LA QUERELLA ANTE EL JUEZ', 'CUANDO LAS PARTES LO SOLICITEN', NULL, 'd', 'AL CONTESTAR LA QUERELLA ANTE EL JUEZ', '(ART: 7) [LIBRO PRIMERO]  [SECCION I]', '184588'),
(1753, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CUESTIÓN PREVIA Y LAS EXCEPCIONES TAMBIÉN SE PUEDEN DEDUCIR DURANTE LA:', 'FASE PRELIMINAR', 'INVESTIGACIÓN PREPARATORIA', 'ACTIVIDAD PROCESAL', 'ETAPA DEL JUICIO', 'ETAPA INTERMEDIA', NULL, 'e', 'ETAPA INTERMEDIA', '(ART: 7) [LIBRO PRIMERO]  [SECCION I]', '184589'),
(1754, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LOS MEDIOS DE DEFENSA REFERIDOS EN ESTE DISPOSITIVO, PUEDEN SER DECLARADOS DE:', 'OFICIO', 'PARTE', 'POR EL FISCAL', 'POR EL JUEZ', 'A SOLICITUD DEL ABOGADO DEFENSOR', NULL, 'a', 'OFICIO', '(ART: 7) [LIBRO PRIMERO]  [SECCION I]', '184590'),
(1755, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CUESTIÓN PREVIA, CUESTIÓN PREJUDICIAL Y LAS EXCEPCIONES QUE SE DEDUZCAN DURANTE LA INVESTIGACIÓN PREPARATORIA SERÁN PLANTEADAS MEDIANTE:', 'EL ABOGADO DEFENSOR', 'EL JUICIO ORAL', 'SOLICITUD DEBIDAMENTE FUNDAMENTADA', 'SOLICITUD DE LAS PARTES EN CONJUNTO', 'EL DOCUMENTO QUE CORRESPONDA', NULL, 'c', 'SOLICITUD DEBIDAMENTE FUNDAMENTADA', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184591'),
(1756, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA, UNA VEZ QUE HA RECABADO INFORMACIÓN DEL FISCAL ACERCA DE LOS SUJETOS PROCESALES APERSONADOS EN LA CAUSA Y LUEGO DE NOTIFICARLES LA ADMISIÓN DEL MEDIO DE DEFENSA DEDUCIDO, DENTRO DEL TERCER DÍA SEÑALARÁ FECHA PARA:', 'EL INICIO DEL PROCESO PENAL', 'LA RECEPCIÓN DE DECLARACIONES', 'EL JUICIO ORAL', 'LA REALIZACIÓN DE LA AUDIENCIA', 'INICIAR LA ETAPA PREPARATORIA', NULL, 'd', 'LA REALIZACIÓN DE LA AUDIENCIA', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184592'),
(1757, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL FISCAL ASISTIRÁ OBLIGATORIAMENTE Y EXHIBIRÁ EL EXPEDIENTE FISCAL PARA SU EXAMEN INMEDIATO POR EL:', 'ABOGADO DEFENSOR', 'JUEZ PRELIMINAR', 'JUEZ DEL JUICIO ORAL', 'JUEZ EN ESE ACTO', 'PERITO RESPECTIVO', NULL, 'd', 'JUEZ EN ESE ACTO', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184593'),
(1758, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'INSTALADA LA AUDIENCIA, EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA ESCUCHARÁ POR SU ORDEN, AL ABOGADO DEFENSOR QUE PROPUSO EL:', 'EXAMEN PERICIAL', 'ALEGATO DE DEFENSA', 'IMPULSO DEL PROCESO', 'RECURSO IMPUGNATORIO', 'MEDIO DE DEFENSA', NULL, 'e', 'MEDIO DE DEFENSA', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184594'),
(1759, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN EL TURNO QUE LES CORRESPONDE, LOS PARTICIPANTES HARÁN MENCIÓN A LOS ELEMENTOS DE CONVICCIÓN QUE CONSTEN EN AUTOS O QUE HAN ACOMPAÑADO EN SEDE JUDICIAL. SI ASISTE EL IMPUTADO TIENE DERECHO A INTERVENIR EN:', 'ÚLTIMO TÉRMINO', 'CUANTO LO DISPONGA EL JUEZ', 'PRIMER TÉRMINO', 'CUANTO LO DISPONGA EL FISCAL', 'COMPAÑÍA DE SU ABOGADO DEFENSOR', NULL, 'a', 'ÚLTIMO TÉRMINO', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184595'),
(1760, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA RESOLVERÁ INMEDIATAMENTE O, EN TODO CASO, EN EL PLAZO DE DOS DÍAS LUEGO DE:', 'CELEBRADA LA VISTA', 'INICIADO EL PROCESO PENAL', 'VISTA LA MOTIVACIÓN DE LA CAUSA', 'ESTIMAR LO MÁS CONVENIENTE', 'TOMAR CONOCIMIENTO DE LOS DICTÁMENES PERICIALES', NULL, 'a', 'CELEBRADA LA VISTA', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184596'),
(1761, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ, EXCEPCIONALMENTE, Y HASTA POR VEINTICUATRO HORAS, PODRÁ RETENER EL EXPEDIENTE FISCAL PARA RESOLVER EL MEDIO DE DEFENSA DEDUCIDO, QUE SE HARÁ MEDIANTE:', 'PETICIÓN DEL IMPUTADO', 'AUTO DEBIDAMENTE FUNDAMENTADO', 'PETICIÓN DE CUALQUIERA DE LAS PARTES', 'AUTO APERTORIO DEL CASO', 'SOLICITUD FUNDADA DEL ABOGADO DEFENSOR', NULL, 'b', 'AUTO DEBIDAMENTE FUNDAMENTADO', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184597'),
(1762, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA CUESTIÓN PREVIA, CUESTIÓN PREJUDICIAL Y LAS EXCEPCIONES DEDUCIDAS A FAVOR DE UNO DE LOS IMPUTADOS BENEFICIA A LOS DEMÁS, SIEMPRE QUE SE ENCUENTREN EN:', 'LA MISMA CAUSA PROCESAL', 'CONDICIONES DE SER PENADOS', 'EL MISMO RECINTO ESTABLECIDO COMO SEDE JUDICIAL', 'IGUAL SITUACIÓN JURÍDICA', 'DIFERENTES CIRCUNSTANCIAS DE PARTICIPACIÓN DELICTIVA', NULL, 'd', 'IGUAL SITUACIÓN JURÍDICA', '(ART: 8) [LIBRO PRIMERO]  [SECCION I]', '184598'),
(1763, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CONTRA EL AUTO EXPEDIDO POR EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA PROCEDE:', 'RECURSO IMPUGNATORIO', 'RECLAMO FUNDAMENTADO', 'RECURSO DE CASACIÓN', 'RECURSO DE IMPROCEDENCIA', 'RECURSO DE APELACIÓN', NULL, 'e', 'RECURSO DE APELACIÓN', '(ART: 9) [LIBRO PRIMERO]  [SECCION I]', '184599'),
(1764, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CONCEDIDO EL RECURSO DE APELACIÓN, EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA DISPONDRÁ, ANTES DE LA ELEVACIÓN DEL RECURSO A LA SALA PENAL SUPERIOR, QUE DENTRO DEL QUINTO DÍA SE AGREGUEN A LOS ACTUADOS FORMADOS EN SEDE JUDICIAL LAS:', 'COPIAS CERTIFICADAS PERTINENTES DEL EXPEDIENTE FISCAL', 'SOLICITUDES MOTIVANDO LOS RECLAMOS', 'PERICIAS REFERENTE AL CASO', 'DILIGENCIAS EFECTUADAS EN LA INVESTIGACIÓN PREPARATORIA', 'EL ORIGINAL DEL LIBRILLO FORMADO EN SEDE JUDICIAL', NULL, 'a', 'COPIAS CERTIFICADAS PERTINENTES DEL EXPEDIENTE FISCAL', '(ART: 9) [LIBRO PRIMERO]  [SECCION I]', '184600'),
(1765, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI TRANSCURRE EL PLAZO SIN QUE SE HAYA AGREGADO LAS COPIAS CORRESPONDIENTES, EL JUEZ INMEDIATAMENTE ELEVARÁ LOS ACTUADOS A LA:', 'SALA PENAL SUPREMA', 'SALA PENAL SUPERIOR', 'FISCALÍA DE LA NACIÓN', 'JUDICATURA CORRESPONDIENTE', 'MESA DE PARTES DEL PODER JUDICIAL', NULL, 'b', 'SALA PENAL SUPERIOR', '(ART: 9) [LIBRO PRIMERO]  [SECCION I]', '184601'),
(1766, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'CUANDO EN LA SUSTANCIACIÓN DE UN PROCESO EXTRA-PENAL APAREZCAN INDICIOS DE LA COMISIÓN DE UN DELITO DE PERSECUCIÓN PÚBLICA EL JUEZ DE OFICIO O A PEDIDO DE PARTE, COMUNICARÁ AL MINISTERIO PÚBLICO PARA LOS:', 'ACTOS Y MEDIOS DE DEFENSA', 'PREPARATIVOS DE LA INVESTIGACIÓN FINAL', 'FINES CONSIGUIENTES', 'EXÁMENES Y DICTÁMENES JUDICIALES', 'ALEGATOS DEL ABOGADO DEFENSOR', NULL, 'c', 'FINES CONSIGUIENTES', '(ART: 10) [LIBRO PRIMERO]  [SECCION I]', '184602'),
(1767, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI EL FISCAL LUEGO DE LAS PRIMERAS DILIGENCIAS DECIDE CONTINUAR CON LA INVESTIGACIÓN PREPARATORIA LO COMUNICARÁ AL JUEZ EXTRA PENAL, QUIEN:', 'IMPULSARÁ EL PROCESO', 'FINALIZARÁ EL PROCESO', 'EJECUTARÁ EL PROCESO', 'SUSPENDERÁ EL PROCESO', 'CORTARÁ EL PROCESO', NULL, 'd', 'SUSPENDERÁ EL PROCESO', '(ART: 10) [LIBRO PRIMERO]  [SECCION I]', '184603'),
(1768, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL EJERCICIO DE LA ACCIÓN CIVIL DERIVADA DEL HECHO PUNIBLE CORRESPONDE AL:', 'PODER JUDICIAL', 'JUEZ DE LA INVESTIGACIÓN PREPARATORIA', 'MINISTERIO PÚBLICO', 'JUEZ DE LA ETAPA INTERMEDIA', 'JUEZ DE LA CAUSA', NULL, 'c', 'MINISTERIO PÚBLICO', '(ART: 11) [LIBRO PRIMERO]  [SECCION II]', '184604'),
(1769, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL PERJUDICADO POR EL DELITO PODRÁ EJERCER LA ACCIÓN CIVIL EN EL PROCESO PENAL O ANTE EL:', 'FISCAL DE LA INVESTIGACIÓN PREPARATORIA', 'JUEZ DE LA FASE PRELIMINAR', 'ÓRGANO JURISDICCIONAL EN LO PENAL', 'ORDEN JURISDICCIONAL CIVIL', 'JUEZ DE LA ETAPA INTERMEDIA', NULL, 'd', 'ORDEN JURISDICCIONAL CIVIL', '(ART: 12) [LIBRO PRIMERO]  [SECCION II]', '184605'),
(1770, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI LA PERSECUCIÓN PENAL NO PUDIESE PROSEGUIR, YA SEA QUE SE DISPONGA LA RESERVA DEL PROCESO O SE SUSPENDA POR ALGUNA CONSIDERACIÓN LEGAL, LA ACCIÓN CIVIL DERIVADA DEL HECHO PUNIBLE PODRÁ SER EJERCIDA ANTE EL:', 'JUEZ DE LA ETAPA INTERMEDIA', 'ÓRGANO JURISDICCIONAL EN LO PENAL', 'JUEZ DE LA FASE PRELIMINAR', 'FISCAL DE LA INVESTIGACIÓN PREPARATORIA', 'ORDEN JURISDICCIONAL CIVIL', NULL, 'e', 'ORDEN JURISDICCIONAL CIVIL', '(ART: 12) [LIBRO PRIMERO]  [SECCION II]', '184606'),
(1771, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA SENTENCIA ABSOLUTORIA O EL AUTO DE SOBRESEIMIENTO NO IMPEDIRÁ AL ÓRGANO JURISDICCIONAL PRONUNCIARSE SOBRE LA:', 'ACCIÓN CIVIL DERIVADA DEL HECHO PUNIBLE', 'RESOLUCIÓN FISCAL', 'RESOLUCIÓN JUDICIAL', 'MOTIVACIÓN DEL HECHO PUNIBLE', 'ACCIÓN PENAL QUE SE DEBERÁ EMPLEAR', NULL, 'a', 'ACCIÓN CIVIL DERIVADA DEL HECHO PUNIBLE', '(ART: 12) [LIBRO PRIMERO]  [SECCION II]', '184607'),
(1772, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'HASTA CUÁNDO, EL ACTOR CIVIL PODRÁ DESISTIRSE DE SU PRETENSIÓN DE REPARACIÓN CIVIL:', 'DESPUÉS DEL INICIO DE LA ETAPA INTERMEDIA DEL PROCESO', 'DESPUÉS DEL INICIO DE LAS INVESTIGACIONES PRELIMINARES', 'DESPUÉS QUE SE HA HECHO EFECTIVO EL PAGO DE REPARACIÓN CIVIL', 'ANTES DEL INICIO DE LA ETAPA INTERMEDIA DEL PROCESO', 'CUANDO HAYAN ACORDADO LAS PARTES', NULL, 'd', 'ANTES DEL INICIO DE LA ETAPA INTERMEDIA DEL PROCESO', '(ART: 13) [LIBRO PRIMERO]  [SECCION II]', '184608'),
(1773, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DERECHO A LA DEFENSA TÉCNICA.- EL SERVICIO NACIONAL DE LA DEFENSA DE OFICIO, A CARGO DEL MINISTERIO DE JUSTICIA, PROVEERÁ:', 'LA DEFENSA POR UN ABOGADO DE UN ESTUDIO JURÍDICO', 'LA INDEFENSIÓN', 'LA DEFENSA GRATUITA', 'LA DEFENSA SOLVENTADA', 'LA DEFENSA DE PARTE', NULL, 'c', 'LA DEFENSA GRATUITA', '(ART: 80) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO II]', '184609'),
(1774, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL DESISTIMIENTO DE SU PRETENSIÓN DE REPARACIÓN CIVIL, GENERA LA OBLIGACIÓN AL ACTOR CIVIL DEL:', 'PAGO DE COSTOS', 'PAGO DE COSTAS', 'ARANCEL ADUANERO', 'PAGO DE DERECHO DE TRÁMITE', 'IMPUESTO SELECTIVA', NULL, 'b', 'PAGO DE COSTAS', '(ART: 13) [LIBRO PRIMERO]  [SECCION II]', '184610'),
(1775, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA ACCIÓN CIVIL DERIVADA DEL HECHO PUNIBLE PODRÁ SER OBJETO DE:', 'CASACIÓN', 'ARREGLO', 'AMONESTACIÓN', 'TRANSACCIÓN', 'PRESCRIPCIÓN', NULL, 'd', 'TRANSACCIÓN', '(ART: 14) [LIBRO PRIMERO]  [SECCION II]', '184611'),
(1776, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'UNA VEZ QUE LA TRANSACCIÓN SE FORMALICE ANTE EL JUEZ DE LA INVESTIGACIÓN PREPARATORIA, RESPECTO DE LA CUAL NO SE PERMITE OPOSICIÓN DEL MINISTERIO PÚBLICO, EL FISCAL SE ABSTENDRÁ DE:', 'EMITIR RESOLUCIÓN AL RESPECTO', 'FORMALIZAR EL PAGO DE REPARACIÓN CIVIL', 'SEGUIR ACTUANDO EN REFERENCIA AL PAGO', 'COMUNICAR AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA', 'SOLICITAR REPARACIÓN CIVIL EN SU ACUSACIÓN', NULL, 'e', 'SOLICITAR REPARACIÓN CIVIL EN SU ACUSACIÓN', '(ART: 14) [LIBRO PRIMERO]  [SECCION II]', '184612'),
(1777, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DEFENSA CONJUNTA.-SI CONCURREN VARIOS ABOGADOS ASOCIADOS A LAS DILIGENCIAS:', 'EL MÁS CARACTERIZADO EJERCERÁ LA DEFENSA', 'TODOS EJERCERÁN LA DEFENSA', 'UNO SOLO EJERCERÁ LA DEFENSA', 'EL MÁS ANTIGUO EJERCERÁ LA DEFENSA', 'LA DEFENSA LO EJERCERÁ EL ABOGADO QUE EL JUEZ DESIGNE', NULL, 'c', 'UNO SOLO EJERCERÁ LA DEFENSA', '(ART: 82) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO II]', '184613'),
(1778, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL MINISTERIO PÚBLICO O EL ACTOR CIVIL, INTRODUCIRÁN MOTIVADAMENTE LA PRETENSIÓN ANULATORIA CORRESPONDIENTE E INSTARÁ AL JUEZ DE LA INVESTIGACIÓN PREPARATORIA QUE DISPONGA AL FISCAL LA FORMACIÓN DEL:', 'REQUERIMIENTO DE PAGO DE REPARACIÓN CIVIL', 'CUADERNO DE NULIDAD DE TRANSFERENCIA', 'CUADERNILLO ACUSATORIO', 'ALEGATO DE DEFENSA', 'CONCEPTO INICIAL DEL HECHO PUNIBLE', NULL, 'b', 'CUADERNO DE NULIDAD DE TRANSFERENCIA', '(ART: 15) [LIBRO PRIMERO]  [SECCION II]', '184614'),
(1779, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EFECTOS DE LA NOTIFICACIÓN.- LA NOTIFICACIÓN EFECTUADA POR ORDEN DEL FISCAL O DEL JUEZ, EN EL DOMICILIO PROCESAL SEÑALADO EN AUTOS POR EL ESTUDIO ASOCIADO, COMPRENDERÁ A:', 'ALGÚN ABOGADO QUE PARTICIPÓ EN LA DEFENSA', 'ALGUNOS ABOGADOS QUE CONOCEN DEL PROCESO', 'TODOS LOS ABOGADOS QUE YA NO PARTICIPAN DEL PROCESO', 'TODOS Y CADA UNO DE LOS ABOGADOS QUE PARTICIPAN EN LA DEFENSA', 'UNO DE LOS ABOGADOS QUE PARTICIPÓ DE LA DEFENSA', NULL, 'd', 'TODOS Y CADA UNO DE LOS ABOGADOS QUE PARTICIPAN EN LA DEFENSA', '(ART: 83) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO II]', '184615'),
(1780, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ CORRERÁ TRASLADO DEL REQUERIMIENTO DE NULIDAD AL IMPUTADO, AL ADQUIRENTE Y/O POSEEDOR DEL BIEN CUESTIONADO O A:', 'AQUÉL EN CUYO FAVOR SE GRAVÓ EL BIEN', 'QUIEN RESULTE PERJUDICADO', 'SU ABOGADO DEFENSOR DE CADA UNO DE ELLOS', 'QUIEN TAMBIÉN ESTÉ ENCAUSADO EN EL PROCESO', 'AQUÉL QUE SE IRROGUE ESE DERECHO', NULL, 'a', 'AQUÉL EN CUYO FAVOR SE GRAVÓ EL BIEN', '(ART: 15) [LIBRO PRIMERO]  [SECCION II]', '184616'),
(1781, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL JUEZ, ABSUELTO EL TRÁMITE O TRANSCURRIDO EL PLAZO RESPECTIVO, DE SER EL CASO, CITARÁ A UNA AUDIENCIA DENTRO DEL QUINTO DÍA PARA LA ACTUACIÓN DE LAS PRUEBAS OFRECIDAS Y ESCUCHAR LOS:', 'INFORMES DEL FISCAL', 'ACUERDOS DE LAS PARTES', 'ALEGATOS DE LOS PARTICIPANTES', 'DICTÁMENES PERICIALES', 'FUNDAMENTOS DEL ABOGADO DEFENSOR', NULL, 'c', 'ALEGATOS DE LOS PARTICIPANTES', '(ART: 15) [LIBRO PRIMERO]  [SECCION II]', '184617'),
