(1783, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL ÓRGANO JURISDICCIONAL COMPETENTE PARA DICTAR SENTENCIA SE PRONUNCIARÁ SOBRE LA:', 'CAUSA DEL HECHO PUNIBLE', 'MOTIVO DEL PROCESO PENAL', 'INICIO DE LA DEMANDA', 'CAUSA QUE DIO ORIGEN AL PROCESO', 'NULIDAD DEMANDADA', NULL, 'e', 'NULIDAD DEMANDADA', '(ART: 15) [LIBRO PRIMERO]  [SECCION II]', '184619'),
(1784, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'TODOS LOS LEGITIMADOS PARA INTERVENIR EN ESTE INCIDENTE PUEDEN PARTICIPAR EN TODAS LAS ACTUACIONES PROCESALES QUE PUEDAN AFECTAR SU DERECHO Y, ESPECIALMENTE, EN:', 'EL DESARROLLO DE TODO PROCESO', 'EL PROCESO PENAL', 'EL JUICIO ORAL', 'EL ANÁLISIS DE LOS ELEMENTOS PROBATORIOS', 'LA REVISIÓN DE TODO EL EXPEDIENTE', NULL, 'c', 'EL JUICIO ORAL', '(ART: 15) [LIBRO PRIMERO]  [SECCION II]', '184620'),
(1785, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SEGÚN LA NULIDAD DE TRANSFERENCIA, ESTA PRETENSIÓN TAMBIÉN PUEDE INTERPONERSE DURANTE LA ETAPA INTERMEDIA, EN QUÉ MOMENTO:', 'EN CUALQUIER ETAPA DEL PROCESO', 'EN EL FIJADO POR LA LEY', 'EN LA ETAPA PRELIMINAR, CON EL ASESORAMIENTO DE UN ABOGADO', 'EN LA ETAPA INTERMEDIA, CON MOTIVACIÓN DEL FISCAL', 'CUANDO LO SOLICITE FORMALMENTE EL ABOGADO DEFENSOR', NULL, 'b', 'EN EL FIJADO POR LA LEY', '(ART: 15) [LIBRO PRIMERO]  [SECCION II]', '184621'),
(1786, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI EL ABOGADO DEFENSOR NO ASISTE INJUSTIFICADAMENTE A LA DILIGENCIA PARA LA QUE ES CITADO, Y ÉSTA NO TIENE EL CARÁCTER DE INAPLAZABLE, EL PROCESADO SERÁ REQUERIDO PARA QUE EN EL TÉRMINO DE:', 'EN EL DÍA DESIGNE AL REEMPLAZANTE', 'LA DISTANCIA DESIGNE AL REEMPLAZANTE', '48 HORAS DESIGNE AL REEMPLAZANTE', '24 HORAS DESIGNE AL REEMPLAZANTE', '72 HORAS DESIGNE AL REEMPLAZANTE', NULL, 'd', '24 HORAS DESIGNE AL REEMPLAZANTE', '(ART: 85) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO II]', '184622'),
(1787, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA POTESTAD JURISDICCIONAL DEL ESTADO EN MATERIA PENAL SE EJERCE POR:', 'LA CONTRALORÍA DEL PODER JUDICIAL', 'EL MINISTERIO PÚBLICO', 'LA SALA PENAL DE LA CORTE SUPREMA', 'LA PROCURADURÍA DEL ESTADO EN LO PENAL', 'LA DEFENSORÍA DEL PUEBLO EN LO PENAL', NULL, 'c', 'LA SALA PENAL DE LA CORTE SUPREMA', '(ART: 16) [LIBRO PRIMERO]  [SECCION III]  [TITULO I]', '184623'),
