(1789, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA DECLARACIÓN DEL IMPUTADO.- LAS AMPLIACIONES DE DECLARACIÓN PROCEDERÁN SI FUEREN PERTINENTES Y NO APAREZCAN SÓLO COMO UN PROCEDIMIENTO DILATORIO O:', 'MALICIOSO', 'DISTRACTOR', 'PERTURBADOR', 'INEFICAZ', 'IMPROCEDENTE', NULL, 'a', 'MALICIOSO', '(ART: 86) [LIBRO PRIMERO]  [SECCION IV]  [TITULO II]  [CAPITULO II]', '184625'),
(1790, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA POTESTAD JURISDICCIONAL DEL ESTADO EN MATERIA PENAL SE EJERCE POR:', 'LOS JUZGADOS DE PAZ NO LETRADOS', 'LA DEFENSORÍA DEL PUEBLO EN MATERIA PENAL', 'LOS JUZGADOS CIVILES MIXTOS', 'LA PROCURADURÍA DEL ESTADO EN LO PENAL', 'LOS JUZGADOS PENALES, CONSTITUIDOS EN ÓRGANOS COLEGIADOS O UNIPERSONALES', NULL, 'e', 'LOS JUZGADOS PENALES, CONSTITUIDOS EN ÓRGANOS COLEGIADOS O UNIPERSONALES', '(ART: 16) [LIBRO PRIMERO]  [SECCION III]  [TITULO I]', '184626'),
(1791, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA POTESTAD JURISDICCIONAL DEL ESTADO EN MATERIA PENAL SE EJERCE POR:', 'LOS JUZGADOS DE LA INVESTIGACIÓN PREPARATORIA', 'LA PROCURADURÍA DEL ESTADO EN LO PENAL', 'LOS JUZGADOS DE PAZ NO LETRADOS', 'LA DEFENSORÍA DEL PUEBLO EN MATERIA PENAL', 'LOS JUZGADOS CIVILES MIXTOS', NULL, 'a', 'LOS JUZGADOS DE LA INVESTIGACIÓN PREPARATORIA', '(ART: 16) [LIBRO PRIMERO]  [SECCION III]  [TITULO I]', '184627'),
(1792, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'LA POTESTAD JURISDICCIONAL DEL ESTADO EN MATERIA PENAL SE EJERCE POR:', 'LOS JUZGADOS DE PAZ NO LETRADOS', 'LA DEFENSORÍA DEL PUEBLO EN MATERIA PENAL', 'LA PROCURADURÍA DEL ESTADO EN LO PENAL', 'LOS JUZGADOS DE PAZ LETRADOS', 'LOS JUZGADOS CIVILES MIXTOS', NULL, 'd', 'LOS JUZGADOS DE PAZ LETRADOS', '(ART: 16) [LIBRO PRIMERO]  [SECCION III]  [TITULO I]', '184628'),
