(1828, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI EL DELITO ES COMETIDO FUERA DEL TERRITORIO NACIONAL Y DEBE SER JUZGADO EN EL PERÚ CONFORME AL CÓDIGO PENAL, LA COMPETENCIA DEL JUEZ SE ESTABLECE EN EL SIGUIENTE ORDEN:', 'POR EL PREDIO DONDE EL IMPUTADO NO TUVO SU ÚLTIMO DOMICILIO EN EL PAÍS', 'POR EL LUGAR DONDE EL IMPUTADO TUVO SU ÚLTIMO DOMICILIO EN EL PAÍS', 'POR LA VECINDAD DONDE EL TESTIGO TUVO SU ÚLTIMO DOMICILIO EN EL PAÍS', 'POR LA PROPIEDAD DONDE EL COAUTOR TUVO SU ÚLTIMO DOMICILIO EN EL PAÍS', 'POR EL BARRIO DONDE EL AGRAVIADO TUVO SU ÚLTIMA MORADA EN EL PAÍS', NULL, 'b', 'POR EL LUGAR DONDE EL IMPUTADO TUVO SU ÚLTIMO DOMICILIO EN EL PAÍS', '(ART: 23) [LIBRO PRIMERO]  [SECCION III]  [TITULO II]  [CAPITULO I]', '184664'),
(1829, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI EL DELITO ES COMETIDO FUERA DEL TERRITORIO NACIONAL Y DEBE SER JUZGADO EN EL PERÚ CONFORME AL CÓDIGO PENAL, LA COMPETENCIA DEL JUEZ SE ESTABLECE EN EL SIGUIENTE ORDEN:', 'POR EL LUGAR DE LLEGADA DEL INTERIOR DEL PAÍS', 'POR EL LUGAR DE LLEGADA DEL IMPUTADO', 'POR EL LUGAR DE LLEGADA DEL TESTIGO', 'POR EL LUGAR DE LLEGADA DEL EXTRANJERO', 'POR EL LUGAR DE LLEGADA DEL PROCESADO', NULL, 'd', 'POR EL LUGAR DE LLEGADA DEL EXTRANJERO', '(ART: 23) [LIBRO PRIMERO]  [SECCION III]  [TITULO II]  [CAPITULO I]', '184665'),
(1830, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL EXAMEN DE LA SALA PENAL SUPERIOR TIENE COMO PROPÓSITO QUE LA RESOLUCIÓN IMPUGNADA SEA:', 'ANULADA PARCIALMENTE', 'ANULADA O REVOCADA, TOTAL O PARCIALMENTE', 'ANULADA TOTALMENTE', 'NO SEA ANULADA, NI REVOCADA', 'NO SEA ANULADA, NI REVOCADA, TOTAL O PARCIALMENTE', NULL, 'b', 'ANULADA O REVOCADA, TOTAL O PARCIALMENTE', '(ART: 419) [LIBRO CUARTO]  [SECCION IV]  [TITULO I]', '184666'),
(1831, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL ACTA SERÁ SUSCRITA POR EL FUNCIONARIO O AUTORIDAD QUE:', 'DIRIGE Y POR LOS DEMÁS INTERVINIENTES, PREVIA LECTURA', 'PARTICIPA Y POR LOS DEMÁS TESTIGOS, PREVIA LECTURA', 'DIRIGE Y POR LOS DEMÁS INTERVINIENTES, PREVIA CONSULTA', 'DIRIGE Y POR LOS DEMÁS PARTICIPANTES, PREVIA REVISIÓN', 'ACTÚA Y POR LOS DEMÁS INTERVINIENTES, PREVIA AUDIENCIA', NULL, 'a', 'DIRIGE Y POR LOS DEMÁS INTERVINIENTES, PREVIA LECTURA', '(ART: 120) [LIBRO SEGUNDO]  [SECCION I]  [TITULO I]  [CAPITULO II]', '184667'),
(1832, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI EL DELITO ES COMETIDO FUERA DEL TERRITORIO NACIONAL Y DEBE SER JUZGADO EN EL PERÚ CONFORME AL CÓDIGO PENAL, LA COMPETENCIA DEL JUEZ SE ESTABLECE EN EL SIGUIENTE ORDEN:', 'POR LA ZONA DONDE SE ENCUENTRE EL COAUTOR AL MOMENTO DE PROMOVERSE LA ACCIÓN PENAL', 'POR LA VECINDAD DONDE SE ENCUENTRE EL IMPUTADO AL MOMENTO DE DICTARSE SENTENCIA', 'POR EL BARRIO DONDE SE ENCUENTRE EL IMPUTADO AL MOMENTO DE NOTIFICÁRSELE SOBRE EL HECHO PUNIBLE', 'POR LA PROPIEDAD DONDE SE ENCUENTRE EL IMPUTADO PRÓXIMO AL DOMICILIO DEL AGRAVIADO', 'POR EL LUGAR DONDE SE ENCUENTRE EL IMPUTADO AL MOMENTO DE PROMOVERSE LA ACCIÓN PENAL', NULL, 'e', 'POR EL LUGAR DONDE SE ENCUENTRE EL IMPUTADO AL MOMENTO DE PROMOVERSE LA ACCIÓN PENAL', '(ART: 23) [LIBRO PRIMERO]  [SECCION III]  [TITULO II]  [CAPITULO I]', '184668'),
(1833, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EL AUTO EN EL QUE LA SALA DECLARA INADMISIBLE EL RECURSO PODRÁ SER OBJETO DE RECURSO DE:', 'APELACIÓN', 'REPOSICIÓN', 'REVISIÓN', 'NULIDAD', 'CASACIÓN', NULL, 'b', 'REPOSICIÓN', '(ART: 420) [LIBRO CUARTO]  [SECCION IV]  [TITULO II]', '184669'),
(1834, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿CUÁL DE LOS SIGUIENTES PRESUPUESTOS MATERIALES ES INDISPENSABLE PARA QUE EL JUEZ DICTE MANDATO DE PRISIÓN PREVENTIVA, SEGÚN EL ARTÍCULO 268 DEL CÓDIGO PROCESAL PENAL?', 'QUE EXISTAN FUNDADOS Y GRAVES ELEMENTOS DE CONVICCIÓN QUE VINCULEN AL IMPUTADO COMO AUTOR O', 'QUE EL IMPUTADO HAYA CONFESADO LA COMISIÓN DEL DELITO', 'QUE LA VÍCTIMA SOLICITE EXPRESAMENTE LA PRISIÓN PREVENTIVA', 'QUE SE TRATE SIEMPRE DE DELITOS COMETIDOS CON VIOLENCIA', 'QUE EL IMPUTADO ESTÉ EN SITUACIÓN DE REINCIDENCIA PENAL', NULL, 'a', 'QUE EXISTAN FUNDADOS Y GRAVES ELEMENTOS DE CONVICCIÓN QUE VINCULEN AL IMPUTADO COMO AUTOR', '(ART: 268) Articulo 268.- Presupuestos materiales', '184673'),
(1835, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SEGÚN EL ARTÍCULO 268 DEL CÓDIGO PROCESAL PENAL, ¿EN QUÉ SUPUESTOS PUEDE EL JUEZ COLEGIR RAZONABLEMENTE EL PELIGRO DE FUGA U OBSTACULIZACIÓN?', 'CUANDO EXISTA AMENAZA CONTRA LA VIDA DEL IMPUTADO', 'EN RAZÓN A LOS ANTECEDENTES Y OTRAS CIRCUNSTANCIAS DEL CASO PARTICULAR DEL IMPUTADO', 'SI EL IMPUTADO NO TIENE DOMICILIO CONOCIDO', 'ÚNICAMENTE CUANDO EL IMPUTADO TENGA SENTENCIA FIRME', 'CUANDO EXISTAN PRUEBAS DOCUMENTALES ÚNICAMENTE', NULL, 'b', 'EN RAZÓN A LOS ANTECEDENTES Y OTRAS CIRCUNSTANCIAS DEL CASO PARTICULAR DEL IMPUTADO', '(ART: 268) Articulo 268.- Presupuestos materiales', '184674'),
(1836, 'Decreto Legislativo Nº 957 Código Procesal Penal', '¿EN QUÉ CASOS NO PROCEDE LA PRISIÓN PREVENTIVA SEGÚN LO ESTABLECIDO EN EL ARTÍCULO 268, SALVO CIRCUNSTANCIAS EXCEPCIONALES?', 'EN CASOS DE FLAGRANCIA DELICTIVA', 'EN LOS CASOS DE INMINENTE APLICACIÓN DE LEGÍTIMA DEFENSA PROPIA O DE TERCERO CONFORME A LEY', 'CUANDO EL IMPUTADO SE ENCUENTRA FUERA DEL PAÍS', 'SI EL DELITO NO ESTÁ TIPIFICADO EN EL CÓDIGO PENAL', 'SI EL FISCAL CONSIDERA INNECESARIA LA MEDIDA', NULL, 'b', 'EN LOS CASOS DE INMINENTE APLICACIÓN DE LEGÍTIMA DEFENSA PROPIA O DE TERCERO CONFORME A LEY', '(ART: 268) Articulo 268.- Presupuestos materiales', '184675'),
(1837, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'ARTÍCULO N° 268.- PRESUPUESTOS MATERIALES. EL JUEZ, A SOLICITUD DEL MINISTERIO PÚBLICO, PODRÁ DICTAR MANDATO DE PRISIÓN PREVENTIVA, SI ATENDIENDO A LOS PRIMEROS RECAUDOS SEA POSIBLE DETERMINAR LA CONCURRENCIA DE LOS SIGUIENTES PRESUPUESTOS: QUE LA SANCIÓN A IMPONERSE SEA SUPERIOR A:', 'TRES AÑOS', 'CINCO AÑOS', 'CUATRO AÑOS', 'DOS AÑOS', 'UN AÑO', NULL, 'b', 'CINCO AÑOS', '(ART: 268) Articulo 268.- Presupuestos materiales', '184676'),
(1838, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'DE ACUERDO CON EL ARTÍCULO 138, ¿EN QUÉ SITUACIONES PUEDE EL MINISTERIO PÚBLICO SOLICITAR COPIAS DE ACTUACIONES DE OTROS PROCESOS?', 'EN CUALQUIER MOMENTO Y SIN NINGUNA JUSTIFICACIÓN PREVIA', 'SOLO DURANTE LA ETAPA INTERMEDIA, PREVIA AUTORIZACIÓN JUDICIAL', 'CUANDO SEA NECESARIO PARA EL CUMPLIMIENTO DE LA INVESTIGACIÓN PREPARATORIA, DE OTRO FISCAL O DEL JUEZ', 'EXCLUSIVAMENTE CUANDO EJERZA FUNCIONES DE TITULAR DE ACCIÓN PENAL', 'ÚNICAMENTE CON ORDEN DE LA SALA PENAL SUPERIOR COMPETENTE', NULL, 'c', 'CUANDO SEA NECESARIO PARA EL CUMPLIMIENTO DE LA INVESTIGACIÓN PREPARATORIA, DE OTRO FISCAL O', '(ART: 138)  Articulo 138.- Obtencion de copias', '184684'),
(1839, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'SI UN PARTICULAR SOLICITA COPIAS DE ACTUACIONES PROCESALES Y ACREDITA LEGÍTIMO INTERÉS, ¿QUÉ REQUISITO ADICIONAL DEBE CUMPLIRSE PARA QUE DICHA SOLICITUD SEA ESTIMADA CONFORME AL ARTÍCULO 138?', 'DEBE EXISTIR CONFORMIDAD EXPRESA DE TODAS LAS PARTES PROCESALES', 'LA SOLICITUD DEBE ACOMPAÑAR UN DICTAMEN PERICIAL QUE JUSTIFIQUE LA NECESIDAD', 'NO DEBE OBSTACULIZAR LA NORMAL PROSECUCIÓN DEL PROCESO NI AFECTAR DERECHOS FUNDAMENTALES DE', 'DEBEN HABERSE AGOTADO PREVIAMENTE LOS RECURSOS IMPUGNATORIOS ORDINARIOS', 'LA SOLICITUD REQUIERE LA APROBACIÓN PREVIA DEL JUEZ DE INVESTIGACIÓN PREPARATORIA Y DEL FISCAL SUPERIOR', NULL, 'c', 'NO DEBE OBSTACULIZAR LA NORMAL PROSECUCIÓN DEL PROCESO NI AFECTAR DERECHOS FUNDAMENTALES', '(ART: 138) Articulo 138.- Obtencion de copias', '184685'),
(1840, 'Decreto Legislativo Nº 957 Código Procesal Penal', 'EN EL CONTEXTO DEL ARTÍCULO 328 DEL NCPC, ¿QUÉ PROCEDIMIENTO DEBE SEGUIRSE SI EL DENUNCIANTE NO PUEDE FIRMAR UNA DENUNCIA ESCRITA O VERBAL?', 'SE LIMITARÁ A COLOCAR SU IMPRESIÓN DIGITAL, DEJÁNDOSE CONSTANCIA EN EL ACTA DEL IMPEDIMENTO', 'LA DENUNCIA SE CONSIDERARÁ NULA SI NO SE FIRMA', 'EL FUNCIONARIO A CARGO DEBE FIRMAR POR EL DENUNCIANTE SIN MAYOR CONSTANCIA', 'EL DENUNCIANTE DEBE ESPERAR HASTA PODER FIRMAR PERSONALMENTE', 'DEBE PRESENTAR UNA DECLARACIÓN JURADA POR SU INCAPACIDAD DE FIRMAR', NULL, 'a', 'SE LIMITARÁ A COLOCAR SU IMPRESIÓN DIGITAL, DEJÁNDOSE CONSTANCIA EN EL ACTA DEL IMPEDIMENTO', '(ART: 328) Articulo 328.- Contenido y forma de la denuncia', '184691'),
(1841, 'Decreto Legislativo Nº 635 Código Penal', 'EL JUEZ O FISCAL QUE CONOCE EN UN PROCESO QUE ANTERIORMENTE PATROCINÓ COMO ABOGADO, COMETE DELITO DE:.', 'PROHIBICIÓN DE CONOCER UN PROCESO QUE PATROCINÓ.', 'PATROCINIO INFIEL.', 'PREVARICATO POR INCOMPETENCIA.', 'PREVARICATO AGRAVADO.', 'PREVARICATO ILEGAL.', NULL, 'a', 'PROHIBICIÓN DE CONOCER UN PROCESO QUE PATROCINÓ.', '(ART: 420)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION II]', '183939'),
(1842, 'Decreto Legislativo Nº 635 Código Penal', 'EL MANDATARIO JUDICIAL O ABOGADO QUE, DESPUÉS DE HABER PATROCINADO O REPRESENTADO A UNA PARTE EN UN PROCESO JUDICIAL O ADMINISTRATIVO, ASUME LA DEFENSA DE LA PARTE CONTRARIA EN EL MISMO PROCESO, ESTA INCURSO EN EL DELITO DE:.', 'PREVARICATO.', 'PATROCINIO ILEGAL.', 'PATROCINIO INDEBIDO DE ABOGADO O MANDATARIO JUDICIAL.', 'PATROCINIO INCOMPATIBLE.', 'PATROCINIO IMPROPIO.', NULL, 'c', 'PATROCINIO INDEBIDO DE ABOGADO O MANDATARIO JUDICIAL.', '(ART: 421)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION II]', '183940'),
(1843, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE INDEBIDAMENTE REVELA LA IDENTIDAD DE UN COLABORADOR EFICAZ, TESTIGO, AGRAVIADO O PERITO PROTEGIDO, AGENTE ENCUBIERTO O ESPECIAL, ASÍ COMO, BRINDE INFORMACIÓN QUE PERMITA SU IDENTIFICACIÓN, COMETE DELITO DE:', 'OBSTRUCCIÓN A LA JUSTICIA.', 'REVELACIÓN INDEBIDA DE IDENTIDAD.', 'REVELACIÓN INDEBIDA DE INFORMACIÓN.', 'REVELACIÓN DE INFORMACIÓN CLASIFICADA.', 'REVELACIÓN DE INFORMACIÓN RESERVADA.', NULL, 'b', 'REVELACIÓN INDEBIDA DE IDENTIDAD.', '(ART: 409-B)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '183941'),
(1844, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, POR VIOLENCIA, AMENAZA O ASTUCIA, HACE EVADIR A UN PRESO, DETENIDO O INTERNO O LE PRESTA ASISTENCIA EN CUALQUIER FORMA PARA EVADIRSE, COMETE DELITO DE:.', 'FAVORECIMIENTO A LA FUGA.', 'FUGA MEDIANTE VIOLENCIA.', 'FUGA MEDIANTE AMENAZA.', 'FAVORECIMIENTO A LA EVASIÓN DE LA JUSTICIA.', 'FUGA MEDIANTE VIOLENCIA O AMENAZA.', NULL, 'a', 'FAVORECIMIENTO A LA FUGA.', '(ART: 414)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '183942'),
(1845, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE OMITE COMUNICAR A LA AUTORIDAD LAS NOTICIAS QUE TENGA ACERCA DE LA COMISIÓN DE ALGÚN DELITO, CUANDO ESTÉ OBLIGADO A HACERLO POR SU PROFESIÓN O EMPLEO, COMETE DELITO DE:.', 'OMISIÓN DE INFORMAR.', 'OMISIÓN A LA JUSTICIA.', 'OMISIÓN AGRAVADA.', 'OMISIÓN DE DENUNCIA.', 'OMISIÓN IMPROPIA.', NULL, 'd', 'OMISIÓN DE DENUNCIA.', '(ART: 407)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '183943'),
(1846, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE PROMUEVE, FAVORECE, FINANCIA O FACILITA EL INGRESO O REINGRESO ILEGAL O EL TRÁNSITO IRREGULAR EN EL PAÍS DE OTRA PERSONA, CON EL FIN DE OBTENER DIRECTA O INDIRECTAMENTE, CUALQUIER BENEFICIO PARA SÍ O PARA TERCERO, COMETE DELITO DE:.', 'TRÁFICO LÍCITO DE MIGRANTES.', 'TRÁFICO ILÍCITO DE EXTRANJEROS.', 'TRÁFICO ILÍCITO DE NACIONALES.', 'TRÁFICO ILÍCITO DE MIGRANTES.', 'TRÁFICO ILÍCITO DE INMIGRANTES.', NULL, 'd', 'TRÁFICO ILÍCITO DE MIGRANTES.', '(ART: 303-A)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO IV]', '183945'),
(1847, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE DAÑA, DESTRUYE O INUTILIZA UN BIEN, MUEBLE O INMUEBLE, TOTAL O PARCIALMENTE AJENO, COMETE DELITO DE:.', 'DAÑO AGRAVADO.', 'DAÑO SIMPLE.', 'DAÑO DE UN BIEN.', 'DAÑO A LA PROPIEDAD PÚBLICA.', 'DAÑO A LA PROPIEDAD AJENA.', NULL, 'b', 'DAÑO SIMPLE.', '(ART: 205)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IX]', '183946'),
(1848, 'Decreto Legislativo Nº 635 Código Penal', 'EL AUDITOR INTERNO O EXTERNO QUE A SABIENDAS DE LA EXISTENCIA DE DISTORSIONES O TERGIVERSACIONES SIGNIFICATIVAS EN LA INFORMACIÓN CONTABLE Y FINANCIERA DE LA PERSONA JURÍDICA NO LAS REVELA EN SU INFORME O DICTAMEN, COMETE DELITO DE:.', 'INFORMES MANIPULADOS DE AUDITORÍA.', 'INFORMES DE AUDITORÍA FALSOS.', 'INFORMES DE AUDITORÍA ADULTERADOS.', 'INFORMES DE AUDITORÍA DISTORSIONADOS.', 'INFORMES DE AUDITORÍA CON INFORMACIÓN FALSA.', NULL, 'd', 'INFORMES DE AUDITORÍA DISTORSIONADOS.', '(ART: 198-A)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VI]', '183947'),
(1849, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE VIOLA LAS MEDIDAS IMPUESTAS POR LA LEY O POR LA AUTORIDAD PARA LA INTRODUCCIÓN AL PAÍS O LA PROPAGACIÓN DE UNA ENFERMEDAD O EPIDEMIA O UNA PLAGA, COMETE EL DELITO DE:.', 'VIOLACIÓN DE MEDIDAS PREVENTIVAS DE SALUD.', 'VIOLACIÓN DE MEDIDAS SANITARIAS.', 'VIOLACIÓN DE MEDIDAS DE SALUD.', 'VIOLACIÓN DE DISPOSICIONES DE RIESGO.', 'VIOLACIÓN DE NORMAS DE PELIGRO COMÚN.', NULL, 'b', 'VIOLACIÓN DE MEDIDAS SANITARIAS.', '(ART: 292)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO III]  [SECCION I]', '183949'),
(1850, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, A SABIENDAS, MATA A SU ASCENDIENTE, DESCENDIENTE, NATURAL O ADOPTIVO, O A UNA PERSONA CON QUIEN SOSTIENE O HAYA SOSTENIDO UNA RELACIÓN CONYUGAL O DE CONVIVENCIA, CORRESPONDE A LA MODALIDAD DE:', 'HOMICIDIO SIMPLE.', 'ASESINATO.', 'PARRICIDIO.', 'SUICIDIO.', 'HOMICIDIO.', NULL, 'c', 'PARRICIDIO.', '(ART: 107)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183951'),
(1851, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATE A OTRO CONCURRIENDO CUALQUIERA DE LAS CIRCUNSTANCIAS SIGUIENTES: POR FEROCIDAD, CODICIA, LUCRO O PLACER, PARA FACILITAR U OCULTAR OTRO DELITO, CON GRAN CRUELDAD O ALEVOSÍA, POR FUEGO, EXPLOSIÓN U OTRO MEDIO CAPAZ DE PONER EN PELIGRO LA VIDA O SALUD DE OTRAS PERSONAS. ESTA CONSIDERADO COMO DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD EN LA MODALIDAD DE:.', 'HOMICIDIO SIMPLE.', 'HOMICIDIO GRAVE.', 'HOMICIDIO PLANIFICADO.', 'HOMICIDIO CRUEL.', 'HOMICIDIO CALIFICADO.', NULL, 'e', 'HOMICIDIO CALIFICADO.', '(ART: 108)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183952'),
(1852, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATA A UNO DE LOS ALTOS FUNCIONARIOS COMPRENDIDOS EN EL ARTÍCULO 39 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ, A UN MIEMBRO DE LA POLICÍA NACIONAL, DE LAS FUERZAS ARMADAS, A UN MAGISTRADO DEL PODER JUDICIAL, O DEL MINISTERIO PÚBLICO, O A UN MIEMBRO DEL TRIBUNAL CONSTITUCIONAL O A CUALQUIER AUTORIDAD ELEGIDA POR MANDATO POPULAR EN EL EJERCICIO DE SUS FUNCIONES O COMO CONSECUENCIA DE ELLAS.- COMETE DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD:.', 'HOMICIDIO SIMPLE POR LA CONDICIÓN DE LA VÍCTIMA.', 'HOMICIDIO PLANIFICADO POR LA CONDICIÓN DE LA VÍCTIMA.', 'HOMICIDIO CALIFICADO POR LA CONDICIÓN DE LA VÍCTIMA.', 'HOMICIDIO AGRAVADO POR LA CONDICIÓN DEL AUTOR.', 'HOMICIDIO CALIFICADO POR LA RELACIÓN DEL AUTOR CON LA VÍCTIMA.', NULL, 'c', 'HOMICIDIO CALIFICADO POR LA CONDICIÓN DE LA VÍCTIMA.', '(ART: 108-A)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183953'),
(1853, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, EN EL CONTEXTO DE VIOLENCIA FAMILIAR, COACCIÓN, HOSTIGAMIENTO O ACOSO, ABUSO DE PODER, CONFIANZA O DE CUALQUIER OTRA POSICIÓN O RELACIÓN QUE LE CONFIERA AUTORIDAD AL AGENTE, MATA A UNA MUJER POR SU CONDICIÓN DE TAL, COMETE DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD DE:.', 'PARRICIDIO.', 'INFANTICIDIO.', 'SUICIDIO.', 'GENOCIDIO.', 'FEMINICIDIO.', NULL, 'e', 'FEMINICIDIO.', '(ART: 108-B)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183954'),
(1854, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL DELITO DE FEMINICIDIO, LA PENA SERÁ DE CADENA PERPETUA, CUANDO CONCURRAN CIRCUNSTANCIAS AGRAVANTES EN CANTIDAD DE:.', 'TRES O MÁS CIRCUNSTANCIAS AGRAVANTES.', 'DOS O MÁS CIRCUNSTANCIAS AGRAVANTES.', 'SOLO UNA CIRCUNSTANCIA AGRAVANTE.', 'NO HAY CADENA PERPETUA PARA ESTE DELITO.', 'CUATRO CIRCUNSTANCIAS AGRAVANTES.', NULL, 'b', 'DOS O MÁS CIRCUNSTANCIAS AGRAVANTES.', '(ART: 108-B)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183955'),
(1855, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATA A OTRO POR ORDEN, ENCARGO O ACUERDO, CON EL PROPÓSITO DE OBTENER PARA SÍ O PARA OTRO UN BENEFICIO ECONÓMICO O DE CUALQUIER OTRA ÍNDOLE. CORRESPONDE A LA COMISIÓN DE DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD DE:.', 'ASESINATO.', 'SICARIATO.', 'FEMINICIDIO.', 'GENOCIDIO.', 'PARRICIDIO.', NULL, 'b', 'SICARIATO.', '(ART: 108-C)** [TITULO I]  [CAPITULO I]', '183956'),
(1856, 'Decreto Legislativo Nº 635 Código Penal', 'QUIEN PARTICIPA EN UNA CONSPIRACIÓN PARA PROMOVER, FAVORECER O FACILITAR EL DELITO DE SICARIATO Y QUIEN SOLICITA U OFRECE A OTROS, COMETER EL DELITO DE SICARIATO O ACTÚA COMO INTERMEDIARIO, SE ENCUENTRA INCURSO EN:.', 'SICARIATO Y PARTICIPACIÓN INDIRECTA AGRAVADA.', 'APOYO AL SICARIATO Y ORGANIZACIONES CRIMINALES.', 'CONSPIRACIÓN Y OFRECIMIENTO PARA EL DELITO DE SICARIATO.', 'SICARIATO CON BANDA ORGANIZADA TRANSNACIONAL.', 'INVERSIONISTA PARA EL DELITO DE SICARIATO.', NULL, 'c', 'CONSPIRACIÓN Y OFRECIMIENTO PARA EL DELITO DE SICARIATO.', '(ART: 108-D)** [TITULO I]  [CAPITULO I]', '183957'),
(1857, 'Decreto Legislativo Nº 635 Código Penal', 'LA MADRE QUE MATA A SU HIJO DURANTE EL PARTO O BAJO LA INFLUENCIA DEL ESTADO PUERPERAL. INCURRE EN DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD; EN LA MODALIDAD DE:', 'PARRICIDIO.', 'FEMINICIDIO.', 'HOMICIDIO.', 'INFANTICIDIO.', 'GENOCIDIO.', NULL, 'd', 'INFANTICIDIO.', '(ART: 110)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183959'),
(1858, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, POR PIEDAD, MATA A UN ENFERMO INCURABLE QUE LE SOLICITA DE MANERA EXPRESA Y CONSCIENTE PARA PONER FIN A SUS INTOLERABLES DOLORES. INCURRE EN DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD DE:', 'HOMICIDIO CULPOSO.', 'HOMICIDIO PIADOSO.', 'HOMICIDIO AGRAVADO.', 'HOMICIDIO SIMPLE.', 'HOMICIDIO ATENUADO.', NULL, 'b', 'HOMICIDIO PIADOSO.', '(ART: 112)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183961'),
(1859, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE INSTIGA A OTRO AL SUICIDIO O LO AYUDA A COMETERLO, SERÁ REPRIMIDO, SI EL SUICIDIO SE HA CONSUMADO O INTENTADO. ESTAMOS REFIRIÉNDONOS AL DELITO CONTRA LA VIDA, EL CUERPO Y LA SALUD, EN LA MODALIDAD DE:', 'PROVOCACIÓN PARA EL SUICIDIO.', 'INSTIGACIÓN O AYUDA AL SUICIDIO.', 'INSTIGACIÓN O AYUDA AL HOMICIDIO.', 'INSTIGACIÓN O AYUDA AL PARRICIDIO.', 'INSTIGACIÓN O AYUDA AL INFANTICIDIO.', NULL, 'b', 'INSTIGACIÓN O AYUDA AL SUICIDIO.', '(ART: 113)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '183962'),
(1860, 'Decreto Legislativo Nº 635 Código Penal', 'LA MUJER QUE CAUSA SU ABORTO, O CONSIENTE QUE OTRO LE PRACTIQUE, CORRESPONDE A LA DEFINICIÓN DE:', 'ABORTO CONSENTIDO.', 'AUTOABORTO.', 'ABORTO SIN CONSENTIMIENTO.', 'ABORTO PRETERINTENCIONAL.', 'ABORTO TERAPÉUTICO.', NULL, 'b', 'AUTOABORTO.', '(ART: 114)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '183963'),
(1861, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE HACE ABORTAR A UNA MUJER SIN SU CONSENTIMIENTO, CORRESPONDE A LA DEFINICIÓN DE:', 'ABORTO CONSENTIDO.', 'ABORTO EUGENÉSICO.', 'ABORTO SIN CONSENTIMIENTO.', 'ABORTO PRETERINTENCIONAL.', 'ABORTO TERAPÉUTICO.', NULL, 'c', 'ABORTO SIN CONSENTIMIENTO.', '(ART: 116)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '183965'),
(1862, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, CON VIOLENCIA, OCASIONA UN ABORTO, SIN HABER TENIDO EL PROPÓSITO DE CAUSARLO, SIENDO NOTORIO O CONSTÁNDOLE EL EMBARAZO, COMETE DELITO DE:', 'ABORTO CONSENTIDO.', 'ABORTO SIN CONSENTIMIENTO.', 'AUTOABORTO.', 'ABORTO PRETERINTENCIONAL.', 'ABORTO TERAPÉUTICO.', NULL, 'd', 'ABORTO PRETERINTENCIONAL.', '(ART: 118)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '183966'),
(1863, 'Decreto Legislativo Nº 635 Código Penal', 'NO ES PUNIBLE EL ABORTO PRACTICADO POR UN MÉDICO CON EL CONSENTIMIENTO DE LA MUJER EMBARAZADA O DE SU REPRESENTANTE LEGAL, SI LO TUVIERE, CUANDO ES EL ÚNICO MEDIO PARA SALVAR LA VIDA DE LA GESTANTE O PARA EVITAR EN SU SALUD UN MAL GRAVE Y PERMANENTE, ESTE ENUNCIADO CORRESPONDE A:', 'ABORTO SANITARIO.', 'ABORTO CONSENTIDO.', 'ABORTO SIN CONSENTIMIENTO.', 'ABORTO PRETERINTENCIONAL.', 'ABORTO TERAPÉUTICO.', NULL, 'e', 'ABORTO TERAPÉUTICO.', '(ART: 119)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '183967'),
(1864, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA A OTRO DAÑO GRAVE EN EL CUERPO O EN LA SALUD FÍSICA Y MENTAL Y PONE EN PELIGRO INMINENTE LA VIDA DE LA VÍCTIMA, COMETE DELITO DE:', 'LESIONES GRAVES.', 'LESIONES LEVES.', 'LESIONES SIMPLES.', 'LESIONES DOLOSAS.', 'LESIONES CULPOSAS.', NULL, 'a', 'LESIONES GRAVES.', '(ART: 121)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '183969'),
(1865, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA A OTRO DAÑO GRAVE EN EL CUERPO O EN LA SALUD FÍSICA O MENTAL, Y LA VÍCTIMA ES MENOR DE EDAD, ADULTA MAYOR O TIENE DISCAPACIDAD Y EL AGENTE SE APROVECHA DE DICHA CONDICIÓN, COMETE DELITO DE:', 'LESIONES GRAVES.', 'LESIONES LEVES.', 'LESIONES CULPOSAS.', 'LESIONES PRETERINTENCIONALES.', 'LESIONES SIMPLES.', NULL, 'a', 'LESIONES GRAVES.', '(ART: 121)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '183970'),
(1866, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA A OTRO LESIONES EN EL CUERPO O EN LA SALUD FÍSICA Y MENTAL QUE REQUIERA MÁS DE DIEZ Y MENOS DE VEINTE DÍAS DE ASISTENCIA O DESCANSO, SEGÚN PRESCRIPCIÓN FACULTATIVA, O NIVEL MODERADO DE DAÑO PSÍQUICO. ESTE ENUNCIADO SE REFIERE A:', 'LESIONES GRAVES.', 'LESIONES DOLOSAS.', 'LESIONES CULPOSAS.', 'LESIONES LEVES.', 'LESIONES AGRAVADAS.', NULL, 'd', 'LESIONES LEVES.', '(ART: 122)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '183971'),
(1867, 'Decreto Legislativo Nº 635 Código Penal', 'CUANDO EL AGENTE PRODUZCA UN RESULTADO GRAVE QUE NO QUISO CAUSAR, NI PUDO PREVER, LA PENA SERÁ DISMINUIDA PRUDENCIALMENTE HASTA LA QUE CORRESPONDA A LA LESIÓN QUE QUISO INFERIR, CORRESPONDE A:', 'LESIONES PREDETERMINADAS CON RESULTADO FORTUITO.', 'LESIONES DOLOSAS CON RESULTADO FORTUITO.', 'LESIONES INTENCIONALES CON RESULTADO FORTUITO.', 'LESIONES PRETERINTENCIONALES CON RESULTADO FORTUITO.', 'LESIONES CULPOSAS CON RESULTADO FORTUITO.', NULL, 'd', 'LESIONES PRETERINTENCIONALES CON RESULTADO FORTUITO.', '(ART: 123)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '183972'),
(1868, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE POR CULPA CAUSA A OTRO UN DAÑO EN EL CUERPO O EN LA SALUD, SERÁ REPRIMIDO POR ACCIÓN PRIVADA, CON PENA PRIVATIVA DE LIBERTAD NO MAYOR DE UN AÑO Y CON SESENTA A CIENTO VEINTE DÍAS-MULTA, COMETE DELITO DE:', 'LESIONES PRETERINTENCIONALES.', 'LESIONES INTENCIONALES.', 'LESIONES CULPOSAS.', 'LESIONES DOLOSAS.', 'LESIONES AGRAVADAS.', NULL, 'c', 'LESIONES CULPOSAS.', '(ART: 124)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '183973'),
(1869, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE EXPONE A PELIGRO DE MUERTE O DE GRAVE E INMINENTE DAÑO A LA SALUD O ABANDONA EN IGUALES CIRCUNSTANCIAS A UN MENOR DE EDAD O A UNA PERSONA INCAPAZ DE VALERSE POR SÍ MISMA QUE ESTÉN LEGALMENTE BAJO SU PROTECCIÓN O QUE SE HALLEN DE HECHO BAJO SU CUIDADO, COMETE DELITO DE:', 'ABANDONO DE PERSONAS BAJO SU TUTELA.', 'EXPOSICIÓN O ABANDONO DELICADOS.', 'EXPOSICIÓN O ABANDONO CULPOSOS.', 'EXPOSICIÓN O ABANDONO ATENUADOS.', 'EXPOSICIÓN O ABANDONO PELIGROSOS.', NULL, 'e', 'EXPOSICIÓN O ABANDONO PELIGROSOS.', '(ART: 125)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO IV]', '183975'),
(1870, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ENCUENTRA A UN HERIDO O A CUALQUIER OTRA PERSONA EN ESTADO DE GRAVE E INMINENTE PELIGRO Y OMITE PRESTARLE AUXILIO INMEDIATO PUDIENDO HACERLO SIN RIESGO PROPIO O DE TERCERO O SE ABSTIENE DE DAR AVISO A LA AUTORIDAD, COMETE DELITO DE:.', 'OMISIÓN DE AUXILIO O AVISO A LA AUTORIDAD.', 'OMISIÓN DE APOYO A PERSONA EN PELIGRO O AUXILIO A LA AUTORIDAD.', 'OMISIÓN DE AUXILIO A PERSONA FUERA DE PELIGRO O AVISO A LA AUTORIDAD.', 'OMISIÓN DE SOCORRO Y EXPOSICIÓN A PELIGRO A PERSONA.', 'OMISIÓN DE AVISO A LA AUTORIDAD U OMISIÓN DE AUXILIO A PERSONA ILESA.', NULL, 'a', 'OMISIÓN DE AUXILIO O AVISO A LA AUTORIDAD.', '(ART: 127)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO IV]', '183977'),
(1871, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE EXPONE A PELIGRO LA VIDA O LA SALUD DE UNA PERSONA COLOCADA BAJO SU AUTORIDAD, DEPENDENCIA, TUTELA, CURATELA O VIGILANCIA, SEA PRIVÁNDOLA DE ALIMENTOS O CUIDADOS INDISPENSABLES, SEA ABUSANDO DE LOS MEDIOS DE CORRECCIÓN O DISCIPLINA, O CUALQUIER ACTO ANÁLOGO, COMETE DELITO DE:', 'EXPOSICIÓN A LESIONES DE PERSONA INDEPENDIENTE.', 'EXPOSICIÓN A DAÑOS NATURALES DE PERSONA DEPENDIENTE.', 'EXPOSICIÓN A MUERTE DE PERSONA INDEPENDIENTE.', 'EXPOSICIÓN A EXTRAVIARSE DE PERSONA DEPENDIENTE.', 'EXPOSICIÓN A PELIGRO DE PERSONA DEPENDIENTE.', NULL, 'e', 'EXPOSICIÓN A PELIGRO DE PERSONA DEPENDIENTE.', '(ART: 128)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO IV]', '183978'),
(1872, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, MEDIANTE AMENAZA O VIOLENCIA, OBLIGA A OTRO A HACER LO QUE LA LEY NO MANDA O LE IMPIDE HACER LO QUE ELLA NO PROHÍBE. COMETE DELITO DE:', 'COACCIÓN.', 'EXTORSIÓN LEVE.', 'EXTORSIÓN GRAVE.', 'EXTORSIÓN.', 'SECUESTRO.', NULL, 'a', 'COACCIÓN.', '(ART: 151)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO I]', '183979'),
(1873, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN DERECHO, MOTIVO NI FACULTAD JUSTIFICADA, PRIVA A OTRO DE SU LIBERTAD PERSONAL, CUALQUIERA SEA EL MÓVIL, EL PROPÓSITO, LA MODALIDAD O CIRCUNSTANCIA O TIEMPO QUE EL AGRAVIADO SUFRA LA PRIVACIÓN O RESTRICCIÓN DE SU LIBERTAD, COMETE DELITO DE:', 'COACCIÓN.', 'INJURIA.', 'DIFAMACIÓN.', 'SECUESTRO.', 'EXTORSIÓN.', NULL, 'd', 'SECUESTRO.', '(ART: 152)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO I]', '183980'),
(1874, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE VIOLA LA VIDA PERSONAL O FAMILIAR YA SEA OBSERVANDO, ESCUCHANDO O REGISTRANDO UN HECHO. COMETE DELITO DE:.', 'VIOLACIÓN DE LA REALIDAD.', 'VIOLACIÓN DE LA INTIMIDAD.', 'VIOLACIÓN DE LA PERSONA.', 'VIOLACIÓN DE MISIVAS.', 'VIOLACIÓN DE PARTICULARES.', NULL, 'b', 'VIOLACIÓN DE LA INTIMIDAD.', '(ART: 154)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO II]', '183982'),
(1875, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ILEGÍTIMAMENTE COMERCIALIZA O VENDE INFORMACIÓN NO PÚBLICA RELATIVA A CUALQUIER ÁMBITO DE LA ESFERA PERSONAL, FAMILIAR, PATRIMONIAL, LABORAL, FINANCIERA U OTRO DE NATURALEZA ANÁLOGA SOBRE UNA PERSONA NATURAL, COMETE DELITO DE:', 'TRÁFICO ILEGAL DE DATOS NATURALES.', 'TRÁFICO ILEGAL DE DATOS NACIONALES.', 'TRÁFICO ILEGAL DE DATOS PERSONALES.', 'TRÁFICO LEGAL DE DATOS NATURALES.', 'TRÁFICO ILEGAL DE DATOS INFORMÁTICOS.', NULL, 'c', 'TRÁFICO ILEGAL DE DATOS PERSONALES.', '(ART: 154-A)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO II]', '183983'),
(1876, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE REVELA ASPECTOS DE LA INTIMIDAD PERSONAL O FAMILIAR QUE CONOCIERA CON MOTIVO DEL TRABAJO QUE PRESTÓ AL AGRAVIADO O A LA PERSONA A QUIEN ÉSTE SE LO CONFIÓ. COMETE DELITO DE:', 'REVELACIÓN DE LA INTIMIDAD PROFESIONAL Y FAMILIAR.', 'REVELACIÓN DE LA INTIMIDAD PARTICULAR Y FAMILIAR.', 'REVELACIÓN DE LA INTIMIDAD PERSONAL Y FAMILIAR.', 'REVELACIÓN DE LA INTIMIDAD PERSONAL Y PARTICULAR.', 'REVELACIÓN DE LA INTIMIDAD PERSONAL Y PROFESIONAL.', NULL, 'c', 'REVELACIÓN DE LA INTIMIDAD PERSONAL Y FAMILIAR.', '(ART: 156)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO II]', '183984'),
(1877, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, INDEBIDAMENTE, ORGANIZA, PROPORCIONA O EMPLEA CUALQUIER ARCHIVO QUE TENGA DATOS REFERENTES A LAS CONVICCIONES POLÍTICAS O RELIGIOSAS Y OTROS ASPECTOS DE LA VIDA ÍNTIMA DE UNA O MÁS PERSONAS. COMETE DELITO DE:', 'USO DEBIDO DE ARCHIVOS REGISTRADOS.', 'USO DEBIDO DE ARCHIVOS LEGALIZADOS.', 'USO INDEBIDO DE ARCHIVOS PERSONALES.', 'USO INDEBIDO DE ARCHIVOS COMPUTARIZADOS.', 'USO INDEBIDO DE ARCHIVOS PASIVOS.', NULL, 'd', 'USO INDEBIDO DE ARCHIVOS COMPUTARIZADOS.', '(ART: 157)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO II]', '183985'),
(1878, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN DERECHO, PENETRA EN MORADA O CASA DE NEGOCIO AJENA, EN SU DEPENDENCIA O EN EL RECINTO HABITADO POR OTRO O EL QUE PERMANECE ALLÍ REHUSANDO LA INTIMACIÓN QUE LE HAGA QUIEN TENGA DERECHO A FORMULARLA, COMETE DELITO DE:', 'VIOLACIÓN DE PROPIEDAD.', 'ALLANAMIENTO ILEGAL DE DOMICILIO.', 'ALLANAMIENTO.', 'VIOLACIÓN DE DOMICILIO.', 'VIOLACIÓN DE VIVIENDA PROPIA.', NULL, 'd', 'VIOLACIÓN DE DOMICILIO.', '(ART: 159)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO III]', '183987'),
(1879, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ALLANA UN DOMICILIO, SIN LAS FORMALIDADES PRESCRITAS POR LA LEY O FUERA DE LOS CASOS QUE ELLA DETERMINA, COMETE DELITO DE:', 'ALLANAMIENTO ILEGAL DE DOMICILIO.', 'VIOLACIÓN ILEGAL DE DOMICILIO.', 'VIOLACIÓN ILEGAL DE MORADA PARTICULAR.', 'ALLANAMIENTO.', 'VIOLACIÓN DE DOMICILIO.', NULL, 'a', 'ALLANAMIENTO ILEGAL DE DOMICILIO.', '(ART: 160)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO III]', '183988'),
(1880, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ABRE, INDEBIDAMENTE, UNA CARTA, UN PLIEGO, TELEGRAMA, RADIOGRAMA, DESPACHO TELEFÓNICO U OTRO DOCUMENTO DE NATURALEZA ANÁLOGA, QUE NO LE ESTÉ DIRIGIDO, O SE APODERA INDEBIDAMENTE DE ALGUNO DE ESTOS DOCUMENTOS, AUNQUE NO ESTÉ CERRADO, COMETE DELITO DE:', 'VIOLACIÓN DE LOS MENSAJES.', 'VIOLACIÓN DE CORRESPONDENCIA.', 'VIOLACIÓN DE LA MISIVA.', 'VIOLACIÓN DE LA CARTA NOTARIAL.', 'VIOLACIÓN DE LAS COMUNICACIONES.', NULL, 'b', 'VIOLACIÓN DE CORRESPONDENCIA.', '(ART: 161)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IV]', '183989'),
(1881, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE FABRICA, ADQUIERE, INTRODUCE AL TERRITORIO NACIONAL, POSEE O COMERCIALIZA EQUIPOS O SOFTWARES DESTINADOS A INTERCEPTAR ILEGALMENTE LAS COMUNICACIONES O SIMILARES, COMETE DELITO DE:', 'POSESIÓN O COMERCIALIZACIÓN DE EQUIPOS DESTINADOS A LA INJERENCIA TELEFÓNICA O SIMILAR.', 'POSESIÓN O COMERCIALIZACIÓN DE EQUIPOS DESTINADOS A LA COMUNICACIÓN TELEFÓNICA O SIMILAR.', 'POSESIÓN O MICROCOMERCIALIZACIÓN DE EQUIPOS DESTINADOS A LA INJERENCIA TELEFÓNICA O SIMILAR.', 'POSESIÓN O COMERCIALIZACIÓN DE EQUIPOS DESTINADOS A LA INTERCEPTACIÓN TELEFÓNICA O SIMILAR.', 'POSESIÓN O COMERCIALIZACIÓN DE AUDIOS Y VIDEOS DESTINADOS A LA INJERENCIA TELEFÓNICA O SIMILAR.', NULL, 'd', 'POSESIÓN O COMERCIALIZACIÓN DE EQUIPOS DESTINADOS A LA INTERCEPTACIÓN TELEFÓNICA O SIMILAR.', '(ART: 162-A)** [TITULO IV]  [CAPITULO IV]', '183991'),
(1882, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE PUBLICA, INDEBIDAMENTE, UNA CORRESPONDENCIA EPISTOLAR O TELEGRÁFICA, NO DESTINADA A LA PUBLICIDAD, AUNQUE LE HAYA SIDO DIRIGIDA, SERÁ REPRIMIDO, SI EL HECHO CAUSA ALGÚN PERJUICIO A OTRO, COMETE DELITO DE:', 'PUBLICACIÓN ILEGAL DE CORRESPONDENCIA TELEGRÁFICA.', 'PUBLICACIÓN INCORRECTA DE CORRESPONDENCIA EPISTOLAR.', 'PUBLICACIÓN INDEBIDA DE CORRESPONDENCIA.', 'PUBLICACIÓN AUTORIZADA DE CORRESPONDENCIA PRIVADA.', 'PUBLICACIÓN NO AUTORIZADA DE CORRESPONDENCIA PÚBLICA.', NULL, 'c', 'PUBLICACIÓN INDEBIDA DE CORRESPONDENCIA.', '(ART: 164)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IV]', '183992'),
(1883, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, TENIENDO INFORMACIÓN POR RAZÓN DE SU ESTADO, OFICIO, EMPLEO, PROFESIÓN O MINISTERIO, DE SECRETOS CUYA PUBLICACIÓN PUEDA CAUSAR DAÑO, LOS REVELA SIN CONSENTIMIENTO DEL INTERESADO, COMETE DELITO DE:', 'VIOLACIÓN DEL SECRETO PERSONAL.', 'VIOLACIÓN DEL SECRETO PROFESIONAL.', 'VIOLACIÓN DEL INFORME PROFESIONAL.', 'VIOLACIÓN DEL SECRETO NO AUTORIZADO.', 'VIOLACIÓN DEL SECRETO AUTORIZADO.', NULL, 'b', 'VIOLACIÓN DEL SECRETO PROFESIONAL.', '(ART: 165)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO V]', '183993'),
(1884, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL DELITO DE VIOLACIÓN DE LA LIBERTAD DE REUNIÓN, EL FUNCIONARIO PÚBLICO QUE ABUSANDO DE SU CARGO NO AUTORIZA, NO GARANTIZA, PROHÍBE O IMPIDE UNA REUNIÓN PÚBLICA, LÍCITAMENTE CONVOCADA, COMETE DELITO DE:', 'PROHIBICIÓN DE REUNIÓN PÚBLICA ILÍCITA POR FUNCIONARIO PARTICULAR.', 'PROHIBICIÓN DE REUNIÓN SIN ARMAS ILÍCITA POR FUNCIONARIO PÚBLICO.', 'PROHIBICIÓN DE REUNIÓN CON ARMAS LÍCITA POR FUNCIONARIO PARTICULAR.', 'PROHIBICIÓN DE REUNIÓN ESCANDALOSA U OBSCENA POR FUNCIONARIO PÚBLICO.', 'PROHIBICIÓN DE REUNIÓN PÚBLICA LÍCITA POR FUNCIONARIO PÚBLICO.', NULL, 'e', 'PROHIBICIÓN DE REUNIÓN PÚBLICA LÍCITA POR FUNCIONARIO PÚBLICO.', '(ART: 167)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO VI]', '183995'),
(1885, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO PÚBLICO QUE, ABUSANDO DE SU CARGO, SUSPENDE O CLAUSURA ALGÚN MEDIO DE COMUNICACIÓN SOCIAL O IMPIDE SU CIRCULACIÓN O DIFUSIÓN, COMETE DELITO DE:', 'VIOLACIÓN DE LA LIBERTAD DE EXPRESIÓN.', 'VIOLACIÓN DE LA LIBERTAD DE CULTURA.', 'VIOLACIÓN DE LA LIBERTAD DE PROGRAMACIÓN.', 'PROHIBICIÓN DE LA LIBERTAD DE EXPRESARSE.', 'PROHIBICIÓN DE LA LIBERTAD DE CULTURA.', NULL, 'a', 'VIOLACIÓN DE LA LIBERTAD DE EXPRESIÓN.', '(ART: 169)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO VIII]', '183997'),
(1886, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CON VIOLENCIA, FÍSICA O PSICOLÓGICA, GRAVE AMENAZA O APROVECHÁNDOSE DE UN ENTORNO DE COACCIÓN O DE CUALQUIER OTRO ENTORNO QUE IMPIDA A LA PERSONA DAR SU LIBRE CONSENTIMIENTO, OBLIGA A ESTA A TENER ACCESO CARNAL POR VÍA VAGINAL, ANAL O BUCAL O REALIZA CUALQUIER OTRO ACTO ANÁLOGO CON LA INTRODUCCIÓN DE UN OBJETO O PARTE DEL CUERPO POR ALGUNA DE LAS DOS PRIMERAS VÍAS, COMETE DELITO DE:', 'VIOLACIÓN ÍNTIMA.', 'VIOLACIÓN DE LA INTIMIDAD.', 'VIOLACIÓN NO CONSENTIDA.', 'VIOLACIÓN SEXUAL.', 'VIOLACIÓN PERSONAL.', NULL, 'd', 'VIOLACIÓN SEXUAL.', '(ART: 170)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IX]', '183998'),
(1887, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE TIENE ACCESO CARNAL CON UNA PERSONA POR VÍA VAGINAL, ANAL O BUCAL, O REALIZA CUALQUIER OTRO ACTO ANÁLOGO CON LA INTRODUCCIÓN DE UN OBJETO O PARTE DEL CUERPO POR ALGUNA DE LAS DOS PRIMERAS VÍAS, DESPUÉS DE HABERLA PUESTO EN ESTADO DE INCONSCIENCIA O EN LA IMPOSIBILIDAD DE RESISTIR, COMETE DELITO DE:', 'VIOLACIÓN SEXUAL DE PERSONA CONSCIENTE ANTE LA POSIBILIDAD DE RESISTIR.', 'VIOLACIÓN INTIMA DE PERSONA QUE SE RESISTE Y EN ESTADO CONSIENTE.', 'VIOLACIÓN DE PERSONA EN ESTADO DE INCONSCIENCIA O EN LA IMPOSIBILIDAD DE RESISTIR.', 'VIOLACIÓN DE PERSONA EN ESTADO DE CONSCIENCIA O EN LA POSIBILIDAD DE RESISTIR.', 'VIOLACIÓN DE PERSONA EN ESTADO DE GESTACIÓN O EN LA POSIBILIDAD DE NO RESISTIR.', NULL, 'c', 'VIOLACIÓN DE PERSONA EN ESTADO DE INCONSCIENCIA O EN LA IMPOSIBILIDAD DE RESISTIR.', '(ART: 171)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IX]', '183999'),
(1888, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE TIENE ACCESO CARNAL POR VÍA VAGINAL, ANAL O BUCAL O REALIZA CUALQUIER OTRO ACTO ANÁLOGO CON LA INTRODUCCIÓN DE UN OBJETO O PARTE DEL CUERPO POR ALGUNA DE LAS DOS PRIMERAS VÍAS, CON UN MENOR, COMETE DELITO DE:', 'VIOLACIÓN SEXUAL CULPOSA CON MENOR DE EDAD.', 'VIOLACIÓN SEXUAL DE PERSONAS INCAPACES.', 'VIOLACIÓN SEXUAL CONSENTIDA CON MENOR.', 'VIOLACIÓN SEXUAL NO CONSENTIDA CON INCAPAZ.', 'VIOLACIÓN SEXUAL DE MENOR DE EDAD.', NULL, 'e', 'VIOLACIÓN SEXUAL DE MENOR DE EDAD.', '(ART: 173)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IX]', '184001'),
(1889, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE EMPLEE, DESARROLLE, PRODUZCA, ADQUIERA, ALMACENE, CONSERVE O TRANSFIERA A UNA PERSONA NATURAL O JURÍDICA, MINAS ANTIPERSONALES, COMETE DELITO DE:', 'SUSTRACCIÓN O ARREBATO DE ARMAS DE FUEGO.', 'FABRICACIÓN, SUMINISTRO DE MATERIALES Y RESIDUOS PELIGROSOS.', 'EMPLEO, PRODUCCIÓN Y TRANSFERENCIA DE MINAS ANTIPERSONALES.', 'USO DE ARMA EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', 'EMPLEO Y TRANSFERENCIA DE EXPLOSIVOS ANTIPERSONALES.', NULL, 'c', 'EMPLEO, PRODUCCIÓN Y TRANSFERENCIA DE MINAS ANTIPERSONALES.', '(ART: 279-D)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184002'),
(1890, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SIN CUMPLIR CON LA NORMATIVIDAD VIGENTE Y/O SIN CONTAR CON LA AUTORIZACIÓN EXPRESA, QUE PARA EL EFECTO EXPIDA LA AUTORIDAD COMPETENTE, REALICE U ORDENE REALIZAR A SUS SUBORDINADOS LA ACTIVIDAD DE ENSAMBLADO DE ÓMNIBUS SOBRE CHASIS ORIGINALMENTE DISEÑADO Y FABRICADO PARA EL TRANSPORTE DE MERCANCÍAS CON CORTE O ALARGAMIENTO DEL CHASIS; COMETE DELITO DE:', 'COMERCIALIZACIÓN Y UTILIZACIÓN, EN EL SERVICIO PÚBLICO DE TRANSPORTE CON ESTRUCTURAS PROHIBIDAS.', 'ENSAMBLADO, COMERCIALIZACIÓN Y UTILIZACIÓN, EN EL SERVICIO PÚBLICO, DE TRANSPORTE DE OMNIBUSES SOBRE', 'ENSAMBLADO, COMERCIALIZACIÓN Y UTILIZACIÓN DE ÓMNIBUS SOBRE CHASIS DE SERVICIO PUBLICO.', 'DISEÑO Y FABRICACIÓN PARA EL TRANSPORTE DE MERCADERÍAS SOBRE CHASIS DE CAMIÓN.', 'AUTORIZACIÓN PARA EL ENSAMBLADO DE CHASIS DE CAMIÓN PARA TRANSPORTE PÚBLICO.', NULL, 'b', 'ENSAMBLADO, COMERCIALIZACIÓN Y UTILIZACIÓN, EN EL SERVICIO PÚBLICO, DE TRANSPORTE DE OMNIBUSES', '(ART: 279-E)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184003'),
(1891, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN ESTAR DEBIDAMENTE AUTORIZADO, FABRICA, ENSAMBLA, MODIFICA, ALMACENA, SUMINISTRA, COMERCIALIZA, TRAFICA, USA, PORTA O TIENE EN SU PODER, ARMAS DE FUEGO DE CUALQUIER TIPO, MUNICIONES, ACCESORIOS O', 'FABRICACIÓN, COMERCIALIZACIÓN, USO O PORTE DE ARMAS.', 'FABRICACIÓN DE ARMAS DE FUEGO Y EXPLOSIVOS.', 'ENSAMBLAJE DE ARMAS DE FUEGO Y MATERIAL DE GUERRA.', 'MODIFICACIÓN DE ARMAS DE FUEGO PARA USO PRIVADO.', 'COMERCIALIZACIÓN Y TRÁFICO DE ARMAS DE FUEGO.', NULL, 'a', 'FABRICACIÓN, COMERCIALIZACIÓN, USO O PORTE DE ARMAS.', '(ART: 279-G)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184005'),
(1892, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CONTACTA CON UN MENOR DE CATORCE AÑOS PARA SOLICITAR U OBTENER DE ÉL MATERIAL PORNOGRÁFICO, O PARA PROPONERLE LLEVAR A CABO CUALQUIER ACTO DE CONNOTACIÓN SEXUAL CON ÉL O CON TERCEROS, COMETE DELITO DE:', 'PROPOSICIONES SEXUALES A NIÑOS Y JÓVENES.', 'PROPOSICIONES SEXUALES A NIÑOS Y ADOLESCENTES.', 'PROPOSICIONES SEXUALES A NIÑAS Y ADOLESCENTES.', 'PROPOSICIONES SEXUALES A NIÑOS, NIÑAS Y JÓVENES.', 'PROPOSICIONES A NIÑOS, NIÑAS Y ADOLESCENTES CON FINES SEXUALES.', NULL, 'e', 'PROPOSICIONES A NIÑOS, NIÑAS Y ADOLESCENTES CON FINES SEXUALES.', '(ART: 183-B)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO XI]', '184007'),
(1893, 'Decreto Legislativo Nº 635 Código Penal', 'EXCUSA ABSOLUTORIA. EXENCIÓN DE PENA: NO SON REPRIMIBLES, SIN PERJUICIO DE LA REPARACIÓN CIVIL, LOS HURTOS, APROPIACIONES, DEFRAUDACIONES O DAÑOS QUE SE CAUSEN:', 'LOS CÓNYUGES, CONCUBINOS, ASCENDIENTES, DESCENDIENTES Y AFINES EN LÍNEA ASCENDENTE.', 'LOS CÓNYUGES, CONCUBINOS, ASCENDIENTES, DESCENDIENTES Y AFINES EN LÍNEA DESCENDIENTE.', 'LOS CÓNYUGES, VECINOS, ASCENDIENTES, DESCENDIENTES Y AFINES EN LÍNEA RECTA.', 'LOS CÓNYUGES, CONSUEGROS, ASCENDIENTES, DESCENDIENTES Y AFINES EN LÍNEA RECTA.', 'LOS CÓNYUGES, CONCUBINOS, ASCENDIENTES, DESCENDIENTES Y AFINES EN LÍNEA RECTA.', NULL, 'e', 'LOS CÓNYUGES, CONCUBINOS, ASCENDIENTES, DESCENDIENTES Y AFINES EN LÍNEA RECTA.', '(ART: 208)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO XI]', '184009'),
(1894, 'Decreto Legislativo Nº 635 Código Penal', 'EL MÉDICO, OBSTETRA, FARMACÉUTICO O CUALQUIER PROFESIONAL SANITARIO QUE ABUSA DE SU CIENCIA O ARTE PARA CAUSAR EL ABORTO, SE LE CONSIDERARÁ:', 'ATENUACIÓN DE LA PENA POR LA CALIDAD DEL SUJETO.', 'AUMENTO DE LA PENA POR LA CALIDAD DEL SUJETO.', 'INCREMENTO DE LA PENA POR LA CALIDAD DEL SUJETO.', 'AGRAVACIÓN DE LA PENA POR LA CALIDAD DEL SUJETO.', 'DISMINUCIÓN DE LA PENA POR LA CALIDAD DEL SUJETO.', NULL, 'd', 'AGRAVACIÓN DE LA PENA POR LA CALIDAD DEL SUJETO.', '(ART: 117)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '184010'),
(1895, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN TÍTULO O NOMBRAMIENTO, USURPA UNA FUNCIÓN PÚBLICA, O LA FACULTAD DE DAR ÓRDENES MILITARES O POLICIALES, O EL QUE HALLÁNDOSE DESTITUIDO, CESADO, SUSPENDIDO O SUBROGADO DE SU CARGO CONTINÚA EJERCIÉNDOLO, O EL QUE EJERCE FUNCIONES CORRESPONDIENTES A CARGO DIFERENTE DEL QUE TIENE, COMETE DELITO DE:', 'DESACATO.', 'RESISTENCIA A LA AUTORIDAD.', 'NOMBRAMIENTO INDEBIDO.', 'USURPACIÓN DE FUNCIÓN PÚBLICA.', 'USURPACIÓN DE LA AUTORIDAD AGRAVADA.', NULL, 'd', 'USURPACIÓN DE FUNCIÓN PÚBLICA.', '(ART: 361)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION I]', '184011'),
(1896, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE EJERCE PROFESIÓN SIN REUNIR LOS REQUISITOS LEGALES REQUERIDOS, COMETE DELITO DE:', 'DESACATO A LA AUTORIDAD.', 'EJERCICIO ILEGAL DE PROFESIÓN.', 'EJERCICIO LEGAL DE LA PROFESIÓN.', 'PROFESIÓN ILEGAL.', 'EJERCICIO DE PROFESIÓN PUNIBLE.', NULL, 'b', 'EJERCICIO ILEGAL DE PROFESIÓN.', '(ART: 363)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION I]', '184012'),
(1897, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, CON LA INTENCIÓN DE DESTRUIR, TOTAL O PARCIALMENTE, A UN GRUPO NACIONAL, ÉTNICO, SOCIAL O RELIGIOSO, REALIZA: TRANSFERENCIA FORZADA DE NIÑOS A OTRO GRUPO, COMETE DELITO DE:', 'DESAPARICIÓN FORZADA.', 'SECUESTRO.', 'GENOCIDIO.', 'DISCRIMINACIÓN.', 'MANIPULACIÓN GENÉTICA.', NULL, 'c', 'GENOCIDIO.', '(ART: 319)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO I]', '184013'),
(1898, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, PÚBLICAMENTE, OSTENTA INSIGNIAS O DISTINTIVOS DE UNA FUNCIÓN O CARGO QUE NO EJERCE O SE ARROGA GRADO ACADÉMICO, TÍTULO PROFESIONAL U HONORES QUE NO LE CORRESPONDEN, COMETE DELITO DE:', 'EJERCICIO DE DISTINTIVOS DE FUNCIÓN PÚBLICA QUE NO EJERCE.', 'USO DE DISTINTIVOS DE FUNCIÓN Y CARGOS QUE NO EJERCE LEGALMENTE.', 'EJERCICIO DE DISTINTIVOS DE FUNCIÓN, AUTORIDAD O CARGOS QUE NO LE PERTENECE.', 'UTILIZACIÓN DE INSIGNIAS DE FUNCIÓN O CARGOS QUE NO AMERITAN.', 'OSTENTACIÓN DE DISTINTIVOS DE FUNCIÓN O CARGOS QUE NO EJERCE.', NULL, 'e', 'OSTENTACIÓN DE DISTINTIVOS DE FUNCIÓN O CARGOS QUE NO EJERCE.', '(ART: 362)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION I]', '184014'),
(1899, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN ALZAMIENTO PÚBLICO, MEDIANTE VIOLENCIA O AMENAZA, IMPIDE A UNA AUTORIDAD O A UN FUNCIONARIO O SERVIDOR PÚBLICO EJERCER SUS FUNCIONES O LE OBLIGA A PRACTICAR UN DETERMINADO ACTO DE SUS FUNCIONES O LE ESTORBA EN EL EJERCICIO DE ÉSTAS, COMETE DELITO DE:', 'RESISTENCIA Y AMENAZA A LA AUTORIDAD.', 'VIOLENCIA Y RESISTENCIA.', 'VIOLENCIA CONTRA LA AUTORIDAD PARA OBLIGARLE A ALGO.', 'VIOLENCIA CONTRA UN FUNCIONARIO PRIVADO.', 'VIOLENCIA Y AMENAZA A FUNCIONARIO PÚBLICO.', NULL, 'c', 'VIOLENCIA CONTRA LA AUTORIDAD PARA OBLIGARLE A ALGO.', '(ART: 365)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184016'),
(1900, 'Decreto Legislativo Nº 635 Código Penal', 'EL PROFESIONAL QUE AMPARA CON SU FIRMA EL TRABAJO DE QUIEN NO TIENE TÍTULO PARA EJERCERLO, COMETE DELITO DE:', 'EJERCICIO ILEGAL DE PROFESIÓN.', 'OSTENTACIÓN DE TÍTULOS U HONORES QUE NO EJERCE.', 'PARTICIPACIÓN EN EJERCICIO ILEGAL DE LA PROFESIÓN.', 'PARTICIPACIÓN DEL EJERCICIO LÍCITO PROFESIONAL.', 'AMPARO EN EL EJERCICIO PROFESIONAL ILEGAL.', NULL, 'c', 'PARTICIPACIÓN EN EJERCICIO ILEGAL DE LA PROFESIÓN.', '(ART: 364)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION I]', '184017'),
(1901, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, CON LA INTENCIÓN DE DESTRUIR, TOTAL O PARCIALMENTE, A UN GRUPO ÉTNICO REALIZA, MATANZA DE MIEMBROS DEL GRUPO, COMETE DELITO DE:', 'HOMICIDIO AGRAVADO.', 'DESAPARICIÓN FORZADA.', 'HOMICIDIO CALIFICADO.', 'GENOCIDIO.', 'HOMICIDIO FORZADO.', NULL, 'd', 'GENOCIDIO.', '(ART: 319)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO I]', '184018'),
(1902, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE EMPLEA INTIMIDACIÓN O VIOLENCIA CONTRA UN FUNCIONARIO PÚBLICO O CONTRA LA PERSONA QUE LE PRESTA ASISTENCIA EN VIRTUD DE UN DEBER LEGAL O ANTE REQUERIMIENTO DE AQUÉL, PARA IMPEDIR O TRABAR LA EJECUCIÓN DE UN ACTO PROPIO DE LEGÍTIMO EJERCICIO DE SUS FUNCIONES, COMETE DELITO DE:', 'VIOLENCIA CONTRA LA AUTORIDAD PÚBLICA PARA NO IMPEDIR EJERCICIO FUNCIONAL.', 'VIOLENCIA CONTRA LA FUNCIONARIO PÚBLICO PARA OBLIGARLE A ALGO.', 'VIOLENCIA CONTRA LA AUTORIDAD PARA COACCIONARLE.', 'VIOLENCIA CONTRA LA AUTORIDAD PARA IMPEDIR EL EJERCICIO DE SUS FUNCIONES.', 'VIOLENCIA CONTRA FUNCIONARIO PÚBLICO EN EJERCICIO LEGAL.', NULL, 'd', 'VIOLENCIA CONTRA LA AUTORIDAD PARA IMPEDIR EL EJERCICIO DE SUS FUNCIONES.', '(ART: 366)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184019'),
(1903, 'Decreto Legislativo Nº 635 Código Penal', 'UNA DE LAS FORMAS AGRAVADAS DE LOS DELITOS DE VIOLENCIA Y RESISTENCIA A LA AUTORIDAD (VIOLENCIA CONTRA LA AUTORIDAD PARA OBLIGARLE A ALGO Y VIOLENCIA CONTRA LA AUTORIDAD PARA IMPEDIR EL EJERCICIO DE SUS FUNCIONES), ES CUANDO:', 'EL HECHO SE REALIZA POR DOS O MÁS PERSONAS.', 'EL HECHO SE COMETE RESPECTO A INVESTIGACIONES.', 'EL AUTOR CAUSA UNA LESIÓN LEVE QUE HAYA PODIDO PREVER.', 'EL HECHO SE REALIZA POR UNA MULTITUD DE PERSONAS.', 'EL HECHO SE REALIZA DURANTE LA NOCHE Y EN CASA HABITADA.', NULL, 'a', 'EL HECHO SE REALIZA POR DOS O MÁS PERSONAS.', '(ART: 367)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184021'),
(1904, 'Decreto Legislativo Nº 635 Código Penal', 'UNA DE LAS FORMAS AGRAVADAS DE LOS DELITOS DE VIOLENCIA Y RESISTENCIA A LA AUTORIDAD (VIOLENCIA CONTRA LA AUTORIDAD PARA OBLIGARLE A ALGO Y VIOLENCIA CONTRA LA AUTORIDAD PARA IMPEDIR EL EJERCICIO DE SUS FUNCIONES), ES CUANDO:', 'EL HECHO SE REALIZA POR UNA O DOS PERSONAS.', 'EL AUTOR ES FUNCIONARIO O SERVIDOR PÚBLICO.', 'EL HECHO SE REALIZA DURANTE LA NOCHE Y EN CASA HABITADA.', 'EL AUTOR CAUSA UNA LESIÓN LEVE QUE HAYA PODIDO PREVER.', 'EL AUTOR ES FUNCIONARIO O SERVIDOR PÚBLICO O PRIVADO.', NULL, 'b', 'EL AUTOR ES FUNCIONARIO O SERVIDOR PÚBLICO.', '(ART: 367)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184022'),
(1905, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO, O CUALQUIER PERSONA CON EL CONSENTIMIENTO O AQUIESCENCIA DE AQUEL, QUE DE CUALQUIER FORMA PRIVA A OTRO DE SU LIBERTAD Y SE HAYA NEGADO A RECONOCER DICHA PRIVACIÓN DE LIBERTAD O A DAR INFORMACIÓN CIERTA SOBRE EL DESTINO O EL PARADERO DE LA VÍCTIMA; COMETE DELITO DE:', 'GENOCIDIO.', 'SECUESTRO AGRAVADO.', 'COACCIÓN DE LA LIBERTAD.', 'DESAPARICIÓN FORZADA DE PERSONAS.', 'SECUESTRO SEGUIDO DE MUERTE.', NULL, 'd', 'DESAPARICIÓN FORZADA DE PERSONAS.', '(ART: 320)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO II]', '184024'),
