(1910, 'Decreto Legislativo Nº 635 Código Penal', 'UNA DE LAS FORMAS AGRAVADAS DE LOS DELITOS DE VIOLENCIA Y RESISTENCIA A LA AUTORIDAD (VIOLENCIA CONTRA LA AUTORIDAD PARA OBLIGARLE A ALGO Y VIOLENCIA CONTRA LA AUTORIDAD PARA IMPEDIR EL EJERCICIO DE SUS FUNCIONES), ES CUANDO:', 'EL HECHO SE REALIZA EN CONTRA DE UNA AUTORIDAD ELEGIDA POR MANDATO POPULAR, EN EL EJERCICIO DE SUS', 'EL HECHO SE REALIZA EN CONTRA DE UNA AUTORIDAD ELEGIDA POR MANDATO LEGAL, EN EL EJERCICIO DE SUS', 'EL HECHO SE REALIZA EN CONTRA DE UNA AUTORIDAD ELEGIDA POR MANDATO ELECTORAL, EN EL EJERCICIO DE SUS', 'EL HECHO SE REALIZA EN CONTRA DE UNA AUTORIDAD ELEGIDA POR MANDATO CONSTITUCIONAL, EN EL EJERCICIO DE', 'EL HECHO SE REALIZA EN CONTRA DE UNA AUTORIDAD ELEGIDA POR MANDATO SUPREMO, EN EL EJERCICIO DE SUS', NULL, 'a', 'EL HECHO SE REALIZA EN CONTRA DE UNA AUTORIDAD ELEGIDA POR MANDATO POPULAR, EN EL EJERCICIO', '(ART: 367)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184031'),
(1911, 'Decreto Legislativo Nº 635 Código Penal', 'ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE DESAPARICIÓN FORZADA DE PERSONAS, SI LA VÍCTIMA:', 'SE ENCUENTRA DELICADA DE SALUD.', 'SE ENCUENTRA EN ESTADO PUERPERAL.', 'ES MUJER.', 'SE ENCUENTRA EN ESTADO DE GESTACIÓN.', 'TIENE HIJOS MENORES DE EDAD A SU CUIDADO.', NULL, 'd', 'SE ENCUENTRA EN ESTADO DE GESTACIÓN.', '(ART: 320)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO II]', '184032'),
