(1919, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE DESOBEDECE O RESISTE LA ORDEN LEGALMENTE IMPARTIDA POR UN FUNCIONARIO PÚBLICO EN EL EJERCICIO DE SUS ATRIBUCIONES, SALVO QUE SE TRATE DE LA PROPIA DETENCIÓN, COMETE DELITO DE:', 'VIOLENCIA CONTRA LA AUTORIDAD PARA IMPEDIR EL EJERCICIO DE SUS FUNCIONES.', 'VIOLENCIA Y RESISTENCIA A LA AUTORIDAD.', 'DESACATO.', 'RESISTENCIA O DESOBEDIENCIA A LA AUTORIDAD.', 'DESACATO AGRAVADO.', NULL, 'd', 'RESISTENCIA O DESOBEDIENCIA A LA AUTORIDAD.', '(ART: 368)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184042'),
