(1925, 'Decreto Legislativo Nº 635 Código Penal', 'EL MÉDICO O CUALQUIER PROFESIONAL SANITARIO QUE COOPERARA EN LA PERPETRACIÓN DEL DELITO DE TORTURA, SERÁ REPRIMIDO CON:', 'UN TERCIO MÁS, DE LA PENA DE LOS AUTORES.', 'UN TERCIO MENOS, DE LA PENA DE LOS AUTORES.', 'LA MITAD DE LA PENA DE LOS AUTORES.', 'LA MISMA PENA DE LOS AUTORES.', 'LA MISMA PENA DE LOS COLABORADORES.', NULL, 'd', 'LA MISMA PENA DE LOS AUTORES.', '(ART: 322)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO III]', '184050'),
