(1927, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, POR SÍ O MEDIANTE TERCEROS, REALIZA ACTOS DE DISTINCIÓN, EXCLUSIÓN, RESTRICCIÓN O PREFERENCIA QUE ANULAN O MENOSCABAN EL RECONOCIMIENTO, GOCE O EJERCICIO DE CUALQUIER DERECHO DE UNA PERSONA O GRUPO DE PERSONAS RECONOCIDO EN LA LEY, LA CONSTITUCIÓN O EN LOS TRATADOS DE DERECHOS HUMANOS DE LOS CUALES EL PERÚ ES PARTE, BASADOS EN MOTIVOS RACIALES, RELIGIOSOS, NACIONALIDAD, EDAD, SEXO, ORIENTACIÓN SEXUAL, IDENTIDAD DE GÉNERO, IDIOMA, IDENTIDAD ÉTNICA O CULTURAL, OPINIÓN, NIVEL SOCIO ECONÓMICO, CONDICIÓN MIGRATORIA, DISCAPACIDAD, CONDICIÓN DE SALUD, FACTOR GENÉTICO, FILIACIÓN, O CUALQUIER OTRO MOTIVO, COMETE DELITO DE:', 'TORTURA.', 'DISCRIMINACIÓN E INCITACIÓN A LA DISCRIMINACIÓN.', 'DISCRIMINACIÓN Y SEGREGACIÓN.', 'COACCIÓN.', 'CONTRA LA PAZ SOCIAL.', NULL, 'b', 'DISCRIMINACIÓN E INCITACIÓN A LA DISCRIMINACIÓN.', '(ART: 323)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO IV]', '184052'),
(1928, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, MEDIANTE VIOLENCIA O AMENAZA, IMPIDE A UNA AUTORIDAD ELEGIDA EN UN PROCESO ELECTORAL GENERAL, PARLAMENTARIO, REGIONAL O MUNICIPAL JURAMENTAR, ASUMIR O EJERCER SUS FUNCIONES, COMETE DELITO DE:', 'VIOLENCIA CONTRA AUTORIDADES PÚBLICAS.', 'VIOLENCIA CONTRA AUTORIDADES ELEGIDAS.', 'VIOLENCIA CONTRA AUTORIDADES CONSTITUCIONALES.', 'VIOLENCIA CONTRA AUTORIDADES NOMBRADAS.', 'VIOLENCIA CONTRA AUTORIDADES O SERVIDORES.', NULL, 'b', 'VIOLENCIA CONTRA AUTORIDADES ELEGIDAS.', '(ART: 369)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184053'),
(1929, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, POR SÍ, REALIZA ACTOS DE DISTINCIÓN, QUE ANULAN O MENOSCABAN EL RECONOCIMIENTO, GOCE O EJERCICIO DE CUALQUIER DERECHO DE UNA PERSONA O GRUPO DE PERSONAS RECONOCIDO EN LOS TRATADOS DE DERECHOS HUMANOS DE LOS CUALES EL PERÚ ES PARTE, BASADOS EN MOTIVOS DE ORIENTACIÓN SEXUAL, COMETE DELITO DE:', 'VIOLENCIA DE GÉNERO.', 'DISCRIMINACIÓN Y SEGREGACIÓN.', 'ABUSO DE GÉNERO.', 'DISCRIMINACIÓN E INCITACIÓN A LA DISCRIMINACIÓN.', 'CONTRA LA IDENTIDAD DE GÉNERO.', NULL, 'd', 'DISCRIMINACIÓN E INCITACIÓN A LA DISCRIMINACIÓN.', '(ART: 323)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO IV]', '184055'),
(1930, 'Decreto Legislativo Nº 635 Código Penal', 'EL TESTIGO, PERITO, TRADUCTOR O INTÉRPRETE QUE, SIENDO LEGALMENTE REQUERIDO, SE ABSTIENE DE COMPARECER O PRESTAR LA DECLARACIÓN, INFORME O SERVICIO RESPECTIVO, COMETE DELITO DE:', 'OMISIÓN A COLABORAR CON LA ADMINISTRACIÓN PENAL.', 'NEGATIVA A COLABORAR CON LA ADMINISTRACIÓN DE JUSTICIA.', 'NEGATIVA A LITIGAR CON LA ADMINISTRACIÓN PÚBLICA.', 'NEGATIVA A AYUDAR A LA ADMINISTRACIÓN PÚBLICA.', 'NEGATIVA A AYUDAR CON LA ADMINISTRACIÓN ESTATAL.', NULL, 'b', 'NEGATIVA A COLABORAR CON LA ADMINISTRACIÓN DE JUSTICIA.', '(ART: 371)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184056'),
(1931, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SUSTRAE, OCULTA, CAMBIA, DESTRUYE O INUTILIZA OBJETOS, REGISTROS O DOCUMENTOS DESTINADOS A SERVIR DE PRUEBA ANTE LA AUTORIDAD COMPETENTE QUE SUSTANCIA UN PROCESO, CONFIADOS A LA CUSTODIA DE UN FUNCIONARIO O DE OTRA PERSONA, COMETE DELITO DE:', 'ATENTADO CONTRA DOCUMENTOS QUE SIRVEN DE PRUEBA EN EL JUICIO CIVIL.', 'ATENTADO CONTRA DOCUMENTOS QUE SIRVEN DE PRUEBA EN LA INVESTIGACIÓN.', 'ATENTADO CONTRA DOCUMENTOS QUE SIRVEN DE PRUEBA EN EL PROCESO.', 'ATENTADO CONTRA DOCUMENTOS QUE SIRVEN DE PRUEBA EN EL PROCESO CONTENCIOSO ADMINISTRATVO.', 'ATENTADO CONTRA DOCUMENTOS QUE SIRVEN DE PRUEBA EN EL JUICIO PENAL.', NULL, 'c', 'ATENTADO CONTRA DOCUMENTOS QUE SIRVEN DE PRUEBA EN EL PROCESO.', '(ART: 372)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION II]', '184057'),
(1932, 'Decreto Legislativo Nº 635 Código Penal', 'EL DELITO DE DISCRIMINACIÓN SE AGRAVA, SI EL HECHO SE REALIZA MEDIANTE ACTOS DE VIOLENCIA FISICA O MENTAL:', 'A TRAVÉS DEL INTERNET U OTRO MEDIO ANALOGO.', 'A TRAVÉS DE REUNIONES PÚBLICAS.', 'HACIENDO USO DE LAS VÍAS DE COMUNICACIÓN PÚBLICAS.', 'A TRAVÉS DE ORGANISMOS DEL ESTADO.', 'A TRAVÉS E ORGANISMOS PRIVADAS.', NULL, 'a', 'A TRAVÉS DEL INTERNET U OTRO MEDIO ANALOGO.', '(ART: 323)** [LIBRO SEGUNDO]  [TITULO XIV-A]  [CAPITULO IV]', '184059'),
(1933, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA DESORDEN EN LA SALA DE SESIONES DEL CONGRESO O DE LAS CÁMARAS LEGISLATIVAS, DE LAS ASAMBLEAS REGIONALES, DE LOS CONSEJOS MUNICIPALES O DE LOS TRIBUNALES DE JUSTICIA U OTRO LUGAR DONDE LAS AUTORIDADES PÚBLICAS EJERCEN SUS FUNCIONES O EL QUE ENTRA ARMADO EN DICHOS LUGARES; COMETE DELITO DE:', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD LEGISLA PARLAMENTARIAMENTE.', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SUS ATRIBUCIONES.', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD ADMINISTRA JUSTICIA.', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SU FUNCIÓN.', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD SANCIONA.', NULL, 'd', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SU FUNCIÓN.', '(ART: 375)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION III]', '184060'),
(1934, 'Decreto Legislativo Nº 635 Código Penal', 'EL DELITO DE PELIGRO COMÚN, POR MEDIO DE INCENDIO, EXPLOSIÓN O LIBERANDO CUALQUIER CLASE DE ENERGÍA, CREA UN PELIGRO COMÚN PARA:', 'EL ORDEN SOCIAL.', 'LAS PERSONAS O LOS BIENES.', 'LOS OBJETOS.', 'SOLO CONTRA LAS PERSONAS.', 'CONTRA LOS ELEMENTOS MATERIALES.', NULL, 'b', 'LAS PERSONAS O LOS BIENES.', '(ART: 273)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184062'),
(1935, 'Decreto Legislativo Nº 635 Código Penal', 'EL DELITO DE CONDUCCIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN, CUANDO EL AGENTE PRESTA SERVICIO DE TRANSPORTE PÚBLICO DE PASAJEROS, SE CONFIGURA CUANDO HAY PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN:', 'SUPERIOR A 0,50 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'IGUAL O MAYOR A 0,5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'IGUAL O MAYOR DE 0,25 GRAMOS-LITRO O BAJO EFECTO DE DROGAS TÓXICAS.', 'SUPERIOR DE 0,25 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'SUPERIOR A 0,05 GRAMOS-LITRO O BAJO EFECTO DE DROGAS TÓXICAS.', NULL, 'd', 'SUPERIOR DE 0,25 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', '(ART: 274)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184063'),
(1936, 'Decreto Legislativo Nº 635 Código Penal', 'EL DELITO DE CONDUCCIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN, SE CONFIGURA CUANDO HAY PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN:', 'MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'MENOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'IGUAL O MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'IGUAL O MAYOR DE 0.3 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'MAYOR DE 0.25 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', NULL, 'a', 'MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE DROGAS TÓXICAS.', '(ART: 274)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184064'),
(1937, 'Decreto Legislativo Nº 635 Código Penal', 'EL DELITO DE MANIPULACIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN, SE CONFIGURA CUANDO EL AGENTE OPERA O MANIOBRA HERRAMIENTA O MÁQUINA QUE REPRESENTE RIESGO O PELIGRO, CON PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN:', 'MAYOR O IGUAL DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES.', 'MAYOR DE 0.1 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS.', 'MAYOR O IGUAL DE 0.1 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES.', 'MAYOR DE 1.5 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES, DROGAS TÓXICAS.', NULL, 'c', 'MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS.', '(ART: 274-A)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184065'),
(1938, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ENCONTRÁNDOSE EN ESTADO DE EBRIEDAD, CON PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE ESTUPEFACIENTES, DROGAS TÓXICAS, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS, OPERA O MANIOBRA INSTRUMENTO, HERRAMIENTA, MÁQUINA U OTRO ANÁLOGO QUE REPRESENTE RIESGO O PELIGRO; COMETE:', 'DELITO DE PELIGRO COMÚN - MANIPULACIÓN DE INSTRUMENTOS EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', 'DELITO DE RIESGO COMÚN - MANIPULACIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', 'DELITO DE PELIGRO COMÚN - MANIPULACIÓN EN ESTADO DE INHABILITACIÓN.', 'DELITO DE PELIGRO EMINENTE - MANIPULACIÓN EN ESTADO DE EBRIEDAD O INTERNACIÓN.', 'DELITO DE PELIGRO INMINENTE - RIESGOS EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', NULL, 'a', 'DELITO DE PELIGRO COMÚN - MANIPULACIÓN DE INSTRUMENTOS EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', '(ART: 274-A)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184066'),
(1939, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, PARA IMPEDIR O DIFICULTAR LAS TAREAS DE DEFENSA, SUSTRAE, OCULTA, DESTRUYE O INUTILIZA MATERIALES, INSTRUMENTOS U OTROS MEDIOS DESTINADOS A LA DEFENSA COMÚN, COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', 'PELIGRO DE OBRAS DESTINADAS A LA DEFENSA COMÚN.', 'DAÑOS DE OBRAS DESTINADAS A LA DEFENSA COMUNAL.', 'DAÑOS DE OBRAS PARA LA DEFENSA COMÚN.', 'PELIGRO DE OBRAS DESTINADAS A LA DEFENSA COMUNAL.', 'DAÑOS DE OBRAS SOCIALES.', NULL, 'c', 'DAÑOS DE OBRAS PARA LA DEFENSA COMÚN.', '(ART: 277)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184068'),
(1940, 'Decreto Legislativo Nº 635 Código Penal', 'QUE DELITO COMETE EL CONDUCTOR, CAPITÁN, COMANDANTE, PILOTO, TÉCNICO, MAQUINISTA O MECÁNICO DE CUALQUIER MEDIO DE TRANSPORTE, QUE ABANDONA SU RESPECTIVO SERVICIO ANTES DEL TÉRMINO DEL VIAJE:', 'DELITO DE ABANDONO DE TRANSPORTE PRIVADO.', 'DELITO DE ABANDONO DE SERVICIO PÚBLICO.', 'DELITO DE ABANDONO DE SERVICIO DE TRANSPORTE.', 'DELITO DE PELIGRO COMÚN.', 'DELITO DE IMPEDIMENTO DE FUNCIONES EN UN MEDIO DE TRANSPORTE.', NULL, 'c', 'DELITO DE ABANDONO DE SERVICIO DE TRANSPORTE.', '(ART: 284)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO II]', '184069'),
(1941, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN ESTAR DEBIDAMENTE AUTORIZADO, FABRICA, ENSAMBLA, MODIFICA, ALMACENA, SUMINISTRA, COMERCIALIZA, OFRECE O TIENE EN SU PODER BOMBAS, ARTEFACTOS O MATERIALES EXPLOSIVOS, INFLAMABLES, ASFIXIANTES O TÓXICOS O SUSTANCIAS O MATERIALES DESTINADOS PARA SU PREPARACIÓN; COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', 'FABRICACIÓN, SUMINISTRO O TENENCIA Y ALMACENAMIENTO DE MATERIALES PELIGROSOS Y RESIDUOS.', 'FABRICACIÓN, SUMINISTRO, ENSAMBLAJE O TENENCIA DE MATERIALES Y RESIDUOS PELIGROSOS.', 'FABRICACIÓN O TENENCIA DE INSUMOS QUÍMICOS PELIGROSOS.', 'FABRICACIÓN O TENENCIA DE MATERIALES QUÍMICOS PELIGROSOS.', 'FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES PELIGROSOS Y RESIDUOS PELIGROSOS.', NULL, 'e', 'FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES PELIGROSOS Y RESIDUOS PELIGROSOS.', '(ART: 279)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184071'),
(1942, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN ESTAR DEBIDAMENTE AUTORIZADO, TRANSFORMA O TRANSPORTA MATERIALES Y RESIDUOS PELIGROSOS SÓLIDOS, LÍQUIDOS, GASEOSOS U OTROS, QUE PONGA EN PELIGRO LA VIDA, SALUD, PATRIMONIO PÚBLICO O PRIVADO Y EL MEDIO AMBIENTE, COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', 'ELABORACIÓN DE INSUMOS QUÍMICOS PELIGROSOS Y RESIDUOS QUÍMICOS PELIGROSOS.', 'FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES PELIGROSOS Y RESIDUOS PELIGROSOS.', 'FABRICACIÓN Y TENENCIA DE INSUMOS QUÍMICOS PELIGROSOS.', 'FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES Y RESIDUOS.', 'TENENCIA Y TRANSPORTE DE INSUMOS QUÍMICOS CONTRA EL MEDIO AMBIENTE.', NULL, 'b', 'FABRICACIÓN, SUMINISTRO O TENENCIA DE MATERIALES PELIGROSOS Y RESIDUOS PELIGROSOS.', '(ART: 279)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184072'),
(1943, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE PRODUCE, DESARROLLA, COMERCIALIZA, ALMACENA, VENDE, ADQUIERE, USA O POSEE ARMAS QUÍMICAS, - CONTRAVINIENDO LAS PROHIBICIONES ESTABLECIDAS EN LA CONVENCIÓN SOBRE ARMAS QUÍMICAS ADOPTADA POR LAS NACIONES UNIDAS EN 1992- O LAS QUE TRANSFIERE A OTRO, O EL QUE PROMUEVE, FAVORECE O FACILITA QUE SE REALICEN DICHOS ACTOS, COMETE DELITO DE PELIGRO COMÚN EN LA MODALIDAD DE:', 'PRODUCCIÓN, DESARROLLO Y COMERCIALIZACIÓN ILEGAL DE ARMAS QUÍMICAS.', 'CONTRA LA CONVENCIÓN SOBRE ARMAS QUÍMICAS.', 'COMERCIALIZACIÓN DE ARMAS QUÍMICAS AUTORIZADAS POR LA CONVENCIÓN.', 'PRODUCCIÓN, TRÁFICO LEGAL DE ARMAS, MUNICIONES Y EXPLOSIVOS.', 'USO DE ARMAS QUÍMICAS SIN AUTORIZACIÓN DE LA CONVENCIÓN.', NULL, 'a', 'PRODUCCIÓN, DESARROLLO Y COMERCIALIZACIÓN ILEGAL DE ARMAS QUÍMICAS.', '(ART: 279-A)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184073'),
(1944, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN ESTAR DEBIDAMENTE AUTORIZADO, FABRICA, IMPORTA, EXPORTA, DEPOSITA, TRANSPORTA, COMERCIALIZA O USA PRODUCTOS PIROTÉCNICOS DE CUALQUIER TIPO, O LOS QUE VENDAN ESTOS PRODUCTOS A MENORES DE EDAD; COMETE DELITO DE:', 'FABRICACIÓN Y TENENCIA DE PRODUCTO PIROTÉCNICOS.', 'SUSTRACCIÓN O ARREBATO DE PRODUCTOS PIROTÉCNICOS.', 'TRÁFICO DE PRODUCTOS PIROTÉCNICOS.', 'VENTA DE PRODUCTOS PIROTÉCNICOS A MENORES DE EDAD.', 'TRÁFICO DE FUEGOS ARTIFICIALES.', NULL, 'c', 'TRÁFICO DE PRODUCTOS PIROTÉCNICOS.', '(ART: 279-C)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184075'),
(1945, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, VALIÉNDOSE DE SU CONDICIÓN DE FUNCIONARIO O SERVIDOR PÚBLICO, CONDICIONA LA DISTRIBUCIÓN DE BIENES O LA PRESTACIÓN DE SERVICIOS CORRESPONDIENTES A PROGRAMAS PÚBLICOS DE APOYO O DESARROLLO SOCIAL, CON LA FINALIDAD DE OBTENER VENTAJA POLÍTICA Y/O ELECTORAL DE CUALQUIER TIPO EN FAVOR PROPIO O DE TERCEROS; COMETE:', 'ABUSO DE CARGO CALIFICADO CONDICIONADO ILEGALMENTE A LA RECEPCIÓN DE BIENES Y SERVICIOS.', 'ABUSO DE AUTORIDAD CONDICIONANDO LEGALMENTE LA ENTREGA DE BIENES, BENEFICIOS Y SERVICIOS.', 'ABUSO DE AUTORIDAD CONDICIONANDO ILEGALMENTE LA ENTREGA DE ADQUISICIÓN DE SERVICIOS.', 'ABUSO DE AUTORIDAD AGRAVADA ILEGALMENTE POR LOS JEFES SUPERIORES.', 'ABUSO DE AUTORIDAD CONDICIONANDO ILEGALMENTE LA ENTREGA DE BIENES Y SERVICIOS.', NULL, 'e', 'ABUSO DE AUTORIDAD CONDICIONANDO ILEGALMENTE LA ENTREGA DE BIENES Y SERVICIOS.', '(ART: 376-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION I]', '184077'),
(1946, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO PÚBLICO QUE, EN VIOLACIÓN DE SUS ATRIBUCIONES U OBLIGACIONES, OTORGA ILEGÍTIMAMENTE DERECHOS DE POSESIÓN O EMITE TÍTULOS DE PROPIEDAD SOBRE BIENES DE DOMINIO PÚBLICO O BIENES DE DOMINIO PRIVADO ESTATAL, O BIENES INMUEBLES DE PROPIEDAD PRIVADA, SIN CUMPLIR CON LOS REQUISITOS ESTABLECIDOS POR LA NORMATIVIDAD VIGENTE; COMETE DELITO DE:', 'ABUSO DE AUTORIDAD CONDICIONANDO ILEGALMENTE LA ENTREGA DE BIENES Y SERVICIOS.', 'OTORGAMIENTO ILEGÍTIMO DE DERECHOS SOBRE MUEBLES.', 'OTORGAMIENTO LEGÍTIMO DE DERECHOS SOBRE INMUEBLES.', 'OTORGAMIENTO ILEGÍTIMO DE DERECHOS SOBRE INMUEBLES.', 'OMISIÓN, REHUSAMIENTO O DEMORA DE ACTOS FUNCIONALES.', NULL, 'd', 'OTORGAMIENTO ILEGÍTIMO DE DERECHOS SOBRE INMUEBLES.', '(ART: 376-B)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION I]', '184078'),
(1947, 'Decreto Legislativo Nº 635 Código Penal', 'EL POLICÍA QUE REHÚSA, OMITE O RETARDA, SIN CAUSA JUSTIFICADA, LA PRESTACIÓN DE UN AUXILIO LEGALMENTE REQUERIDO POR LA AUTORIDAD CIVIL COMPETENTE; COMETE DELITO DE:', 'REQUERIMIENTO INDEBIDO DE LA FUERZA PÚBLICA.', 'DENEGACIÓN O DEFICIENTE APOYO POLICIAL.', 'OMISIÓN, REHUSAMIENTO O DEMORA DE APOYO POLICIAL.', 'DENEGACIÓN O DEFICIENTE SERVICIO POLICIAL.', 'OMISIÓN, REHUSAMIENTO O DEMORA DE ACTOS POLICIALES.', NULL, 'b', 'DENEGACIÓN O DEFICIENTE APOYO POLICIAL.', '(ART: 378)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION I]', '184080'),
(1948, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO PÚBLICO QUE REQUIERE LA ASISTENCIA DE LA FUERZA PÚBLICA PARA OPONERSE A LA EJECUCIÓN DE DISPOSICIONES U ÓRDENES LEGALES DE LA AUTORIDAD O CONTRA LA EJECUCIÓN DE SENTENCIA O MANDATO JUDICIAL, COMETE DELITO DE:', 'DENEGACIÓN O DEFICIENTE APOYO POLICIAL.', 'OMISIÓN O DEMORA DE ACTOS POLICIALES.', 'REQUERIMIENTO INDEBIDO DE LA FUERZA PÚBLICA.', 'DENEGACIÓN O DEFICIENTE APOYO DEL MINISTERO PUBLICO.', 'OMISIÓN, REHUSAMIENTO O DEMORA DE ACTOS FUNCIONALES.', NULL, 'c', 'REQUERIMIENTO INDEBIDO DE LA FUERZA PÚBLICA.', '(ART: 379)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION I]', '184081'),
(1949, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, CON DAÑO DEL SERVICIO, ABANDONA SU CARGO SIN HABER CESADO LEGALMENTE EN EL DESEMPEÑO DEL MISMO, COMETE DELITO DE:', 'ABANDONO DE CARGO.', 'ABANDONO DE DESTINO.', 'DENEGACIÓN O DEFICIENTE APOYO POLICIAL.', 'ABUSO DE CARGO.', 'ABANDONO DE SERVICIO.', NULL, 'a', 'ABANDONO DE CARGO.', '(ART: 380)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION I]', '184082'),
(1950, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, ABUSANDO DE SU CARGO, OBLIGA O INDUCE A UNA PERSONA A DAR O PROMETER INDEBIDAMENTE, PARA SÍ O PARA OTRO, UN BIEN O UN BENEFICIO PATRIMONIAL, COMETE DELITO DE:', 'APROVECHAMIENTO INDEBIDO.', 'EXTORSIÓN.', 'ABUSO DE AUTORIDAD.', 'CONCUSIÓN.', 'COLUSIÓN.', NULL, 'd', 'CONCUSIÓN.', '(ART: 382)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION II]', '184083'),
(1951, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, ABUSANDO DE SU CARGO, EXIGE O HACE PAGAR O ENTREGAR CONTRIBUCIONES O EMOLUMENTOS NO DEBIDOS O EN CANTIDAD QUE EXCEDE A LA TARIFA LEGAL, COMETE DELITO DE:', 'CONCUSIÓN.', 'COLUSIÓN.', 'PECULADO.', 'ABUSO DE AUTORIDAD.', 'COBRO INDEBIDO.', NULL, 'e', 'COBRO INDEBIDO.', '(ART: 383)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION II]', '184084'),
(1952, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, VALIÉNDOSE DE SU CALIDAD DE FUNCIONARIO O SERVIDOR PÚBLICO, PATROCINA INTERESES DE PARTICULARES ANTE LA ADMINISTRACIÓN PÚBLICA, COMETE DELITO DE:', 'PATROCINIO ILEGAL.', 'COBRO INDEBIDO.', 'CONCUSIÓN.', 'ABUSO DE AUTORIDAD.', 'COLUSIÓN.', NULL, 'a', 'PATROCINIO ILEGAL.', '(ART: 385)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION II]', '184085'),
(1953, 'Decreto Legislativo Nº 635 Código Penal', 'COMETE DELITO DE PROMOCIÓN, FAVORECIMIENTO O FACILITAMIENTO DEL CONSUMO ILEGAL DE DROGAS TÓXICAS; EL QUE PROMUEVE, FAVORECE O FACILITA EL CONSUMO ILEGAL DE DROGAS TÓXICAS, SEAN ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O:', 'NUEVAS SUSTANCIAS EXÓTICAS.', 'SUSTANCIAS FISCALIZADAS.', 'SUSTANCIAS PROHIBIDAS.', 'SUSTANCIAS ALUCINÓGENAS.', 'NUEVAS SUSTANCIAS PSICOACTIVAS.', NULL, 'e', 'NUEVAS SUSTANCIAS PSICOACTIVAS.', '(ART: 296)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO III]  [SECCION II]', '184087'),
(1954, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL DELITO DE PECULADO DOLOSO, SI LOS CAUDALES O EFECTOS ESTUVIERAN DESTINADOS A FINES ASISTENCIALES O A PROGRAMAS DE APOYO O INCLUSIÓN SOCIAL:', 'CONSTITUYE CIRCUNSTANCIA EXIMENTE.', 'CONSTITUYE CIRCUNSTANCIA MUY GRAVE.', 'CONSTITUYE CIRCUNSTANCIA ESPECIAL.', 'CONSTITUYE CIRCUNSTANCIA AGRAVANTE.', 'CONSTITUYE CIRCUNSTANCIA ATENUANTE.', NULL, 'd', 'CONSTITUYE CIRCUNSTANCIA AGRAVANTE.', '(ART: 387)** [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184088'),
(1955, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, PARA FINES AJENOS AL SERVICIO, USA O PERMITE QUE OTRO USE VEHÍCULOS, MÁQUINAS O CUALQUIER OTRO INSTRUMENTO DE TRABAJO PERTENECIENTES A LA ADMINISTRACIÓN PÚBLICA O QUE SE HALLAN BAJO SU GUARDA, COMETE DELITO DE:', 'COLUSIÓN.', 'PECULADO.', 'CONCUSIÓN DE USO.', 'PECULADO DE USO.', 'MALVERSACIÓN DE FONDOS.', NULL, 'd', 'PECULADO DE USO.', '(ART: 388)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184089'),
(1956, 'Decreto Legislativo Nº 635 Código Penal', 'EL DELITO DE PECULADO DE USO, ES APLICABLE AL CONTRATISTA DE UNA OBRA PÚBLICA O A SUS EMPLEADOS CUANDO LOS EFECTOS INDICADOS:', 'PERTENECEN AL ESTADO O A CUALQUIER EMPRESA.', 'SON DE PROPIEDAD DEL JEFE DE LA ENTIDAD.', 'HAN SIDO DECLARADOS EN ABANDONO LEGAL O CIVIL.', 'ESTÁN SOMETIDOS A PROCESO JUDICIAL.', 'PERTENECEN AL ESTADO O A CUALQUIER DEPENDENCIA PÚBLICA.', NULL, 'e', 'PERTENECEN AL ESTADO O A CUALQUIER DEPENDENCIA PÚBLICA.', '(ART: 388)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184091'),
(1957, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE DA AL DINERO O BIENES QUE ADMINISTRA UNA APLICACIÓN DEFINITIVA DIFERENTE DE AQUELLA A LOS QUE ESTÁN DESTINADOS, AFECTANDO EL SERVICIO O LA FUNCIÓN ENCOMENDADA, COMETE DELITO DE:', 'COLUSIÓN.', 'CONCUSIÓN.', 'PECULADO.', 'COBRO INDEBIDO.', 'MALVERSACIÓN.', NULL, 'e', 'MALVERSACIÓN.', '(ART: 389)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184092'),
(1958, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, REQUERIDO CON LAS FORMALIDADES DE LEY POR LA AUTORIDAD COMPETENTE, REHÚSA ENTREGAR DINERO, COSAS O EFECTOS DEPOSITADOS O PUESTOS BAJO SU CUSTODIA O ADMINISTRACIÓN, COMETE:', 'COLUSIÓN DOLOSA Y CULPOSA.', 'REHUSAMIENTO A ENTREGA DE BIENES DEPOSITADOS O PUESTOS EN CUSTODIA.', 'RETARDO INJUSTIFICADO DE PAGO.', 'REHUSAMIENTO A ENTREGA DE BIENES PÚBLICOS O PUESTOS EN CUSTODIA.', 'PECULADO DE USO SIN LA FORMALIDADES DE LEY.', NULL, 'b', 'REHUSAMIENTO A ENTREGA DE BIENES DEPOSITADOS O PUESTOS EN CUSTODIA.', '(ART: 391)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184094'),
(1959, 'Decreto Legislativo Nº 635 Código Penal', 'COMETE DELITO DE PROMOCIÓN, FAVORECIMIENTO O FACILITAMIENTO DEL CONSUMO ILEGAL DE DROGAS TÓXICAS; EL QUE FAVORECE EL CONSUMO ILEGAL DE DROGAS TÓXICAS, MEDIANTE ACTOS DE:', 'FABRICACIÓN LEGAL.', 'PRODUCCIÓN AUTORIZADA.', 'VENTA LEGAL.', 'DESTRUCCIÓN.', 'FABRICACIÓN O TRÁFICO.', NULL, 'e', 'FABRICACIÓN O TRÁFICO.', '(ART: 296)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO III]  [SECCION II]', '184095'),
(1960, 'Decreto Legislativo Nº 635 Código Penal', 'ESTÁN SUJETOS A LOS DELITOS DE PECULADO DOLOSO Y CULPOSO, PECULADO DE USO Y MALVERSACIÓN, LOS:', 'ADMINISTRADORES DE DINERO O BIENES EMBARGADOS O DEPOSITADOS POR ORDEN DE AUTORIDAD COMPETENTE,', 'ADMINISTRADORES O CUSTODIOS DE DINERO O BIENES EMBARGADOS O DEPOSITADOS POR ORDEN DE AUTORIDAD', 'DEPOSITARIOS DE DINERO O BIENES EMBARGADOS O DEPOSITADOS POR ORDEN DE AUTORIDAD COMPETENTE, AUNQUE', 'ADMINISTRADORES O DEPOSITARIOS DE DINERO O BIENES EMBARGADOS O DEPOSITADOS POR ORDEN DE AUTORIDAD', 'ADMINISTRADORES O DEPOSITARIOS DE DINERO O BIENES EMBARGADOS O DEPOSITADOS POR ORDEN DE AUTORIDAD', NULL, 'd', 'ADMINISTRADORES O DEPOSITARIOS DE DINERO O BIENES EMBARGADOS O DEPOSITADOS POR ORDEN DE', '(ART: 392)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184097'),
(1961, 'Decreto Legislativo Nº 635 Código Penal', '¿QUIÉNES ESTÁN SUJETOS A LOS DELITOS DE PECULADO DOLOSO Y CULPOSO, PECULADO DE USO Y MALVERSACIÓN?', 'LOS REPRESENTANTES LEGALES DE PERSONAS JURÍDICAS QUE ADMINISTREN O CUSTODIEN DINERO O BIENES', 'LOS GERENTES O REPRESENTANTES LEGALES DE PERSONAS JURÍDICAS QUE ADMINISTREN O CUSTODIEN DINERO O', 'LAS PERSONAS O REPRESENTANTES LEGALES DE PERSONAS JURÍDICAS QUE ADMINISTREN O CUSTODIEN DINERO O', 'LOS ADMINISTRADORES JUDICIALES PERSONAS O REPRESENTANTES LEGALES DE PERSONAS JURÍDICAS QUE', 'LOS CONTADORES PARTICULARES O REPRESENTANTES JUDICIALES DE PERSONAS JURÍDICAS QUE ADMINISTREN O', NULL, 'c', 'LAS PERSONAS O REPRESENTANTES LEGALES DE PERSONAS JURÍDICAS QUE ADMINISTREN O CUSTODIEN', '(ART: 392)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184098'),
(1962, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ACEPTE O RECIBA DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, PARA REALIZAR U OMITIR UN ACTO EN VIOLACIÓN DE SUS OBLIGACIONES O EL QUE LAS ACEPTA A CONSECUENCIA DE HABER FALTADO A ELLAS, COMETE:', 'COHECHO PASIVO PROPIO.', 'COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN.', 'CORRUPCIÓN PASIVA DE AUXILIARES JURISDICCIONALES.', 'COHECHO ACTIVO GENÉRICO.', 'COHECHO PASIVO IMPROPIO EN EL EJERCICIO DE LA FUNCIÓN.', NULL, 'a', 'COHECHO PASIVO PROPIO.', '(ART: 393)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184099'),
(1963, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO EXTRANJERO QUE ACEPTA, RECIBE O SOLICITA, DIRECTA O INDIRECTAMENTE, DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, PARA REALIZAR U OMITIR UN ACTO EN EL EJERCICIO DE SUS FUNCIONES OFICIALES, EN VIOLACIÓN DE SUS OBLIGACIONES, O LAS ACEPTA COMO CONSECUENCIA DE HABER FALTADO A ELLAS, PARA OBTENER O RETENER UN NEGOCIO U OTRA VENTAJA INDEBIDA, EN LA REALIZACIÓN DE ACTIVIDADES ECONÓMICAS INTERNACIONALES:', 'DELITO DE PECULADO TRANSNACIONAL.', 'SOBORNO INTERNACIONAL PASIVO.', 'COHECHO ACTIVO INTERNACIONAL.', 'COHECHO IMPROPIO INTERNACIONAL.', 'DELITO DE CONCUSIÓN TRANSNACIONAL.', NULL, 'b', 'SOBORNO INTERNACIONAL PASIVO.', '(ART: 393-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184100'),
(1964, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ACEPTE O RECIBA DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO INDEBIDO PARA REALIZAR UN ACTO PROPIO DE SU CARGO O EMPLEO, SIN FALTAR A SU OBLIGACIÓN, O COMO CONSECUENCIA DEL YA REALIZADO, COMETE:', 'COHECHO PASIVO PROPIO.', 'COHECHO PROPIO.', 'MALVERSACIÓN.', 'COHECHO PASIVO IMPROPIO.', 'PECULADO DE USO.', NULL, 'd', 'COHECHO PASIVO IMPROPIO.', '(ART: 394)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184101'),
(1965, 'Decreto Legislativo Nº 635 Código Penal', 'EL MAGISTRADO, ÁRBITRO, FISCAL, PERITO, MIEMBRO DE TRIBUNAL ADMINISTRATIVO O CUALQUIER OTRO ANÁLOGO A LOS ANTERIORES QUE BAJO CUALQUIER MODALIDAD ACEPTE O RECIBA DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, A SABIENDAS QUE ES HECHO CON EL FIN DE INFLUIR O DECIDIR EN ASUNTO SOMETIDO A SU CONOCIMIENTO O COMPETENCIA, COMETE:', 'COHECHO PASIVO ESPECÍFICO.', 'COHECHO PASIVO IMPROPIO.', 'COHECHO PASIVO PROPIO.', 'ABUSO DE AUTORIDAD.', 'MALVERSACIÓN.', NULL, 'a', 'COHECHO PASIVO ESPECÍFICO.', '(ART: 395)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184103'),
(1966, 'Decreto Legislativo Nº 635 Código Penal', 'EL MAGISTRADO, ÁRBITRO, FISCAL, PERITO, MIEMBRO DE TRIBUNAL ADMINISTRATIVO O CUALQUIER OTRO ANÁLOGO A LOS ANTERIORES QUE BAJO CUALQUIER MODALIDAD SOLICITE, DIRECTA O INDIRECTAMENTE, DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, A SABIENDAS QUE ES HECHO CON EL FIN DE INFLUIR EN LA DECISIÓN DE UN ASUNTO QUE ESTÉ SOMETIDO A SU CONOCIMIENTO:', 'COHECHO PASIVO PROPIO.', 'ABUSO DE AUTORIDAD.', 'MALVERSACIÓN.', 'COHECHO PASIVO ESPECÍFICO.', 'COHECHO PASIVO IMPROPIO.', NULL, 'd', 'COHECHO PASIVO ESPECÍFICO.', '(ART: 395)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184104'),
(1967, 'Decreto Legislativo Nº 635 Código Penal', 'EL MIEMBRO DE LA POLICÍA NACIONAL QUE SOLICITA, DIRECTA O INDIRECTAMENTE, DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, PARA REALIZAR U OMITIR UN ACTO EN VIOLACIÓN DE SUS OBLIGACIONES DERIVADAS DE LA FUNCIÓN POLICIAL O A CONSECUENCIA DE HABER FALTADO A ELLAS, COMETE:', 'COHECHO ACTIVO IMPROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'COHECHO PASIVO IMPROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'COHECHO PASIVO ESPECÍFICO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'COHECHO ACTIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', NULL, 'b', 'COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', '(ART: 395-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184105'),
(1968, 'Decreto Legislativo Nº 635 Código Penal', 'SI EN EL CASO DEL DELITO DE COHECHO PASIVO ESPECÍFICO, EL AGENTE ES SECRETARIO JUDICIAL, RELATOR, ESPECIALISTA, AUXILIAR JURISDICCIONAL O CUALQUIER OTRO ANÁLOGO A LOS ANTERIORES, COMETE:', 'CORRUPCIÓN ACTIVA DE ESPECIALISTAS LEGALES JURISDICCIONALES.', 'CORRUPCIÓN IMPROPIA DE AUXILIARES JURISDICCIONALES.', 'CORRUPCIÓN ACTIVA DE AUXILIARES PÚBLICOS.', 'CORRUPCIÓN PASIVA DE AUXILIARES LEGALES.', 'CORRUPCIÓN PASIVA DE AUXILIARES JURISDICCIONALES.', NULL, 'e', 'CORRUPCIÓN PASIVA DE AUXILIARES JURISDICCIONALES.', '(ART: 396)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184107'),
(1969, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, TENIENDO LA NACIONALIDAD PERUANA O LA REPRESENTACIÓN DE UNA PERSONA JURÍDICA DOMICILIADA EN EL PERÚ, BAJO CUALQUIER MODALIDAD, OFREZCA, OTORGUE O PROMETA DIRECTA O INDIRECTAMENTE A UN FUNCIONARIO O SERVIDOR PÚBLICO EXTRANJERO DONATIVO, PROMESA, VENTAJA O BENEFICIO INDEBIDO QUE REDUNDE EN SU PROPIO PROVECHO O EN EL DE OTRA PERSONA, PARA QUE DICHO SERVIDOR O FUNCIONARIO PÚBLICO REALICE U OMITA ACTOS PROPIOS DE SU CARGO O EMPLEO, EN VIOLACIÓN DE SUS OBLIGACIONES O SIN FALTAR A SU OBLIGACIÓN PARA OBTENER O RETENER UN NEGOCIO U OTRA VENTAJA INDEBIDA EN LA REALIZACIÓN DE ACTIVIDADES ECONÓMICAS O COMERCIALES INTERNACIONALES:', 'COHECHO ACTIVO TRANSNACIONAL.', 'MALVERSACIÓN INTERNACIONAL.', 'NEGOCIACIÓN INDEBIDA INTERNACIONAL.', 'DELITO TRANSNACIONAL.', 'PECULADO TRANSNACIONAL.', NULL, 'a', 'COHECHO ACTIVO TRANSNACIONAL.', '(ART: 397-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184109'),
(1970, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, BAJO CUALQUIER MODALIDAD, OFRECE, DA O PROMETE DONATIVO, VENTAJA O BENEFICIO A UN MAGISTRADO, FISCAL, PERITO, ÁRBITRO, MIEMBRO DE TRIBUNAL ADMINISTRATIVO O ANÁLOGO CON EL OBJETO DE INFLUIR EN LA DECISIÓN DE UN ASUNTO SOMETIDO A SU CONOCIMIENTO O COMPETENCIA:', 'COHECHO ACTIVO ESPECÍFICO.', 'COHECHO ACTIVO IMPROPIO.', 'COHECHO ACTIVO PROPIO.', 'COHECHO ACTIVO INTERNACIONAL.', 'COHECHO PASIVO ESPECÍFICO.', NULL, 'a', 'COHECHO ACTIVO ESPECÍFICO.', '(ART: 398)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184110'),
(1971, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE INDEBIDAMENTE EN FORMA DIRECTA O INDIRECTA O POR ACTO SIMULADO SE INTERESA, EN PROVECHO PROPIO O DE TERCERO, POR CUALQUIER CONTRATO U OPERACIÓN EN QUE INTERVIENE POR RAZÓN DE SU CARGO:', 'COHECHO ACTIVO IMPROPIO.', 'CONCUSIÓN.', 'NEGOCIACIÓN INCOMPATIBLE O APROVECHAMIENTO INDEBIDO DEL CARGO.', 'PECULADO DE USO.', 'COLUSIÓN.', NULL, 'c', 'NEGOCIACIÓN INCOMPATIBLE O APROVECHAMIENTO INDEBIDO DEL CARGO.', '(ART: 399)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184112'),
(1972, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE INDEBIDAMENTE EN FORMA DIRECTA O INDIRECTA O POR ACTO SIMULADO SE INTERESA, EN PROVECHO PROPIO O DE TERCERO, POR CUALQUIER CONTRATO U OPERACIÓN EN QUE INTERVIENE POR RAZÓN DE SU CARGO, COMETE:', 'COHECHO ACTIVO.', 'NEGOCIACION INCOMPATIBLE O APROVECHAMIENTO INDEBIDO DE CARGO.', 'CONCUSIÓN.', 'PECULADO.', 'NEGOCIACIÓN COMPATIBLE.', NULL, 'b', 'NEGOCIACION INCOMPATIBLE O APROVECHAMIENTO INDEBIDO DE CARGO.', '(ART: 399)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184114'),
(1973, 'Decreto Legislativo Nº 635 Código Penal', 'CONSTITUYE UNA FORMA AGRAVADA DEL DELITO DE CONTAMINACIÓN DEL AMBIENTE:', 'SI POR EFECTO DE LA ACTIVIDAD ILEGAL SE PRODUCEN LESIONES GRAVES O MUERTE.', 'SI POR EFECTO DE LA ACTIVIDAD PROCESAL SE PRODUCEN LESIONES GRAVES O MUERTE.', 'SI POR EFECTO DE LA ACTIVIDAD CONTAMINANTE SE PRODUCEN LESIONES O MUERTE.', 'SI COMO EFECTO DE LA ACTIVIDAD CONTAMINANTE SE PRODUCEN LESIONES GRAVES O MUERTE.', 'SI POR EFECTO DE LA ACTIVIDAD CONTAMINANTE SE PRODUCEN ACCIDENTES O MUERTE.', NULL, 'd', 'SI COMO EFECTO DE LA ACTIVIDAD CONTAMINANTE SE PRODUCEN LESIONES GRAVES O MUERTE.', '(ART: 305)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184115'),
(1974, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, ABUSANDO DE SU CARGO, INCREMENTA ILÍCITAMENTE SU PATRIMONIO RESPECTO DE SUS INGRESOS LEGÍTIMOS, COMETE:', 'APROVECHAMIENTO INDEBIDO DEL CARGO.', 'CORRUPCIÓN DE FUNCIONARIOS.', 'APROPIACIÓN ILÍCITA.', 'ENRIQUECIMIENTO ILÍCITO.', 'PECULADO.', NULL, 'd', 'ENRIQUECIMIENTO ILÍCITO.', '(ART: 401)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184116'),
(1975, 'Decreto Legislativo Nº 635 Código Penal', 'ES UNA FORMA AGRAVADA DE CONTAMINACIÓN DEL AMBIENTE, EL QUE FALSEA U OCULTA INFORMACIÓN SOBRE EL HECHO CONTAMINANTE, LA CANTIDAD O CALIDAD DE LAS DESCARGAS, EMISIONES, FILTRACIONES, VERTIMIENTOS O RADIACIONES CONTAMINANTES REFERIDOS EN EL ARTÍCULO 304, A:', 'LA AUTORIDAD COMPETENTE O A LA INSTITUCIÓN AUTORIZADA PARA REALIZAR LABORES DE FISCALIZACIÓN O AUDITORÍA', 'LA AUTORIDAD LOCAL O A LA INSTITUCIÓN AUTORIZADA PARA REALIZAR LABORES DE FISCALIZACIÓN MUNICIPAL.', 'LA AUTORIDAD COMPETENTE O A LA INSTITUCIÓN POLICIAL AUTORIZADA PARA REALIZAR LABORES DE MEDIO AMBIENTE.', 'LA AUTORIDAD JUDICIAL O A LA INSTITUCIÓN AUTORIZADA PARA REALIZAR LABORES DE CONTROL O AUDITORÍA', 'LA AUTORIDAD COMPROMETIDA CON EL CUIDADO DEL MEDIO AMBIENTE.', NULL, 'a', 'LA AUTORIDAD COMPETENTE O A LA INSTITUCIÓN AUTORIZADA PARA REALIZAR LABORES DE FISCALIZACIÓN O', '(ART: 305)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184117'),
(1976, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL DELITO DE ENRIQUECIMIENTO ILÍCITO, LOS BIENES DECOMISADOS E INCAUTADOS DURANTE LA INVESTIGACIÓN POLICIAL Y PROCESO JUDICIAL, SERÁN PUESTOS A DISPOSICIÓN DEL:', 'FISCAL DE LA NACIÓN.', 'MINISTERIO DE JUSTICIA.', 'MINISTERIO DEL INTERIOR.', 'MINISTERIO DE DEFENSA.', 'MINISTERIO PÚBLICO.', NULL, 'b', 'MINISTERIO DE JUSTICIA.', '(ART: 401-B)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184118'),
(1977, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL DELITO DE ENRIQUECIMIENTO ILÍCITO, LOS BIENES DECOMISADOS O INCAUTADOS DEFINITIVAMENTE SERÁN ADJUDICADOS:', 'AL MINISTERIO PÚBLICO.', 'AL PODER JUDICIAL.', 'A LOS GOBIERNOS REGIONALES.', 'AL ESTADO.', 'MINISTERIO DEL INTERIOR.', NULL, 'd', 'AL ESTADO.', '(ART: 401-B)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184119'),
(1978, 'Decreto Legislativo Nº 635 Código Penal', 'COMETE DELITO DE CONTAMINACIÓN DEL AMBIENTE:', 'EL QUE, OBEDECIENDO LEYES, REGLAMENTOS O LÍMITES MÁXIMOS PERMISIBLES, PROVOQUE O REALICE DESCARGAS', 'EL QUE, FALSIFICANDO LEYES, REGLAMENTOS O LÍMITES MÁXIMOS PERMISIBLES, PROVOQUE O REALICE DESCARGAS', 'EL QUE, CONTROLANDO LEYES, O LÍMITES MÍNIMOS PERMITIDOS, PROVOQUE O REALICE CARGAS CONTAMINANTES QUE', 'EL QUE, CUMPLIENDO LEYES, REGLAMENTOS O LÍMITES AUTORIZADOS, PROVOQUE O REALICE DESCARGAS', 'EL QUE, INFRINGIENDO LEYES, REGLAMENTOS O LÍMITES MÁXIMOS PERMISIBLES, PROVOQUE O REALICE DESCARGAS,', NULL, 'e', 'EL QUE, INFRINGIENDO LEYES, REGLAMENTOS O LÍMITES MÁXIMOS PERMISIBLES, PROVOQUE O REALICE', '(ART: 304)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184120'),
(1979, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, SIN AUTORIZACIÓN O APROBACIÓN DE LA AUTORIDAD COMPETENTE, ESTABLECE UN VERTEDERO O BOTADERO DE RESIDUOS SÓLIDOS QUE PUEDA PERJUDICAR GRAVEMENTE LA CALIDAD DEL AMBIENTE, LA SALUD HUMANA, INCURRE EN:', 'DELITO CONTRA LAS NORMAS RELATIVAS AL MANEJO DE RESIDUOS SÓLIDOS.', 'INCUMPLIMIENTO DE LAS NORMAS RELATIVAS AL MANEJO DE RESIDUOS SÓLIDOS.', 'INCUMPLIMIENTO DE LAS NORMAS RELATIVAS AL CONTROL DE RESIDUOS SÓLIDOS.', 'INCUMPLIMIENTO DE LOS ESTATUTOS RELATIVAS AL MANEJO DE RESIDUOS SÓLIDOS.', 'INCUMPLIMIENTO DE LAS NORMAS REFERIDAS A LA TRANSFORMACIÓN DE DESECHOS LÍQUIDOS.', NULL, 'b', 'INCUMPLIMIENTO DE LAS NORMAS RELATIVAS AL MANEJO DE RESIDUOS SÓLIDOS.', '(ART: 306)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184121'),
(1980, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE DENUNCIA A LA AUTORIDAD UN HECHO PUNIBLE, A SABIENDAS DE QUE NO SE HA COMETIDO O QUE HA SIDO COMETIDO POR PERSONA DISTINTA A LA DENUNCIADA, O EL QUE SIMULA O ADULTERA PRUEBAS O INDICIOS DE SU COMISIÓN QUE PUEDAN SERVIR DE MOTIVO PARA UN PROCESO PENAL O EL QUE FALSAMENTE SE ATRIBUYE DELITO NO COMETIDO O QUE HA SIDO COMETIDO POR OTRO:', 'FALSEDAD GENÉRICA.', 'DENUNCIA DOLOSA.', 'FALSA DENUNCIA.', 'DENUNCIA SIMULADA.', 'DENUNCIA CALUMNIOSA.', NULL, 'e', 'DENUNCIA CALUMNIOSA.', '(ART: 402)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184122'),
(1981, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, CONTRAVINIENDO LEYES, REGLAMENTOS O DISPOSICIONES ESTABLECIDAS, UTILIZA DESECHOS SÓLIDOS PARA LA ALIMENTACIÓN DE ANIMALES DESTINADOS AL CONSUMO HUMANO ESTA INCURSO EN:', 'INCUMPLIMIENTO DE LAS NORMAS RELATIVAS AL MANEJO DE RESIDUOS PELIGROSOS.', 'CONTRA LA SALUD PÚBLICA.', 'INCUMPLIMIENTO DE LAS NORMAS RELATIVAS AL MANEJO DE RESIDUOS SÓLIDOS.', 'CONTRA LAS NORMAS SANITARIAS.', 'EXPOSICIÓN DE PERSONAS A PELIGRO.', NULL, 'c', 'INCUMPLIMIENTO DE LAS NORMAS RELATIVAS AL MANEJO DE RESIDUOS SÓLIDOS.', '(ART: 306)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184123'),
(1982, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE OCULTA A UN MENOR DE EDAD A LAS INVESTIGACIONES DE LA JUSTICIA O DE LA QUE REALIZA LA AUTORIDAD COMPETENTE, COMETE:', 'EXPOSICIÓN DE MENOR A LAS INVESTIGACIONES.', 'SEPARACIÓN DE MENOR DE LAS INVESTIGACIONES.', 'OCULTAMIENTO DE MENOR A LAS INVESTIGACIONES.', 'RESISTENCIA DE MENOR A LAS INVESTIGACIONES.', 'REPRESIÓN A MENOR DE EDAD.', NULL, 'c', 'OCULTAMIENTO DE MENOR A LAS INVESTIGACIONES.', '(ART: 403)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184124'),
(1983, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE INGRESE ILEGALMENTE AL TERRITORIO NACIONAL, SIN LA DEBIDA AUTORIZACIÓN, RESIDUOS O DESECHOS TÓXICOS O PELIGROSOS PARA EL AMBIENTE ESTA INCURSO EN:', 'TRÁFICO ILÍCITO DE MATERIAL TÓXICO.', 'TRÁFICO ILEGAL DE RESIDUOS PELIGROSOS.', 'TRÁFICO ILÍCITO DE SUSTANCIAS PELIGROSAS.', 'TRÁFICO ILEGAL DE RESIDUO QUIRÚRGICO.', 'TRÁFICO ILÍCITO DE SUSTANCIAS TÓXICAS PARA LA SALUD.', NULL, 'b', 'TRÁFICO ILEGAL DE RESIDUOS PELIGROSOS.', '(ART: 307)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184125'),
(1984, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SUSTRAE A UNA PERSONA DE LA PERSECUCIÓN PENAL O A LA EJECUCIÓN DE UNA PENA O DE OTRA MEDIDA ORDENADA POR LA JUSTICIA, COMETE:', 'SUSTRACCIÓN DE TESTIGO.', 'ENCUBRIMIENTO PERSONAL.', 'OCULTAMIENTO DE TESTIGO.', 'ENCUBRIMIENTO DE IMPUTADO.', 'OCULTAMIENTO PERSONAL.', NULL, 'b', 'ENCUBRIMIENTO PERSONAL.', '(ART: 404)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184126'),
(1985, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE TRASLADE O DISPONGA SIN LA DEBIDA AUTORIZACIÓN, RESIDUOS O DESECHOS TÓXICOS O PELIGROSOS PARA EL AMBIENTE, ESTA INCURSO EN:', 'TRÁFICO ILÍCITO DE MATERIAL TÓXICO.', 'TRÁFICO ILÍCITO DE SUSTANCIAS PELIGROSAS.', 'TRÁFICO ILEGAL DE RIESGO QUIRÚRGICO.', 'TRÁFICO ILÍCITO DE SUSTANCIAS TÓXICAS PARA LA SALUD.', 'TRÁFICO ILEGAL DE RESIDUOS PELIGROSOS.', NULL, 'e', 'TRÁFICO ILEGAL DE RESIDUOS PELIGROSOS.', '(ART: 307)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184127'),
(1986, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE DIFICULTA LA ACCIÓN DE LA JUSTICIA PROCURANDO LA DESAPARICIÓN DE LAS HUELLAS O PRUEBA DEL DELITO U OCULTANDO LOS EFECTOS DEL MISMO, COMETE:', 'ENCUBRIMIENTO PERSONAL.', 'OCULTAMIENTO DE PRUEBAS.', 'ENCUBRIMIENTO REAL.', 'SUSTRACCIÓN DE INDICIOS.', 'CONTAMINACIÓN DE LA ESCENA DEL DELITO.', NULL, 'c', 'ENCUBRIMIENTO REAL.', '(ART: 405)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184128'),
(1987, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE USE, EMPLEE, COLOQUE SIN LA DEBIDA AUTORIZACIÓN, RESIDUOS O DESECHOS TÓXICOS O PELIGROSOS PARA EL AMBIENTE ESTA INCURSO EN:', 'TRÁFICO ILÍCITO DE SUSTANCIAS TÓXICAS PARA LA SALUD.', 'TRÁFICO ILÍCITO DE SUSTANCIAS PELIGROSAS.', 'TRÁFICO ILEGAL DE RESIDUOS PELIGROSOS.', 'TRÁFICO ILEGAL DE RESIDUOS SOLIDOS.', 'TRÁFICO ILÍCITO DE MATERIAL TÓXICO.', NULL, 'c', 'TRÁFICO ILEGAL DE RESIDUOS PELIGROSOS.', '(ART: 307)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184129'),
(1988, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE HACE, EN TODO O EN PARTE, UN DOCUMENTO FALSO O ADULTERA UNO VERDADERO QUE PUEDA DAR ORIGEN A DERECHO U OBLIGACIÓN O SERVIR PARA PROBAR UN HECHO, CON EL PROPÓSITO DE UTILIZAR EL DOCUMENTO Y SI DE SU USO PUEDE RESULTAR ALGÚN PERJUICIO, COMETE DELITO DE:', 'FALSEDAD GENÉRICA.', 'FALSEDAD IDEOLÓGICA.', 'FALSEDAD EN EL REPORTE DE LOS VOLÚMENES.', 'EQUIPARACIÓN A DOCUMENTO PÚBLICO.', 'FALSIFICACIÓN DE DOCUMENTOS.', NULL, 'e', 'FALSIFICACIÓN DE DOCUMENTOS.', '(ART: 427)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184130'),
(1989, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE HACE USO DE UN DOCUMENTO FALSO O FALSIFICADO, COMO SI FUESE LEGÍTIMO, SIEMPRE QUE DE SU USO PUEDA RESULTAR ALGÚN PERJUICIO, COMETE:', 'DELITO DE MALVERSACIÓN.', 'FALSIFICACIÓN DE DOCUMENTOS.', 'FALSEDAD EN EL REPORTE.', 'OMISIÓN DE CONSIGNAR DECLARACIONES EN DOCUMENTOS.', 'SUPRESIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', NULL, 'b', 'FALSIFICACIÓN DE DOCUMENTOS.', '(ART: 427)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184131'),
(1990, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE INSERTA O HACE INSERTAR, EN INSTRUMENTO PÚBLICO, DECLARACIONES FALSAS CONCERNIENTES A HECHOS QUE DEBAN PROBARSE CON EL DOCUMENTO, CON EL OBJETO DE EMPLEARLO COMO SI LA DECLARACIÓN FUERA CONFORME A LA VERDAD, COMETE DELITO DE:', 'FALSIFICACIÓN DE DOCUMENTOS.', 'SUPRESIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', 'FALSEDAD IDEOLÓGICA.', 'FALSEDAD EN EL REPORTE.', 'FALSIFICACIÓN GENÉRICA.', NULL, 'c', 'FALSEDAD IDEOLÓGICA.', '(ART: 428)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184132'),
(1991, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, ESTANDO INCLUIDO DENTRO DEL RÉGIMEN DE LÍMITES MÁXIMOS DE CAPTURA POR EMBARCACIÓN ESTABLECIDO POR LEY, INSERTA O HACE INSERTAR EN CUALQUIER DOCUMENTO DONDE SE CONSIGNE LA INFORMACIÓN REFERENTE A LOS VOLÚMENES DE CAPTURA, INFORMACIÓN FALSA O DISTINTA RESPECTO AL VOLUMEN REALMENTE CAPTURADO, COMETE DELITO DE:', 'FALSEDAD EN EL REPORTE DIARIO DE LOS VOLÚMENES DE PESCA.', 'FALSEDAD EN EL INFORME DE LAS RUTAS DE PESCA CAPTURADOS.', 'OMISIÓN DE INFORMACIÓN DECLARACIONES EN DOCUMENTOS.', 'FALSEDAD EN EL REPORTE DE LOS VOLÚMENES DE PESCA CAPTURADOS.', 'OMISIÓN DE CONSIGNAR DECLARACIONES EN DOCUMENTOS.', NULL, 'd', 'FALSEDAD EN EL REPORTE DE LOS VOLÚMENES DE PESCA CAPTURADOS.', '(ART: 428-B)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184133'),
(1992, 'Decreto Legislativo Nº 635 Código Penal', 'QUIEN ALTERA O AYUDA A LA ALTERACIÓN DE LOS INSTRUMENTOS DE PESAJE CON LOS QUE SE CALCULA LOS VOLÚMENES DE PESCA CAPTURADOS, SI DICHA ALTERACIÓN TIENE LA FINALIDAD DE CONSIGNAR UN VOLUMEN DISTINTO AL REALMENTE CAPTURADO, COMETE DELITO DE:', 'FALSEDAD EN EL REPORTE DE LOS VOLÚMENES DE PESCA CAPTURADOS.', 'SUPRESIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', 'OMISIÓN DE CONSIGNAR DECLARACIONES EN DOCUMENTOS.', 'FALSEDAD Y OMISIÓN EN EL INFORME DE LOS VOLÚMENES DE PESCA.', 'OMISIÓN DE CONSIGNAR DECLARACIONES EN INFORME DE PESCA FORMAL.', NULL, 'a', 'FALSEDAD EN EL REPORTE DE LOS VOLÚMENES DE PESCA CAPTURADOS.', '(ART: 428-B)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184134'),
(1993, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE OMITE EN UN DOCUMENTO PÚBLICO O PRIVADO DECLARACIONES QUE DEBERÍAN CONSTAR O EXPIDE DUPLICADOS CON IGUAL OMISIÓN, AL TIEMPO DE EJERCER UNA FUNCIÓN Y CON EL FIN DE DAR ORIGEN A UN HECHO U OBLIGACIÓN, COMETE DELITO DE:', 'SUPRESIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', 'FALSEDAD EN EL REPORTE.', 'FALSIFICACIÓN DE DOCUMENTOS.', 'FALSEDAD IDEOLÓGICA.', 'OMISIÓN DE CONSIGNAR DECLARACIONES EN DOCUMENTOS.', NULL, 'e', 'OMISIÓN DE CONSIGNAR DECLARACIONES EN DOCUMENTOS.', '(ART: 429)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184135'),
(1994, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SUPRIME, DESTRUYE U OCULTA UN DOCUMENTO, EN TODO O EN PARTE DE MODO QUE PUEDA RESULTAR PERJUICIO PARA OTRO, CORRESPONDE A:', 'SUSPENSIÓN, DESTRUCCIÓN U ORDENAMIENTO DE DOCUMENTOS.', 'SUPRESIÓN, ERRADICACIÓN U OCULTAMIENTO DE DOCUMENTOS.', 'SUSPENSIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', 'SUPRESIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', 'SUPRESIÓN O FALSEDAD GENÉRICA.', NULL, 'd', 'SUPRESIÓN, DESTRUCCIÓN U OCULTAMIENTO DE DOCUMENTOS.', '(ART: 430)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184136'),
(1995, 'Decreto Legislativo Nº 635 Código Penal', 'EL MÉDICO QUE, MALICIOSAMENTE, EXPIDE UN CERTIFICADO FALSO RESPECTO A LA EXISTENCIA O NO EXISTENCIA, PRESENTE O PASADA, DE ENFERMEDADES FÍSICAS O MENTALES, COMETE DELITO DE:', 'EXPEDICIÓN DE CERTIFICADO MÉDICO FALSO.', 'FALSEDAD GENÉRICA.', 'EXPEDICIÓN DE CERTIFICADO FALSIFICADO.', 'OMISIÓN DE CONSIGNAR INFORMACIÓN EN DOCUMENTO.', 'FALSEDAD IDEOLÓGICA.', NULL, 'a', 'EXPEDICIÓN DE CERTIFICADO MÉDICO FALSO.', '(ART: 431)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184137'),
(1996, 'Decreto Legislativo Nº 635 Código Penal', 'SE COMETE DELITO DE EXPEDICIÓN DE CERTIFICADO MÉDICO FALSO, CUANDO SE HAYA DADO LA FALSA CERTIFICACIÓN CON EL OBJETO QUE SE ADMITA O INTERNE A UNA PERSONA EN UN HOSPITAL PARA:', 'ENFERMOS MENTALES.', 'ENFERMOS TERMINALES.', 'ENFERMOS GRAVES.', 'ENFERMOS PANDÉMICOS.', 'ENFERMOS ONCOLÓGICOS.', NULL, 'a', 'ENFERMOS MENTALES.', '(ART: 431)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184138'),
(1997, 'Decreto Legislativo Nº 635 Código Penal', 'TAMBIÉN COMETE DELITO DE EXPEDICIÓN DE CERTIFICADO MÉDICO FALSO:', 'EL QUE HAGA USO INDISCRIMINADO DE LA CERTIFICACIÓN.', 'EL QUE NO HAGA USO LEGAL DE LA CERTIFICACIÓN.', 'EL QUE HAGA USO MALICIOSO DE LA CERTIFICACIÓN.', 'EL QUE HAGA USO LIBRE DE LA CERTIFICACIÓN.', 'EL QUE HAGA USO NO PUNIBLE DE LA CERTIFICACIÓN.', NULL, 'c', 'EL QUE HAGA USO MALICIOSO DE LA CERTIFICACIÓN.', '(ART: 431)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184139'),
(1998, 'Decreto Legislativo Nº 635 Código Penal', 'COMETE HURTO SIMPLE EL QUE PARA OBTENER PROVECHO:', 'SE APODERA ILEGÍTIMAMENTE DE UN BIEN INMUEBLE, TOTALMENTE AJENO, SUSTRAYÉNDOLO DEL LUGAR DONDE SE', 'SE APODERA LEGÍTIMAMENTE DE UN BIEN MUEBLE, TOTALMENTE AJENO, SUSTRAYÉNDOLO DEL LUGAR DONDE SE', 'SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE, SUSTRAYÉNDOLO DEL LUGAR DONDE SE ENCUENTRA.', 'SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE, TOTAL O PARCIALMENTE AJENO, SUSTRAYÉNDOLO DEL LUGAR', 'SE APODERA ILEGÍTIMAMENTE MEDIANTE EL ENGAÑO DE UN BIEN INMUEBLE, SUSTRAYÉNDOLO DEL LUGAR DONDE SE', NULL, 'd', 'SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE, TOTAL O PARCIALMENTE AJENO, SUSTRAYÉNDOLO DEL', '(ART: 185)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO I]', '184140'),
