(2035, 'Decreto Legislativo Nº 635 Código Penal', 'ES UNA FORMA AGRAVADA DE MINERÍA ILEGAL, LA QUE SE REALIZA EN:', 'ZONAS DESTINAS A LA ACTIVIDAD EXTRACTIVA.', 'ZONAS GANADERAS.', 'ZONAS NO PERMITIDAS PARA EL DESARROLLO DE ACTIVIDAD MINERA.', 'ZONAS DE EMERGENCIA.', 'ZONAS DESTINADAS A LA CONCESIÓN MINERA.', NULL, 'c', 'ZONAS NO PERMITIDAS PARA EL DESARROLLO DE ACTIVIDAD MINERA.', '(ART: 307-B)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184177'),
(2036, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SE APODERA ILEGÍTIMAMENTE DE BIENES DE VALOR CIENTÍFICO, PARA APROVECHARSE DE ELLOS, SUSTRAYÉNDOLES DEL LUGAR EN QUE SE ENCUENTRAN, EMPLEANDO VIOLENCIA CONTRA LA PERSONA, COMETE DELITO DE:', 'HURTO AGRAVADO.', 'HURTO DE BIENES CIENTÍFICOS.', 'HURTO SIMPLE.', 'DAÑOS A LA PROPIEDAD INTELECTUAL.', 'ROBO AGRAVADO.', NULL, 'e', 'ROBO AGRAVADO.', '(ART: 189)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO II]', '184178'),
(2037, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SUPUESTOS,  ES UNA FORMA AGRAVADA DE MINERÍA ILEGAL:', 'EN ÁREAS DESTINADAS A LA CONCESIÓN MINERA.', 'EN ÁREAS GANADERAS.', 'EN ÁREAS DESTINAS A LA ACTIVIDAD EXTRACTIVA.', 'EN ÁREAS NATURALES PROTEGIDAS.', 'EN ÁREAS DE EMERGENCIA.', NULL, 'd', 'EN ÁREAS NATURALES PROTEGIDAS.', '(ART: 307-B)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184179'),
(2038, 'Decreto Legislativo Nº 635 Código Penal', 'CUANDO EL HECHO RECAE SOBRE BIENES QUE INTEGREN EL PATRIMONIO CULTURAL DE LA NACIÓN, PARA APROVECHARSE DE ELLOS, SUSTRAYÉNDOLOS DEL LUGAR EN QUE SE ENCUENTRAN, EMPLEANDO VIOLENCIA CONTRA LA PERSONA, COMETE DELITO DE:', 'HURTO AGRAVADO.', 'HURTO CONTRA EL PATRIMONIO DEL ESTADO.', 'HURTO SIMPLE.', 'ROBO.', 'ROBO AGRAVADO.', NULL, 'e', 'ROBO AGRAVADO.', '(ART: 189)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO II]', '184180'),
(2039, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MEDIANTE VIOLENCIA O AMENAZA OBLIGA A UNA PERSONA O A UNA INSTITUCIÓN PÚBLICA O PRIVADA A OTORGAR AL AGENTE O A UN TERCERO UNA VENTAJA ECONÓMICA INDEBIDA U OTRA VENTAJA DE CUALQUIER OTRA ÍNDOLE; COMETE:', 'HURTO.', 'EXTORSIÓN.', 'ESTELIONATO.', 'HURTO AGRAVADO.', 'CHANTAJE.', NULL, 'b', 'EXTORSIÓN.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184181'),
(2040, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SUPUESTOS ES UNA FORMA AGRAVADA DE MINERÍA ILEGAL:', 'UTILIZANDO DRAGAS, ARTEFACTOS U OTROS INSTRUMENTOS SIMILARES.', 'UTILIZANDO PERSONAL TÉCNICO O BACHILLERES EN INGENIERÍA AMBIENTAL.', 'UTILIZANDO ARTEFACTOS DE ÚLTIMA GENERACIÓN INGRESADOS AL PAÍS ILEGALMENTE.', 'UTILIZANDO A POBLADORES DE LAS COMUNIDADES NATIVAS.', 'UTILIZANDO EMPRESAS MINERAS SANCIONADAS CON SUSPENSIÓN TEMPORAL.', NULL, 'a', 'UTILIZANDO DRAGAS, ARTEFACTOS U OTROS INSTRUMENTOS SIMILARES.', '(ART: 307-B)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184182'),
(2041, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, HACIENDO SABER A OTRO QUE SE DISPONE A PUBLICAR, UN HECHO O CONDUCTA CUYA DIVULGACIÓN PUEDE PERJUDICARLO PERSONALMENTE, TRATA DE DETERMINARLO O LO DETERMINA A COMPRAR SU SILENCIO; COMETE:', 'EXTORSIÓN.', 'COACCIÓN.', 'CHANTAJE.', 'DELITO CONTRA LA LIBERTAD.', 'ESTELIONATO.', NULL, 'c', 'CHANTAJE.', '(ART: 201)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184183'),
(2042, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SUPUESTOS ES UNA FORMA AGRAVADA DE MINERÍA ILEGAL:', 'SI EL AGENTE UTILIZA MAQUINARIA NO CERTIFICADAS POR EL PROGRAMA DE APOYO AL MEDIO AMBIENTE (PAMA).', 'SI EL AGENTE EMPLEA INSTRUMENTOS U OBJETOS CAPACES DE PONER EN PELIGRO LA VIDA, LA SALUD O EL PATRIMONIO', 'SI EL AGENTE UTILIZA EMPRESAS DEDICADAS A LA EXPLOTACIÓN MINERA.', 'SI EL AGENTE UTILIZA A TÉCNICOS Y BACHILLERES EN INGENIERÍA AMBIENTAL.', 'SI EL AGENTE EMPLEA ZONAS INTANGIBLES DECLARADAS POR EL INSTITUTO NACIONAL DE CULTURA.', NULL, 'b', 'SI EL AGENTE EMPLEA INSTRUMENTOS U OBJETOS CAPACES DE PONER EN PELIGRO LA VIDA, LA SALUD O EL', '(ART: 307-B)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184184'),
(2043, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE PROCURA PARA SÍ O PARA OTRO UN PROVECHO ILÍCITO EN PERJUICIO DE TERCERO, INDUCIENDO O MANTENIENDO EN ERROR AL AGRAVIADO MEDIANTE ENGAÑO, ASTUCIA, ARDID U OTRA FORMA FRAUDULENTA; COMETE DELITO DE:', 'ESTAFA.', 'CHANTAJE.', 'USURA.', 'EXTORSIÓN.', 'FRAUDE.', NULL, 'a', 'ESTAFA.', '(ART: 196)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO V]', '184185'),
(2044, 'Decreto Legislativo Nº 635 Código Penal', 'ES UNA FORMA AGRAVADA DE MINERÍA ILEGAL, CUANDO:', 'SE UTILIZA AGUAS SERVIDAS.', 'SE UTILIZA ACUEDUCTOS PRIVADOS.', 'SE AFECTA EL SISTEMA LACUSTRE O LA FAUNA DESTINADA AL CONSUMO HUMANO.', 'SE AFECTA SISTEMAS DE IRRIGACIÓN O AGUAS DESTINADOS AL CONSUMO HUMANO.', 'SE AFECTA A LA EXPLOTACIÓN DE RECURSOS MINERALES METÁLICOS Y NO METÁLICOS DEL PAÍS.', NULL, 'd', 'SE AFECTA SISTEMAS DE IRRIGACIÓN O AGUAS DESTINADOS AL CONSUMO HUMANO.', '(ART: 307-B)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184186'),
(2045, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, CON VIOLENCIA, AMENAZA, ENGAÑO O ABUSO DE CONFIANZA, DESPOJA A OTRO, TOTAL O PARCIALMENTE, DE LA POSESIÓN O TENENCIA DE UN INMUEBLE O DEL EJERCICIO DE UN DERECHO REAL, COMETE DELITO DE:', 'APROPIACIÓN ILÍCITA.', 'DAÑOS.', 'HURTO.', 'ROBO.', 'USURPACIÓN.', NULL, 'e', 'USURPACIÓN.', '(ART: 202)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184187'),
(2046, 'Decreto Legislativo Nº 635 Código Penal', 'ES UNA FORMA AGRAVADA DE MINERÍA ILEGAL, CUANDO:', 'EL AGENTE EMPLEA PARA LA COMISIÓN DEL DELITO A EXTRANJEROS.', 'EL AGENTE EMPLEA PARA LA COMISIÓN DEL DELITO A PERSONA DE LA TERCERA EDAD.', 'EL AGENTE EMPLEA PARA LA COMISIÓN DEL DELITO A FAMILIARES DEDICADOS A LA EXPLOTACIÓN MINERA.', 'EL AGENTE EMPLEA PARA LA COMISIÓN DEL DELITO A EMPRESAS DEDICADA A LA MINERÍA.', 'EL AGENTE EMPLEA PARA LA COMISIÓN DEL DELITO A MENORES DE EDAD U OTRA PERSONA INIMPUTABLE.', NULL, 'e', 'EL AGENTE EMPLEA PARA LA COMISIÓN DEL DELITO A MENORES DE EDAD U OTRA PERSONA INIMPUTABLE.', '(ART: 307-B)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184188'),
(2047, 'Decreto Legislativo Nº 635 Código Penal', 'ES UNA FORMA DE USURPACIÓN AGRAVADA, CUANDO LA USURPACIÓN SE COMETE:', 'SOBRE BIENES NO DESTINADOS A SERVICIOS BÁSICOS.', 'CON LA PARTICIPACIÓN DE UN MENOR DE EDAD.', 'SOBRE BIENES DESTINADOS A SERVICIOS PÚBLICOS.', 'CON CONOCIMIENTO DE LA AUTORIDAD JURISDICCIONAL.', 'CON CONOCIMIENTO DE LA AUTORIDAD POLICIAL.', NULL, 'c', 'SOBRE BIENES DESTINADOS A SERVICIOS PÚBLICOS.', '(ART: 204)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184189'),
(2048, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE OBSTACULIZA O IMPIDE LA ACTIVIDAD DE EVALUACIÓN, CONTROL Y FISCALIZACIÓN DE LA AUTORIDAD ADMINISTRATIVA RELACIONADA CON LA MINERÍA ILEGAL; COMETE DELITO DE:', 'OBSTACULIZACIÓN DE FUNCIONES DE SERVIDOR PÚBLICO.', 'OBSTACULIZACIÓN DE LA FISCALIZACIÓN ADMINISTRATIVA.', 'OBSTACULIZACIÓN DE LA FISCALIZACIÓN JURISDICCIONAL.', 'OBSTACULIZACIÓN DE LA FISCALIZACIÓN GUBERNAMENTAL.', 'OBSTACULIZACIÓN DE LA FISCALIZACIÓN MUNICIPAL.', NULL, 'b', 'OBSTACULIZACIÓN DE LA FISCALIZACIÓN ADMINISTRATIVA.', '(ART: 307-D)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184190'),
(2049, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MUTILA UN MIEMBRO U ÓRGANO PRINCIPAL DEL CUERPO O LO HACEN IMPROPIO PARA SU FUNCIÓN, COMETE:', 'LESIONES MUTILADORAS.', 'LESIONES LEVES.', 'LESIONES GRAVES.', 'LESIÓN DE ÓRGANO.', 'LESIONES SEGUIDAS DE MUTILACIÓN.', NULL, 'c', 'LESIONES GRAVES.', '(ART: 121)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '184191'),
(2050, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, INFRINGIENDO LAS LEYES Y REGLAMENTOS, ADQUIERE, VENDE, DISTRIBUYE, COMERCIALIZA, TRANSPORTA, IMPORTA, POSEE O ALMACENA INSUMOS QUÍMICOS, CON EL PROPÓSITO DE DESTINAR DICHOS BIENES A LA COMISIÓN DE LOS DELITOS DE MINERÍA ILEGAL; COMETE DELITO DE:', 'CONTRABANDO ILEGAL DE INSUMOS QUÍMICOS FISCALIZADOS Y MAQUINARIAS DESTINADOS A MINERÍA.', 'CONTRABANDO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA ILEGAL.', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA FORMAL.', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA ILEGAL.', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS FISCALIZADOS DESTINADOS A MINERÍA.', NULL, 'd', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA ILEGAL.', '(ART: 307-E)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184192'),
(2051, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ADQUIERE, VENDE, ARRIENDA, TRANSFIERE O CEDE EN USO BAJO CUALQUIER TÍTULO, DISTRIBUYE, COMERCIALIZA, TRANSPORTA, IMPORTA, POSEE O ALMACENA MAQUINARIAS, A SABIENDAS DE QUE SERÁN DESTINADAS A LA COMISIÓN DE LOS DELITOS DE MINERÍA ILEGAL; COMETE DELITO DE:', 'CONTRABANDO ILEGAL DE INSUMOS QUÍMICOS FISCALIZADOS Y MAQUINARIAS DESTINADOS A MINERÍA.', 'CONTRABANDO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA ILEGAL.', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA FORMAL.', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA ILEGAL.', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS FISCALIZADOS DESTINADOS A MINERÍA.', NULL, 'd', 'TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y MAQUINARIAS DESTINADOS A MINERÍA ILEGAL.', '(ART: 307-E)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184193'),
(2052, 'Decreto Legislativo Nº 635 Código Penal', 'EL AGENTE DE LOS DELITOS DE MINERÍA ILEGAL SERÁ ADEMÁS SANCIONADO, DE CONFORMIDAD CON EL ARTÍCULO 36, INCISO 4,CON LA PENA DE:', 'INHABILITACIÓN PARA OBTENER, A NOMBRE PROPIO O A TRAVÉS DE TERCEROS, CONCESIONES MINERAS POR UN', 'INHABILITACIÓN PARA OBTENER, A NOMBRE PROPIO O A TRAVÉS DE TERCEROS, CONCESIONES MINERAS POR UN', 'INHABILITACIÓN PARA OBTENER, A NOMBRE PROPIO O A TRAVÉS DE TERCEROS, CONCESIONES MINERAS POR UN', 'INHABILITACIÓN PARA OBTENER, A NOMBRE PROPIO O A TRAVÉS DE TERCEROS, CONCESIONES MINERAS POR UN', 'INHABILITACIÓN PARA OBTENER, A NOMBRE PROPIO O A TRAVÉS DE TERCEROS, CONCESIONES MINERAS POR UN', NULL, 'a', 'INHABILITACIÓN PARA OBTENER, A NOMBRE PROPIO O A TRAVÉS DE TERCEROS, CONCESIONES MINERAS POR', '(ART: 307-F)** [LIBRO SEGUNDO]  [TITULO XIII]  [CAPITULO I]', '184194'),
(2053, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, MEDIANTE VIOLENCIA O AMENAZA, TOMA LOCALES, OBSTACULIZA VÍAS DE COMUNICACIÓN O IMPIDE EL LIBRE TRÁNSITO DE LA CIUDADANÍA O PERTURBA EL NORMAL FUNCIONAMIENTO DE LOS SERVICIOS PÚBLICOS O LA EJECUCIÓN DE OBRAS LEGALMENTE AUTORIZADAS, CON EL OBJETO DE OBTENER DE LAS AUTORIDADES CUALQUIER BENEFICIO O VENTAJA ECONÓMICA INDEBIDA, INCURRE EN DELITO DE:', 'DIFAMACIÓN.', 'INJURIA.', 'EXTORSIÓN.', 'ROBO.', 'ROBO AGRAVADO.', NULL, 'c', 'EXTORSIÓN.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184195'),
(2054, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE RUFIANISMO:', 'LA VÍCTIMA TIENE 60 AÑOS O MÁS.', 'LA VÍCTIMA TIENE 18 AÑOS.', 'LA VÍCTIMA ES CONYUGUE.', 'LA VÍCTIMA ES ESCLAVIZADA.', 'LA VÍCTIMA ES AUTORIDAD.', NULL, 'c', 'LA VÍCTIMA ES CONYUGUE.', '(ART: 180)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO X]', '184196'),
(2055, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS; ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE PROXENETISMO:', 'PARIENTE EN 5TO GRADO DE AFINIDAD.', 'INCAPACIDAD DE RESISTIR.', 'LA VÍCTIMA ESTE EN SITUACIÓN DE ABANDONO.', 'ESCLAVITUD.', 'CONDICIONES DE FALTA DE HIGIENE.', NULL, 'c', 'LA VÍCTIMA ESTE EN SITUACIÓN DE ABANDONO.', '(ART: 181)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO X]', '184197'),
(2056, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, EN SU PROVECHO O DE UN TERCERO, SE APROPIA INDEBIDAMENTE DE UN BIEN MUEBLE, UNA SUMA DE DINERO O UN VALOR QUE HA RECIBIDO EN COMISIÓN, QUE PRODUZCA OBLIGACIÓN DE ENTREGAR, DEVOLVER, O HACER UN USO DETERMINADO, COMETE DELITO DE:', 'HURTO.', 'ROBO.', 'FRAUDE.', 'ESTAFA.', 'APROPIACIÓN ILÍCITA.', NULL, 'e', 'APROPIACIÓN ILÍCITA.', '(ART: 190)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO III]', '184198'),
(2057, 'Decreto Legislativo Nº 635 Código Penal', 'EL CURADOR, TUTOR O ALBACEA, QUE EN SU PROVECHO SE APROPIA INDEBIDAMENTE DE UN BIEN MUEBLE QUE HA RECIBIDO EN COMISIÓN, QUE PRODUZCA OBLIGACIÓN DE DEVOLVER, COMETE DELITO DE:', 'HURTO AGRAVADO.', 'CORRUPCIÓN DE FUNCIONARIOS.', 'APROPIACIÓN ILÍCITA COMÚN.', 'ESTAFA.', 'MALVERSACIÓN DE FONDOS.', NULL, 'c', 'APROPIACIÓN ILÍCITA COMÚN.', '(ART: 190)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO III]', '184199'),
(2058, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN EL BIEN OBJETO DEL HECHO, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE APROPIACIÓN ILÍCITA:', 'ALIMENTOS.', 'MEDICINAS.', 'BIENES DESTINADOS AL AUXILIO DE POBLACIONES QUE SUFREN LAS CONSECUENCIAS DE DESASTRES NATURALES.', 'BIENES DE ADULTOS MAYORES.', 'BIENES DE ORFANATOS Y ASILOS.', NULL, 'c', 'BIENES DESTINADOS AL AUXILIO DE POBLACIONES QUE SUFREN LAS CONSECUENCIAS DE DESASTRES', '(ART: 190)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO III]', '184200'),
(2059, 'Decreto Legislativo Nº 635 Código Penal', 'EL PROPIETARIO DE UN BIEN MUEBLE QUE LO SUSTRAE DE QUIEN LO TENGA LEGÍTIMAMENTE EN SU PODER, CON PERJUICIO DE ÉSTE O DE UN TERCERO COMETE EL DELITO DE:', 'HURTO.', 'APROPIACIÓN ILÍCITA AGRAVADA.', 'APROPIACIÓN IRREGULAR.', 'SUSTRACCIÓN DE BIEN PROPIO.', 'ROBO.', NULL, 'd', 'SUSTRACCIÓN DE BIEN PROPIO.', '(ART: 191)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO III]', '184201'),
(2060, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ADQUIERE, RECIBE EN DONACIÓN O EN PRENDA O GUARDA, ESCONDE, VENDE O AYUDA A NEGOCIAR UN BIEN DE CUYA PROCEDENCIA DELICTUOSA TENÍA CONOCIMIENTO O DEBÍA PRESUMIR QUE PROVENÍA DE UN DELITO, COMETE EL DELITO DE:', 'ENCUBRIMIENTO REAL.', 'OMISIÓN DE DENUNCIA.', 'ESTAFA.', 'RECEPTACIÓN.', 'APROPIACIÓN ILÍCITA.', NULL, 'd', 'RECEPTACIÓN.', '(ART: 194)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184202'),
(2061, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SIGUIENTES ENUNCIADOS PRESENTADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE RECEPTACIÓN:', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO AL USO PÚBLICO.', 'EL BIEN ES PROPIEDAD DE ASILOS Y ALBERGUES.', 'EL BIEN ES PROPIEDAD DE PERSONAS POBRES.', 'EL BIEN ES PROPIEDAD DE COMUNIDADES NATIVAS.', 'EL BIEN ES PROPIEDAD DE ANCIANOS EN INCAPACIDAD DE RESISTIR.', NULL, 'a', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO AL USO PÚBLICO.', '(ART: 195)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184203'),
(2062, 'Decreto Legislativo Nº 635 Código Penal', 'EL JUEZ O EL FISCAL QUE DICTA RESOLUCIÓN O EMITE DICTAMEN, MANIFIESTAMENTE CONTRARIOS AL TEXTO EXPRESO Y CLARO DE LA LEY, O CITA PRUEBAS INEXISTENTES O HECHOS FALSOS, O SE APOYA EN LEYES SUPUESTAS O DEROGADAS. COMETE EL DELITO DE:', 'CONCUSIÓN.', 'PREVARICATO.', 'FALSEDAD GENÉRICA.', 'FALSIFICACIÓN DE DOCUMENTOS.', 'MANIPULACIÓN PROVOCADA.', NULL, 'b', 'PREVARICATO.', '(ART: 418)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION II]', '184204'),
(2063, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE RECEPTACIÓN:', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO AL USO PRIVADO.', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO A PROGRAMAS DE APOYO SOCIAL.', 'EL BIEN ES PROPIEDAD DE PERSONAS EN EXTREMA POBREZA.', 'EL BIEN ES PROPIEDAD DE COMUNIDADES NATIVAS O CAMPESINAS.', 'EL BIEN ES PROPIEDAD DE ANCIANOS EN INCAPACIDAD DE RESISTIR.', NULL, 'b', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO A PROGRAMAS DE APOYO SOCIAL.', '(ART: 195)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184205'),
(2064, 'Decreto Legislativo Nº 635 Código Penal', 'CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE RECEPTACIÓN:', 'EL BIEN ES PROPIEDAD DE COMUNIDADES NATIVAS O CAMPESINAS.', 'EL BIEN ES EQUIPO DE PESCA ARTESANAL.', 'EL BIEN ES PROPIEDAD DE PERSONAS POBRES.', 'EL BIEN ES VEHÍCULO AUTOMOTOR, SUS AUTOPARTES O ACCESORIOS.', 'EL BIEN ES PROPIEDAD DE MENORES DE EDAD.', NULL, 'd', 'EL BIEN ES VEHÍCULO AUTOMOTOR, SUS AUTOPARTES O ACCESORIOS.', '(ART: 195)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184206'),
(2065, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE RECEPTACIÓN:', 'EL BIEN ES ALIMENTO Y BEBIDA DE CONSUMO HUMANO.', 'EL BIEN ES PROPIEDAD DE ANCIANOS EN INCAPACIDAD DE RESISTIR.', 'EL BIEN ES PROPIEDAD DE COMUNIDADES NATIVAS.', 'EL BIEN ES GAS, HIDROCARBUROS O PRODUCTOS DERIVADOS.', 'EL BIEN ES MEDICINA E INSTRUMENTAL MÉDICO.', NULL, 'd', 'EL BIEN ES GAS, HIDROCARBUROS O PRODUCTOS DERIVADOS.', '(ART: 195)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184207'),
(2066, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, NO ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE RECEPTACIÓN:', 'EL BIEN ES GAS, HIDROCARBUROS O PRODUCTOS DERIVADOS.', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO A PROGRAMAS DE APOYO SOCIAL.', 'EL BIEN ES MEDICINA E INSTRUMENTAL MÉDICO.', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO A FINES ASISTENCIALES.', 'EL BIEN ES PROPIEDAD DEL ESTADO DESTINADO AL USO PÚBLICO.', NULL, 'c', 'EL BIEN ES MEDICINA E INSTRUMENTAL MÉDICO.', '(ART: 195)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184208'),
(2067, 'Decreto Legislativo Nº 635 Código Penal', 'LA EXTORSIÓN AGRAVADA, ES UNA MODALIDAD DEL DELITO:', 'SECUESTRO.', 'CONTRA LA SEGURIDAD PÚBLICA.', 'CONTRA LA LIBERTAD INDIVIDUAL.', 'CONTRA EL PATRIMONIO.', 'CONTRA LA SEGURIDAD CIUDADANA.', NULL, 'd', 'CONTRA EL PATRIMONIO.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184209'),
(2068, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO PÚBLICO CON PODER DE DECISIÓN QUE, CONTRAVINIENDO LO ESTABLECIDO EN EL ART. 42° DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ, PARTICIPE EN UNA HUELGA CON EL OBJETO DE OBTENER PARA SÍ O PARA TERCEROS CUALQUIER BENEFICIO O VENTAJA ECONÓMICA INDEBIDA U OTRA VENTAJA DE CUALQUIER OTRA ÍNDOLE COMETE EL DELITO:', 'CONTRA LOS PODERES DEL ESTADO Y EL ORDEN CONSTITUCIONAL - REBELIÓN.', 'CONTRA LA ADMINISTRACIÓN PÚBLICA - VIOLENCIA Y RESISTENCIA A LA AUTORIDAD.', 'CONTRA LA ADMINISTRACIÓN PÚBLICA - ABANDONO DE CARGO.', 'CONTRA EL PATRIMONIO - EXTORSIÓN.', 'CONTRA EL ORDEN ECONÓMICO - DESEMPEÑO DE ACTIVIDADES NO AUTORIZADAS.', NULL, 'd', 'CONTRA EL PATRIMONIO - EXTORSIÓN.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184210'),
(2069, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MEDIANTE VIOLENCIA O AMENAZA, TOMA LOCALES, OBSTACULIZA VÍAS DE COMUNICACIÓN O IMPIDE EL LIBRE TRÁNSITO DE LA CIUDADANÍA O PERTURBA EL NORMAL FUNCIONAMIENTO DE LOS SERVICIOS PÚBLICOS O LA EJECUCIÓN DE OBRAS LEGALMENTE AUTORIZADAS, CON EL OBJETO DE OBTENER DE LAS AUTORIDADES CUALQUIER BENEFICIO O VENTAJA ECONÓMICA INDEBIDA U OTRA VENTAJA DE CUALQUIER OTRA ÍNDOLE COMETE DELITO:', 'CONTRA LA SEGURIDAD PÚBLICA -CONTRA LOS MEDIOS DE TRANSPORTE.', 'CONTRA LA ADMINISTRACIÓN PÚBLICA-VIOLENCIA Y RESISTENCIA A LA AUTORIDAD.', 'CONTRA LA LIBERTAD -VIOLACIÓN DE LA LIBERTAD DE TRABAJO.', 'CONTRA EL PATRIMONIO-EXTORSIÓN.', 'CONTRA EL ORDEN ECONÓMICO -DESEMPEÑO DE ACTIVIDADES NO AUTORIZADAS.', NULL, 'd', 'CONTRA EL PATRIMONIO-EXTORSIÓN.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184211'),
(2070, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE EXTORSIÓN:', 'EN AGRAVIO DE PROPIETARIO DE INMUEBLES.', 'EL REHÉN ES MAYOR DE 60 AÑOS.', 'EL REHÉN ADOLECE DE ENFERMEDAD LEVE.', 'EL AGENTE SE VALE DE MAYORES DE EDAD.', 'EN AGRAVIO DE REPRESENTANTE DIPLOMÁTICO.', NULL, 'e', 'EN AGRAVIO DE REPRESENTANTE DIPLOMÁTICO.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184212'),
(2071, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, NO ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE EXTORSIÓN:', 'EN AGRAVIO DE PROPIETARIO DE OBRA DE CONSTRUCCIÓN CIVIL.', 'EN AGRAVIO DE CONTRATISTA DE OBRA DE CONSTRUCCIÓN CIVIL PÚBLICA.', 'EN AGRAVIO DE CONTRATISTA DE OBRA DE CONSTRUCCIÓN CIVIL PRIVADA.', 'EN AGRAVIO DE RESPONSABLE DE OBRA DE CONSTRUCCIÓN CIVIL PÚBLICA.', 'EN AGRAVIO DE INTEGRANTE DEL SINDICATO DE CONSTRUCCIÓN CIVIL.', NULL, 'e', 'EN AGRAVIO DE INTEGRANTE DEL SINDICATO DE CONSTRUCCIÓN CIVIL.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184213'),
(2072, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, NO ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE EXTORSIÓN:', 'A MANO ARMADA O UTILIZANDO ARTEFACTOS EXPLOSIVOS.', 'EN AGRAVIO DE CONTRATISTA DE OBRA DE CONSTRUCCIÓN CIVIL PÚBLICA.', 'APROVECHANDO SU CONDICIÓN DE PROPIETARIO DE OBRA DE CONSTRUCCIÓN CIVIL.', 'SIMULANDO SER TRABAJADOR DE CONSTRUCCIÓN CIVIL.', 'APROVECHANDO SU CONDICIÓN DE INTEGRANTE DEL SINDICATO DE CONSTRUCCIÓN CIVIL.', NULL, 'c', 'APROVECHANDO SU CONDICIÓN DE PROPIETARIO DE OBRA DE CONSTRUCCIÓN CIVIL.', '(ART: 200)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184214'),
(2073, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, HACIENDO SABER A OTRO QUE SE DISPONE A PUBLICAR, DENUNCIAR O REVELAR UN HECHO O CONDUCTA CUYA DIVULGACIÓN PUEDE PERJUDICARLO PERSONALMENTE O A UN TERCERO CON QUIEN ESTÉ ESTRECHAMENTE VINCULADO, TRATA DE DETERMINARLO O LO DETERMINA A COMPRAR SU SILENCIO, COMETE DELITO DE:', 'CONTRA EL PATRIMONIO - CHANTAJE.', 'CONTRA LA LIBERTAD -VIOLACIÓN DEL SECRETO PROFESIONAL.', 'CONTRA EL HONOR - DIFAMACIÓN.', 'CONTRA LA LIBERTAD - VIOLACIÓN DE LA INTIMIDAD.', 'CONTRA EL HONOR - CALUMNIA.', NULL, 'a', 'CONTRA EL PATRIMONIO - CHANTAJE.', '(ART: 201)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VII]', '184215'),
(2074, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, ILEGÍTIMAMENTE, INGRESA A UN INMUEBLE MEDIANTE ACTOS OCULTOS, EN AUSENCIA DEL POSEEDOR O CON PRECAUCIONES PARA ASEGURARSE EL DESCONOCIMIENTO DE QUIENES TENGAN DERECHO A OPONERSE, COMETE DELITO DE:', 'CONTRA LA LIBERTAD - VIOLACIÓN DE DOMICILIO.', 'CONTRA LA ADMINISTRACIÓN PÚBLICA-ALLANAMIENTO INDEBIDO DE MORADA.', 'CONTRA EL PATRIMONIO - USURPACIÓN.', 'CONTRA LA LIBERTAD - VIOLACIÓN DE LA INTIMIDAD.', 'CONTRA EL PATRIMONIO - APROPIACIÓN ILÍCITA.', NULL, 'c', 'CONTRA EL PATRIMONIO - USURPACIÓN.', '(ART: 202)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184216'),
(2075, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE USURPACIÓN:', 'UTILIZANDO DOCUMENTOS PRIVADOS.', 'EN AGRAVIO DE FUNCIONARIO O SERVIDOR PÚBLICO.', 'USANDO SUSTANCIAS PELIGROSAS.', 'EL AGENTE SE VALE DE MAYORES DE EDAD.', 'EN AGRAVIO DE REPRESENTANTE DIPLOMÁTICO.', NULL, 'c', 'USANDO SUSTANCIAS PELIGROSAS.', '(ART: 204)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184217'),
(2076, 'Decreto Legislativo Nº 635 Código Penal', 'TODOS LOS DONATIVOS DADIVAS O PRESENTES RECIBIDOS POR FUNCIONARIOS Y/O SERVIDORES PÚBLICOS DE MANERA ILÍCITA SERÁN:', 'INCAUTADOS.', 'DONADOS.', 'DECOMISADOS.', 'SUSTRAÍDOS.', 'DEVUELTOS.', NULL, 'c', 'DECOMISADOS.', '(ART: 401-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184218'),
(2077, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE USURPACIÓN:', 'UTILIZANDO DOCUMENTOS PRIVADOS AUTÉNTICOS.', 'AFECTANDO LA LIBRE CIRCULACIÓN EN VÍAS DE COMUNICACIÓN.', 'USANDO SUSTANCIAS LÍQUIDAS.', 'EL AGENTE SE VALE DE MAYORES DE EDAD.', 'EN AGRAVIO DE REPRESENTANTE DIPLOMÁTICO.', NULL, 'b', 'AFECTANDO LA LIBRE CIRCULACIÓN EN VÍAS DE COMUNICACIÓN.', '(ART: 204)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184219'),
(2078, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE DENUNCIA A LA AUTORIDAD UN HECHO PUNIBLE, A SABIENDAS DE QUE NO SE HA COMETIDO O QUE HA SIDO POR PERSONA DISTINTA A LA DENUNCIADA, COMETE DELITO DE:', 'DENUNCIA PERNICIOSA.', 'DENUNCIA CALUMNIOSA.', 'DENUNCIA FALSA.', 'DENUNCIA OMISIVA.', 'DENUNCIA ENGAÑOSA.', NULL, 'b', 'DENUNCIA CALUMNIOSA.', '(ART: 402)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184220'),
(2079, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, ESTANDO LEGALMENTE PRIVADO DE SU LIBERTAD, SE EVADE POR MEDIO DE LA VIOLENCIA O AMENAZA, COMETE DELITO DE:', 'EVASIÓN CAUSANDO LESIONES.', 'FUGA MEDIANTE LESIONES.', 'FUGA MEDIANTE AGRESIÓN Y AMENAZA.', 'EVASIÓN VIOLENTA.', 'EVASIÓN MEDIANTE VIOLENCIA O AMENAZA.', NULL, 'e', 'EVASIÓN MEDIANTE VIOLENCIA O AMENAZA.', '(ART: 413)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184221'),
(2080, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, NO ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE USURPACIÓN:', 'COLOCANDO ANUNCIOS.', 'COLOCANDO HITOS.', 'COLOCANDO ESTERAS.', 'COLOCANDO PLÁSTICOS.', 'COLOCANDO ANIMALES.', NULL, 'e', 'COLOCANDO ANIMALES.', '(ART: 204)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184222'),
(2081, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, NO ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE USURPACIÓN:', 'COLOCANDO PANELES O ANUNCIOS.', 'ABUSANDO DE SU CARGO O CONDICIÓN DE FUNCIONARIO PÚBLICO.', 'DESVIANDO EL CURSO DE AGUAS PÚBLICAS.', 'USANDO ARMAS DE FUEGO O EXPLOSIVOS.', 'COLOCANDO CERCOS PERIMÉTRICOS.', NULL, 'c', 'DESVIANDO EL CURSO DE AGUAS PÚBLICAS.', '(ART: 204)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO VIII]', '184223'),
(2082, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE COMETE ACTOS DE CRUELDAD CONTRA UN ANIMAL DOMÉSTICO O UN ANIMAL SILVESTRE, O LOS ABANDONA, COMETE EL DELITO:', 'CONTRA LOS RECURSOS NATURALES.', 'ABANDONO Y ACTOS DE CRUELDAD CONTRA ANIMALES DOMÉSTICOS Y SILVESTRES.', 'CONTRA EL PATRIMONIO CULTURAL.', 'CONTRA EL PATRIMONIO - ABIGEATO.', 'CONTRA LA VIDA, EL CUERPO Y LA SALUD.', NULL, 'b', 'ABANDONO Y ACTOS DE CRUELDAD CONTRA ANIMALES DOMÉSTICOS Y SILVESTRES.', '(ART: 206-A)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IX]', '184225'),
(2083, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA DESORDEN EN LA SALA DE SESIONES DEL CONGRESO O DE LAS CÁMARAS LEGISLATIVAS, DE LAS ASAMBLEAS REGIONALES, DE LOS CONSEJOS MUNICIPALES O DE LOS TRIBUNALES DE JUSTICIA U OTRO LUGAR DONDE LAS AUTORIDADES PÚBLICAS EJERCEN SUS FUNCIONES O EL QUE ENTRA ARMADO EN DICHOS LUGARES, COMETE EL DELITO:', 'CONTRA LOS PODERES DEL ESTADO - CONTRA LA VOLUNTAD POPULAR.', 'CONTRA EL PATRIMONIO - USURPACIÓN AGRAVADA.', 'CONTRA EL PATRIMONIO CULTURAL -CONTRA LOS BIENES CULTURALES.', 'CONTRA LA PAZ PÚBLICA - TERRORISMO.', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SU FUNCIÓN.', NULL, 'e', 'PERTURBACIÓN DEL ORDEN EN EL LUGAR DONDE LA AUTORIDAD EJERCE SU FUNCIÓN.', '(ART: 375)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO I]  [SECCION III]', '184226'),
(2084, 'Decreto Legislativo Nº 635 Código Penal', 'CUAL DE LOS SIGUIENTES ENUNCIADOS, ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE PROXENETISMO:', 'LA VÍCTIMA ES PARIENTE EN 5TO GRADO DE AFINIDAD.', 'LA VÍCTIMA SE ENCUENTRA EN INCAPACIDAD DE RESISTIR.', 'EL PROXENETISMO SEA UN MEDIO DE SUBSISTENCIA DEL AGENTE.', 'SE ESCLAVIZA A LA VÍCTIMA.', 'SE EJERCE LA ACCIÓN EN CONDICIONES DE FALTA DE HIGIENE.', NULL, 'c', 'EL PROXENETISMO SEA UN MEDIO DE SUBSISTENCIA DEL AGENTE.', '(ART: 181)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO X]', '184227'),
(2085, 'Decreto Legislativo Nº 635 Código Penal', 'AL QUE CON LA FINALIDAD DE CONTRIBUIR A LA COMISIÓN DEL DELITO DE SECUESTRO, SUMINISTRA INFORMACIÓN QUE HAYA CONOCIDO POR RAZÓN O CON OCASIÓN DE SUS FUNCIONES, CARGO U OFICIO, O PROPORCIONA DELIBERADAMENTE LOS MEDIOS PARA LA PERPETRACIÓN DEL DELITO, SE LE APLICARÁ:', 'LA MISMA PENA.', 'EL DOBLE DE PENA.', 'EL TERCIO DE LA PENA.', 'LA MISMA PENA MAS UN TERCIO.', 'NINGUNA DE LAS ANTERIORES.', NULL, 'a', 'LA MISMA PENA.', '(ART: 152)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO I]', '184228'),
(2086, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ENUNCIADOS, NO ES UNA CIRCUNSTANCIA AGRAVANTE DEL DELITO DE SECUESTRO:', 'EL AGRAVIADO ES FUNCIONARIO O SERVIDOR PÚBLICO.', 'EL AGRAVIADO ES DIPLOMÁTICO DE OTRO PAÍS.', 'EL AGRAVIADO ES MENOR DE EDAD.', 'EL AGRAVIADO SUFRE DISCAPACIDAD.', 'SE COMETE PARA OBTENER TEJIDOS SOMÁTICOS DEL AGRAVIADO.', NULL, 'e', 'SE COMETE PARA OBTENER TEJIDOS SOMÁTICOS DEL AGRAVIADO.', '(ART: 152)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO I]', '184229'),
(2087, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATA A OTRO CON GRAN CRUELDAD O ALEVOSÍA, QUE DELITO COMETE:', 'HOMICIDIO CALIFICADO.', 'SICARIATO.', 'INFANTICIDIO.', 'ESTAFA.', 'SUICIDIO.', NULL, 'a', 'HOMICIDIO CALIFICADO.', '(ART: 108)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '184231'),
(2088, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATA A UNA MUJER POR SU CONDICION DE TAL DENTRO DEL CONTEXTO DE LA VIOLENCIA FAMILIAR, QUE DELITO COMETE:', 'PARRICIDIO.', 'HOMICIDIO.', 'SUICIDIO.', 'FEMINICIDIO.', 'LESIONES.', NULL, 'd', 'FEMINICIDIO.', '(ART: 108-B)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '184232'),
(2089, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATA A OTRO POR ORDEN, ENCARGO O ACUERDO CON EL PROPÓSITO DE OBTENER PARA SÍ O PARA OTRO UN BENEFICIO ECONÓMICO, QUE DELITO COMETE:', 'SUICIDIO.', 'INFANTICIDIO.', 'SICARIATO.', 'LESIONES.', 'PARRICIDIO.', NULL, 'c', 'SICARIATO.', '(ART: 108-C)** [TITULO I]  [CAPITULO I]', '184233'),
(2090, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MATA A OTRO BAJO EL IMPERIO DE UNA EMOCIÓN VIOLENTA QUE LAS CIRCUNSTANCIAS HACEN EXCUSABLE, QUE DELITO COMETE:', 'HOMICIDIO POR EMOCIÓN VIOLENTA.', 'SICARIATO.', 'SUICIDIO.', 'HOMICIDIO CALIFICADO.', 'HOMICIDIO SIMPLE.', NULL, 'a', 'HOMICIDIO POR EMOCIÓN VIOLENTA.', '(ART: 109)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '184234'),
(2091, 'Decreto Legislativo Nº 635 Código Penal', 'LA MADRE QUE MATA A SU HIJO DURANTE EL PARTO O BAJO LA INFLUENCIA DEL ESTADO PUERPERAL, QUE DELITO COMETE:', 'INFANTICIDIO.', 'PARRICIDIO.', 'HOMICIDIO CALIFICADO.', 'SUICIDIO.', 'LESIONES.', NULL, 'a', 'INFANTICIDIO.', '(ART: 110)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO I]', '184235'),
(2092, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA EL ABORTO CON EL CONSENTIMIENTO DE LA GESTANTE, QUE DELITO COMETE:', 'ABORTO CONSENTIDO.', 'ABORTO PRETERINTENCIONAL.', 'ABORTO TERAPÉUTICO.', 'AUTOABORTO.', 'HOMICIDIO SIMPLE.', NULL, 'a', 'ABORTO CONSENTIDO.', '(ART: 115)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '184237'),
(2093, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE HACE ABORTAR A UNA MUJER SIN SU CONSENTIMIENTO, QUE DELITO COMETE:', 'HOMICIDIO.', 'AUTOABORTO.', 'SUICIDIO.', 'PARRICIDIO.', 'ABORTO SIN CONSENTIMIENTO.', NULL, 'e', 'ABORTO SIN CONSENTIMIENTO.', '(ART: 116)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '184238'),
(2094, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, CON VIOLENCIA OCASIONA UN ABORTO, SIN HABER TENIDO EL PROPÓSITO DE CAUSARLO, COMETE DELITO DE:', 'AUTOABORTO.', 'HOMICIDIO.', 'ABORTO PRETERINTENCIONAL.', 'PARRICIDIO.', 'INFANTICIDIO.', NULL, 'c', 'ABORTO PRETERINTENCIONAL.', '(ART: 118)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO II]', '184239'),
(2095, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA A OTRO DAÑO GRAVE EN EL CUERPO O EN LA SALUD FÍSICA O MENTAL, PONIENDO EN PELIGRO INMINENTE LA VIDA DE LA VÍCTIMA, COMETE DELITO DE:', 'HOMICIDIO.', 'LESIONES GRAVES.', 'ABORTO.', 'DAÑOS.', 'LESIONES LEVES.', NULL, 'b', 'LESIONES GRAVES.', '(ART: 121)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '184240'),
(2096, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CAUSA A OTRO LESIONES EN EL CUERPO O EN LA SALUD FÍSICA O MENTAL QUE REQUIERA MAS DE DIEZ Y MENOS DE VEINTE DÍAS DE ASISTENCIA O DESCANSO, SEGÚN PRESCRIPCIÓN FACULTATIVA, QUE DELITO COMETE:', 'LESIONES LEVES.', 'LESIONES CULPOSAS.', 'LESIONES GRAVES.', 'DAÑOS.', 'ABORTO.', NULL, 'a', 'LESIONES LEVES.', '(ART: 122)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '184241'),
(2097, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE POR CULPA CAUSA A OTRO UN DAÑO EN EL CUERPO O EN LA SALUD QUE DELITO COMETE:', 'LESIONES CULPOSAS.', 'LESIONES MENORES.', 'LESIONES LEVES.', 'LESIONES GRAVES.', 'DAÑOS.', NULL, 'a', 'LESIONES CULPOSAS.', '(ART: 124)** [LIBRO SEGUNDO]  [TITULO I]  [CAPITULO III]', '184242'),
(2098, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MEDIANTE AMENAZA O VIOLENCIA OBLIGA A OTRO A HACER LO QUE LA LEY NO MANDA O LE IMPIDE HACER LO QUE ELLA NO PROHÍBE, COMETE DELITO DE:', 'HURTO.', 'EXPLOTACIÓN SEXUAL.', 'SECUESTRO.', 'TRATA DE PERSONAS.', 'COACCIÓN.', NULL, 'e', 'COACCIÓN.', '(ART: 151)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO I]', '184243'),
(2099, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SIN DERECHO, MOTIVO NI FACULTAD JUSTIFICADA, PRIVA A OTRO DE SU LIBERTAD PERSONAL, CUALQUIERA SEA EL MÓVIL, EL PROPÓSITO, LA MODALIDAD O CIRCUNSTANCIA O TIEMPO QUE EL AGRAVIADO SUFRA LA PRIVACIÓN O RESTRICCIÓN DE SU LIBERTAD, COMETE DELITO DE:', 'ROBO.', 'COACCIÓN.', 'SECUESTRO.', 'TRATA DE PERSONAS.', 'VIOLACIÓN DE LA INTIMIDAD.', NULL, 'c', 'SECUESTRO.', '(ART: 152)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO I]', '184244'),
(2100, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, EN LUGAR PÚBLICO O PONIENDO EN RIESGO BIENES JURÍDICOS DE TERCEROS Y TENIENDO LICENCIA PARA PORTAR ARMA DE FUEGO, HACE USO, MANIOBRA O DE CUALQUIER FORMA MANIPULA LA MISMA EN ESTADO DE EBRIEDAD, CON PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN MAYOR DE 0.5 GRAMOS-LITRO O BAJO EL EFECTO DE ESTUPEFACIENTES, DROGAS TÓXICAS, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS, COMETE DELITO DE:', 'COACCIÓN.', 'SECUESTRO.', 'USO DE ARMAS EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', 'EXTORSIÓN.', 'ESTAFA.', NULL, 'c', 'USO DE ARMAS EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', '(ART: 279-F)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184245'),
(2101, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, MEDIANTE VIOLENCIA, AMENAZA U OTRO MEDIO OBLIGA A UNA PERSONA A EJERCER ACTOS DE CONNOTACIÓN SEXUAL CON LA FINALIDAD DE OBTENER UN APROVECHAMIENTO ECONÓMICO O DE OTRA ÍNDOLE, COMETE DELITO DE:', 'SECUESTRO.', 'EXPLOTACIÓN SEXUAL.', 'VIOLACIÓN SEXUAL.', 'ACOSO.', 'SEDUCCIÓN.', NULL, 'b', 'EXPLOTACIÓN SEXUAL.', '(ART: 129-C)** [TITULO I-A]  [CAPITULO II]', '184246'),
(2102, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE OBLIGA A UNA PERSONA A TRABAJAR EN CONDICIONES DE ESCLAVITUD O SERVIDUMBRE, O LA REDUCE O MANTIENE EN DICHAS CONDICIONES, CON EXCEPCIÓN DE LOS SUPUESTOS DEL DELITO DE EXPLOTACIÓN SEXUAL, COMETE DELITO DE:', 'COACCIÓN.', 'SECUESTRO.', 'EXTORSIÓN.', 'ESCLAVITUD Y OTRAS FORMAS DE EXPLOTACIÓN.', 'ACOSO.', NULL, 'd', 'ESCLAVITUD Y OTRAS FORMAS DE EXPLOTACIÓN.', '(ART: 129-Ñ)** [TITULO I-A]  [CAPITULO II]', '184247'),
(2103, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SIN DERECHO, PENETRA EN MORADA O CASA DE NEGOCIO AJENA, EN SU DEPENDENCIA O EN EL RECINTO HABITADO POR OTRO O EL QUE PERMANECE ALLÍ REHUSANDO LA INTIMACIÓN QUE LE HAGA QUIEN TENGA DERECHO A FORMULARLA, COMETE DELITO DE:', 'ALLANAMIENTO.', 'COACCIÓN.', 'ACOSO.', 'VIOLACIÓN DE DOMICILIO.', 'VIOLACIÓN DE LA INTIMIDAD.', NULL, 'd', 'VIOLACIÓN DE DOMICILIO.', '(ART: 159)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO III]', '184248'),
(2104, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ALLANA UN DOMICILIO, SIN LAS FORMALIDADES PRESCRITAS POR LA LEY O FUERA DE LOS CASOS QUE ELLA DETERMINA, COMETE DELITO DE:', 'VIOLACIÓN DE DOMICILIO.', 'VIOLACIÓN DE CORRESPONDENCIA.', 'ALLANAMIENTO ILEGAL DE DOMICILIO.', 'SECUESTRO.', 'ROBO.', NULL, 'c', 'ALLANAMIENTO ILEGAL DE DOMICILIO.', '(ART: 160)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO III]', '184249'),
(2105, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE INDEBIDAMENTE, INTERVIENE O INTERFIERE O ESCUCHA UNA CONVERSACIÓN TELEFÓNICA O SIMILAR, COMETE DELITO DE:', 'INTERFERENCIA TELEFÓNICA.', 'VIOLACIÓN DE CORRESPONDENCIA.', 'VIOLACIÓN DEL SECRETO PROFESIONAL.', 'COACCIÓN.', 'ACOSO.', NULL, 'a', 'INTERFERENCIA TELEFÓNICA.', '(ART: 162)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IV]', '184250'),
(2106, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE PARA OBTENER PROVECHO, SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE, TOTAL O PARCIALMENTE AJENO, SUSTRAYÉNDOLO DEL LUGAR DONDE SE ENCUENTRA, COMETE DELITO DE:', 'HURTO SIMPLE.', 'ROBO.', 'HURTO AGRAVADO.', 'APROPIACIÓN ILÍCITA.', 'RECEPTACIÓN.', NULL, 'a', 'HURTO SIMPLE.', '(ART: 185)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO I]', '184251'),
(2107, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE PARA OBTENER PROVECHO, SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE, TOTAL O PARCIALMENTE AJENO, SUSTRAYÉNDOLO DEL LUGAR DONDE SE ENCUENTRA, MEDIANTE DESTREZA, ESCALAMIENTO, ROTURA DE OBSTÁCULOS, COMETE DELITO DE:', 'HURTO SIMPLE.', 'ROBO.', 'ROBO AGRAVADO.', 'DAÑOS.', 'HURTO AGRAVADO.', NULL, 'e', 'HURTO AGRAVADO.', '(ART: 186)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO I]', '184252'),
(2108, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE TOTAL O PARCIALMENTE AJENO, PARA APROVECHARSE DE ÉL, SUSTRAYÉNDOLO DEL LUGAR EN QUE SE ENCUENTRA, EMPLEANDO VIOLENCIA CONTRA LA PERSONA O AMENAZÁNDOLA CON UN PELIGRO INMINENTE PARA SU VIDA O INTEGRIDAD FÍSICA, COMETE DELITO DE:', 'HURTO DE CASO.', 'HURTO SIMPLE.', 'APROPIACIÓN ILÍCITA.', 'ROBO AGRAVADO.', 'ROBO.', NULL, 'e', 'ROBO.', '(ART: 188)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO II]', '184253'),
(2109, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SE APODERA ILEGÍTIMAMENTE DE UN BIEN MUEBLE TOTAL O PARCIALMENTE, PARA APROVECHARSE DE EL, SUSTRAYÉNDOLO DEL LUGAR EN QUE SE ENCUENTRA, EMPLEANDO VIOLENCIA CONTRA LA PERSONA O AMENAZÁNDOLA CON UN PELIGRO INMINENTE PARA SU VIDA O INTEGRIDAD FÍSICA, CON EL CONCURSO DE DOS O MAS PERSONAS, QUE DELITO COMETE:', 'HURTO AGRAVADO.', 'HURTO SIMPLE.', 'APROPIACIÓN ILÍCITA.', 'ROBO AGRAVADO.', 'HURTO DE USO.', NULL, 'd', 'ROBO AGRAVADO.', '(ART: 189)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO II]', '184254'),
(2110, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, EN SU PROVECHO O DE UN TERCERO, SE APROPIA INDEBIDAMENTE DE UN BIEN MUEBLE, UNA SUMA DE DINERO O UN VALOR QUE HA RECIBIDO EN DEPÓSITO, COMISIÓN, ADMINISTRACIÓN U OTRO TÍTULO SEMEJANTE QUE PRODUZCA OBLIGACIÓN DE ENTREGAR, DEVOLVER, O HACER UN USO DETERMINADO, COMETE DELITO DE:', 'HURTO.', 'ROBO.', 'APROPIACIÓN ILÍCITA.', 'ESTAFA.', 'RECEPTACIÓN.', NULL, 'c', 'APROPIACIÓN ILÍCITA.', '(ART: 190)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO III]', '184255'),
(2111, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ADQUIERE, RECIBE EN DONACIÓN, EN PRENDA, GUARDA, ESCONDE, EXPONE PARA LA VENTA, AYUDA A NEGOCIAR, COMERCIALIZA, DESENSAMBLA O UTILIZA, UN BIEN O SUS PARTES DE CUYA PROCEDENCIA DELICTUOSA TENÍA CONOCIMIENTO O DEBÍA PRESUMIR QUE PROVENÍA DE UN DELITO, COMETE DELITO DE:', 'HURTO.', 'ESTAFA.', 'APROPIACIÓN ILÍCITA.', 'ROBO.', 'RECEPTACIÓN.', NULL, 'e', 'RECEPTACIÓN.', '(ART: 194)** [LIBRO SEGUNDO]  [TITULO V]  [CAPITULO IV]', '184256'),
(2112, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE ENCONTRÁNDOSE EN ESTADO DE EBRIEDAD, CON PRESENCIA DE ALCOHOL EN LA SANGRE EN PROPORCIÓN MAYOR DE 0.5 GRAMOS-LITRO, O BAJO EL EFECTO DE DROGAS TÓXICAS, ESTUPEFACIENTES, SUSTANCIAS PSICOTRÓPICAS O SINTÉTICAS, CONDUCE, OPERA O MANIOBRA VEHÍCULO MOTORIZADO, COMETE DELITO DE:', 'ATENTADO CONTRA LA SEGURIDAD COMÚN.', 'OMISIÓN DE AUXILIO O AVISO A LA AUTORIDAD.', 'LESIONES CULPOSAS.', 'ESTRAGOS ESPECIALES.', 'CONDUCCIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', NULL, 'e', 'CONDUCCIÓN EN ESTADO DE EBRIEDAD O DROGADICCIÓN.', '(ART: 274)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184257'),
(2113, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE SUSTRAE O ARREBATE ARMAS DE FUEGO EN GENERAL, O MUNICIONES Y GRANADAS DE GUERRA O EXPLOSIVOS A MIEMBROS DE LAS FUERZAS ARMADAS O DE LA POLICÍA NACIONAL O DE SERVICIOS DE SEGURIDAD, COMETE DELITO DE:', 'TRÁFICO DE PRODUCTOS PIROTÉCNICOS.', 'HURTO SIMPLE.', 'APROPIACIÓN ILÍCITA.', 'SUSTRACCIÓN O ARREBATO DE ARMAS DE FUEGO.', 'EXTORSIÓN.', NULL, 'd', 'SUSTRACCIÓN O ARREBATO DE ARMAS DE FUEGO.', '(ART: 279-B)** [LIBRO SEGUNDO]  [TITULO XII]  [CAPITULO I]', '184258'),
(2114, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE CON VIOLENCIA, FÍSICA O PSICOLÓGICA, GRAVE AMENAZA O APROVECHÁNDOSE DE UN ENTORNO DE COACCIÓN O DE CUALQUIER OTRO ENTORNO QUE IMPIDA A LA PERSONA DAR SU LIBRE CONSENTIMIENTO, OBLIGA A ESTA A TENER ACCESO CARNAL POR VÍA VAGINAL, ANAL O BUCAL O REALIZA CUALQUIER OTRO ACTO ANÁLOGO CON LA INTRODUCCIÓN DE UN OBJETO O PARTE DEL CUERPO POR ALGUNA DE LAS DOS PRIMERAS VÍAS, COMETE DELITO DE:', 'VIOLACIÓN DE LA INTIMIDAD.', 'VIOLACIÓN SEXUAL.', 'VIOLACIÓN DE MENOR DE EDAD.', 'COACCIÓN.', 'LESIONES GRAVES.', NULL, 'b', 'VIOLACIÓN SEXUAL.', '(ART: 170)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IX]', '184259'),
(2115, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, MEDIANTE ENGAÑO TIENE ACCESO CARNAL POR VÍA VAGINAL, ANAL O BUCAL O REALIZA CUALQUIER OTRO ACTO ANÁLOGO CON LA INTRODUCCIÓN DE UN OBJETO O PARTE DEL CUERPO POR ALGUNA DE LAS DOS PRIMERAS VÍAS, A UNA PERSONA DE CATORCE AÑOS Y MENOS DE DIECIOCHO AÑOS, COMETE DELITO DE:', 'VIOLACIÓN SEXUAL MEDIANTE ENGAÑO.', 'VIOLACIÓN DE MENOR DE EDAD.', 'DAÑOS.', 'TOCAMIENTOS INDEBIDOS.', 'ESTAFA.', NULL, 'a', 'VIOLACIÓN SEXUAL MEDIANTE ENGAÑO.', '(ART: 175)** [LIBRO SEGUNDO]  [TITULO IV]  [CAPITULO IX]', '184260'),
(2116, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO PÚBLICO QUE ABUSANDO DE SUS ATRIBUCIONES, COMETE U ORDENA UN ACTO ARBITRARIO QUE CAUSE PERJUICIO A ALGUIEN, COMETE DELITO DE:', 'COACCIÓN.', 'ABUSO DE AUTORIDAD.', 'RESISTENCIA A LA AUTORIDAD.', 'DESACATO.', 'CORRUPCIÓN DE FUNCIONARIOS.', NULL, 'b', 'ABUSO DE AUTORIDAD.', '(ART: 376)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION I]', '184262'),
(2117, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE, ABUSANDO DE SU CARGO, OBLIGA O INDUCE A UNA PERSONA A DAR O PROMETER INDEBIDAMENTE, PARA SÍ O PARA OTRO, UN BIEN O UN BENEFICIO PATRIMONIAL, COMETE DELITO DE:', 'PECULADO.', 'COLUSIÓN.', 'CONCUSIÓN.', 'COHECHO PASIVO.', 'COBRO INDEBIDO.', NULL, 'c', 'CONCUSIÓN.', '(ART: 382)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION II]', '184263'),
(2118, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE SE APROPIA O UTILIZA EN CUALQUIER FORMA, PARA SÍ O PARA OTRO, CAUDALES O EFECTOS CUYA PERCEPCIÓN, ADMINISTRACIÓN O CUSTODIA LE ESTÉN CONFIADOS, POR RAZÓN DE SU CARGO, COMETE DELITO DE:', 'CONCUSIÓN.', 'COBRO INDEBIDO.', 'MALVERSACIÓN.', 'PECULADO.', 'COLUSIÓN.', NULL, 'd', 'PECULADO.', '(ART: 387)** [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184264'),
(2119, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE DA AL DINERO O BIENES QUE ADMINISTRA UNA APLICACIÓN DEFINITIVA DIFERENTE DE AQUELLA A LOS QUE ESTÁN DESTINADOS, AFECTANDO EL SERVICIO O LA FUNCIÓN ENCOMENDADA, COMETE DELITO DE:', 'PECULADO DE USO.', 'APROPIACIÓN ILÍCITA.', 'MALVERSACIÓN.', 'COHECHO PASIVO.', 'CONCUSIÓN.', NULL, 'c', 'MALVERSACIÓN.', '(ART: 389)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION III]', '184265'),
(2120, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ACEPTE O RECIBA DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, PARA REALIZAR U OMITIR UN ACTO EN VIOLACIÓN DE SUS OBLIGACIONES O EL QUE LAS ACEPTA A CONSECUENCIA DE HABER FALTADO A ELLAS, COMETE DELITO DE:', 'APROPIACIÓN ILÍCITA.', 'COHECHO PASIVO ESPECÍFICO.', 'COHECHO PASIVO PROPIO.', 'MALVERSACIÓN.', 'COHECHO PASIVO IMPROPIO.', NULL, 'c', 'COHECHO PASIVO PROPIO.', '(ART: 393)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184266'),
(2121, 'Decreto Legislativo Nº 635 Código Penal', 'EL FUNCIONARIO O SERVIDOR PÚBLICO QUE ACEPTE O RECIBA DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO INDEBIDO PARA REALIZAR UN ACTO PROPIO DE SU CARGO O EMPLEO, SIN FALTAR A SU OBLIGACIÓN, O COMO CONSECUENCIA DEL YA REALIZADO, COMETE DELITO DE:', 'APROPIACIÓN ILÍCITA.', 'COHECHO PASIVO ESPECÍFICO.', 'PECULADO.', 'MALVERSACIÓN.', 'COHECHO PASIVO IMPROPIO.', NULL, 'e', 'COHECHO PASIVO IMPROPIO.', '(ART: 394)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184267'),
(2122, 'Decreto Legislativo Nº 635 Código Penal', 'EL MIEMBRO DE LA POLICÍA NACIONAL QUE ACEPTA O RECIBE DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO, PARA SÍ O PARA OTRO, PARA REALIZAR U OMITIR UN ACTO EN VIOLACIÓN DE SUS OBLIGACIONES DERIVADAS DE LA FUNCIÓN POLICIAL O EL QUE LAS ACEPTA A CONSECUENCIA DE HABER FALTADO A ELLAS, COMETE DELITO DE:', 'COHECHO PASIVO PROPIO.', 'COHECHO PASIVO ESPECÍFICO.', 'COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'APROPIACIÓN ILÍCITA.', 'PECULADO.', NULL, 'c', 'COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', '(ART: 395-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184268'),
(2123, 'Decreto Legislativo Nº 635 Código Penal', 'EL MIEMBRO DE LA POLICÍA NACIONAL O DEL SISTEMA PENITENCIARIO QUE ACEPTE O RECIBE DONATIVO, PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO INDEBIDO PARA REALIZAR U OMITIR UN ACTO PROPIO DE SU FUNCIÓN, SIN FALTAR A SU OBLIGACIÓN, O COMO CONSECUENCIA DEL ACTO YA REALIZADO U OMITIDO, COMETE DELITO DE:', 'PECULADO.', 'COBRO INDEBIDO.', 'COHECHO PASIVO PROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'COHECHO PASIVO IMPROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', 'COHECHO PASIVO ESPECÍFICO.', NULL, 'd', 'COHECHO PASIVO IMPROPIO EN EL EJERCICIO DE LA FUNCIÓN POLICIAL.', '(ART: 395-B)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184269'),
(2124, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE, INVOCANDO O TENIENDO INFLUENCIAS REALES O SIMULADAS, RECIBE, HACE DAR O PROMETER PARA SÍ O PARA UN TERCERO, DONATIVO O PROMESA O CUALQUIER OTRA VENTAJA O BENEFICIO CON EL OFRECIMIENTO DE INTERCEDER ANTE UN FUNCIONARIO O SERVIDOR PÚBLICO QUE HA DE CONOCER, ESTÉ CONOCIENDO O HAYA CONOCIDO UN CASO JUDICIAL O ADMINISTRATIVO, COMETE DELITO DE:', 'ENRIQUECIMIENTO ILÍCITO.', 'TRÁFICO DE INFLUENCIAS.', 'CONCUSIÓN.', 'PATROCINIO ILEGAL.', 'COBRO INDEBIDO.', NULL, 'b', 'TRÁFICO DE INFLUENCIAS.', '(ART: 400)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO II]  [SECCION IV]', '184270'),
(2125, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE MEDIANTE EL USO DE LA FUERZA FÍSICA, AMENAZA, OFRECIMIENTO O CONCESIÓN DE UN BENEFICIO INDEBIDO, IMPIDE U OBSTACULIZA SE PRESTE UN TESTIMONIO O LA APORTACIÓN DE PRUEBAS O INDUCE A QUE SE PRESTE UN FALSO TESTIMONIO O PRUEBAS FALSAS, COMETE DELITO DE:', 'ENCUBRIMIENTO REAL.', 'OBSTRUCCIÓN DE LA JUSTICIA.', 'FRAUDE PROCESAL.', 'DENUNCIA CALUMNIOSA.', 'FRAUDE PROCESAL PENAL.', NULL, 'b', 'OBSTRUCCIÓN DE LA JUSTICIA.', '(ART: 409-A)** [LIBRO SEGUNDO]  [TITULO XVIII]  [CAPITULO III]  [SECCION I]', '184271'),
(2126, 'Decreto Legislativo Nº 635 Código Penal', 'EL QUE INSERTA O HACE INSERTAR EN INSTRUMENTO PÚBLICO, DECLARACIONES FALSAS, CONCERNIENTES A HECHOS QUE DEBAN PROBARSE CON EL DOCUMENTO, CON EL OBJETO DE EMPLEARLO COMO SI LA DECLARACIÓN FUERA CONFORME A LA VERDAD, SI DE SU USO PUEDE RESULTAR ALGÚN PERJUICIO, COMETE DELITO:', 'FALSIFICACIÓN DE DOCUMENTOS.', 'FALSEDAD GENÉRICA.', 'PREVARICATO.', 'FALSEDAD IDEOLÓGICA.', 'ENCUBRIMIENTO REAL.', NULL, 'd', 'FALSEDAD IDEOLÓGICA.', '(ART: 428)** [LIBRO SEGUNDO]  [TITULO XIX]  [CAPITULO I]', '184272'),
(2127, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES SUPUESTOS EXIME DE LA RESPONSABILIDAD PENAL POR ANOMALÍA PSÍQUICA DE ACUERDO AL ARTÍCULO 20 DEL CÓDIGO PENAL:', 'CUANDO EL AGENTE PRESENTA CUALQUIER TIPO DE TRASTORNO MENTAL LEVE, SIN QUE AFECTE GRAVEMENTE SU', 'EL QUE POR ANOMALÍA PSÍQUICA O GRAVE ALTERACIÓN DE LA CONCIENCIA, QUE AFECTAN GRAVEMENTE SU CONCEPTO', 'CUANDO EL AGENTE ACTÚA BAJO LOS EFECTOS VOLUNTARIOS DE ESTUPEFACIENTES.', 'CUANDO EL AGENTE DESCONOCE EL DEBER JURÍDICO POR SU CULTURA O EDUCACIÓN.', 'EL QUE COMETE EL HECHO EN ESTADO DE IRA MOMENTÁNEA.', NULL, 'b', 'EL QUE POR ANOMALÍA PSÍQUICA O GRAVE ALTERACIÓN DE LA CONCIENCIA, QUE AFECTAN GRAVEMENTE SU', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184273'),
(2128, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO AL USO DE LA FUERZA LETAL EN DEFENSA DE BIENES JURÍDICOS, SEÑALE LA ALTERNATIVA CORRECTA SEGÚN EL ARTÍCULO 20 DEL CÓDIGO PENAL:', 'SOLO ESTÁ PERMITIDO CUANDO HAY RIESGO INMINENTE DE MUERTE PARA EL DEFENSOR.', 'DEBE EXISTIR AGRESIÓN ILEGÍTIMA, REAL Y ACTUAL; NECESIDAD RACIONAL DEL MEDIO EMPLEADO Y AUSENCIA DE', 'EL USO DE LA FUERZA LETAL ESTÁ PERMITIDO SIN MÁS CONDICIONES SI ES EN DEFENSA PROPIA.', 'LA PROPORCIONALIDAD ENTRE EL MEDIO DE DEFENSA Y LA AGRESIÓN ES EL ÚNICO CRITERIO RELEVANTE.', 'EL DEFENSOR DEBE ESPERAR A SER ATACADO FÍSICAMENTE ANTES DE REPELER LA AGRESIÓN.', NULL, 'b', 'DEBE EXISTIR AGRESIÓN ILEGÍTIMA, REAL Y ACTUAL; NECESIDAD RACIONAL DEL MEDIO EMPLEADO Y', '(ART: (ART: 20)**  Articulo 20.-Inimputabilidad)**', '184274'),
(2129, 'Decreto Legislativo Nº 635 Código Penal', 'EN RELACIÓN A LA EXENCIÓN DE RESPONSABILIDAD PENAL POR ESTADO DE NECESIDAD, SEGÚN EL ARTÍCULO 20, ¿CUÁL ES LA PREMISA ESENCIAL PARA LA APLICACIÓN DE ESTA CAUSA JUSTIFICANTE:', 'LA INMINENCIA DE DAÑO A CUALQUIER BIEN JURÍDICO, SIN DISTINCIÓN DE SU RELEVANCIA.', 'SOLO LA IMPOSIBILIDAD DE ESCAPAR DEL PELIGRO JUSTIFICA EL HECHO ANTIJURÍDICO.', 'EL BIEN JURÍDICO PROTEGIDO DEBE SER PREDOMINANTE SOBRE EL INTERÉS DAÑADO Y EL MEDIO EMPLEADO DEBE SER', 'LA SIMPLE PRESENCIA DEL PELIGRO ACTUAL ES SUFICIENTE PARA EXCUSAR LA CONDUCTA.', 'SE REQUIERE QUE EL AGENTE HAYA CAUSADO PREVIAMENTE EL PELIGRO PARA QUE OPERE LA EXENCIÓN.', NULL, 'c', 'EL BIEN JURÍDICO PROTEGIDO DEBE SER PREDOMINANTE SOBRE EL INTERÉS DAÑADO Y EL MEDIO EMPLEADO', '(ART: (ART: 20)**  Articulo 20.-Inimputabilidad)**', '184275'),
(2130, 'Decreto Legislativo Nº 635 Código Penal', '¿EN QUÉ SUPUESTO NO PROCEDERÁ LA EXENCIÓN DE RESPONSABILIDAD PENAL POR ESTADO DE NECESIDAD EXCULPANTE, CONFORME AL ARTÍCULO 20 DEL CÓDIGO PENAL:', 'CUANDO EL PELIGRO PROVIENE DE ACTO PROPIO DEL AGENTE.', 'CUANDO SE EMPLEA CUALQUIER MEDIO PARA ALEJAR EL PELIGRO.', 'CUANDO EL AGENTE NO GUARDA RELACIÓN JURÍDICA CON EL BIEN PROTEGIDO.', 'CUANDO EL RIESGO ES PARA BIENES PATRIMONIALES ÚNICAMENTE.', 'SI EL AGENTE ACTÚA EN LEGÍTIMA DEFENSA.', NULL, 'a', 'CUANDO EL PELIGRO PROVIENE DE ACTO PROPIO DEL AGENTE.', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184276'),
(2131, 'Decreto Legislativo Nº 635 Código Penal', 'CONFORME AL ARTÍCULO 20 DEL CÓDIGO PENAL, ¿EL CONSENTIMIENTO VÁLIDO DEL TITULAR DE UN BIEN JURÍDICO DE LIBRE DISPOSICIÓN EXIME DE RESPONSABILIDAD PENAL CUANDO:', 'EL CONSENTIMIENTO ES TÁCITO Y OTORGADO BAJO PRESIÓN.', 'EL BIEN JURÍDICO AFECTADO NO ES DE LIBRE DISPOSICIÓN.', 'EL CONSENTIMIENTO ES OTORGADO VÁLIDAMENTE, EL TITULAR ES CAPAZ Y EL BIEN JURÍDICO ES DE LIBRE DISPOSICIÓN.', 'EL AGENTE OBRA SOBRE BIENES JURÍDICOS INDISPONIBLES DE TERCEROS.', 'EL CONSENTIMIENTO SE OTORGA DESPUÉS DE LA COMISIÓN DEL HECHO.', NULL, 'c', 'EL CONSENTIMIENTO ES OTORGADO VÁLIDAMENTE, EL TITULAR ES CAPAZ Y EL BIEN JURÍDICO ES DE LIBRE', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184277'),
(2132, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL ES EL CRITERIO QUE SE REEMPLAZA PARA VALORAR LA RACIONALIDAD DEL MEDIO DE DEFENSA SEGÚN EL ARTÍCULO 20 DEL CÓDIGO PENAL:', 'EL CRITERIO DE NECESIDAD DE MEDIOS.', 'EL DE PROPORCIONALIDAD DE MEDIOS, SIENDO SUSTITUIDO POR LA VALORACIÓN DE LA INTENSIDAD Y PELIGROSIDAD DE', 'LA INMEDIATEZ DE LA AGRESIÓN.', 'LA EXISTENCIA DE LESIONES RECÍPROCAS.', 'EL PELIGRO POTENCIAL DEL DEFENSOR.', NULL, 'b', 'EL DE PROPORCIONALIDAD DE MEDIOS, SIENDO SUSTITUIDO POR LA VALORACIÓN DE LA INTENSIDAD Y', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184278'),
(2133, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN EL ARTÍCULO 20 DEL CÓDIGO PENAL, ¿QUIÉNES PUEDEN INVOCAR LA EXENCIÓN DE RESPONSABILIDAD PENAL POR DEFENDER UN INMUEBLE ILEGÍTIMAMENTE OCUPADO:', 'SOLO EL PROPIETARIO LEGAL DEL INMUEBLE.', 'EL POSEEDOR LEGÍTIMO Y SUS PARIENTES HASTA EL TERCER GRADO DE CONSANGUINIDAD O DE AFINIDAD PRESENTES', 'CUALQUIER PERSONA QUE SE ENCUENTRE EN EL INMUEBLE.', 'SOLAMENTE AGENTES DEL ORDEN.', 'PERSONAS AUTORIZADAS POR EL PROPIETARIO EN CUALQUIER CIRCUNSTANCIA.', NULL, 'b', 'EL POSEEDOR LEGÍTIMO Y SUS PARIENTES HASTA EL TERCER GRADO DE CONSANGUINIDAD O DE AFINIDAD', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184279'),
(2134, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ SUCEDE SI UNA PERSONA ACTÚA POR MIEDO INSUPERABLE DE UN MAL IGUAL O MAYOR, SEGÚN EL ARTÍCULO 20 DEL CÓDIGO PENAL:', 'SE LE EXIME DE RESPONSABILIDAD PENAL.', 'SE LE IMPONE UNA ATENUANTE ESPECIAL.', 'EL MIEDO DEBE SER OBJETIVAMENTE JUSTIFICADO Y NO SÓLO SUBJETIVO PARA EXIMIRLO.', 'SÓLO SE CONSIDERA PARA HECHOS SANCIONADOS CON PENA PRIVATIVA NO MAYOR DE CUATRO AÑOS.', 'NO SE CONSIDERA EXIMENTE BAJO NINGUNA CIRCUNSTANCIA.', NULL, 'a', 'SE LE EXIME DE RESPONSABILIDAD PENAL.', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184280'),
(2135, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL ES LA DIFERENCIA FUNDAMENTAL ENTRE ESTADO DE NECESIDAD JUSTIFICANTE Y EXCULPANTE CONFORME AL ARTÍCULO 20:', 'EL ESTADO DE NECESIDAD JUSTIFICANTE PRIORIZA EL BIEN PROTEGIDO, MIENTRAS EL EXCULPANTE LIBERA DE', 'LA PRIMERA REQUIERE PELIGRO ACTUAL, LA SEGUNDA NO.', 'EL PRIMER CASO REQUIERE ORDEN DE AUTORIDAD, EL SEGUNDO NO.', 'AMBOS CASOS EXIGEN QUE EL AGENTE HAYA PROVOCADO EL PELIGRO.', 'NO EXISTE DIFERENCIA SEGÚN LA LEY.', NULL, 'a', 'EL ESTADO DE NECESIDAD JUSTIFICANTE PRIORIZA EL BIEN PROTEGIDO, MIENTRAS EL EXCULPANTE LIBERA', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184281'),
(2136, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL USO LEGÍTIMO DE ARMAS POR LA POLICÍA NACIONAL DEL PERÚ, CONFORME AL ARTÍCULO 20, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA:', 'SE EXIME DE RESPONSABILIDAD PENAL SIEMPRE QUE EL USO DE ARMAS CAUSE LESIONES O MUERTE Y SE REALICE EN', 'EL USO DE ARMAS ESTÁ PROHIBIDO SALVO EN SITUACIONES DE GUERRA.', 'LA RESPONSABILIDAD PENAL SE PRESUME EN CASO DE MUERTE, SIN EXCEPCIÓN.', 'SOLO SE PERMITE EL USO DE ARMAS EN DEFENSA DE PROPIOS BIENES.', 'LA EXENCIÓN SOLO APLICA CUANDO NO SE UTILIZAN ARMAS LETALES.', NULL, 'a', 'SE EXIME DE RESPONSABILIDAD PENAL SIEMPRE QUE EL USO DE ARMAS CAUSE LESIONES O MUERTE Y SE', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184282'),
(2137, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ REQUISITO SE EXIGE CUANDO SE ACTÚA POR ORDEN OBLIGATORIA DE AUTORIDAD COMPETENTE SEGÚN EL ARTÍCULO 20:', 'QUE LA ORDEN SEA EXPEDIDA EN EL EJERCICIO DE LAS FUNCIONES DE LA AUTORIDAD.', 'QUE LA ORDEN SEA DEBIDAMENTE MOTIVADA Y NOTIFICADA AL AGENTE.', 'QUE LA ORDEN SEA DADA POR ESCRITO.', 'QUE EL AGENTE ACTÚE FUERA DE LA FUNCIÓN PÚBLICA.', 'QUE LA ORDEN SEA REVISADA POR JUEZ ANTES DE SU CUMPLIMIENTO.', NULL, 'a', 'QUE LA ORDEN SEA EXPEDIDA EN EL EJERCICIO DE LAS FUNCIONES DE LA AUTORIDAD.', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184283'),
(2138, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO A LA FUERZA FÍSICA IRRESISTIBLE COMO CAUSA EXIMENTE PENAL, INDIQUE EL SUPUESTO CORRECTO:', 'SÓLO EXIME CUANDO LA FUERZA PROVIENE DE LA NATURALEZA, NUNCA DE UN TERCERO.', 'EXIME DE RESPONSABILIDAD SIEMPRE QUE LA FUERZA FÍSICA SEA IRRESISTIBLE Y PROVENGA DE UN TERCERO O DE LA', 'LA FUERZA DEBE SER MORAL Y NO FÍSICA.', 'LA FUERZA FÍSICA DEBE SER CONSENTIDA POR EL AGENTE.', 'EL AGENTE PUDO RESISTIR LA FUERZA PERO DECIDIÓ NO HACERLO.', NULL, 'b', 'EXIME DE RESPONSABILIDAD SIEMPRE QUE LA FUERZA FÍSICA SEA IRRESISTIBLE Y PROVENGA DE UN', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184284'),
(2139, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ CONDICIÓN INVALIDA LA LEGÍTIMA DEFENSA, SEGÚN EL ARTÍCULO 20:', 'LA EXISTENCIA DE UNA PROVOCACIÓN SUFICIENTE POR PARTE DE QUIEN SE DEFIENDE.', 'LA INMEDIATEZ DE LA AGRESIÓN.', 'EL PELIGRO PARA UN BIEN PROPIO.', 'LA DEFENSA DE BIENES PATRIMONIALES.', 'EL USO DE UN OBJETO CONTUNDENTE.', NULL, 'a', 'LA EXISTENCIA DE UNA PROVOCACIÓN SUFICIENTE POR PARTE DE QUIEN SE DEFIENDE.', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184285'),
(2140, 'Decreto Legislativo Nº 635 Código Penal', '¿EN CUÁL DE LOS SIGUIENTES ESCENARIOS SE APLICA LA EXIMENTE DE RESPONSABILIDAD PENAL POR EL EJERCICIO LEGÍTIMO DE UN DERECHO, OFICIO O CARGO:', 'CUANDO EL AGENTE CUMPLE UN DEBER LEGAL EXIGIDO EN LA LEY.', 'CUANDO EL AGENTE ACTÚA FUERA DE SUS FUNCIONES LEGALES PARA PROTEGER SUS INTERESES.', 'CUANDO EL AGENTE ACTÚA MOTIVADO POR BENEFICIO ECONÓMICO PERSONAL.', 'CUANDO ACTÚA BAJO UNA ORDEN ILEGAL.', 'CUANDO ACTÚA POR CONSEJO DE UN AMIGO QUE ES AUTORIDAD.', NULL, 'a', 'CUANDO EL AGENTE CUMPLE UN DEBER LEGAL EXIGIDO EN LA LEY.', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184286'),
(2141, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO A LA DEFENSA DE BIENES JURÍDICOS PROPIOS MEDIANTE LA FUERZA LETAL, ¿EN CUÁL DE LOS ESCENARIOS SIGUIENTES NO SE CONFIGURA UNA EXIMENTE DE RESPONSABILIDAD PENAL:', 'CUANDO SE REPELE UNA AGRESIÓN ILEGÍTIMA, REAL Y ACTUAL, SIN PROVOCACIÓN SUFICIENTE Y USANDO', 'CUANDO EXISTE UNA IRRUPCIÓN VIOLENTA E ILEGÍTIMA EN EL INMUEBLE DEL AGENTE Y SE UTILIZA LA FUERZA', 'CUANDO NO EXISTE PELIGRO ACTUAL PERO SE CREE QUE PODRÍA HABERLO EN EL FUTURO.', 'CUANDO LA DEFENSA SE EJERCE EN EL LUGAR DE TRABAJO ANTE INGRESO SUBREPTICIO ILEGÍTIMO.', 'CUANDO LA PERSONA DEFIENDE LA INTEGRIDAD DE UN PARIENTE HASTA TERCER GRADO DE CONSANGUINIDAD EN SU', NULL, 'c', 'CUANDO NO EXISTE PELIGRO ACTUAL PERO SE CREE QUE PODRÍA HABERLO EN EL FUTURO.', '(ART: (ART: 20)**  Articulo 20.- Inimputabilidad)**', '184287'),
(2142, 'Decreto Legislativo Nº 635 Código Penal', 'DE ACUERDO CON EL ARTÍCULO 21 DEL CÓDIGO PENAL, EN LOS SUPUESTOS DE LOS CASOS REGULADOS POR EL ARTÍCULO 20, SI NO CONCURRE ALGUNO DE LOS REQUISITOS NECESARIOS PARA ELIMINAR COMPLETAMENTE LA RESPONSABILIDAD, QUÉ FACULTAD TIENE EL JUEZ RESPECTO A LA SANCIÓN QUE PODRÍA IMPONERSE:', 'EL JUEZ PUEDE EXIMIR DE TODA RESPONSABILIDAD PENAL AL IMPUTADO, SI ASÍ LO CONSIDERA CONVENIENTE A LOS', 'EL JUEZ PUEDE REDUCIR PRUDENCIALMENTE LA PENA HASTA LÍMITES INFERIORES AL MÍNIMO LEGAL.', 'EL JUEZ NECESARIAMENTE DEBE IMPONER LA PENA CON AGRAVANTES AL EXISTIR RESPONSABILIDAD RESIDUAL.', 'EL JUEZ DEBE REMITIR EL CASO A LA CORTE SUPREMA PARA QUE RESUELVA LA PROCEDENCIA DE LA DISMINUCIÓN DE LA', 'EL JUEZ PODRÁ INCREMENTAR LA PENA POR CONSIDERAR QUE LA CONCURRENCIA PARCIAL DE REQUISITOS IMPLICA', NULL, 'b', 'EL JUEZ PUEDE REDUCIR PRUDENCIALMENTE LA PENA HASTA LÍMITES INFERIORES AL MÍNIMO LEGAL.', '(ART: (ART: 21)**   Articulo 21.- Responsabilidad restringida)**', '184288'),
(2143, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN EL SEGUNDO PÁRRAFO DEL ARTÍCULO 21 DEL CÓDIGO PENAL, ¿CUÁL ES EL PROCEDIMIENTO QUE DEBE SEGUIR LA AUTORIDAD RESPECTO AL ARMA DE FUEGO UTILIZADA POR QUIEN REPELE UNA AGRESIÓN ILEGÍTIMA, SIEMPRE QUE ESTÉ LEGALMENTE INSCRITA A SU NOMBRE:', 'DEBE SER DECOMISADA DE MANERA DEFINITIVA SIN POSIBILIDAD DE DEVOLUCIÓN.', 'EL ARMA DEBE SER TRANSFERIDA INMEDIATAMENTE AL ESTADO COMO MEDIDA DE PREVENCIÓN.', 'SE INCAUTA EL ARMA DENTRO DE LAS 48 HORAS PARA FINES DE INVESTIGACIONES PRELIMINARES, BAJO', 'NO PROCEDE NINGUNA INCAUTACIÓN POR ESTAR EL ARMA DEBIDAMENTE INSCRITA.', 'EL JUEZ VALORARÁ SI REQUIERE O NO LA INCAUTACIÓN DEL ARMA SOLAMENTE EN SENTENCIA FIRME.', NULL, 'c', 'SE INCAUTA EL ARMA DENTRO DE LAS 48 HORAS PARA FINES DE INVESTIGACIONES PRELIMINARES, BAJO', '(ART: (ART: 21)**   Articulo 21.- Responsabilidad restringida)**', '184289'),
(2144, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN EL ARTÍCULO 22 DEL CÓDIGO PENAL, ¿EN QUÉ SUPUESTO NO PROCEDERÁ LA REDUCCIÓN DE LA PENA SEÑALADA PARA EL HECHO PUNIBLE COMETIDO POR UN AGENTE ENTRE DIECISÉIS Y MENOS DE VEINTIÚN AÑOS:', 'CUANDO EL AGENTE INTEGRA UNA ORGANIZACIÓN CRIMINAL AL MOMENTO DEL HECHO.', 'CUANDO EL DELITO COMETIDO ES EL DE HOMICIDIO SIMPLE.', 'CUANDO EL AGENTE HA COMETIDO EL DELITO DE APOLOGÍA DE DELITO.', 'CUANDO EL AGENTE ES REINCIDENTE EN HURTO SIMPLE.', 'CUANDO EL DELITO COMETIDO ES TRÁFICO ILÍCITO DE DROGAS.', NULL, 'a', 'CUANDO EL AGENTE INTEGRA UNA ORGANIZACIÓN CRIMINAL AL MOMENTO DEL HECHO.', '(ART: (ART: 22)**    Artículo 22.- Responsabilidad restringida por la edad)**', '184290'),
(2145, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO A LA SITUACIÓN PROCESAL DE UNA PERSONA MAYOR DE OCHENTA AÑOS CONDENADA POR UN DELITO, ¿CUÁL ES LA MEDIDA HUMANITARIA PREVISTA EN EL ARTÍCULO 22 DEL CÓDIGO PENAL:', 'SE LE EXIME AUTOMÁTICAMENTE DE LA RESPONSABILIDAD PENAL.', 'PUEDE AFRONTAR SU CONDENA CONFORME A LO REGULADO EN LOS ARTÍCULOS 288 O 290 DEL NUEVO CÓDIGO', 'SE LE CONCEDE LIBERTAD PLENA POR RAZÓN DE EDAD AVANZADA.', 'ES TRASLADADA A UNA INSTITUCIÓN GERIÁTRICA EN LUGAR DE PRISIÓN.', 'DEBE PURGAR CONDENA SOLO LA MITAD DEL TIEMPO ESTIPULADO POR LEY.', NULL, 'b', 'PUEDE AFRONTAR SU CONDENA CONFORME A LO REGULADO EN LOS ARTÍCULOS 288 O 290 DEL NUEVO', '(ART: (ART: 22)**    Artículo 22.- Responsabilidad restringida por la edad)**', '184291'),
(2146, 'Decreto Legislativo Nº 635 Código Penal', '¿EN CUÁL DE LOS SIGUIENTES SUPUESTOS NO ESTÁ EXCLUIDA LA POSIBILIDAD DE REDUCCIÓN PRUDENCIAL DE LA PENA POR EDAD, DE ACUERDO CON EL ARTÍCULO 22 DEL CÓDIGO PENAL:', 'INTEGRANTE DE UNA ORGANIZACIÓN CRIMINAL.', 'COMISIÓN DE SECUESTRO.', 'COMISIÓN DE HOMICIDIO PRETERINTENCIONAL.', 'COMISIÓN DE FEMINICIDIO.', 'COMISIÓN DE SICARIATO.', NULL, 'c', 'COMISIÓN DE HOMICIDIO PRETERINTENCIONAL.', '(ART: (ART: 22)**    Artículo 22.- Responsabilidad restringida por la edad)**', '184292'),
(2147, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ CRITERIO ESTABLECE EL ARTÍCULO 22 DEL CÓDIGO PENAL PARA QUE SE EXCLUYA LA RESPONSABILIDAD RESTRINGIDA POR LA EDAD EN CASO DE REITERACIÓN DELICTIVA:', 'CUANDO EL AGENTE HA INCURRIDO REPETIDAMENTE EN DELITOS DE VIOLENCIA FAMILIAR.', 'CUANDO EL AGENTE HA COMETIDO EN FORMA REITERADA DELITOS DE HOMICIDIO CALIFICADO Y LESIONES GRAVES CON', 'CUANDO EL AGENTE HA INCURRIDO EN FORMA REITERADA EN LOS DELITOS PREVISTOS EN LOS ARTÍCULOS 111, TERCER', 'CUANDO EL AGENTE ES REINCIDENTE EN DELITOS DE CORRUPCIÓN DE FUNCIONARIOS.', 'CUANDO EL AGENTE HA COMETIDO DELITOS DE APOLOGÍA O TORTURA EN REITERADAS OCASIONES.', NULL, 'c', 'CUANDO EL AGENTE HA INCURRIDO EN FORMA REITERADA EN LOS DELITOS PREVISTOS EN LOS ARTÍCULOS', '(ART: (ART: 22)**    Artículo 22.- Responsabilidad restringida por la edad)**', '184293'),
(2148, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES ELEMENTOS ES INDISPENSABLE PARA QUE SE CONFIGURE EL DELITO DE ORGANIZACIÓN CRIMINAL DE ACUERDO AL ARTÍCULO 317 DEL CÓDIGO PENAL PERUANO:', 'QUE EL GRUPO DELICTIVO ESTÉ COMPUESTO ÚNICAMENTE POR MIEMBROS DE UNA MISMA FAMILIA.', 'QUE EL GRUPO TENGA UNA COMPLEJA ESTRUCTURA DESARROLLADA Y MAYOR CAPACIDAD OPERATIVA, COMPUESTO', 'QUE EL NÚMERO DE INTEGRANTES VARÍE ESPORÁDICAMENTE ANTES DE LA COMISIÓN DE UN DELITO.', 'QUE LA ESTRUCTURA DEL GRUPO SEA INFORMAL Y SIN ROLES DEFINIDOS.', 'QUE EL GRUPO DELICTIVO OPERE NECESARIAMENTE EN MÁS DE UNA CIUDAD.', NULL, 'b', 'QUE EL GRUPO TENGA UNA COMPLEJA ESTRUCTURA DESARROLLADA Y MAYOR CAPACIDAD OPERATIVA,', '(ART: (ART: 317)**     Articulo 317.- Organizacion criminal)**', '184294'),
(2149, 'Decreto Legislativo Nº 635 Código Penal', '¿EN QUÉ CIRCUNSTANCIA LA PENA POR ORGANIZACIÓN CRIMINAL SE INCREMENTA A NO MENOR DE QUINCE NI MAYOR DE VEINTE AÑOS DE PRIVACIÓN DE LIBERTAD, SEGÚN EL ARTÍCULO 317:', 'CUANDO LA ORGANIZACIÓN COMETE DELITOS MENORES A LA PENA MÍNIMA DE CINCO AÑOS.', 'CUANDO EL AGENTE ES ÚNICAMENTE UN INTEGRANTE SIN FUNCIONES DIRECTIVAS.', 'CUANDO EL AGENTE ACTÚA DESDE UN ESTABLECIMIENTO PENITENCIARIO O UTILIZANDO TECNOLOGÍAS DE LA', 'CUANDO EL AGENTE COMETE LOS DELITOS EN AUSENCIA DE COORDINACIÓN GRUPAL.', 'CUANDO LA ESTRUCTURA CARECE DE ROLES DEFINIDOS PERO HAY BENEFICIO ECONÓMICO.', NULL, 'c', 'CUANDO EL AGENTE ACTÚA DESDE UN ESTABLECIMIENTO PENITENCIARIO O UTILIZANDO TECNOLOGÍAS DE LA', '(ART: (ART: 317)**     Articulo 317.- Organizacion criminal)**', '184295'),
(2150, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN LA DEFINICIÓN DE ORGANIZACIÓN CRIMINAL DEL ARTÍCULO 317, ¿QUÉ CARACTERÍSTICA NO ES INDISPENSABLE PARA CONFIGURAR DICHO DELITO:', 'LA ACCIÓN CONCERTADA Y COORDINADA ENTRE SUS MIEMBROS.', 'EL REPARTO DE ROLES CORRELACIONADOS ENTRE SÍ.', 'LA OBTENCIÓN DE UN BENEFICIO ECONÓMICO U OTRO DE ORDEN MATERIAL.', 'LA COMISIÓN DE DELITOS CUYA PENA MÍNIMA SEA IGUAL O MAYOR DE CINCO AÑOS.', 'LA EXISTENCIA DE UNA ESTRUCTURA JERÁRQUICA ESTRICTAMENTE MILITARIZADA.', NULL, 'e', 'LA EXISTENCIA DE UNA ESTRUCTURA JERÁRQUICA ESTRICTAMENTE MILITARIZADA.', '(ART: (ART: 317)**     Articulo 317.- Organizacion criminal)**', '184296'),
(2151, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES NO CONSTITUYE UNA HIPÓTESIS AGRAVANTE CONFORME A LOS SUPUESTOS PREVISTOS EN EL SEGUNDO PÁRRAFO DEL ARTÍCULO 317 DEL CÓDIGO PENAL:', 'QUE EL AGENTE TENGA LA CONDICIÓN DE LÍDER, JEFE, FINANCISTA O DIRIGENTE DE LA ORGANIZACIÓN CRIMINAL.', 'QUE PRODUCTO DEL ACCIONAR DELICTIVO, CUALQUIERA DE SUS MIEMBROS CAUSE LA MUERTE O LESIONES GRAVES A', 'QUE LOS INTEGRANTES SEAN MENORES DE EDAD.', 'QUE LOS BENEFICIOS OBTENIDOS POR LA ORGANIZACIÓN TENGAN CARÁCTER TRASNACIONAL.', 'QUE EL AGENTE SE VALGA DE MARCAS, SEÑALES, OBJETOS, CÓDIGOS, NOMBRE O SEUDÓNIMO DE LA ORGANIZACIÓN', NULL, 'c', 'QUE LOS INTEGRANTES SEAN MENORES DE EDAD.', '(ART: (ART: 317)**     Articulo 317.- Organizacion criminal)**', '184297'),
(2152, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO A LA INHABILITACIÓN ESTABLECIDA EN EL ARTÍCULO 317, ¿A QUÉ ARTÍCULO REMITE Y CUÁLES SON ALGUNOS DE SUS NUMERALES APLICABLES:', 'REMITE AL ARTÍCULO 34, NUMERALES 1, 2, 4 Y 8 DEL CÓDIGO PENAL.', 'REMITE AL ARTÍCULO 36, NUMERALES 1, 2, 4 Y 8 DEL CÓDIGO PENAL.', 'REMITE AL ARTÍCULO 42, NUMERALES 1, 2 Y 3 DEL CÓDIGO PENAL.', 'REMITE AL ARTÍCULO 31, NUMERALES 2 Y 3 DEL CÓDIGO PENAL.', 'REMITE AL ARTÍCULO 317-A, NUMERALES 1, 2 Y 4 DEL CÓDIGO PENAL.', NULL, 'b', 'REMITE AL ARTÍCULO 36, NUMERALES 1, 2, 4 Y 8 DEL CÓDIGO PENAL.', '(ART: (ART: 317)**     Articulo 317.- Organizacion criminal)**', '184298'),
(2153, 'Decreto Legislativo Nº 635 Código Penal', 'CONFORME AL ARTÍCULO 317, ¿QUÉ FINALIDAD DEBE PERSEGUIR UNA ORGANIZACIÓN CRIMINAL PARA SER CONSIDERADA COMO TAL BAJO EL TIPO PENAL:', 'DIFUNDIR IDEOLOGÍAS RELIGIOSAS O POLÍTICAS EXTREMISTAS.', 'OBTENER, DIRECTA O INDIRECTAMENTE, UN BENEFICIO ECONÓMICO U OTRO DE ORDEN MATERIAL.', 'ELIMINAR LA COMPETENCIA EN EL MERCADO LABORAL.', 'CONSEGUIR INFLUENCIA EN ORGANIZACIONES SOCIALES SIN OBTENER BENEFICIOS MATERIALES.', 'REALIZAR ACTIVIDADES ALTRUISTAS MEDIANTE EL USO DE VIOLENCIA.', NULL, 'b', 'OBTENER, DIRECTA O INDIRECTAMENTE, UN BENEFICIO ECONÓMICO U OTRO DE ORDEN MATERIAL.', '(ART: (ART: 317)**     Articulo 317.- Organizacion criminal)**', '184299'),
(2154, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO A LA TENTATIVA, CONFORME LO ESTABLECE EL ARTÍCULO 16 DEL CÓDIGO PENAL PERUANO, SEÑALE CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA:', 'EL JUEZ DEBE DISMINUIR EN TODOS LOS CASOS LA PENA EN UN TERCIO SOBRE EL MÍNIMO LEGAL DE LA PENA PREVISTA', 'LA TENTATIVA SIEMPRE ES REPRIMIDA CON LA MISMA PENA QUE EL DELITO CONSUMADO, PERO CON CRITERIO DE', 'EN LOS DELITOS DE TENTATIVA REGULADOS EN EL ARTÍCULO 108-B DEL CÓDIGO PENAL, LA PENA DISMINUIDA NO PUEDE', 'PARA TODOS LOS DELITOS TENTADOS, LA REDUCCIÓN DE LA PENA ES OBLIGATORIA Y NO PUEDE SER APLICADA A', 'EN NINGÚN CASO LA TENTATIVA PODRÁ SER REPRIMIDA, SALVO LOS DELITOS CONTRA LA VIDA, EL CUERPO Y LA SALUD.', NULL, 'c', 'EN LOS DELITOS DE TENTATIVA REGULADOS EN EL ARTÍCULO 108-B DEL CÓDIGO PENAL, LA PENA DISMINUIDA', '(ART: (ART: 16)**  Articulo 16.- Tentativa)**', '184300'),
(2155, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL ES LA CONSECUENCIA JURÍDICA ESPECÍFICA ESTABLECIDA PARA LA TENTATIVA DE LOS DELITOS INCLUIDOS EN EL TÍTULO I-A Y EN EL CAPÍTULO IX DEL TÍTULO IV DEL LIBRO SEGUNDO DEL CÓDIGO PENAL PERUANO, SEGÚN EL ARTÍCULO 16:', 'SE APLICA LA DISMINUCIÓN PRUDENCIAL DE LA PENA CONFORME A LA GRAVEDAD DEL HECHO, SIN LÍMITE SUPERIOR.', 'EL JUEZ ESTÁ FACULTADO PARA ABSOLVER DE RESPONSABILIDAD PENAL SI LA TENTATIVA RESULTA INOFENSIVA.', 'LA DISMINUCIÓN DE LA PENA NO PUEDE SER MAYOR QUE UN TERCIO DEL MÍNIMO DE LA PENA LEGALMENTE FIJADA PARA', 'EL AGENTE SÓLO ES REPRIMIDO SI SE COMPLETÓ AL MENOS LA MITAD DE LOS ACTOS EJECUTIVOS DEL DELITO.', 'LA TENTATIVA EN ESTOS DELITOS NO ES PUNIBLE BAJO NINGÚN SUPUESTO NORMATIVO.', NULL, 'c', 'LA DISMINUCIÓN DE LA PENA NO PUEDE SER MAYOR QUE UN TERCIO DEL MÍNIMO DE LA PENA LEGALMENTE', '(ART: (ART: 16)**  Articulo 16.- Tentativa)**', '184301'),
(2156, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LAS SIGUIENTES CIRCUNSTANCIAS PUEDE SER CONSIDERADA COMO ATENUANTE SEGÚN EL ARTÍCULO 46 DEL CÓDIGO PENAL PERUANO, EN TANTO NO SEA ELEMENTO CONSTITUTIVO DEL DELITO NI ESTÉ PREVISTA ESPECÍFICAMENTE PARA SANCIONARLO:', 'EJECUTAR LA CONDUCTA PUNIBLE SOBRE RECURSOS PÚBLICOS', 'EL OBRAR POR MÓVILES NOBLES O ALTRUISTAS', 'REALIZAR LA CONDUCTA PUNIBLE ABUSANDO EL AGENTE DE SU CARGO', 'EJECUTAR LA CONDUCTA SOBRE BIENES DE UTILIDAD COMÚN', 'LA PLURALIDAD DE AGENTES QUE INTERVIENEN EN LA EJECUCIÓN', NULL, 'b', 'EL OBRAR POR MÓVILES NOBLES O ALTRUISTAS', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184302'),
(2157, 'Decreto Legislativo Nº 635 Código Penal', 'SEÑALE LA ALTERNATIVA QUE CONSTITUYE UNA CIRCUNSTANCIA AGRAVANTE CONFORME AL ARTÍCULO 46 DEL CÓDIGO PENAL PERUANO RELACIONADO CON EL USO DE LA INTELIGENCIA ARTIFICIAL:', 'CUANDO LA CONDUCTA PUNIBLE SE REALIZA EN ESTADO DE EMOCIÓN EXCUSABLE', 'CUANDO LA CONDUCTA PUNIBLE ES COMETIDA CONTRA BIENES DESTINADOS A ACTIVIDADES DE UTILIDAD COMÚN', 'CUANDO PARA LA REALIZACIÓN DE LA CONDUCTA PUNIBLE SE UTILICE LA INTELIGENCIA ARTIFICIAL O TECNOLOGÍAS', 'CUANDO EL AGENTE CARECE DE ANTECEDENTES PENALES', 'CUANDO LA REPARACIÓN DEL DAÑO SE HACE VOLUNTARIAMENTE POSTERIOR AL DELITO', NULL, 'c', 'CUANDO PARA LA REALIZACIÓN DE LA CONDUCTA PUNIBLE SE UTILICE LA INTELIGENCIA ARTIFICIAL O', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184303'),
(2158, 'Decreto Legislativo Nº 635 Código Penal', '¿EN QUÉ CASO, SEGÚN EL ARTÍCULO 46, SE CONSIDERA AGRAVANTE LA PLURALIDAD EN LA EJECUCIÓN DEL DELITO:', 'SI VARIOS AGENTES INTERVIENEN EN LA DISPUTA POR MÓVILES NOBLES', 'CUANDO INTERVIENEN TANTO AUTOR DIRECTO COMO CÓMPLICE NECESARIO', 'LA PLURALIDAD DE AGENTES QUE INTERVIENEN EN LA EJECUCIÓN DEL DELITO', 'CUANDO DOS AGENTES TIENEN CARENCIA DE ANTECEDENTES PENALES', 'CUANDO EXISTE PLURALIDAD DE VÍCTIMAS PERO UN SOLO AGENTE', NULL, 'c', 'LA PLURALIDAD DE AGENTES QUE INTERVIENEN EN LA EJECUCIÓN DEL DELITO', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184304'),
(2159, 'Decreto Legislativo Nº 635 Código Penal', 'EL CÓDIGO PENAL, EN SU ARTÍCULO 46, DETERMINA UNA ATENUANTE SI EL IMPUTADO:', 'REPARA VOLUNTARIAMENTE EL DAÑO OCASIONADO O LAS CONSECUENCIAS DERIVADAS DEL PELIGRO GENERADO', 'REALIZA LA CONDUCTA PUNIBLE EMPLEANDO MEDIOS ESPECIALMENTE PELIGROSOS', 'INTERVIENE CON PLURALIDAD DE AGENTES', 'ACTÚA ABUSANDO DE SU POSICIÓN ECONÓMICA', 'EJECUTA EL DELITO COMO PARTE DE UN GRUPO CRIMINAL', NULL, 'a', 'REPARA VOLUNTARIAMENTE EL DAÑO OCASIONADO O LAS CONSECUENCIAS DERIVADAS DEL PELIGRO', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184305'),
(2160, 'Decreto Legislativo Nº 635 Código Penal', 'SELECCIONE UNA CIRCUNSTANCIA AGRAVANTE RELACIONADA CON LA CONDICIÓN DE LA VÍCTIMA SEGÚN EL ARTÍCULO 46:', 'QUE LA VÍCTIMA SEA MENOR DE EDAD O ADULTO MAYOR EN SITUACIÓN DE ESPECIAL VULNERABILIDAD', 'QUE LA VÍCTIMA SE PRESENTE VOLUNTARIAMENTE ANTE LA AUTORIDAD', 'QUE LA VÍCTIMA PROCURE DISMINUIR LAS CONSECUENCIAS DEL DELITO', 'QUE LA VÍCTIMA TENGA ANTECEDENTES PENALES', 'QUE LA VÍCTIMA SEA FAMILIAR DEL IMPUTADO', NULL, 'a', 'QUE LA VÍCTIMA SEA MENOR DE EDAD O ADULTO MAYOR EN SITUACIÓN DE ESPECIAL VULNERABILIDAD', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184306'),
(2161, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LAS SIGUIENTES NO ES UNA ATENUANTE SEGÚN EL ARTÍCULO 46 DEL CÓDIGO PENAL PERUANO:', 'LA EDAD DEL IMPUTADO EN TANTO HAYA INFLUIDO EN LA CONDUCTA PUNIBLE', 'PRESENTARSE VOLUNTARIAMENTE A LAS AUTORIDADES PARA ADMITIR SU RESPONSABILIDAD', 'EL OBRAR POR MÓVILES ALTRUISTAS', 'REALIZAR LA CONDUCTA PUNIBLE ABUSANDO EL AGENTE DE SU PROFESIÓN', 'REPARAR VOLUNTARIAMENTE EL DAÑO OCASIONADO', NULL, 'd', 'REALIZAR LA CONDUCTA PUNIBLE ABUSANDO EL AGENTE DE SU PROFESIÓN', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184307'),
(2162, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL SERÍA UNA AGRAVANTE SEGÚN EL ARTÍCULO 46 SI EL HECHO PUNIBLE SE COMETE DENTRO DE UN PENAL POR UN INTERNO:', 'SI SE REALIZA PARA PROTEGER A OTRO INTERNO', 'SI SE COMETE POR QUIEN ESTÁ PRIVADO DE LIBERTAD DESDE EL INTERIOR DE UN LUGAR DE RECLUSIÓN', 'SI EL INTERNO PROCURA REPARAR EL DAÑO CAUSADO', 'SI EL INTERNO ACTÚA EN ESTADO DE TEMOR EXCUSABLE', 'SI EL INTERNO CARECE DE ANTECEDENTES PENALES', NULL, 'b', 'SI SE COMETE POR QUIEN ESTÁ PRIVADO DE LIBERTAD DESDE EL INTERIOR DE UN LUGAR DE RECLUSIÓN', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184308'),
(2163, 'Decreto Legislativo Nº 635 Código Penal', 'DE LAS SIGUIENTES OPCIONES, SELECCIONE LA QUE CORRESPONDE A UNA AGRAVANTE CUANDO HAY MOTIVACIONES DISCRIMINATORIAS:', 'EL OBRAR EN ESTADO DE EMOCIÓN EXCUSABLE', 'EJECUTAR EL DELITO BAJO MÓVILES DE INTOLERANCIA O DISCRIMINACIÓN POR RAZONES DE RAZA, IDENTIDAD ÉTNICA Y', 'LA REPARACIÓN VOLUNTARIA DEL DAÑO', 'LA CARENCIA DE ANTECEDENTES PENALES', 'EL OBRAR POR MÓVILES NOBLES', NULL, 'b', 'EJECUTAR EL DELITO BAJO MÓVILES DE INTOLERANCIA O DISCRIMINACIÓN POR RAZONES DE RAZA,', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184309'),
(2164, 'Decreto Legislativo Nº 635 Código Penal', 'CUANDO EL AGENTE INCREMENTA DELIBERADAMENTE LAS CONSECUENCIAS DAÑOSAS MÁS ALLÁ DE LO NECESARIO PARA CONSUMAR EL DELITO, SEGÚN EL ARTÍCULO 46 ESTO CONSTITUYE:', 'UNA CAUSA GENERAL DE EXCLUSIÓN DE RESPONSABILIDAD', 'UNA ATENUANTE ESPECIAL', 'UNA REPARACIÓN POSTERIOR', 'UNA AGRAVANTE GENÉRICA', 'UNA EXIMENTE', NULL, 'd', 'UNA AGRAVANTE GENÉRICA', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184310'),
(2165, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LAS SIGUIENTES ES UNA ATENUANTE SI LAS CIRCUNSTANCIAS PERSONALES O FAMILIARES INFLUYEN EN LA EJECUCIÓN DEL DELITO, DE ACUERDO AL ARTÍCULO 46:', 'LA INFLUENCIA DE APREMIANTES CIRCUNSTANCIAS PERSONALES O FAMILIARES EN LA EJECUCIÓN DE LA CONDUCTA', 'EJECUCIÓN DEL HECHO POR VARIOS AGENTES', 'COMETER EL DELITO DURANTE EL EJERCICIO DE UNA FUNCIÓN PÚBLICA', 'EJECUCIÓN SOBRE BIENES PÚBLICOS', 'EJECUCIÓN EMPLEANDO ARMAS O EXPLOSIVOS', NULL, 'a', 'LA INFLUENCIA DE APREMIANTES CIRCUNSTANCIAS PERSONALES O FAMILIARES EN LA EJECUCIÓN DE LA', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184311'),
(2166, 'Decreto Legislativo Nº 635 Código Penal', 'SELECCIONE LA ALTERNATIVA QUE CONSTITUYE UNA AGRAVANTE VINCULADA A LOS MEDIOS EMPLEADOS EN LA EJECUCIÓN DEL DELITO, SEGÚN EL ARTÍCULO 46 DEL CÓDIGO PENAL PERUANO:', 'OBRAR POR MÓVILES ALTRUISTAS', 'EMPLEAR MEDIOS DE CUYO USO PUEDA RESULTAR PELIGRO COMÚN, COMO EXPLOSIVOS O VENENOS', 'DISMINUIR VOLUNTARIAMENTE LAS CONSECUENCIAS DEL DELITO', 'PRESENTARSE VOLUNTARIAMENTE ANTE LA AUTORIDAD', 'CARECER DE ANTECEDENTES PENALES', NULL, 'b', 'EMPLEAR MEDIOS DE CUYO USO PUEDA RESULTAR PELIGRO COMÚN, COMO EXPLOSIVOS O VENENOS', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184312'),
(2167, 'Decreto Legislativo Nº 635 Código Penal', 'IDENTIFIQUE CUÁL ES UNA AGRAVANTE GENERAL AL COMETER UN DELITO ABUSANDO EL AUTOR DE SU CARGO, PROFESIÓN O FUNCIÓN, DE ACUERDO AL ARTÍCULO 46:', 'EL AUTOR ACTÚA EN ESTADO DE TEMOR EXCUSABLE VINCULADO A SU FUNCIÓN', 'EL AUTOR REPARA EL DAÑO ANTES DE SER PROCESADO', 'EL AGENTE REALIZA LA CONDUCTA PUNIBLE ABUSANDO DE SU CARGO, FORMACIÓN, OFICIO O FUNCIÓN', 'EL AGENTE OBRA SIN MÓVILES DETERMINADOS', 'EL AGENTE OBRA EN BENEFICIO DE UN FAMILIAR VULNERABLE', NULL, 'c', 'EL AGENTE REALIZA LA CONDUCTA PUNIBLE ABUSANDO DE SU CARGO, FORMACIÓN, OFICIO O FUNCIÓN', '(ART: (ART: 46)**  Articulo 46.- Circunstancias de atenuacion y agravacion)**', '184313'),
(2168, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LAS SIGUIENTES CIRCUNSTANCIAS IMPLICA LA IMPOSICIÓN DE CADENA PERPETUA SEGÚN EL ARTÍCULO 129-Q DEL CÓDIGO PENAL PERUANO:', 'CUANDO EL AGENTE ACTÚA EN CONCURSO CON OTRAS PERSONAS MAYORES DE EDAD.', 'CUANDO SE EMPLEA VIOLENCIA SIN MEDIACIÓN DE VÍNCULO FAMILIAR.', 'CUANDO EL AGENTE SE VALE DE SU POSICIÓN, CARGO O VÍNCULO FAMILIAR QUE LE OTORGA PARTICULAR AUTORIDAD', 'CUANDO EL MENOR COMETE UN DELITO DE HURTO SIMPLE POR INFLUENCIA DEL AGENTE.', 'CUANDO EL AGENTE ES REINCIDENTE EN DELITOS COMUNES DISTINTOS A LOS SEÑALADOS EN EL ARTÍCULO.', NULL, 'c', 'CUANDO EL AGENTE SE VALE DE SU POSICIÓN, CARGO O VÍNCULO FAMILIAR QUE LE OTORGA PARTICULAR', '(ART: (ART: 129-Q)**  Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184314'),
(2169, 'Decreto Legislativo Nº 635 Código Penal', '¿EN CUÁL DE LOS SIGUIENTES SUPUESTOS SE APLICA LA PENA PRIVATIVA DE LIBERTAD NO MENOR DE DOCE NI MAYOR DE VEINTICINCO AÑOS SEGÚN EL ARTÍCULO 129-Q:', 'SIEMPRE QUE SE UTILICE CUALQUIER TIPO DE COACCIÓN PARA INFLUIR EN EL MENOR.', 'CUANDO EL DELITO COMETIDO O INTENTADO POR EL MENOR ES HURTO SIMPLE.', 'CUANDO EL DELITO COMETIDO O INTENTADO TIENE COMO OBJETIVO ACTOS DE SICARIATO, ROBO AGRAVADO, TRÁFICO', 'CUANDO EL MENOR ES CAPTADO POR UN FAMILIAR SIN EMPLEO DE VIOLENCIA.', 'CUANDO EL MENOR TIENE MENOS DE 14 AÑOS DE EDAD.', NULL, 'c', 'CUANDO EL DELITO COMETIDO O INTENTADO TIENE COMO OBJETIVO ACTOS DE SICARIATO, ROBO AGRAVADO,', '(ART: (ART: 129-Q)**  Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184315'),
(2170, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN EL ARTÍCULO 129-Q, ¿CUÁL DE LOS SIGUIENTES ELEMENTOS NO ES NECESARIO PARA LA CONFIGURACIÓN DEL TIPO PENAL DE CAPTACIÓN DE MENORES PARA LA COMISIÓN DE DELITOS:', 'LA EXISTENCIA DE VIOLENCIA, AMENAZA U OTRAS FORMAS DE COACCIÓN, ABUSO DE PODER O SITUACIÓN DE', 'LA PARTICIPACIÓN ACTIVA DEL MENOR EN LA EJECUCIÓN DEL DELITO REQUERIDO.', 'EL USO DE LA PERSUASIÓN PARA INDUCIR O INSTIGAR AL MENOR.', 'QUE LA VÍCTIMA SEA MENOR DE EDAD.', 'QUE EL ACTO TENGA POR FINALIDAD LA COMISIÓN DE UN DELITO.', NULL, 'b', 'LA PARTICIPACIÓN ACTIVA DEL MENOR EN LA EJECUCIÓN DEL DELITO REQUERIDO.', '(ART: (ART: 129-Q)**  Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184316'),
(2171, 'Decreto Legislativo Nº 635 Código Penal', 'EL ARTÍCULO 129-Q DEL CÓDIGO PENAL SEÑALA QUE LA PENA AUMENTARÁ SI EL DELITO COMETIDO O INTENTADO POR EL MENOR ES:', 'LESIONES PERSONALES GRAVES.', 'ROBO AGRAVADO, SICARIATO, TRÁFICO ILÍCITO DE DROGAS O INTEGRAR A UNA ORGANIZACIÓN CRIMINAL.', 'ESTAFA AGRAVADA U HOMICIDIO CULPOSO.', 'COACCIÓN AGRAVADA O SECUESTRO SIMPLE.', 'DESOBEDIENCIA A LA AUTORIDAD O USURPACIÓN.', NULL, 'b', 'ROBO AGRAVADO, SICARIATO, TRÁFICO ILÍCITO DE DROGAS O INTEGRAR A UNA ORGANIZACIÓN CRIMINAL.', '(ART: (ART: 129-Q)**  Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184317'),
(2172, 'Decreto Legislativo Nº 635 Código Penal', 'RESPECTO AL ARTÍCULO 129-Q, ¿CUÁL DE LAS SIGUIENTES ALTERNATIVAS DESCRIBE CORRECTAMENTE UN SUPUESTO DE CAPTACIÓN EN SITUACIÓN DE VULNERABILIDAD:', 'CAPTAR A UN MENOR QUE PERTENECE A UNA FAMILIA ECONÓMICAMENTE ACOMODADA Y CON PLENO ACCESO A REDES', 'INDUCIR A UN MENOR DE EDAD SIN QUE MEDIEN AMENAZAS NI ABUSO DE PODER.', 'PERSUADIR A UN MENOR CUYA SITUACIÓN FAMILIAR LO COLOCA EN DESVENTAJA SOCIAL NOTABLE PARA QUE PARTICIPE', 'FAVORECER A MENORES MAYORES DE 17 AÑOS SIN DISTINCIÓN DE SITUACIÓN.', 'UTILIZAR A UN MENOR DE EDAD ÚNICAMENTE COMO TESTIGO DE UN DELITO SIN SU PARTICIPACIÓN ACTIVA.', NULL, 'c', 'PERSUADIR A UN MENOR CUYA SITUACIÓN FAMILIAR LO COLOCA EN DESVENTAJA SOCIAL NOTABLE PARA QUE', '(ART: (ART: 129-Q)**  Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184318'),
(2173, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ ELEMENTO SUBJETIVO SE REQUIERE PARA IMPUTAR LA RESPONSABILIDAD PENAL EN BASE AL ARTÍCULO 129-Q:', 'DOLO DIRECTO EN LA CAPTACIÓN Y PERSUASIÓN DEL MENOR PARA DELITOS.', 'CULPA CONSCIENTE EN LA INDUCCIÓN AL DELITO.', 'ERROR INVENCIBLE SOBRE LA EDAD DEL MENOR.', 'DOLO EVENTUAL EN CUALQUIER FORMA DE PARTICIPACIÓN DEL MENOR.', 'RESPONSABILIDAD OBJETIVA POR EL SOLO HECHO DE LA EXISTENCIA DEL MENOR EN EL AMBIENTE DEL AGENTE.', NULL, 'a', 'DOLO DIRECTO EN LA CAPTACIÓN Y PERSUASIÓN DEL MENOR PARA DELITOS.', '(ART: (ART: 129-Q)**  Artículo 129-Q.- Captacion de menores de edad para la comision de delitos)**', '184319'),
(2174, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LAS SIGUIENTES CONDUCTAS AGRAVARÍA LA PENA POR EL DELITO DE EXHIBICIONES Y PUBLICACIONES OBSCENAS SEGÚN EL ARTÍCULO 183 DEL CÓDIGO PENAL PERUANO:', 'REALIZAR ACTOS OBSCENOS EN PRESENCIA DE ADULTOS MAYORES DE 65 AÑOS.', 'MOSTRAR IMÁGENES OBSCENAS A UN MENOR DE DIECIOCHO AÑOS.', 'INCITAR A UNA PERSONA ADULTA A LA PRÁCTICA DE UN ACTO DE ÍNDOLE SEXUAL EN UN LOCAL CERRADO.', 'VENDER OBJETOS DE CONTENIDO ERÓTICO A MAYORES DE EDAD.', 'FACILITAR LA ENTRADA A MENORES DE EDAD A CUALQUIER TIPO DE ESPECTÁCULO CULTURAL.', NULL, 'b', 'MOSTRAR IMÁGENES OBSCENAS A UN MENOR DE DIECIOCHO AÑOS.', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184320'),
(2175, 'Decreto Legislativo Nº 635 Código Penal', 'PARA QUE SE CONFIGURE LA AGRAVANTE DE QUIEN INCITA A UN MENOR DE 18 AÑOS A LA PRÁCTICA DE UN ACTO SEXUAL, ¿CUÁL ES EL ELEMENTO ESENCIAL QUE DEBE CUMPLIRSE:', 'QUE EL ACTO SE REALICE EXCLUSIVAMENTE EN AMBIENTES ESCOLARES.', 'QUE LA INCITACIÓN PROVENGA DE UN FAMILIAR DIRECTO.', 'QUE LA INCITACIÓN SEA DESTINADA A FACILITAR LA ENTRADA A LUGARES CON PROPÓSITOS SEXUALES.', 'QUE LA INCITACIÓN SE REALICE POR MEDIOS ELECTRÓNICOS ÚNICAMENTE.', 'QUE LA INCITACIÓN IMPLIQUE AMENAZAS O VIOLENCIA FÍSICA.', NULL, 'c', 'QUE LA INCITACIÓN SEA DESTINADA A FACILITAR LA ENTRADA A LUGARES CON PROPÓSITOS SEXUALES.', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184321'),
(2176, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ SUCEDE SI UNA PERSONA, SIN SER DOCENTE NI FUNCIONARIO PÚBLICO, COMETE UNA CONDUCTA OBSCENA EN UN ESPECTÁCULO PERMITIDO Y UN MENOR DE EDAD INGRESA POR ERROR:', 'SE SANCIONA SOLO COMO FALTA ADMINISTRATIVA.', 'NO SE CONFIGURA DELITO PORQUE NO HUBO INTENCIÓN.', 'SE CONFIGURA AGRAVANTE SI LA CONDUCTA OCURRIÓ EN PRESENCIA DEL MENOR DE EDAD.', 'SOLO EL ADMINISTRADOR DEL LUGAR ES RESPONSABLE PENALMENTE.', 'LA RESPONSABILIDAD PENAL RECAE EXCLUSIVAMENTE EN LOS PADRES DEL MENOR.', NULL, 'c', 'SE CONFIGURA AGRAVANTE SI LA CONDUCTA OCURRIÓ EN PRESENCIA DEL MENOR DE EDAD.', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184322'),
(2177, 'Decreto Legislativo Nº 635 Código Penal', 'SEGÚN EL ARTÍCULO 183, ¿CUÁL DE LAS SIGUIENTES ALTERNATIVAS AMPLÍA LA CONDICIÓN DEL SUJETO ACTIVO EN EL AGRAVANTE DEL TIPO PENAL:', 'CUALQUIER PERSONA QUE ESTÉ PRESENTE EN EL LUGAR DE LOS HECHOS.', 'SOLO EL ADMINISTRADOR DEL LOCAL PÚBLICO.', 'QUIEN TENGA POSICIÓN DE GARANTE Y DEBER DE CUSTODIA SOBRE UN MENOR O PERSONA VULNERABLE.', 'ÚNICAMENTE UN VIGILANTE QUE NO TENGA RELACIÓN CON MENORES.', 'UNA PERSONA NO IDENTIFICADA POR LAS VÍCTIMAS.', NULL, 'c', 'QUIEN TENGA POSICIÓN DE GARANTE Y DEBER DE CUSTODIA SOBRE UN MENOR O PERSONA VULNERABLE.', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184323'),
(2178, 'Decreto Legislativo Nº 635 Código Penal', 'EN EL CASO DE UN DOCENTE QUE PERMITE A UN MENOR DE EDAD EL INGRESO A UN CINE DONDE SE EXHIBEN ACTOS DE ÍNDOLE SEXUAL, QUÉ AGRAVANTE APLICARÍAS:', 'NINGUNA, PORQUE EL MENOR INGRESÓ POR SU CUENTA.', 'AGRAVANTE POR SER DOCENTE O PERSONAL ADMINISTRATIVO DE UNA INSTITUCIÓN EDUCATIVA.', 'AGRAVANTE POR INCITAR A ADULTOS A COMETER EL ACTO.', 'AGRAVANTE SOLO SI EL DOCENTE ES TAMBIÉN ADMINISTRADOR DEL CINE.', 'NINGUNA PORQUE EL CINE TENÍA SEÑALIZACIÓN ADECUADA.', NULL, 'b', 'AGRAVANTE POR SER DOCENTE O PERSONAL ADMINISTRATIVO DE UNA INSTITUCIÓN EDUCATIVA.', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184324'),
(2179, 'Decreto Legislativo Nº 635 Código Penal', '¿CUÁL DE LOS SIGUIENTES SUPUESTOS NO CONSTITUYE UNA AGRAVANTE SEGÚN EL ARTÍCULO 183 DEL CÓDIGO PENAL PERUANO:', 'LA CONDUCTA DE ÍNDOLE OBSCENA ES REALIZADA POR UN SERVIDOR PÚBLICO.', 'LA CONDUCTA SE REALIZA EN PRESENCIA DE UN MENOR DE EDAD.', 'LA CONDUCTA ES COMETIDA POR UN VIGILANTE DE UN CINE QUE PERMITE EL INGRESO DE MENORES A FUNCIONES', 'LA CONDUCTA OBSCENA ES REALIZADA FRENTE A PERSONAS ADULTAS QUE CONSIENTEN EL ACTO.', 'EL RESPONSABLE TIENE DEBER DE CUSTODIA SOBRE PERSONAS EN SITUACIÓN DE ESPECIAL VULNERABILIDAD.', NULL, 'd', 'LA CONDUCTA OBSCENA ES REALIZADA FRENTE A PERSONAS ADULTAS QUE CONSIENTEN EL ACTO.', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184325'),
(2180, 'Decreto Legislativo Nº 635 Código Penal', '¿QUÉ DIFERENCIA SUSTANTIVA PRESENTA EL SEGUNDO SUPUESTO AGRAVADO RESPECTO DEL PRIMERO EN EL ARTÍCULO 183 DEL CÓDIGO PENAL PERUANO:', 'LA NATURALEZA DE LA CONDUCTA RECAE EN LA ENTREGA DE OBJETOS, MIENTRAS EL OTRO EN LA INCITACIÓN A LA', 'AMBOS SUPONEN SOLO LA EXHIBICIÓN PÚBLICA ANTE MENORES, CON DISTINTOS TIPOS DE IMÁGENES.', 'EN EL PRIMERO, LA VÍCTIMA NECESARIAMENTE DEBE SER UNA PERSONA CON DISCAPACIDAD INTELECTUAL.', 'AMBOS EXIGEN POSICIÓN DE GARANTE DEL SUJETO ACTIVO.', 'EL PRIMERO ES APLICABLE ÚNICAMENTE A ESCRITOS, EL SEGUNDO ÚNICAMENTE A AUDIOS.', NULL, 'a', 'LA NATURALEZA DE LA CONDUCTA RECAE EN LA ENTREGA DE OBJETOS, MIENTRAS EL OTRO EN LA', '(ART: (ART: 183)**  Articulo 183.- Exhibiciones y publicaciones obscenas)**', '184326'),
(2181, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', '¿QUÉ, MARCO LEGAL REGULA EL USO DE LA FUERZA POR PARTE DEL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN CUMPLIMIENTO DE SU FINALIDAD CONSTITUCIONAL:', 'DECRETO SUPREMO 1185.', 'DECRETO LEGISLATIVO 8611.', 'DECRETO SUPREMO 8611.', 'DECRETO SUPREMO 1186.', 'DECRETO LEGISLATIVO 1186.', NULL, 'e', 'DECRETO LEGISLATIVO 1186.', '(texto: 1) (item: 184)** [TITULO I]  [CAPITULO I]', '184701'),
(2182, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', '¿CUÁL ES EL OBJETO DEL DECRETO LEGISLATIVO 1186:', 'REGULA LOS PROCESOS INMEDIATOS EN CASOS DE FLAGRANCIA.', 'REGULA LA LUCHA CONTRA LA DELINCUENCIA COMÚN.', 'EVITAR QUE PERSONAL POLICIAL SEA DENUNCIADO.', 'REGULA LAS ACTUACIONES POLICIALES.', 'REGULAR EL USO DE LA FUERZA POR PARTE DEL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'e', 'REGULAR EL USO DE LA FUERZA POR PARTE DEL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ.', '(texto: 1) (item: 59)** [TITULO I]  [CAPITULO I]', '184702'),
(2183, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', '¿CUÁL ES EL ALCANCE DEL DECRETO LEGISLATIVO 1186:', 'A TODO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE ACTIVIDAD. DISPONIBILIDAD O RETIRO QUE', 'A TODO EL PERSONAL DE LOS SERENAZGOS EN SITUACIÓN DE ACTIVIDAD QUE USA LA FUERZA EN DEFENSA DE LA', 'A TODO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE DISPONIBILIDAD QUE USA LA FUERZA EN', 'A TODO EL PERSONAL DE LAS FUERZAS ARMADAS EN SITUACIÓN DE ACTIVIDAD QUE USA LA FUERZA EN DEFENSA DE LA', 'A TODO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE ACTIVIDAD QUE USA LA FUERZA EN DEFENSA', NULL, 'e', 'A TODO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE ACTIVIDAD QUE USA LA FUERZA', '(texto: 2) (item: 184)** [TITULO I]  [CAPITULO I]', '184703'),
(2184, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'ALCANZAN A TODO EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN SITUACIÓN DE ACTIVIDAD QUE USA LA FUERZA EN DEFENSA DE LA PERSONA, LA SOCIEDAD Y EL ESTADO; ESTE DECRETO LEGISLATIVO REGULA:', 'EL USO DE LA FUERZA POR FUNCIONARIOS PÚBLICOS.', 'EL USO DE LA FUERZA POR PARTE DE INSPECTORÍA DE LA POLICÍA NACIONAL DEL PERÚ.', 'EL USO DE LA FUERZA POR PARTE DE LAS FUERZAS ARMADAS.', 'EL USO DE LA FUERZA POR PARTE DE LA POLICÍA MUNICIPAL DEL PERÚ.', 'EL USO DE LA FUERZA POR PARTE DE LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'e', 'EL USO DE LA FUERZA POR PARTE DE LA POLICÍA NACIONAL DEL PERÚ.', '(texto: 2) (item: 184)** [TITULO I]  [CAPITULO I]', '184704'),
(2185, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'ES EL MEDIO QUE EN SUS DIFERENTE NIVELES USA EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, DENTRO DEL MARCO DE LA LEY, PARA LOGRAR EL CONTROL DE UNA SITUACIÓN QUE CONSTITUYE UNA AMENAZA O ATENTA CONTRA LA SEGURIDAD, EL ORDEN PÚBLICO, LA INTEGRIDAD O LA VIDA DE LAS PERSONAS:', 'MEDIOS NECESARIOS.', 'FUERZA.', 'EQUIPOS TÁCTICOS.', 'PLANES Y ESTRATEGIAS.', 'INTELIGENCIA OPERATIVA.', NULL, 'b', 'FUERZA.', '(texto: 3) (item: 184)** [TITULO I]  [CAPITULO II]', '184705'),
(2186, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'ES LA GRADUACIÓN Y ADECUACIÓN, POR PARTE DEL PERSONAL POLICIAL, DE LOS MEDIOS Y MÉTODOS A EMPLEAR TENIENDO EN CUENTA EL NIVEL DE COOPERACIÓN, RESISTENCIA O AGRESIÓN QUE REPRESENTE LA PERSONA A INTERVENIR O LA SITUACIÓN A CONTROLAR; CORRESPONDE A LA DEFINICIÓN DE:', 'USO NECESARIO Y PROGRESIVO DE LA FUERZA.', 'USO PROGRESIVO Y DIFERENCIADO DE LA FUERZA.', 'MEDIOS DE POLICÍA.', 'CUMPLIMIENTO DEL DEBER.', 'USO DE LA FUERZA FÍSICA.', NULL, 'b', 'USO PROGRESIVO Y DIFERENCIADO DE LA FUERZA.', '(texto: 3) (item: 184)** [TITULO I]  [CAPITULO II]', '184706'),
(2187, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'SON LAS ARMAS, EQUIPO, ACCESORIOS Y OTROS ELEMENTOS DE APOYO, AUTORIZADOS O PROPORCIONADOS POR EL ESTADO, QUE EMPLEA EL PERSONAL POLICIAL PARA ENFRENTAR UNA AMENAZA O ATENTADO CONTRA LA SEGURIDAD, EL ORDEN PÚBLICO, LA INTEGRIDAD O LA VIDA DE LAS PERSONAS; CORRESPONDE A LA DEFINICIÓN DE:', 'PROPORCIONALIDAD.', 'CUMPLIMIENTO DEL DEBER.', 'USO PROGRESIVO Y DIFERENCIADO DE LA FUERZA.', 'MEDIOS DE POLICÍA.', 'FUERZA.', NULL, 'd', 'MEDIOS DE POLICÍA.', '(texto: 3) (item: 184)** [TITULO I]  [CAPITULO II]', '184707'),
(2188, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'ES LA OBLIGACIÓN DEL PERSONAL POLICIAL EN EL EJERCICIO DE LA AUTORIDAD QUE REPRESENTA, DE GARANTIZAR EL ORDEN Y LA SEGURIDAD SIRVIENDO A LA COMUNIDAD Y PROTEGIENDO A LAS PERSONAS EN EL MARCO DE SUS COMPETENCIAS, FUNCIONES Y ATRIBUCIONES LEGALMENTE ESTABLECIDAS. CORRESPONDE A LA:', 'DEFINICIÓN DE CUMPLIMIENTO DEL DEBER.', 'DEFINICIÓN DE CUMPLIMIENTO DE LA MISIÓN.', 'DEFINICIÓN DE CUMPLIMIENTO DE LA VISIÓN.', 'DEFINICIÓN DE CUMPLIMIENTO DE LA OBLIGACIÓN.', 'DEFINICIÓN DE CUMPLIMIENTO DEL PODER.', NULL, 'a', 'DEFINICIÓN DE CUMPLIMIENTO DEL DEBER.', '(texto: 3) (item: 184)** [TITULO I]  [CAPITULO II]', '184708'),
(2189, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'EL USO DE LA FUERZA DEBE ORIENTARSE AL LOGRO DE UN OBJETIVO LEGAL. LOS MEDIOS Y MÉTODOS UTILIZADOS EN CUMPLIMIENTO DEL DEBER DEBEN ESTAR AMPARADOS EN EL MARCO DEL DERECHO INTERNACIONAL DE LOS DERECHOS HUMANOS, LA CONSTITUCIÓN POLÍTICA DEL PERÚ, Y DEMÁS NORMAS NACIONALES SOBRE LA MATERIA; CORRESPONDE AL PRINCIPIO DE:', 'NECESIDAD.', 'LEGALIDAD.', 'PROPORCIONALIDAD.', 'MEDIOS DE POLICÍA.', 'FUERZA.', NULL, 'b', 'LEGALIDAD.', '(texto: 4) (item: 184)** [TITULO I]  [CAPITULO II]', '184709'),
(2190, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'EL USO DE LA FUERZA EN EL CUMPLIMIENTO DEL DEBER ES NECESARIO, CUANDO OTROS MEDIOS RESULTEN INEFICACES O NO GARANTICEN DE NINGUNA MANERA EL LOGRO DEL OBJETIVO LEGAL BUSCADO. CORRESPONDE AL PRINCIPIO DE:', 'PROPORCIONALIDAD.', 'FUERZA.', 'LEGALIDAD.', 'MEDIOS DE POLICÍA.', 'NECESIDAD.', NULL, 'e', 'NECESIDAD.', '(texto: 4) (item: 184)** [TITULO I]  [CAPITULO II]', '184710'),
(2191, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ EN EL PLANEAMIENTO, CONDUCCIÓN Y EJECUCIÓN DE OPERACIONES EN EL EJERCICIO DE SUS FUNCIONES, OBSERVARÁ Y SE SUJETARÁ A:', 'FUERZA.', 'PRINCIPIOS CONTEMPLADOS EN EL PRESENTE DECRETO LEGISLATIVO.', 'NECESIDAD.', 'LEGALIDAD.', 'MEDIOS DE POLICÍA.', NULL, 'b', 'PRINCIPIOS CONTEMPLADOS EN EL PRESENTE DECRETO LEGISLATIVO.', '(texto: 4) (item: 184)** [TITULO I]  [CAPITULO II]', '184711'),
