(2193, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'EN EL PRINCIPIO DE NECESIDAD; PARA DETERMINAR EL NIVEL DE FUERZA A USAR, SE DEBE CONSIDERAR, RAZONABLEMENTE, ENTRE OTRAS CIRCUNSTANCIAS EL NIVEL DE:', 'PROPORCIONALIDAD.', 'COOPERACIÓN.', 'RESISTENCIA NO OFRECIDA.', 'PELIGRO REPRESENTADO POR LA PERSONA A INTERVENIR.', 'SITUACIÓN A CONTROLAR.', NULL, 'b', 'COOPERACIÓN.', '(texto: 4) (item: 184)** [TITULO I]  [CAPITULO II]', '184713'),
