(2266, 'Decreto Legislativo Nº 1186 Ley Que Regula El Uso De La Fuerza Por Parte De La P', 'ENTENDIDA COMO DEMOSTRACIÓN DE AUTORIDAD DEL PERSONAL DE LA POLICÍA NACIONAL UNIFORMADO, EQUIPADO, EN ACTITUD DE ALERTA Y REALIZANDO UN CONTROL VISUAL, QUE PREVIENE Y DISUADE LA COMISIÓN DE UNA INFRACCIÓN O UN DELITO. CORRESPONDE A LA DEFINICIÓN DE:', 'PRESENCIA POLICIAL.', 'PRESENCIA UNIFORMADA.', 'CONTROL DE CONTACTO.', 'VERBALIZACIÓN.', 'CONTROL TÁCTICO.', NULL, 'a', 'PRESENCIA POLICIAL.', '(texto: 7) (item: 184)** [TITULO II]  [CAPITULO I]', '184786'),
