(2274, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿QUIÉNES TIENEN LA OBLIGACIÓN DE COADYUVAR CON LAS AUTORIDADES COMPETENTES EN LA LUCHA CONTRA EL TRÁFICO ILÍCITO DE DROGAS - TID?.', 'TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PRIVADAS.', 'ALGUNAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS Y PRIVADAS.', 'TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS Y PRIVADAS.', 'TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS.', 'TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUTOS PÚBLICOS Y PRIVADOS.', NULL, 'c', 'TODAS LAS PERSONAS NATURALES, JURÍDICAS E INSTITUCIONES PÚBLICAS Y PRIVADAS.', '(texto: 2)** [CAPITULO I]', '184953'),
(2275, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿QUÉ ACCIONES A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, DESARROLLA LA POLICÍA NACIONAL DEL PERÚ?. MARQUE LA RESPUESTA CORRECTA:.', 'APOYA A LA SUPERINTENDENCIA NACIONAL DE ADUANAS EN EL FORTALECIMIENTO DEL PROGRAMA DE REHABILITACIÓN.', 'ADMINISTRA LA PLATAFORMA DE INTEROPERABILIDAD DE LUCHA CONTRA EL TRÁFICO ILÍCITO DE DROGAS - TID.', 'APOYA A LA SUPERINTENDENCIA DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA - SUNAT EN LOS CONTROLES MÍNIMOS', 'RETENER DEFINITIVAMENTE SUSTANCIAS QUÍMICAS Y MEDIOS DE TRANSPORTE, CUANDO SE TRATE DE LA COMISIÓN DE', 'APOYAR A LA SUPERINTENDENCIA NACIONAL DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA - SUNAT EN LA LABOR DE', NULL, 'a', '', '(texto: 3)** [CAPITULO II]', '184954'),
(2276, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', 'LA POLICÍA NACIONAL DEL PERÚ A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS ANTIDROGAS REALIZAN OPERACIONES POLICIALES:.', 'PREVENTIVAS, DISUASIVAS Y DE CONTROL.', 'PREVENTIVAS, PERSUASIVAS Y DE CONTROL.', 'REPRESIVAS Y DE CONTROL.', 'PREVENTIVAS, DEFENSIVAS Y DE CONTROL.', 'PREVENTIVAS, DISOLUTIVAS Y DE CONTROL.', NULL, 'a', 'PREVENTIVAS, DISUASIVAS Y DE CONTROL.', '(texto: 3)** [CAPITULO II]', '184955'),
(2277, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', 'EN EL ÁMBITO DE LA INTERDICCIÓN, LA POLICÍA NACIONAL DEL PERÚ APOYA LA PRÁCTICA DE ACTIVIDADES DE SENSIBILIZACIÓN COLECTIVA DIRIGIDA A:.', 'LAS INSTITUCIONES ARMADAS.', 'LAS INSTITUCIONES PÚBLICAS Y PRIVADAS.', 'LOS SEGMENTOS VULNERABLES DE LA SOCIEDAD.', 'LOS SEGMENTOS VULNERABLES SEGÚN LA LEY.', 'LOS SEGMENTOS VULNERABLES DEL ESTADO.', NULL, 'c', 'LOS SEGMENTOS VULNERABLES DE LA SOCIEDAD.', '(texto: 3)** [CAPITULO II]', '184956'),
(2278, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', 'A TRAVÉS DE SU DEPENDENCIA ESPECIALIZADA, ES LA AUTORIDAD ADMINISTRATIVA A CARGO DEL CONTROL Y FISCALIZACIÓN DE SUSTANCIAS QUÍMICAS EMPLEADAS LEGALMENTE EN LA INDUSTRIA FARMACÉUTICA Y QUE PUEDEN SER SUSCEPTIBLES DE UTILIZACIÓN EN LOS PROCESOS DE ELABORACIÓN ILEGAL DE ESTUPEFACIENTES Y SUSTANCIAS PSICOTRÓPICAS:.', 'MINISTERIO DE LA PRODUCCIÓN.', 'MINISTERIO DEL INTERIOR.', 'MINISTERIO DE AMBIENTE.', 'MINISTERIO DE DEFENSA.', 'MINISTERIO DE SALUD.', NULL, 'e', 'MINISTERIO DE SALUD.', '(texto: 11)** [CAPITULO III]', '184957'),
(2279, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', 'LAS ACCIONES DE PREVENCIÓN QUE REALIZA LA POLICÍA NACIONAL DEL PERÚ A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, CON LA FINALIDAD DE EVITAR EL DESVIÓ DE SUSTANCIAS QUÍMICAS O EL TRÁFICO ILÍCITO DE INSUMOS QUÍMICOS Y PRODUCTOS FISCALIZADOS (IQPF) HACIA EL TRÁFICO ILÍCITO DE DROGAS - TID, TIENEN CARÁCTER:.', 'GENERAL.', 'FISCALIZADOR.', 'REPRESIVO.', 'SELECTIVO.', 'INDIVIDUAL.', NULL, 'd', 'SELECTIVO.', '(texto: 3)** [CAPITULO II]', '184958'),
(2280, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿QUÉ SANCIÓN ES APLICABLE CUANDO LA POLICÍA NACIONAL DEL PERÚ A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, RETIENE TEMPORALMENTE SUSTANCIAS QUÍMICAS Y MEDIOS DE TRANSPORTE, POR REPRESENTAR INFRACCIONES A LAS LEYES DE CONTROL Y FISCALIZACIÓN?:.', 'DECOMISO.', 'INCAUTACIÓN.', 'MULTA.', 'PERENNIZACIÓN.', 'DESTRUCCIÓN.', NULL, 'b', 'INCAUTACIÓN.', '(texto: 3)** [CAPITULO II]', '184959'),
(2281, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿CON QUÉ AUTORIDADES DEBERÁ DE COORDINAR LA POLICÍA NACIONAL, PARA LA DESTRUCCIÓN E INHABILITACIÓN DE PISTAS DE ATERRIZAJE CLANDESTINAS, UTILIZADAS PARA EL TRANSPORTE ILEGAL DE DROGAS TÓXICAS, ESTUPEFACIENTES O SUSTANCIAS PSICOTRÓPICAS?:.', 'MINISTERIO DE LA PRODUCCIÓN O GOBIERNOS REGIONALES.', 'MINISTERIO PÚBLICO.', 'MINISTERIO DE TRANSPORTES Y COMUNICACIONES O GOBIERNOS REGIONALES.', 'MINISTERIO DE TRANSPORTES Y COMUNICACIONES O GOBIERNOS LOCALES.', 'PROCURADOR ANTIDROGAS.', NULL, 'c', 'MINISTERIO DE TRANSPORTES Y COMUNICACIONES O GOBIERNOS REGIONALES.', '(texto: 3)** [CAPITULO II]', '184960'),
(2282, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', 'LA POLICÍA NACIONAL A TRAVÉS DE SUS UNIDADES ESPECIALIZADAS, PARA LA DESTRUCCIÓN O NEUTRALIZACIÓN SEGÚN SEA EL CASO INSTALACIONES RÚSTICAS, FÁBRICAS O LABORATORIOS DE ELABORACIÓN ILEGAL DE DROGAS TÓXICAS COCAÍNITAS, ESTUPEFACIENTES O SUSTANCIAS PSICOTRÓPICAS, CULTIVOS DE PLANTAS DE AMAPOLA O ADORMIDERA DE LA ESPECIE PAPAVER SOMNÍFERUM O DE MARIHUANA DE LA ESPECIE CANNABIS SATIVA, SUSTANCIAS QUÍMICAS, MATERIA PRIMA, MATERIALES E IMPLEMENTOS QUE SE EMPLEAN EN LA ELABORACIÓN DE LAS INDICADAS DROGAS, ADOPTA LAS MEDIDAS ORIENTADAS A:.', 'MINIMIZAR EL IMPACTO ECONÓMICO.', 'MINIMIZAR EL IMPACTO EN LAS ZONAS ADYACENTES.', 'MINIMIZAR EL IMPACTO EN EL ECOSISTEMA.', 'MINIMIZAR EL IMPACTO SOCIOECONÓMICO.', 'MINIMIZAR EL IMPACTO AMBIENTAL.', NULL, 'e', 'MINIMIZAR EL IMPACTO AMBIENTAL.', '(texto: 3)** [CAPITULO II]', '184961'),
(2283, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿QUIÉN AUTORIZA LA DESTRUCCIÓN O INUTILIZACIÓN DE LOS MEDIOS DE TRANSPORTE TERRESTRE, ACUÁTICO O AÉREO QUE SE EMPLEEN O SE PRETENDA EMPLEAR PARA EL TRASLADO DE DROGAS TÓXICAS Y OTRAS SUSTANCIAS ILEGALES?. MARQUE LA RESPUESTA CORRECTA:.', 'JUEZ ESPECIALIZADO.', 'GOBIERNO REGIONAL.', 'DEVIDA.', 'PROCURADOR ANTIDROGAS.', 'MINISTERIO PÚBLICO.', NULL, 'e', 'MINISTERIO PÚBLICO.', '(texto: 3)** [CAPITULO II]', '184962'),
