(2320, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', 'CULTIVOS PROHIBIDOS.- ¿MEDIANTE QUE NORMA LEGAL SE PUEDE INCORPORAR OTRAS PLANTAS O ESPECIES PROHIBIDAS?.', 'MEDIANTE DECRETO LEY, A PROPUESTA DEL MINISTERIO DEL INTERIOR O EN FORMA CONJUNTA CON SECTORES O', 'MEDIANTE RESOLUCIÓN SUPREMA, A PROPUESTA DEL MINISTERIO DEL INTERIOR O EN FORMA CONJUNTA CON', 'MEDIANTE DECRETO DE URGENCIA, A PROPUESTA DEL MINISTERIO DEL INTERIOR O EN FORMA CONJUNTA CON', 'MEDIANTE DECRETO LEGISLATIVO A PROPUESTA DEL MINISTERIO DEL INTERIOR O EN FORMA CONJUNTA CON SECTORES', 'MEDIANTE DECRETO SUPREMO, A PROPUESTA DEL MINISTERIO DEL INTERIOR O EN FORMA CONJUNTA CON SECTORES O', NULL, 'e', 'MEDIANTE DECRETO SUPREMO, A PROPUESTA DEL MINISTERIO DEL INTERIOR O EN FORMA CONJUNTA CON', '(texto: 5)** [CAPITULO III]', '184999'),
(2321, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿EL ESTADO A TRAVÉS DE QUIÉN REALIZA EXCLUSIVAMENTE LA INDUSTRIALIZACIÓN Y COMERCIALIZACIÓN INTERNA Y EXTERNA DE LA HOJA DE COCA PROVENIENTE DE LOS PREDIOS EMPADRONADOS?.', 'LA POLICÍA NACIONAL DEL PERU.', 'MINISTERIO DE LA PRODUCCIÓN.', 'CORAH.', 'ENACO S.A.', 'CONABI.', NULL, 'd', 'ENACO S.A.', '(texto: 6)** [CAPITULO III]', '185000'),
(2322, 'Decreto Legislativo Nº 1241 Que Fortalece La Lucha Contra El Trafico Ilícito De ', '¿QUÉ COMPRENDE LA ELABORACIÓN DE PASTA BÁSICA DE COCAÍNA, CLORHIDRATO DE COCAÍNA Y DEMÁS DERIVADOS DE LA HOJA DE COCA DE PRODUCCIÓN LÍCITA CON FINES BENÉFICOS?.', 'LA COMERCIALIZACIÓN.', 'LA INDUSTRIALIZACIÓN.', 'LA PRODUCCIÓN.', 'LA OFERTA.', 'LA DEMANDA.', NULL, 'b', 'LA INDUSTRIALIZACIÓN.', '(texto: 6)** [CAPITULO III]', '185001'),
