(2581, 'Ley Nº 30077 - Contra El Crimen Organizado', 'SOLO SE INTERCEPTA, RETIENE E INCAUTA LA CORRESPONDENCIA VINCULADA AL DELITO OBJETO DE INVESTIGACIÓN VINCULADO A LA ORGANIZACIÓN CRIMINAL, PROCURANDO, EN LA MEDIDA DE LO POSIBLE:.', 'RESPETAR EL DERECHO A LA INTIMIDAD, ÉTICA Y MORAL PÚBLICA.', 'NO AFECTAR LA CORRESPONDENCIA DE CUARTOS INVOLUCRADOS.', 'AFECTAR LA CORRESPONDENCIA DE PERSONAS NO INVOLUCRADOS.', 'NO AFECTAR LA CORRESPONDENCIA DE TERCEROS NO INVOLUCRADOS.', 'NO AFECTAR LA CORRESPONDENCIA DE FAMILIARES NO INVOLUCRADOS.', NULL, 'd', 'NO AFECTAR LA CORRESPONDENCIA DE TERCEROS NO INVOLUCRADOS.', '(texto: 9)** [TITULO II]  [CAPITULO II]', '185316'),
