(2584, 'Ley Nº 30077 - Contra El Crimen Organizado', 'EN LA AUDIENCIA JUDICIAL DE REEXAMEN, UNA VEZ EJECUTADAS LAS TÉCNICAS ESPECIALES DE INVESTIGACIÓN PREVISTAS EN LOS ARTÍCULOS 9 Y 10, EL AFECTADO PUEDE INSTAR LA REALIZACIÓN DE LA:.', 'AUDIENCIA JUDICIAL DE REEXAMEN.', 'HOMOLOGACIÓN DE DICTÁMENES PERICIALES.', 'CERTIFICACIÓN JUDICIAL DEL PROCEDIMIENTO.', 'PRESENTACIÓN PROCESAL COMO MEDIO DE PRUEBA.', 'DESTRUCCIÓN DEL ELEMENTO DE SOPORTE O MEDIO OBTENIDO.', NULL, 'a', 'AUDIENCIA JUDICIAL DE REEXAMEN.', '(texto: 11)** [TITULO II]  [CAPITULO II]', '185319'),
(2585, 'Ley Nº 30077 - Contra El Crimen Organizado', 'ES UNA TÉCNICA ESPECIAL DE INVESTIGACIÓN, MEDIANTE EL CUAL, UNA VEZ EMITIDA LA DISPOSICIÓN FISCAL QUE AUTORIZA SU PARTICIPACIÓN, QUEDAN FACULTADOS PARA PARTICIPAR EN EL TRÁFICO JURÍDICO Y SOCIAL, ADQUIRIR, POSEER O TRANSPORTAR BIENES DE CARÁCTER DELICTIVO, PERMITIR SU INCAUTACIÓN E INTERVENIR EN TODA ACTIVIDAD ÚTIL Y NECESARIA PARA LA INVESTIGACIÓN DEL DELITO QUE MOTIVÓ LA DILIGENCIA.', 'COLABORADOR EFICAZ.', 'AGENTE ENCUBIERTO.', 'PESQUISA INSTRUCTOR.', 'PERITO JUDICIAL.', 'FISCAL ESPECIAL.', NULL, 'b', 'AGENTE ENCUBIERTO.', '(texto: 13)** [TITULO II]  [CAPITULO II]', '185321'),
