(2648, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL PERSONAL POLICIAL CUANDO CONSIDERE QUE UNA PERSONA OCULTE EN SU CUERPO O ÁMBITO CORPORAL, BIENES RELACIONADOS CON EL DELITO, DEBERÁ: (MARQUE LA ALTERNATIVA CORRECTA)', 'COMUNICAR AL JEFE DE UNIDAD PARA QUE DISPONGA LO CONVENIENTE', 'COMUNICAR A LA UNIDAD Y PROCEDER CON EL REGISTRO', 'REGISTRAR A LA PERSONA INMEDIATAMENTE', 'COMUNICAR AL JUEZ COMPETENTE', 'SOLICITARÁ A LA PERSONA A QUE EXHIBA Y ENTREGUE EL BIEN BUSCADO', NULL, 'e', 'SOLICITARÁ A LA PERSONA A QUE EXHIBA Y ENTREGUE EL BIEN BUSCADO', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185727'),
(2649, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ANTES DE INICIAR EL REGISTRO SE EXPRESARÁ A EL/LA INTERVENIDO/A LAS RAZONES DE SU EJECUCIÓN, Y SE LE INDICARÁ QUE TIENE DERECHO DE HACERSE ASISTIR EN ESE ACTO POR UNA PERSONA DE SU CONFIANZA, SIEMPRE QUE ÉSTA SE PUEDA UBICAR RÁPIDAMENTE Y SEA MAYOR DE EDAD. SI LA PERSONA ES UBICADA, PERO SU ESPERA PONE EN RIESGO LA FINALIDAD DE LA MEDIDA:', 'EL REGISTRO SE REALIZARÁ SIN SU PARTICIPACIÓN, DEJÁNDOSE CONSTANCIA DE ELLO', 'EL REGISTRO SE REALIZARÁ SIN SU PARTICIPACIÓN, NO DEJÁNDOSE CONSTANCIA DE ELLO', 'EL REGISTRO SE REALIZARÁ CON SU PARTICIPACIÓN, DEJÁNDOSE CONSTANCIA DE ELLO', 'EL REGISTRO SE REALIZARÁ CON SU PARTICIPACIÓN, NO DEJÁNDOSE CONSTANCIA DE ELLO', 'EL REGISTRO SE REALIZA DE TODAS FORMAS Y SE ESPERA A LA PERSONA PARA LA FIRMA DEL ACTA', NULL, 'a', 'EL REGISTRO SE REALIZARÁ SIN SU PARTICIPACIÓN, DEJÁNDOSE CONSTANCIA DE ELLO', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185728'),
(2650, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LOS CASOS EN QUE LA PERSONA INTERVENIDA NO ACEPTE SOMETERSE AL REGISTRO POR UN PERSONAL POLICIAL DE OTRO SEXO Y, NO EXISTA RIESGO DE PÉRDIDA DE LA FUENTE DE PRUEBA, DEBERÁ:', 'SER CONDUCIDA A LA DEPENDENCIA POLICIAL MÁS CERCANA, DANDO CUENTA INMEDIATAMENTE AL FISCAL', 'SER CONDUCIDA A LA DEPENDENCIA POLICIAL MÁS CERCANA, DANDO CUENTA INMEDIATAMENTE AL JUEZ', 'SER CONDUCIDA AL DESPACHO FISCAL', 'SER CONDUCIDA AL JUEZ COMPETENTE', 'SER CONDUCIDA AL DESPACHO FISCAL, DANDO CUENTA INMEDIATAMENTE AL JEFE', NULL, 'a', 'SER CONDUCIDA A LA DEPENDENCIA POLICIAL MÁS CERCANA, DANDO CUENTA INMEDIATAMENTE AL FISCAL', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185729'),
(2651, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL REGISTRO PERSONAL NO COMPRENDE EXTRACCIÓN DE MUESTRAS COMO PRUEBAS DE ANÁLISIS SANGUÍNEO, GENÉTICO-MOLECULARES; ASÍ COMO, EXPLORACIONES RADIOLÓGICAS, U OTRAS MÍNIMAS INTERVENCIONES CORPORALES PARA OBSERVACIÓN; SALVO QUE LA PERSONA DEBIDAMENTE INFORMADA LO AUTORICE.', 'EL RECONOCIMIENTO MÉDICO LEGAL', 'LA INTERVENCIÓN POLICIAL', 'EL REGISTRO PERSONAL', 'LOS EXÁMENES DE LEY', 'EL RECONOCIMIENTO MÉDICO', NULL, 'c', 'EL REGISTRO PERSONAL', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN. LÍMITES', '185730'),
(2652, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SI DEL REGISTRO PERSONAL SE PRESUME QUE LA PERSONA LLEVA DENTRO DE SU CUERPO ELEMENTOS O INDICIOS DE PRUEBA:', 'EL PERSONAL POLICIAL DEBERÁ DAR CUENTA A EL/LA FISCAL, A FIN QUE ÉSTE ÚLTIMO SOLICITE EL REQUERIMIENTO', 'EL PERSONAL POLICIAL DEBERÁ DAR CUENTA AL JEFE DE UNIDAD, A FIN QUE ÉSTE ÚLTIMO SOLICITE EL REQUERIMIENTO', 'EL PERSONAL POLICIAL DEBERÁ DAR CUENTA AL FISCAL Y JUEZ COMPETENTE', 'EL PERSONAL POLICIAL DEBERÁ DAR JUEZ COMPETENTE', 'EL PERSONAL POLICIAL DEBERÁ DAR CUENTA AL FISCAL PARA QUE DISPONGA LO COMPETENTE', NULL, 'a', 'EL PERSONAL POLICIAL DEBERÁ DAR CUENTA A EL/LA FISCAL, A FIN QUE ÉSTE ÚLTIMO SOLICITE EL', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185731'),
(2653, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES AQUELLA INJERENCIA CON EL PROPÓSITO DE BUSCAR O HALLAR EFECTOS O ELEMENTOS VINCULADOS AL DELITO, SIN QUE ELLO IMPLIQUE EL EXAMEN DEL CUERPO.', 'LA RECEPCIÓN', 'LA CADENA DE CUSTODIA', 'EL COMISO', 'LA INCAUTACIÓN', 'EL REGISTRO', NULL, 'e', 'EL REGISTRO', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185732'),
(2654, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EXCEPCIONALMENTE CUANDO HAYA URGENCIA Y PELIGRO EN LA DEMORA Y, NO SE PUEDA ESPERAR LA ORDEN JUDICIAL:ROCEDE A:.', 'EL/LA FISCAL SUSPENDERÁ LA DILIGENCIA', 'EL JUEZ NO DISPONE LA DILIGENCIA POR EL TIEMPO TRANSCURRIDO', 'EL/LA FISCAL ORDENARÁ LA INTERVENCIÓN CORPORAL', 'EL/LA FISCAL ES INDEPENDIENTE', 'EL/LA FISCAL ORDENARÁ LA INTERVENCIÓN POLICIAL', NULL, 'c', 'EL/LA FISCAL ORDENARÁ LA INTERVENCIÓN CORPORAL', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185733'),
(2655, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SE PRODUCE ANTE LA ENTREGA VOLUNTARIA Y ESPONTÁNEA DE LOS EFECTOS O ELEMENTOS VINCULADOS AL DELITO, O COMO CONSECUENCIA DE LA SOLICITUD DE LA AUTORIDAD COMPETENTE.', 'LA CADENA DE CUSTODIA', 'EL COMISO', 'EL REGISTRO', 'LA RECEPCIÓN', 'LA INCAUTACIÓN', NULL, 'd', 'LA RECEPCIÓN', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185734'),
(2656, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SI SE VERIFICA QUE EN EL VEHÍCULO SE ENCUENTRAN BIENES, EFECTOS O INSTRUMENTOS VINCULADOS A LA COMISIÓN DE UN DELITO, SE PROCEDERÁ A INFORMAR A EL/LA DETENIDO/A LA CAUSA:', 'EL MOTIVO DE SU DETENCIÓN Y EL DELITO QUE SE LE ATRIBUYE ASÍ COMO, LOS DERECHOS ESTABLECIDOS EN EL', 'EL MOTIVO DE SU DETENCIÓN Y EL DELITO QUE SE LE ATRIBUYE ASÍ COMO, LOS DERECHOS ESTABLECIDOS EN EL', 'EL MOTIVO DE SU DETENCIÓN Y EL DELITO QUE SE LE ATRIBUYE ASÍ COMO, LOS DERECHOS ESTABLECIDOS EN EL', 'EL MOTIVO DE SU DETENCIÓN Y EL DELITO QUE SE LE ATRIBUYE ASÍ COMO, LOS DERECHOS ESTABLECIDOS EN EL', 'EL MOTIVO DE SU DETENCIÓN Y EL DELITO QUE SE LE ATRIBUYE ASÍ COMO, LOS DERECHOS ESTABLECIDOS EN EL', NULL, 'a', 'EL MOTIVO DE SU DETENCIÓN Y EL DELITO QUE SE LE ATRIBUYE ASÍ COMO, LOS DERECHOS ESTABLECIDOS', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185735'),
(2657, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL REGISTRO DE VEHÍCULOS VINCULADOS CON DELITOS. EL PERSONAL POLICIAL PROCEDERÁ A LEVANTAR LAS SIGUIENTES ACTAS:', 'ACTA DE RECEPCIÓN', 'ACTA DE ENTREGA', 'ACTA DE HALLAZGO', 'ACTA DE COMISO', 'ACTA DE SITUACIÓN VEHICULAR Y ACTA DE REGISTRO VEHICULAR', NULL, 'e', 'ACTA DE SITUACIÓN VEHICULAR Y ACTA DE REGISTRO VEHICULAR', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185736'),
(2658, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CULMINADAS LAS DILIGENCIAS NECESARIAS EN EL LUGAR DE LOS HECHOS, EL VEHÍCULO SERÁ TRASLADADO: (MARQUE LA ALTERNATIVA CORRECTA)', 'AL DEPÓSITO MUNICIPAL', 'AL DESPACHO DEL JUEZ', 'AL DESPACHO DEL FISCAL', 'A LA PLAYA DE ESTACIONAMIENTO QUE INDIQUE EL INTERVENIDO', 'A LA DEPENDENCIA POLICIAL QUE TENDRÁ A SU CARGO LA INVESTIGACIÓN', NULL, 'e', 'A LA DEPENDENCIA POLICIAL QUE TENDRÁ A SU CARGO LA INVESTIGACIÓN', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL PARA LA APLICACIÓN DEL REGISTRO Y RECEPCIÓN.', '185737'),
(2659, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'QUE NORMA APRUEBA EL PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL ESPECÍFICO PARA LA APLICACIÓN DEL PROCESO INMEDIATO REFORMADO.', 'DECRETO SUPREMO N° 009-2018-JUS', 'DECRETO SUPREMO N° 010-2018-JUS', 'DECRETO SUPREMO N° 012-2018-JUS', 'DECRETO SUPREMO N° 013-2018-JUS', 'DECRETO SUPREMO N° 014-2018-JUS', NULL, 'a', 'DECRETO SUPREMO N° 009-2018-JUS', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL ESPECÍFICO PARA LA APLICACIÓN DEL PROCESO', '185738'),
(2660, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'FORTALECER LA ACTUACIÓN DE LOS OPERADORES DEL SISTEMA DE JUSTICIA PENAL EN LA APLICACIÓN DEL PROCESO INMEDIATO EN CASOS DE FLAGRANCIA Y OTROS SUPUESTOS (JUECES/ZAS, FISCALES, DEFENSORES/AS. POLICÍAS Y PROCURADORES/AS). EL PRESENTE ENUNCIADO CORRESPONDE A:', 'OBJETIVO', 'FINALIDAD', 'ALCANCE', 'EFICACIA', 'SIMPLIFICACIÓN', NULL, 'a', 'OBJETIVO', 'PROTOCOLO DE ACTUACIÓN INTERINSTITUCIONAL ESPECÍFICO PARA LA APLICACIÓN DEL PROCESO', '185739'),
(2661, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL ÁMBITO DE ACTUACIÓN JURISDICCIONAL DE LA INVESTIGACIÓN REALIZADA POR LA POLICÍA NACIONAL DEL PERÚ BAJO LA CONDUCCIÓN JURÍDICA DEL MINISTERIO PÚBLICO SEGÚN LA MODIFICACIÓN DE LA LEY 32130:', 'LA INVESTIGACIÓN POLICIAL TIENE CARÁCTER JURISDICCIONAL PLENO DESDE SU INICIO, PERMITIENDO A LA POLICÍA', 'LA INVESTIGACIÓN POLICIAL, BAJO LA CONDUCCIÓN DEL MINISTERIO PÚBLICO, ADQUIERE CARÁCTER JURISDICCIONAL', 'LA INVESTIGACIÓN POLICIAL, BAJO CONDUCCIÓN DEL MINISTERIO PÚBLICO, NO TIENE CARÁCTER JURISDICCIONAL,', 'LA INVESTIGACIÓN POLICIAL ES DE NATURALEZA JURISDICCIONAL SOLO CUANDO INTERVIENEN PERITOS EXTERNOS', 'LA INVESTIGACIÓN POLICIAL Y LA FISCALÍA COMPARTEN COMPETENCIA JURISDICCIONAL EN IGUALDAD DE CONDICIONES', NULL, 'c', 'LA INVESTIGACIÓN POLICIAL, BAJO CONDUCCIÓN DEL MINISTERIO PÚBLICO, NO TIENE CARÁCTER', '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184850'),
(2662, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA LEY 32130, ¿CUÁL ES LA FUNCIÓN PRIMORDIAL DEL MINISTERIO PÚBLICO EN RELACIÓN CON LA POLICÍA NACIONAL DURANTE LA INVESTIGACIÓN PRELIMINAR DE UN DELITO:', 'EMITIR RESOLUCIONES JURISDICCIONALES REEMPLAZANDO AL JUEZ PENAL EN ACTOS DE URGENCIA.', 'DIRIGIR JURÍDICAMENTE LA INVESTIGACIÓN ORIENTANDO LEGALMENTE LAS ACCIONES DE LA POLICÍA NACIONAL DEL', 'REALIZAR DE MANERA INDEPENDIENTE LA INTERVENCIÓN POLICIAL SIN COORDINACIÓN INTERINSTITUCIONAL.', 'SUPERVISAR ÚNICAMENTE LA RECOLECCIÓN DE PRUEBAS FÍSICAS Y DOCUMENTALES SIN INDAGAR SOBRE LA INOCENCIA', 'DESIGNAR A LOS ABOGADOS DEFENSORES PÚBLICOS EN TODOS LOS CASOS QUE INVESTIGUE LA POLICÍA.', NULL, 'b', 'DIRIGIR JURÍDICAMENTE LA INVESTIGACIÓN ORIENTANDO LEGALMENTE LAS ACCIONES DE LA POLICÍA', '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184851'),
(2663, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN VIRTUD DE LA MODIFICACIÓN LEGAL REFERIDA, QUÉ DEBER FUNDAMENTAL RECAE SOBRE EL MINISTERIO PÚBLICO RESPECTO A LA CARGA DE LA PRUEBA EN EL PROCESO PENAL:', 'COMPARTIR LA CARGA DE LA PRUEBA CON EL IMPUTADO EN LA INVESTIGACIÓN PRELIMINAR.', 'RECABAR LA MAYOR CANTIDAD DE ELEMENTOS PROBATORIOS, SIN IMPORTAR SI DETERMINAN INOCENCIA O', 'ASUMIR LA CARGA DE LA PRUEBA. ACTUANDO CON OBJETIVIDAD, INDAGANDO POR INTERMEDIO DE LA POLICIA TANTO', 'LIMITAR LA CARGA DE LA PRUEBA SOLO A LOS HECHOS PRESENTADOS POR LA ACUSACIÓN PARTICULAR.', 'DELEGAR LA CARGA DE LA PRUEBA EN SU TOTALIDAD EN LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'c', 'ASUMIR LA CARGA DE LA PRUEBA. ACTUANDO CON OBJETIVIDAD, INDAGANDO POR INTERMEDIO DE LA POLICIA', '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184852'),
(2664, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ANTE QUÉ SITUACIÓN LA POLICÍA NACIONAL Y EL MINISTERIO PÚBLICO DEBEN REQUERIR LA INTERVENCIÓN DEL ÓRGANO JURISDICCIONAL COMPETENTE DURANTE LA ETAPA DE INVESTIGACIÓN PRELIMINAR:', 'CUANDO SE TRATE DE ACTOS DE INVESTIGACIÓN QUE INVOLUCREN MENORES DE EDAD, INDEPENDIENTEMENTE DEL TIPO', 'SOLO CUANDO LA POLICÍA NACIONAL NO CUENTE CON LOS RECURSOS MATERIALES PARA CONTINUAR LA INVESTIGACIÓN', 'SIEMPRE QUE SE REQUIERA UNA DECISIÓN DE NATURALEZA JURISDICCIONAL QUE EXCEDA LAS COMPETENCIAS LEGALES,', 'AL INICIO DE TODA INVESTIGACIÓN PRELIMINAR, SIN EXCLUSIÓN DE ACTOS JURÍDICOS POSTERIORES.', 'CUANDO EL DELITO INVESTIGADO INVOLUCRE FUNCIONARIOS PÚBLICOS BAJO RESERVA DE LEY.', NULL, 'c', 'SIEMPRE QUE SE REQUIERA UNA DECISIÓN DE NATURALEZA JURISDICCIONAL QUE EXCEDA LAS', '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184853'),
(2665, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO CON LA LEY 32130, ¿CUÁL ES LA RELACIÓN JERÁRQUICA Y FUNCIONAL ENTRE EL MINISTERIO PÚBLICO Y LA POLICÍA NACIONAL EN EL MARCO DE LA INVESTIGACIÓN DEL DELITO:', 'LA POLICÍA NACIONAL DIRIGE AUTÓNOMAMENTE LA INVESTIGACIÓN Y EL MINISTERIO PÚBLICO SOLO REVISA EL INFORME', 'LA POLICÍA NACIONAL EJERCE INICIATIVA PLENA EN LA PRODUCCIÓN DE PRUEBAS Y EL MINISTERIO PÚBLICO SE LIMITA A', 'EL MINISTERIO PÚBLICO ASUME LA CONDUCCIÓN JURÍDICA DE LA INVESTIGACIÓN Y LA POLICÍA NACIONAL REALIZA LA', 'AMBOS ÓRGANOS ACTÚAN EN PIE DE IGUALDAD EN LA TOMA DE DECISIONES JURÍDICAS DURANTE LA INVESTIGACIÓN', 'LA POLICÍA NACIONAL SOLO INTERVIENE CUANDO EL JUEZ PENAL LO AUTORIZA, ACTUANDO BAJO CONTROL JUDICIAL', NULL, 'c', 'EL MINISTERIO PÚBLICO ASUME LA CONDUCCIÓN JURÍDICA DE LA INVESTIGACIÓN Y LA POLICÍA NACIONAL', '(texto: (ART: UNICO)**Articulo IV. Titular de la accion Penal)**', '184854'),
(2666, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES SITUACIONES CONSTITUYE UNA CAUSAL DE INHIBICIÓN OBLIGATORIA PARA JUECES EN UN PROCESO PENAL SEGÚN LA MODIFICACIÓN INTRODUCIDA POR LA LEY 32130 AL ARTÍCULO ÚNICO DEL D.LEG. 957:', 'QUE EL JUEZ HAYA MANIFESTADO SU OPINIÓN SOBRE LA CAUSA A UNA DE LAS PARTES DEL PROCESO DE MODO', 'QUE EL JUEZ HAYA PARTICIPADO PREVIAMENTE COMO ABOGADO DEFENSOR EN UNA CAUSA SIMILAR.', 'QUE EL JUEZ TENGA PARENTESCO CON UNO DE LOS TESTIGOS DEL PROCESO.', 'QUE EL JUEZ HAYA ACONSEJADO SOBRE LA CAUSA A CUALQUIERA DE LAS PARTES DEL PROCESO, AFECTANDO', 'QUE EL JUEZ HAYA INTERPRETADO UN ARTÍCULO DEL CÓDIGO PENAL PARA EFECTOS DOCTRINARIOS EN UNA REVISTA', NULL, 'd', 'QUE EL JUEZ HAYA ACONSEJADO SOBRE LA CAUSA A CUALQUIERA DE LAS PARTES DEL PROCESO,', '(texto: (ART: UNICO)**Articulo 53. Inhibicion)**', '184855'),
(2667, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA INHIBICIÓN DE FISCALES SEÑALADA EN EL ART 53 ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA TENIENDO EN CUENTA LA LEY 32130:', 'LA INHIBICIÓN DE FISCALES SOLO SE APLICA SI HAN ACTUADO COMO ABOGADOS EN UNA CAUSA CONEXA.', 'LA DISPOSICIÓN SOBRE INHIBICIÓN DE FISCALES APLICA ÚNICAMENTE SI EXISTE PRUEBA DOCUMENTAL DE PARCIALIDAD.', 'LA FALTA COMETIDA POR LOS FISCALES QUE INCURREN EN LAS CAUSALES DE INHIBICIÓN ES CONSIDERADA FALTA LEVE', 'DICHA INHIBICIÓN ALCANZA A LOS FISCALES EN LOS MISMOS TÉRMINOS QUE A LOS JUECES Y SU INOBSERVANCIA', 'NO SE EXIGE FUNDAMENTO PARA LA INHIBICIÓN DE FISCALES, BASTA LA SIMPLE SOSPECHA DE IMPARCIALIDAD.', NULL, 'd', 'DICHA INHIBICIÓN ALCANZA A LOS FISCALES EN LOS MISMOS TÉRMINOS QUE A LOS JUECES Y SU', '(texto: (ART: UNICO)**Articulo 53. Inhibicion)**', '184856'),
(2668, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN EL MARCO DE LA LEY 32130, QUE MODIFICA EL ARTÍCULO 54 DEL CÓDIGO PROCESAL PENAL SOBRE RECUSACIONES, ¿EN QUÉ MOMENTO PUEDE SER INTERPUESTA UNA RECUSACIÓN DURANTE EL PROCEDIMIENTO RECURSAL Y CUÁL ES LA OBLIGACIÓN PROCESAL RESPECTO AL PLAZO PARA LAS PARTES:', 'PUEDE SER INTERPUESTA HASTA ANTES DE LA NOTIFICACIÓN DE LA SENTENCIA, SIENDO EL ÓRGANO REVISOR QUIEN', 'DEBE SER INTERPUESTA HASTA UN DÍA HÁBIL ANTES DE LA AUDIENCIA DE VISTA DE LA CAUSA Y EL ÓRGANO REVISOR', 'LA RECUSACIÓN PUEDE INTERPONERSE EN CUALQUIER MOMENTO ANTES DEL PRONUNCIAMIENTO DEL JUZGADO DE', 'ES VÁLIDA SOLO CUANDO SE INTERPONE AL INICIO DE LA AUDIENCIA, DEBIENDO EL ÓRGANO REVISOR CONCEDER CINCO', 'LA RECUSACIÓN SÓLO PUEDE PLANTEARSE DURANTE LA AUDIENCIA DE VISTA DE LA CAUSA, Y EL ÓRGANO REVISOR ESTÁ', NULL, 'b', 'DEBE SER INTERPUESTA HASTA UN DÍA HÁBIL ANTES DE LA AUDIENCIA DE VISTA DE LA CAUSA Y EL ÓRGANO', '(texto: (ART: UNICO)**Articulo 54. Requisitos de la recusacion)**', '184857'),
(2669, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LAS MODIFICACIONES INTRODUCIDAS AL ARTÍCULO 54 DEL CÓDIGO PROCESAL PENAL POR LA LEY 32130, ¿QUÉ IMPLICANCIAS TIENE PARA EL JUEZ NO INHIBIRSE DE OFICIO ANTE LA VERIFICACIÓN DE UNA CAUSAL DE INHIBICIÓN DESPUÉS DEL INICIO DE LA AUDIENCIA Y BAJO QUÉ LEY SE TIPIFICA DICHA CONDUCTA:', 'EL JUEZ QUE NO SE INHIBE DE OFICIO INCURRIRÁ EN UNA FALTA ADMINISTRATIVA LEVE PREVISTA EN LA LEY ORGÁNICA', 'LA OMISIÓN DE INHIBICIÓN DE OFICIO DEL JUEZ CONSTITUYE UNA FALTA MUY GRAVE PREVISTA EN LA LEY 29277, LEY DE', 'DICHO ACTO CONSTITUYE DELITO DE PREVARICATO SEGÚN EL CÓDIGO PENAL Y NO FALTA DISCIPLINARIA.', 'EL JUEZ ÚNICAMENTE INCUMPLE UN REQUISITO DE FORMALIDAD SIN OTRAS CONSECUENCIAS JURÍDICAS.', 'NO EXISTEN CONSECUENCIAS PARA EL JUEZ SI NINGUNA DE LAS PARTES ADVIERTE EL HECHO CONSTITUTIVO DE CAUSAL', NULL, 'b', 'LA OMISIÓN DE INHIBICIÓN DE OFICIO DEL JUEZ CONSTITUYE UNA FALTA MUY GRAVE PREVISTA EN LA LEY', '(texto: (ART: UNICO)**Articulo 54. Requisitos de la recusacion)**', '184858'),
(2670, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿SEGÚN EL ARTÍCULO 60 MODIFICADO POR LA LEY 32130, CUÁL ES LA FUNCIÓN CENTRAL DEL FISCAL EN LA INVESTIGACIÓN PRELIMINAR DEL DELITO:', 'EL FISCAL EJECUTA MATERIALMENTE TODOS LOS ACTOS DE INVESTIGACIÓN DE MODO EXCLUSIVO.', 'EL FISCAL CONDUCE JURÍDICAMENTE LA INVESTIGACIÓN PRELIMINAR, LA CUAL ES LLEVADA A CABO POR LA POLICÍA', 'LA POLICÍA NACIONAL DEL PERÚ DIRIGE LA INVESTIGACIÓN PRELIMINAR Y EL FISCAL SOLO SUPERVISA SUS ACCIONES.', 'EL FISCAL Y LA POLICÍA NACIONAL DEL PERÚ COMPARTEN IDÉNTICAS COMPETENCIAS Y FUNCIONES DURANTE LA', 'EL FISCAL SOLO INTERVIENE EN LA INVESTIGACIÓN PREPARATORIA, MIENTRAS QUE LA INVESTIGACIÓN PRELIMINAR ES', NULL, 'b', 'EL FISCAL CONDUCE JURÍDICAMENTE LA INVESTIGACIÓN PRELIMINAR, LA CUAL ES LLEVADA A CABO POR LA', '(texto: (ART: UNICO)**Articulo 60. Funciones)**', '184859'),
(2671, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CONFORME AL ARTÍCULO 60 DEL CÓDIGO PROCESAL PENAL TRAS LA MODIFICACIÓN POR LA LEY 32130, ¿BAJO QUÉ PRINCIPIO DEBE EL FISCAL CONDUCIR LA INVESTIGACIÓN PREPARATORIA DEL DELITO:', 'BAJO EL PRINCIPIO DE OPORTUNIDAD, PROMOVIENDO LA CONCILIACIÓN ENTRE LAS PARTES.', 'BAJO EL PRINCIPIO DE LEGALIDAD, ASEGURANDO LA CORRECTA APLICACIÓN DE LA NORMA.', 'BAJO EL PRINCIPIO DE ARBITRARIEDAD, ACTUANDO SEGÚN SU PROPIO CRITERIO.', 'BAJO EL PRINCIPIO DE EJECUCIÓN DIRECTA Y MATERIAL DE LAS ACCIONES POLICIALES.', 'BAJO EL PRINCIPIO DE AUTONOMÍA ABSOLUTA DE LA POLICÍA NACIONAL DEL PERÚ SIN INTERVENCIÓN DEL MINISTERIO', NULL, 'b', 'BAJO EL PRINCIPIO DE LEGALIDAD, ASEGURANDO LA CORRECTA APLICACIÓN DE LA NORMA.', '(texto: (ART: UNICO)**Articulo 60. Funciones)**', '184860'),
(2672, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL PLAZO MÁXIMO QUE TIENE EL FISCAL PARA DISPONER EL INICIO DE LA INVESTIGACIÓN PRELIMINAR EN CASO DE DELITOS DE TRÁFICO ILÍCITO DE DROGAS, TERRORISMO, SICARIATO, EXTORSIÓN, SECUESTRO, FEMINICIDIO Y CRIMINALIDAD ORGANIZADA:', 'DOCE HORAS', 'TREINTA Y SEIS HORAS', 'CUARENTA Y OCHO HORAS', 'VEINTICUATRO HORAS', 'SETENTA Y DOS HORAS', NULL, 'd', 'VEINTICUATRO HORAS', '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184861'),
(2673, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO PROCESADO, ¿EN QUÉ MOMENTO INTERVIENE EL FISCAL DE MANERA PERMANENTE EN LA INVESTIGACIÓN A CARGO DE LA POLICÍA NACIONAL DEL PERÚ:', 'DESDE LA DENUNCIA POLICIAL HASTA LA ACUSACIÓN', 'DESDE LA DISPOSICIÓN PARA LA INVESTIGACIÓN PRELIMINAR BAJO SU CONDUCCIÓN', 'DESDE EL INICIO DE LA INVESTIGACIÓN PRELIMINAR HASTA QUE SE DICTA SENTENCIA', 'ÚNICAMENTE AL MOMENTO DE RECIBIR EL ATESTADO POLICIAL', 'A PARTIR DE LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA Y DURANTE TODO EL DESARROLLO DEL PROCESO', NULL, 'e', 'A PARTIR DE LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA Y DURANTE TODO EL DESARROLLO', '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184862'),
(2674, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ DEBE PROCURAR EL FISCAL AL INDAGAR POR INTERMEDIO DE LA POLICÍA NACIONAL DEL PERÚ, EN CASO NO EXISTA DETENIDO NI FLAGRANCIA:', 'SOLO RECABAR PRUEBAS QUE INCRIMINEN AL IMPUTADO', 'INDAGAR ÚNICAMENTE SOBRE LAS CIRCUNSTANCIAS QUE EXIMAN DE RESPONSABILIDAD AL IMPUTADO', 'INVESTIGAR TANTO CIRCUNSTANCIAS QUE COMPRUEBEN LA IMPUTACIÓN, COMO LAS QUE EXIMAN O ATENÚEN LA', 'SOLICITAR INMEDIATAMENTE LA PRISIÓN PREVENTIVA', 'DELEGAR TOTALMENTE LA INVESTIGACIÓN A LA POLICÍA SIN NINGÚN CONTROL POSTERIOR', NULL, 'c', 'INVESTIGAR TANTO CIRCUNSTANCIAS QUE COMPRUEBEN LA IMPUTACIÓN, COMO LAS QUE EXIMAN O', '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184863'),
(2675, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES ACCIONES ES UNA ATRIBUCIÓN Y/O OBLIGACION DIRECTA DEL FISCAL, CONFORME AL ARTÍCULO 61 DE LA PRESENTE LEY:', 'EMITIR SENTENCIAS DE PRIMERA INSTANCIA', 'SOLICITAR AL JUEZ LAS MEDIDAS QUE CONSIDERE NECESARIAS CUANDO CORRESPONDA HACERLO', 'ORDENAR LA DETENCIÓN SIN INTERVENCIÓN JUDICIAL', 'OTORGAR PERMISOS DE LIBERTAD PROVISORIA', 'EJERCER FUNCIONES DE DEFENSOR PÚBLICO', NULL, 'b', 'SOLICITAR AL JUEZ LAS MEDIDAS QUE CONSIDERE NECESARIAS CUANDO CORRESPONDA HACERLO', '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184864'),
(2676, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LAS ATRIBUCIONES Y OBLIGACIONES (ART61), EL FISCAL, MARQUE LA ALTERNATIVA CORRECTA, DE CONFORMIDAD A LA NORMA COMENTADA:', 'SOLO PUEDE APELAR SENTENCIAS ABSOLUTORIAS', 'TIENE LEGITIMACIÓN PARA INTERPONER LOS RECURSOS Y MEDIOS DE IMPUGNACIÓN QUE LA LEY ESTABLECE', 'ESTÁ LIMITADO A INTERPONER RECURSOS ÚNICAMENTE DURANTE LA INVESTIGACIÓN PRELIMINAR', 'NO PUEDE INTERPONER RECURSOS EN NINGUNA ETAPA', 'SOLO PUEDE INTERPONER QUEJAS ADMINISTRATIVAS ANTE EL PODER JUDICIAL', NULL, 'b', 'TIENE LEGITIMACIÓN PARA INTERPONER LOS RECURSOS Y MEDIOS DE IMPUGNACIÓN QUE LA LEY ESTABLECE', '(texto: (ART: UNICO)**Articulo 61. Atribuciones y obligaciones)**', '184865'),
(2677, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL ROL INICIAL QUE DEBE ASUMIR EL FISCAL CUANDO RECIBE NOTICIA DE LA COMISIÓN DE UN DELITO, CONFORME AL ARTÍCULO 65 DEL CÓDIGO PROCESAL PENAL MODIFICADO POR LA LEY 32130?:', 'SOLICITAR AL PODER JUDICIAL QUE AUTORICE LA INVESTIGACIÓN.', 'DISPONER DE FORMA INMEDIATA QUE LA DEFENSORÍA DEL PUEBLO REALICE LAS DILIGENCIAS PRELIMINARES.', 'DISPONER DE FORMA INMEDIATA QUE LA POLICÍA NACIONAL DEL PERÚ REALICE LAS DILIGENCIAS PRELIMINARES.', 'LLAMAR A LAS PARTES INVOLUCRADAS A UNA CONCILIACIÓN EXTRAJUDICIAL.', 'REMITIR EL CASO A LA JUNTA DE FISCALES SUPERIORES PARA SU EVALUACIÓN.', NULL, 'c', 'DISPONER DE FORMA INMEDIATA QUE LA POLICÍA NACIONAL DEL PERÚ REALICE LAS DILIGENCIAS', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184866'),
(2678, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO CON EL ARTÍCULO 65, CUANDO EL FISCAL DISPONE EL INICIO DE LA INVESTIGACIÓN PRELIMINAR, ¿QUÉ DEBE PRECISARSE NECESARIAMENTE?:', 'EL OBJETO, LOS PLAZOS Y LAS FORMALIDADES ESPECÍFICAS APLICABLES.', 'LA DESIGNACIÓN DE UN PERITO OFICIAL.', 'EL MONTO DE LAS REPARACIONES CIVILES.', 'EL JUEZ QUE SUPERVISARÁ LA INVESTIGACIÓN.', 'EL PRONUNCIAMIENTO SOBRE LA CULPABILIDAD DEL IMPUTADO.', NULL, 'a', 'EL OBJETO, LOS PLAZOS Y LAS FORMALIDADES ESPECÍFICAS APLICABLES.', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184867'),
(2679, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA MODIFICACIÓN INTRODUCIDA POR LA LEY 32130, ¿A QUIÉN CORRESPONDE DEFINIR LA ESTRATEGIA OPERATIVA EN LA INVESTIGACIÓN DEL DELITO?:', 'AL JUEZ DE GARANTÍAS.', 'AL FISCAL EN TODO MOMENTO Y SIN EXCEPCIÓN.', 'A LA POLICÍA NACIONAL DEL PERÚ.', 'A LA CORTE SUPERIOR DE JUSTICIA.', 'A LA DEFENSA TÉCNICA DEL IMPUTADO.', NULL, 'c', 'A LA POLICÍA NACIONAL DEL PERÚ.', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184868'),
(2680, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ASPECTO DEBEN GARANTIZAR TANTO EL FISCAL COMO LA POLICÍA NACIONAL DEL PERÚ DURANTE LA INVESTIGACIÓN DEL DELITO, SEGÚN EL ARTÍCULO 65 DE LA LEY N°32130?:', 'EL RESARCIMIENTO ECONÓMICO DE LA VÍCTIMA.', 'EL DERECHO DE DEFENSA DEL IMPUTADO Y SUS DEMAS DERECHOS FUNDAMENTALES.', 'LA OBTENCIÓN DE PRUEBAS SIN LÍMITES LEGALES CUANDO SE TRATE DE DELITOS GRAVES.', 'LA PARTICIPACIÓN DE LA PRENSA EN TODAS LAS DILIGENCIAS.', 'EL SECRETO ABSOLUTO DE LAS ACTUACIONES.', NULL, 'b', 'EL DERECHO DE DEFENSA DEL IMPUTADO Y SUS DEMAS DERECHOS FUNDAMENTALES.', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184869'),
(2681, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA RELACIÓN ENTRE LA ESTRATEGIA JURÍDICA Y LA ESTRATEGIA OPERATIVA SEGÚN LA LEY 32130?:', 'AMBAS ESTRATEGIAS SON DIRIGIDAS POR LA POLICÍA NACIONAL DEL PERÚ.', 'LA ESTRATEGIA JURÍDICA ES COMPETENCIA DEL FISCAL Y LA OPERATIVA DE LA POLICÍA, PERO DEBEN SER', 'LA ESTRATEGIA JURÍDICA Y LA OPERATIVA SÓLO LAS DEFINE EL JUEZ PENAL.', 'EL FISCAL DEFINE LA OPERATIVA Y LA POLICÍA LA JURÍDICA.', 'AMBAS ESTRATEGIAS NO REQUIEREN COORDINACIÓN.', NULL, 'b', 'LA ESTRATEGIA JURÍDICA ES COMPETENCIA DEL FISCAL Y LA OPERATIVA DE LA POLICÍA, PERO DEBEN SER', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184870'),
(2682, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA INVESTIGACIÓN DEL DELITO CONFORME AL ARTÍCULO 65, ¿QUÉ DEBE HACER EL FISCAL RESPECTO A LAS DILIGENCIAS PRACTICADAS POR LA POLICÍA NACIONAL DEL PERÚ?:', 'REGISTRAR EN AUDIO Y VIDEO TODAS LAS DILIGENCIAS.', 'REALIZAR LAS FORMALIDADES ESPECIFICAS QUE DEBEN REUNIR LOS ACTOS DE INVESTIGACION PARA GARANTIZAR SU', 'NO INTERVENIR BAJO NINGUNA CIRCUNSTANCIA.', 'SOLICITAR LA APROBACIÓN DE LA CORTE SUPREMA ANTES DE CADA DILIGENCIA.', 'ADMINISTRAR LOS FONDOS PARA QUE SE REALICEN LAS DILIGENCIAS.', NULL, 'b', 'REALIZAR LAS FORMALIDADES ESPECIFICAS QUE DEBEN REUNIR LOS ACTOS DE INVESTIGACION PARA', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184871'),
(2683, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'UNA DE LAS OBLIGACIONES DEL FISCAL AL INICIAR UNA INVESTIGACIÓN PRELIMINAR, SEGÚN EL ARTÍCULO 65, ES:', 'EMITIR SENTENCIA EN UN PLAZO NO MAYOR DE 48 HORAS.', 'PRECISAR EL OBJETO Y LOS PLAZOS DE LA INVESTIGACIÓN.', 'SOLICITAR LA DETENCIÓN DEL IMPUTADO SIN MAYOR ANÁLISIS.', 'NOMBRAR INMEDIATAMENTE UNA COMISIÓN INVESTIGADORA DEL CONGRESO.', 'IMPONER MEDIDAS DISCIPLINARIAS A LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'b', 'PRECISAR EL OBJETO Y LOS PLAZOS DE LA INVESTIGACIÓN.', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184872'),
(2684, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA GARANTÍA DE LOS DERECHOS FUNDAMENTALES DEL IMPUTADO DURANTE LA INVESTIGACIÓN, EL ARTÍCULO 65 ESTABLECE QUE:', 'ES UNA FACULTAD EXCLUSIVA DEL FISCAL.', 'ES RESPONSABILIDAD DEL FISCAL Y LA POLICÍA NACIONAL DEL PERÚ.', 'CORRESPONDE ÚNICAMENTE AL PODER JUDICIAL.', 'ES COMPETENCIA DE LA DEFENSORÍA DEL PUEBLO.', 'QUEDA A CRITERIO DEL MINISTERIO DEL INTERIOR EXCLUSIVAMENTE.', NULL, 'b', 'ES RESPONSABILIDAD DEL FISCAL Y LA POLICÍA NACIONAL DEL PERÚ.', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184873'),
(2685, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'PARA LA INVESTIGACION DEL DELITO, CORRESPONDE LA ESTRASTEGIA JURIDICA Y OPERATIVA, PARA TAL FIN PROGRAMAN EL EMPLEO DE PAUTAS, TÉCNICAS Y MEDIOS DE INVESTIGACIÓN, EL ARTÍCULO 65 ESTABLECE QUE:', 'EL FISCAL PUEDE UTILIZAR CUALQUIER MEDIO SIN COORDINACIÓN CON LA POLICÍA.', 'DEBEN PROGRAMARSE Y COORDINARSE DE MANERA CONJUNTA ENTRE EL FISCAL Y LA POLICÍA NACIONAL DEL PERÚ.', 'SOLAMENTE LA POLICÍA DECIDE QUÉ MEDIOS UTILIZAR SIN CONSULTAR A NADIE.', 'SOLO PUEDEN USARSE LOS MEDIOS DEFINIDOS POR LA PROCURADURÍA PÚBLICA.', 'LA UTILIZACIÓN DE MEDIOS QUEDA RESTRINGIDA A LOS CASOS DE FLAGRANCIA.', NULL, 'b', 'DEBEN PROGRAMARSE Y COORDINARSE DE MANERA CONJUNTA ENTRE EL FISCAL Y LA POLICÍA NACIONAL', '(texto: (ART: UNICO)** Articulo 65. La investigacion del delito destinada a ejercitar la accion penal)**', '184875'),
(2686, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA CONDICIÓN ESENCIAL PARA QUE LA POLICÍA NACIONAL DEL PERÚ PUEDA RECIBIR LA MANIFESTACIÓN DE LOS PRESUNTOS AUTORES O PARTÍCIPES DE UN DELITO DURANTE LA INVESTIGACIÓN?:', 'DEBE CONTAR CON UNA ORDEN JUDICIAL EXPRESA PARA CADA DECLARACIÓN.', 'ES OBLIGATORIA LA PRESENCIA FÍSICA DEL FISCAL EN TODOS LOS CASOS.', 'LA MANIFESTACIÓN SOLO PUEDE RECIBIRSE SI EL MINISTERIO PÚBLICO AUTORIZA PREVIAMENTE MEDIANTE RESOLUCIÓN', 'OBLIGATORIEDAD DE LA PRESENCIA DEL ABOGADO DEFENSOR DE ELECCIÓN DEL INVESTIGADO, O DEL DEFENSOR', 'SOLO SE PUEDE RECIBIR MANIFESTACIÓN SI EL INVESTIGADO RENUNCIA EXPRESAMENTE A SU DERECHO AL SILENCIO EN', NULL, 'd', 'OBLIGATORIEDAD DE LA PRESENCIA DEL ABOGADO DEFENSOR DE ELECCIÓN DEL INVESTIGADO, O DEL', '(texto: (ART: UNICO)** Articulo 68. Función de investigación de la Policía Nacional del Perú)**', '184876'),
(2687, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL REGISTRO DE LAS MANIFESTACIONES DE LOS PRESUNTOS AUTORES O PARTÍCIPES POR LA POLICÍA NACIONAL DEL PERÚ, SEGÚN LA NORMA ANALIZADA, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA?:', 'EL REGISTRO EN DISPOSITIVOS O EQUIPOS AUDIOVISUALES ES OPCIONAL Y DEPENDE DE LA COMPLEJIDAD DEL CASO.', 'LA MANIFESTACIÓN DEBE NECESARIAMENTE CONSTAR EN ACTA ESCRITA POR LA POLICÍA NACIONAL SIN MEDIOS', 'SIEMPRE DEBE INTERVENIR PRESENCIALMENTE EL FISCAL TITULAR PARA DAR VALIDEZ A LA DILIGENCIA.', 'EL REGISTRO DE LAS DECLARACIONES DEBE REALIZARSE EN DISPOSITIVOS O EQUIPOS AUDIOVISUALES.', 'LAS MANIFESTACIONES SÓLO TIENEN VALOR PROBATORIO SI FUERON GRABADAS EN PRESENCIA DEL JUEZ DE', NULL, 'd', 'EL REGISTRO DE LAS DECLARACIONES DEBE REALIZARSE EN DISPOSITIVOS O EQUIPOS AUDIOVISUALES.', '(texto: (ART: UNICO)** Articulo 67. Funcion de investigacion de la Policia Nacional del Peru)**', '184877'),
(2688, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 68 MODIFICADO, ¿CÓMO DEBE PROCEDERSE EN CASO EL FISCAL TENGA CONOCIMIENTO DE LA DILIGENCIA POLICIAL DE MANIFESTACIÓN PERO NO PUEDA ASISTIR PRESENCIALMENTE?:', 'EL FISCAL PUEDE DELEGAR SU PARTICIPACIÓN A CUALQUIER POLICÍA DE MAYOR RANGO.', 'LA DILIGENCIA DEBE SUSPENDERSE HASTA QUE EL FISCAL PUEDA ESTAR PRESENTE FÍSICAMENTE.', 'EL FISCAL PUEDE PARTICIPAR DE MANERA VIRTUAL, DEBIÉNDOSE DEJAR CONSTANCIA DE SU PARTICIPACIÓN.', 'LA DECLARATORIA QUEDA AUTOMÁTICAMENTE INVALIDADA POR AUSENCIA DEL FISCAL.', 'LA MANIFESTACIÓN DEBE POSTERGARSE HASTA QUE SE NOTIFIQUE FORMALMENTE AL DEFENSOR PÚBLICO.', NULL, 'c', 'EL FISCAL PUEDE PARTICIPAR DE MANERA VIRTUAL, DEBIÉNDOSE DEJAR CONSTANCIA DE SU PARTICIPACIÓN.', '(texto: (ART: UNICO)** Articulo 68. Funcion de investigacion de la Policia Nacional del Peru)**', '184878'),
(2689, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE TODAS LAS DILIGENCIAS DE INVESTIGACIÓN REALIZADAS POR LA POLICÍA NACIONAL DEL PERÚ BAJO CONDUCCIÓN FISCAL, ¿QUE DOCUMENTOS FORMULARAN RESPETANDO LAS FORMALIDADES PREVISTAS PARA LA INVESTIGACION?:', 'SÓLO DEBEN ENVIARSE RESÚMENES EJECUTIVOS AL FISCAL.', 'LAS ACTAS DETALLADAS LAS QUE ENTREGARA AL FISCAL Y EMITIRA EL INFORME POLICIAL.', 'LAS ACTAS SÓLO SON REQUERIDAS CUANDO SE TRATA DE DELITOS GRAVES O COMPLEJOS, NO EN DELITOS SIMPLES.', 'LAS ACTAS E INFORMES DEBEN REMITIRSE EXCLUSIVAMENTE AL JUEZ DE INVESTIGACIÓN PREPARATORIA.', 'ELABORAR ACTAS DETALLADAS ES OPTATIVO, DEPENDIENDO DEL CRITERIO DEL COMISARIO RESPONSABLE.', NULL, 'b', 'LAS ACTAS DETALLADAS LAS QUE ENTREGARA AL FISCAL Y EMITIRA EL INFORME POLICIAL.', '(texto: (ART: UNICO)** Articulo 68. Funcion de investigacion de la Policia Nacional del Peru)**', '184879'),
(2690, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL DESTINO OBLIGATORIO DE LAS ACTAS DETALLADAS DE LAS DILIGENCIAS ESPECÍFICAS REALIZADAS POR LA POLICÍA NACIONAL DEL PERÚ, SEGÚN LA LEY MODIFICADA?:', 'DEBEN SER REMITIDAS AL MINISTERIO DEL INTERIOR PARA CONSTANCIA INTERNA.', 'SE CONSERVAN EN LA COMISARÍA HASTA FINALIZADO EL JUICIO ORAL.', 'SE ENTREGAN AL FISCAL A CARGO Y SE EMITE INFORME POLICIAL CORRESPONDIENTE.', 'SON ENTREGADAS ÚNICAMENTE AL ÓRGANO JURISDICCIONAL PENAL.', 'SE PUBLICAN EN EL PORTAL DE TRANSPARENCIA POLICIAL PARA CONTROL CIUDADANO.', NULL, 'c', 'SE ENTREGAN AL FISCAL A CARGO Y SE EMITE INFORME POLICIAL CORRESPONDIENTE.', '(texto: (ART: UNICO)** Articulo 67. Funcion de investigacion de la Policia Nacional del Peru)**', '184882'),
(2691, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA MODIFICACIÓN INTRODUCIDA EN EL CÓDIGO PROCESAL PENAL, ¿QUÉ SUCEDE SI EL DECLARANTE NO CUENTA CON ABOGADO DEFENSOR DE ELECCIÓN O DEFENSOR PÚBLICO EN SU MANIFESTACIÓN ANTE LA POLICÍA NACIONAL DEL PERÚ?:', 'SE SUSPENDE LA DILIGENCIA Y SE REPROGRAMA.', 'EL ACTO PUEDE SER SUBSANADO SI EL FISCAL RATIFICA LA ACTUACIÓN POLICIAL A POSTERIORI.', 'LA MANIFESTACIÓN ES VÁLIDA SIEMPRE QUE SEA VOLUNTARIA, AUN SIN DEFENSA TÉCNICA.', 'EL DEFECTO SOLO AFECTA EL VALOR PROBATORIO Y NO LA EXISTENCIA DE LA MANIFESTACIÓN.', 'LA ACTUACIÓN POLICIAL QUEDA SUSPENDIDA AUTOMÁTICAMENTE Y DEBE INFORMARSE AL JUEZ.', NULL, 'a', 'SE SUSPENDE LA DILIGENCIA Y SE REPROGRAMA.', '(texto: (ART: UNICO)** Articulo 68. Funcion de investigacion de la Policia Nacional del Peru)**', '184883'),
(2692, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 84 DEL CÓDIGO PROCESAL PENAL, MODIFICADO POR LA LEY 32130, RESPECTO AL ACCESO DEL ABOGADO DEFENSOR A LA INFORMACIÓN DEL PROCESO, SEÑALE LA RESPUESTA CORRECTA:', 'EL ABOGADO DEFENSOR PUEDE ACCEDER SOLO A LOS DOCUMENTOS DEL ÁMBITO JUDICIAL DESPUÉS DE LA ETAPA DE', 'EL DERECHO DEL ABOGADO DEFENSOR A ACCEDER A LOS DOCUMENTOS ESTÁ RESTRINGIDO ÚNICAMENTE A LAS ETAPAS', 'EL ACCESO A LOS DOCUMENTOS POR PARTE DEL ABOGADO DEFENSOR DEPENDE DE LA AUTORIZACIÓN EXPRESA DEL', 'EL ABOGADO DEFENSOR TIENE DERECHO A ACCEDER A LOS DOCUMENTOS DE ÁMBITO POLICIAL, FISCAL Y JUDICIAL EN', 'EL ABOGADO DEFENSOR PUEDE SOLICITAR LA RESTRICCIÓN DE SU PROPIO ACCESO A LOS DOCUMENTOS COMO', NULL, 'd', 'EL ABOGADO DEFENSOR TIENE DERECHO A ACCEDER A LOS DOCUMENTOS DE ÁMBITO POLICIAL, FISCAL Y', '(texto: (ART: UNICO)** Articulo 84. Derechos y deberes del abogado defensor)**', '184884'),
(2693, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN CUANTO A LA OBTENCIÓN DE COPIAS SIMPLES DE LAS ACTUACIONES PROCESALES, CONFORME AL ARTÍCULO 84 MODIFICADO POR LA LEY 32130, ¿QUÉ DISPOSICIÓN SE APLICA AL ABOGADO DEFENSOR?', 'SOLO PUEDE OBTENER COPIAS SIMPLES DURANTE LA FASE DE INVESTIGACIÓN POLICIAL, NUNCA DURANTE LA FASE', 'ESTÁ FACULTADO A OBTENER COPIAS SIMPLES DE LAS ACTUACIONES ÚNICAMENTE CON AUTORIZACIÓN JUDICIAL', 'EL DERECHO DEL ABOGADO DEFENSOR A OBTENER COPIAS SIMPLES DE LAS ACTUACIONES ES PROCEDENTE EN', 'NO PUEDE ACCEDER A COPIAS SIMPLES SI SE TRATA DE DOCUMENTACIÓN FISCAL CLASIFICADA COMO RESERVADA,', 'PUEDE ACCEDER A COPIAS SIMPLES SOLO SI EL CASO SE ENCUENTRA EN INSTANCIA DE APELACIÓN Y PRESENTA UNA', NULL, 'c', 'EL DERECHO DEL ABOGADO DEFENSOR A OBTENER COPIAS SIMPLES DE LAS ACTUACIONES ES PROCEDENTE', '(texto: (ART: UNICO)** Articulo 84. Derechos y deberes del abogado defensor)**', '184885'),
(2694, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO CON EL ARTÍCULO 84 DEL CÓDIGO PROCESAL PENAL, TRAS LA REFORMA INTRODUCIDA POR LA LEY 32130, ¿CUÁL SERÍA EL LÍMITE AL DERECHO DEL ABOGADO DEFENSOR A ACCEDER A LA INFORMACIÓN DEL PROCESO?', 'LA ESTABLECIDA POR LA PROPIA LEY.', 'EL LÍMITE ES LA DISCRECIONALIDAD QUE TENGA EL JUEZ DEL CASO, QUIEN PUEDE IMPEDIR EL EJERCICIO DEL DERECHO', 'SOLO PUEDE ACCEDER A LA INFORMACIÓN SI LA PARTE AGRAVIADA LO AUTORIZA EXPRESAMENTE.', 'EL MINISTERIO PÚBLICO PUEDE IMPEDIR EL ACCESO DEL ABOGADO DEFENSOR EN CUALQUIER MOMENTO POR RAZONES', 'NO EXISTE LÍMITE ALGUNO, EL ABOGADO DEFENSOR PUEDE ACCEDER ABSOLUTAMENTE A TODOS LOS DOCUMENTOS SIN', NULL, 'a', 'LA ESTABLECIDA POR LA PROPIA LEY.', '(texto: (ART: UNICO)** Articulo 84. Derechos y deberes del abogado defensor)**', '184886'),
(2695, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA MODIFICACIÓN DEL ARTÍCULO 160 DEL CÓDIGO PROCESAL PENAL INTRODUCIDA POR LA LEY 32130 (ARTÍCULO ÚNICO), ¿EN CUÁL DE LAS SIGUIENTES SITUACIONES LA CONFESIÓN DE UN IMPUTADO TIENE VALOR PROBATORIO EN EL PROCESO PENAL?:', 'CUANDO EL IMPUTADO CONFIESA ANTE EL FISCAL O JUEZ, CON PRESENCIA DE SU ABOGADO DEFENSOR, Y DICHA', 'CUANDO EL IMPUTADO CONFIESA ANTE LA POLICÍA NACIONAL DURANTE LA INVESTIGACIÓN PRELIMINAR, SIN NECESIDAD', 'CUANDO LA CONFESIÓN ES PRESTADA ANTE CUALQUIER SERVIDOR PÚBLICO Y EN CUALQUIER ETAPA DEL PROCESO,', 'CUANDO EL IMPUTADO FIRMA UN ACTA DE CONFESIÓN EXTRAJUDICIAL, AUNQUE NO HAYA REGISTRO AUDIOVISUAL NI', 'CUANDO LA CONFESIÓN ES OBTENIDA MEDIANTE ACTA POLICIAL EN CUALQUIER ETAPA DEL PROCESO Y NO SE ALEGUE', NULL, 'a', 'CUANDO EL IMPUTADO CONFIESA ANTE EL FISCAL O JUEZ, CON PRESENCIA DE SU ABOGADO DEFENSOR, Y', '(texto: (ART: UNICO)**Articulo 160. Valor de prueba de la confesion)**', '184887'),
(2696, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN VIRTUD DE LA REDACCIÓN ACTUAL DEL ARTÍCULO 160 DEL CÓDIGO PROCESAL PENAL, TRAS LA ENTRADA EN VIGENCIA DE LA LEY 32130, ¿CUÁL SERÍA EL EFECTO PROBATORIO DE UNA CONFESIÓN OBTENIDA POR LA POLICÍA NACIONAL EN ETAPA DE INVESTIGACIÓN PRELIMINAR SIN LA PRESENCIA DEL ABOGADO DEFENSOR, AUNQUE ESTUVIERA GRABADA POR EQUIPOS AUDIOVISUALES?:', 'SERÍA VÁLIDA SI EL IMPUTADO RATIFICA LA CONFESIÓN ANTE EL JUEZ DURANTE LA ETAPA INTERMEDIA, CON ABOGADO', 'CARECERÍA DE VALOR PROBATORIO POR OMITIR LA PRESENCIA DEL ABOGADO DEFENSOR, AÚN EXISTIENDO REGISTRO', 'TENDRÍA VALOR PROBATORIO ÚNICAMENTE RESPECTO A LOS ASPECTOS MATERIALES DE LA IMPUTACIÓN, PERO NO A LA', 'PODRÍA SER UTILIZADA DE MANERA OFICIOSA POR EL MINISTERIO PÚBLICO PARA SOLICITAR DETENCIÓN PREVENTIVA,', 'SERÍA VÁLIDA SI LA DEFENSA CONSIENTE EXPRESAMENTE LA UTILIZACIÓN DE LA CONFESIÓN EN LA ETAPA DE JUICIO', NULL, 'b', 'CARECERÍA DE VALOR PROBATORIO POR OMITIR LA PRESENCIA DEL ABOGADO DEFENSOR, AÚN EXISTIENDO', '(texto: (ART: UNICO)**Articulo 160. Valor de prueba de la confesion)**', '184888'),
(2697, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 173 MODIFICADO POR LA LEY 32130, ¿CUÁL ES LA ENTIDAD QUE, DE MANERA PRIORITARIA Y SIN NECESIDAD DE DESIGNACIÓN EXPRESA, TIENE A SU CARGO LA REALIZACIÓN DE EXÁMENES O PERICIAS CRIMINALÍSTICAS EN TODA INVESTIGACIÓN PENAL?:', 'EL MINISTERIO PÚBLICO.', 'LA DIRECCIÓN DE CRIMINALÍSTICA DE LA POLICÍA NACIONAL DEL PERÚ O SUS OFICINAS DESCENTRALIZADAS.', 'LAS UNIVERSIDADES AUTORIZADAS POR EL ESTADO.', 'EL PODER JUDICIAL.', 'EL INSTITUTO DE MEDICINA LEGAL Y CIENCIAS FORENSES.', NULL, 'b', 'LA DIRECCIÓN DE CRIMINALÍSTICA DE LA POLICÍA NACIONAL DEL PERÚ O SUS OFICINAS DESCENTRALIZADAS.', '(texto: (ART: UNICO)**Articulo 173. Nombramiento)**', '184889'),
(2698, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿EN QUÉ CIRCUNSTANCIA SE PUEDE ENCOMENDAR LA PERICIA CRIMINALÍSTICA OFICIAL A ENTIDADES DISTINTAS A LA DIRECCIÓN DE CRIMINALÍSTICA DE LA PNP SEGÚN LA NORMATIVA REFERIDA?:', 'CUANDO LOS INVESTIGADOS ASÍ LO SOLICITEN EXPRESAMENTE Y EXISTA JUSTIFICACIÓN RAZONABLE.', 'EN EL CASO DE QUE LA DIRECCIÓN DE CRIMINALÍSTICA DE LA PNP CAREZCA DE PERITOS O DE MATERIAL DE', 'POR DECISIÓN DISCRECIONAL DEL JUEZ DE INVESTIGACIÓN PREPARATORIA.', 'ÚNICAMENTE CUANDO EL MINISTERIO PÚBLICO DETERMINE LA IMPARCIALIDAD DE LAS ENTIDADES POLICIALES.', 'SIEMPRE QUE LA PERICIA SE REALICE EN EL EXTRANJERO.', NULL, 'b', 'EN EL CASO DE QUE LA DIRECCIÓN DE CRIMINALÍSTICA DE LA PNP CAREZCA DE PERITOS O DE MATERIAL DE', '(texto: (ART: UNICO)**Articulo 173. Nombramiento)**', '184890'),
(2699, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿ES CORRECTO AFIRMAR QUE LA LABOR PERICIAL PUEDE SER ENCOMENDADA A ORGANISMOS DEL ESTADO QUE DESARROLLAN LABOR CIENTÍFICA O TÉCNICA, Y BAJO QUÉ CONDICIÓN PRINCIPAL SEGÚN EL ARTÍCULO 173?:', 'SÍ, PERO SOLO CUANDO EXISTAN CONVENIOS INTERNACIONALES QUE LO PERMITAN.', 'NO, PORQUE LA LABOR PERICIAL ES FUNCIÓN EXCLUSIVA DEL MINISTERIO PÚBLICO.', 'SÍ, SIEMPRE QUE REUNAN LAS CUALIDADES NECESARIAS PARA TAL FIN, CON CONOCIMIENTO DE LAS PARTES.', 'NO, LA LABOR SOLO PUEDE ENCARGARLA LA DIRECCIÓN DE CRIMINALÍSTICA DE LA PNP.', 'SÍ, PERO ÚNICAMENTE SI EL ÓRGANO TIENE PERITOS CERTIFICADOS INTERNACIONALMENTE.', NULL, 'c', 'SÍ, SIEMPRE QUE REUNAN LAS CUALIDADES NECESARIAS PARA TAL FIN, CON CONOCIMIENTO DE LAS PARTES.', '(texto: (ART: UNICO)**Articulo 173. Nombramiento)**', '184891'),
(2700, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 173, ¿QUÉ CARACTERÍSTICA DESCRIBE LA PRESTACIÓN DEL AUXILIO PERICIAL POR PARTE DE LAS ENTIDADES ESTATALES CIENTÍFICAS O TÉCNICAS?', 'ES REMUNERADA SEGÚN ARANCEL ESTABLECIDO.', 'ES GRATUITA, CONFORME AL MANDATO LEGAL.', 'ES SUJETA A COSTOS DETERMINADOS POR LA POLICÍA NACIONAL.', 'IMPLICA UN REINTEGRO ECONÓMICO POSTERIOR A LA SENTENCIA.', 'ES ASUMIDA EXCLUSIVAMENTE POR LA PARTE INTERESADA EN LA PERICIA.', NULL, 'b', 'ES GRATUITA, CONFORME AL MANDATO LEGAL.', '(texto: (ART: UNICO)**Articulo 173. Nombramiento)**', '184893'),
(2701, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 180 MODIFICADO DEL CÓDIGO PROCESAL PENAL, ¿CUÁNDO PUEDEN LAS PARTES PRESENTAR OBSERVACIONES AL INFORME PERICIAL OFICIAL, Y BAJO QUÉ PRINCIPIO SE FUNDAMENTA ESTE DERECHO PROCESAL?', 'SOLAMENTE UNA VEZ EMITIDO EL INFORME PERICIAL OFICIAL POR UN ÚNICO PERITO Y ANTES QUE SEA REMITIDO AL', 'EN UN PLAZO IGUAL AL OTORGADO AL PERITO OFICIAL, DESPUÉS DE LA COMUNICACIÓN A LAS PARTES JUNTO CON COPIA', 'EN CUALQUIER MOMENTO DEL PROCEDIMIENTO PENAL MEDIANTE UNA SOLICITUD MOTIVADA, SIN NECESIDAD DE', 'ÚNICAMENTE AL FINALIZAR EL JUICIO ORAL Y BAJO EL PRINCIPIO DE CONTRADICCIÓN DE LA PRUEBA.', 'LAS OBSERVACIONES SÓLO PUEDEN FORMULARSE SI EXISTEN MÁS DE DOS PERITOS Y ESTOS HAN PRESENTADO', NULL, 'b', 'EN UN PLAZO IGUAL AL OTORGADO AL PERITO OFICIAL, DESPUÉS DE LA COMUNICACIÓN A LAS PARTES JUNTO', '(texto: (ART: UNICO)**Articulo 180. Reglas adicionales)**', '184894'),
(2702, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA PRESENTACIÓN DEL INFORME PERICIAL OFICIAL SEGÚN LA LEY 32130, ¿CUÁL ES EL MECANISMO PREVISTO CUANDO EXISTEN VARIOS PERITOS OFICIALES, PERO ENTRE ELLOS NO EXISTE UNANIMIDAD EN SUS CONCLUSIONES?:', 'EL INFORME PERICIAL ES ELABORADO SOLO POR EL PERITO MÁS ANTIGUO EN EL CARGO, DESCARTANDO LAS OPINIONES', 'SE RECHAZAN LOS INFORMES INDIVIDUALES DISCREPANTES Y SE SOLICITA UN NUEVO INFORME CONJUNTO A TODOS LOS', 'CADA PERITO OFICIAL QUE DISCREPE DEBE PRESENTAR SU PROPIO INFORME PERICIAL.', 'EL JUEZ DETERMINA DE OFICIO CUÁL OPINIÓN PREVALECE SIN NECESIDAD DE NUEVOS INFORMES ADICIONALES.', 'LOS PERITOS DEBEN CONSENSUAR OBLIGATORIAMENTE UN ÚNICO INFORME ANTES DE SU PRESENTACIÓN, BAJO', NULL, 'c', 'CADA PERITO OFICIAL QUE DISCREPE DEBE PRESENTAR SU PROPIO INFORME PERICIAL.', '(texto: (ART: UNICO)**Articulo 180. Reglas adicionales)**', '184895'),
(2703, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA CONDICIÓN ESENCIAL PARA QUE LA POLICÍA NACIONAL DEL PERÚ PUEDA REQUERIR LA IDENTIFICACIÓN DE UNA PERSONA EN LA VÍA PÚBLICA SIN ORDEN JUDICIAL NI FISCAL SEGÚN EL ARTÍCULO 205 MODIFICADO POR LA LEY 32130?:', 'QUE EXISTAN ANTECEDENTES POLICIALES PREVIOS DEL INTERVENIDO.', 'QUE LA SITUACIÓN SE DÉ EN CUALQUIER HORA DEL DÍA SIN DISTINGUIR CONTEXTO ALGUNO.', 'QUE LA POLICÍA CONSIDERE NECESARIO PREVENIR UN DELITO U OBTENER INFORMACIÓN ÚTIL PARA LA AVERIGUACIÓN', 'QUE EXISTA FLAGRANCIA DELICTIVA POR PARTE DEL INTERVENIDO.', 'QUE SEA AUTORIZADO EXPRESAMENTE POR UN SUPERIOR JERÁRQUICO POLICIAL.', NULL, 'c', 'QUE LA POLICÍA CONSIDERE NECESARIO PREVENIR UN DELITO U OBTENER INFORMACIÓN ÚTIL PARA LA', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184896'),
(2704, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN RELACIÓN A LA INTERVENCIÓN POLICIAL REGULADA POR EL ARTÍCULO 205, ¿QUÉ DERECHO LE ASISTE AL CIUDADANO INTERVENIDO POR CONTROL DE IDENTIDAD?:', 'EXIGIR QUE LA INTERVENCIÓN SE REALICE FRENTE AL MINISTERIO PÚBLICO.', 'SOLICITAR LA IDENTIDAD DEL POLICÍA, LA DEPENDENCIA ASIGNADA Y SER INFORMADO QUE LA INTERVENCIÓN PUEDE SER', 'ELEGIR EL LUGAR DONDE SE LE TOMA LA DECLARACIÓN.', 'NEGARSE A MOSTRAR DOCUMENTOS DE IDENTIDAD BAJO CUALQUIER CIRCUNSTANCIA.', 'REQUERIR LA PRESENCIA DE UN ABOGADO PARA LA IDENTIFICACIÓN PRIMARIA.', NULL, 'b', 'SOLICITAR LA IDENTIDAD DEL POLICÍA, LA DEPENDENCIA ASIGNADA Y SER INFORMADO QUE LA INTERVENCIÓN', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184897'),
(2705, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ACTUACIÓN POLICIAL ADICIONAL ACTIVA LA OBLIGACIÓN DE LEVANTAR ACTA Y COMUNICACIÓN INMEDIATA Y POR ESCRITO AL MINISTERIO PÚBLICO SEGÚN EL ARTÍCULO 205 MODIFICADO?:', 'SOLICITAR LA IDENTIFICACIÓN DE UNA PERSONA SIN CONSENTIMIENTO.', 'REGISTRAR LAS VESTIMENTAS, EQUIPAJE O VEHÍCULO ANTE UN FUNDADO MOTIVO QUE EL INTERVENIDO PUEDA ESTAR', 'TOMAR DECLARACIÓN TESTIMONIAL AL INTERVENIDO EN EL ACTO.', 'REALIZAR UN REGISTRO PERSONAL POR MOTIVOS PREVENTIVOS.', 'PEDIR ANTECEDENTES POLICIALES A LA PERSONA ANTES DE SOLICITAR SU DNI.', NULL, 'b', 'REGISTRAR LAS VESTIMENTAS, EQUIPAJE O VEHÍCULO ANTE UN FUNDADO MOTIVO QUE EL INTERVENIDO', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184898'),
(2706, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA TOMA DE FOTOGRAFÍAS DEL IMPUTADO EN EL CONTROL DE IDENTIDAD, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA CONFORME AL ARTÍCULO 205 REFORMADO?:', 'LAS FOTOGRAFÍAS SOLO PUEDEN TOMARSE CON EL CONSENTIMIENTO EXPRESO DEL IMPUTADO.', 'LAS FOTOGRAFIAS PUEDEN SER TOMADA CONTRA LA VOLUNTAD DEL IMPUTADO, DEBIENDO LEVANTARSE UN ACTA Y', 'LA POLICÍA DEBE PEDIR AUTORIZACIÓN AL JUEZ PARA CADA FOTOGRAFÍA TOMADA EN VÍA PÚBLICA.', 'DEBERÁN TOMARSE ÚNICAMENTE SI EL IMPUTADO ESTÁ DETENIDO EN FLAGRANCIA.', 'ES EXCLUSIVO PARA CIUDADANOS EXTRANJEROS SIN IDENTIFICACIÓN NACIONAL.', NULL, 'b', 'LAS FOTOGRAFIAS PUEDEN SER TOMADA CONTRA LA VOLUNTAD DEL IMPUTADO, DEBIENDO LEVANTARSE UN', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184899'),
(2707, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES FUNCIONES NO SE ENCUENTRA EXPRESAMENTE HABILITADA EN EL ARTÍCULO 205, BAJO LA COMPETENCIA POLICIAL VINCULADA AL CONTROL DE IDENTIDAD?:', 'REGISTRAR EQUIPAJE MEDIANTE FUNDADO MOTIVO.', 'LEVANTAR UN ACTA SI EL REGISTRO RESULTA POSITIVO.', 'FACULTAR AL POLICÍA A IDENTIFICAR Y A INFORMAR SU DEPENDENCIA.', 'EMITIR CITACIONES JUDICIALES EN EL ACTO DE INTERVENCIÓN.', 'REGISTRAR EN AUDIO O VIDEO EL MOMENTO DE LA INTERVENCIÓN.', NULL, 'd', 'EMITIR CITACIONES JUDICIALES EN EL ACTO DE INTERVENCIÓN.', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184900'),
(2708, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA ÚLTIMA REFORMA, ¿CUÁL ES LA CONSECUENCIA JURÍDICA SI LA INTERVENCIÓN POLICIAL EN EL CONTROL DE IDENTIDAD CULMINA CON UN HALLAZGO POSITIVO DURANTE EL REGISTRO?:', 'SE INICIA PROCESO JUDICIAL AUTOMÁTICO.', 'EL POLICÍA DEBE LEVANTAR UN ACTA, DESCRIBIR LO ENCONTRADO Y COMUNICAR INMEDIATAMENTE AL MINISTERIO', 'SE TRASLADA INMEDIATAMENTE AL INTERVENIDO A LA COMISARÍA SIN EXCEPCIÓN.', 'DEBE SOLICITAR PRESENCIA DE UN ABOGADO ANTES DE PROCEDER.', 'LA INTERVENCIÓN DEBE CESAR Y DEJAR EN LIBERTAD AL CIUDADANO INTERVENIDO.', NULL, 'b', 'EL POLICÍA DEBE LEVANTAR UN ACTA, DESCRIBIR LO ENCONTRADO Y COMUNICAR INMEDIATAMENTE AL', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184901'),
(2709, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿EN QUÉ CASOS ESTÁ AUTORIZADA LA TOMA DE FOTOGRAFIAS DEL IMPUTADO, SIN PERJUICIO DE SUS IMPRESIONES DIGITALES INCLUSO CONTRA DE SU VOLUNTAD, SEGÚN EL ARTÍCULO 205 MODIFICADO?:', 'ÚNICAMENTE CUANDO EL IMPUTADO ES REINCIDENTE.', 'SIEMPRE QUE SEA NECESARIO PARA LAS FINALIDADES DEL JUICIO O PARA LAS FINALIDADES DE IDENTIFICACION.', 'CUANDO ASÍ LO DISPONGA EL FISCAL EN CADA CASO CONCRETO.', 'SOLO SI EL IMPUTADO LO SOLICITA VOLUNTARIAMENTE.', 'EN NINGÚN CASO SIN PREVIA AUTORIZACIÓN DE UN JUEZ DEL CONTROL DE GARANTÍAS.', NULL, 'b', 'SIEMPRE QUE SEA NECESARIO PARA LAS FINALIDADES DEL JUICIO O PARA LAS FINALIDADES DE', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184902'),
(2710, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL TIEMPO LIMITE PARA LA COMUNICACIÓN AL MINISTERIO PÚBLICO, CUANDO SE REALICE EL REGISTRO PERSONAL, DE EQUIPAJE O VEHÍCULO CON RESULTADO POSITIVO DURANTE EL CONTROL DE IDENTIDAD POLICIAL?:', 'DENTRO DE LAS 48 HORAS SIGUIENTES AL HALLAZGO.', 'EN CUALQUIER MOMENTO PREVIO A LA AUDIENCIA DE CONTROL DE IDENTIDAD.', 'DE MANERA INMEDIATA Y POR ESCRITO CONFORME LO ESTABLECE EL ARTÍCULO 205 MODIFICADO.', 'SOLO DESPUÉS DE QUE EL INTERVENIDO DECLARE ANTE EL FISCAL DE TURNO.', 'NO EXISTE OBLIGACIÓN EXPRESA DE COMUNICARLO AL MINISTERIO PÚBLICO.', NULL, 'c', 'DE MANERA INMEDIATA Y POR ESCRITO CONFORME LO ESTABLECE EL ARTÍCULO 205 MODIFICADO.', '(texto: (ART: UNICO)**Articulo 205. Control de identidad policial)**', '184903'),
(2711, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LOS SIGUIENTES ELEMENTOS DEBE CONSIGNAR OBLIGATORIAMENTE EL REQUERIMIENTO FISCAL Y, EN SU CASO, LA RESOLUCIÓN JUDICIAL QUE AUTORIZA LA INTERVENCIÓN, GRABACIÓN O REGISTRO DE COMUNICACIONES, SEGÚN EL ARTÍCULO 230 DEL D.LEG. 957 MODIFICADO POR LA LEY 32130?:', 'LA AMISTAD PREVIA ENTRE EL AFECTADO Y EL FISCAL INTERVINIENTE.', 'LA IDENTIDAD DEL TELÉFONO O MEDIO DE COMUNICACIÓN A INTERVENIR, EL NOMBRE Y DIRECCIÓN DEL AFECTADO SI SE', 'EL GRADO ACADÉMICO DE LOS POLICÍAS PARTICIPANTES EN LA DILIGENCIA.', 'EL CARGO POLÍTICO DE LA PERSONA AFECTADA.', 'EL TIPO DE RESIDENCIA FISCAL DE LA PERSONA INVESTIGADA EN EL EXTRANJERO.', NULL, 'b', 'LA IDENTIDAD DEL TELÉFONO O MEDIO DE COMUNICACIÓN A INTERVENIR, EL NOMBRE Y DIRECCIÓN DEL', '(texto: (ART: UNICO)** Articulo 230. Intervencion, grabacion o registro de comunicaciones telefonicas o de otras formas de', '184904'),
(2712, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL PLAZO DE INTERVENCIÓN DE LAS COMUNICACIONES SEGÚN EL ARTÍCULO 230 (MODIFICADO POR LA LEY 32130), ¿CUÁL ES LA DISPOSICIÓN EXACTA SOBRE LA DURACIÓN Y PRÓRROGA DE LA MEDIDA?:', 'LA INTERVENCIÓN PUEDE DURAR HASTA NOVENTA DÍAS Y SER PRORROGADA UNA VEZ MÁS POR IGUAL PLAZO SIN', 'LA INTERVENCIÓN NO TIENE UN PLAZO DEFINIDO Y PUEDE MANTENERSE VIGENTE HASTA QUE EL FISCAL LO CONSIDERE', 'EL PLAZO MÁXIMO ES DE SESENTA DÍAS, PRORROGABLE POR ÚNICA VEZ POR IGUAL PLAZO, PREVIA SUSTENTACIÓN', 'LA INTERVENCIÓN ÚNICAMENTE PUEDE DURAR QUINCE DÍAS, PRORROGABLE ILIMITADAMENTE CON AUTORIZACIÓN', 'LA INTERVENCIÓN PUEDE SER PRORROGADA CUANTAS VECES LO SOLICITE LA POLICÍA, MIENTRAS LO SUSTENTE', NULL, 'c', 'EL PLAZO MÁXIMO ES DE SESENTA DÍAS, PRORROGABLE POR ÚNICA VEZ POR IGUAL PLAZO, PREVIA', '(texto: (ART: UNICO)** Articulo 230. Intervencion, grabacion o registro de comunicaciones telefonicas o de otras formas de', '184905'),
(2713, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LOS SIGUIENTES MOTIVOS JUSTIFICARÍA LEGALMENTE QUE SE CONCEDA UNA PRÓRROGA A LA INTERVENCIÓN DE COMUNICACIONES, AUTORIZADA JUDICIALMENTE SEGÚN LA LEY 32130 Y EL ARTÍCULO 230 DEL D.LEG 957?:', 'LA SOLA CONCLUSIÓN DE QUE LOS RESULTADOS INICIALES FUERON INSUFICIENTES, SIN NUEVOS ELEMENTOS', 'LA EXISTENCIA DE NUEVOS APORTES Y SUFICIENTES ELEMENTOS PROBATORIOS QUE LA JUSTIFIQUEN.', 'EL DESEO DE AMPLIAR LA INVESTIGACIÓN PARA CUBRIR HECHOS FUTUROS DESCONOCIDOS.', 'LA PETICIÓN EXPRESA DE LA VÍCTIMA SIN VALORACIÓN DE MÉRITO DEL FISCAL.', 'LA REINCIDENCIA DEL INVESTIGADO EN LA COMISIÓN DE DELITOS NO VINCULADOS A LA INVESTIGACIÓN PRINCIPAL.', NULL, 'b', 'LA EXISTENCIA DE NUEVOS APORTES Y SUFICIENTES ELEMENTOS PROBATORIOS QUE LA JUSTIFIQUEN.', '(texto: (ART: UNICO)** Articulo 230. Intervencion, grabacion o registro de comunicaciones telefonicas o de otras formas de', '184906'),
(2714, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA MODIFICACIÓN INTRODUCIDA POR LA LEY 32130 AL ARTÍCULO 261 DEL CÓDIGO PROCESAL PENAL, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DEFINE CORRECTAMENTE LA VIGENCIA DE LA REQUISITORIA CURSADA A LA AUTORIDAD POLICIAL?:', 'LA REQUISITORIA TIENE UNA VIGENCIA INDEFINIDA HASTA QUE SE PRODUZCA LA DETENCIÓN DEL REQUISITORIADO,', 'LA REQUISITORIA MANTIENE SU VIGENCIA POR SEIS MESES, SALVO QUE FUESEN RENOVADAS.', 'LA REQUISITORIA CADUCA AUTOMÁTICAMENTE EN UN PLAZO DE 12 MESES SI NO ES RENOVADA, SALVO DISPOSICIÓN', 'LA REQUISITORIA SOLO CADUCA CUANDO EL JUEZ LO DISPONE MOTIVADAMENTE, SIN TENER EN CUENTA EL TIPO DE', 'LA REQUISITORIA ES VÁLIDA SOLO DURANTE LA INVESTIGACIÓN PREPARATORIA, LUEGO PIERDE EFECTO', NULL, 'b', 'LA REQUISITORIA MANTIENE SU VIGENCIA POR SEIS MESES, SALVO QUE FUESEN RENOVADAS.', '(texto: (ART: UNICO)** Articulo 261. Detencion Preliminar Judicial)**', '184907'),
(2715, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CONFORME AL ARTÍCULO 261 MODIFICADO POR LA LEY 32130, ¿EN CUÁL DE LOS SIGUIENTES SUPUESTOS LA REQUISITORIA NO CADUCA AUTOMÁTICAMENTE A LOS SEIS MESES Y SE MANTIENE VIGENTE HASTA LA EFECTIVA DETENCIÓN DEL REQUISITORIADO?:', 'DELITOS DE TERRORISMO Y DELITOS COMETIDOS POR ORGANIZACIONES CRIMINALES.', 'DELITOS DE LESIONES LEVES Y OMISIÓN A LA ASISTENCIA FAMILIAR.', 'DELITO DE CORRUPCIÓN DE FUNCIONARIOS COMETIDO POR SERVIDOR PÚBLICO.', 'DELITOS SANCIONADOS EN EL FUERO MILITAR POLICIAL DURANTE ESTADO DE EMERGENCIA.', 'DELITOS DE FALSIFICACIÓN DE DOCUMENTOS PÚBLICOS PARA GESTIÓN DE CONTRATOS ESTATALES.', NULL, 'a', 'DELITOS DE TERRORISMO Y DELITOS COMETIDOS POR ORGANIZACIONES CRIMINALES.', '(texto: (ART: UNICO)** Articulo 261. Detencion Preliminar Judicial)**', '184908'),
(2716, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA OBLIGACIÓN DEL JUEZ DE LA INVESTIGACIÓN PREPARATORIA RESPECTO A LA PRISIÓN PREVENTIVA O MEDIDAS DE COMPARECENCIA RESTRICTIVAS TRANSCURRIDOS SEIS MESES DESDE SU EJECUCIÓN O DESDE LA ÚLTIMA AUDIENCIA EN LA QUE SE HUBIERA DISCUTIDO LA CESACIÓN DE LA MEDIDA?:', 'DEBE DECLARAR AUTOMÁTICAMENTE LA LIBERTAD DEL IMPUTADO POR EL EXCESO DEL PLAZO.', 'DEBE SOLICITAR AL MINISTERIO PÚBLICO UN INFORME SOBRE LA VIGENCIA DE LOS PRESUPUESTOS DE LA MEDIDA.', 'DEBERA REVISAR DE OFICIO LA VIGENCIA DE LOS PRESUPUESTOS QUE DIERON LUGAR A LA IMPOSICIÓN DE LA MEDIDA', 'PUEDE SOLICITAR LA REVISIÓN SOLO SI ALGUNA DE LAS PARTES LO PIDE EXPRESAMENTE.', 'DEBE CONVOCAR A LAS PARTES A UNA AUDIENCIA DE CONCLUSIONES FINALES.', NULL, 'c', 'DEBERA REVISAR DE OFICIO LA VIGENCIA DE LOS PRESUPUESTOS QUE DIERON LUGAR A LA IMPOSICIÓN DE', '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184909'),
(2717, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿BAJO QUÉ CIRCUNSTANCIAS PROCEDERÁ LA CESACIÓN DE LA PRISIÓN PREVENTIVA O DE LAS MEDIDAS DE COMPARECENCIA SEGÚN EL ARTÍCULO 83 DE LA LEY N°32130?:', 'CUANDO EL IMPUTADO SOLICITE POR PRIMERA VEZ LA CESACIÓN, SIN NECESIDAD DE MÁS REQUISITOS.', 'CUANDO SE HAYAN CUMPLIDO LOS REQUISITOS DE INVESTIGACIÓN PRELIMINAR.', 'CUANDO NUEVOS ELEMENTOS DE CONVICCIÓN DEMUESTREN QUE NO CONCURREN O NO SUBSISTEN LOS MOTIVOS QUE', 'SOLO CUANDO EL PROCESO PENAL HAYA SUPERADO LA ETAPA INTERMEDIA.', 'CUANDO EL MINISTERIO PÚBLICO DECLARE LA INOCENCIA DEL IMPUTADO.', NULL, 'c', 'CUANDO NUEVOS ELEMENTOS DE CONVICCIÓN DEMUESTREN QUE NO CONCURREN O NO SUBSISTEN LOS', '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184910'),
(2718, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'PARA LA DETERMINACION DE LA MEDIDA SUSTITUTIVA EL JUEZ TENDRA EN CONSIDERACION ADICIONALMENTE, SEÑALE LA CORRECTA:', 'LA GRAVEDAD DEL DELITO INVESTIGADO EXCLUSIVAMENTE.', 'EL MONTO DEL DAÑO CIVIL CAUSADO POR EL IMPUTADO.', 'LAS CARACTERÍSTICAS PERSONALES DEL IMPUTADO, EL TIEMPO TRANSCURRIDO DESDE LA PRIVACIÓN DE LIBERTAD Y EL', 'EL OBJETIVO DE IMPONER LA MAYOR RESTRICCIÓN POSIBLE PARA EVITAR LA FUGA.', 'LA OPINIÓN DEL AGRAVIADO COMO FACTOR DETERMINANTE.', NULL, 'c', 'LAS CARACTERÍSTICAS PERSONALES DEL IMPUTADO, EL TIEMPO TRANSCURRIDO DESDE LA PRIVACIÓN DE', '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184911'),
(2719, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ SUCEDE SI EL JUEZ DETERMINA LA CESACIÓN DE LA PRISIÓN PREVENTIVA Y LA REEMPLAZA POR COMPARECENCIA, SEGÚN EL TEXTO PROCESADO?:', 'EL IMPUTADO QUEDA EN LIBERTAD SIN NINGUNA CONDICIÓN ADICIONAL.', 'NO ES NECESARIO IMPONER REGLA DE CONDUCTA ALGUNA.', 'EL JUEZ DEBE IMPONER MEDIDAS O REGLAS DE CONDUCTA NECESARIAS PARA GARANTIZAR LA PRESENCIA DEL', 'LA CESACIÓN ES AUTOMÁTICA Y DEFINITIVA, SIN POSIBILIDAD DE REVISIÓN POSTERIOR.', 'EL PODER JUDICIAL DEBE EMITIR UNA RESOLUCIÓN ADMINISTRATIVA ADICIONAL.', NULL, 'c', 'EL JUEZ DEBE IMPONER MEDIDAS O REGLAS DE CONDUCTA NECESARIAS PARA GARANTIZAR LA PRESENCIA', '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184912'),
(2720, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ DERECHO LE ASISTE AL IMPUTADO RESPECTO A LA SOLICITUD DE CESACIÓN DE PRISIÓN PREVENTIVA O COMPARECENCIA RESTRICTIVA?:', 'PUEDE SOLICITAR LA CESACIÓN SÓLO UNA VEZ DURANTE LA INVESTIGACIÓN PREPARATORIA.', 'PUEDE SOLICITAR LA CESACIÓN TANTAS VECES COMO LO CONSIDERE PERTINENTE.', 'SOLO PUEDE SOLICITAR LA CESACIÓN SI HAN TRANSCURRIDO DOCE MESES DESDE LA IMPOSICIÓN DE LA MEDIDA.', 'DEBE PRESENTAR LA SOLICITUD ÚNICAMENTE A TRAVÉS DE SU ABOGADO DEFENSOR.', 'PUEDE SOLICITAR CESACIÓN ÚNICAMENTE PREVIA AUTORIZACIÓN DEL MINISTERIO PÚBLICO.', NULL, 'b', 'PUEDE SOLICITAR LA CESACIÓN TANTAS VECES COMO LO CONSIDERE PERTINENTE.', '(texto: (ART: UNICO)** Articulo 283. Cesacion de la prision preventiva o de la comparecencia)**', '184913'),
(2721, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA FINALIDAD PRINCIPAL DE LA INVESTIGACIÓN PREPARATORIA SEGÚN EL ARTÍCULO 321?:', 'FORMULAR ACUSACIÓN DE INMEDIATO CONTRA EL IMPUTADO SIN MAYOR ANÁLISIS.', 'PROTEGER EXCLUSIVAMENTE LOS DERECHOS DE LA VÍCTIMA.', 'REUNIR ELEMENTOS DE CONVICCIÓN PARA QUE EL FISCAL DECIDA SI FORMULA O NO ACUSACIÓN Y PERMITIR AL', 'SANCIONAR ANTICIPADAMENTE A LOS RESPONSABLES DEL DELITO.', 'IMPULSAR ACCIONES ADMINISTRATIVAS EN CASO DE DELITOS MENORES.', NULL, 'c', 'REUNIR ELEMENTOS DE CONVICCIÓN PARA QUE EL FISCAL DECIDA SI FORMULA O NO ACUSACIÓN Y PERMITIR', '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184914'),
(2722, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA ESTRUCTURA DE LA INVESTIGACIÓN PREPARATORIA (ART 321)¿ SEÑALE CUÁL ES LA CORRECTA, SEGÚN LA MODIFICACIÓN ESTABLECIDA EN LA LEY N°32130?:', 'TIENE DOS SUBETAPAS: INICIAL Y CONCLUSIVA, AMBAS DIRIGIDAS SOLO POR LA POLICÍA.', 'SE DIVIDE EN ACTUACIÓN PRELIMINAR Y JUZGAMIENTO, AMBAS BAJO COMPETENCIA EXCLUSIVA DEL MINISTERIO', 'CONSTA DE DOS SUBETAPAS: LA INVESTIGACIÓN PRELIMINAR REALIZADA POR LA POLICIA NACIONAL DEL PERU CON', 'LA INVESTIGACIÓN SOLO ES FORMAL SI INTERVIENE EL PODER JUDICIAL DESDE EL INICIO.', 'LA INVESTIGACIÓN PREPARATORIA SOLO EXISTE PARA DELITOS GRAVES SEGÚN LA NUEVA LEY.', NULL, 'c', 'CONSTA DE DOS SUBETAPAS: LA INVESTIGACIÓN PRELIMINAR REALIZADA POR LA POLICIA NACIONAL DEL', '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184915'),
(2723, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 321 MODIFICADO, ¿QUÉ ROL CORRESPONDE A LA POLICÍA NACIONAL DEL PERÚ EN LA ETAPA PRELIMINAR DE INVESTIGACIÓN?', 'ES ÚNICAMENTE UNA FUNCIÓN DE APOYO EN EJECUCIÓN DE MANDATOS JUDICIALES.', 'ACTÚA DIRECTAMENTE EN LA INVESTIGACIÓN PRELIMINAR BAJO LA CONDUCCIÓN JURÍDICA DEL MINISTERIO PÚBLICO.', 'TIENE COMPETENCIA AUTÓNOMA EN LA DISPOSICIÓN DE DILIGENCIAS FISCALES Y JUDICIALES.', 'SOLO PUEDE INTERVENIR EN DETENCIONES IN FRAGANTI.', 'ASUME LA DIRECCIÓN EXCLUSIVA EN TODO EL PROCESO PENAL.', NULL, 'b', 'ACTÚA DIRECTAMENTE EN LA INVESTIGACIÓN PRELIMINAR BAJO LA CONDUCCIÓN JURÍDICA DEL MINISTERIO', '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184916'),
(2724, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LOS SIGUIENTES ASPECTOS, NO ES UNA FINALIDAD DE LA INVESTIGACIÓN PREPARATORIA SEGÚN EL ART 321 DE LA LEY N°32130?:', 'DETERMINAR LA EXISTENCIA DEL DAÑO CAUSADO.', 'IDENTIFICAR LA IDENTIDAD DEL AUTOR O PARTÍCIPE DEL DELITO.', 'DETERMINAR SI LA CONDUCTA INCRIMINADA ES DELICTUOSA.', 'EJECUTAR SANCIONES PENALES DE MANERA ANTICIPADA.', 'CONOCER LOS MÓVILES DE LA PERPETRACIÓN DEL DELITO.', NULL, 'd', 'EJECUTAR SANCIONES PENALES DE MANERA ANTICIPADA.', '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184917'),
(2725, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿A QUIÉN CORRESPONDE LA DIRECCIÓN PRINCIPAL DE LA INVESTIGACIÓN PREPARATORIA FORMALIZADA, DE ACUERDO CON LA MODIFICACIÓN AL CÓDIGO PROCESAL PENAL?:', 'EXCLUSIVAMENTE AL PODER JUDICIAL, CON INTERVENCIÓN PUNTUAL DEL MINISTERIO PÚBLICO.', 'A LA POLICÍA NACIONAL DEL PERÚ, SIN INJERENCIA DE OTRAS ENTIDADES.', 'AL MINISTERIO PÚBLICO, CON APOYO EN LAS DILIGENCIAS DE LA POLICÍA NACIONAL DEL PERÚ.', 'A LOS ABOGADOS DEFENSORES DE LAS PARTES, PARA GARANTIZAR EL CONTRADICTORIO.', 'A LA DEFENSORÍA DEL PUEBLO, COMO GARANTE DE DERECHOS FUNDAMENTALES.', NULL, 'c', 'AL MINISTERIO PÚBLICO, CON APOYO EN LAS DILIGENCIAS DE LA POLICÍA NACIONAL DEL PERÚ.', '(texto: (ART: UNICO)** Articulo 321. Finalidad)**', '184918'),
(2726, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿EN EL MARCO DEL ARTÍCULO 322 DEL CÓDIGO PROCESAL PENAL, MODIFICADO POR LA LEY 32130, CUÁL DE LAS SIGUIENTES FUNCIONES CORRESPONDE DE MODO PRINCIPAL A LA POLICÍA NACIONAL DEL PERÚ DURANTE LA ETAPA PRELIMINAR DE LA INVESTIGACIÓN?:', 'CONDUCIR JURÍDICAMENTE LA INVESTIGACIÓN PREPARATORIA, DIRIGIENDO AL MINISTERIO PÚBLICO EN LA TOMA DE', 'PRACTICAR LA INVESTIGACIÓN MATERIAL DEL DELITO POR INICIATIVA PROPIA O A SOLICITUD DE PARTE, SIEMPRE QUE NO', 'EMITIR RESOLUCIONES JURISDICCIONALES SOBRE MEDIDAS LIMITATIVAS DE DERECHOS FUNDAMENTALES EN EL', 'EJERCER CONTROL DISCIPLINARIO SOBRE FISCALES Y JUECES DURANTE LA INVESTIGACIÓN PRELIMINAR.', 'FORMULAR REQUERIMIENTOS DE FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA ANTE EL JUEZ COMPETENTE.', NULL, 'b', 'PRACTICAR LA INVESTIGACIÓN MATERIAL DEL DELITO POR INICIATIVA PROPIA O A SOLICITUD DE PARTE,', '(texto: (ART: UNICO)** Articulo 322. Direccion de la investigacion)**', '184919'),
(2727, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 322 DEL CÓDIGO PROCESAL PENAL TRAS SU MODIFICACIÓN, ¿EN QUÉ SUPUESTO EL MINISTERIO PÚBLICO PUEDE SOLICITAR EL APOYO DE LA POLICÍA NACIONAL DEL PERÚ UNA VEZ FORMALIZADA LA INVESTIGACIÓN PREPARATORIA?:', 'CUANDO CONSTITUYE UNA GARANTÍA PERSONAL DEL INVESTIGADO.', 'CUANDO LA INVESTIGACIÓN REQUIERA DILIGENCIAS QUE TENGAN CONTENIDO JURISDICCIONAL, ESPECIALMENTE LAS', 'PARA QUE LA POLICÍA REALICE INVESTIGACIONES COMPLEMENTARIAS BAJO LA DIRECCIÓN DEL MINISTERIO PÚBLICO.', 'SÓLO CUANDO EL CASO HA SIDO ELEVADO A JUICIO ORAL POR EL JUEZ PENAL.', 'EN CASOS DE FLAGRANCIA DELICTIVA, SIN IMPORTAR ETAPA PROCESAL.', NULL, 'c', 'PARA QUE LA POLICÍA REALICE INVESTIGACIONES COMPLEMENTARIAS BAJO LA DIRECCIÓN DEL MINISTERIO', '(texto: (ART: UNICO)** Articulo 322. Direccion de la investigacion)**', '184920'),
(2728, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO CON EL ARTÍCULO 329, MODIFICADO POR LA LEY 32130, ¿CUÁL ES EL MODO PROCEDIMENTAL CORRECTO PARA INICIAR LOS ACTOS DE INVESTIGACIÓN POR PARTE DE LA POLICÍA NACIONAL DEL PERÚ EN UN CASO DE SOSPECHA DE DELITO?:', 'LA POLICÍA NACIONAL DEBE INICIAR LOS ACTOS DE INVESTIGACIÓN SÓLO CON MANDATO PREVIO DEL JUEZ DE', 'LOS ACTOS DE INVESTIGACIÓN PUEDEN INICIARSE ÚNICAMENTE SI MEDIA DENUNCIA ESCRITA DE LOS TESTIGOS Y LA', 'LA POLICÍA NACIONAL PUEDE INICIAR LOS ACTOS DE INVESTIGACIÓN, PERO ÚNICAMENTE TRAS RECIBIR LA DISPOSICIÓN', 'LA POLICÍA NACIONAL INICIA LOS ACTOS DE INVESTIGACIÓN COMUNICANDO DE FORMA INMEDIATA AL FISCAL CUANDO', 'LOS ACTOS DE INVESTIGACIÓN SE INICIAN EXCLUSIVAMENTE POR ORDEN MOTIVADA DEL FISCAL SUPERIOR Y SIN', NULL, 'd', 'LA POLICÍA NACIONAL INICIA LOS ACTOS DE INVESTIGACIÓN COMUNICANDO DE FORMA INMEDIATA AL FISCAL', '(texto: (ART: UNICO)** Articulo 329. Formas de iniciar la investigacion)**', '184922'),
(2729, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA FINALIDAD INMEDIATA DE LA INVESTIGACIÓN PRELIMINAR, SEGÚN EL ARTÍCULO 330 MODIFICADO POR LA LEY 32130?:', 'INDIVIDUALIZAR ÚNICAMENTE A LOS PRESUNTOS AUTORES DEL DELITO PARA SU DETENCIÓN.', 'GARANTIZAR LOS DERECHOS FUNDAMENTALES DE LOS DETENIDOS EN LA ETAPA INTERMEDIA.', 'REALIZAR ACTOS URGENTES O INAPLAZABLES PARA DETERMINAR LA EXISTENCIA DE LOS HECHOS, SU DELICTUOSIDAD Y', 'DEFINIR EL GRADO DE RESPONSABILIDAD DE LOS PARTÍCIPES DURANTE LA INVESTIGACIÓN PREPARATORIA.', 'PREPARAR LA ACUSACIÓN FISCAL PARA EL REQUERIMIENTO DE PRISIÓN PREVENTIVA.', NULL, 'c', 'REALIZAR ACTOS URGENTES O INAPLAZABLES PARA DETERMINAR LA EXISTENCIA DE LOS HECHOS, SU', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184923'),
(2730, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUIÉN ESTÁ ENCARGADO DE LA INVESTIGACIÓN PRELIMINAR DEL DELITO, CONFORME AL ARTÍCULO 330 DE LA LEY N°32130, MARQUE LA RESPUESTA CORRECTA?:', 'ÚNICAMENTE EL FISCAL, CON AUXILIO DE LA POLICÍA NACIONAL DEL PERÚ.', 'EL PODER JUDICIAL, CON APOYO DEL MINISTERIO PÚBLICO.', 'LA POLICÍA NACIONAL DEL PERÚ, CON LA CONDUCCIÓN JURÍDICA DEL FISCAL.', 'EL MINISTERIO PÚBLICO, DE MANERA AUTÓNOMA E INDEPENDIENTE.', 'EL PROCURADOR PÚBLICO, CON INTERVENCIÓN SUBSIDIARIA DEL FISCAL.', NULL, 'c', 'LA POLICÍA NACIONAL DEL PERÚ, CON LA CONDUCCIÓN JURÍDICA DEL FISCAL.', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184924'),
(2731, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LOS ENUNCIADOS, NO ES UN PROPÓSITO INMEDIATO DE LA INVESTIGACIÓN PRELIMINAR, SEGÚN EL ART 330 DE LA LEY N°32130?:', 'IDENTIFICAR Y UBICAR A LOS PRESUNTOS AUTORES Y PARTÍCIPES DEL HECHO DELICTIVO.', 'ASEGURAR DEBIDAMENTE A LAS PERSONAS INVOLUCRADAS, DENTRO DE LOS LÍMITES DE LA LEY.', 'IMPEDIR QUE EL DELITO PRODUZCA CONSECUENCIAS ULTERIORES.', 'ASEGURAR LOS ELEMENTOS MATERIALES DE LA COMISIÓN DEL HECHO.', 'FORMALIZAR LA ACUSACIÓN ANTE EL ÓRGANO JURISDICCIONAL COMPETENTE.', NULL, 'e', 'FORMALIZAR LA ACUSACIÓN ANTE EL ÓRGANO JURISDICCIONAL COMPETENTE.', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184925'),
(2732, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DENTRO DEL MARCO DEL ARTÍCULO 330 REFORMADO, ¿CUÁL ES EL PAPEL DE LA POLICÍA NACIONAL AL TENER CONOCIMIENTO DE UN DELITO DE EJERCICIO PÚBLICO DE LA ACCIÓN PENAL?:', 'CONDUCIR LA INVESTIGACIÓN PRELIMINAR DE MANERA AUTÓNOMA Y SIN SUPERVISIÓN FISCAL.', 'PODRA CONSTITUIRSE INMEDIATAMENTE EN EL LUGAR DE LOS HECHOS CON PERSONAL POLICIAL ESPECIALIZADO Y', 'SOLICITAR A LA FISCALÍA LA AUTORIZACIÓN PARA INTERVENIR EN EL LUGAR DEL DELITO.', 'EMITIR PRONTAMENTE LA ACUSACIÓN PENAL FORMAL SIN INTERVENCIÓN DEL MINISTERIO PÚBLICO.', 'COORDINAR CON EL PODER JUDICIAL PARA DETERMINAR LAS MEDIDAS CAUTELARES PROVISIONALES.', NULL, 'b', 'PODRA CONSTITUIRSE INMEDIATAMENTE EN EL LUGAR DE LOS HECHOS CON PERSONAL POLICIAL', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184926'),
(2733, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA FINALIDAD MEDIATA DE LA INVESTIGACIÓN PRELIMINAR, DE CONFORMIDAD AL ART 330 DE LA LEY N°32130, ES:', 'ARBITRAR LA DETENCIÓN PREVENTIVA DE LOS AGRAVIADOS.', 'INVESTIGAR LOS HECHOS POSTERIORES A LA SENTENCIA.', 'INVESTIGAR LOS HECHOS IDENTIFICANDO, UBICANDO, CAPTURANDO O CITANDO A LOS PRESUNTOS AUTORES Y', 'PROTEGER ÚNICAMENTE A LAS VÍCTIMAS Y TESTIGOS DURANTE EL PROCESO.', 'COORDINAR CON ORGANISMOS INTERNACIONALES PARA LA EXTRADICIÓN DE SOSPECHOSOS.', NULL, 'c', 'INVESTIGAR LOS HECHOS IDENTIFICANDO, UBICANDO, CAPTURANDO O CITANDO A LOS PRESUNTOS AUTORES', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184927'),
(2734, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DENTRO DE LA INVESTIGACIÓN PRELIMINAR BAJO LA LEY 32130, ¿QUÉ ACTO ESTÁ JUSTIFICADO COMO FUNCIÓN AUTÓNOMA POLICIAL?:', 'CONDUCIR TODAS LAS DILIGENCIAS SIN CONTROL DEL FISCAL.', 'REALIZAR ACTOS URGENTES O INAPLAZABLES NECESARIOS PARA IMPEDIR CONSECUENCIAS ULTERIORES DEL DELITO.', 'DICTO DE MEDIDAS COERCITIVAS PERSONALES SIN INTERVENCIÓN DEL MINISTERIO PÚBLICO.', 'INICIAR FORMALMENTE EL PROCESO PENAL ANTE EL JUEZ.', 'EMITIR SENTENCIA CONDENATORIA LUEGO DE LA INVESTIGACIÓN POLICIAL.', NULL, 'b', 'REALIZAR ACTOS URGENTES O INAPLAZABLES NECESARIOS PARA IMPEDIR CONSECUENCIAS ULTERIORES', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184928'),
(2735, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'AL TENER CONOCIMIENTO DE UN DELITO DE EJERCIO PUBLICO, QUIENES DEBEN CONSTITUIRSE INMEDIATAMENTE AL LUGAR DE LOS HECHOS?:', 'EL FISCAL O LA POLICIA.', 'EL MINISTERIO PUBLICO Y JUEZ DE LA INVESTIGACION PREPARATORIA.', 'LA POLICÍA NACIONAL Y CUERPO GENERAL DE BOMBEROS.', 'EL MINISTERIO PUBLICO Y FUERZAS ARMADAS.', 'LA ESCENA PUEDE SER INTERVENIDA SOLO TRAS LA DECLARACIÓN DE EMERGENCIA NACIONAL.', NULL, 'a', 'EL FISCAL O LA POLICIA.', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184929'),
(2736, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 330, ¿QUÉ FUNCIÓN CUMPLE EL INFORME POLICIAL EMITIDO AL FISCAL AL CONCLUIR LA INVESTIGACIÓN PRELIMINAR?', 'PERMITE DECIDIR SOBRE LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA.', 'SUSTITUYE LA IMPUTACIÓN FORMAL ANTE EL PODER JUDICIAL.', 'DEFINE LA CULPABILIDAD DEL INVESTIGADO.', 'PRESENTA LOS ALEGATOS DE CIERRE PARA LA SENTENCIA.', 'ORDENA LA DETENCIÓN JUDICIAL DIRECTA DEL IMPUTADO.', NULL, 'a', 'PERMITE DECIDIR SOBRE LA FORMALIZACIÓN DE LA INVESTIGACIÓN PREPARATORIA.', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184930'),
(2737, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SOBRE LA FACULTAD DE CONSTITUIRSE EN EL LUGAR DE LOS HECHOS, ¿EN QUÉ CASOS PUEDEN HACERLO EL FISCAL O LA POLICÍA NACIONAL?:', 'SOLAMENTE SI EXISTE FLAGRANCIA DELICTIVA GRAVE.', 'AL TENER CONOCIMIENTO DE CUALQUIER DELITO PERSEGUIBLE POR ACCIÓN PRIVADA.', 'AL TENER CONOCIMIENTO DE UN DELITO DE EJERCICIO PÚBLICO DE LA ACCIÓN PENAL.', 'DESPUÉS DE LA FORMALIZACIÓN DE LA ACUSACIÓN PENAL.', 'SOLO AL RECIBIR DENUNCIA ESCRITA DEL AGRAVIADO.', NULL, 'c', 'AL TENER CONOCIMIENTO DE UN DELITO DE EJERCICIO PÚBLICO DE LA ACCIÓN PENAL.', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184931'),
(2738, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CONFORME AL ART 330 DE LA LEY N°32130, ¿QUÉ ELEMENTO NO ES DESTACADO COMO COMPETENCIA DE LA INVESTIGACIÓN PRELIMINAR DE LA PNP BAJO CONDUCCIÓN FISCAL?:', 'IMPEDIR QUE EL DELITO PRODUZCA CONSECUENCIAS ULTERIORES.', 'ASEGURAR LOS ELEMENTOS MATERIALES DEL DELITO.', 'INDIVIDUALIZAR A LOS AGRAVIADOS.', 'ASEGURAR DEBIDAMENTE A LAS PERSONAS INVOLUCRADAS.', 'EMITIR AUTO DE PRISIÓN PREVENTIVA.', NULL, 'e', 'EMITIR AUTO DE PRISIÓN PREVENTIVA.', '(texto: (ART: UNICO)** Articulo 330. Investigacion preliminar)**', '184932'),
(2739, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO AL ARTÍCULO 331, ¿CUÁL ES EL DEBER INMEDIATO DE LA POLICÍA NACIONAL DEL PERÚ AL TENER CONOCIMIENTO DE LA COMISIÓN DE UN DELITO?:', 'REALIZAR LA DETENCIÓN DE LOS SOSPECHOSOS Y LUEGO INFORMAR AL MINISTERIO PÚBLICO EN UN PLAZO MÁXIMO DE', 'INICIAR LA INVESTIGACIÓN PRELIMINAR, COMUNICAR DE FORMA INMEDIATA AL MINISTERIO PÚBLICO, TANTO POR LA VÍA', 'ESPERAR LA AUTORIZACIÓN JUDICIAL ANTES DE INFORMAR SOBRE EL DELITO AL MINISTERIO PÚBLICO.', 'ÚNICAMENTE RECOGER LA INFORMACIÓN DEL DELITO Y ALMACENARLA HASTA QUE EL FISCAL LO REQUIERA', 'ELABORAR UN INFORME POLICIAL Y COMUNICARLO SOLO CUANDO LAS PRUEBAS ESTÉN COMPLETAS.', NULL, 'b', 'INICIAR LA INVESTIGACIÓN PRELIMINAR, COMUNICAR DE FORMA INMEDIATA AL MINISTERIO PÚBLICO, TANTO', '(texto: (ART: UNICO)** Articulo 331. Actuacion policial)**', '184933'),
(2740, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA MODIFICACIÓN DEL ARTÍCULO 331, ¿CUÁNDO DEBE LA POLICÍA PONER A DISPOSICIÓN DEL FISCAL TODO LO ACTUADO DURANTE LA INVESTIGACIÓN PRELIMINAR?:', 'UNA VEZ QUE EL MINISTERIO PÚBLICO LE COMUNIQUE FORMALMENTE UNA ORDEN EXPRESA.', 'AL FINALIZAR LA INVESTIGACIÓN PRELIMINAR, MEDIANTE EL CORRESPONDIENTE INFORME POLICIAL.', 'ÚNICAMENTE CUANDO SE HAYA DICTADO PRISIÓN PREVENTIVA PARA EL INVESTIGADO.', 'SIEMPRE QUE EXISTAN PRUEBAS INCRIMINATORIAS SUFICIENTES, SIN IMPORTAR EL ESTADO DEL PROCEDIMIENTO.', 'AL MOMENTO EN QUE SE REMITA EL EXPEDIENTE AL PODER JUDICIAL PARA JUZGAMIENTO.', NULL, 'b', 'AL FINALIZAR LA INVESTIGACIÓN PRELIMINAR, MEDIANTE EL CORRESPONDIENTE INFORME POLICIAL.', '(texto: (ART: UNICO)** Articulo 331. Actuacion policial)**', '184934'),
(2741, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ INFORMACIÓN ADICIONAL DEBE REMITIR LA POLICÍA AL MINISTERIO PÚBLICO, SEGÚN EL ARTÍCULO 331, SIN PERJUICIO DE LA COMUNICACIÓN INMEDIATA?:', 'SOLO EL ACTA POLICIAL Y LA RELACIÓN DE LOS PRESUNTOS RESPONSABLES.', 'TODA LA DOCUMENTACIÓN QUE PUDIERA EXISTIR RELACIONADA AL HECHO INVESTIGADO.', 'ÚNICAMENTE LA DECLARACIÓN DE LOS TESTIGOS PRESENCIALES Y LA EVIDENCIA MATERIAL.', 'LA PETICIÓN FORMAL DE INICIO DE PROCESO PENAL.', 'LA SOLICITUD DE AUTORIZACIÓN PARA REALIZAR DILIGENCIAS ADICIONALES.', NULL, 'b', 'TODA LA DOCUMENTACIÓN QUE PUDIERA EXISTIR RELACIONADA AL HECHO INVESTIGADO.', '(texto: (ART: UNICO)** Articulo 331. Actuacion policial)**', '184935'),
(2742, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL INFORME POLICIAL REGULADO EN EL ARTÍCULO 332, ¿CUÁL DE LOS SIGUIENTES ENUNCIADOS ES CORRECTO EN CUANTO A SU NATURALEZA Y EFECTOS JURÍDICOS ANTE EL FISCAL?:', 'EL INFORME POLICIAL ES VINCULANTE Y OBLIGA AL FISCAL A ADECUAR SU DECISIÓN CONFORME AL MISMO.', 'EL INFORME POLICIAL NO ES VINCULANTE.', 'EL INFORME POLICIAL TIENE CARÁCTER RESOLUTIVO Y PUEDE SUSTITUIR LA ACUSACIÓN FISCAL.', 'EL INFORME POLICIAL ES OBLIGATORIO TANTO EN SU CONTENIDO COMO EN SUS RECOMENDACIONES PARA EL FISCAL.', 'EL INFORME POLICIAL DEBE SER CALIFICADO POR EL FISCAL COMO MÉRITO SUFICIENTE PARA ABRIR JUICIO ORAL.', NULL, 'b', 'EL INFORME POLICIAL NO ES VINCULANTE.', '(texto: (ART: UNICO)**  Articulo 332. Informe policial)**', '184936'),
(2743, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA MODIFICACIÓN INTRODUCIDA POR LA LEY 32130 AL ARTÍCULO 332, ¿CUÁL ES LA RESPONSABILIDAD QUE ASUME LA POLICÍA NACIONAL RESPECTO DE LA PRESENTACIÓN DEL INFORME POLICIAL AL MINISTERIO PÚBLICO?:', 'SOLO ADMINISTRATIVA, POR NO PRESENTAR EL INFORME DENTRO DEL PLAZO.', 'SOLO CIVIL, POR DAÑOS Y PERJUICIOS A LOS INVESTIGADOS.', 'NINGUNA, YA QUE LA ELABORACIÓN DEL INFORME ES FACULTATIVA.', 'RESPONSABILIDAD FUNCIONAL POR LA NO PRESENTACIÓN OPORTUNA DEL INFORME CONFORME AL PLAZO OTORGADO', 'SOLO PENAL, EN CASO DE OCULTAR PRUEBAS EN EL INFORME.', NULL, 'd', 'RESPONSABILIDAD FUNCIONAL POR LA NO PRESENTACIÓN OPORTUNA DEL INFORME CONFORME AL PLAZO', '(texto: (ART: UNICO)**  Articulo 332. Informe policial)**', '184937'),
(2744, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CONFORME A LO DISPUESTO EN EL ARTÍCULO 332, ¿CUÁLES DE LOS SIGUIENTES ELEMENTOS NO DEBE NECESARIAMENTE CONTENER EL INFORME POLICIAL REMITIDO AL FISCAL?:', 'LOS ANTECEDENTES QUE MOTIVARON LA INTERVENCIÓN POLICIAL.', 'LA RELACIÓN DETALLADA DE LAS DILIGENCIAS EFECTUADAS DURANTE LA INVESTIGACIÓN.', 'UNA VALORACIÓN DEFINITIVA SOBRE LA CULPABILIDAD DEL INVESTIGADO.', 'LAS PRECALIFICACIONES DE LOS DELITOS PRESUNTAMENTE COMETIDOS.', 'EL ANÁLISIS DE LOS HECHOS INVESTIGADOS Y LAS CONCLUSIONES RESPECTIVAS.', NULL, 'c', 'UNA VALORACIÓN DEFINITIVA SOBRE LA CULPABILIDAD DEL INVESTIGADO.', '(texto: (ART: UNICO)**  Articulo 332. Informe policial)**', '184938'),
(2745, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA FUNCIÓN PRINCIPAL DEL INFORME POLICIAL EN EL PROCEDIMIENTO PENAL PERUANO, CONFORME AL ARTÍCULO 332 MODIFICADO POR LA LEY 32130?', 'SERVIR COMO DICTAMEN PERICIAL PARA RESOLUCIONES JUDICIALES.', 'CONSTITUIR LA BASE ESENCIAL PARA LA ACUSACIÓN FISCAL EN JUICIO ORAL.', 'PROPORCIONAR ANTECEDENTES, DILIGENCIAS REALIZADAS, PRECALIFICACIONES Y CONCLUSIONES PARA FUNDAMENTAR', 'DETERMINAR LA RESPONSABILIDAD PENAL DEL IMPUTADO DIRECTA E IRREVOCABLEMENTE.', 'VALIDAR ADMINISTRATIVAMENTE LA ACTUACIÓN POLICIAL ANTE EL FISCAL SUPERIOR.', NULL, 'c', 'PROPORCIONAR ANTECEDENTES, DILIGENCIAS REALIZADAS, PRECALIFICACIONES Y CONCLUSIONES PARA', '(texto: (ART: UNICO)**  Articulo 332. Informe policial)**', '184940'),
(2746, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 337, ¿EN QUÉ SUPUESTO ESPECÍFICO LA INVESTIGACIÓN PRELIMINAR PUEDE SER AMPLIADA UNA VEZ FORMALIZADA LA INVESTIGACIÓN PREPARATORIA?:', 'CUANDO LO SOLICITA LA DEFENSA TÉCNICA DEL IMPUTADO, ALEGANDO VULNERACIÓN DE SUS DERECHOS PROCESALES.', 'SI LA VÍCTIMA PRESENTA UNA NUEVA DENUNCIA SOBRE LOS MISMOS HECHOS.', 'CUANDO EL FISCAL ADVIERTA UN GRAVE DEFECTO EN LA ACTUACIÓN DE LA DILIGENCIA O SE DEBA COMPLETAR', 'CADA VEZ QUE LA POLICÍA NACIONAL LO CONSIDERE NECESARIO EN CUMPLIMIENTO DE SU FUNCIÓN INVESTIGADORA.', 'ANTE LA EXISTENCIA DE CONTRADICCIONES ENTRE TESTIMONIOS RECABADOS DURANTE LA INVESTIGACIÓN PRELIMINAR.', NULL, 'c', 'CUANDO EL FISCAL ADVIERTA UN GRAVE DEFECTO EN LA ACTUACIÓN DE LA DILIGENCIA O SE DEBA', '(texto: (ART: UNICO)**   Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184942'),
(2747, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL LÍMITE IMPUESTO A LA POLICÍA NACIONAL POR EL ARTÍCULO 337 RESPECTO A LA REALIZACIÓN DE DILIGENCIAS INVESTIGATIVAS?', 'PUEDE REALIZAR CUALQUIER DILIGENCIA DE INVESTIGACIÓN QUE CONSIDERE ÚTIL, SIN LIMITACIONES LEGALES.', 'DEBE ACTUAR SOLAMENTE BAJO ÓRDENES JUDICIALES DIRECTAS.', 'SOLO PUEDE REALIZAR DILIGENCIAS DISPUESTAS Y ENMARCADAS DENTRO DE LOS LÍMITES DE LA LEY, SEGÚN LO', 'PUEDE AMPLIAR SUS INVESTIGACIONES EN CUALQUIER MOMENTO Y SIN COORDINACIÓN CON EL FISCAL.', 'QUEDA LIMITADA SOLO POR LA DISPONIBILIDAD DE RECURSOS LOGÍSTICOS.', NULL, 'c', 'SOLO PUEDE REALIZAR DILIGENCIAS DISPUESTAS Y ENMARCADAS DENTRO DE LOS LÍMITES DE LA LEY, SEGÚN', '(texto: (ART: UNICO)**   Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184944'),
(2748, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA NATURALEZA DE LA INVESTIGACIÓN PRELIMINAR EN EL MARCO DE LA LEY N°32130, CONFORME AL ARTÍCULO 337, INDIQUE LA AFIRMACIÓN CORRECTA:', 'ES UNA ETAPA AUTÓNOMA INDEPENDIENTE DE LA INVESTIGACIÓN PREPARATORIA.', 'ES UNA SUBETAPA DE LA INVESTIGACIÓN PREPARATORIA Y ESTÁ SUJETA A LIMITACIONES RELATIVAS A SU REPETICIÓN Y', 'PUEDE SER DISPUESTA EN CUALQUIER MOMENTO DEL PROCESO JUDICIAL, INCLUSO EN ETAPA DE JUZGAMIENTO.', 'LA POLICÍA LA DIRIGE DE FORMA INDEPENDIENTE, SIN INTERVENCIÓN DEL FISCAL.', 'SE DESARROLLA SIEMPRE DE MANERA PÚBLICA Y ORAL BAJO CONTROL JUDICIAL.', NULL, 'b', 'ES UNA SUBETAPA DE LA INVESTIGACIÓN PREPARATORIA Y ESTÁ SUJETA A LIMITACIONES RELATIVAS A SU', '(texto: (ART: UNICO)**   Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184945'),
(2749, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CONFORME AL ARTÍCULO 337, ¿CUÁL DE LOS SIGUIENTES ENUNCIADOS REFLEJA CORRECTAMENTE LA RELACIÓN ENTRE LA ACTUACIÓN FISCAL Y POLICIAL EN LA INVESTIGACIÓN DE DELITOS?:', 'EL FISCAL ESTÁ AUTORIZADO A DELEGAR EN LA POLICÍA ÚNICAMENTE LA BÚSQUEDA DE ELEMENTOS MATERIALES DE', 'LA POLICÍA INVESTIGA SOLO BAJO LA SUPERVISIÓN DEL JUEZ DE LA INVESTIGACIÓN PREPARATORIA.', 'LA POLICÍA REALIZA DILIGENCIAS QUE CONSIDERE PERTINENTES Y ÚTILES, PERO SIEMPRE DENTRO DE LOS LÍMITES', 'LA POLICÍA TIENE FACULTAD AUTÓNOMA DE DECIDIR EL INICIO, EL CONTENIDO Y LA CULMINACIÓN DE LAS DILIGENCIAS DE', 'EL FISCAL SOLO INTERVIENE SI EXISTE UNA SOLICITUD EXPRESA DE LA VÍCTIMA.', NULL, 'c', 'LA POLICÍA REALIZA DILIGENCIAS QUE CONSIDERE PERTINENTES Y ÚTILES, PERO SIEMPRE DENTRO DE LOS', '(texto: (ART: UNICO)**   Articulo 337. Diligencias de la Investigacion Preparatoria)**', '184946'),
(2750, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 353 MODIFICADO POR LA LEY 32130, ¿CUÁL ES LA CONDICIÓN ESENCIAL PARA QUE EL AUTO DE ENJUICIAMIENTO PUEDA SER RECURRIDO POR LAS PARTES PROCESALES?:', 'SI EN EL AUTO DE ENJUICIAMIENTO NO SE CITA EXPRESAMENTE LA LEY QUE SUSTENTA LA ACUSACIÓN FISCAL.', 'CUANDO EL AUTO DE ENJUICIAMIENTO OMITE IDENTIFICAR A LOS SUJETOS PASIVOS DEL PROCESO PENAL.', 'SI LA IMPUTACIÓN NECESARIA NO ESTÁ DEBIDAMENTE FORMULADA, ES DECIR, NO SE IDENTIFICAN CORRECTAMENTE LOS', 'EN TODOS LOS CASOS EN LOS QUE SE DICTE UN AUTO DE ENJUICIAMIENTO, INDEPENDIENTEMENTE DE SU CONTENIDO.', 'CUANDO EL JUEZ DICTA EL AUTO DE ENJUICIAMIENTO SIN HABER INTERVENIDO EL FISCAL PRINCIPAL EN LA AUDIENCIA', NULL, 'c', 'SI LA IMPUTACIÓN NECESARIA NO ESTÁ DEBIDAMENTE FORMULADA, ES DECIR, NO SE IDENTIFICAN', '(texto: (ART: UNICO)**   Articulo 353. Contenido del auto de enjuiciamiento)**', '184947'),
(2751, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL ÁMBITO DE APLICACIÓN TERRITORIAL DEL DECRETO LEGISLATIVO 1611 RESPECTO A LA PREVENCIÓN E INVESTIGACIÓN DEL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS, SEGÚN EL ARTÍCULO 2?', 'SE APLICA ÚNICAMENTE EN ZONAS URBANAS DEL TERRITORIO NACIONAL, EXCLUYENDO ÁREAS RURALES Y ZONAS DE', 'SE APLICA EN TODO EL TERRITORIO DE LA REPÚBLICA, INCLUYENDO ÁREAS DE EXCLUSIÓN, RÉGIMEN ESPECIAL', 'SE LIMITA EXCLUSIVAMENTE A LOS ESPACIOS GEOGRÁFICOS SUJETOS A ESTADO DE EMERGENCIA DECRETADO POR EL', 'ALCANZA SOLO PROPIEDAD PÚBLICA, EXCLUYENDO DE MANERA PERMANENTE LA INVESTIGACIÓN EN ESPACIOS', 'OPERA SOLAMENTE EN CIRCUNSCRIPCIONES DONDE EXISTAN ANTECEDENTES DE DELITOS DE EXTORSIÓN VERIFICADOS', NULL, 'b', 'SE APLICA EN TODO EL TERRITORIO DE LA REPÚBLICA, INCLUYENDO ÁREAS DE EXCLUSIÓN, RÉGIMEN', '(texto: (ART: 2)**   Articulo 2.- Ambito de Aplicacion)**', '185359'),
(2752, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 2 DEL DECRETO LEGISLATIVO 1611, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA RESPECTO A LAS ACTUACIONES EN PROPIEDAD PRIVADA EN EL MARCO DE LA PREVENCIÓN E INVESTIGACIÓN DE EXTORSIÓN?', 'PUEDEN REALIZARSE SIN MANDATO JUDICIAL SI EXISTE RIESGO INMINENTE PARA LA SEGURIDAD PÚBLICA.', 'DEBEN CONTAR SIEMPRE CON MANDATO JUDICIAL, SALVO EN ZONAS DECLARADAS DE EMERGENCIA NACIONAL.', 'LAS ACTUACIONES EN PROPIEDAD QUE EXIGEN MANDATO JUDICIAL, Y CON LA ÚNICA EXCLUSIÓN DE RECINTOS', 'NO SE PERMITE ACTUACIÓN ALGUNA EN PROPIEDAD PRIVADA SEGÚN LA NORMA.', 'LA INTERVENCIÓN EN PROPIEDAD PRIVADA SOLO EXIGE NOTIFICACIÓN AL TITULAR UNA VEZ REALIZADA LA DILIGENCIA,', NULL, 'c', 'LAS ACTUACIONES EN PROPIEDAD QUE EXIGEN MANDATO JUDICIAL, Y CON LA ÚNICA EXCLUSIÓN DE', '(texto: (ART: 2)**   Articulo 2.- Ambito de Aplicacion)**', '185360'),
(2753, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CON QUÉ TIPO DE ELEMENTOS PUEDE ESTAR RELACIONADO EL ÁMBITO DE APLICACIÓN DEL DECRETO LEGISLATIVO 1611 PARA VINCULAR A PRESUNTOS AUTORES O VÍCTIMAS DE EXTORSIÓN Y DELITOS CONEXOS?', 'SOLO CON ARMAS DE FUEGO Y SUSTANCIAS ILÍCITAS FÍSICAS PRESENTES EN LA ESCENA DEL DELITO.', 'ÚNICAMENTE CON ELEMENTOS MATERIALES DE CONVICCIÓN INDIVIDUALIZADOS DIRECTAMENTE EN EL LUGAR DE LOS', 'CON CIRCUNSTANCIAS, EFECTOS, OBJETOS, INSTRUMENTOS O MEDIOS DETECTADOS A TRAVÉS DE APARATOS, SISTEMAS', 'EXCLUYENTEMENTE CON OBJETOS QUE SE HALLEN EN SOPORTES TECNOLÓGICOS DE ALMACENAMIENTO EXTERNO Y NO', 'SOLAMENTE CON INFORMACIÓN PROVENIENTE DE REGISTROS ADMINISTRATIVOS CERTIFICADOS POR AUTORIDADES', NULL, 'c', 'CON CIRCUNSTANCIAS, EFECTOS, OBJETOS, INSTRUMENTOS O MEDIOS DETECTADOS A TRAVÉS DE', '(texto: (ART: 2)**   Articulo 2.- Ambito de Aplicacion)**', '185361'),
(2754, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL TRATAMIENTO DEL CIBERESPACIO SEGÚN EL ARTÍCULO 2 DEL DECRETO LEGISLATIVO 1611, ¿CUÁL DE LAS SIGUIENTES OPCIONES ES CORRECTA?', 'EL DECRETO LEGISLATIVO EXCLUYE EXPRESAMENTE EL CIBERESPACIO Y SOLO ES APLICABLE EN ENTORNOS FÍSICOS.', 'LA APLICACIÓN DEL DECRETO SE LIMITA AL CIBERESPACIO SOLO CUANDO SE TRATE DE DELITOS INFORMÁTICOS Y NO', 'EL CIBERESPACIO ESTÁ INCLUIDO EN EL ÁMBITO DE APLICACIÓN, PERMITIENDO LA ACTUACIÓN RESPECTO DE', 'EL CIBERESPACIO SOLO PUEDE SER INTERVENIDO PREVIA AUTORIZACIÓN DEL MINISTERIO DEL INTERIOR.', 'LA NORMA CONTEMPLA EL CIBERESPACIO COMO ÁMBITO INDIFERENTE Y NO LO REGULA DE MANERA EXPRESA.', NULL, 'c', 'EL CIBERESPACIO ESTÁ INCLUIDO EN EL ÁMBITO DE APLICACIÓN, PERMITIENDO LA ACTUACIÓN RESPECTO DE', '(texto: (ART: 2)**   Articulo 2.- Ambito de Aplicacion)**', '185362'),
(2755, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 2, ¿CUÁL DE LAS SIGUIENTES ALTERNATIVAS EXPRESA CORRECTAMENTE UNA EXCEPCIÓN AL ÁMBITO DE APLICACIÓN DEL DECRETO LEGISLATIVO 1611?', 'LAS ACTUACIONES EN PROPIEDADES DE EMPRESAS MULTINACIONALES CON CONVENIOS VIGENTES CON EL ESTADO', 'RECINTOS PROTEGIDOS POR INMUNIDAD DIPLOMÁTICA, EN CUYO CASO NO PROCEDE LA APLICACIÓN DEL DECRETO.', 'EL CUERPO DIPLOMÁTICO EN TERRITORIOS FORÁNEOS, AUN CUANDO OPEREN DESDE EL PERÚ VIRTUALMENTE.', 'EMPRESAS DE TELECOMUNICACIONES SUJETAS A REGULACIÓN ESPECIAL BAJO LA LEY GENERAL DE', 'ÁREAS RESIDENCIALES CON PATRULLAJE ESPECIAL DE LA POLICÍA NACIONAL DEL PERÚ.', NULL, 'b', 'RECINTOS PROTEGIDOS POR INMUNIDAD DIPLOMÁTICA, EN CUYO CASO NO PROCEDE LA APLICACIÓN DEL', '(texto: (ART: 2)**   Articulo 2.- Ambito de Aplicacion)**', '185363'),
(2756, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 3 DEL D. LEG 1611, ¿CUÁL ES EL ROL ESPECÍFICO QUE ASUME EL MINISTERIO PÚBLICO RESPECTO A LA INVESTIGACIÓN DEL DELITO DE EXTORSIÓN Y DELITOS CONEXOS?', 'COORDINA LA EJECUCIÓN DE LAS ÓRDENES JUDICIALES SOBRE EXTORSIÓN Y DELITOS CONEXOS.', 'APOYA LOGÍSTICAMENTE A LA POLICÍA NACIONAL EN OPERATIVOS PREVENTIVOS.', 'ASUME LA CONDUCCIÓN Y CONTROL JURÍDICO DE LA INVESTIGACIÓN DESDE SU INICIO.', 'ES COMPETENTE ÚNICAMENTE PARA SUPERVISAR LOS INFORMES POLICIALES EMITIDOS.', 'DICTA SENTENCIAS CONDENATORIAS EN PRIMERA INSTANCIA EN MATERIA DE EXTORSIÓN.', NULL, 'c', 'ASUME LA CONDUCCIÓN Y CONTROL JURÍDICO DE LA INVESTIGACIÓN DESDE SU INICIO.', '(texto: (ART: 3)**    Articulo 3.- Alcance)**', '185364'),
(2757, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO AL TEXTO ANALIZADO, ¿QUÉ FUNCIÓN CUMPLE LA POLICÍA NACIONAL DEL PERÚ RESPECTO AL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS?', 'DIRIGE LA INVESTIGACIÓN JUDICIAL A CARGO DEL PODER JUDICIAL.', 'PREVIENE, INVESTIGA Y COMBATE LA DELINCUENCIA EN GENERAL, Y REALIZA LA INVESTIGACIÓN DEL DELITO DE', 'SOLICITA DE MANERA EXCLUSIVA ÓRDENES DE ALLANAMIENTO EN INVESTIGACIONES DE EXTORSIÓN.', 'ELABORA Y EJECUTA SENTENCIAS EN CASOS DE EXTORSIÓN.', 'SUSTITUYE AL MINISTERIO PÚBLICO CUANDO ESTE SE DECLARE IMPEDIDO.', NULL, 'b', 'PREVIENE, INVESTIGA Y COMBATE LA DELINCUENCIA EN GENERAL, Y REALIZA LA INVESTIGACIÓN DEL DELITO', '(texto: (ART: 3)**    Articulo 3.- Alcance)**', '185365'),
(2758, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL DEBER DE LAS INSTITUCIONES O PERSONAS JURÍDICAS RELACIONADAS CON LOS SERVICIOS PÚBLICOS SEGÚN EL ARTÍCULO 3 DEL D. LEG 1611?', 'EJERCEN FUNCIONES DE CO-INVESTIGACIÓN DIRECTAMENTE CON EL MINISTERIO PÚBLICO.', 'SE ENCARGAN DE PROCESAR LAS DENUNCIAS DE EXTORSIÓN ANTES DE SU REMISIÓN FORMAL.', 'COLABORAN EN LA PROVISIÓN DE DOCUMENTOS, DATOS O INFORMACIONES RELEVANTES PARA LA PREVENCIÓN E', 'ACTÚAN COMO ASESORES TÉCNICOS EN LOS PROCEDIMIENTOS JUDICIALES DE EXTORSIÓN.', 'OTORGAN INMUNIDAD FUNCIONAL A LOS TESTIGOS DE CASOS DE EXTORSIÓN.', NULL, 'c', 'COLABORAN EN LA PROVISIÓN DE DOCUMENTOS, DATOS O INFORMACIONES RELEVANTES PARA LA', '(texto: (ART: 3)**    Articulo 3.- Alcance)**', '185366'),
(2759, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'IDENTIFIQUE LA AFIRMACIÓN INCORRECTA EN RELACIÓN AL ARTÍCULO 3 DEL D. LEG 1611:', 'EL MINISTERIO PÚBLICO CONTROLA LEGALMENTE LA INVESTIGACIÓN REALIZADA POR LA POLICÍA NACIONAL EN DELITOS', 'LA POLICÍA NACIONAL, EN MATERIA PROCESAL PENAL, INVESTIGA EL DELITO DE EXTORSIÓN BAJO LA CONDUCCIÓN DEL', 'LAS INSTITUCIONES RELACIONADAS CON SERVICIOS PÚBLICOS TIENEN UN DEBER DE COLABORACIÓN EN', 'LA POLICÍA NACIONAL PUEDE INICIAR Y CONDUCIR INVESTIGACIONES DE EXTORSIÓN DE MANERA AUTÓNOMA, SIN', 'EL MINISTERIO PÚBLICO ES TITULAR DE LA ACCIÓN PENAL Y DIRIGE LA INVESTIGACIÓN DESDE SU INICIO.', NULL, 'd', 'LA POLICÍA NACIONAL PUEDE INICIAR Y CONDUCIR INVESTIGACIONES DE EXTORSIÓN DE MANERA AUTÓNOMA,', '(texto: (ART: 3)**    Articulo 3.- Alcance)**', '185367'),
(2760, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES ACCIONES DE LA POLICÍA NACIONAL DEL PERÚ ESTÁ ESPECÍFICAMENTE ORIENTADA A LA PREVENCIÓN DE LA DELINCUENCIA EN ZONAS DE ALTO RIESGO, SEGÚN EL ARTÍCULO 4 DEL D.LEG 1611?', 'RONDAS O PATRULLAJES VEHICULARES, VIGILANCIA FIJA O MÓVIL DETERMINADA POR LA POLICÍA NACIONAL DEL PERÚ', 'CENTROS DE MEDIACIÓN POLICIAL PARA CONFLICTOS VECINALES', 'IMPLEMENTACIÓN DE CÁMARAS DE VIDEO VIGILANCIA A CARGO DE LAS MUNICIPALIDADES', 'ASIGNACIÓN DE FISCALES ANTIDROGAS POR DISTRITO', 'CONTROL DE DOCUMENTOS MIGRATORIOS EN PUESTOS FRONTERIZOS', NULL, 'a', 'RONDAS O PATRULLAJES VEHICULARES, VIGILANCIA FIJA O MÓVIL DETERMINADA POR LA POLICÍA NACIONAL', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185368'),
(2761, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN EL CONTEXTO DEL D.LEG 1611, ¿CUÁL DE LAS SIGUIENTES CIRCUNSTANCIAS HABILITA EXPRESAMENTE A LA POLICÍA NACIONAL PARA REALIZAR REGISTRO PERSONAL Y VEHICULAR EN OPERATIVOS DE CONTROL TERRITORIAL?', 'ANTE LA RESISTENCIA VERBAL DEL CONDUCTOR A UNA CONSULTA POLICIAL', 'CUANDO SE UTILICE MOTOCICLETA LINEAL CON DOS O MÁS OCUPANTES A BORDO', 'EN PRESENCIA DE MENORES DE EDAD EN EL VEHÍCULO', 'AL OBSERVAR PLACAS VEHICULARES DETERIORADAS', 'SI EL VEHÍCULO CIRCULA FUERA DEL HORARIO DE TOQUE DE QUEDA', NULL, 'b', 'CUANDO SE UTILICE MOTOCICLETA LINEAL CON DOS O MÁS OCUPANTES A BORDO', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185369'),
(2762, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL MARCO DEL ARTÍCULO 4 DEL D.LEG 1611, SI DURANTE UN CONTROL TERRITORIAL UN INDIVIDUO NO LOGRA ACREDITAR SU IDENTIDAD A PESAR DE LAS FACILIDADES BRINDADAS, ¿CUÁL ES EL SIGUIENTE PASO QUE LA POLICÍA PUEDE TOMAR?', 'DISPONER SU DETENCIÓN PREVENTIVA INMEDIATA POR FLAGRANCIA DELICTIVA', 'PERMITIRLE SEGUIR SU CAMINO PREVIA ADVERTENCIA VERBAL', 'CONDUCIRLO A LA DEPENDENCIA POLICIAL PARA EFECTOS DE IDENTIFICACIÓN Y VERIFICACIÓN DE REQUISITORIAS', 'SOLICITAR QUE FIRME UN ACTA DE COMPROMISO DE PRESENTACIÓN POSTERIOR', 'INICIAR UN PROCESO DE DEPORTACIÓN ADMINISTRATIVA', NULL, 'c', 'CONDUCIRLO A LA DEPENDENCIA POLICIAL PARA EFECTOS DE IDENTIFICACIÓN Y VERIFICACIÓN DE', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185370'),
(2763, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL TRATAMIENTO PROCESAL QUE OTORGA EL D.LEG 1611 A LOS CASOS EN LOS QUE DURANTE UN CONTROL SE DETECTA LA PRESENCIA DE DROGAS, ARMAS, DINERO U OBJETOS DE ORIGEN O DESTINO ILEGAL?', 'LA PERSONA PERMANECE RETENIDA HASTA QUE SE RESUELVA SU SITUACIÓN ADMINISTRATIVA', 'LA ACTUACIÓN POLICIAL PROSIGUE EN EL MARCO PROCESAL PENAL CORRESPONDIENTE', 'SÓLO SE SANCIONA ADMINISTRATIVAMENTE CON UNA MULTA', 'SE CONCEDE UN PLAZO MÁXIMO DE 24 HORAS PARA JUSTIFICAR LA TENENCIA', 'SE REDIRIGE EL CASO EXCLUSIVAMENTE A LAS UNIDADES ANTIDROGAS', NULL, 'b', 'LA ACTUACIÓN POLICIAL PROSIGUE EN EL MARCO PROCESAL PENAL CORRESPONDIENTE', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185371'),
(2764, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ DISPOSICIÓN ESPECÍFICA ESTABLECE EL ARTÍCULO 4 DEL D.LEG 1611 RESPECTO AL REGISTRO DE LA INFORMACIÓN PERSONAL Y TOMA DE MUESTRAS PARA IDENTIFICAR A UNA PERSONA NO IDENTIFICADA DURANTE UNA INTERVENCIÓN?', 'LA TOMA DE MUESTRAS SANGUÍNEAS ES OBLIGATORIA EN TODOS LOS CASOS', 'SOLAMENTE SE PERMITE EL REGISTRO ESCRITO DE DATOS PERSONALES SIN OTROS PROCEDIMIENTOS', 'SE REALIZA EL REGISTRO DE INFORMACIÓN PROPORCIONADA, IMPRESIONES DECADACTILARES, CARACTERÍSTICAS', 'LA IDENTIFICACIÓN SE LIMITA ÚNICAMENTE A LA COMPROBACIÓN VISUAL ANTE DOS TESTIGOS', 'SE NOTIFICA DIRECTAMENTE A LA FISCALÍA PARA LA VALIDACIÓN INMEDIATA DE LOS DATOS', NULL, 'c', 'SE REALIZA EL REGISTRO DE INFORMACIÓN PROPORCIONADA, IMPRESIONES DECADACTILARES,', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185372'),
(2765, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN RELACIÓN AL PATRULLAJE EN EL CIBERESPACIO PRESCRITO EN EL ARTÍCULO 4 DEL D.LEG 1611, ¿CUÁL ES EL ALCANCE PERMITIDO PARA LA POLICÍA NACIONAL DEL PERÚ?', 'INTERCEPTAR TODAS LAS COMUNICACIONES ELECTRÓNICAS SIN ORDEN JUDICIAL', 'UTILIZAR INSTRUMENTOS INFORMÁTICOS EN LÍNEA Y EN TIEMPO REAL, DENTRO DEL MARCO LEGAL, PARA ALERTAR Y', 'ACCEDER Y MODIFICAR BASES DE DATOS PRIVADAS EN SERVIDORES NACIONALES', 'LLEVAR A CABO CAMPAÑAS DE EDUCACIÓN VIRTUAL OBLIGATORIAS PARA USUARIOS DE INTERNET', 'REALIZAR BLOQUEOS SISTEMÁTICOS DE SITIOS WEB EXTRANJEROS SIN SUPERVISIÓN JUDICIAL', NULL, 'b', 'UTILIZAR INSTRUMENTOS INFORMÁTICOS EN LÍNEA Y EN TIEMPO REAL, DENTRO DEL MARCO LEGAL, PARA', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185373'),
(2766, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CÓMO DEBE PROCEDER LA POLICÍA NACIONAL DEL PERÚ EN CASO DE COMPROBAR UNA TASA DE ALCOHOLEMIA POSITIVA DURANTE UN OPERATIVO CONFORME AL ARTÍCULO 4 DEL D.LEG 1611?', 'LIBERAR AL INTERVENIDO TRAS LA TOMA DE MUESTRA Y REGISTRO DE DATOS', 'APLICAR ÚNICAMENTE UNA SANCIÓN PECUNIARIA Y DEJAR SIN EFECTO LA INTERVENCIÓN', 'CONTINUAR LA ACTUACIÓN EN EL MARCO DEL PROCESO PENAL SI LA EBRIEDAD TIPIFICA UN DELITO DE PELIGRO COMÚN', 'DERIVAR EL CASO A LA MUNICIPALIDAD CORRESPONDIENTE PARA TRÁMITE ADMINISTRATIVO', 'ORDENAR LA RETENCIÓN INDEFINIDA DEL VEHÍCULO', NULL, 'c', 'CONTINUAR LA ACTUACIÓN EN EL MARCO DEL PROCESO PENAL SI LA EBRIEDAD TIPIFICA UN DELITO DE', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185374'),
(2767, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ REQUISITOS ESTABLECE EL ARTÍCULO 4 DEL D.LEG 1611 PARA LA TOMA DE MUESTRAS DE VOZ DE INVESTIGADOS POR PRESUNTO DELITO DE EXTORSIÓN O CONEXOS?', 'LA TOMA ES VÁLIDA SÓLO CON LA PRESENCIA DE UN FISCAL SUPERIOR', 'DEBE REALIZARSE EN EL MARCO CONSTITUCIONAL Y CONFORME AL PROCEDIMIENTO REGLAMENTARIO DE LA DIRECCIÓN', 'SE EFECTÚA SÓLO EN CASOS DE DETENCIÓN EN FLAGRANCIA DELICTIVA', 'ES REQUISITO PREVIO UNA AUTORIZACIÓN FORMAL DE LA VÍCTIMA DEL DELITO', 'LA MUESTRA SÓLO PUEDE SER OBTENIDA POR ORDEN JUDICIAL CON MOTIVACIÓN EXPRESA', NULL, 'b', 'DEBE REALIZARSE EN EL MARCO CONSTITUCIONAL Y CONFORME AL PROCEDIMIENTO REGLAMENTARIO DE LA', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185375'),
(2768, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN CUANTO AL PLAZO DE RETENCIÓN POR CONTROL DE IDENTIDAD EN PREVENCIÓN DEL DELITO, ¿QUÉ DIRECTRIZ SEÑALA EL ARTÍCULO 4 DEL D.LEG 1611?', 'EL PLAZO ES DE 12 HORAS, SEGÚN CRITERIO POLICIAL DISCRECIONAL', 'NO PUEDE EXCEDER EL TIEMPO RAZONABLE PARA SUPERAR LA FALTA DE IDENTIFICACIÓN, EQUIVALENTE AL PREVISTO', 'SE ESTABLECE UN MÁXIMO DE 72 HORAS CON CONTROL JUDICIAL POSTERIOR', 'DEPENDE EXCLUSIVAMENTE DEL TIPO DE DELITO SOSPECHADO', 'EL PLAZO DE RETENCIÓN ES INDEFINIDO HASTA LOGRAR LA PLENA IDENTIFICACIÓN', NULL, 'b', 'NO PUEDE EXCEDER EL TIEMPO RAZONABLE PARA SUPERAR LA FALTA DE IDENTIFICACIÓN, EQUIVALENTE AL', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185376'),
(2769, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ALTERNATIVA RESUME ADECUADAMENTE LA FINALIDAD PRINCIPAL DE LAS ACCIONES PREVENTIVAS POLICIALES PREVISTAS EN EL ARTÍCULO 4 DEL D.LEG 1611 RESPECTO A LA DELINCUENCIA Y, EN PARTICULAR, LA EXTORSIÓN Y DELITOS CONEXOS?', 'GARANTIZAR LA RECAUDACIÓN DE MULTAS ADMINISTRATIVAS Y SANCIONES DISCIPLINARIAS', 'ASEGURAR LA INMEDIATEZ EN LA DETENCIÓN PREVENTIVA SIN CONTROL FISCAL', 'PREVENIR LA COMISIÓN DE DELITOS Y GARANTIZAR LA PAZ Y SEGURIDAD HUMANA EN ZONAS DE ALTO RIESGO', 'FORTALECER LA AUTONOMÍA MUNICIPAL EN MATERIA DE SEGURIDAD CIUDADANA', 'DESPLEGAR OPERACIONES MILITARES CONJUNTAS CON LAS FUERZAS ARMADAS', NULL, 'c', 'PREVENIR LA COMISIÓN DE DELITOS Y GARANTIZAR LA PAZ Y SEGURIDAD HUMANA EN ZONAS DE ALTO', '(texto: (ART: 4)**   Articulo 4.- Prevencion de la delincuencia)**', '185377'),
(2770, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 5 DEL D.LEG 1611, ¿A TRAVÉS DE CUÁLES MEDIOS PUEDE LA POLICÍA NACIONAL DEL PERÚ RECIBIR LA NOTICIA CRIMINAL RESPECTO AL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS?', 'SOLO MEDIANTE DENUNCIA ESCRITA DE LA VÍCTIMA O AGRAVIADO ANTE LA COMISARÍA.', 'POR DENUNCIA DE LA VÍCTIMA, COMUNICACIÓN DE AUTORIDAD, MEDIOS DE COMUNICACIÓN, ACCIÓN POPULAR, O', 'ÚNICAMENTE MEDIANTE INTERVENCIÓN DIRECTA DE UN FISCAL QUE CONSTATE EL DELITO EN FLAGRANCIA.', 'EXCLUSIVAMENTE POR INFORMACIÓN COMPROBADA A TRAVÉS DE VIGILANCIA ELECTRÓNICA Y SISTEMA DE', 'SOLO SI LA VÍCTIMA PRESENTA PRUEBAS MATERIALES ANTE EL JUZGADO PENAL COMPETENTE.', NULL, 'b', 'POR DENUNCIA DE LA VÍCTIMA, COMUNICACIÓN DE AUTORIDAD, MEDIOS DE COMUNICACIÓN, ACCIÓN', '(texto: (ART: 5)**    Articulo 5.- Noticia criminal)**', '185378'),
(2771, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'OBSERVE LAS OBLIGACIONES ESTABLECIDAS EN EL ARTÍCULO 5 DEL D.LEG 1611. SI LA POLICÍA NACIONAL DEL PERÚ TOMA CONOCIMIENTO DE UN DELITO DE EXTORSIÓN A TRAVÉS DE UNA FUENTE ANÓNIMA Y TRAS VERIFICAR LA NOTICIA, ¿QUÉ ACTUACIÓN LE CORRESPONDE REALIZAR SEGÚN DICHA NORMA?', 'INICIAR DE INMEDIATO LA DETENCIÓN DEL SOSPECHOSO Y ARCHIVAR EL CASO SI NO SE ENCUENTRA EVIDENCIA FÍSICA.', 'NOTIFICAR DIRECTAMENTE AL PODER JUDICIAL PARA QUE ESTE ORDENE LAS INVESTIGACIONES.', 'COMUNICAR POR LOS MEDIOS IDÓNEOS Y CÉLERES AL MINISTERIO PÚBLICO PARA LA CONDUCCIÓN DE LA', 'PUBLICAR LOS HECHOS EN LOS MEDIOS DE COMUNICACIÓN ANTES DE CUALQUIER INTERVENCIÓN FISCAL.', 'CUSTODIAR LA INFORMACIÓN OBTENIDA HASTA RECIBIR UNA ORDEN SUPERIOR ADMINISTRATIVA.', NULL, 'c', 'COMUNICAR POR LOS MEDIOS IDÓNEOS Y CÉLERES AL MINISTERIO PÚBLICO PARA LA CONDUCCIÓN DE LA', '(texto: (ART: 5)**    Articulo 5.- Noticia criminal)**', '185379'),
(2772, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SOBRE EL CONCEPTO DE NOTICIA CRIMINAL REFERIDO EN EL ARTÍCULO 5 DEL D.LEG 1611, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES ES CORRECTA RESPECTO A LA PROCEDENCIA Y TRATAMIENTO DE DICHA NOTICIA?', 'LA NOTICIA CRIMINAL SOLO SERÁ VÁLIDA SI PROVIENE DE UNA FUENTE PLENAMENTE IDENTIFICADA.', 'SI LA NOTICIA CRIMINAL PROVIENE DE UNA FUENTE ANÓNIMA, LA POLICÍA DEBE ABSTENERSE DE INICIAR CUALQUIER', 'CUALQUIER FUENTE, SEA ANÓNIMA O CLASIFICADA,  COMPROBADA ÉSTA, POR LA UNIDAD DE INVESTIGACIÓN POLICIAL', 'LAS NOTICIAS CRIMINALES RECIBIDAS A TRAVÉS DE MEDIOS DE COMUNICACIÓN DEBEN SER DESESTIMADAS POR', 'ÚNICAMENTE LA COMUNICACIÓN DE AUTORIDAD FACULTA A LA POLICÍA PARA INICIAR INVESTIGACIONES DE EXTORSIÓN.', NULL, 'c', 'CUALQUIER FUENTE, SEA ANÓNIMA O CLASIFICADA,  COMPROBADA ÉSTA, POR LA UNIDAD DE INVESTIGACIÓN', '(texto: (ART: 5)**    Articulo 5.- Noticia criminal)**', '185380'),
(2773, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿SEGÚN EL ARTÍCULO 6 DEL D.LEG 1611, CUÁL ES LA FINALIDAD PRINCIPAL DE LAS DILIGENCIAS URGENTES E IMPRESCINDIBLES REALIZADAS POR LA UNIDAD DE INVESTIGACIÓN POLICIAL EN EL MARCO DE UN DELITO DE EXTORSIÓN Y DELITOS CONEXOS?', 'PREVENIR LA FILTRACIÓN DE INFORMACIÓN SENSIBLE A LOS MEDIOS DE COMUNICACIÓN.', 'ASEGURAR LA CADENA DE CUSTODIA EXCLUSIVAMENTE DE BIENES PATRIMONIALES INCAUTADOS.', 'EVITAR LA PERMANENCIA DEL DELITO O LA PROLONGACIÓN DE SUS EFECTOS LESIVOS Y POSIBILITAR LA IDENTIFICACIÓN', 'GARANTIZAR EL DERECHO A LA DEFENSA DE LOS IMPLICADOS ANTES DEL INICIO FORMAL DE LA INVESTIGACIÓN FISCAL.', 'INCREMENTAR LA EFICIENCIA DE LA RECAUDACIÓN DE PRUEBAS MEDIANTE PROCEDIMIENTOS ADMINISTRATIVOS', NULL, 'c', 'EVITAR LA PERMANENCIA DEL DELITO O LA PROLONGACIÓN DE SUS EFECTOS LESIVOS Y POSIBILITAR LA', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185381'),
(2774, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN CASO DE RECOLECCIÓN DE REGISTROS DE VIDEOVIGILANCIA DURANTE LA INSPECCIÓN, ¿CÓMO DEBE PROCEDER LA POLICÍA DE ACUERDO AL TEXTO ANALIZADO?', 'SOLICITAR AUTORIZACIÓN JUDICIAL PREVIA A LA RECEPCIÓN DE LOS MISMOS.', 'PROCEDER A LA SOLICITUD Y RECEPCIÓN DOCUMENTADA, PARA SU RESPECTIVA VISUALIZACIÓN.', 'REQUERIR A LOS PARTICULARES LA ENTREGA VOLUNTARIA SIN NECESIDAD DE DEJAR CONSTANCIA ESCRITA.', 'SOLICITAR LA PRESENCIA DEL MINISTERIO PÚBLICO EN TODOS LOS CASOS PARA AUTENTICAR LA EVIDENCIA.', 'DESTRUIR CUALQUIER GRABACIÓN QUE NO SEA PERTINENTE PARA EVITAR VICIOS PROCESALES.', NULL, 'b', 'PROCEDER A LA SOLICITUD Y RECEPCIÓN DOCUMENTADA, PARA SU RESPECTIVA VISUALIZACIÓN.', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185382'),
(2775, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LAS ACTAS RELATIVAS A LAS DILIGENCIAS EFECTUADAS EN EL LUGAR DE LOS HECHOS, SEGÚN EL ARTÍCULO 6, DEBEN SER LEVANTADAS:', 'EN EL DESPACHO FISCAL INMEDIATAMENTE DESPUÉS DE LA INTERVENCIÓN POLICIAL.', 'DE MANERA CRONOLÓGICA Y COHERENTE, FIRMADAS EN EL MISMO LUGAR DE LOS HECHOS SALVO IMPEDIMENTO', 'SOLO DE MANERA DIGITAL Y BAJO FE NOTARIAL.', 'ÚNICAMENTE POR LOS JEFES DE LA UNIDAD POLICIAL SIN INVOLUCRAR A LOS INTERVINIENTES.', 'POSTERIOR AL TRASLADO DE LOS EFECTOS APREHENDIDOS, SIN NECESIDAD DE CRONOLOGÍA.', NULL, 'b', 'DE MANERA CRONOLÓGICA Y COHERENTE, FIRMADAS EN EL MISMO LUGAR DE LOS HECHOS SALVO', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185383'),
(2776, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ REQUISITO DEBEN CUMPLIR LAS VERSIONES EXPUSTAS POR LOS INTERVENIDOS PARA QUE MOTIVEN DILIGENCIAS INMEDIATAS DE CORROBORACIÓN?', 'SER MANIFESTADAS EN PRESENCIA OBLIGATORIA DEL FISCAL SUPERIOR.', 'HABER SIDO PRESTADAS LIBREMENTE, EN ESTADO NORMAL DE LAS FACULTADES PSÍQUICAS, Y HABIENDO SIDO', 'ESTAR GRABADAS EN AUDIO Y VIDEO CON FIRMA LEGALIZADA.', 'EXPRESARSE POR ESCRITO Y EN PRESENCIA DE TESTIGOS CIVILES.', 'CONTENER INFORMACIÓN SOBRE TODAS LAS ETAPAS DEL ILÍCITO PENAL.', NULL, 'b', 'HABER SIDO PRESTADAS LIBREMENTE, EN ESTADO NORMAL DE LAS FACULTADES PSÍQUICAS, Y HABIENDO', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185384'),
(2777, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ SUCEDE SI LAS DILIGENCIAS DE CORROBORACIÓN A LAS VERSIONES ESPONTÁNEAS RESULTAN POSITIVAS, SEGÚN LO EXPUESTO EN EL D.LEG 1611?', 'EL FISCAL PUEDE VALORAR ESTAS DILIGENCIAS PARA EFECTOS DE UNA POSIBLE CONFESIÓN SINCERA Y APLICACIÓN DE', 'LA POLICÍA ORDENA LA DETENCIÓN INMEDIATA DEL SOSPECHOSO SIN INTERVENCIÓN FISCAL.', 'SE ARCHIVAN LAS EVIDENCIAS COMO PRUEBAS IRRELEVANTES SI EL ACUSADO LO SOLICITA.', 'EL JUEZ DEBE NECESARIAMENTE ABSOLVER AL IMPLICADO.', 'LAS ACTAS SON REMITIDAS DIRECTAMENTE A LOS JUECES DE INVESTIGACIÓN PREPARATORIA PARA CONTROL DE', NULL, 'a', 'EL FISCAL PUEDE VALORAR ESTAS DILIGENCIAS PARA EFECTOS DE UNA POSIBLE CONFESIÓN SINCERA Y', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185385'),
(2778, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ DILIGENCIA URGENTE NO ESTÁ CONTEMPLADA EXPRESAMENTE EN EL ARTÍCULO 6 DEL D.LEG 1611?', 'EL LEVANTAMIENTO Y EMBALAJE DE MUESTRAS EN LA ESCENA DEL CRIMEN.', 'REGISTROS E INSPECCIONES DE VEHÍCULOS RELACIONADOS CON LOS HECHOS.', 'EL ASEGURAMIENTO MEDIANTE LACRADO DE EVIDENCIAS.', 'LA DESTRUCCIÓN INMEDIATA DE ELEMENTOS PROBATORIOS IRRELEVANTES.', 'IDENTIFICACIÓN Y ENTREVISTA DE TESTIGOS PRESENCIALES.', NULL, 'd', 'LA DESTRUCCIÓN INMEDIATA DE ELEMENTOS PROBATORIOS IRRELEVANTES.', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185386'),
(2779, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES AFIRMACIONES REFLEJA ADECUADAMENTE EL SENTIDO DE LA PERENNIZACIÓN DE LA ESCENA DE LOS HECHOS A TRAÉS DE MEDIOS DE SOPORTE FISICO O DIGITAL SEGÚN EL ARTÍCULO 6?', 'LA POLICÍA DEBE CERRAR EL ÁREA DEL DELITO DE MANERA INDEFINIDA HASTA DETERMINAR LA FINALIZACIÓN DE TODAS', 'INSPECCIÓN TÉCNICA POLICIAL. LEVANTAMIENTO Y RECOJO DE MUESTRAS E INDICIOS APROVECHABLES QUE', 'LA CADENA DE CUSTODIA SOLO APLICA A OBJETOS DE VALOR ECONÓMICO INCAUTADOS.', 'EL MINISTERIO PÚBLICO DEBE SUPERVISAR PRESENCIALMENTE TODA LA PERENNIZACIÓN.', 'LOS TESTIGOS SON RESPONSABLES DE REALIZAR LA PERENNIZACIÓN BAJO JURAMENTO.', NULL, 'b', 'INSPECCIÓN TÉCNICA POLICIAL. LEVANTAMIENTO Y RECOJO DE MUESTRAS E INDICIOS APROVECHABLES QUE', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185387'),
(2780, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿EL LEVANTAMIENTO DE LAS ACTAS EN FORMA CRONOLOGICAS Y DE MANERA COHERENTE, SUSCRIBIENDOLA QUIENES PARTICIPARON EN LAS RESPECTIVAS DILIGENCIAS, EN EL MISMO LUGAR DE LOS HECHOS SALVO IMPEDIMENTO DEBIDAMENTE ACREDITADO Y EXPRESADO?', 'SI POR RAZONES DE SEGURIDAD O CAUSAS AJENAS A LA VOLUNTAD DEL PERSONAL POLICIAL, NO ES POSIBLE LEVANTAR', 'LA DILIGENCIA SE ANULA AUTOMÁTICAMENTE POR INCUMPLIMIENTO DE FORMALIDAD.', 'SE TOMA COMO VÁLIDA CUALQUIER VERSIÓN ORAL DE LOS INTERVINIENTES, SIN NECESIDAD DE ACTA ESCRITA.', 'EL FISCAL COMPETENTE DEBE ASUMIR LA REDACCIÓN DE LAS ACTAS EN SU DESPACHO SIN INFORMACIÓN POLICIAL.', 'NO EXISTE SOLUCIÓN LEGALMENTE PREVISTA Y DEBE REPETIRSE LA DILIGENCIA EN OTRO MOMENTO.', NULL, 'a', 'SI POR RAZONES DE SEGURIDAD O CAUSAS AJENAS A LA VOLUNTAD DEL PERSONAL POLICIAL, NO ES POSIBLE', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185389'),
(2781, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA COMPETENCIA DE LA POLICÍA EN LAS PESQUISAS E INDAGACIONES URGENTES, CONFORME EL ARTÍCULO 6?', 'REALIZAR SOLO INDAGACIONES PRELIMINARES SIN ACTUACIÓN ALGUNA EN EL LUGAR DE LOS HECHOS.', 'LLEVAR A CABO PESQUISAS PARA IDENTIFICAR Y LOCALIZAR AUTORES, VÍCTIMAS, MEDIOS E INSTRUMENTOS DEL DELITO,', 'EXCLUSIVAMENTE PROTEGER LOS DERECHOS HUMANOS DE LOS IMPUTADOS DURANTE LA DILIGENCIA.', 'DEDICAR SUS FUNCIONES A LA ORGANIZACIÓN DE OPERATIVOS PREVENTIVOS FUERA DE LA ESCENA DEL DELITO.', 'REMITIR TODA SOSPECHA DIRECTAMENTE AL PODER JUDICIAL SIN DILIGENCIA PREVIA.', NULL, 'b', 'LLEVAR A CABO PESQUISAS PARA IDENTIFICAR Y LOCALIZAR AUTORES, VÍCTIMAS, MEDIOS E INSTRUMENTOS', '(texto: (ART: 6)**    Articulo 6.- Diligencias urgentes e imprescindibles por la comision de delito de extorsion y delitos', '185390'),
(2782, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LOS SIGUIENTES MÉTODOS UTILIZADOS PARA LA IDENTIFICACIÓN DE PRESUNTOS AUTORES Y PARTÍCIPES DE DELITOS DE EXTORSIÓN Y CONEXOS ES EXPRESAMENTE MENCIONADO EN EL ARTÍCULO 7 DEL D.LEG 1611?', 'RECONOCIMIENTO DE HUELLAS DACTILARES A TRAVÉS DE INTELIGENCIA ARTIFICIAL.', 'EXÁMENES PERICIALES PAPILOSCÓPICOS, MORFOLÓGICOS, FACIALES, CINÉTICOS (GAIT), BIOMÉTRICOS O', 'ENTREVISTAS PSICOLÓGICAS A FAMILIARES DEL IMPUTADO.', 'INTERCEPTACIÓN DE LLAMADAS TELEFÓNICAS SIN AUTORIZACIÓN JUDICIAL.', 'ANÁLISIS DE SOLVENCIA ECONÓMICA DEL IMPUTADO.', NULL, 'b', 'EXÁMENES PERICIALES PAPILOSCÓPICOS, MORFOLÓGICOS, FACIALES, CINÉTICOS (GAIT), BIOMÉTRICOS O', '(texto: (ART: 7)**    Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185391'),
(2783, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 7 DEL D. LEG. 1611, ¿QUÉ TECNOLOGÍA PUEDE SER EMPLEADA PARA LA UBICACIÓN DE LOS PRESUNTOS AUTORES O PARTÍCIPES DE DELITOS DE EXTORSIÓN Y CONEXOS?', 'DISPOSITIVOS DE RASTREO EMBEBIDOS ÚNICAMENTE EN VEHÍCULOS AUTOMOTORES.', 'APLICATIVOS INFORMÁTICOS PARA RASTREO O SEGUIMIENTO EN INTERNET, REDES SOCIALES U OTRAS PLATAFORMAS.', 'SISTEMA DE VIGILANCIA SATELITAL DE USO AGRÍCOLA.', 'MONITOREO DE CUENTAS BANCARIAS EN EL EXTRANJERO EXCLUSIVAMENTE.', 'GRABACIONES DE CONVERSACIONES REALIZADAS POR TESTIGOS SIN CONSENTIMIENTO.', NULL, 'b', 'APLICATIVOS INFORMÁTICOS PARA RASTREO O SEGUIMIENTO EN INTERNET, REDES SOCIALES U OTRAS', '(texto: (ART: 7)**    Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185392'),
(2784, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUIÉNES ESTÁN OBLIGADOS A OTORGAR PRIORIDAD AL REQUERIMIENTO DE LOCALIZACIÓN Y GEOLOCALIZACIÓN EN LAS INVESTIGACIONES DE EXTORSIÓN Y DELITOS CONEXOS, SEGÚN EL ARTÍCULO 7?»ÚNICAMENTE LA POLICÍA NACIONAL DEL PERÚ.', 'LAS AUTORIDADES POLICIALES, FISCALES Y JUDICIALES, ASÍ COMO LOS CONCESIONARIOS DE SERVICIOS PÚBLICOS DE', 'EL MINISTERIO DE DEFENSA Y LA FISCALÍA DE LA NACIÓN.', 'SOLO LAS AUTORIDADES JUDICIALES CON COMPETENCIA EN MATERIA PENAL.', 'LAS EMPRESAS DE TRANSPORTE PÚBLICO Y TAXISTAS REGISTRADOS.', NULL, NULL, 'a', 'LAS AUTORIDADES POLICIALES, FISCALES Y JUDICIALES, ASÍ COMO LOS CONCESIONARIOS DE SERVICIOS', '(texto: (ART: 7)**    Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185393'),
(2785, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN VIRTUD DEL ARTÍCULO 7 DEL D. LEG. 1611, ¿QUÉ ROL CUMPLE LA INTELIGENCIA ARTIFICIAL EN LA IDENTIFICACIÓN DE PARTÍCIPES DE DELITOS DE EXTORSIÓN?', 'PUEDE UTILIZARSE COMO FORMA IDÓNEA DE COMPROBACIÓN JUNTO A OTROS EXÁMENES ESPECIALIZADOS.', 'SOLO ES APLICABLE PARA EL RECONOCIMIENTO FACIAL EN TIEMPO REAL FUERA DEL PROCESO PENAL.', 'ES EXCLUSIVA PARA LA EVALUACIÓN DE ANTECEDENTES FINANCIEROS.', 'NO TIENE NINGÚN ROL REGULADO EN LA NORMA.', 'ES EMPLEADA SOLO PARA LA VIGILANCIA MASIVA SIN CONTROL NI REGISTRO.', NULL, 'a', 'PUEDE UTILIZARSE COMO FORMA IDÓNEA DE COMPROBACIÓN JUNTO A OTROS EXÁMENES ESPECIALIZADOS.', '(texto: (ART: 7)**    Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185394'),
(2786, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL TEXTO DEL ARTÍCULO 7, ¿QUÉ ELEMENTO ES OBJETO DE LOCALIZACIÓN O UBICACIÓN MEDIANTE MEDIOS TECNOLÓGICOS EN PROCESOS DE EXTORSIÓN Y DELITOS CONEXOS?', 'SOLO LOS PRESUNTOS AUTORES Y PARTÍCIPES.', 'PRESUNTOS AUTORES O PARTÍCIPES, VÍCTIMAS E INSTRUMENTOS, MEDIOS, EFECTOS U OBJETO MATERIAL DEL DELITO.', 'TESTIGOS PROTEGIDOS Y ABOGADOS DEFENSORES.', 'FUNCIONARIO PÚBLICO QUE NO COLABORA CON LA INVESTIGACIÓN.', 'TODA PERSONA VINCULADA ADMINISTRATIVA O CONTRACTUALMENTE A LA VÍCTIMA.', NULL, 'b', 'PRESUNTOS AUTORES O PARTÍCIPES, VÍCTIMAS E INSTRUMENTOS, MEDIOS, EFECTOS U OBJETO MATERIAL', '(texto: (ART: 7)**    Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185395'),
(2787, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ DISPOSICIONES ADICIONALES MENCIONA EL ARTÍCULO 7 EN RELACIÓN A LOS CONCESIONARIOS DE LOS SERVICIOS PÚBLICOS DE TELECOMUNICACIONES?', 'PUEDEN RETRASAR LA ENTREGA DE INFORMACIÓN SI INVOCAN RAZONES DE SEGURIDAD NACIONAL.', 'OTORGAN PRIORIDAD AL REQUERIMIENTO CONFORME AL D. LEG. 1182, NORMAS MODIFICATORIAS Y REGLAMENTARIAS.', 'ESTÁN EXONERADOS DE RESPONDER REQUERIMIENTOS JUDICIALES.', 'ÚNICAMENTE DEBEN COLABORAR SI EL DELITO ESTÁ TIPIFICADO COMO CRIMEN ORGANIZADO.', 'NO SE REGULAN SUS CONDUCTAS EN PROCESOS PENALES.', NULL, 'b', 'OTORGAN PRIORIDAD AL REQUERIMIENTO CONFORME AL D. LEG. 1182, NORMAS MODIFICATORIAS Y', '(texto: (ART: 7)**    Articulo 7.- Identificacion y localizacion de presuntos autores y participes)**', '185396'),
(2788, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿EN CUÁL DE LOS SIGUIENTES SUPUESTOS LAS ENTIDADES PÚBLICAS Y PRIVADAS ESTÁN OBLIGADAS A COOPERAR CON LA AUTORIDAD POLICIAL EN INVESTIGACIONES SOBRE EXTORSIÓN, SEGÚN EL ARTÍCULO 9 DEL D. LEG. 1611?', 'SOLO EN PRESENCIA DE ORDEN JUDICIAL DEBIDAMENTE MOTIVADA.', 'ÚNICAMENTE CUANDO EXISTA FLAGRANCIA DELICTIVA RELACIONADA CON EXTORSIÓN O DELITOS CONEXOS.', 'SIEMPRE QUE LA AUTORIDAD POLICIAL LO SOLICITE, SIN NECESIDAD DE NINGÚN TIPO DE ACTO PROCESAL.', 'SOLO CUANDO LA FISCALÍA ASÍ LO REQUIERA, CON INDEPENDENCIA DE LA FLAGRANCIA.', 'EN CUALQUIER INVESTIGACIÓN CRIMINAL, INDEPENDIENTEMENTE DEL TIPO DELICTIVO.', NULL, 'b', 'ÚNICAMENTE CUANDO EXISTA FLAGRANCIA DELICTIVA RELACIONADA CON EXTORSIÓN O DELITOS CONEXOS.', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185400'),
(2789, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ PROCEDIMIENTO DEBE OBSERVARSE PARA OBTENER INFORMACIÓN DE ABONADOS DE TELEFONÍA MÓVIL UTILIZADOS EN LA COMISIÓN DE DELITOS DE EXTORSIÓN SEGÚN EL CITADO ARTÍCULO?', 'LA ENTREGA DEBE REALIZARSE EXTRAJUDICIALMENTE SIN PROCEDIMIENTO ESTABLECIDO.', 'LA INFORMACIÓN SE PROPORCIONA MEDIANTE UN PROCEDIMIENTO DEBIDAMENTE ESTABLECIDO EN EL CÓDIGO', 'SE REQUIERE APROBACIÓN DEL MINISTERIO DEL INTERIOR.', 'SOLO PUEDE SOLICITARSE BAJO SUPERVISIÓN DE LA CONTRALORÍA GENERAL DE LA REPÚBLICA.', 'ES SUFICIENTE UNA SOLICITUD INFORMAL POR PARTE DE LA POLICÍA NACIONAL.', NULL, 'b', 'LA INFORMACIÓN SE PROPORCIONA MEDIANTE UN PROCEDIMIENTO DEBIDAMENTE ESTABLECIDO EN EL', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185401'),
(2790, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES ENTIDADES NO SE MENCIONA EXPRESAMENTE EN EL ARTÍCULO 9 COMO HABILITADA PARA INTEGRAR EL MECANISMO PÚBLICO-PRIVADO DE INTERCAMBIO DE INFORMACIÓN?', 'SUPERINTENDENCIA DE BANCA, SEGUROS Y AFP.', 'MINISTERIO PÚBLICO.', 'CONTRALORÍA GENERAL DE LA REPÚBLICA.', 'MINISTERIO DE JUSTICIA Y DERECHOS HUMANOS.', 'SUPERINTENDENCIA NACIONAL DE ADUANAS Y DE ADMINISTRACIÓN TRIBUTARIA.', NULL, 'd', 'MINISTERIO DE JUSTICIA Y DERECHOS HUMANOS.', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185403'),
(2791, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN EL CONTEXTO DEL ARTÍCULO 9, ¿QUIÉN PUEDE ARTICULAR Y ESTABLECER PROCEDIMIENTOS PARA EL FUNCIONAMIENTO DEL MECANISMO PÚBLICO-PRIVADO PARA EL INTERCAMBIO DE INFORMACIÓN?', 'LA CONTRALORÍA GENERAL DE LA REPÚBLICA.', 'LA UNIDAD DE INTELIGENCIA FINANCIERA DEL PERÚ (UIF-PERÚ).', 'EL PODER JUDICIAL.', 'EL MINISTERIO DE ECONOMÍA Y FINANZAS.', 'EL TRIBUNAL CONSTITUCIONAL.', NULL, 'b', 'LA UNIDAD DE INTELIGENCIA FINANCIERA DEL PERÚ (UIF-PERÚ).', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185405'),
(2792, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿A QUÉ DEBER ESTÁN SUJETOS LOS PARTICIPANTES, REPRESENTANTES Y PERSONAL DE ENTIDADES QUE TOMAN CONOCIMIENTO DE INFORMACIÓN INTERCAMBIADA EN EL MECANISMO PÚBLICO-PRIVADO?', 'DEBER DE PUBLICIDAD IRRESTRICTA.', 'DEBER DE COLABORACIÓN CON ORGANISMOS INTERNACIONALES.', 'DEBER DE RESERVA DE INFORMACIÓN CONFORME AL ARTÍCULO 12 DE LA LEY N° 27693.', 'DEBER EXCLUSIVO DE ARCHIVO.', 'DEBER DE NOTIFICAR AL CONGRESO DE LA REPÚBLICA.', NULL, 'c', 'DEBER DE RESERVA DE INFORMACIÓN CONFORME AL ARTÍCULO 12 DE LA LEY N° 27693.', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185406'),
(2793, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL ROL DE LA UIF-PERÚ RESPECTO AL MECANISMO PÚBLICO-PRIVADO DE LUCHA CONTRA LA EXTORSIÓN Y DELITOS CONEXOS SEGÚN EL ARTÍCULO 9?', 'SUPERVISAR A LAS ENTIDADES BANCARIAS EXCLUSIVAMENTE.', 'EJERCER LA ARTICULACIÓN DEL MECANISMO Y ESTABLECER MEDIANTE RESOLUCIÓN LOS ALCANCES Y', 'EMITIR SENTENCIAS VINCULANTES.', 'LIDERAR LAS INVESTIGACIONES JUDICIALES DE EXTORSIÓN.', 'DETERMINAR LA SANCIÓN PENAL DE LOS INVESTIGADOS.', NULL, 'b', 'EJERCER LA ARTICULACIÓN DEL MECANISMO Y ESTABLECER MEDIANTE RESOLUCIÓN LOS ALCANCES Y', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185407'),
(2794, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL ARTÍCULO 9, ¿CUÁLES SUJETOS PRIVADOS PUEDEN INTEGRARSE AL MECANISMO PÚBLICO-PRIVADO DE INTERCAMBIO DE INFORMACIÓN?', 'ÚNICAMENTE BANCOS NACIONALES.', 'ÚNICAMENTE LAS PERSONAS JURÍDICAS INSCRITAS ANTE SUNAT.', 'LOS SUJETOS OBLIGADOS A INFORMAR A LA UIF-PERÚ EN MATERIA DE PREVENCIÓN DEL LAVADO DE ACTIVOS Y', 'CUALQUIER CIUDADANO INTERESADO EN LA PREVENCIÓN DEL DELITO.', 'SOLAMENTE EMPRESAS DE TELECOMUNICACIONES.', NULL, 'c', 'LOS SUJETOS OBLIGADOS A INFORMAR A LA UIF-PERÚ EN MATERIA DE PREVENCIÓN DEL LAVADO DE ACTIVOS', '(texto: (ART: 9)**    Articulo 9.- Apoyo de las entidades publicas y privadas)**', '185409'),
(2795, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA FUNCIÓN PRINCIPAL DE LA POLICÍA NACIONAL DEL PERÚ EN LA INVESTIGACIÓN DEL DELITO DE EXTORSIÓN Y SUS DELITOS CONEXOS SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', 'TOMAR DECISIONES AUTÓNOMAS SOBRE MEDIDAS RESTRICTIVAS DE DERECHOS DURANTE LA INVESTIGACIÓN.', 'DIRIGIR Y CONDUCIR ÍNTEGRAMENTE LA INVESTIGACIÓN FISCAL Y POLICIAL.', 'RECOMENDAR LA ESTRATEGIA DE LA INVESTIGACIÓN AL FISCAL Y EJECUTAR ACCIONES TÉCNICAS NECESARIAS BAJO', 'EMITIR RESOLUCIONES JUDICIALES FRENTE A HALLAZGOS RELEVANTES.', 'DICTAR MEDIDAS CAUTELARES ADMINISTRATIVAS SOBRE BIENES INCAUTADOS.', NULL, 'c', 'RECOMENDAR LA ESTRATEGIA DE LA INVESTIGACIÓN AL FISCAL Y EJECUTAR ACCIONES TÉCNICAS', '(texto: (ART: 10)**   Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185410'),
(2796, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'FRENTE A LA INCAUTACIÓN DE VEHÍCULOS O BIENES INMUEBLES VINCULADOS A DELITOS DE EXTORSIÓN Y CONEXOS, ¿QUÉ PROCEDIMIENTO SE DEBE SEGUIR SEGÚN EL ARTÍCULO 10?', 'REMITIR EL BIEN DE MANERA INMEDIATA A LA MUNICIPALIDAD CORRESPONDIENTE.', 'LA INCAUTACIÓN DEBE SER CONFIRMADA POR UN JUEZ A SOLICITUD DEL FISCAL EN UN PLAZO DE 48 HORAS DESDE LA', 'ESPERAR AUTORIZACIÓN EXPRESA DEL PROPIETARIO LEGÍTIMO ANTES DE INCAUTAR EL BIEN.', 'ORDENAR LA DESTRUCCIÓN DEL BIEN INCAUTADO EN LAS PRIMERAS 24 HORAS.', 'DISPONER LA INMEDIATA VENTA PÚBLICA DEL BIEN INCAUTADO PARA EVITAR SU DETERIORO.', NULL, 'b', 'LA INCAUTACIÓN DEBE SER CONFIRMADA POR UN JUEZ A SOLICITUD DEL FISCAL EN UN PLAZO DE 48 HORAS', '(texto: (ART: 10)**   Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185411'),
(2797, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO CON EL ARTÍCULO 10 DEL D.LEG 1611, ¿QUÉ LÍMITE IMPONE LA ENTREGA DE INFORMACIÓN POR PARTE DE ENTIDADES PÚBLICAS O PRIVADAS REQUERIDAS POR LA POLICÍA NACIONAL DEL PERÚ?', 'QUE LA INFORMACIÓN SEA REMITIDA SÓLO EN FORMATO FÍSICO CON FIRMAS LEGALIZADAS.', 'QUE LA INFORMACIÓN REQUERIDA EXCLUYA LO REFERENTE AL SECRETO BANCARIO, LA RESERVA TRIBUTARIA, EL', 'QUE LA INFORMACIÓN SÓLO PUEDA SER ENTREGADA EN PRESENCIA DEL TITULAR DEL DATO.', 'QUE TODA INFORMACIÓN DEBE SER DIVULGADA PÚBLICAMENTE INMEDIATAMENTE DESPUÉS DE SU ENTREGA.', 'QUE LAS ENTIDADES PUEDEN NEGARSE A TODO REQUERIMIENTO POLICIAL JUSTIFICANDO CARGA LABORAL EXCESIVA.', NULL, 'b', 'QUE LA INFORMACIÓN REQUERIDA EXCLUYA LO REFERENTE AL SECRETO BANCARIO, LA RESERVA', '(texto: (ART: 10)**   Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185414'),
(2798, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LOS BIENES INCAUTADOS POR LA POLICÍA NACIONAL DEL PERÚ, ¿QUÉ CARACTERÍSTICA DEBEN CUMPLIR PARA SER INCAUTADOS SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', 'SOLO PUEDEN INCAUTARSE SI HAN SIDO ROBADOS DE UNA DEPENDENCIA ESTATAL.', 'DEBEN SER BIENES AUTOMOTORES Y, EN CASO DE COMPUTADORAS, SÓLO SI SON NUEVAS.', 'PUEDEN SER INCAUTADOS SI SE DUDA DE LA LEGALIDAD DE SU ORIGEN Y SE ENCUENTRAN VINCULADOS A DELITOS', 'ES IRRELEVANTE LA DOCUMENTACIÓN DEL BIEN A INCAUTAR.', 'PUEDEN SER DECOMISADOS POR CUALQUIER AGENTE PÚBLICO SIN REQUISITOS ADICIONALES.', NULL, 'c', 'PUEDEN SER INCAUTADOS SI SE DUDA DE LA LEGALIDAD DE SU ORIGEN Y SE ENCUENTRAN VINCULADOS A', '(texto: (ART: 10)**   Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185416'),
(2799, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ACCIÓN PUEDE TOMAR LA POLICÍA NACIONAL DEL PERÚ RESPECTO A CENTROS DE OPERACIONES ILÍCITAS CONFORME AL ARTÍCULO 10 DEL D.LEG 1611?', 'SOLICITAR SU CLAUSURA ADMINISTRATIVA POR PARTE DE LA MUNICIPALIDAD.', 'EJECUTAR VIGILANCIA Y SEGUIMIENTO PARA IDENTIFICACIÓN, INDIVIDUALIZACIÓN Y DOCUMENTACIÓN DE LAS', 'REMITIR UN INFORME PRO FORMA SIN INTERVENCIÓN DIRECTA.', 'ORDENAR JUDICIALMENTE EL DESALOJO INMEDIATO.', 'APROPIAR TEMPORALMENTE LOS BIENES DEL LUGAR CON FINES RECAUDATORIOS.', NULL, 'b', 'EJECUTAR VIGILANCIA Y SEGUIMIENTO PARA IDENTIFICACIÓN, INDIVIDUALIZACIÓN Y DOCUMENTACIÓN DE LAS', '(texto: (ART: 10)**   Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185417'),
(2800, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CUANDO LA POLICÍA REQUIERE INFORMACIÓN DE REGISTROS OFICIALES O PRIVADOS DURANTE LA INVESTIGACIÓN, ¿CUÁL ES EL PROCEDIMIENTO CORRECTO SEGÚN EL ARTÍCULO 10 DEL D.LEG 1611?', 'SOLICITAR SIEMPRE INFORMACIÓN EN DOCUMENTOS EN PAPEL FIRMADOS ANTE NOTARIO.', 'LOS REQUERIDOS DEBEN SUMINISTRAR DATOS SIN DILACIÓN A TRAVÉS DE SOPORTES MAGNÉTICOS O ELECTRÓNICOS,', 'EXIGIR LA PRESENCIA FÍSICA DE TODOS LOS TITULARES EN LA ENTREGA DE INFORMACIÓN.', 'COORDINAR LA ENTREGA CON LA DEFENSORÍA DEL PUEBLO.', 'PERMITIR QUE LA ENTIDAD REQUERIDA ENTREGUE LOS DATOS EN UN PLAZO NO MENOR A 30 DÍAS HÁBILES.', NULL, 'b', 'LOS REQUERIDOS DEBEN SUMINISTRAR DATOS SIN DILACIÓN A TRAVÉS DE SOPORTES MAGNÉTICOS O', '(texto: (ART: 10)**   Articulo 10.- Sobre la investigacion de la Policia Nacional del Peru)**', '185419'),
(2801, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL NIVEL DE FUERZA A EMPLEAR ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TECNICAS DE INTERVENCION, Y SE REFIERE A:', 'SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS', 'EL EFECTIVO POLICIAL DEBE TENER EN CUENTA EL COMPORTAMIENTO DE LA PERSONA A INTERVENIR, QUE PUEDE SER', 'ESTA INTERVENCIÓN SE DEBE INICIAR CON LA VERBALIZACIÓN.', 'LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL', 'FORMAR EL CONO DE SEGURIDAD, TOMANDO UNA DISTANCIA APROXIMADA DE DOS BRAZOS EXTENDIDOS, QUE IMPIDA AL', NULL, 'd', 'LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185988'),
(2802, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- SE HAN CONSIDERADO DOS SITUACIONES QUE SE PRESENTAN EN FORMA COTIDIANA EN EL SERVICIO POLICIAL: LA PRIMERA, CON FINES DE IDENTIFICACIÓN, Y LA SEGUNDA, CUANDO SE TRATE DE UN PRESUNTO INFRACTOR. SIN EMBARGO ...:', 'UNA NO ES EXCLUYENTE DE LA OTRA.', 'UNA ES EXCLUYENTE DE LA OTRA.', 'UNA NO ES INCLUYENTE DE LA OTRA.', 'UNA ES INCLUYENTE DE LA OTRA.', 'EN OCASIONES AMBAS SITUACIONES NO SE CUMPLEN.', NULL, 'a', 'UNA NO ES EXCLUYENTE DE LA OTRA.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185989'),
(2803, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA PERCEPCIÓN DEL RIESGO ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN, DONDE SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS DESCONOCIDAS, CALLEJONES, EDIFICACIONES, ILUMINACIÓN, ENTRE OTROS) QUE PUEDAN REPRESENTAR UN RIESGO PARA LA INTEGRIDAD DEL PERSONAL POLICIAL O DE TERCEROS, ASÍ COMO EL POSIBLE....:', 'APOYO POLICIAL.', 'INCREMENTO DE LAS FUERZAS AMIGAS.', 'EVENTO DE FUGA DE LA PERSONA INTERVENIDA.', 'APOYO DE OTRAS PERSONAS AL INFRACTOR.', 'ATAQUE TERRORISTA.', NULL, 'd', 'APOYO DE OTRAS PERSONAS AL INFRACTOR.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185990'),
(2804, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL NIVEL DE FUERZA A EMPLEAR ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TECNICAS DE INTERVENCION, EN LA CUAL, LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL PERSONAL POLICIAL EMPLEARÁ LA FUERZA, DE ACUERDO.....:', 'A LA FUERZA QUE SE PUEDA EJERCER SOBRE LA PERSONA A INTERVENIR.', 'A LA EDAD DEL EFECTIVO POLICIAL.', 'A LA CONDICIÓN FISICA DEL EFECTIVO POLICIAL.', 'A LA EDAD DE LA PERSONA A INTERVENIR.', 'AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR.', NULL, 'e', 'AL NIVEL DE RESISTENCIA DE LA PERSONA A INTERVENIR.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185991'),
(2805, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- RESPECTO A LA INTERVENCIÓN CON FINES DE IDENTIFICACIÓN, ES CONVENIENTE TENER EN CONSIDERACIÓN LOS SIGUIENTES ASPECTOS:', 'IDENTIFICARSE (SALUDO, GRADO, APELLIDOS, UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO', 'PUEDEN PRESENTARSE DURANTE EL PATRULLAJE O A MÉRITO DE UNA COMUNICACIÓN RADIAL O TELEFÓNICA DE LA', 'ESTAS INTERVENCIONES SON LAS QUE REPRESENTAN UN MAYOR NIVEL DE RIESGO PARA LOS EFECTIVOS POLICIALES', 'ES DE SUMA IMPORTANCIA QUE LA INFORMACIÓN QUE RECABEN LOS EFECTIVOS QUE VAN A INTERVENIR SEA DETALLADA', 'EL POLICÍA DEBE IDENTIFICARSE COMO TAL EXPRESANDO EN VOZ ALTA: ¡ALTO POLICÍA!', NULL, 'a', 'IDENTIFICARSE (SALUDO, GRADO, APELLIDOS, UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185992'),
(2806, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ASPECTOS IMPORTANTES SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN?', 'EL NÚMERO DE EFECTIVOS.', 'EL CONO DE SEGURIDAD.', 'LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD.', 'EL NIVEL DE FUERZA A EMPLEAR', 'LA LÍNEA IMAGINARIA QUE DIVIDE LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD', NULL, 'd', 'EL NIVEL DE FUERZA A EMPLEAR', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185993'),
(2807, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INDIQUE LA ALTERNATIVA QUE FORMA PARTE DE LOS PASOS QUE SE DEBEN TENER EN CUENTA AL MOMENTO DE UNA INTERVENCIÓN A UN PRESUNTO INFRACTOR:', 'CULMINADA LA INTERVENCIÓN SIN NOVEDAD, EL POLICÍA DE CONTACTO (P1) AGRADECERÁ SU COLABORACIÓN,', 'EFECTUAR PREGUNTAS RELACIONADAS A LOS DATOS CONSIGNADOS EN EL DOCUMENTO DE IDENTIDAD CON LA', 'SOLICITARLE SUS DOCUMENTOS DE IDENTIFICACIÓN PERSONAL, PERMANECIENDO SIEMPRE EN UNA ACTITUD VIGILANTE,', 'AL VERIFICAR LOS DOCUMENTOS, HACERLO EN UNA POSICIÓN TAL QUE NO OBSTACULICE EL DOMINIO VISUAL,', 'HACERLE SABER EL MOTIVO DE LA INTERVENCIÓN, POR EJEMPLO: ES USTED SOSPECHOSO DE .....; O HA COMETIDO EL', NULL, 'e', 'HACERLE SABER EL MOTIVO DE LA INTERVENCIÓN, POR EJEMPLO: ES USTED SOSPECHOSO DE .....; O HA', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185994'),
(2808, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR, INDIQUE EL ENUNCIADO CORRECTO:', 'ESTAS INTERVENCIONES SON LAS QUE REPRESENTAN UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL.', 'SE INDIVIDUALIZA CLARAMENTE A LA PERSONA A INTERVENIR (VESTIMENTA, CARACTERÍSTICAS FÍSICAS, SEXO, ETC.)', 'SE RECIBE LOS DOCUMENTOS CON LA MANO QUE NO PORTE EL ARMA DE FUEGO; ESTO PARA PERMITIR QUE ANTE UNA', 'IDENTIFICARSE (GRADO, APELLIDOS Y UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO DE LA', 'SE SOLICITA SUS DOCUMENTOS DE IDENTIFICACIÓN PERSONAL, PERMANECIENDO SIEMPRE EN UNA ACTITUD VIGILANTE,', NULL, 'a', 'ESTAS INTERVENCIONES SON LAS QUE REPRESENTAN UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185995'),
(2809, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR, INDIQUE EL ENUNCIADO CORRECTO.', 'SE FORMAR EL CONO DE SEGURIDAD, TOMANDO UNA DISTANCIA APROXIMADA DE DOS BRAZOS EXTENDIDOS, QUE IMPIDA', 'SE INDIVIDUALIZA CLARAMENTE A LA PERSONA A INTERVENIR (VESTIMENTA, CARACTERÍSTICAS FÍSICAS, SEXO, ETC.)', 'ESTA INTERVENCION SON LA QUE REPRESENTA UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL.', 'IDENTIFICARSE (GRADO, APELLIDOS Y UNIDAD EN LA QUE PRESTA SERVICIO), HACIÉNDOLE CONOCER EL MOTIVO DE LA', 'SE SOLICITA SUS DOCUMENTOS DE IDENTIFICACIÓN PERSONAL, PERMANECIENDO SIEMPRE EN UNA ACTITUD VIGILANTE,', NULL, 'c', 'ESTA INTERVENCION SON LA QUE REPRESENTA UN MAYOR NIVEL DE RIESGO PARA EL PERSONAL POLICIAL.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185996'),
(2810, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INDIQUE LA ALTERNATIVA QUE NO FORMA PARTE DE LOS PASOS QUE SE DEBEN TENER EN CUENTA AL MOMENTO DE UNA INTERVENCIÓN A UN PRESUNTO INFRACTOR:', 'EL POLICÍA DEBE IDENTIFICARSE COMO TAL EXPRESANDO EN VOZ ALTA: ¡ALTO POLICÍA!', '¡LEVANTE LAS MANOS, MÍREME!', 'HACERLE SABER EL MOTIVO DE LA INTERVENCIÓN, POR EJEMPLO: ES USTED SOSPECHOSO DE ..... O HA COMETIDO EL', 'INDICARLE QUE SE LE VA A IDENTIFICAR Y REGISTRAR, PARA QUE ASÍ PUEDA COLABORAR CON LA INTERVENCIÓN. DE SER', 'CULMINADA LA INTERVENCIÓN SIN NOVEDAD, EL POLICÍA DE CONTACTO (P1) AGRADECERÁ SU COLABORACIÓN,', NULL, 'e', 'CULMINADA LA INTERVENCIÓN SIN NOVEDAD, EL POLICÍA DE CONTACTO (P1) AGRADECERÁ SU', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185997'),
(2811, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- COMPLETE CORRECTAMENTE RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR: UNA ACCIÓN QUE AYUDARÁ A MINIMIZAR LOS RIESGOS ES (.................). ELLO NOS PERMITIRÁ UBICAR CUALQUIER TIPO DE AMENAZA (ARMA U OBJETO). ESTA ACCIÓN SE EFECTÚA EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO VERBAL, DESDE LA LÍNEA IMAGINARIA QUE DIVIDE EL ÁREA DE SEGURIDAD Y LA DE RIESGO.', 'EFECTUAR UN REGISTRO CORPORAL DEL INTERVENIDO.', 'EFECTUAR UN ALLANAMIENTO AL DOMICILIO DEL INTERVENIDO.', 'EFECTUAR UN REGISTRO AL DOMICILIO DEL INTERVENIDO.', 'EFECTUAR UN REGISTRO PERSONAL DEL INTERVENIDO.', 'EFECTUAR UN REGISTRO VISUAL DEL INTERVENIDO.', NULL, 'e', 'EFECTUAR UN REGISTRO VISUAL DEL INTERVENIDO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185998'),
(2812, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- COMPLETE CORRECTAMENTE RESPECTO A LA INTERVENCIÓN A UN PRESUNTO INFRACTOR: UNA ACCIÓN QUE AYUDARÁ A MINIMIZAR LOS RIESGOS ES EFECTUAR UN REGISTRO VISUAL DEL INTERVENIDO. ELLO NOS PERMITIRÁ UBICAR CUALQUIER TIPO DE AMENAZA (ARMA U OBJETO). ESTA ACCIÓN SE EFECTÚA (...................), DESDE LA LÍNEA IMAGINARIA QUE DIVIDE EL ÁREA DE SEGURIDAD Y LA DE RIESGO.', 'EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL POLICÍA QUE REALIZA EL CONTACTO VERBAL.', 'EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO', 'DESPUÉS QUE SE REALIZA EL CONTACTO VISUAL.', 'EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA DISTANTE AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO', 'EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA LEJOS AL EFECTIVO POLICIAL QUE REALIZA EL CONTACTO', NULL, 'a', 'EN EL MOMENTO QUE EL INTERVENIDO SE ENCUENTRA FRENTE AL POLICÍA QUE REALIZA EL CONTACTO', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '185999'),
(2813, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. ELIJA LA ALTERNATIVA QUE SE RELACIONE CON LA POSICIÓN DE PIE:', 'ES RECOMENDABLE EMPLEAR ESTA TÉCNICA CUANDO EL INFRACTOR SE ENCUENTRA EN UN AMBIENTE ABIERTO.', 'ESTA POSICIÓN ES RECOMENDABLE CUANDO EN EL LUGAR DE LA INTERVENCIÓN EXISTE UN MURO, PARED, ETC. DONDE', 'EFECTUADO EL CONTACTO VISUAL E INICIADA LA VERBALIZACIÓN, SE ORDENARÁ AL INTERVENIDO COLOCARSE FRENTE A', 'ESTA POSICIÓN ES LA MÁS SEGURA, REPRESENTA MENOS RIESGO O POSIBILIDAD DE REACCIÓN DEL INFRACTOR. ES LA', 'UTILIZANDO LA VERBALIZACIÓN SE ORDENARÁ AL INTERVENIDO UBICARSE FRENTE A LOS EFECTIVOS POLICIALES, A UNA', NULL, 'b', 'ESTA POSICIÓN ES RECOMENDABLE CUANDO EN EL LUGAR DE LA INTERVENCIÓN EXISTE UN MURO, PARED,', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186000'),
(2814, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ASPECTOS IMPORTANTES SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN?', 'EL NÚMERO DE EFECTIVOS POLICIALES.', 'LA ACTITUD DE LA PERSONA A SER INTERVENIDA.', 'LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD.', 'LA LÍNEA IMAGINARIA QUE DIVIDE LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD.', 'EL CONO DE SEGURIDAD.', NULL, 'b', 'LA ACTITUD DE LA PERSONA A SER INTERVENIDA.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186001'),
(2815, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. SI DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN TENDIDO O ECHADO, EL INTERVENIDO SE TORNA VIOLENTO, EL EFECTIVO POLICIAL DE CONTACTO SE ALEJARA RÁPIDAMENTE DE ÉL, RETORNANDO A SU ÁREA DE SEGURIDAD EMPUÑANDO SU ARMA, Y REINICIANDO LA (...............) PARA RETOMAR EL PROCEDIMIENTO.', 'INTERVENCIÓN.', 'VERBALIZACIÓN.', 'TÉCNICA DE CONDUCCIÓN.', 'TÉCNICA DE INTERVENCIÓN.', 'SECUENCIA DE INTERVENCIÓN.', NULL, 'b', 'VERBALIZACIÓN.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186002'),
(2816, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. SI DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN TENDIDO O ECHADO, EL INTERVENIDO SE TORNA VIOLENTO, EL (.................) SE ALEJARA RÁPIDAMENTE DE ÉL, RETORNANDO A SU ÁREA DE SEGURIDAD EMPUÑANDO SU ARMA, Y REINICIANDO LA VERBALIZACIÓN PARA RETOMAR EL PROCEDIMIENTO.', 'POLICÍA DE CONTACTO.', 'INTERVENIDO.', 'EFECTIVO POLICIAL QUE INTERVIENE.', 'EFECTIVO POLICIAL DE SEGURIDAD.', 'EFECTIVO POLICIAL DE APOYO.', NULL, 'a', 'POLICÍA DE CONTACTO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186003'),
(2817, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA PERCEPCIÓN DEL RIESGO ES UNO DE LOS ASPECTOS IMPORTANTES QUE SE TIENEN QUE TENER EN CUENTA EN LAS TECNICAS DE INTERVENCION, Y SE REFIERE A:', 'SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS', 'EL EFECTIVO POLICIAL DEBE TENER EN CUENTA EL COMPORTAMIENTO DE LA PERSONA A INTERVENIR, QUE PUEDE SER', 'INTERVENCIONES CON ARMA DE FUEGO.', 'LUEGO DE UNA APRECIACIÓN DE LA SITUACIÓN Y LAS CIRCUNSTANCIAS QUE SE PRESENTAN EN LA INTERVENCIÓN, EL', 'EL POLICÍA DEBE IDENTIFICARSE COMO TAL EXPRESANDO EN VOZ ALTA: !ALTO POLICÍA!', NULL, 'a', 'SE DEBE CONSIDERAR LAS CARACTERÍSTICAS DEL LUGAR DE LA INTERVENCIÓN (UBICACIÓN, ESTRUCTURAS', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186004'),
(2818, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN DE RODILLAS, EFECTUADO EL CONTACTO VISUAL E INICIADA LA VERBALIZACIÓN, SE ORDENARÁ AL INTERVENIDO COLOCARSE FRENTE A LOS POLICÍAS, A UNA DISTANCIA (............), FORMANDO EL TRIÁNGULO DE SEGURIDAD; SE LE INDICA QUE LEVANTE LOS BRAZOS, CON LAS MANOS TOTALMENTE ALEJADAS UNA DE OTRA Y LOS DEDOS SEPARADOS.', 'DE 10 METROS.', 'DE 5 METROS.', 'DE UN METRO.', 'DE OCHO METROS.', 'QUE PERMITA DOMINAR LA SITUACIÓN.', NULL, 'e', 'QUE PERMITA DOMINAR LA SITUACIÓN.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186005'),
(2819, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN A PERSONAS EN LA VÍA POR EFECTIVOS POLICIALES A PIE.- INTERVENCIÓN A UN PRESUNTO INFRACTOR: PARA EFECTUAR EL ARRESTO, EL EFECTIVO POLICIAL PUEDE UTILIZAR BÁSICAMENTE TRES POSICIONES, LAS CUALES SON: DE PIE, DE RODILLAS, Y TENDIDO O ECHADO. DURANTE LA EJECUCIÓN DEL PROCEDIMIENTO DEL ARRESTO EN LA POSICIÓN DE RODILLAS, LUEGO DE COLOCARLE LAS GRILLETES SE PROCEDERÁ ....:', 'A LA VERBALIZACIÓN.', 'AL REGISTRO MINUCIOSO DEL INFRACTOR.', 'A LA CONDUCCIÓN INMEDIATA DEL INFRACTOR.', 'A LEERLE SUS DERECHOS AL INFRACTOR.', 'A IDENTIFICAR AL INFRACTOR.', NULL, 'b', 'AL REGISTRO MINUCIOSO DEL INFRACTOR.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186006'),
(2820, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA POLICÍA DE SEGURIDAD EN LA POSICIÓN DE TENDIDO O ECHADO DEBE VERBALIZAR PARA OBTENER INFORMACIÓN Y NO PERMITIR QUE EL INTERVENIDO SE CONCENTRE EN:', 'PLANIFICAR UNA RESPUESTA VIOLENTA CONTRA SU INTEGRIDAD FÍSICA.', 'PLANIFICAR SU FUGA.', 'SU FAMILIA.', 'PLANIFICAR UNA RESPUESTA VIOLENTA CONTRA LA ACCIÓN DEL POLICÍA DE CONTACTO.', 'PLANIFICAR UNA RESPUESTA PACÍFICA CONTRA LA ACCIÓN DEL POLICÍA DE SEGURIDAD.', NULL, 'd', 'PLANIFICAR UNA RESPUESTA VIOLENTA CONTRA LA ACCIÓN DEL POLICÍA DE CONTACTO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186007'),
(2821, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LAS TÉCNICAS DE INTERVENCIÓN, EN CASO QUE LA INTERVENCIÓN SEA EJECUTADA POR DOS POLICIAS A PIE, ÉSTOS DEBEN FORMAR EN LO POSIBLE UN (.....................), EN CUYA BASE DEBEN UBICARSE LOS POLICÍAS INTERVENTORES, Y EN EL VÉRTICE O PUNTO MEDIO PROYECTADO DEL TRIÁNGULO.', 'TRIÁNGULO DE RESPUESTA.', 'TRIÁNGULO DE SEGURIDAD.', 'LÍNEA IMAGINARIA.', 'TRIÁNGULO IMAGINARIO.', 'ÁREA DE SEGURIDAD.', NULL, 'b', 'TRIÁNGULO DE SEGURIDAD.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186008'),
(2822, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'AL SER COMUNICADO DE UNA INTERVENCIÓN EN INMUEBLES O EN OTROS LUGARES QUE AMERITEN DESPLAZARSE POR UNA ZONA NO RECONOCIDA E INSEGURA, SE DEBE UTILIZAR LOS PRINCIPIOS DEL PENSAMIENTO TÁCTICO PARA EVALUAR LAS POSIBLES ÁREAS DE RIESGO. SE DEBEN ANTICIPAR LAS SITUACIONES PELIGROSAS Y MANTENERSE LISTOS PARA DEFENDERSE. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'INTERVENCIÓN EN INMUEBLES: INGRESO.', 'INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS.', 'INTERVENCIÓN EN INMUEBLES: RECONOCIMIENTO.', 'INTERVENCIÓN EN INMUEBLES: PASADIZOS.', 'INTERVENCIÓN EN INMUEBLES: ESCALERAS.', NULL, 'b', 'INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186009'),
(2823, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SE DEBE TENER SIEMPRE PRESENTE QUE POR MÁS INFORMACIÓN QUE SE OBTENGA DEL INMUEBLE, LOS AMBIENTES INTERIORES CONSTITUYEN ZONAS DE RIESGO PERMANENTE. ESTAS ZONAS SON CONTROLADAS Y CONVERTIDAS EN ÁREAS SEGURAS UNA POR UNA. OTRO ASPECTO A CONSIDERAR ES EL DISEÑO Y MATERIAL EMPLEADOS EN SU CONSTRUCCIÓN, ELLO CONLLEVA UN TRABAJO PROFESIONAL ALTAMENTE COORDINADO, DONDE PRIME LA SEGURIDAD COMO NORMA BÁSICA Y SE LA EJECUTE CON SIGILO, DINAMISMO, DESTREZA Y CONTROL EMOCIONAL. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'INTERVENCIÓN EN INMUEBLES: INGRESO.', 'INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS.', 'INTERVENCIÓN EN INMUEBLES: RECONOCIMIENTO.', 'INTERVENCIÓN EN INMUEBLES: PASADIZOS.', 'INTERVENCIÓN EN INMUEBLES: ESCALERAS.', NULL, 'c', 'INTERVENCIÓN EN INMUEBLES: RECONOCIMIENTO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186010'),
(2824, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN CASO QUE LA INTERVENCIÓN SEA EJECUTADA POR DOS POLICÍAS A PIE, ÉSTOS DEBEN FORMAR EN LO POSIBLE UN TRIÁNGULO DE SEGURIDAD, EN CUYA BASE DEBEN UBICARSE:', 'LAS VÍCTIMAS.', 'LOS VEHÍCULOS POLICIALES.', 'LOS PRESUNTOS INFRACTORES.', 'LOS VEHÍCULOS DE LOS PRESUNTOS INFRACTORES.', 'LOS POLICÍAS INTERVENTORES.', NULL, 'e', 'LOS POLICÍAS INTERVENTORES.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186011'),
(2825, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DENTRO DE UN INMUEBLE EL CONTROL DE UNA ESCALERA ES UNA ACCIÓN DE GRAN RIESGO Y PELIGRO. LA COORDINACIÓN, COMUNICACIÓN Y COOPERACIÓN SON ABSOLUTAMENTE NECESARIAS. LA TÉCNICA A EMPLEARSE SE DEBERÁ ACONDICIONAR AL TIPO, ESTRUCTURA Y UBICACIÓN ESPECÍFICA DE LA ESCALERA, TENIENDO ESPECIAL CUIDADO EN LOS DESCANSOS. SI SE TIENE HERRAMIENTAS DE OBSERVACIÓN DEBERÁN SER EMPLEADAS. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'INTERVENCIÓN EN INMUEBLES: CONFORMACIÓN DE LOS EQUIPOS.', 'INTERVENCIÓN EN INMUEBLES: DESPLAZAMIENTOS.', 'INTERVENCIÓN EN INMUEBLES: INTERVENCIÓN EN EQUIPO.', 'INTERVENCIÓN EN INMUEBLES: PASADIZOS.', 'INTERVENCIÓN EN INMUEBLES: ESCALERAS.', NULL, 'e', 'INTERVENCIÓN EN INMUEBLES: ESCALERAS.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186012'),
(2826, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- RECONOCIMIENTO.- ¿CUÁL ES EL MAYOR PROBLEMA EN LA INTERVENCIÓN EN INMUEBLES?', 'LA EXISTENCIA DE MASCOTAS.', 'EL TIPO DE INMUEBLE.', 'EL CERCO PERIMÉTRICO EXTERIOR.', 'LOS PUNTOS DE ENTRADA O INGRESO.', 'EL CERCO PERIMÉTRICO INTERIOR.', NULL, 'd', 'LOS PUNTOS DE ENTRADA O INGRESO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186013'),
(2827, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LA ALTERNATIVA QUE SE RELACIONE CON LA SIGUIENTE TÉCNICA DE INGRESO A INMUEBLES: EL PERONAL POLICIAL INTERVINIENTES SE DEBEN UBICAR A AMBOS LADOS DE LA PUERTA, ORIENTANDO SUS ARMAS HACIA ÉSTA. EL MÁS CARACTERIZADO SEÑALA CUÁNDO HAY QUE MOVERSE. RECORDAR: EL QUE INGRESE PRIMERO DEBERÁ CUBRIR LA PARTE DE LA HABITACIÓN QUE GENERALMENTE ESTÁ DEL LADO DE LAS BISAGRAS.', 'INGRESO EN X.', 'INGRESO EN J.', 'INGRESO POR EL LADO LARGO.', 'INGRESO DINÁMICO.', 'INGRESO POR EL LADO CORTO.', NULL, 'a', 'INGRESO EN X.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186014'),
(2828, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LOS TIPOS DE INGRESO, QUE PUEDE APLICAR UN EFECTIVO PNP AL MOMENTO QUE PARTICIPA EN LA INTERVENCIÓN A UN INMUEBLE:', 'INGRESO DINÁMICO, INGRESO EN Y, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO,', 'INGRESO DINÁMICO, INGRESO EN X, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO,', 'INGRESO DINÁMICO, INGRESO EN X, INGRESO EN G, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO,', 'INGRESO DINÁMICO, INGRESO EN PEINE, INGRESO EN X, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL', 'INGRESO RÁPIDO, INGRESO EN X, INGRESO EN G, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO CORTO,', NULL, 'b', 'INGRESO DINÁMICO, INGRESO EN X, INGRESO EN J, INGRESO POR EL LADO LARGO, INGRESÓ POR EL LADO', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186015'),
(2829, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LA ALTERNATIVA QUE SE RELACIONE CON LA SIGUIENTE TÉCNICA DE INGRESO A INMUEBLES: SE ENTIENDE POR LADO LARGO, LA MAYOR EXTENSIÓN DE PARED EN LA QUE ESTÁ LA PUERTA; LOS DOS EFECTIVOS POLICIALES ESTÁN EN EL MISMO LADO DE LA PARED; EL PRIMER EFECTIVO POLICIAL DEBE ASEGURARSE QUE LA PUERTA NO ESTÉ CERRADA O TRANCADA.', 'INGRESO EN X.', 'INGRESO EN J.', 'INGRESO POR EL LADO LARGO.', 'INGRESO DINÁMICO.', 'INGRESO POR EL LADO CORTO.', NULL, 'c', 'INGRESO POR EL LADO LARGO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186016'),
(2830, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ASPECTOS IMPORTANTES SE TIENEN QUE TENER EN CUENTA EN LAS TÉCNICAS DE INTERVENCIÓN?', 'EL NÚMERO DE EFECTIVOS POLICIALES', 'EL CONO DE SEGURIDAD.', 'LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD.', 'LA LÍNEA IMAGINARIA QUE DIVIDE LA ZONA DE RIESGO Y LA ZONA DE SEGURIDAD.', 'LA PERCEPCIÓN DEL RIESGO.', NULL, 'e', 'LA PERCEPCIÓN DEL RIESGO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186017'),
(2831, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿BAJO QUÉ CIRCUNSTANCIAS SE PUEDE QUEBRANTAR LOS PRINCIPIOS DE DERECHO NACIONAL E INTERNACIONAL QUE REGULAN LA RESPUESTA A UNA CRISIS?', 'EN SITUACIÓN PÚBLICA DE EMERGENCIA.', 'EN GRAVE SITUACIÓN PÚBLICA DE EMERGENCIA.', 'EN GRAVE SITUACIÓN PÚBLICA DE EMERGENCIA QUE JUSTIFIQUE LOS MEDIOS EMPLEADOS.', 'BAJO NINGUNA CIRCUNSTANCIA.', 'CUANDO ESTÁ EN RIESGO LA PROPIEDAD PÚBLICA Y PRIVADA.', NULL, 'd', 'BAJO NINGUNA CIRCUNSTANCIA.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186018'),
(2832, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CON FRECUENCIA LOS EFECTIVOS POLICIALES SON LESIONADOS POR ALGO QUE NO ANTICIPARON, NO RESPONDIERON NI ESTABAN MENTALMENTE PREPARADOS PARA ENFRENTAR;. EL SIGUIENTE ENUNCIADO CORRESPONDE AL:', 'NIVEL DE REACCIÓN.', 'NIVEL DE SEGURIDAD.', 'NIVEL DE ALERTA MÁXIMA.', 'NIVEL DE DISTRACCIÓN.', 'NIVEL DE ATENCIÓN.', NULL, 'e', 'NIVEL DE ATENCIÓN.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186019'),
(2833, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DEBEN GARANTIZAR UNA ALTA PROFESIONALIZACIÓN, INDIVIDUAL Y COLECTIVA, INCIDIENDO EN ASPECTOS IMPORTANTES PARA EL DESARROLLO DE LA FUNCIÓN POLICIAL COMO SON: USO DE LA FUERZA, ARMAS DE FUEGO, TÉCNICAS DE INTERVENCIÓN POLICIAL, TÁCTICAS DEFENSIVAS NO LETALES, CONTROL FÍSICO DE INTERVENIDOS, ÉTICA EN LA FUNCIÓN POLICIAL. ESTA INSTRUCCIÓN SE DEBE MANTENER EN LOS DIFERENTES NIVELES EDUCATIVOS. TAMBIÉN SE DEBE GARANTIZAR UNA EVALUACIÓN REAL SOSTENIDA QUE PERMITA APRECIAR LA CALIFICACIÓN DE LA APTITUD Y ACTITUD PARA CUMPLIR CON LA FUNCIÓN POLICIAL. EL PÁRRAFO ANTERIOR SE REFIERE A:', 'USO DE ARMAS DE FUEGO.', 'LOS PLANES Y PROGRAMAS DE LA INSTITUCIÓN POLICIAL.', 'EL PLANEAMIENTO OPERATIVO DE LOS SERVICIOS POLICIALES.', 'LA INSTRUCCIÓN BÁSICA POLICIAL.', 'LOS PLANES Y PROGRAMAS DEL SISTEMA EDUCATIVO POLICIAL.', NULL, 'e', 'LOS PLANES Y PROGRAMAS DEL SISTEMA EDUCATIVO POLICIAL.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186020'),
(2834, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'VERIFICAR QUE EL PERSONAL ESTÉ ADECUADAMENTE EQUIPADO. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: COMUNICACIÓN.', 'ANTES DE LA EJECUCIÓN DE LAS OPERACIONES.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: APARIENCIA.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: EMPLEO DE LA FUERZA.', NULL, 'c', 'ANTES DE LA EJECUCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186021'),
(2835, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'A QUE NIVEL DE ALERTA CORRESPONDE EL SIGUIENTE ENUNCIADO: SE DISTRAE CON LO QUE ESTÁ SUCEDIENDO A SU ALREDEDOR, LO QUE PUEDE SER OCASIONADO POR EL CANSANCIO O LA CREENCIA DE QUE NO HAY POSIBILIDAD DE PROBLEMAS.', 'NIVEL DE ATENCIÓN.', 'NIVEL DE SEGURIDAD.', 'NIVEL DE DISTRACCIÓN.', 'NIVEL DE ALERTA MÁXIMA.', 'NIVEL DE REACCIÓN.', NULL, 'c', 'NIVEL DE DISTRACCIÓN.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186022'),
(2836, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LAS  EMOCIONES  COMO  LA  CÓLERA,  LA  IRA,  LA  COMPASIÓN,  EL  MIEDO,  ENTRE  OTRAS,  SON  ESTADOS  DE  ÁNIMO QUE INFLUYEN DIRECTAMENTE EN EL ACCIONAR DEL PERSONAL POLICIAL. ESTE ENUNCIADO ESTÁ RELACIONADO A:', 'VERBALIZACIÓN.', 'USO DE LA FUERZA.', 'MANEJO DE EQUIPO.', 'CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL.', 'ENTRENAMIENTO FÍSICO.', NULL, 'd', 'CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186023'),
(2837, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- INDIQUE LA ALTERNATIVA QUE SE RELACIONE CON LA SIGUIENTE TÉCNICA DE INGRESO A INMUEBLES: UBICADOS A UN SOLO LADO DE LA PUERTA O NIVEL DE LA PARED; ES NECESARIO ADOPTAR UNA POSICIÓN CÓMODA Y SEGURA, PUES SE ESTÁ PRESUMIENDO QUE AL DETECTAR UNA AMENAZA SE TENDRÁ QUE EMPLEAR EL ARMA DE FUEGO PARA NEUTRALIZARLE O CONTROLARLA; AMBOS EFECTIVOS POLICIALES DEBERÁN ALEJARSE DE LOS NIVELES DEL MARCO CENTRAL O PARED, PARA EVITAR QUE UNA PERSONA ESCONDIDA DETRÁS DE ELLOS LES PUEDA ARREBATAR EL ARMA.', 'INGRESO EN X.', 'INGRESO EN J.', 'INGRESO POR EL LADO LARGO.', 'INGRESO DINÁMICO.', 'INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL).', NULL, 'e', 'INGRESO POR BARRIDA O GANADA DE ÁNGULO (CORTE PASTEL).', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186024'),
(2838, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA DISTRIBUCIÓN TÁCTICA EN EL MANEJO DE CRISIS: ¿POR DÓNDE INGRESAN O SALEN LAS PERSONAS INVOLUCRADAS?', 'POR EL CORDÓN EXTERIOR.', 'POR EL PUNTO DE CONTROL ANTERIOR.', 'POR EL PUNTO DE ENCUENTRO.', 'POR EL PUNTO DE CONTROL POSTERIOR.', 'POR EL CORDÓN INTERIOR.', NULL, 'c', 'POR EL PUNTO DE ENCUENTRO.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186025'),
