(2843, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- DESPLAZAMIENTOS.- INDIQUE LA ALTERNATIVA QUE COMPLETE CORRECTAMENTE EL SIGUIENTE ENUNCIADO: DESPLAZARSE A TRAVÉS DE LA RUTA MÁS SEGURA Y CORTA, BUSCANDO LA PROTECCIÓN DE ABRIGOS (PARAPETOS) SUCESIVOS Y EVITANDO EXPONERSE A RIESGOS INNECESARIOS, ESPECIALMENTE EN ......:', 'ÁREAS SEGURAS.', 'ÁREAS CONFLICTIVAS.', 'ÁREAS LARGAS.', 'ÁREAS CORTAS.', 'ÁREAS LIBRES.', NULL, 'e', 'ÁREAS LIBRES.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186030'),
(2844, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL: ¿DE QUÉ DEPENDERÁ SU NIVEL DE ALERTA?', 'DE SU CONTROL DE EMOCIONES E INTELIGENCIA EMOCIONAL.', 'DE SU PREPARACION MENTAL.', 'DE SU CAPACIDAD DE ANTICIPACIÓN AL PELIGRO.', 'DEL CONOCIMIENTO DE LA SITUACIÓN PREEXISTENTE.', 'DEL CONOCIMIENTO DE LAS ACCIONES DEL ENEMIGO.', NULL, 'c', 'DE SU CAPACIDAD DE ANTICIPACIÓN AL PELIGRO.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186031'),
(2845, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS ALTERNATIVAS SE RELACIONA CON UN NIVEL DE SEGURIDAD?', 'EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA.', 'CUANDO EL PELIGRO SE MANTIENE POR UN TIEMPO PROLONGADO O EL EFECTIVO POLICIAL ENFRENTA UN PELIGRO PARA', 'ES EL NIVEL DE ALERTA QUE USTED DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO.', 'SE DISTRAE CON LO QUE ESTÁ SUCEDIENDO A SU ALREDEDOR, LO QUE PUEDE SER OCASIONADO POR EL CANSANCIO O', 'HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO. SIN EMBARGO, EL ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y', NULL, 'e', 'HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO. SIN EMBARGO, EL ENTRENAMIENTO, EXPERIENCIA,', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186032'),
(2846, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS ALTERNATIVAS SE RELACIONA CON EL NIVEL DE ALERTA, NIVEL DE ATENCIÓN?', 'CUANDO EL PELIGRO SE MANTIENE POR UN TIEMPO PROLONGADO O EL EFECTIVO POLICIAL ENFRENTA UN PELIGRO PARA', 'HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO, SIN EMBARGO SU ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y', 'SU ESTADO MENTAL NO ESTÁ PREPARADO PARA UN EVENTUAL ENFRENTAMIENTO, AUMENTANDO SU PROPIA', 'EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA.', 'ES EL NIVEL DE ALERTA QUE EL PERSONAL POLICIAL DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO,', NULL, 'e', 'ES EL NIVEL DE ALERTA QUE EL PERSONAL POLICIAL DEBE TENER EN TODO MOMENTO CUANDO ESTÁ', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186033'),
(2847, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INTERVENCIÓN EN INMUEBLES.- ESCALERAS.- ELIJA LA ALTERNATIVA QUE COMPLETE CORRECTAMENTE EL SIGUIENTE ENUNCIADO: EXISTE MAYOR RIESGO EN CONTROLAR UNA ESCALERA (.....................).', 'HACIA ABAJO.', 'HACIA ARRIBA.', 'CARACOL.', 'MARINERO.', 'DE METAL.', NULL, 'b', 'HACIA ARRIBA.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186034'),
(2848, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS ALTERNATIVAS SE RELACIONA CON EL NIVEL DE ALERTA, NIVEL DE REACCIÓN POSITIVA?', 'EN ESTE ESTADO SUS OJOS PUEDEN VER LA AMENAZA, PERO SU MENTE NO ESTARÁ PREPARADA PARA SUMINISTRAR LAS', 'EL NIVEL DE SEGURIDAD DISMINUYE LOS RIESGOS DE USTED Y SU EQUIPO. SI SON SORPRENDIDOS SE ENCONTRARÁN', 'HAY CONCIENCIA DE LA EXISTENCIA DE UN PELIGRO, SIN EMBARGO SU ENTRENAMIENTO, EXPERIENCIA, EDUCACIÓN Y', 'ES EL NIVEL DE ALERTA QUE USTED DEBE TENER EN TODO MOMENTO CUANDO ESTÁ PATRULLANDO.', 'EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA.', NULL, 'e', 'EL RIESGO ES REAL Y LA REACCIÓN DEBE SER INSTANTÁNEA.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186035'),
