(2860, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL MANEJO DE UNA CRISIS INDIQUE: A FALTA DE UN NEGOCIADOR PROFESIONAL DE LA POLICÍA ¿QUIÉN DEBE ESTAR A CARGO DE LAS NEGOCIACIONES?', 'EL EFECTIVO POLICIAL MÁS ANTIGUO.', 'EL RESPONSABLE DEL GRUPO', 'EL EFECTIVO POLICIAL QUE REÚNA LAS CONDICIONES PARA DESEMPEÑARSE COMO TAL.', 'EL EFECTIVO POLICIAL CON MÁS EXPERIENCIA.', 'UN REPRESENTANTE DE LA DEFENSORÍA DEL PUEBLO.', NULL, 'c', 'EL EFECTIVO POLICIAL QUE REÚNA LAS CONDICIONES PARA DESEMPEÑARSE COMO TAL.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186047'),
(2861, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA GUÍA PARA NEGOCIADORES NO ENTRENADOS INDIQUE QUE ES LO QUE NO SE DEBE HACER CON EL CAUSANTE:', 'IDENTIFICARSE CON SU NOMBRE, SIN GRADO.', 'NOMBRAR A UN SEGUNDO NEGOCIADOR.', 'ELABORAR EL PLAN DE CONTINGENCIA ANTE UNA POSIBLE RENDICIÓN.', 'TRANSMITIR CON LA VOZ SENTIMIENTOS DE COMPRENSIÓN, AMISTAD, CALIDEZ Y RESPETO.', 'PREGUNTAR POR SUS EXIGENCIAS.', NULL, 'e', 'PREGUNTAR POR SUS EXIGENCIAS.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186048'),
(2862, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LA GUÍA PARA NEGOCIADORES NO ENTRENADOS INDIQUE: ¿QUÉ ES LO QUE NO SE DEBE HACER CON EL CAUSANTE?', 'SUGERIR PERIÓDICAMENTE QUE DEBE DETENER O ACABAR CON ESTA SITUACIÓN.', 'PRESENTARSE COMO EL QUE VA A TOMAR LAS DECISIONES.', 'DISTRAER AL CAUSANTE CUANDO ESTÉ POR CUMPLIRSE UN PLAZO DE TIEMPO FIJADO.', 'TRANSMITIR CON LA VOZ SENTIMIENTOS DE COMPRENSIÓN, AMISTAD, CALIDEZ Y RESPETO.', 'REACCIONAR CON SENSIBILIDAD ANTE LAS EMOCIONES DEL CAUSANTE.', NULL, 'b', 'PRESENTARSE COMO EL QUE VA A TOMAR LAS DECISIONES.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186049'),
(2863, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE EXISTIR DETENIDOS, LESIONADOS O MUERTOS, COMUNICAR DE INMEDIATO A SUS FAMILIARES. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'DESPUÉS DE LA EJECUCIÓN DE LAS OPERACIONES.', 'MANTENIMIENTO DEL ORDEN PUBLICO: INTERVENCIÓN OPORTUNA.', 'MANTENIMIENTO DEL ORDEN PUBLICO: COMUNICACIÓN', 'MANTENIMIENTO DEL ORDEN PUBLICO: EMPLEO DE LA FUERZA.', 'MANTENIMIENTO DEL ORDEN PUBLICO: APARIENCIA.', NULL, 'a', 'DESPUÉS DE LA EJECUCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186050'),
(2864, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DEJAR DE UTILIZAR LA FUERZA INMEDIATAMENTE AL CESE DE LA RESISTENCIA O VIOLENCIA, ADOPTANDO LAS CORRESPONDIENTES MEDIDAS DE SEGURIDAD. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: INTERVENCIÓN OPORTUNA.', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: APARIENCIA.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: COMUNICACIÓN', NULL, 'c', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186051'),
(2865, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'QUE NIVEL DE ALERTA CORRESPONDE EL SIGUIENTE ENUNCIADO: NO ES UNA GARANTÍA DE PROTECCIÓN, PERO NOS DARÁ MEJORES CONDICIONES PARA DETECTAR UN PELIGRO Y, DE SER EL CASO, PASAR A UN ESTADO O NIVEL DE REACCIÓN.', 'NIVEL DE REACCIÓN.', 'NIVEL DE DISTRACCIÓN.', 'NIVEL DE ATENCIÓN.', 'NIVEL DE SEGURIDAD.', 'NIVEL DE ALERTA MÍNIMA.', NULL, 'c', 'NIVEL DE ATENCIÓN.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186052'),
(2866, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN ESTAS SITUACIONES SE REQUIERE LA INTERVENCIÓN DIRECTA DE UNIDADES ESPECIALIZADAS DE LA POLICÍA. PUEDE COMPROMETER LA INTERVENCIÓN DE LAS MÁS ALTAS AUTORIDADES DEL SECTOR.¿A QUÉ NIVEL DE RESPUESTA A LA CRISIS CORRESPONDE?:', 'ALTO RIESGO.', 'ALTÍSIMO RIESGO.', 'RIESGO EXTRAORDINARIO.', 'RIESGO EXCEPCIONAL.', 'RIESGO ALTAMENTE EXCEPCIONAL.', NULL, 'b', 'ALTÍSIMO RIESGO.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186053'),
(2867, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA INSTRUCCIÓN BÁSICA.- PREPARACIÓN PSICOLÓGICA.- LOS NIVELES DE ALERTA SON:', 'NIVEL DE DISTRACCIÓN, NIVEL DE ATENCIÓN, NIVEL DE ALERTA MÁXIMA Y NIVEL DE REACCIÓN.', 'NIVEL DE ALERTA MÍNIMA, NIVEL DE ATENCIÓN, NIVEL DE SEGURIDAD Y NIVEL DE REACCIÓN.', 'NIVEL DE DISTRACCIÓN, NIVEL DE ATENCIÓN, NIVEL DE SEGURIDAD Y NIVEL DE REACCIÓN.', 'NIVEL DE DISTRACCIÓN, NIVEL DE ATENCIÓN, NIVEL DE SEGURIDAD Y NIVEL SOCIAL.', 'NIVEL BÁSICO, NIVEL DE ATENCIÓN, NIVEL DE SEGURIDAD Y NIVEL DE REACCIÓN.', NULL, 'c', 'NIVEL DE DISTRACCIÓN, NIVEL DE ATENCIÓN, NIVEL DE SEGURIDAD Y NIVEL DE REACCIÓN.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186054'),
(2868, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'PRIORIZAR EL NIVEL PREVENTIVO DEL EMPLEO DE LA FUERZA CUANDO SE DISPERSEN REUNIONES NO VIOLENTAS. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: INTERVENCIÓN OPORTUNA.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: COMUNICACIÓN', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: APARIENCIA.', NULL, 'd', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186055'),
(2869, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'NO ARREBATAR BANDEROLAS O PANCARTAS UTILIZADAS POR LOS MANIFESTANTES PARA NO EXACERBAR LOS ÁNIMOS, LIMITÁNDOSE AL DECOMISO DE OBJETOS CONTUNDENTES O PUNZO CORTANTES QUE PUEDAN SER UTILIZADOS CONTRA LAS PERSONAS (CIVILES O POLICÍAS). EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: APARIENCIA.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: COMUNICACIÓN', 'MANTENIMIENTO DEL ORDEN PÚBLICO: INTERVENCIÓN OPORTUNA.', NULL, 'a', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186056'),
(2870, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES EL ÁREA DONDE EL POLICÍA TIENE EL DOMINIO DE LA SITUACIÓN DESPUÉS DE UNA ACCIÓN DE CONTROL QUE LE PERMITE MINIMIZAR CUALQUIER RIESGO PARA SU INTEGRIDAD FÍSICA Y LA DE SUS COMPAÑEROS:', 'ÁREA DE SEGURIDAD.', 'ÁREA ADYACENTE.', 'ÁREA DE INFLUENCIA.', 'ÁREA DE RIESGO.', 'ÁREA CONTROLADA.', NULL, 'a', 'ÁREA DE SEGURIDAD.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186057'),
(2871, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES LA HERRAMIENTA O RECURSO MÁS UTILIZADO EN UNA INTERVENCIÓN POLICIAL, MEDIANTE EL QUE SE TRATA DE MANTENER O RESTABLECER EL PRINCIPIO DE AUTORIDAD A TRAVÉS DEL EMPLEO DE LA EXPRESIÓN ORAL, CON LA FIRMEZA Y ENERGÍA ADECUADA A CADA SITUACIÓN PARTICULAR:', 'PREPARACIÓN PSICOLÓGICA.', 'VERBALIZACIÓN.', 'CONTACTO VERBAL.', 'INSTRUCCIONES.', 'NEGOCIAR.', NULL, 'b', 'VERBALIZACIÓN.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186058'),
(2872, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'MEDIOS DE POLICÍA.- PARA EL CUMPLIMIENTO DE SU SERVICIO, EL PERSONAL POLICIAL DEBE CONTAR CON UN EQUIPAMIENTO BÁSICO, CONFORMADO PRINCIPALMENTE POR:', 'VARA DE GOMA, ESPOSAS, CHALECO BALÍSTICO, PROTECTORES CORPORALES Y MUNICIÓN REGLAMENTARIA.', 'VARA DE GOMA, MÁSCARA ANTIGAS, CHALECO TÁCTICO, ARMA DE FUEGO Y MUNICIÓN REGLAMENTARIA.', 'ESCUDOS, ESPOSAS, CHALECO BALÍSTICO, ARMA DE FUEGO Y MUNICIÓN REGLAMENTARIA.', 'BASTONES POLICIALES, GRILLETES POLICIALES, CHALECO BALÍSTICO, ARMA DE FUEGO Y MUNICIÓN REGLAMENTARIA Y', 'VARA DE GOMA, ESPOSAS, CHALECO TÁCTICO, ARMA DE FUEGO Y MUNICIÓN REGLAMENTARIA.', NULL, 'd', 'BASTONES POLICIALES, GRILLETES POLICIALES, CHALECO BALÍSTICO, ARMA DE FUEGO Y MUNICIÓN', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186059'),
(2873, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'NO PODEMOS DEJAR DE MENCIONAR QUE SEGÚN LA ESPECIALIDAD FUNCIONAL HAY UNIDADES POLICIALES QUE DEBEN CONTAR CON OTROS MEDIOS DISPONIBLES MENOS LESIVOS PARA TUTELAR LA VIDA E INTEGRIDAD DE LA PERSONA O SITUACIÓN QUE SE PRETENDE PROTEGER; TALES COMO:', 'CASCO PROTECTOR, ESPOSAS, ARMA DE FUEGO, PROTECTORES CORPORALES, ESCUDOS, ESCOPETAS LANZA GAS, ETC .', 'CASCO PROTECTOR, MÁSCARA ANTIGAS, PROTECTORES CORPORALES, ESCUDOS, MUNICIÓN REGLAMENTARIA, ARMA DE', 'VARA DE GOMA, ARMA DE FUEGO, MÁSCARA ANTIGAS, PROTECTORES CORPORALES, ESCUDOS, ESCOPETAS LANZA GAS,', 'CASCO PROTECTOR, MÁSCARA ANTIGAS, CHALECO BALÍSTICO, ARMA DE FUEGO, ESCUDOS, ESCOPETAS LANZA GAS, ETC.', 'CASCO PROTECTOR, MÁSCARA ANTIGÁS, PROTECTORES CORPORALES, ESCUDOS, ESCOPETAS LANZA GAS Y ESCOPETAS', NULL, 'e', 'CASCO PROTECTOR, MÁSCARA ANTIGÁS, PROTECTORES CORPORALES, ESCUDOS, ESCOPETAS LANZA GAS Y', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186060'),
(2874, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DEFENSA DE GOMA.- EL EMPUÑAMIENTO DE LA DEFENSA DE GOMA PUEDE SER DE DOS FORMAS:', 'TOMA BAJA Y TOMA LARGA.', 'TOMA CORTA Y TOMA ALTA.', 'TOMA ANGOSTA Y TOMA LARGA.', 'TOMA CORTA Y TOMA LARGA.', 'TOMA BAJA Y TOMA ANCHA.', NULL, 'd', 'TOMA CORTA Y TOMA LARGA.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186061'),
(2875, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INDIQUE LA FORMA DE EMPUÑAMIENTO DE LA DEFENSA DE GOMA CORRESPONDE AL SIGUIENTE CONCEPTO: SE SUJETA LA DEFENSA DE GOMA LO MÁS CERCA DEL EXTREMO SUPERIOR DONDE ESTÁ EL REVESTIMIENTO FINAL DEL CUERO EN MAYOR DIÁMETRO.', 'TOMA LARGA.', 'TOMA FUERTE.', 'TOMA CORTA.', 'TOMA DÉBIL.', 'TOMA SIMPLE.', NULL, 'a', 'TOMA LARGA.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186062'),
(2876, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'REDUCEN LAS POSIBILIDADES DE LA PERSONA INTERVENIDA DE AGREDIR AL PERSONAL POLICIAL, GARANTIZANDO SU INTEGRIDAD FÍSICA Y LA DE SUS COMPAÑEROS. ESTE ENUNCIADO CORRESPONDE A:', 'LA VARA DE GOMA.', 'EL ARMA DE FUEGO.', 'EL CHALECO BALÍSTICO.', 'CASCO PROTECTOR.', 'GRILLETES POLICIALES.', NULL, 'e', 'GRILLETES POLICIALES.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186063'),
(2877, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL USO DEL ARMA ES:', 'EXTRAORDINARIO.', 'EXCEPCIONAL.', 'PARTICULAR.', 'PÚBLICO.', 'RUTINARIO.', NULL, 'b', 'EXCEPCIONAL.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186064'),
(2878, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SE DESENFUNDA EL ARMA EXTENDIENDO LOS BRAZOS HACIA EL OBJETIVO, APUNTANDO DIRECTAMENTE AL CENTRO DE LA MASA CORPORAL. LA EVALUACIÓN DE LA AMENAZA A LA VIDA O A LA INTEGRIDAD DETERMINARÁ SI EXISTE LA NECESIDAD DE DISPARAR. EL ENUNCIADO ANTERIOR CORRESPONDE A UNA POSICIÓN BÁSICA DE TIRO DENOMINADA:', 'POSICIÓN DE ENTREVISTA.', 'POSICIÓN DE POTENCIAL DISPARO (POSICIÓN 4).', 'POSICIÓN PREVENTIVA (POSICIÓN 2).', 'POSICIÓN DE CONTACTO (POSICIÓN 1).', 'POSICIÓN DE ALERTA (POSICIÓN 3).', NULL, 'b', 'POSICIÓN DE POTENCIAL DISPARO (POSICIÓN 4).', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186065'),
(2879, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN DEFENSA PROPIA O DE OTRAS PERSONAS EN CASO DE PELIGRO INMINENTE DE MUERTE O LESIONES GRAVES. EN ESTE CASO EL POLICÍA PODRÁ UTILIZAR EN FORMA EXCEPCIONAL ...:', 'SU ESCUDO.', 'SUS ARMAS NO LETALES.', 'EL USO DIFERENCIADO DE LA FUERZA.', 'SU ARMA DE FUEGO.', 'LA VARA DE LEY.', NULL, 'd', 'SU ARMA DE FUEGO.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186066'),
(2880, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'PROCEDIMIENTOS PARA EL EMPLEO DE ARMAS DE FUEGO.- CUANDO SE HAYAN PRODUCIDO HERIDOS COMO CONSECUENCIA DEL DISPARO DE ARMAS DE FUEGO, SE PROCEDERÁ:', 'A COMUNICAR AL JUEZ PENAL.', 'TRASLADAR AL HERIDO A LA COMISARÍA.', 'AL AUXILIO INMEDIATO.', 'LEVANTAR EL ACTA Y FORMULAR EL INFORME.', 'A COMUNICAR AL FISCAL.', NULL, 'c', 'AL AUXILIO INMEDIATO.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186067'),
(2881, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES EL MEDIO QUE EN SUS DIFERENTES NIVELES USA EL PERSONAL DE LA POLICÍA NACIONAL DEL PERÚ, DENTRO DEL MARCO DE LA LEY, PARA LOGRAR EL CONTROL DE UNA SITUACIÓN QUE CONSTITUYE UNA AMENAZA O ATENTA CONTRA LA SEGURIDAD, EL ORDEN PÚBLICO, LA INTEGRIDAD O LA VIDA DE LAS PERSONAS. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'DEFINICIÓN DE LA FUNCIÓN POLICIAL.', 'DEFINICIÓN DE LOS PRINCIPIOS BÁSICOS DEL USO DE LA FUERZA.', 'DEFINICIÓN DEL USO DE LA FUERZA.', 'DEFINICIÓN DE FUERZA EN EL ACCIONAR POLICIAL.', 'DEFINICIÓN DEL PODER DE POLICÍA.', NULL, 'd', 'DEFINICIÓN DE FUERZA EN EL ACCIONAR POLICIAL.', '(texto: II-II)** [PARTE SEGUNDA]  [CAPITULO II]', '186068'),
(2882, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL USO DE LA FUERZA EN EL CUMPLIMIENTO DEL DEBER ES NECESARIO CUANDO OTROS MEDIOS RESULTEN INEFICACES O NO GARANTICEN DE NINGUNA MANERA EL LOGRO DEL OBJETIVO LEGAL BUSCADO. EL ENUNCIADO ANTERIOR, CONSTITUYE LA DEFINICIÓN DE UNO DE LOS PRINCIPIOS DEL USO DE LA FUERZA, DENOMINADO:', 'LEGALIDAD.', 'NECESIDAD.', 'RACIONALIDAD.', 'PROPORCIONALIDAD.', 'RAZONABILIDAD.', NULL, 'b', 'NECESIDAD.', '(texto: II-II)** [PARTE SEGUNDA]  [CAPITULO II]', '186069'),
(2883, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'AL INTERVENIR A PERSONAS EN EL CUMPLIMIENTO DE SU FUNCIÓN, EL PERSONAL POLICIAL ENCONTRARÁ COMO RESPUESTA UNA SERIE DE CONDUCTAS CLASIFICADAS EN NIVELES DE RESISTENCIA, ANTE LO CUAL EL POLICÍA DEBERÁ HACER:', 'USO PROPORCIONAL DE LA FUERZA.', 'USO LEGAL DE LA FUERZA.', 'UN USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA.', 'USO PROLONGADO DE LA FUERZA, HASTA CESAR LA AMENAZA.', 'USO EXTREMO DE LA FUERZA, HASTA CESAR LA AMENAZA.', NULL, 'c', 'UN USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA.', '(texto: II-II)** [PARTE SEGUNDA]  [CAPITULO II]', '186070'),
(2884, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES LA AMENAZA PERMANENTE NO VISIBLE PRESENTE EN TODA INTERVENCIÓN POLICIAL. EL ENUNCIADO ANTERIOR CORRESPONDE A LOS NIVELES DE RESISTENCIA EN EL USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA, DENOMINADO:', 'NIVEL DE RESISTENCIA ACTIVA: NO COOPERADOR.', 'NIVEL DE RESISTENCIA ACTIVA: RESISTENCIA FÍSICA.', 'NIVEL DE RESISTENCIA ACTIVA: AGRESIÓN NO LETAL.', 'NIVEL DE RESISTENCIA PASIVA: RIESGO LATENTE.', 'NIVEL DE RESISTENCIA PASIVA: NO COOPERADOR.', NULL, 'd', 'NIVEL DE RESISTENCIA PASIVA: RIESGO LATENTE.', '(texto: II-II)** [PARTE SEGUNDA]  [CAPITULO II]', '186071'),
(2885, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'TÉCNICAS DE INTERVENCIÓN.- TODA INTERVENCIÓN POLICIAL, POR LO GENERAL, DEBE SER EFECTUADA COMO MÍNIMO POR:', 'TRES EFECTIVOS POLICIALES.', 'CUATRO EFECTIVOS POLICIALES.', 'UN EFECTIVO POLICIAL.', 'DOS POLICIAS.', 'CINCO EFECTIVOS POLICIALES.', NULL, 'd', 'DOS POLICIAS.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186072'),
(2886, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿A QUÉ ASPECTO MUY IMPORTANTE DEL MANTENIMIENTO DEL ORDEN PÚBLICO, CORRESPONDE EL SIGUIENTE ENUNCIADO?: NO ARROJAR CONTRA LOS MANIFESTANTES OBJETOS CONTUNDENTES (PIEDRAS, PALOS, FIERROS, ETC.) QUE ESTÉN AL ALCANCE O QUE SEAN LANZADOS AL PERSONAL POLICIAL, MANTENIENDO LAS FORMACIONES TÁCTICAS Y EMPLEANDO ADECUADAMENTE LOS EQUIPOS DE PROTECCIÓN: (SEÑALE LA RESPUESTA CORRECTA)', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', 'PREPARACIÓN.', 'APARIENCIA.', 'COMUNICACIÓN.', 'INTERVENCIÓN OPORTUNA.', NULL, 'a', 'DURANTE LA EJECUCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186073'),
(2887, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EL ESTADO DE ALERTA PUEDE SER IDENTIFICADO A TRAVÉS DE LOS SIGUIENTES NIVELES: (SEÑALE LA RESPUESTA CORRECTA)', 'NIVEL DE DETECCIÓN.', 'NIVEL DE PREVENCIÓN.', 'NIVEL DE DISTRACCIÓN.', 'NIVEL DE ALERTA MAYOR.', 'NIVEL DE CONTROL.', NULL, 'c', 'NIVEL DE DISTRACCIÓN.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186074'),
(2888, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ESTÁ A CARGO DE LOS DIFERENTES NIVELES DE COMANDO (ALTA DIRECCIÓN, DIRECCIÓN EJECUTIVA DE OPERACIONES, DIRECCIONES ESPECIALIZADAS, DIRECCIONES TERRITORIALES Y JEFATURAS DE REGIÓN) QUE ASUMEN LA RESPONSABILIDAD INSTITUCIONAL DE SUPERVISIÓN Y CONTROL DE ACUERDO A LOS OBJETIVOS, ESTRATEGIAS Y POLÍTICAS DEL SECTOR. EL ENUNCIADO ANTERIOR CORRESPONDE A:', 'MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: INTERVENCIÓN OPORTUNA.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: COMUNICACIÓN', 'MANTENIMIENTO DEL ORDEN PÚBLICO: EMPLEO DE LA FUERZA.', 'DIRECCIÓN DE LAS OPERACIONES.', NULL, 'e', 'DIRECCIÓN DE LAS OPERACIONES.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186075'),
(2889, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA POLICÍA NACIONAL DEL PERÚ TIENE COMO FUNCIÓN MANTENER Y RESTABLECER EL ORDEN PÚBLICO, SIENDO NECESARIA UNA ACTUACIÓN PROFESIONAL Y SUSTENTADA EN LOS DERECHOS HUMANOS APLICADOS A LA FUNCIÓN POLICIAL, GARANTIZANDO LA DEFENSA DE LA PERSONA, LA SOCIEDAD Y EL ESTADO:', 'MANTENIMIENTO DEL ORDEN PÚBLICO: PREPARACIÓN.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: INTERVENCIÓN OPORTUNA.', 'OPERACIONES DE ORDEN PÚBLICO.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: EMPLEO DE LA FUERZA.', 'MANTENIMIENTO DEL ORDEN PÚBLICO: APARIENCIA.', NULL, 'c', 'OPERACIONES DE ORDEN PÚBLICO.', '(texto: II-IV)** [PARTE SEGUNDA]  [CAPITULO IV]', '186076'),
(2890, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LAS TÉCNICAS DE INTERVENCIÓN, LOS EFECTIVOS POLICIALES DEBEN TRAZAR SIEMPRE UNA (......................) QUE DIVIDA EL ÁREA DE LA INTERVENCIÓN, ESTABLECIENDO EL ÁREA DE SEGURIDAD (DOMINADA POR ELLOS) Y EL ÁREA DE RIESGO (NO CONTROLADA POR ELLOS), EN DONDE SE PRESUMA O SE TENGA LA CERTEZA DE LA PRESENCIA DEL INTERVENIDO O PRESUNTO INFRACTOR.', 'LÍNEA RECTA, CON SU TIZA TÁCTICA.', 'LÍNEA IMAGINARIA.', 'LÍNEA PERPENDICULAR A LA INTERVENCIÓN.', 'LÍNEA PARALELA A LA UBICACIÓN DEL ÁREA SEGURA', 'LÍNEA PARALELA A LA UBICACIÓN DEL ÁREA DE RIESGO.', NULL, 'b', 'LÍNEA IMAGINARIA.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186077'),
(2891, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA INTERVENCIÓN POLICIAL A UN VEHÍCULO CON PRESUNTOS INFRACTORES. INDIQUE, ¿CUÁL DEBE SER LA POSICIÓN DEL VEHÍCULO POLICIAL (PATRULLERO)?', 'UBICAR EL VEHÍCULO POLICIAL DETRÁS DEL VEHÍCULO A INTERVENIR, A UNOS OCHO METROS APROXIMADAMENTE.', 'EN DIAGONAL (90º APROX.), VÉRTICE ANTERIOR DERECHO EN PROYECCIÓN AL VÉRTICE POSTERIOR IZQUIERDO DEL', 'EN DIAGONAL (45º APROX.), VÉRTICE ANTERIOR DERECHO EN PROYECCIÓN AL VÉRTICE POSTERIOR IZQUIERDO DEL', 'EN DIAGONAL (180º APROX.), VÉRTICE ANTERIOR DERECHO EN PROYECCIÓN AL VÉRTICE POSTERIOR IZQUIERDO DEL', 'EN DIAGONAL (45º APROX.), VÉRTICE POSTERIOR DERECHO EN PROYECCIÓN AL VÉRTICE POSTERIOR IZQUIERDO DEL', NULL, 'c', 'EN DIAGONAL (45º APROX.), VÉRTICE ANTERIOR DERECHO EN PROYECCIÓN AL VÉRTICE POSTERIOR', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186078'),
(2892, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES UN EXCELENTE MEDIO DEFENSIVO QUE PERMITE ESTABLECER UN ÁREA DE SEGURIDAD MAYOR AL DE LA PROTECCIÓN ALCANZADA CON BRAZOS Y PIES. NOS REFERIMOS:', 'AL ARMA DE FUEGO.', 'AL ÁREA DE SEGURIDAD.', 'A LA DEFENSA DE GOMA.', 'A LAS ESPOSAS DE SEGURIDAD.', 'AL ESCUDO.', NULL, 'c', 'A LA DEFENSA DE GOMA.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186079'),
(2893, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'ES  NECESARIO  QUE  (........)  ESTÉ  PREPARADO  PROFESIONALMENTE  Y  MOTIVADO  PARA  EL  DESARROLLO ADECUADO DE  ACTITUDES,  HABILIDADES,  CONFIANZA,  ESPÍRITU  DE  EQUIPO  POSITIVO,  LIDERAZGO  EFICAZ  Y  LA  EJECUCIÓN  DE TÁCTICAS OPERACIONALES; ASPECTOS QUE DEBEN FORMAR PARTE DE SU INSTRUCCIÓN Y ENTRENAMIENTO:', 'EL ABOGADO.', 'EL FISCAL.', 'EL SERENAZGO.', 'EL POLICÍA.', 'EL JUEZ.', NULL, 'd', 'EL POLICÍA.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186080'),
(2894, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS ALTERNATIVAS SIGUIENTES ES PARTE DE LA DISTRIBUCIÓN TÁCTICA DEL MANEJO DE CRISIS?', 'EQUIPO DE ACCIONES TÁCTICAS.', 'EQUIPO DE COLABORADORES.', 'EQUIPO DE CONFIDENTES.', 'EQUIPO DE PERITOS.', 'EQUIPO DE FRANCOTIRADORES.', NULL, 'e', 'EQUIPO DE FRANCOTIRADORES.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186081'),
(2895, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'POR EL MATERIAL EMPLEADO EN SU FABRICACIÓN, EL USO DE LOS GRILLETES DE SEGURIDAD PUEDE ORIGINAR LESIONES SI SON MAL EMPLEADOS. POR ELLO, EL PERSONAL POLICIAL DEBERÁ POSIBILITAR LA ATENCIÓN MÉDICA NECESARIA EN CASO DE QUE ESTAS LESIONES SE HAYAN PRODUCIDO. EL PÁRRAFO ANTERIOR SE REFIERE A:', 'LA VARA DE GOMA.', 'TÉCNICAS DE USO PARTIENDO DE LA POSICIÓN PREVENTIVA.', 'ARMA DE FUEGO.', 'MUNICIÓN REGLAMENTARIA.', 'LOS GRILLETES DE SEGURIDAD.', NULL, 'e', 'LOS GRILLETES DE SEGURIDAD.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186082'),
(2896, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LOS NIVELES DE RESPUESTA DE LA POLICÍA, SE ENMARCAN EN LOS PRINCIPIOS DEL USO DE LA FUERZA DESARROLLADOS EN EL MANUAL, Y ESTÁN EN RELACIÓN DIRECTA AL:', 'CAUSANTE.', 'DESPLIEGUE POLICIAL Y FUERZA LETAL.', 'GRADO DE AMENAZA.', 'COMPROMISO AGRESIVO.', 'EMPLEO DE LA FUERZA LETAL.', NULL, 'c', 'GRADO DE AMENAZA.', '(texto: II-V)** [PARTE SEGUNDA]  [CAPITULO V]', '186083'),
(2897, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DEBEMOS TOMAR CONCIENCIA QUE TODO EMPLEO EXCESIVO DE LA FUERZA SE CONVIERTE EN VIOLENCIA Y ES VISTO COMO UN ACTO ARBITRARIO, ILEGAL, ILEGÍTIMO Y NO PROFESIONAL. POR ELLO, LOS Y LAS POLICÍAS DEBEN TENER PRESENTE SIEMPRE QUE:', 'FUERZA ES ORDEN.', 'ORDEN NO ES FUERZA.', 'FUERZA NO ES VIOLENCIA.', 'ORDEN NO ES VIOLENCIA.', 'FUERZA NO ES CASTIGO.', NULL, 'c', 'FUERZA NO ES VIOLENCIA.', '(texto: II-II)** [PARTE SEGUNDA]  [CAPITULO II]', '186084'),
(2898, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA  SEGURIDAD  DEL  PERSONAL  POLICIAL  ESTÁ  DIRECTAMENTE  RELACIONADA  CON  SU  PREPARACIÓN  O  ESTADO MENTAL.  ESTO  LE PERMITIRÁ VISUALIZAR Y ENSAYAR SUS ACCIONES, DE MODO QUE SE TENGA UNA RESPUESTA EN RAZÓN A LA FORMA DE ACTUAR DE  LOS  PRESUNTOS  INFRACTORES  DE  LA  LEY.  POR  ESTAS  MISMAS  RAZONES,  EL PERSONAL  POLICIAL  DEBE  RECIBIR  ORIENTACIÓN PSICOLÓGICA POR CUENTA DEL ESTADO PARA SOBRELLEVAR LAS TENSIONES GENERADAS POR EL USO DE LA FUERZA QUE AFECTEN LA VIDA O INTEGRIDAD FÍSICA DE OTRAS PERSONAS. EL PÁRRAFO ANTERIOR SE REFIERE A:', 'LOS PRINCIPIOS BÁSICOS DEL USO DE LA FUERZA.', 'PREPARACIÓN PSICOLÓGICA.', 'EL ESTADO MENTAL DEL POLICÍA.', 'ENTRENAMIENTO POLICIAL.', 'ENTRENAMIENTO MENTAL.', NULL, 'b', 'PREPARACIÓN PSICOLÓGICA.', '(texto: II-I)** [PARTE SEGUNDA]  [CAPITULO I]', '186085'),
(2899, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA INTERVENCIÓN A VEHÍCULOS SE REALIZA PRINCIPALMENTE EN DOS SITUACIONES, LAS CUALES SON:', 'POR IDENTIFICACIÓN DE LOS OCUPANTES, POR INFRACCIÓN AL REGLAMENTO DE TRÁNSITO, POR PREVENCIÓN DE', 'POR IDENTIFICACIÓN DEL CONDUCTOR, POR INFRACCIÓN AL CÓDIGO PENAL, Y POR PREVENCIÓN DE DELITOS Y FALTAS.', 'PARA IDENTIFICAR AL PRESUNTO AUTOR DE UN DELITO, POR INFRACCIÓN AL REGLAMENTO DE TRÁNSITO, Y POR', 'POR INFRACCIÓN AL REGLAMENTO NACIONAL DE TRÁNSITO; Y POR PREVENCIÓN DE DELITOS Y FALTAS.', 'PARA IDENTIFICAR LOS DATOS DEL VEHÍCULO, POR INFRACCIÓN AL REGLAMENTO DE TRÁNSITO, Y POR PREVENCIÓN DE', NULL, 'd', 'POR INFRACCIÓN AL REGLAMENTO NACIONAL DE TRÁNSITO; Y POR PREVENCIÓN DE DELITOS Y FALTAS.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186086'),
(2900, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA INTERVENCIÓN POLICIAL DIURNA A UN VEHÍCULO CON PRESUNTOS INFRACTORES DESDE UN VEHÍCULO POLICIAL, ANTE LA PRESENCIA DE UN TERCERO O MÁS OCUPANTES, INDIQUE EL PROCEDIMIENTO CORRECTO:', 'ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, A LOS OCUPANTES DEL', 'ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, AL (LOS) OCUPANTE(S) DEL', 'ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, AL (LOS) OCUPANTE(S) DEL', 'ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, A LOS OCUPANTES DEL', 'ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, A LOS OCUPANTES DEL', NULL, 'a', 'ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, A LOS OCUPANTES', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186087'),
(2901, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA INTERVENCIÓN POLICIAL DIURNA A UN VEHÍCULO CON PRESUNTOS INFRACTORES DESDE UN VEHÍCULO POLICIAL, ANTE LA PRESENCIA DE UN TERCERO O MÁS OCUPANTES, ES RECOMENDABLE HACER DESCENDER, LUEGO DE HABER INTERVENIDO AL CONDUCTOR, A LOS OCUPANTES DEL ASIENTO TRASERO POR LA (...........), PARA MINIMIZAR LA POSIBILIDAD DE UNA TOMA DE REHÉN POR LOS OTROS INFRACTORES.', 'VENTANA POSTERIOR IZQUIERDA (DETRÁS DE LA DEL CONDUCTOR).', 'PUERTA POSTERIOR IZQUIERDA (DETRÁS DE LA DEL CONDUCTOR).', 'PUERTA POSTERIOR DERECHA (DETRÁS DE LA DEL CONDUCTOR).', 'PUERTA DELANTERA IZQUIERDA (DETRÁS DE LA DEL CONDUCTOR).', 'PUERTA DELANTERA DERECHA (DETRÁS DE LA DEL CONDUCTOR).', NULL, 'b', 'PUERTA POSTERIOR IZQUIERDA (DETRÁS DE LA DEL CONDUCTOR).', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186088'),
(2902, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO A LAS TÉCNICAS DE INTERVENCIÓN,LOS PROCEDIMIENTOS DE LA INTERVENCIÓN POLICIAL PROPIAMENTE DICHA (IDENTIFICACIÓN, REDUCCIÓN, INMOVILIZACIÓN Y REGISTRO) DEBERÁN EFECTUARSE SIEMPRE EN LA ZONA DE SEGURIDAD. EL EFECTIVO POLICIAL JAMÁS INGRESARÁ A LA ZONA DE (................), SI ES QUE ÉSTA NO HA SIDO DEBIDAMENTE CONTROLADA.', 'RIESGO.', 'FUEGO.', 'AFLUENCIA.', 'INFLUENCIA.', 'CONFLICTO.', NULL, 'a', 'RIESGO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186089'),
(2903, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA INTERVENCIÓN POLICIAL DIURNA A UN VEHÍCULO CON PRESUNTOS INFRACTORES DESDE UN VEHÍCULO POLICIAL, ANTE LA PRESENCIA DE UN TERCERO O MÁS OCUPANTES, INDIQUE EL PROCEDIMIENTO CORRECTO:', 'SE LES INDICARÁ QUE SAQUEN LA CABEZA POR LA VENTANA DEL LADO DERECHO.', 'SE LES INDICARÁ QUE SAQUEN LAS MANOS POR LA VENTANA DEL LADO DERECHO.', 'SE LES INDICARÁ QUE SAQUEN LAS MANOS POR LA VENTANA DEL LADO IZQUIERDO.', 'SE LES INDICARÁ QUE SAQUEN LAS MANOS POR LA PUERTA DEL LADO IZQUIERDO.', 'SE LES INDICARÁ QUE SAQUEN LA CABEZA POR LA VENTANA DEL LADO IZQUIERDO.', NULL, 'b', 'SE LES INDICARÁ QUE SAQUEN LAS MANOS POR LA VENTANA DEL LADO DERECHO.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186090'),
(2904, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EXISTEN EN LA ACTUALIDAD EQUIPAMIENTOS POLICIALES BASADOS EN EL EMPLEO DE ESPEJOS (PERISCOPIO, PLANCHA DE IDENTIFICACIÓN, ESPEJO TÁCTICO, ENTRE OTROS); SU USO BRINDA MAYOR SEGURIDAD AL EFECTIVO POLICIAL, PUES EVITA EXPONER PARTE DE SU CUERPO PARA REALIZAR LA (................), FACILITANDO SU MANTENIMIENTO EN LA ZONA DE ABRIGO O PARAPETO.', 'INTERVENCIÓN.', 'CAPTURA.', 'BUSQUEDA.', 'COBERTURA.', 'OBSERVACIÓN.', NULL, 'e', 'OBSERVACIÓN.', '(texto: II-III)** [PARTE SEGUNDA]  [CAPITULO III]', '186091'),
(2905, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL OBJETIVO FUNDAMENTAL DEL USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA POR PARTE DEL PERSONAL POLICIAL, SEGÚN EL MARCO NORMATIVO ANALIZADO?', 'IMPONER LA AUTORIDAD POLICIAL A CUALQUIER COSTO PARA MANTENER EL ORDEN PÚBLICO.', 'MAXIMIZAR EL IMPACTO DISUASIVO DE LA INTERVENCIÓN POLICIAL MEDIANTE EL USO PREVENTIVO DE ARMAS.', 'ADAPTAR LOS MEDIOS Y MÉTODOS DE INTERVENCIÓN SEGÚN EL NIVEL DE COOPERACIÓN, RESISTENCIA O AGRESIÓN DE', 'ASEGURAR LA INMOVILIZACIÓN INMEDIATA DEL PRESUNTO INFRACTOR, SIN DISTINCIÓN DEL CONTEXTO SOCIAL.', 'GARANTIZAR EN TODO MOMENTO LA NEUTRALIZACIÓN DEFINITIVA DEL PROBABLE AGRESOR POR VÍAS FÍSICAS.', NULL, 'c', 'ADAPTAR LOS MEDIOS Y MÉTODOS DE INTERVENCIÓN SEGÚN EL NIVEL DE COOPERACIÓN, RESISTENCIA O', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186092'),
(2906, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN EL MARCO DEL USO PROGRESIVO DE LA FUERZA, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DEFINE CON MAYOR PRECISIÓN LA "RESISTENCIA PASIVA-NO COOPERADOR"?', 'OPOSICIÓN FÍSICA ACTIVA Y EVIDENTE CONTRA EL PERSONAL POLICIAL.', 'EL INTERVENIDO NO ACATA LAS INDICACIONES. NO REACCIONA NI AGREDE.', 'AGRESIÓN FÍSICA CON ARMAS NO LETALES CONTRA LA POLICÍA.', 'ACTITUD COMPLETAMENTE AJENA A LA INTERVENCIÓN POLICIAL CON INDIFERENCIA TOTAL.', 'ATAQUE LETAL A LA INTEGRIDAD DEL PERSONAL POLICIAL O DE TERCEROS.', NULL, 'b', 'EL INTERVENIDO NO ACATA LAS INDICACIONES. NO REACCIONA NI AGREDE.', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186093'),
(2907, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN RELACIÓN A LOS NIVELES PREVENTIVOS DEL USO DE LA FUERZA, ¿CUÁL DE LAS SIGUIENTES ALTERNATIVAS CORRESPONDE  A LA AL PRESENCIA POLICIAL?', 'VERBALIZACIÓN REITERADA Y FIRME DE ÓRDENES DIRECTAS.', 'APLICACIÓN INMEDIATA DE CONTROL FÍSICO FRENTE A CUALQUIER RESISTENCIA.', 'DEMOSTRACIÓN DE AUTORIDAD DEL PERSONAL DE LA POLICIA NACIONAL UNIFORMADO O DEBIDAMENTE IDENTIFICADO,', 'USO DE TÁCTICAS DEFENSIVAS NO LETALES COMO MEDIDA PRIMARIA.', 'REGISTRO PERSONAL DE TODOS LOS CIUDADANOS PRESENTES.', NULL, 'c', 'DEMOSTRACIÓN DE AUTORIDAD DEL PERSONAL DE LA POLICIA NACIONAL UNIFORMADO O DEBIDAMENTE', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186094'),
(2908, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO AL TEXTO, ¿CUÁNDO CORRESPONDE UTILIZAR LA FUERZA POTENCIALMENTE LETAL SEGÚN EL USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA?', 'CUANDO EL PRESUNTO INFRACTOR REALIZA UNA AGRESIÓN FÍSICA SIMPLE.', 'AL PRODUCIRSE DESOBEDIENCIA VERBAL REITERADA Y HOSTIL.', 'CUANDO EXISTE UN PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES CON EL OBJETIVO DE CONTRATARLO Y', 'EN TODA SITUACIÓN DONDE SE PERCIBA DESORDEN PÚBLICO.', 'SIEMPRE QUE EL PERSONAL POLICIAL SIENTA TEMOR FUNDADO ANTE LA ACTITUD DEL PRESUNTO INFRACTOR.', NULL, 'c', 'CUANDO EXISTE UN PELIGRO REAL E INMINENTE DE MUERTE O LESIONES GRAVES CON EL OBJETIVO DE', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186095'),
(2909, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL "CONTROL DE CONTACTO", ¿CUÁL ES SU PRINCIPAL OBJETIVO DENTRO DE LOS NIVELES DEL USO DE LA FUERZA?', 'EJERCER PRESIÓN FÍSICA INMEDIATA PARA REDUCIR A LA PERSONA INTERVENIDA.', 'APLICAR TÉCNICAS DE MANIPULACIÓN FÍSICA PARA SUJETAR AL INTERVENIDO.', 'GUIAR Y CONTENER LA ACCIÓN O ACTUTUD DE LA PERSONA, MEDIANTE TÉCNICAS DE COMUNICACIÓN Y NEGOCIACIÓN,', 'AISLAR AL GRUPO INTERVENIDO PARA EVITAR DISTURBIOS.', 'GARANTIZAR LA ENTREGA DE LA PERSONA INTERVENIDA A LA AUTORIDAD JUDICIAL COMPETENTE EN EL MOMENTO.', NULL, 'c', 'GUIAR Y CONTENER LA ACCIÓN O ACTUTUD DE LA PERSONA, MEDIANTE TÉCNICAS DE COMUNICACIÓN Y', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186096'),
(2910, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE LOS SIGUIENTES CONCEPTOS, ¿CUÁL DEFINE MEJOR LA AGRESIÓN NO LETAL DENTRO DE LA RESISTENCIA ACTIVA?', 'ACCIÓN QUE CAUSA INMINENTE RIESGO DE MUERTE AL PERSONAL POLICIAL.', 'OPOSICIÓN VERBAL Y GESTUAL DE DESOBEDIENCIA REITERADA.', 'USO DE FUERZA CORPORAL U OBJETO PELIGROSO QUE ATENTA CONTRA LA INTEGRIDAD FÍSICA, SIN GENERAR PELIGRO', 'ATAQUE GRUPAL COORDINADO CON ARMAS DE FUEGO.', 'SIMULACIÓN DE COLABORACIÓN PARA EVADIR EL CONTROL POLICIAL.', NULL, 'c', 'USO DE FUERZA CORPORAL U OBJETO PELIGROSO QUE ATENTA CONTRA LA INTEGRIDAD FÍSICA, SIN', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186099'),
(2911, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿EN QUÉ MOMENTO Y CÓMO DEBE APLICARSE LA VERBALIZACIÓN EN EL USO PROGRESIVO DE LA FUERZA POLICIAL?', 'SOLO TRAS LA APLICACIÓN DE CONTROL FÍSICO Y ANTE RESISTENCIA EVIDENTE.', 'EN TODOS LOS NIVELES DEL USO DE LA FUERZA COMO PRIMER MÉTODO DE COMUNICACIÓN Y CONTROL.', 'EXCLUSIVAMENTE FRENTE A SITUACIONES DE RESISTENCIA ACTIVA.', 'ÚNICAMENTE CON GRUPOS NUMEROSOS Y POTENCIALMENTE PELIGROSOS.', 'EN EL TRASLADO POST-INTERVENCIÓN HACIA LA DEPENDENCIA POLICIAL.', NULL, 'b', 'EN TODOS LOS NIVELES DEL USO DE LA FUERZA COMO PRIMER MÉTODO DE COMUNICACIÓN Y CONTROL.', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186100'),
(2912, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿A QUÉ SE REFIERE EL "RIESGO LATENTE" EN LA RESISTENCIA PASIVA?', 'A LA POSIBILIDAD DE RESISTENCIA FÍSICA ACTIVA DEL INTERVENIDO.', 'A LA AMENAZA PERMANENTE NO VISIBLE, DERIVADA DE FACTORES SOCIALES, ECONÓMICOS O GEOGRÁFICOS', 'A LA PRONTA COLABORACIÓN DEL CIUDADANO CON LA AUTORIDAD.', 'A LA PRESENCIA DE TESTIGOS HOSTILES EN LA INTERVENCIÓN.', 'A LA EVENTUALIDAD DE UN ERROR POLICIAL EN LA IDENTIFICACIÓN DEL SOSPECHOSO.', NULL, 'b', 'A LA AMENAZA PERMANENTE NO VISIBLE, DERIVADA DE FACTORES SOCIALES, ECONÓMICOS O GEOGRÁFICOS', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186101'),
(2913, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES ALTERNATIVAS EXPRESA CORRECTAMENTE EL CONCEPTO DE "CONTROLAR" SEGÚN EL NIVEL REACTIVO?', 'APLICAR MANIPULACIÓN VERBAL PARA CALMAR AL INTERVENIDO.', 'EL RESULTADO OBTENIDO DE REDUCIR, INMOVILIZAR Y CONDUCIR AL INTERVENIDO', 'UTILIZAR SOLO EL USO DE ARMAS DE FUEGO PARA NEUTRALIZAR AL AGRESOR.', 'SOLICITAR EL APOYO DE FUERZAS ESPECIALES EN TODA CONDUCCIÓN.', 'ELEVAR UN INFORME POSTERIOR PARA EVALUAR EL PROCEDIMIENTO.', NULL, 'b', 'EL RESULTADO OBTENIDO DE REDUCIR, INMOVILIZAR Y CONDUCIR AL INTERVENIDO', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186102'),
(2914, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DENTRO DEL ESPECTRO DEL USO PROGRESIVO DE LA FUERZA, ¿QUÉ CARACTERÍSTICA DIFERENCIA LA REDUCCIÓN DE LA INMOVILIZACIÓN?', 'LA REDUCCIÓN IMPLICA LA APLICACIÓN DE ARMAS LETALES, MIENTRAS QUE LA INMOVILIZACIÓN NO.', 'LA REDUCCIÓN CONSISTE EN MINIMIZAR LA RESISTENCIA FÍSICA, Y LA INMOVILIZACIÓN EN IMPEDIR TEMPORALMENTE LA', 'AMBAS SE REFIEREN ÚNICAMENTE A TÉCNICAS VERBALES DE PERSUASIÓN.', 'LA INMOVILIZACIÓN SUPONE SIEMPRE EL USO DE LA FUERZA LETAL.', 'LA REDUCCIÓN SOLO SE USA EN PRESENCIA DE ALTO RIESGO LATENTE.', NULL, 'b', 'LA REDUCCIÓN CONSISTE EN MINIMIZAR LA RESISTENCIA FÍSICA, Y LA INMOVILIZACIÓN EN IMPEDIR', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186103'),
(2915, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ CARACTERIZA PRINCIPALMENTE AL "COOPERADOR" EN LA RESISTENCIA PASIVA SEGÚN EL TEXTO ANALIZADO?', 'EL INTERVENIDO DESACATA LAS ÓRDENES DELIBERADAMENTE.', 'EL INTERVENIDO ACATA TODAS LAS INDICACIONES DEL EFECTIVO POLICIAL, SIN RESISTENCIA MANIFIESTA DURANTE LA', 'EL INTERVENIDO SE RESISTE FÍSICAMENTE PERO SIN EMPLEAR ARMAS.', 'EL INTERVENIDO AGREDE VERBALMENTE PERO NO FÍSICAMENTE.', 'EL INTERVENIDO SE SOMETE ÚNICAMENTE ANTE LA AMENAZA DE USO DE ARMAS.', NULL, 'b', 'EL INTERVENIDO ACATA TODAS LAS INDICACIONES DEL EFECTIVO POLICIAL, SIN RESISTENCIA MANIFIESTA', '(ART: II-II)**USO DIFERENCIADO Y PROGRESIVO DE LA FUERZA', '186108'),
(2916, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'CON RELACIÓN A LOS PRINCIPIOS INTERNACIONALES SOBRE EL USO DE LA FUERZA APLICABLES A LA FUNCIÓN POLICIAL, ¿CUÁL DE LAS SIGUIENTES AFIRMACIONES DESCRIBE CORRECTAMENTE EL PRINCIPIO DE LEGALIDAD?', 'IMPLICA QUE TODO USO DE LA FUERZA ESTÁ PERMITIDO MIENTRAS EXISTE UN FIN LEGÍTIMO, INCLUSO SI NO ESTÁ', 'EXIGE QUE EL USO DE LA FUERZA ESTÉ ORIENTADO AL LOGRO DE UN OBJETIVO LEGAL Y AMPARADOS EN EL MARCO DEL', 'PERMITE LA UTILIZACIÓN DE CUALQUIER MEDIO PARA ALCANZAR EL OBJETIVO POLICIAL, ADAPTANDO LA NORMATIVA', 'SE REFIERE SOLAMENTE A LA IMPOSICIÓN DE SANCIONES LEGALES LUEGO DEL USO DE LA FUERZA.', 'SIGNIFICA QUE LOS FUNCIONARIOS PUEDEN IMPROVISAR MÉTODOS DE FUERZA SIEMPRE QUE CUENTEN CON UNA', NULL, 'b', 'EXIGE QUE EL USO DE LA FUERZA ESTÉ ORIENTADO AL LOGRO DE UN OBJETIVO LEGAL Y AMPARADOS EN EL', '(ART: II-II)**PRINCIPIOS DEL USO DE LA FUERZA', '186117'),
(2917, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN EL TEXTO, ¿CUÁNDO EL USO DE LA FUERZA POR PARTE DE LA POLICÍA NACIONAL DEL PERÚ SE CONVIERTE EN VIOLENCIA?', 'CUANDO SE EMPLEA EN AUSENCIA DE UN SUPERIOR JERÁRQUICO.', 'CUANDO SE UTILIZA COMO PRIMERA MEDIDA ANTE CUALQUIER DESOBEDIENCIA CIVIL.', 'CUANDO SU EMPLEO ES EXCESIVO, ARBITRARIO Y NO PROFESIONAL, CON LO QUE DEBE QUEDAR CLARO PARA LOS', 'CUANDO SE UTILIZA SOLO EN MANIFESTACIONES PÚBLICAS.', 'CUANDO SE BASA ÚNICAMENTE EN LA APRECIACIÓN SUBJETIVA DEL AGENTE POLICIAL.', NULL, 'c', 'CUANDO SU EMPLEO ES EXCESIVO, ARBITRARIO Y NO PROFESIONAL, CON LO QUE DEBE QUEDAR CLARO', '(ART: II-II)**Uso de la fuerza', '186123'),
(2918, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL TRATO DEL PERSONAL POLICIAL HACIA GRUPOS VULNERABLES, SEÑALE LA AFIRMACIÓN CORRECTA DE ACUERDO AL TEXTO.', 'EL USO DE LA FUERZA DEBE SER IGUAL PARA TODOS, SIN EXCEPCIÓN.', 'SE DEBEN TOMAR CONSIDERACIONES ESPECIALES Y BRINDAR TRATO HUMANO Y DIGNO A MUJERES, NIÑOS,', 'LA NORMATIVA PERMITE MAYOR USO DE LA FUERZA EN CASOS DE RESISTENCIA FÍSICA DE MENORES DE EDAD.', 'NO EXISTEN ESPECIFICACIONES LEGALES SOBRE TRATO A PERSONAS CON DISCAPACIDAD.', 'EL TRATO DIFERENCIADO VA EN CONTRA DEL PRINCIPIO DE IGUALDAD ANTE LA LEY.', NULL, 'b', 'SE DEBEN TOMAR CONSIDERACIONES ESPECIALES Y BRINDAR TRATO HUMANO Y DIGNO A MUJERES, NIÑOS,', '(ART: II-II)**Uso de la fuerza', '186125'),
(2919, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN LA LÍNEA DE LOS PRINCIPIOS DE DDHH APLICADOS A LA FUNCIÓN POLICIAL, ¿QUÉ ACCIÓN DEBE IMPLEMENTAR LA INSTITUCIÓN POLICIAL PARA REDUCIR EL USO EXCESIVO DE LA FUERZA?', 'CAPACITACIÓN EN SOLUCIÓN PACÍFICA DE CONFLICTOS, ESTUDIO DE COMPORTAMIENTO DE MULTITUDES Y', 'OTORGAR MAYOR DISCRECIONALIDAD PARA INTERVENCIONES RÁPIDAS.', 'INCREMENTAR EL EQUIPAMIENTO LETAL DE SU PERSONAL.', 'PERMITIR USO PREVENTIVO DE LA FUERZA EN ZONAS DE ALTO RIESGO.', 'REDUCIR INFORMES Y SUPERVISIÓN SOBRE EL ACCIONAR POLICIAL.', NULL, 'a', 'CAPACITACIÓN EN SOLUCIÓN PACÍFICA DE CONFLICTOS, ESTUDIO DE COMPORTAMIENTO DE MULTITUDES Y', '(ART: II-II)**Uso de la fuerza', '186126'),
(2920, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN RELACIÓN AL CONTROL DEL USO DE LA FUERZA, ¿QUÉ MECANISMOS ESTABLECE EL TEXTO PARA SUPERVISAR Y SANCIONAR POTENCIALES EXCESOS?', 'SUPERVISIÓN EXCLUSIVA PREVIA POR EL MINISTERIO PÚBLICO.', 'INVESTIGACIONES Y SANCIONES ANTE PRESENTARSE EXCESOS EN EL USO DE LA FUERZA.', 'SANCIÓN SOCIAL POR PARTE DE LA CIUDADANÍA.', 'INFORMES PERIÓDICOS DE CADA OPERATIVO ANTE EL CONGRESO.', 'JUZGAMIENTO INMEDIATO POR TRIBUNALES INTERNACIONALES.', NULL, 'b', 'INVESTIGACIONES Y SANCIONES ANTE PRESENTARSE EXCESOS EN EL USO DE LA FUERZA.', '(ART: II-II)**Uso de la fuerza', '186127'),
(2921, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'INDIQUE CUÁL DE LAS SIGUIENTES ATRIBUCIONES CORRESPONDE A LA POLICÍA NACIONAL DEL PERÚ SEGÚN LA LEY MENCIONADA EN LOS CONCEPTOS PREVIOS.', 'HACER USO IRRESTRICTO DE LA FUERZA ANTE CUALQUIER ALTERACIÓN SOCIAL.', 'APLICAR EL USO DE LA FUERZA CONFORME A LA NORMA, CÓDIGO DE CONDUCTA Y PRINCIPIOS BÁSICOS SOBRE SU', 'IMPLEMENTAR EL USO DE LA FUERZA SIN NECESIDAD DE RENDIR CUENTAS.', 'ACTUAR ÚNICAMENTE BAJO ÓRDENES DEL MINISTERIO DEL INTERIOR EN MATERIA DE FUERZA.', 'NEGOCIAR EL USO DE LA FUERZA CON SINDICATOS POLICIALES.', NULL, 'b', 'APLICAR EL USO DE LA FUERZA CONFORME A LA NORMA, CÓDIGO DE CONDUCTA Y PRINCIPIOS BÁSICOS', '(ART: II-II)**Uso de la fuerza', '186129'),
(2922, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'LA LEGITIMIDAD DEL ACCIONAR POLICIAL AL HACER USO DE LA FUERZA QUEDA ASEGURADA SOLAMENTE SI:', 'SE BASA EN LA SUPERIORIDAD NUMÉRICA DEL PERSONAL POLICIAL.', 'SE EJECUTA CONFORME A LA LEY Y RESPETANDO LOS DERECHOS HUMANOS.', 'CUENTA CON APROBACIÓN POSTERIOR DEL MINISTERIO PÚBLICO.', 'RESPONDE A LA OPINIÓN PÚBLICA DEL MOMENTO.', 'DEPENDE DE LA GRAVEDAD DEL DELITO COMETIDO.', NULL, 'b', 'SE EJECUTA CONFORME A LA LEY Y RESPETANDO LOS DERECHOS HUMANOS.', '(ART: II-II)**Uso de la fuerza', '186130'),
(2923, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA FINALIDAD PRINCIPAL DE INFORMAR AL PERSONAL POLICIAL SOBRE LA OPERACIÓN ANTES DE SU EJECUCIÓN EN EL CONTEXTO DE MANTENIMIENTO DEL ORDEN PÚBLICO?', 'PERMITIR QUE EL PERSONAL DECIDA SI QUIERE PARTICIPAR EN LA OPERACIÓN.', 'FACILITAR LA IDENTIFICACIÓN DE POSIBLES AMENAZAS POR PARTE DE LA POLICÍA.', 'BRINDAR AL PERSONAL CONOCIMIENTO DE LA MISIÓN Y AUMENTAR LA GARANTIA DE CONFIANZA Y SEGURIDAD', 'GARANTIZAR QUE EL PERSONAL PUEDA ELEGIR EL EQUIPO QUE DESEE USAR.', 'REDUCIR LA CANTIDAD DE RECURSOS LOGÍSTICOS A DESPLEGAR.', NULL, 'c', 'BRINDAR AL PERSONAL CONOCIMIENTO DE LA MISIÓN Y AUMENTAR LA GARANTIA DE CONFIANZA Y', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186132'),
(2924, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LAS DISPOSICIONES ANALIZADAS, ¿EN QUÉ CIRCUNSTANCIAS ES LEGÍTIMO EL USO DE CUALQUIER MEDIO A SU ALCANCE POR PARTE DEL PERSONAL POLICIAL EN LA FUERZA POTENCIALMENTE LETAL?', 'CUANDO EXISTAN ENFRENTAMIENTOS ENTRE MANIFESTANTES Y AUTORIDADES.', 'ANTE CUALQUIER TIPO DE RESISTENCIA FÍSICA POR PARTE DE LOS MANIFESTANTES.', 'EN CIRCUNSTANCIAS EXTREMAS DONDE REPRESENTA UN PELIGRO INMINENTE LA VIDA PROPIA O DE OTRAS PERSONAS.', 'CUANDO LA MULTITUD SE NIEGUE A DISPERSARSE DESPUÉS DE VARIAS ADVERTENCIAS.', 'AL IDENTIFICAR A CUALQUIER PERSONA PORTANDO OBJETOS CONTUNDENTES.', NULL, 'c', 'EN CIRCUNSTANCIAS EXTREMAS DONDE REPRESENTA UN PELIGRO INMINENTE LA VIDA PROPIA O DE OTRAS', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186133'),
(2925, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DURANTE UNA MANIFESTACIÓN, ¿CUÁL ES EL PROCEDIMIENTO CORRECTO FRENTE A LA PRESENCIA DE MUJERES, NIÑOS, ANCIANOS O PERSONAS CON DISCAPACIDAD, SEGÚN EL PROTOCOLO?', 'AUMENTAR EL EMPLEO DE LA FUERZA POR CONSIDERARLOS ESCUDOS HUMANOS.', 'EVALUAR SU PARTICIPACIÓN PARA ADOPTAR MEDIOS DE DISUASIÓN, PROTECCIÓN Y/O CONTROL ADECUADOS.', 'DISUADIR EXCLUSIVAMENTE MEDIANTE AGENTES QUÍMICOS A ESTOS GRUPOS.', 'CONCENTRAR LOS ESFUERZOS EN DESALOJAR PRIMERO A ESTOS GRUPOS.', 'IGNORAR SU PRESENCIA DURANTE LA INTERVENCIÓN POLICIAL.', NULL, 'b', 'EVALUAR SU PARTICIPACIÓN PARA ADOPTAR MEDIOS DE DISUASIÓN, PROTECCIÓN Y/O CONTROL', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186134'),
(2926, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA RECOMENDACIÓN CENTRAL RESPECTO AL USO DEL EQUIPO POLICIAL (COMO GRILLETES, DEFENSA DE GOMA, AGENTES QUÍMICOS O ARMAS ESPECIALES) PACTADA PARA ANTES DE LA OPERACIÓN?', 'DEBE SER EMPLEADO SÓLO COMO MÉTODO DE ATAQUE.', 'EL EQUIPO ES DE DEFENSA Y SE USARÁ SOLO CUANDO LAS CIRCUNSTANCIAS LO REQUIERAN O LA LÍNEA DE COMANDO', 'PUEDE SER UTILIZADO CUANDO EL EFECTIVO POLICIAL LO CONSIDERE NECESARIO SIN AUTORIZACIÓN PREVIA.', 'SOLO SE UTILIZA DURANTE EL TRASLADO DE PERSONAS DETENIDAS.', 'DEBE EXHIBIRSE ÚNICAMENTE PARA AMEDRENTAR A LA MULTITUD.', NULL, 'b', 'EL EQUIPO ES DE DEFENSA Y SE USARÁ SOLO CUANDO LAS CIRCUNSTANCIAS LO REQUIERAN O LA LÍNEA DE', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186135'),
(2927, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL CRITERIO CLAVE PARA EL USO DIFERENCIADO Y PROPORCIONAL DE LA FUERZA RECOMENDADO AL PERSONAL POLICIAL?', 'EL GRADO DE VIOLENCIA POTENCIAL DE LA MULTITUD SOLAMENTE.', 'LA DISPONIBILIDAD DE ARMAMENTO LETAL.', 'LOS PRINCIPIOS DE LEGALIDAD, NECESIDAD Y PROPORCIONALIDAD.', 'LA CANTIDAD DE EFECTIVOS DESPLEGADOS.', 'EL RANGO JERÁRQUICO DEL OFICIAL A CARGO.', NULL, 'c', 'LOS PRINCIPIOS DE LEGALIDAD, NECESIDAD Y PROPORCIONALIDAD.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186136'),
(2928, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ RESTRICCIÓN ESPECÍFICA EXISTE SOBRE EL EMPLEO DE MATERIAL LACRIMÓGENO DURANTE LAS OPERACIONES?', 'PUEDE EMPLEARSE EN CUALQUIER LUGAR DONDE HAYA DISTURBIOS.', 'DEBE USARSE PRINCIPALMENTE EN HOSPITALES Y ASILOS PARA DISUADIR MAYOR NÚMERO DE PERSONAS.', 'SE EVITA SU USO EN INMEDIACIONES DE EDIFICACIONES DONDE SE CONGREGUEN PERSONAS CON MAYOR RIESGO,', 'NO EXISTE RESTRICCIÓN SOBRE SU USO EN NINGÚN CASO.', 'SU USO ES OBLIGATORIO EN TODAS LAS OPERACIONES DE CONTROL DE MULTITUDES.', NULL, 'c', 'SE EVITA SU USO EN INMEDIACIONES DE EDIFICACIONES DONDE SE CONGREGUEN PERSONAS CON MAYOR', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186138'),
(2929, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'AL DISOLVER UNA MULTITUD, ¿CUÁL ES LA TÉCNICA RECOMENDADA PARA EVITAR EL AUMENTO DE LA RESISTENCIA DE LOS MANIFESTANTES?', 'AVANZAR DESDE EL PUNTO MÁS CÉNTRICO Y DENSO DEL GRUPO.', 'PROCEDER POR EL LADO MÁS COMPACTO DEL GRUPO.', 'TECNICA DE USO, DIVIDIR Y DISPERSAR EN EL SENTIDO O DIRECCIÓN DE LA VIA QUE SE HAYA PREVISTO.', 'ALEJARSE DEL GRUPO SIN INTERACCIÓN ALGUNA.', 'UTILIZAR AGENTES QUÍMICOS DE FORMA INMEDIATA PARA DESINTEGRAR LA MULTITUD.', NULL, 'c', 'TECNICA DE USO, DIVIDIR Y DISPERSAR EN EL SENTIDO O DIRECCIÓN DE LA VIA QUE SE HAYA PREVISTO.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186139'),
(2930, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LOS LINEAMIENTOS ESTUDIADOS, ¿CÓMO DEBE ACTUAR EL PERSONAL POLICIAL ANTE PERSONAS QUE HUYEN O CAEN Y NO PARTICIPAN EN HECHOS VIOLENTOS DURANTE OPERATIVOS?', 'UTILIZAR LA FUERZA PARA EVITAR QUE ESCAPEN.', 'HACER USO DE ARMAS NO LETALES PARA DETENERLOS.', 'NO HACER USO DE LA FUERZA CONTRA ELLOS.', 'REDUCIRLOS MEDIANTE MANIOBRAS DE SOMETIMIENTO.', 'ARRESTAR INMEDIATAMENTE A TODA PERSONA QUE HUYA.', NULL, 'c', 'NO HACER USO DE LA FUERZA CONTRA ELLOS.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186140'),
(2931, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ ACCIÓN SE EXIGE INMEDIATAMENTE DESPUÉS DE UNA OPERACIÓN POLICIAL SI EXISTEN DETENIDOS, LESIONADOS O MUERTOS?', 'PUBLICAR UN COMUNICADO DE PRENSA SOBRE LOS HECHOS.', 'ESPERAR INSTRUCCIONES ANTES DE COMUNICAR A FAMILIARES.', 'COMUNICAR DE INMEDIATO A SUS FAMILIARES.', 'HACER UN INFORME AL MINISTERIO DEL INTERIOR ÚNICAMENTE.', 'LLEVAR A LOS DETENIDOS A UN LUGAR NO OFICIAL PARA INTERROGATORIO PREVIO.', NULL, 'c', 'COMUNICAR DE INMEDIATO A SUS FAMILIARES.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186141'),
(2932, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN EL CONTEXTO DEL USO DE LA FUERZA, ¿QUÉ OBLIGACIÓN TIENE EL PERSONAL QUE EMPLEE DEFENSA DE GOMA, AGENTES QUÍMICOS O ARMAS ESPECIALES?', 'NO DEJAR EVIDENCIA DE SU INTERVENCIÓN PARA EVITAR CUESTIONAMIENTOS LEGALES.', 'FORMULARA EL PARTE CORRESPONDIENTE DE SU INTERVENCIÓN Y REGISTRAR LA EXISTENCIA DE DETENIDOS, HERIDOS', 'LLEVAR LOS EQUIPOS A SU BASE SIN NOTIFICACIÓN DE USO.', 'SOLO INFORMAR SI HAY MUERTOS.', 'REMITIR ÚNICAMENTE UN REPORTE VERBAL A SU SUPERIOR INMEDIATO.', NULL, 'b', 'FORMULARA EL PARTE CORRESPONDIENTE DE SU INTERVENCIÓN Y REGISTRAR LA EXISTENCIA DE', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186143'),
(2933, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES EL CRITERIO PARA DEJAR DE EMPLEAR LA FUERZA DURANTE LA INTERVENCIÓN POLICIAL?', 'CUANDO LA LÍNEA DE COMANDO AUTORICE LA RETIRADA.', 'AL CESE DE LA RESISTENCIA O VIOLENCIA, ADOPTANDO MEDIDAS DE SEGURIDAD.', 'CUANDO NO HAY TESTIGOS.', 'AL FINALIZAR LA JORNADA LABORAL DE LOS EFECTIVOS.', 'EN CUANTO SE IDENTIFIQUE A UN MANIFESTANTE LÍDER.', NULL, 'b', 'AL CESE DE LA RESISTENCIA O VIOLENCIA, ADOPTANDO MEDIDAS DE SEGURIDAD.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186144'),
(2934, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'RESPECTO AL TRATO DE LOS ARRESTADOS O DETENIDOS, ¿QUÉ OBLIGACIÓN ESTABLECE DIRECTAMENTE LA DIRECTIVA LUEGO DE LA INTERVENCIÓN?', 'PUEDEN SER SOMETIDOS A MÉTODOS DE INTERROGATORIO FORZADO EN CASOS EXCEPCIONALES.', 'NINGUNA CIRCUNSTANCIA JUSTIFICA LA TORTURA NI TRATOS CRUELES, INHUMANOS O DEGRADANTES.', 'ESTÁ PERMITIDO EL USO DE PRESIÓN PSICOLÓGICA EN OPERATIVOS DE ALTO RIESGO.', 'SE PERMITE LA INCOMUNICACIÓN PREVENTIVA POR 24 HORAS.', 'DEBEN SER EXHIBIDOS PÚBLICAMENTE PARA DISUADIR FUTURAS PROTESTAS.', NULL, 'b', 'NINGUNA CIRCUNSTANCIA JUSTIFICA LA TORTURA NI TRATOS CRUELES, INHUMANOS O DEGRADANTES.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186145'),
