(2939, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿SOBRE QUÉ ASPECTOS DEBE RECAER LA EVALUACIÓN FINAL DE CADA INTERVENCIÓN POLICIAL?', 'ÚNICAMENTE EN LOS ERRORES COMETIDOS.', 'EN QUÉ MOMENTOS SE PUDO USAR MÁS LA FUERZA.', 'DESTACANDO LAS FORTALEZAS Y DEBILIDADES.', 'LIMITARSE A METAS LOGRADAS DE ARRESTOS.', 'EXCLUSIVAMENTE SOBRE LA RECUPERACIÓN DE EQUIPO PERDIDO.', NULL, 'c', 'DESTACANDO LAS FORTALEZAS Y DEBILIDADES.', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186150'),
(2940, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL ES LA OBLIGACIÓN RESPECTO A LA EVIDENCIA DE LOS HECHOS DURANTE LA OPERACIÓN POLICIAL?', 'NO PUEDE EMPLEARSE NINGÚN EQUIPO DE FILMACIÓN POR SEGURIDAD.', 'DEBE PROHIBIRSE A TERCEROS GRABAR LAS INCIDENCIAS.', 'PREVER EL EMPLEO DE EQUIPOS DE FILMACIÓN QUE PERMITAN PERENNIZAR LOS HECHOS Y FORTALECER LA EVIDENCIA', 'SÓLO DEBEN GRABARSE LAS DETENCIONES RELEVANTES.', 'LAS GRABACIONES SOLO SE ADMITEN CON AUTORIZACIÓN JUDICIAL PREVIA.', NULL, 'c', 'PREVER EL EMPLEO DE EQUIPOS DE FILMACIÓN QUE PERMITAN PERENNIZAR LOS HECHOS Y FORTALECER LA', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186151'),
(2941, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SI DURANTE UNA OPERACIÓN SURGEN HECHOS O SITUACIONES NO PREVISTAS, ¿CÓMO DEBEN PROCEDER LOS JEFES OPERATIVOS SEGÚN LAS PAUTAS ANALIZADAS?', 'IMITAR PROCEDIMIENTOS ESTABLECIDOS PARA SITUACIONES SIMILARES.', 'AGUARDAR A QUE LA AUTORIDAD NACIONAL EMITA UNA DIRECTIVA ESPECÍFICA.', 'ACTUAR EN BASE A SUS CONOCIMIENTOS Y EXPERIENCIA, DISPONIENDO LAS MEDIDAS NECESARIAS PARA SUPERARLAS.', 'CANCELAR DE INMEDIATO LA OPERACIÓN POLICIAL.', 'DELEGAR LA DECISIÓN EN LOS SUBORDINADOS PRESENTES.', NULL, 'c', 'ACTUAR EN BASE A SUS CONOCIMIENTOS Y EXPERIENCIA, DISPONIENDO LAS MEDIDAS NECESARIAS PARA', '(ART: II-IV)**EJECUCIÃ?N DE LAS OPERACIONES', '186152'),
(2942, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LA GUÍA, ¿QUÉ ACCIÓN ESTÁ PROHIBIDA PARA EL NEGOCIADOR DURANTE LA INTERVENCIÓN CON UN CAUSANTE?', 'DISTRAER AL CAUSANTE CUANDO ESTÉ POR CUMPLIRSE EL PLAZO FIJADO.', 'ELABORAR UN PLAN DE CONTINGENCIA ANTE POSIBLE RENDICIÓN.', 'IGNORAR EL CONTACTO CON EL CAUSANTE.', 'TRANSMITIR CON LA OZ SENTIMIENTOS DE COMPRENSIÓN, AMISTAD, CALIDEZ Y RESPETO.', 'PLANIFICAR LA ENTREGA DE ALIMENTOS.', NULL, 'c', 'IGNORAR EL CONTACTO CON EL CAUSANTE.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186154'),
(2943, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CUÁL DE LAS SIGUIENTES PRÁCTICAS ESTÁ EN CONCORDANCIA CON LOS DDHH APLICADOS A LA FUNCIÓN POLICIAL SEGÚN LA GUÍA ANALIZADA?', 'ACEPTAR DE INMEDIATO TODAS LAS EXIGENCIAS DEL CAUSANTE PARA PRESERVAR LA VIDA.', 'PROMETER CUMPLIR CUALQUIER DEMANDA PARA MANTENER LA CALMA DEL CAUSANTE.', 'IMPLICAR A UN SEGUNDO NEGOCIADOR DURANTE EL PROCESO.', 'AMENAZAR SUTILMENTE PARA GANAR RESPETO.', 'USAR LENGUAJE NEGATIVO Y LIMITANTE.', NULL, 'c', 'IMPLICAR A UN SEGUNDO NEGOCIADOR DURANTE EL PROCESO.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186155'),
(2944, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'EN UNA SITUACIÓN DE CRISIS, ¿QUIÉN DEBE ENTREGAR ALIMENTOS, MEDICINAS O ROPA AL CAUSANTE SEGÚN LA GUÍA?', 'EL NEGOCIADOR PRINCIPAL.', 'UN POLICÍA DE ALTO RANGO.', 'UN MÉDICO POLICIAL.', 'OTRA PERSONA DISTINTA AL NEGOCIADOR.', 'UN FAMILIAR DEL CAUSANTE PREFERENTEMENTE.', NULL, 'd', 'OTRA PERSONA DISTINTA AL NEGOCIADOR.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186157'),
(2945, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DE ACUERDO A LOS PRINCIPIOS DE LA GUÍA, ¿QUÉ ACTITUD DEBE ADOPTAR EL NEGOCIADOR RESPECTO A LAS EMOCIONES DEL CAUSANTE?', 'MOSTRARSE IMPASIBLE Y OBJETIVO PARA EVITAR DESBORDES.', 'REACCIONAR CON SENSIBILIDAD PARA ESTABLECER EMPATÍA Y CONTROL.', 'IGNORAR LAS EMOCIONES PARA CENTRARSE EN LOS HECHOS.', 'CONFRONTAR EMOCIONALMENTE AL CAUSANTE PARA DARLE REALISMO A LA SITUACIÓN.', 'UTILIZAR LAS EMOCIONES PARA MANIPULAR LA DECISIÓN DEL CAUSANTE EN FAVOR DE LA POLICÍA.', NULL, 'b', 'REACCIONAR CON SENSIBILIDAD PARA ESTABLECER EMPATÍA Y CONTROL.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186158'),
(2946, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿CÓMO DEBE PROCEDER EL NEGOCIADOR SI EL CAUSANTE LLEGA AL TIEMPO LÍMITE FIJADO DURANTE LAS CONVERSACIONES?', 'RECORDARLE EL TIEMPO LÍMITE PARA EVIDENCIAR CONTROL.', 'DISTRAER AL CAUSANTE Y GANAR TIEMPO DE NEGOCIACIÓN.', 'AMENAZAR CON INTERVENCIÓN POLICIAL INMEDIATA.', 'INTERRUMPIR LA COMUNICACIÓN PARA PRESIONAR.', 'SOLICITAR UNA EVALUACIÓN MÉDICA DEL CAUSANTE.', NULL, 'b', 'DISTRAER AL CAUSANTE Y GANAR TIEMPO DE NEGOCIACIÓN.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186161'),
(2947, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'DENTRO DE LA FUNCIÓN POLICIAL, UTILIZAR UNA VOZ QUE TRANSMITA SENTIMIENTOS DE COMPRENSIÓN, AMISTAD, CALIDEZ Y RESPETO BUSCA PRINCIPALMENTE:', 'AUMENTAR LA PRESIÓN PSICOLÓGICA SOBRE EL CAUSANTE.', 'CREAR UN AMBIENTE QUE FACILITE LA RENDICIÓN PACÍFICA Y LA PROTECCIÓN DE LOS DDHH.', 'GENERAR CONFUSIÓN CON RELACIÓN A LA VERDADERA ACTITUD DEL NEGOCIADOR.', 'CONSEGUIR LA SIMPATÍA PÚBLICA ANTE LA ACCIÓN POLICIAL.', 'EVITAR LA GRABACIÓN DE LA INTERVENCIÓN.', NULL, 'b', 'CREAR UN AMBIENTE QUE FACILITE LA RENDICIÓN PACÍFICA Y LA PROTECCIÓN DE LOS DDHH.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186162'),
(2948, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEÑALE LA CONDUCTA CONGRUENTE CON LA GUÍA APLICABLE A LA FUNCIÓN POLICIAL FRENTE A UN CAUSANTE ARMADO QUE SOLICITA DROGA O ALCOHOL:', 'NEGOCIAR LA ENTREGA BAJO ESTRICTA SUPERVISIÓN.', 'ENTREGAR DROGA O ALCOHOL PARA EVITAR RIESGOS.', 'NEGARSE FIRMEMENTE Y DISCUTIR LAS ALTERNATIVAS.', 'NO ENTREGAR DROGA NI ALCOHOL, BAJO NINGÚN MOTIVO.', 'SOLICITAR AUTORIZACIÓN SUPERIOR PARA ENTREGAR EL PEDIDO.', NULL, 'd', 'NO ENTREGAR DROGA NI ALCOHOL, BAJO NINGÚN MOTIVO.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186164'),
(2949, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', '¿QUÉ DEBE EVITAR EL NEGOCIADOR PARA MANTENER LA LEGITIMIDAD DE LA FUNCIÓN POLICIAL ANTE UNA CRISIS QUE INVOLUCRA REHENES?', 'MANTENER ARCHIVOS DE LA INTERVENCIÓN.', 'ACEPTAR AMENAZAS O ACTOS VIOLENTOS COMO JUSTIFICABLES.', 'ELABORAR INFORMES SOBRE LA SITUACIÓN.', 'COLABORAR CON AUTORIDADES JUDICIALES.', 'CONTACTAR A LA PRENSA PARA INFORMAR AVANCES.', NULL, 'b', 'ACEPTAR AMENAZAS O ACTOS VIOLENTOS COMO JUSTIFICABLES.', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186165'),
(2950, 'Decreto Supremo N° 009- 2018-Jus - Protocolos De Actuación Lnterinstitucional Es', 'SEGÚN LAS BUENAS PRÁCTICAS INDICADAS, ¿POR QUÉ ES RELEVANTE TOMAR NOTA DE TODO LO SUCEDIDO DURANTE LA NEGOCIACIÓN?', 'PARA CUMPLIR CON REQUISITOS AUDITABLES DEL MINISTERIO DEL INTERIOR.', 'PARA JUSTIFICAR LAS DECISIONES ANTE UNA PROBABLE INVESTIGACIÓN ADMINISTRATIVA O PENAL, Y SALVAGUARDAR', 'PARA EVITAR OLVIDAR DETALLES DEL CASO AL COMUNICARLO A LA PRENSA.', 'PARA ELABORAR ACTAS NOTARIALES PRECISAS.', 'PARA CUMPLIR MANDATOS JUDICIALES INMEDIATOS.', NULL, 'b', 'PARA JUSTIFICAR LAS DECISIONES ANTE UNA PROBABLE INVESTIGACIÓN ADMINISTRATIVA O PENAL, Y', '(ART: II-V)**GUIA PARA NEGOCIADORES NO ENTRENADOS', '186166'),
(2951, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'DESARROLLAR MEDIDAS PARA LA ATENCIÓN DE CASOS DE DESAPARICIÓN DE PERSONAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS, ABARCANDO LA ATENCIÓN DE DENUNCIAS, DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA, UBICACIÓN Y EMPLEO DE MECANISMOS TECNOLÓGICOS PARA LA ORGANIZACIÓN Y DIFUSIÓN DE INFORMACIÓN SOBRE CASOS DE DESAPARICIÓN DE PERSONAS. SE REFIERE AL:', 'OBJETO', 'ÁMBITO DE APLICACIÓN', 'PROPÓSITO', 'PRINCIPIO', 'ACTUACIÓN', NULL, 'a', 'OBJETO', 'ARTÍCULO 1°, MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185859'),
(2952, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'GARANTIZAR LA ATENCIÓN DE DENUNCIAS, DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA Y UBICACIÓN DE PERSONAS DE PERSONAS DESAPARECIDAS, ASÍ COMO PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'ACTUACIÓN', 'PROPÓSITO', 'ÁMBITO DE APLICACIÓN', 'PRINCIPIO', 'FINALIDAD', NULL, 'e', 'FINALIDAD', 'ARTÍCULO 2°, a., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185860'),
(2953, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'PROMOVER LA COOPERACIÓN ENTRE AUTORIDADES, ENTIDADES PÚBLICAS Y PRIVADAS, PERSONAS NATURALES Y JURÍDICAS, SOCIEDAD CIVIL Y COMUNIDAD EN GENERAL PARA LA DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA Y UBICACIÓN DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'ÁMBITO DE APLICACIÓN', 'FINALIDAD', 'PRINCIPIO', 'PROPÓSITO', 'ACTUACIÓN', NULL, 'b', 'FINALIDAD', 'ARTÍCULO 2°, b., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185861'),
(2954, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'IMPLEMENTAR MECANISMOS TECNOLÓGICOS PARA EL INTERCAMBIO DE INFORMACIÓN SOBRE CASOS DE DESAPARICIÓN DE PERSONAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'PRINCIPIO', 'PROPÓSITO', 'FINALIDAD', 'ÁMBITO DE APLICACIÓN', 'ACTUACIÓN', NULL, 'c', 'FINALIDAD', 'ARTÍCULO 2°, c., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185862'),
(2955, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LA POLICÍA NACIONAL DEL PERÚ Y LAS INSTITUCIONES COMPRENDIDAS EN EL PRESENTE DECRETO LEGISLATIVO EJECUTAN DE FORMA OPORTUNA Y SIN DILACIONES TODAS LAS ACCIONES Y MEDIDAS ORIENTADAS A LA ATENCIÓN DE LA DENUNCIA, DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA Y UBICACIÓN DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS. CORRESPONDE AL PRINCIPIO DE:', 'INMEDIATEZ', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 'ATENCIÓN DE SALUD Y COLABORACIÓN EN LA DIFUSIÓN Y BÚSQUEDA', 'ESTADÍA TEMPORAL', NULL, 'a', 'INMEDIATEZ', 'ARTÍCULO 3°, a., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185863'),
(2956, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'EN TODA MEDIDA QUE ADOPTE EL ESTADO A TRAVÉS DE LOS PODERES EJECUTIVO, LEGISLATIVO Y JUDICIAL, DEL MINISTERIO PÚBLICO, LOS GOBIERNOS REGIONALES, GOBIERNOS LOCALES Y SUS DEMÁS INSTITUCIONES, ASÍ COMO EN LA ACCIÓN DE LA SOCIEDAD, SE CONSIDERA DE MANERA PRIMORDIAL LA GARANTÍA Y PROTECCIÓN DE LOS DERECHOS DE LAS PERSONAS DESAPARECIDAS Y TODO CUENTO LE FAVORECE. CORRESPONDE AL PRINCIPIO DE:', 'INTERES SUPERIOR DE LA PERSONA DESAPARECIDA EN SITUACION DE VULNERABILIDAD', 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 'ATENCIÓN DE SALUD Y COLABORACIÓN EN LA DIFUSIÓN Y BÚSQUEDA', 'ESTADÍA TEMPORAL', 'COLABORACIÓN', NULL, 'a', 'INTERES SUPERIOR DE LA PERSONA DESAPARECIDA EN SITUACION DE VULNERABILIDAD', 'ARTÍCULO 3°, b., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185864'),
(2957, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LAS AUTORIDADES, ENTIDADES PÚBLICAS Y PRIVADAS, SOCIEDAD CIVIL Y COMUNIDAD EN GENERAL BRINDAN APOYO A LA POLICÍA NACIONAL DEL PERÚ EN LA DIFUSIÓN, INVESTIGACIÓN, BÚSQUEDA Y UBICACIÓN DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS, EN EL MARCO DE LA OBLIGACIÓN SEÑALADA EN EL ARTÍCULO VI DEL TÍTULO PRELIMINAR DEL DECRETO LEGISLATIVO N° 1267, LEY DE LA POLICÍA NACIONAL DEL PERÚ. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 'PROPÓSITO', 'ÁMBITO DE APLICACIÓN', 'COLABORACIÓN', 'ACTUACIÓN', NULL, 'a', 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO 4°, 4.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185865'),
(2958, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LAS INSTITUCIONES PÚBLICAS O PRIVADAS APOYAN LA DIFUSIÓN DE LA NOTA DE ALERTA Y LA ALERTA AMBER UNA VEZ QUE LA POLICÍA NACIONAL DEL PERÚ HAYA DIFUNDIDO LA DESAPARICIÓN. PARA DICHO EFECTO, ESTAS INSTITUCIONES PONEN A DISPOSICIÓN DE LA AUTORIDAD POLICIAL LOS CANALES DE COORDINACIÓN Y ARTICULACIÓN PERTINENTES, INCLUYENDO LA ALERTA AMBER. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 'ACTUACIÓN', 'ÁMBITO DE APLICACIÓN', 'COLABORACIÓN', 'PROPÓSITO', NULL, 'a', 'APOYO A LA POLICÍA NACIONAL DEL PERÚ', 'ARTÍCULO 4°, 4.2., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185866'),
(2959, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'SE CONSIDERA PERSONA DESAPARECIDA A AQUELLA QUE SE ENCUENTRA AUSENTE DE SU DOMICILIO HABITUAL Y RESPECTO DEL CUAL SE DESCONOCE SU PARADERO. DEFINICIÓN QUE CORRESPONDE A:', 'PERSONA DESAPARECIDA', 'NOTA DE ALERTA', 'PERSONAS EN SITUACIÓN DE VULNERABILIDAD', 'COLABORACIÓN', 'PROPÓSITO', NULL, 'a', 'PERSONA DESAPARECIDA', 'ARTÍCULO 5°, a., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185867'),
(2960, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'PERSONAS QUE SUFREN DISCRIMINACIÓN O SITUACIONES DE DESPROTECCIÓN, ENTRE ELLAS: NIÑAS, NIÑOS, ADOLESCENTES, PERSONAS ADULTAS MAYORES, PERSONAS CON DISCAPACIDAD, DESPLAZADOS, MIGRANTES, MUJERES VÍCTIMAS DE VIOLENCIA, INTEGRANTES DE PUEBLOS INDÍGENAS, PERSONAS LGTBQ+, SITUACIÓN DE POBREZA, ENTRE OTRAS PERSONAS QUE SE ENCUENTREN EN ESTA SITUACIÓN. DEFINICIÓN QUE CORRESPONDE A:', 'PERSONAS EN SITUACION DE VULNERABILIDAD', 'PERSONA DESAPARECIDA', 'COLABORACIÓN', 'PROPÓSITO', 'NOTA DE ALERTA', NULL, 'a', 'PERSONAS EN SITUACION DE VULNERABILIDAD', 'ARTÍCULO 5°, b., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185868'),
(2961, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'FORMATO EMITIDO POR LA POLICÍA NACIONAL DEL PERÚ POSTERIOR A LA RECEPCIÓN Y REGISTRO DE LA DENUNCIA POR DESAPARICIÓN DE UNA PERSONA EN EL SISTEMA DE DENUNCIAS DE LA POLICÍA NACIONAL DEL PERÚ. DEFINICIÓN QUE CORRESPONDE A:', 'NOTA DE ALERTA', 'PERSONAS EN SITUACIÓN DE VULNERABILIDAD', 'COLABORACIÓN', 'PROPÓSITO', 'PERSONA DESAPARECIDA', NULL, 'a', 'NOTA DE ALERTA', 'ARTÍCULO 5°, C., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185869'),
(2962, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'CONTIENE INFORMACIÓN DE LA DENUNCIA Y FOTOGRAFÍA VISIBLE Y ACTUALIZADA DE LA PERSONA DESAPARECIDA Y ES DIFUNDIDA A TRAVÉS DEL PORTAL DE PERSONAS DESAPARECIDAS Y OTROS MEDIOS DE COMUNICACIÓN SOCIAL. DEFINICIÓN QUE CORRESPONDE A:', 'PERSONAS EN SITUACIÓN DE VULNERABILIDAD', 'COLABORACIÓN', 'NOTA DE ALERTA', 'PROPÓSITO', 'PERSONA DESAPARECIDA', NULL, 'c', 'NOTA DE ALERTA', 'ARTÍCULO 5°, c., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185870'),
(2963, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'FORMATO EMITIDO POR LA POLICÍA NACIONAL DEL PERÚ QUE RESUME LA NOTA DE ALERTA. SE EMITE PARA LOS CASOS DE DESAPARICIÓN DE NIÑAS, NIÑOS, ADOLESCENTES, PERSONAS CON DISCAPACIDAD Y MUJERES VÍCTIMAS DE VIOLENCIA EN SITUACIÓN DE ALTO RIESGO. DEFINICIÓN QUE CORRESPONDE A:', 'COLABORACIÓN', 'ALERTA AMBER', 'PERSONAS EN SITUACIÓN DE VULNERABILIDAD', 'PERSONA DESAPARECIDA', 'PROPÓSITO', NULL, 'b', 'ALERTA AMBER', 'ARTÍCULO 5°, d., MODIFICADO POR EL ARTÍCULO ÚNICO DE LA LEY N° 32305, PUBLICADO EL 24 ABRIL 2025', '185871'),
(2964, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'ES TEMPORAL Y SU DIFUSIÓN ES MASIVA CON EL APOYO DE ENTIDADES PÚBLICAS Y PRIVADAS Y PERSONAS NATURALES Y JURÍDICAS. DEFINICIÓN QUE CORRESPONDE A:', 'PROPÓSITO', 'ALERTA AMBER', 'PERSONA DESAPARECIDA', 'PERSONAS EN SITUACIÓN DE VULNERABILIDAD', 'COLABORACIÓN', NULL, 'b', 'ALERTA AMBER', 'ARTÍCULO 5°, d., MODIFICADO POR EL ARTÍCULO ÚNICO DE LA LEY N° 32305, PUBLICADO EL 24 ABRIL 2025', '185872'),
(2965, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'ANTE LA AUSENCIA DE UNA PERSONA DE SU DOMICILIO HABITUAL Y DE LA CUAL SE DESCONOCE SU PARADERO, CUALQUIER PERSONA PUEDE PRESENTAR UNA DENUNCIA ANTE LA POLICÍA NACIONAL DEL PERÚ. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'PROPÓSITO DE LA DENUNCIA', 'REGISTRO DE LA DENUNCIA', 'PRESENTACION DE DENUNCIA', 'OMISIÓN DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', NULL, 'c', 'PRESENTACION DE DENUNCIA', 'ARTÍCULO 6°, 6.1.', '185873'),
(2966, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LA DENUNCIA SE PRESENTA EN CUALQUIER MOMENTO ANTE LA POLICÍA NACIONAL DEL PERÚ. CUANDO LA DENUNCIA SE PRESENTA POR PERSONAS CUYA LENGUA MATERNA ES DISTINTA AL CASTELLANO, PERSONA CON DISCAPACIDAD, PERSONA ADULTA MAYOR U, OTRA SITUACIÓN DE VULNERABILIDAD, LA POLICÍA NACIONAL DEL PERÚ GARANTIZA SU ATENCIÓN CONFORME A LAS DIRECTIVAS, LINEAMIENTOS Y PROTOCOLOS VIGENTES. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'OMISIÓN DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', 'PRESENTACION DE DENUNCIA', 'PROPÓSITO DE LA DENUNCIA', 'REGISTRO DE LA DENUNCIA', NULL, 'c', 'PRESENTACION DE DENUNCIA', 'ARTÍCULO 6°, 6.2.', '185874'),
(2967, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'EL FUNCIONARIO, SERVIDOR PÚBLICO O PERSONAL QUE LABORE EN UNA ENTIDAD DE LA ADMINISTRACIÓN PÚBLICA QUE TOME CONOCIMIENTO SOBRE ALGÚN CASO DE DESAPARICIÓN DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS DEBE COMUNICAR DE FORMA INMEDIATA CON LA POLICÍA NACIONAL DEL PERÚ. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'REGISTRO DE LA DENUNCIA', 'PROPÓSITO DE LA DENUNCIA', 'PRESENTACION DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', 'OMISIÓN DE LA DENUNCIA', NULL, 'c', 'PRESENTACION DE LA DENUNCIA', 'ARTÍCULO 6°, 6.3.', '185875'),
(2968, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LA POLICÍA NACIONAL DEL PERÚ ATIENDE LAS DENUNCIAS SOBRE DESAPARICIÓN DE MANERA INMEDIATA Y EN CUALQUIER MOMENTO, ENCONTRÁNDOSE A CARGO DE SU RECEPCIÓN Y TRÁMITE, BAJO RESPONSABILIDAD FUNCIONAL. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'ATENCIÓN DE LA DENUNCIA', 'REGISTRO DE LA DENUNCIA', 'PROPÓSITO DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', 'OMISIÓN DE LA DENUNCIA', NULL, 'a', 'ATENCIÓN DE LA DENUNCIA', 'ARTÍCULO 7°, 7.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185876'),
(2969, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'NO ES NECESARIO QUE TRANSCURRAN VEINTICUATRO (24) HORAS DESDE LA TOMA DE CONOCIMIENTO DE LA DESAPARICIÓN PARA ATENDER LA DENUNCIA. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'ATENCIÓN DE LA DENUNCIA', 'REGISTRO DE LA DENUNCIA', 'PROPÓSITO DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', 'OMISIÓN DE LA DENUNCIA', NULL, 'a', 'ATENCIÓN DE LA DENUNCIA', 'ARTÍCULO 7°, 7.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185877'),
(2970, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LA POLICÍA NACIONAL DEL PERÚ RECIBE LA DENUNCIA, LA REGISTRA EN EL SISTEMA DE DENUNCIAS POLICIALES (SIDPOL) O EN EL SISTEMA DE REGISTRO DE DENUNCIAS DE INVESTIGACIÓN CRIMINAL (SIRDIQ), E INSCRIBE LA INFORMACIÓN EN EL REGISTRO NACIONAL DE INFORMACIÓN DE PERSONAS DESAPARECIDAS. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'REGISTRO DE LA DENUNCIA', 'ATENCIÓN DE LA DENUNCIA', 'PROPÓSITO DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', 'OMISIÓN DE LA DENUNCIA', NULL, 'b', 'ATENCIÓN DE LA DENUNCIA', 'ARTÍCULO 7°, 7.3., MODIFICADO POR EL ARTÍCULO ÚNICO DE LA LEY N° 32305, PUBLICADO EL 24 ABRIL 2025', '185878'),
(2971, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'EN EL CASO DE QUE LA DENUNCIA NO FUESE RECIBIDA EN FORMA INMEDIATA POR LA POLICÍA NACIONAL DEL PERÚ, LA PERSONA AFECTADA PUEDE DENUNCIAR ESTE HECHO A LA INSPECTORÍA GENERAL DE LA POLICÍA NACIONAL DEL PERÚ Y/O A LA CENTRAL ÚNICA DE DENUNCIAS DEL MINISTERIO DEL INTERIOR, SEGÚN CORRESPONDA. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'PROPÓSITO DE LA DENUNCIA', 'ATENCIÓN DE LA DENUNCIA', 'REGISTRO DE LA DENUNCIA', 'DIFUSIÓN DE LA DENUNCIA', 'OMISIÓN DE LA DENUNCIA', NULL, 'b', 'ATENCIÓN DE LA DENUNCIA', 'ARTÍCULO 7°, 7.3., MODIFICADO POR EL ARTÍCULO ÚNICO DE LA LEY N° 32305, PUBLICADO EL 24 ABRIL 2025', '185879'),
(2972, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LA POLICÍA NACIONAL DEL PERÚ ES RESPONSABLE DE INVESTIGAR Y REALIZAR LA BÚSQUEDA DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS; Y, DE INVESTIGAR LA COMISIÓN DE DELITOS CONCURRENTES, EN COORDINACIÓN CON EL MINISTERIO PÚBLICO. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', NULL, 'c', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 9°, 9.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185880'),
(2973, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'SI DE LAS CIRCUNSTANCIAS EN QUE SE TOMA CONOCIMIENTO LA DESAPARICIÓN Y/O INVESTIGACIÓN POLICIAL, SE DETERMINE O COMPRUEBE LA PRESENCIA DE DELITOS CONCURRENTES, LOS ÓRGANOS ESPECIALIZADOS DE LA POLICÍA NACIONAL DEL PERÚ ARTICULAN ESFUERZOS E INTERVIENEN, CONFORME A SUS PROCEDIMIENTOS OPERATIVOS Y NORMATIVA APLICABLE. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', NULL, 'c', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 9°, 9.2., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185881'),
(2974, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LAS AUTORIDADES, ENTIDADES PÚBLICAS Y PRIVADAS, PERSONAS NATURALES Y JURÍDICAS, SOCIEDAD CIVIL Y COMUNIDAD EN GENERAL ESTÁN OBLIGADAS A PRESTAR APOYO A LA POLICÍA NACIONAL DEL PERÚ EN LA INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DESAPARECIDAS, ASÍ COMO DE PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS, CUANDO LAS CIRCUNSTANCIAS ASÍ LO REQUIERAN, EN EL CUMPLIMIENTO DE SUS FUNCIONES. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', NULL, 'e', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 9°, 9.3., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185882'),
(2975, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LA POLICÍA NACIONAL DEL PERÚ PUEDE UTILIZAR LA GEOLOCALIZACIÓN CUANDO CONSTITUYA UN MEDIO NECESARIO PARA LA INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DESAPARECIDAS. LA PRESENTE MEDIDA SERÁ EJECUTADA A TRAVÉS DE LA UNIDAD ESPECIALIZADA DE LA POLICÍA NACIONAL DEL PERÚ QUE REALICE DICHA FUNCIÓN. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', NULL, 'a', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 9°, 9.4., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185883'),
(2976, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LAS AUTORIDADES ENCARGADAS DE DETERMINAR Y PROPORCIONAR LA AUTORIZACIÓN E INFORMACIÓN DE LA GEOLOCALIZACIÓN, SE RIGEN POR EL PRINCIPIO DE INMEDIATEZ; BAJO RESPONSABILIDAD ADMINISTRATIVA Y PENAL. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', NULL, 'c', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 9°, 9.4., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185884'),
(2977, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LAS EMPRESAS OPERADORAS DE TELEFONÍA MÓVIL Y TELEFONÍA FIJA PROPORCIONAN EL LISTADO DE NÚMEROS TELEFÓNICOS DE LLAMADAS ENTRANTES Y SALIENTES, CON LOS NOMBRES Y APELLIDOS DE LOS TITULARES, DE LAS LÍNEAS TELEFÓNICAS VINCULADAS A LA DESAPARICIÓN DE PERSONAS QUE REQUIERA LA POLICÍA NACIONAL DEL PERÚ, OBSERVANDO LO DISPUESTO POR EL ARTÍCULO 2, INCISO 10 DE LA CONSTITUCIÓN POLÍTICA DEL PERÚ. EN EL REGLAMENTO DEL PRESENTE DECRETO LEGISLATIVO SE REGULA EL PERIODO DE LA INFORMACIÓN REQUERIDA. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'INVESTIGACIÓN DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS NO DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', NULL, 'e', 'INVESTIGACIÓN Y BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 9°, 9.5., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185885'),
(2978, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'CUALQUIER ENTIDAD PÚBLICA O PRIVADA Y PERSONA NATURAL O JURÍDICA QUE UBIQUE O CUENTE CON INFORMACIÓN SOBRE UNA PERSONA DESAPARECIDA, ASÍ COMO PERSONAS EN SITUACIÓN DE VULNERABILIDAD DENUNCIADAS COMO DESAPARECIDAS DEBE COMUNICARSE INMEDIATAMENTE CON LA POLICÍA NACIONAL DEL PERÚ, A TRAVÉS DE LOS CANALES Y PROCEDIMIENTOS HABILITADOS PARA LA RECEPCIÓN DE INFORMACIÓN, CONFORME LO SEÑALADO EN EL REGLAMENTO DEL PRESENTE DECRETO LEGISLATIVO. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INFORMACIÓN SOBRE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', NULL, 'c', 'INFORMACIÓN SOBRE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 10°, 10.1., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185886'),
(2979, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'CUANDO EL DENUNCIANTE UBIQUE O TOME CONOCIMIENTO DE LA UBICACIÓN DE LA PERSONA DESAPARECIDA, ASÍ COMO DE LA PERSONA EN SITUACIÓN DE VULNERABILIDAD DENUNCIADA COMO DESAPARECIDA, DEBE COMUNICAR ESTA SITUACIÓN INMEDIATAMENTE A LA POLICÍA NACIONAL DEL PERÚ. EL PRESENTE ENUNCIADO CORRESPONDE A:', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'INVESTIGACIÓN DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'BÚSQUEDA DE PERSONAS DENUNCIADAS COMO NO UBICABLES', 'INFORMACIÓN SOBRE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', NULL, 'e', 'INFORMACIÓN SOBRE PERSONAS DENUNCIADAS COMO DESAPARECIDAS', 'ARTÍCULO 10°, 10.2., MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185887'),
(2980, 'D.Leg. 1428 - Que Desarrolla Medidas Para La Atencion De Casos De Desaparicion D', 'LAS ENTIDADES PÚBLICAS, EN EL MARCO DE SUS COMPETENCIAS, BRINDAN APOYO A LA POLICÍA NACIONAL DEL PERÚ EN', 'ARTICULACIÓN INSTITUCIONAL', 'ARTICULACIÓN INTERINSTITUCIONAL', 'ARTICULACIÓN INTERMINISTERIAL', 'ARTICULACIÓN POLICIAL', 'ARTICULACIÓN ESTATAL', NULL, 'e', 'ARTICULACIÓN ESTATAL', 'ARTÍCULO 11°, MODIFICADO POR EL ARTÍCULO 3° DEL DECRETO LEGISLATIVO N° 1603, PUBLICADO EL 21', '185888'),
